gameforge.collect_quest_lv30._140_npcChat = "Die Orkz\228hne "
gameforge.collect_quest_lv30._150_say = "Oh, du hast einen Backenzahn gefunden![ENTER]Gib mir einen Moment Zeit, ihn zu pr\252fen... "
gameforge.collect_quest_lv30._160_say = "Oh! Dieser Zahn ist von bester Qualit\228t! Ich[ENTER]werde sofort mit den Untersuchungen beginnen.[ENTER]Allerdings ben\246tige ich noch %s weitere[ENTER]Exemplare. Bitte versuche, welche zu finden![ENTER]Und denk daran, dass ich Zeit brauche. Den[ENTER]n\228chsten Zahn werde ich erst morgen untersuchen[ENTER]k\246nnen. "
gameforge.collect_quest_lv30._170_say = "Du hast alle 10 Orkz\228hne besorgt! Ich danke dir.[ENTER]Doch zu guter Letzt ben\246tige ich noch einen[ENTER]besonderen Stein. Man nennt ihn Jinunggyis[ENTER]Seelenstein. Es w\228re gut, wenn du auch diesen[ENTER]beschaffen k\246nntest. Du wirst ihn im Besitz der[ENTER]Orks finden. "
gameforge.collect_quest_lv30._180_say = "Hm, dieser Zahn ist leider schon sehr verfault.[ENTER]Ich glaube nicht, dass ich ihn f\252r meine[ENTER]Untersuchungen gebrauchen kann. Bitte bringe mir[ENTER]einen anderen![ENTER]Dennoch werde ich Zeit brauchen, diesen hier genau[ENTER]zu analysieren. Den n\228chsten Zahn werde ich erst[ENTER]morgen untersuchen k\246nnen. "
gameforge.collect_quest_lv30._190_say = "Bitte komm zur\252ck, wenn du einen weiteren Orkzahn[ENTER]gefunden hast. "
gameforge.collect_quest_lv30._200_say = "Es tut mir furchtbar leid, aber ich habe die[ENTER]Analyse des letzten Exemplars noch nicht beendet.[ENTER]Macht es dir etwas aus, sp\228ter noch einmal[ENTER]vorbei zu kommen? "
gameforge.collect_quest_lv30._20_say = "Der Biologe Chaegirab, Lehrling Uriels,[ENTER]sucht dringend nach dir.[ENTER]Geh schnell und erkundige dich, wie du ihm[ENTER]behilflich sein kannst. "
gameforge.collect_quest_lv30._210_sendLetter = "Die Forschung des Biologen "
gameforge.collect_quest_lv30._220_sayTitle = "Jinunggyis Seelenstein "
gameforge.collect_quest_lv30._230_sayReward = "Du hast den Seelenstein letztendlich gefunden![ENTER]Bringe ihn zum Biologen Chaegirab.[ENTER]Er wartet bereits auf dich. "
gameforge.collect_quest_lv30._240_say = "F\252r die Forschungen des Biologen Chaegirab,[ENTER]Lehrling Uriels, hast du 10 Orkz\228hne gesammelt.[ENTER]Nun ben\246tigt er zum richtigen Verst\228ndnis seiner[ENTER]Untersuchungsergebnisse noch Jinunggyis[ENTER]Seelenstein. "
gameforge.collect_quest_lv30._250_say = "Du erh\228ltst ihn von den verschiedenen Stolzen[ENTER]Orks im Tal von Seungryong. "
gameforge.collect_quest_lv30._260_sendLetter = "Du hast Jinunggyis Seelenstein gefunden. "
gameforge.collect_quest_lv30._270_npcChat = "Ich habe Jinunggyis Seelenstein. "
gameforge.collect_quest_lv30._280_say = "Hab vielen Dank![ENTER]Um dich zu belohnen, werde ich dir dieses Rezept[ENTER]\252berlassen. Seine Zusammenstellung ist nur[ENTER]wenigen bekannt und wird sorgf\228ltig geh\252tet.[ENTER]Der Trank, den man mit Hilfe der Rezeptur[ENTER]herstellen kann, verleiht deinen F\252\223en Fl\252gel.[ENTER]Geh und suche Baek-Go auf. Er wird den Trank f\252r[ENTER]dich herstellen.[ENTER]Leb wohl, mein Freund. Mit deiner Hilfe konnte[ENTER]ich viele wichtige Erkenntnisse \252ber die Orks[ENTER]erlangen. "
gameforge.collect_quest_lv30._290_say = "Bitte komm zur\252ck, wenn du Jinunggyis Seelenstein[ENTER]gefunden hast. "
gameforge.collect_quest_lv30._300_sendLetter = "Die Belohnung Chaegirabs "
gameforge.collect_quest_lv30._30_npcChat = "H\246r mir zu. "
gameforge.collect_quest_lv30._310_targetVid = "Die Belohnung von Chaegirab "
gameforge.collect_quest_lv30._320_say = "Als Belohnung f\252r die Backenz\228hne und Jinunggyis[ENTER]Seelenstein hat dir der Biologe Chaegirab ein[ENTER]Geheimrezept \252berlassen.[ENTER]Gehe nun zu Baek-Go - er wird das Wundermittel[ENTER]f\252r dich herstellen. "
gameforge.collect_quest_lv30._330_npcChat = "Das Geheimrezept "
gameforge.collect_quest_lv30._340_sayTitle = "Baek-Go: "
gameforge.collect_quest_lv30._350_say = "Sieh mal an, ist das ein Geheimrezept von[ENTER]Chaegirab, dem Biologen? Hm, das wird deine[ENTER]Bewegungsgeschwindigkeit um 10 Punkte erh\246hen.[ENTER]Hier ist dein Trank![ENTER]Au\223erdem soll ich dir noch diesen Ring geben. Er[ENTER]sieht wertvoll aus, also verliere ihn nicht! "
gameforge.collect_quest_lv30._360_sayReward = "Als Belohnung f\252r die Erf\252llung der Bitte[ENTER]Chaegirabs erh\246ht sich deine[ENTER]Bewegungsgeschwindigkeit dauerhaft um 10 Punkte. "
gameforge.collect_quest_lv30._370_npcChat = "Versuche es noch einmal. "
gameforge.collect_quest_lv30._380_say = "Hm, das ist schon sehr gut. Aber vielleicht[ENTER]versuchst du es noch einmal? "
gameforge.collect_quest_lv30._40_say = "Wie gut, dass du kommst - ich ben\246tige deine[ENTER]Hilfe. F\252r meine Forschungen trage ich[ENTER]Informationen \252ber alle Kreaturen zusammen, die[ENTER]auf dem Kontinent leben. Eine sehr umfangreiche[ENTER]Aufgabe, die ich allein nicht bew\228ltigen kann.[ENTER]Wenn du mir hilfst und einige Erkundigungen[ENTER]einholst, werde ich dich f\252r deine Dienste[ENTER]selbstverst\228ndlich entlohnen. "
gameforge.collect_quest_lv30._50_say = "Ich untersuche gerade die Orks im Tal von[ENTER]Seungryong. Mit ihren Backenz\228hnen sind sie in[ENTER]der Lage, sogar Eisen zu zermahlen - eine[ENTER]au\223erordentlich interessante Tatsache.[ENTER]Trotz aller Unterschiede glauben viele Forscher[ENTER]daran, dass die Rassen der Menschen und der Orks[ENTER]miteinander verwandt seien. Vielleicht geben mir[ENTER]die Backenz\228hne der Orks einen Hinweis auf diese[ENTER]Annahmen... und somit einen Schl\252ssel zu unserer[ENTER]Entwicklungsgeschichte. "
gameforge.collect_quest_lv30._60_say = "K\246nntest du losziehen und mir Orkz\228hne[ENTER]besorgen? Es m\252ssen allerdings Backenz\228hne[ENTER]sein. Bringe mir immer nur einen Zahn nach dem[ENTER]anderen, da die Untersuchungen ein wenig[ENTER]aufwendig sind und daher Zeit in Anspruch nehmen[ENTER]werden. Viel Erfolg! "
gameforge.collect_quest_lv30._70_sendLetter = "Die Forschung des Biologen "
gameforge.collect_quest_lv30._80_sayTitle = "Z\228hne aus dem Orktal "
gameforge.collect_quest_lv30._90_say = "Der Biologe Chaegirab, Lehrling Uriels,[ENTER]ben\246tigt f\252r seine Untersuchungen 10[ENTER]Backenz\228hne der Orks aus dem Tal von Seungryong.[ENTER]Bringe ihm stets einen Zahn nach dem anderen,[ENTER]damit er die einzelnen Exemplare eingehend[ENTER]untersuchen kann.[ENTER]Du bekommst die Z\228hne von Orks, Schwarzen Orks[ENTER]und Mutigen Schwarzen Orks. "
