gameforge.collect_quest_lv40._350_sayReward = "Als Belohnung f\252r die Erf\252llung der Bitte[ENTER]Chaegirabs erh\246ht sich deine[ENTER]Angriffsgeschwindigkeit dauerhaft um 5 Punkte. "
gameforge.collect_quest_lv40._40_npcChat = "H\246r mir zu. "
gameforge.collect_quest_lv40._50_say = "Wie gut, dass du kommst - ich ben\246tige deine[ENTER]Hilfe. Ich studiere nicht nur jede Kreatur in[ENTER]diesem Reich, sondern ich mache mir auch Notizen[ENTER]\252ber s\228mtliche Zauber. Eine Aufgabe, die ich[ENTER]allein nicht zu bew\228ltigen vermag, da mir die[ENTER]Zeit fehlt, auf Exkursion zu gehen. W\252rdest du[ENTER]das f\252r mich \252bernehmen? "
gameforge.collect_quest_lv40._60_say = "Ich m\246chte mehr \252ber die geheime Sekte im Tal[ENTER]von Seungryong wissen. Ich glaube, sie besitzen[ENTER]Informationen \252ber die Zauber der alten Zeit;[ENTER]besonders die von ihnen erstellte Fluchsammlung[ENTER]interessiert mich. Diese B\252cher stellen[ENTER]wahrscheinlich den Sch\252ssel dar, der mir noch[ENTER]f\252r meine Forschungen fehlt. "
gameforge.collect_quest_lv40._70_say = "Bitte bringe mir diese B\252cher! Und achte darauf,[ENTER]dass sie intakt sind - manche von ihnen sind so[ENTER]alt, dass man kaum noch etwas darin lesen kann.[ENTER]Solche kann ich leider nicht gebrauchen.[ENTER]F\252r meine Forschungen ben\246tige ich insgesamt 15[ENTER]Fluchsammlungen.[ENTER]Bringe mir stets nur eine, damit ich sie in Ruhe[ENTER]studieren kann. "
gameforge.collect_quest_lv40._80_sayTitle = "Die Zauber der alten Zeit "
gameforge.collect_quest_lv40._90_say = "Der Biologe Chaegirab, Lehrling Uriels,[ENTER]interessiert sich im Zuge seiner Forschungen f\252r[ENTER]die Zauber der alten Zeit. Im Tal von Seungryong[ENTER]existieren 15 B\252cher einer Fluchsammlung. Bringe[ENTER]Chaegirab diese Werke, aber stets eines nach dem[ENTER]anderen.[ENTER]Du bekommst sie von den Dunklen Peinigern und den[ENTER]Hohen Peinigern. "
gameforge.collect_quest_lv50 = {}
gameforge.collect_quest_lv50._100_say = "Der Biologe Chaegirab, Lehrling Uriels,[ENTER]untersucht die Kreaturen im D\228monenturm. F\252r[ENTER]seine Forschungen ben\246tigt er 15 D\228monenandenken.[ENTER]Bringe ihm stets eines nach dem anderen, damit er[ENTER]es in Ruhe studieren kann.[ENTER]Du bekommst sie von den D\228monen im Turm. "
gameforge.collect_quest_lv50._10_sendLetter = "Die Bitte des Biologen "
gameforge.collect_quest_lv50._110_sayReward = "Bis jetzt hast du %s D\228monenandenken abgeliefert. "
gameforge.collect_quest_lv50._120_say = "Du kannst das Elixier des Forschers noch nicht[ENTER]benutzen. "
gameforge.collect_quest_lv50._130_say = "Du hast bereits ein Elixier benutzt! "
gameforge.collect_quest_lv50._140_say = "Du kannst das Elixier benutzen, sobald du ein[ENTER]D\228monenandenken gefunden hast. "
gameforge.collect_quest_lv50._150_npcChat = "Die D\228monenandenken "
gameforge.collect_quest_lv50._160_say = "Oh, du hast eines gefunden![ENTER]Gib mir einen Moment Zeit, es zu pr\252fen... "
gameforge.collect_quest_lv50._170_say = "Oh! Dieses Andenken ist von bester Qualit\228t! Ich[ENTER]werde sofort mit den Untersuchungen beginnen.[ENTER]Allerdings ben\246tige ich noch %s weitere[ENTER]Exemplare. Bitte versuche, welche zu finden![ENTER]Und denk daran, dass ich Zeit brauche. Das n\228chste[ENTER]D\228monenandenken werde ich erst morgen untersuchen[ENTER]k\246nnen. "
gameforge.collect_quest_lv50._180_say = "Du hast alle 15 D\228monenandenken beschafft! Ich[ENTER]danke dir.[ENTER]Nun ben\246tige ich aber noch Sagyis Seelenstein,[ENTER]um den Andenken all ihre Geheimnisse entlocken zu[ENTER]k\246nnen. W\252rdest du auch diese Aufgabe[ENTER]\252bernehmen?[ENTER]Du findest ihn bei den D\228monen im D\228monenturm. "
gameforge.collect_quest_lv50._190_say = "Hm, siehst du diesen tiefen Kratzer? Von einem[ENTER]derart besch\228digten Exemplar kann ich leider[ENTER]nicht viel lernen. Bitte besorge mir ein anderes![ENTER]Dennoch werde ich Zeit brauchen f\252r die Analyse.[ENTER]Das n\228chste D\228monenandenken werde ich erst morgen[ENTER]untersuchen k\246nnen. "
gameforge.collect_quest_lv50._195_say = "Bitte komm zur\252ck, wenn du ein weiteres[ENTER]D\228monenandenken gefunden hast. "
gameforge.collect_quest_lv50._200_say = "Es tut mir furchtbar leid, aber ich habe die[ENTER]Analyse des letzten Exemplars noch nicht beendet.[ENTER]Macht es dir etwas aus, sp\228ter noch einmal vorbei[ENTER]zu kommen? "
