gameforge.collect_quest_lv50._240_say = "F\252r die Forschungen des Biologen Chaegirab,[ENTER]Lehrling Uriels, hast du 15 D\228monenandenken[ENTER]beschafft. Um sie richtig deuten zu k\246nnen,[ENTER]ben\246tigt Chaegirab noch Sagyis Seelenstein. "
