gameforge.collect_quest_lv50._260_sendLetter = "Du hast Sagyis Seelenstein gefunden. "
gameforge.collect_quest_lv50._270_npcChat = "Ich habe Sagyis Seelenstein. "
gameforge.collect_quest_lv50._280_say = "Hab vielen Dank![ENTER]Um dich zu belohnen, werde ich dir dieses Rezept[ENTER]\252berlassen. Seine Zusammenstellung ist nur[ENTER]wenigen bekannt und wird sorgf\228ltig geh\252tet.[ENTER]Der Trank, den man mit Hilfe der Rezeptur[ENTER]herstellen kann, st\228rkt deinen Abwehr-Instinkt.[ENTER]Geh und suche Baek-Go auf. Er wird den Trank f\252r[ENTER]dich herstellen.[ENTER]Leb wohl, mein Freund. Mit deiner Hilfe konnte[ENTER]ich viele wichtige Erkenntnisse \252ber die D\228monen[ENTER]erlangen. "
gameforge.collect_quest_lv50._290_sendLetter = "Die Belohnung Chaegirabs "
gameforge.collect_quest_lv50._295_say = "Bitte komm zur\252ck, wenn du den[ENTER]Sagyis Seelenstein gefunden hast. "
gameforge.collect_quest_lv50._300_sayTitle = "Die Belohnung von Chaegirab "
gameforge.collect_quest_lv50._30_say = "Der Biologe Chaegirab, Lehrling Uriels,[ENTER]sucht dringend nach dir.[ENTER]Geh schnell und erkundige dich, wie du ihm[ENTER]behilflich sein kannst. "
gameforge.collect_quest_lv50._310_say = "Als Belohnung f\252r die D\228monenandenken und den[ENTER]Seelenstein hat dir der Biologe Chaegirab ein[ENTER]Geheimrezept \252berlassen.[ENTER]Gehe nun zu Baek-Go - er wird das Wundermittel[ENTER]f\252r dich herstellen. "
gameforge.collect_quest_lv50._320_say = "Sieh mal an, ist das ein Geheimrezept von[ENTER]Chaegirab, dem Biologen? Hm, das wird deine[ENTER]Verteidigung um 60 Punkte erh\246hen. Hier ist dein[ENTER]Trank![ENTER]Au\223erdem soll ich dir noch dieses Holzk\228stchen[ENTER]geben. Bewahre es sorgf\228ltig auf. "
