gameforge.collect_quest_lv50._40_npcChat = "H\246r mir zu. "
gameforge.collect_quest_lv50._50_say = "Gut, dass du da bist! Ich studiere jede dunkle[ENTER]Kreatur in diesem Reich. Du verstehst sicher,[ENTER]dass ich als Gelehrter nicht losziehen und[ENTER]Monster jagen kann, um diese anschlie\223end zu[ENTER]erforschen. W\252rdest du mir behilflich sein? "
gameforge.collect_quest_lv50._60_say = "Im Zuge meiner Forschungen m\246chte ich die D\228monen[ENTER]im D\228monenturm studieren. Die dunkle Energie des[ENTER]Geb\228udes und der Wesen darin ist sogar noch hier[ENTER]sp\252rbar. Kannst du mir f\252r meine Untersuchungen[ENTER]ein D\228monenandenken besorgen? "
gameforge.collect_quest_lv50._70_say = "Ich w\228re dir f\252r deine Hilfe sehr dankbar. Eines[ENTER]musst du jedoch bedenken: Die D\228monenandenken[ENTER]sind von unterschiedlicher Qualit\228t. F\252r meine[ENTER]Forschungen kann ich jedoch nur solche mit hoher[ENTER]Qualit\228t verwenden.[ENTER]Insgesamt ben\246tige ich 15 Exemplare. Bitte bring[ENTER]sie mir einzeln, da die Untersuchungen ein wenig[ENTER]Zeit in Anspruch nehmen. "
