gameforge.collect_quest_lv80._140_npcChat = "Die Tugyis Tafeln "
gameforge.collect_quest_lv80._150_say = "Oh, du hast eine Tafel gefunden![ENTER]Gib mir einen Moment Zeit, sie zu pr\252fen... "
gameforge.collect_quest_lv80._160_say = "Oh! Diese Tugyis Tafel ist von bester Qualit\228t![ENTER]Ich werde sofort mit den Untersuchungen beginnen.[ENTER]Allerdings ben\246tige ich noch %s weitere[ENTER]Exemplare. Bitte versuche, welche zu finden![ENTER]Und denk daran, dass ich Zeit f\252r die Analyse[ENTER]brauche. Die n\228chste Tafel werde ich erst morgen[ENTER]untersuchen k\246nnen. "
gameforge.collect_quest_lv80._170_say = "Du hast alle 30 Tafeln Tugyis besorgt! Ich danke[ENTER]dir.[ENTER]Nun ben\246tige ich aber noch Tugyis Seelenstein,[ENTER]um die Ursache f\252r die Kraft der Riesen vollends[ENTER]zu verstehen. W\252rdest du auch diese Aufgabe[ENTER]\252bernehmen?[ENTER]Du findest ihn bei den Ogern im Schlangenfeld. "
gameforge.collect_quest_lv80._180_say = "Hm, diese Tafel sieht sehr verwittert aus. Sieh,[ENTER]sie zerbricht ohne Anstrengung! F\252r meine[ENTER]Forschungen ist sie somit ungeeignet.[ENTER]Bitte besorge mir eine andere![ENTER]Dennoch werde ich versuchen, ein paar leichtere[ENTER]Experimente mit dieser hier durchzuf\252hren. Die[ENTER]n\228chste Tugyis Tafel werde ich erst morgen[ENTER]untersuchen k\246nnen. "
gameforge.collect_quest_lv80._185_say = "Bitte komm zur\252ck, wenn du einen weiteren[ENTER]D\228monenedelstein gefunden hast. "
gameforge.collect_quest_lv80._190_sayTitle = "Tugyis Seelenstein "
gameforge.collect_quest_lv80._200_say = "Du hast den Seelenstein letztendlich gefunden![ENTER]Bringe ihn zum Biologen Chaegirab.[ENTER]Er wartet bereits auf dich. "
gameforge.collect_quest_lv80._20_sendLetter = "Die Bitte des Biologen "
gameforge.collect_quest_lv80._210_sayTitle = "Tugyis Seelenstein "
gameforge.collect_quest_lv80._220_say = "F\252r die Forschungen des Biologen Chaegirab,[ENTER]Lehrling Uriels, hast du 30 Tugyis Tafeln[ENTER]zusammengetragen.[ENTER]Nun ben\246tigt er zum Verst\228ndnis ihrer Kr\228fte noch[ENTER]Tugyis Seelenstein. "
gameforge.collect_quest_lv80._230_say = "Du erh\228ltst ihn von den Ogern im Schlangenfeld. "
gameforge.collect_quest_lv80._240_sendLetter = "Du hast Tugyis Seelenstein gefunden. "
gameforge.collect_quest_lv80._250_npcChat = "Ich habe Tugyis Seelenstein. "
gameforge.collect_quest_lv80._260_say = "Hab vielen Dank![ENTER]Um dich zu belohnen, werde ich dir dieses Rezept[ENTER]\252berlassen. Seine Zusammenstellung ist nur[ENTER]wenigen bekannt und wird sorgf\228ltig geh\252tet. Der[ENTER]Trank, den man mit seiner Hilfe herstellen kann,[ENTER]st\228rkt deine Angriffskraft.[ENTER]Geh und suche Baek-Go auf. Er wird den Trank f\252r[ENTER]dich herstellen.[ENTER]Leb wohl, mein Freund. Mit deiner Hilfe konnte[ENTER]ich viele wichtige Erkenntnisse \252ber die Riesen[ENTER]im Schlangenfeld erlangen. "
gameforge.collect_quest_lv80._265_say = "Bitte komm zur\252ck, wenn du[ENTER]Tugyis Seelenstein gefunden hast. "
gameforge.collect_quest_lv80._270_say = "Als Belohnung f\252r die Tugyis Tafeln und den[ENTER]Seelenstein hat dir der Biologe Chaegirab ein[ENTER]Geheimrezept \252berlassen.[ENTER]Gehe nun zu Baek-Go - er wird das Wundermittel[ENTER]f\252r dich herstellen. "
gameforge.collect_quest_lv80._280_say = "Sieh mal an, ist das ein Geheimrezept von[ENTER]Chaegirab, dem Biologen? Hm, das wird deinen[ENTER]Angriffswert um 10% erh\246hen und deine[ENTER]Angriffsgeschwindigkeit um 6 Punkte. Hier ist[ENTER]dein Trank! "
gameforge.collect_quest_lv80._290_say = "Au\223erdem soll ich dir noch diesen Blauen[ENTER]Ebenholzkasten geben. Bewahre ihn sorgf\228ltig auf. "
gameforge.collect_quest_lv80._300_sayReward = "Als Belohnung f\252r die Erf\252llung der Bitte[ENTER]Chaegirabs erh\246ht sich dein Angriffswert[ENTER]dauerhaft um 10% und deine[ENTER]Angriffsgeschwindigkeit dauerhaft um 6 Punkte. "
gameforge.collect_quest_lv80._30_sayTitle = "Die Forschung des Biologen "
gameforge.collect_quest_lv80._310_sendLetter = "Du hast eine Tugyis Tafel gefunden. "
gameforge.collect_quest_lv80._40_say = "Der Biologe Chaegirab, Lehrling Uriels,[ENTER]sucht dringend nach dir.[ENTER]Geh schnell und erkundige dich, wie du ihm[ENTER]behilflich sein kannst. "
gameforge.collect_quest_lv80._50_say = "Danke, dass du auch diesmal wieder Zeit f\252r mich[ENTER]hast! F\252r meine Forschungen trage ich gerade[ENTER]Informationen \252ber das Schlangenfeld zusammen.[ENTER]Das ist eine sehr umfangreiche Aufgabe und ich[ENTER]br\228uchte nat\252rlich auch Informationen aus[ENTER]erster Hand. W\252rdest du f\252r mich zum[ENTER]Schlangenfeld reisen? Du wei\223t, dass ich nicht[ENTER]kleinlich bin, wenn es um die Belohnung geht. "
gameforge.collect_quest_lv80._60_say = "Das Schlangenfeld liegt hinter der Bergkette am[ENTER]Rande der W\252ste. An diesem abgeschiedenen Ort[ENTER]sollen Riesen leben, die nicht nur sehr kr\228ftig,[ENTER]sondern auch extrem angriffslustig sind. Jeder[ENTER]von ihnen tr\228gt eine kleine Tafel mit sich herum[ENTER]- und ich frage mich, ob darin das Geheimnis[ENTER]ihrer Kraft begr\252ndet liegt. "
gameforge.collect_quest_lv80._70_say = "Bitte besorge mir 30 dieser Tafeln von den Ogern[ENTER]im Schlangenfeld. Bring sie mir einzeln, damit[ENTER]ich jede f\252r sich untersuchen kann. Und denk[ENTER]daran, dass ich nur unbesch\228digte, vollst\228ndige[ENTER]Tafeln gebrauchen kann. "
gameforge.collect_quest_lv80._80_sayTitle = "Steintafeln vom Schlangenfeld "
gameforge.collect_quest_lv80._90_say = "Der Biologe Chaegirab, Lehrling Uriels,[ENTER]sammelt Informationen \252ber das Schlangenfeld.[ENTER]F\252r seine Forschungen ben\246tigt er 30 Tugyis[ENTER]Tafeln. Bringe ihm stets nur eine, damit er sie[ENTER]in Ruhe untersuchen kann.[ENTER]Du bekommst sie von den Ogern. "
