gameforge.collect_quest_lv85._065_say = "Ich m\246chte mehr \252ber den Roten Wald erfahren.[ENTER]Dieser war urspr\252nglich ein friedlicher Wald mit[ENTER]riesigen B\228umen. Aber durch den Einfluss der[ENTER]Metinsteine wurde er mit b\246ser Energie verseucht[ENTER]und hat sich in einem verfluchten Ort voller[ENTER]grausamer Geister verwandelt.[ENTER]Um mehr \252ber diesen Ort herauszufinden, brauche[ENTER]ich Rote Geisterbaum-\196ste. "
gameforge.collect_quest_lv85._069_say = "Biologe Chaegirab: "
gameforge.collect_quest_lv85._070_say = "Kannst du mir 40 solcher \196ste besorgen? Achte[ENTER]darauf, dass sie nicht zu d\252nn oder sogar[ENTER]gebrochen sind. Ich kann nur kr\228ftige, gut[ENTER]gewachsene \196ste f\252r meine Forschungen gebrauchen.[ENTER]Und bring sie mir einzeln, damit ich jeden genau[ENTER]\252berpr\252fen kann. "
