gameforge.collect_quest_lv92._060_say = "Heda, tapferer Krieger! Du kommst mir gerade[ENTER]recht. Ich bin auf der Suche nach einer[ENTER]bestimmten Art von Edelsteinen f\252r meine[ENTER]Waffenforschungen. K\246nntest du mir damit helfen?[ENTER]Einige Kreaturen in der Grotte der Verbannung[ENTER]besitzen solche Edelsteine. Aber ich bin zu[ENTER]wichtig, um mein Leben an solch einem[ENTER]gef\228hrlichen Ort aufs Spiel zu setzen. "
gameforge.collect_quest_lv92._070_say = "Im Moment brauche ich die makellosen Juwelen der[ENTER]Missgunst - strahlende Sch\246nheiten, die nur[ENTER]in den Tiefen dieses Berges wachsen. Es sind[ENTER]besondere Diamanten, die lange der m\228chtigen[ENTER]Ausstrahlung des b\246sen Gottes Beran-Setaou[ENTER]ausgesetzt waren und einen winzigen Bruchteil[ENTER]seiner Energien in sich aufgenommen haben.[ENTER]Ich ben\246tige 10 perfekte Exemplare.[ENTER]Viel Gl\252ck und bis bald! "
gameforge.collect_quest_lv92._080_say_title = "Juwelen f\252r Seon-Pyeong "
gameforge.collect_quest_lv92._090_say = "Der Waffenschmied und Forscher Seon-Pyeong[ENTER]ben\246tigt 10 Juwelen der Missgunst f\252r seine[ENTER]Waffenforschung. Bringe sie ihm einzeln, damit er[ENTER]jedes genau untersuchen kann.[ENTER]Du erh\228ltst sie von den Unterwelt-Eism\228nnern und[ENTER]Unterwelt-Eisgolems. "
gameforge.collect_quest_lv92._100_sayReward = "Bis jetzt hast du %s Juwelen abgeliefert. "
gameforge.collect_quest_lv92._110_say = "Du kannst das Elixier des Forschers noch nicht[ENTER]benutzen. "
gameforge.collect_quest_lv92._120_say = "Du hast bereits ein Elixier benutzt! "
gameforge.collect_quest_lv92._130_say = "Du kannst das Elixier benutzen, sobald du ein[ENTER]Juwel gefunden hast. "
gameforge.collect_quest_lv92._140_send_letter = "Juwel gefunden "
gameforge.collect_quest_lv92._145_npcChat = "Juwelen f\252r die Waffenforschung "
gameforge.collect_quest_lv92._150_say = "Du hier? Es tut mir leid, aber ich habe das[ENTER]Studium des letzten Exemplars noch nicht[ENTER]abgeschlossen. Komm sp\228ter wieder! "
gameforge.collect_quest_lv92._160_say = "Du hast noch nichts gefunden? Das tut mir leid.[ENTER]Aber warum bist du dann hier? Auf, auf! Komm[ENTER]wieder her, wenn du mir Juwelen bringen kannst! "
gameforge.collect_quest_lv92._170_say = "Du hast ein Juwel gefunden? Fantastisch! Warte[ENTER]einen Moment, ich muss mich vergewissern... "
gameforge.collect_quest_lv92._180_say = "Oh ja, das ist gut. Ohne jeden Zweifel einer der[ENTER]sch\246nsten Edelsteine, die ich jemals gesehen[ENTER]habe. Vielen Dank! "
gameforge.collect_quest_lv92._190_say = "Aber wie du wei\223t, ben\246tige ich noch %s weitere[ENTER]Exemplare dieser Qualit\228t. Gib mir einen Tag[ENTER]Zeit, diesen hier genau zu untersuchen. Dann[ENTER]kannst du mir den n\228chsten bringen. "
gameforge.collect_quest_lv92._200_say = "Viel Erfolg dabei! "
gameforge.collect_quest_lv92._210_say = "Das war das letzte Juwel, du hast alle 10[ENTER]gesammelt. Ich bin dir zu Dank verpflichtet...[ENTER]und werde bei der Belohnung nicht geizen.[ENTER]W\228hle! "
gameforge.collect_quest_lv92._220_1_select = "Trefferpunkte +1000 "
gameforge.collect_quest_lv92._220_2_select = "Verteidigung +120 "
gameforge.collect_quest_lv92._220_3_select = "Angriff +51 "
gameforge.collect_quest_lv92._230_say = "Hmm... und dieser Edelstein stammt wirklich aus[ENTER]der Grotte der Verbannung? Er ist sch\246n, aber ihm[ENTER]fehlt das innere Feuer. Ich f\252rchte er ist f\252r[ENTER]mich unbrauchbar. Ich werde ihn genau untersuchen[ENTER]und du besorgst mir inzwischen einen anderen, ja? "
gameforge.collect_quest_lv94 = {}
gameforge.collect_quest_lv94._010_target = "Seon-Pyeong "
gameforge.collect_quest_lv94._020_send_letter = "Seon-Pyeongs Forschung "
gameforge.collect_quest_lv94._030_say = "Seon-Pyeong im Tal von Seungryong braucht deine[ENTER]Hilfe. Geh zu ihm und sieh nach, was los ist. "
gameforge.collect_quest_lv94._040_npcChat = "Hilfe bei der Forschung "
gameforge.collect_quest_lv94._050_say_title = "Seon-Pyeong: "
gameforge.collect_quest_lv94._060_say = "Gr\252\223e! Du hast meinen Brief also bekommen?[ENTER]Gut, dann wei\223t du ja bereits, dass ich wieder[ENTER]Hilfe bei der Waffenforschung brauche.[ENTER]Seit der Wiederentdeckung der Grotte kommen immer[ENTER]mehr Einzelheiten ans Licht. Jetzt habe ich[ENTER]erfahren, dass die Kreaturen in diesem Berg noch[ENTER]andere Arten von Juwelen aus dem Stein kratzen. "
gameforge.collect_quest_lv94._070_say = "Es handelt sich um die wundersch\246nen Juwelen der[ENTER]Weisheit - besonders klare und reine Diamanten,[ENTER]von denen man sagt, sie tr\252gen die Essenz der[ENTER]get\246teten G\246ttin Bahar-Taraji in sich. Wenn du in[ENTER]der Grotte bist, halte doch einmal die Augen[ENTER]danach offen![ENTER]Ich ben\246tige 20 perfekte Exemplare.[ENTER]Viel Gl\252ck und lass mich nicht zu lange warten! "
gameforge.collect_quest_lv94._080_say_title = "Juwelen f\252r Seon-Pyeong "
gameforge.collect_quest_lv94._090_say = "Der Waffenschmied und Forscher Seon-Pyeong[ENTER]ben\246tigt 20 Juwelen der Weisheit f\252r seine[ENTER]Waffenforschung. Bringe sie ihm einzeln, damit er[ENTER]jedes genau untersuchen kann.[ENTER]Du erh\228ltst sie von den Setaou-Bogensch\252tzen und[ENTER]den Setaou-Kommandanten. "
gameforge.collect_quest_lv94._100_sayReward = "Bis jetzt hast du %s Juwelen abgeliefert. "
gameforge.collect_quest_lv94._110_say = "Du kannst das Elixier des Forschers noch nicht[ENTER]benutzen. "
gameforge.collect_quest_lv94._120_say = "Du hast bereits ein Elixier benutzt! "
gameforge.collect_quest_lv94._130_say = "Du kannst das Elixier benutzen, sobald du ein[ENTER]Juwel gefunden hast. "
gameforge.collect_quest_lv94._140_send_letter = "Juwel gefunden "
gameforge.collect_quest_lv94._150_npcChat = "Juwelen f\252r die Waffenforschung "
gameforge.collect_quest_lv94._160_say = "Du schon wieder? Es tut mir leid, aber ich habe[ENTER]das Studium des letzten Exemplars noch nicht[ENTER]abgeschlossen. Komm sp\228ter wieder! "
gameforge.collect_quest_lv94._170_say = "Du hast noch nichts gefunden? Das tut mir leid.[ENTER]Aber warum bist du dann hier? Auf, auf! Komm[ENTER]wieder her, wenn du mir Juwelen bringen kannst! "
gameforge.collect_quest_lv94._180_say = "Du hast ein Juwel gefunden? Fantastisch! Warte[ENTER]einen Moment, ich muss mich vergewissern... "
gameforge.collect_quest_lv94._190_say = "Oh, ein wundervoller Edelstein. Sp\252rst du diese[ENTER]leichte W\228rme in deinem Herzen? Diesen Frieden?[ENTER]Das ist sein Werk...[ENTER]Ich danke dir vielmals! "
gameforge.collect_quest_lv94._200_say = "Aber wie du wei\223t, ben\246tige ich noch %s weitere[ENTER]Exemplare dieser Qualit\228t. Gib mir einen Tag[ENTER]Zeit, diesen hier genau zu untersuchen. Dann[ENTER]kannst du mir den n\228chsten bringen. "
gameforge.collect_quest_lv94._210_say = "Viel Erfolg dabei! "
gameforge.collect_quest_lv94._230_1_select = "Trefferpunkte +1100 "
gameforge.collect_quest_lv94._230_2_select = "Verteidigung +140 "
gameforge.collect_quest_lv94._230_3_select = "Angriff +60 "
gameforge.collect_quest_lv94._240_say = "Hmm... ein sch\246ner Diamant, keine Frage. Aber er[ENTER]scheint keine g\246ttliche Aura zu besitzen. Ich[ENTER]f\252rchte, das hilft mir nicht weiter. Besorge mir[ENTER]bitte einen anderen! Und denk daran, dass ich[ENTER]eine Weile brauchen werde, diesen hier genau zu[ENTER]untersuchen. "
gameforge.collect_quest_lv94._250_say = "Du hast es tats\228chlich geschafft! 20 Juwelen der[ENTER]Weisheit... Ich bin beeindruckt![ENTER]Doch leider ist das noch nicht genug. Was ich als[ENTER]N\228chstes brauche, um die Kraft dieser Diamanten[ENTER]in ihrer ganzen F\252lle zu verstehen, ist ein[ENTER]Seelenstein: der Seelenstein des Herrn der[ENTER]Grotte, des Drachen Beran-Setaou. "
gameforge.collect_quest_lv94._260_send_letter = "Seon-Pyeongs Bitte "
gameforge.collect_quest_lv94._270_say_title = "Der Seelenstein des Drachen "
gameforge.collect_quest_lv94._280_say = "Du hast den Seelenstein des Drachen in deinen[ENTER]Besitz bringen k\246nnen. Bringe ihn zu Seon-Pyeong[ENTER]am Eingang der Grotte der Verbannung. "
gameforge.collect_quest_lv94._290_say_title = "Der Seelenstein des Drachen "
gameforge.collect_quest_lv94._300_say = "Du hast Seon-Pyeong im Tal von Seungyrong 20[ENTER]Juwelen der Weisheit gebracht. Nun ben\246tigt er[ENTER]noch den Seelenstein des Drachen! "
gameforge.collect_quest_lv94._310_say = "Du erh\228ltst ihn von Beran-Setaou. "
gameforge.collect_quest_lv94._320_send_letter = "Seelenstein des Drachen erhalten. "
gameforge.collect_quest_lv94._330_npcChat = "Ich habe den Seelenstein des Drachen! "
gameforge.collect_quest_lv94._340_say = "Das ist... unglaublich. Der Seelenstein des[ENTER]Drachen! Ich verneige mich tief vor deinem[ENTER]K\246nnen. Nun steht meinen Forschungen nichts mehr[ENTER]im Wege - und du sollst eine angemessene[ENTER]Belohnung erhalten. W\228hle! "
gameforge.collect_quest_lv94._350_say = "Du hast den Seelenstein erhalten? Und warum sehe[ENTER]ich dann nichts?! Du solltest nicht versuchen,[ENTER]mich hinters Licht zu f\252hren...[ENTER]Ich wei\223, dass ich dir eine schwierige Aufgabe[ENTER]gestellt habe. Doch ich bin sicher, dass du es[ENTER]schaffen kannst! "
gameforge.couple_ring = {}
gameforge.couple_ring._100_sendLetter = "Besiege die Jin-Hee "
gameforge.couple_ring._10_npcChat = "Rache f\252r den Ringh\228ndler "
gameforge.couple_ring._110_sayReward = "Die Alte Frau hat dich um Unterst\252tzung gebeten:[ENTER]ihr Freund, der Ringh\228ndler, wurde von den[ENTER]Jin-Hee ermordet, der Elite des Wei\223en Eid.[ENTER]R\228che den Ringh\228ndler, indem du 30 Jin-Hee[ENTER]t\246test. "
gameforge.couple_ring._120_sayReward = "Anzahl der verbleibenden Jin-Hee: %s "
gameforge.couple_ring._130_say = "Oh ich sehe, du hast gegen die Jin-Hee gek\228mpft.[ENTER]Anscheinend konntest du sie jedoch noch nicht[ENTER]alle besiegen. Ich wei\223 um ihre Kraft und ihr[ENTER]Geschick - es ist keine leichte Aufgabe. "
gameforge.couple_ring._140_say = "Der Ringh\228ndler besa\223 eine Familie, die durch[ENTER]seinen Tod in tiefe Trauer gest\252rzt wurde. Wenn[ENTER]diese durch deinen Einsatz gelindert werden kann,[ENTER]so w\228re das eine Tat, um die ich dich innig[ENTER]bitten w\252rde! "
gameforge.couple_ring._150_say = "Bedauerlich, dass du es vorziehst, den Tod des[ENTER]Ringh\228ndlers nicht zu r\228chen. Aber jedes Leben[ENTER]hat seinen Wert - und ich kann verstehen, dass[ENTER]dein Leben dir viel bedeutet. "
gameforge.couple_ring._160_say = "Als die alte Frau sich abwendet, bemerkst du,[ENTER]dass sie etwas in ihren H\228nden h\228lt. Es handelt[ENTER]sich um einen gl\228nzenden Gegenstand - es k\246nnte[ENTER]ein wertvoller Stein sein. "
gameforge.couple_ring._170_select = "Ich versuche es weiter. "
gameforge.couple_ring._180_say = "An Geld und wertvollen Steinen bin ich nicht[ENTER]interessiert. Ich w\252nsche mir lediglich, dass der[ENTER]Tod des Ringh\228ndlers im Namen seiner Familie[ENTER]ger\228cht wird. Gut, dass du es dir noch einmal[ENTER]\252berlegt hast. "
gameforge.couple_ring._190_say = "Mein Mitgef\252hl geh\246rt in diesen Tagen der Familie[ENTER]des Ringh\228ndlers. Daher ist es bedauerlich, dass[ENTER]du die Herausforderung nicht annimmst. "
gameforge.couple_ring._200_sendLetter = "Zur\252ck zur alten Frau "
gameforge.couple_ring._20_sayTitle = "Alte Frau: "
gameforge.couple_ring._210_say = "Kehre zur alten Frau zur\252ck und berichte ihr,[ENTER]dass der Tod des Ringh\228ndlers durch die[ENTER]Beseitigung der Jin-Hee ger\228cht wurde. "
gameforge.couple_ring._220_npcChat = "Die 30 Jin-Hee sind besiegt! "
gameforge.couple_ring._230_say = "Du hast alle Jin-Hee besiegt. Gut gemacht![ENTER]Die Seele des Ringh\228ndlers kann nun in Frieden[ENTER]ruhen. Hier ist das Schmuckst\252ck, das er mir[ENTER]anvertraute - ein besonderer Verlobungsring.[ENTER]Er soll nun dir geh\246ren. Ich bin mir sicher, dass[ENTER]er es so gewollt h\228tte. "
gameforge.couple_ring._240_sayReward = "Du hast einen Verlobungsring erhalten. "
gameforge.couple_ring._250_sayItem = "Verlobungsring "
gameforge.couple_ring._255_sayItem = "Dieser Ring verk\252ndet eine baldige Hochzeit. "
gameforge.couple_ring._30_say = "Du z\228hlst nun zu den K\228mpfern des Dorfes. Ich[ENTER]w\252sste, wie du deine neu gewonnenen F\228higkeiten[ENTER]nutzen k\246nntest. Hast du jemals von den Jin-Hee[ENTER]geh\246rt? Es sind gef\228hrliche Elitekriegerinnen.[ENTER]Eine der ihren t\246tete den Ringh\228ndler unseres[ENTER]Dorfes. Der H\228ndler war nicht nur ein guter[ENTER]Bekannter von mir, sondern auch ein fairer Mann,[ENTER]der Schmuckst\252cke an junge Paare verkaufte, die[ENTER]eine Heirat beabsichtigten. Bist du bereit,[ENTER]seinen Tod zu r\228chen? Dazu m\252sstest du 30 der[ENTER]Jin-Hee t\246ten... "
gameforge.couple_ring._40_select = "Ich werde den Ringh\228ndler r\228chen. "
gameforge.couple_ring._50_select = "Nein, die Jin-Hee sind mir zu stark. "
gameforge.couple_ring._60_say = "Das ist eine gute und ehrenhafte Entscheidung![ENTER]Denk dran - du musst 30 Jin-Hee t\246ten.[ENTER]Aber sei vorsichtig, denn sie sind listig und[ENTER]wissen sich gut zu verbergen! "
gameforge.couple_ring._70_say = "Das ist eine bedauerliche Entscheidung, aber auch[ENTER]dein gutes Recht. Immerhin kann unvern\252nftige[ENTER]Tapferkeit rasch zum Tod f\252hren.[ENTER]Pass weiterhin auf dich auf! "
gameforge.couple_ring._75_say = "Anzahl der verbleibenden Jin-Hee "
gameforge.couple_ring._80_sayTitle = "Du hast alle Jin-Hee besiegt. "
gameforge.couple_ring._90_say = "Damit ist der Tod des Ringh\228ndlers nun endlich[ENTER]ger\228cht worden. Der Auftrag ist somit[ENTER]abgeschlossen. "
gameforge.cube = {}
gameforge.cube._060_npcChat = "Alle Tr\228nke herstellen "
gameforge.cube._10_say = "Sei gegr\252\223t! Hast du Interesse am Kauf von[ENTER]Tr\228nken, die dich st\228rken oder gar heilen k\246nnen?[ENTER]Ich bin Mediziner und habe mich daher lange Jahre[ENTER]mit der Herstellung solcher Tr\228nke besch\228ftigt.[ENTER]Ich verf\252ge \252ber einige Rezepte, die nirgendwo[ENTER]sonst erh\228ltlich sind. M\246chtest du sie[ENTER]ausprobieren? "
gameforge.cube._20_say = "Die Kr\228uterkunde hat mittlerweile innerhalb der[ENTER]Bev\246lkerung einen guten Ruf erlangt. Hegst du[ENTER]Interesse an solchen Dingen? Ich kann dir einige[ENTER]meiner neuen Rezepte zeigen - damit lassen sich[ENTER]st\228rkere Varianten der allseits bekannten Tr\228nke[ENTER]herstellen. "
gameforge.cube._30_npcChat = "Das geheime Rezept "
gameforge.cube._40_sayTitle = "Huahn-So: "
gameforge.cube._50_say = "Ich habe ein geheimes Rezept gefunden, das sich[ENTER]seit Langem im Besitz meiner Familie befindet.[ENTER]Damit kann ich einen Trank brauen, der dich[ENTER]nahezu unverwundbar macht! Hast du Interesse[ENTER]daran, meine Tr\228nke auszuprobieren? "
