gameforge.deviltower_zone._160_dNotice = "Du hast alle Kreaturen get\246tet. Begib dich nun[ENTER]zum Schmied und hole dir dort deine Belohnung ab[ENTER]- er wird einen Gegenstand deiner Wahl[ENTER]verbessern. Ziehe dazu den Gegenstand, den du zu[ENTER]verbessern w\252nschst, auf den Schmied. "
gameforge.deviltower_zone._170_npcChat = "Die oberen Stockwerke "
gameforge.deviltower_zone._190_say = "Du w\252nschst in den 6. Stock des Turmes zu[ENTER]gelangen? Der Weg ist nicht einfach, du ben\246tigst[ENTER]gro\223es Geschick und viel Erfahrung.[ENTER]Ich kann dich dorthin teleportieren, doch nur,[ENTER]wenn du Level 75 erreicht hast. "
gameforge.deviltower_zone._200_say = "Du besitzt die n\246tige Erfahrung und hast somit[ENTER]eine gute Chance, die oberen Etagen zu \252berleben.[ENTER]Du kannst eintreten! "
gameforge.deviltower_zone._20_sayTitle = "W\228chter des D\228monenturms: "
