gameforge.deviltower_zone._230_say = "Ich kann dir nicht erlauben, die oberen Etagen zu[ENTER]betreten. Deine Erfahrung reicht noch nicht[ENTER]aus, um dort zu \252berleben.[ENTER]Komm zur\252ck, wenn du mindestens Level 75 erreicht[ENTER]hast. "
gameforge.deviltower_zone._240_dNotice = "Mit der Karte der Zin-Grotte er\246ffnet sich dir[ENTER]der Weg zur n\228chsten Ebene.[ENTER]Du kannst sie finden, indem du die Metinsteine[ENTER]zerst\246rst. "
gameforge.deviltower_zone._250_say = "Diese Karte teleportiert dich in den 7. Stock des[ENTER]D\228monenturms. "
gameforge.deviltower_zone._260_dNotice = "Finde den richtigen Schl\252ssel, um in den n\228chsten[ENTER]Stock zu gelangen. Du ben\246tigst den[ENTER]Zin-Bong-In Schl\252ssel, um Sa-Soes Siegel zu[ENTER]\246ffnen. "
gameforge.deviltower_zone._270_dNotice = "T\246te das Oberhaupt der D\228monen. "
gameforge.deviltower_zone._280_dNotice = "Du hast die Aufgabe erfolgreich erf\252llt und[ENTER]wirst in wenigen Minuten hinaus teleportiert. "
gameforge.deviltower_zone._290_dNotice = "Ich werde dich in der Devil's Catacomb erwarten![ENTER]Folge mir und mein Zorn wird einem Erdbeben[ENTER]gleich \252ber dich hereinbrechen! "
gameforge.deviltower_zone._30_say = "In diesem Turm wimmelt es von D\228monen. Nur die[ENTER]st\228rksten K\228mpfer k\246nnen daher seine Spitze[ENTER]erreichen. Es hei\223t jedoch, dass niemand, der den[ENTER]Turm betritt, ihn lebend wieder verl\228sst.[ENTER]Dir ist der Zugang bisher verwehrt, da du noch[ENTER]nicht Level 40 erreicht hast. "
gameforge.deviltower_zone._40_say = "In diesem Turm wimmelt es von D\228monen. Nur die[ENTER]st\228rksten K\228mpfer k\246nnen daher seine Spitze[ENTER]erreichen. Es hei\223t jedoch, dass niemand, der den[ENTER]Turm betritt, ihn lebend wieder verl\228sst.[ENTER]M\246chtest du den D\228monenturm noch immer[ENTER]betreten? "
gameforge.deviltower_zone._50_dNotice = "Du befindest dich am Siegeltor im 3. Stock. Hier[ENTER]warten mehrere Steine darauf, dich zu verwirren.[ENTER]Doch nur einer von ihnen ist der richtige[ENTER]Metinstein. Du musst ihn innerhalb von 15 Minuten[ENTER]zerst\246ren, oder du vermagst das Tor nicht mehr zu[ENTER]passieren. "
