gameforge.dragon_soul = {}
gameforge.dragon_soul._010_sayTitle = "Drachensteinsplitter "
gameforge.dragon_soul._020_say = "In deiner Hand liegt das Fragment eines Steins.[ENTER]Er funkelt geheimnisvoll und du kannst sp\252ren, wie[ENTER]seine Kraft dich durchstr\246mt.[ENTER]Was ist das blo\223 f\252r ein Stein? Bringe ihn zum[ENTER]Alchemisten. Er kann dir sicher weiterhelfen. "
gameforge.dragon_soul._030_npcChat = "Drachensteinsplitter "
gameforge.dragon_soul._040_say = "Das ist das Fragment eines Drachensteins[ENTER]- ein \228u\223erst seltener und wertvoller Kristall[ENTER]mit gro\223er Macht. Es hei\223t, das sei die Seele[ENTER]eines Drachen. Unfassbar sch\246n![ENTER]F\252hlst du, wie seine Kraft dich durchstr\246mt,[ENTER]sobald du ihn bei dir tr\228gst?[ENTER]Bringe mir insgesamt zehn Drachensteinsplitter.[ENTER]Diese kann ich zu einem ganzen Stein[ENTER]transmutieren. "
gameforge.dragon_soul._050_npcChat = "Drachenstein-Transmutation "
gameforge.dragon_soul._060_say = "Nicht so ungeduldig. Ich kann dir erst zehn[ENTER]Splitter zu einem Drachenstein transmutieren.[ENTER]Suche weiter! "
gameforge.dragon_soul._070_say = "Ah, sehr gut! Du hast zehn Drachensteinsplitter[ENTER]gefunden. So, warte einen Moment.[ENTER]...[ENTER]Es ist vollbracht! H\246chst erstaunlich ... Bei der[ENTER]Transmutation ist ein Cor Draconis entstanden - ein[ENTER]kristallenes Drachenherz, das den Drachenstein[ENTER]sch\252tzend umh\252llt.[ENTER]Brich es auf, um herauszufinden, welcher Stein[ENTER]darin ist. Er wandert direkt in das Inventar der[ENTER]Drachensteinalchemie.[ENTER]Wusstest du, dass du Drachensteine noch[ENTER]weiter veredeln kannst? "
gameforge.dragon_soul._080_say = "Du m\246chtest noch ein Cor Draconis?[ENTER]Puh, ich bin nicht mehr der J\252ngste[ENTER]und die Herstellung eines so komplexen[ENTER]Gegenstandes zehrt an meinen Kr\228ften.[ENTER]Aber f\252r dich werde ich es versuchen.[ENTER]Doch mehr als zehn St\252ck pro Tag schaffe[ENTER]ich beim besten Willen nicht! "
gameforge.dragon_soul._090_say = "F\252r heute ist es genug. Mehr als zehn[ENTER]Cor Draconis pro Tag schaffe ich einfach nicht.[ENTER]Ich bin am Ende meiner Kr\228fte und muss[ENTER]mich erst einmal erholen. Komme morgen wieder. "
gameforge.dragon_soul._100_npcChat = "Laden \246ffnen "
gameforge.dragon_soul._1010_sendLetter = "Ankunft der Drachensteinsplitter "
gameforge.dragon_soul._1020_say = "Der Alchemist mit dem fundiertesten Wissen \252ber[ENTER]Mineralien im ganzen Reich sucht nach dir. Geh[ENTER]schnell zu ihm! "
gameforge.dragon_soul._1030_npcChat = "Drachensteinsplitter?! "
gameforge.dragon_soul._1040_say = "Ah, da bist du ja! Ich habe etwas Erstaunliches[ENTER]entdeckt: das Fragment eines Drachensteins! Ein[ENTER]Drachenstein ist ein \228u\223erst seltener und[ENTER]wertvoller Kristall mit gro\223er Macht. Es hei\223t,[ENTER]das sei die Seele eines Drachen. Unfassbar sch\246n![ENTER]Ich verleihe dir die Macht des Drachenauges, damit[ENTER]du die Splitter aufsp\252ren kannst.[ENTER]Bringe mir insgesamt zehn Drachensteinsplitter.[ENTER]Diese kann ich zu einem ganzen Stein transmutieren. "
gameforge.dragon_soul._1050_sendLetter = "Drachensteinsplitter sammeln "
gameforge.dragon_soul._1060_say = "Bringe dem Alchemisten 10 Drachensteinsplitter. "
gameforge.dragon_soul._1070_say = "Ah, du hast zehn Drachensteinsplitter. Bitte[ENTER]gedulde dich einen Moment ...[ENTER]Erstaunlich! Bei der Transmutation ist ein Cor[ENTER]Draconis entstanden - ein kristallenes[ENTER]Drachenherz, das den Drachenstein[ENTER]sch\252tzend umh\252llt. Wenn du es aufbrichst, wandert[ENTER]der Drachenstein darin direkt in das Inventar der[ENTER]Drachensteinalchemie.[ENTER]Um Drachensteinsplitter zu finden und zu[ENTER]transmutieren, brauchst du die Macht des[ENTER]Drachenauges. Einmal t\228glich kann ich sie dir[ENTER]verleihen.[ENTER]Den ersten Drachenstein habe ich dir hergestellt.[ENTER]Die restlichen neun schaffst nun du alleine! "
gameforge.dragon_soul._1080_say = "He, verschwende keine Zeit! Geh lieber und suche[ENTER]Drachensteinsplitter! "
gameforge.dragon_soul._1090_sendLetter = "Macht des Drachenauges "
gameforge.dragon_soul._1100_say = "Verbleibende Macht des Drachenauges: %d "
gameforge.dragon_soul._110_say = "W\228hle aus. "
gameforge.dragon_soul._1110_notice = "Es gibt keine Drachensteinsplitter mehr. "
gameforge.dragon_soul._1120_npcChat = "Gib mir die Macht des Drachenauges "
gameforge.dragon_soul._1130_say = "Hallo! Du hast die Macht des Drachenauges heute[ENTER]bereits erhalten. Das Vorgang schw\228cht mich zu[ENTER]sehr, ich kann dir nur einmal pro Tag helfen. Komm[ENTER]morgen wieder! "
gameforge.dragon_soul._1140_say = "Hallo! Ich wette, du bist wegen der Macht des[ENTER]Drachenauges hier. Richtig? Also gut, hier hast du[ENTER]sie. Viel Gl\252ck bei der Suche! Ich hoffe, du[ENTER]findest gen\252gend Splitter f\252r zehn Drachensteine! "
gameforge.dragon_soul._1150_sendLetter = "Fehlende Macht des Drachenauges "
gameforge.dragon_soul._1160_say = "Die Macht des Drachenauges hat dich verlassen. "
gameforge.dragon_soul._1170_say = "Geh morgen zum Alchemisten zur\252ck, um dir erneut[ENTER]die Macht des Drachenauges abzuholen! "
gameforge.dragon_soul._1180_say = "Geh zum Alchemisten, um dir die Macht des[ENTER]Drachenauges abzuholen! "
gameforge.dragon_soul_daily_gift = {}
gameforge.dragon_soul_daily_gift._010_npcChat = "Cor Draconis als Geschenk "
gameforge.dragon_soul_daily_gift._020_say = "Die Macht des Drachenauges zu beherrschen ist[ENTER]nicht zu einfach, wie es scheint. Nur erfahrene[ENTER]K\228mpfer sind dazu in der Lage. \220be dich weiter im[ENTER]Kampf und komme wieder, wenn du mindestens Level[ENTER]50 erreicht hast. "
gameforge.dragon_soul_daily_gift._030_say = "Um einen Cor Draconis nutzen zu k\246nnen, musst du[ENTER]die Macht des Drachenauges beherrschen. Komme[ENTER]wieder, wenn du dir das zutraust! "
gameforge.dragon_soul_daily_gift._040_say = "Ah, ich sp\252re die Macht des Drachenauges in dir.[ENTER]Als Zeichen meines tiefen Respekts m\246chte ich dir[ENTER]diesen Cor Draconis schenken.[ENTER]Einen Stein am Tag - mehr kann ich leider nicht[ENTER]entbehren. "
gameforge.dragon_soul_daily_gift._050_say = "Bitte sch\246n, hier ist dein Cor Draconis. "
gameforge.dragon_soul_daily_gift._060_say = "Tut mir leid, mehr als einen pro Tag kann ich[ENTER]nicht entbehren. Komme morgen wieder. Vielleicht[ENTER]habe ich da einen neuen Cor Draconis f\252r dich. "
