gameforge.dragon_soul_refine = {}
gameforge.dragon_soul_refine._010_npcChat = "Drachenstein-Veredelung "
gameforge.dragon_soul_refine._020_say = "Du m\246chtest einen Drachenstein veredeln? Nur zu.[ENTER]Vorher solltest du jedoch wissen, dass dieser[ENTER]Prozess auch fehlschlagen kann.[ENTER]Ich habe geh\246rt, dass die sogenannten[ENTER]Drachenbohnen, die man hinter der[ENTER]drehenden M\252nze findet, die Chancen verbessert. "
gameforge.energy_system = {}
gameforge.energy_system._001_npcChat = "Eine neue Technik! "
gameforge.energy_system._010_say = "Ich habe es geschafft![ENTER]Endlich konnte ich eine vollkommen neue Technik[ENTER]entwickeln.[ENTER]Ich habe es m\246glich gemacht, Gegenst\228nde[ENTER]weiterzuverarbeiten und pure Energie aus ihnen zu[ENTER]ziehen. Absolut brillant! "
gameforge.energy_system._020_say = "Zerst\246rt man einen Gegenstand mithilfe meiner[ENTER]Technik, erh\228lt man Energiesplitter. F\252gt man 30[ENTER]dieser Splitter zusammen, erh\228lt man einen[ENTER]machtvollen Energiekristall! Reine, ungefilterte[ENTER]Energie, geb\252ndelt in einem Edelstein. Diese[ENTER]Kraft flie\223t in deine gesamte Ausr\252stung.[ENTER]Hast du Interesse daran? "
gameforge.energy_system._030_say = "Bring Ausr\252stungsgegenst\228nde wie Waffen, Schmuck[ENTER]und Kleidung, die du auf deiner[ENTER]Jagd findest, zu mir. Ich werde sie zu[ENTER]Energiesplittern verarbeiten.[ENTER]Zukunft und Hoffnung unseres Reiches liegen in[ENTER]dieser Technik. Wir werden unbesiegbar! "
gameforge.energy_system._035_npcChat = "Energiesplitter extrahieren "
gameforge.energy_system._040_say = "Hat es funktioniert? Hast du Energiesplitter[ENTER]bekommen?[ENTER]Bring mir mehr Gegenst\228nde und ich werde[ENTER]sie mithilfe der Alchemie zerbrechen.[ENTER]Meine Technik ist noch nicht ganz ausgefeilt.[ENTER]Deswegen kann ich dir nicht garantieren, wie[ENTER]viele Splitter du erh\228ltst. "
gameforge.energy_system._050_say = "Es gibt eine Bedingung: Sowohl dein eigener als[ENTER]auch der Level des Gegenstandes muss[ENTER]mindestens 35 sein.[ENTER]Hm, schauen wir einfach mal ... "
gameforge.energy_system._060_say = "Du bist noch nicht stark genug! Komm wieder,[ENTER]wenn du mindestens Level 35 erreichst hast. "
gameforge.energy_system._070_say = "Ah, ausgezeichnet! Du bist stark und erfahren.[ENTER]Gib mir den Gegenstand, den ich verarbeiten soll. "
gameforge.energy_system._080_say = "Du bist noch nicht stark genug, um die Kraft, die[ENTER]den Energiesplittern innewohnt, zu beherrschen.[ENTER]Komm wieder, wenn du mindestens Level 35[ENTER]erreicht hast. "
gameforge.energy_system._090_say = "Dieser Gegenstand eignet sich nicht f\252r meine[ENTER]Technik. Bring mir etwas Anderes. "
gameforge.energy_system._100_say = "Dieser Gegenstand hat nicht genug Energie.[ENTER]Bring mir einen mit mindestens Level 35 - nur[ENTER]dann kann ich mit meiner Technik seine Kraft[ENTER]herauspressen. "
gameforge.energy_system._110_say = "Soll ich diesen Gegenstand zerst\246ren? "
gameforge.energy_system._120_select = "Ja! "
gameforge.energy_system._130_select = "Nein, noch nicht! "
gameforge.energy_system._140_say = "Ich habe versagt - leider konnte ich keinen[ENTER]Energiesplitter extrahieren. Vielleicht klappt es[ENTER]beim n\228chsten Versuch. "
gameforge.energy_system._150_say = "Sagenhaft! Ich konnte %d Energiesplitter finden.[ENTER]Bitte sehr. "
gameforge.energy_system._160_npcChat = "Energiekristall herstellen "
gameforge.energy_system._170_say = "Hast du deine Kraftreserven etwa schon[ENTER]aufgebraucht? Du solltest nicht so hart arbeiten[ENTER]und dein Leben leichtsinnig aufs Spiel setzen.[ENTER]Um einen Energiekristall herzustellen, ben\246tige[ENTER]ich %d Energiesplitter. "
gameforge.energy_system._180_say = "Du hast noch nicht gen\252gend Energiesplitter.[ENTER]Daraus kann ich keinen Energiekristall[ENTER]herstellen.[ENTER]Komm wieder, wenn du mindestens %d Splitter[ENTER]gesammelt hast. "
gameforge.energy_system._190_say = "Sehr sch\246n, du hast die ben\246tigten %d[ENTER]Energiesplitter. Daraus kann ich einen[ENTER]Energiekristall herstellen.[ENTER]Warte bitte einen Moment. Ich werde es[ENTER]versuchen, aber ich kann dir nicht garantieren,[ENTER]dass es funktioniert. "
gameforge.energy_system._200_say = "Alles ist bereit, um die Splitter zu einem[ENTER]Energiekristall zu verschmelzen.[ENTER]Doch von irgendetwas muss auch ich leben und[ENTER]meine Werkzeuge fallen nicht einfach so vom[ENTER]Himmel. Ich verlange einen kleinen[ENTER]Unkostenbeitrag von %d Yang. Bist du bereit, zu[ENTER]bezahlen? "
gameforge.energy_system._210_select = "Selbstverst\228ndlich! "
gameforge.energy_system._220_select = "Nein, jetzt nicht. "
gameforge.energy_system._230_say = "In Ordnung, ich werde deine Entscheidung[ENTER]respektieren.[ENTER]Komm wieder, wenn du dich anders entschlossen[ENTER]hast und doch einen Energiekristall ben\246tigst. "
gameforge.energy_system._240_say = "Tut mir leid, erst musst du bezahlen. Ich bin[ENTER]doch nicht die Wohlfahrt.[ENTER]So l\228uft das Gesch\228ft - gib mir das Geld, dann[ENTER]werde ich mich an die Arbeit machen. "
gameforge.energy_system._250_say = "Hier, dein Energiekristall. Doch nur der erste[ENTER]Versuch ist immer erfolgreich. Die Alchemie ist[ENTER]eine unberechenbare Wissenschaft - geringf\252gige[ENTER]Abweichungen f\252hren zum Scheitern! Es besteht[ENTER]also immer ein kleines Risiko, dass das[ENTER]Experiment misslingen kann. "
gameforge.energy_system._260_say = "Leider ist der Versuch fehlgeschlagen. Ich konnte[ENTER]keinen Energiekristall herstellen. Meine Technik[ENTER]ist brillant - aber die Ausf\252hrung steckt nun mal[ENTER]voller Risiken. Nicht immer funktioniert alles[ENTER]nach Plan.[ENTER]Beim n\228chsten Mal haben wir bestimmt Erfolg! "
gameforge.energy_system._270_say = "Ich wusste es! Meine Technik ist brillant![ENTER]Hier ist dein Energiekristall.[ENTER]Ein Prachtexemplar! Sp\252rst du die Kraft? "
