gameforge.event_flame_dungeon_open._010_npcChat = "Probleme im Feuerland "
gameforge.event_flame_dungeon_open._020_say = "H, hast du schon geh\246rt? Es wurde eine gro\223e Ruine[ENTER]im Feuerland entdeckt... Wenn ich so ein Krieger[ENTER]wie du w\228re, w\252rde ich mich dorthin trauen, jedoch[ENTER]reichen meine F\228higkeiten nicht aus... "
gameforge.event_flame_dungeon_open._030_say = "Hm... Komm sp\228ter wieder, dann gebe ich dir eine[ENTER]Teleportschriftrolle, auf der die Koordinaten der[ENTER]Ruine aufgezeichnet sind... W\252rdest du damit dorthin[ENTER]gehen und mir davon berichten? Ich bin wirklich[ENTER]neugierig... Hoho "
gameforge.event_flame_dungeon_open._040_npcChat = "Gib mir eine Teleportschriftrolle! "
gameforge.event_flame_dungeon_open._050_say = "Oh ho!! Du bist aber mutig. Du traust dich in das[ENTER]Feuerland zu gehen, wo es stickig und hei\223 ist.[ENTER]Das kann nur ein tapferer Krieger sagen. So, lass[ENTER]mal sehen... "
gameforge.event_flame_dungeon_open._060_say = "So!! Hier!! Wie versprochen, gebe ich dir eine[ENTER]Teleportschriftrolle, in der die Koordinaten der[ENTER]Ruine angezeigt werden. Ich gebe dir dazu noch[ENTER]einen Passierschein. Mach dich auf den Weg und[ENTER]berichte mir danach davon! Pass auf dich auf! "
gameforge.event_flame_dungeon_open._070_say = "Hallo? Auch f\252r mich ist es ziemlich schwer, eine[ENTER]Teleportschriftrolle herzustellen.. Ich kann dir[ENTER]nur eine pro Tag geben, also komm morgen wieder. "
gameforge.event_flame_dungeon_open._080_say = "Bevor du den Dungeon betreten kannst musst du ein paar Cyklopen klopen, have fun! "
gameforge.event_halloween_hair = {}
gameforge.event_halloween_hair._100_say = "Mit dem Zauberstab verwandelst du einen[ENTER]Halloween-K\252rbis in die Halloween-Truhe. Monster[ENTER]lassen K\252rbisse fallen, den Zauberstab habe ich[ENTER]hinter der rotierenden M\252nze versteckt, damit ihn[ENTER]mir keiner klaut. Versuch's mal! "
gameforge.event_halloween_hair._10_npcChat = "Hey, K\252rbissch\228del! "
gameforge.event_halloween_hair._110_say = "Deine K\252rbismaske kann eine Dauer von 6 Stunden,[ENTER]1 Tag oder 7 Tagen haben. Aber das entscheidet[ENTER]der Zufall! "
gameforge.event_halloween_hair._120_say = "Da hast du sie. Die Attribute deiner[ENTER]K\252rbismaske werden zuf\228llig bestimmt. Jede[ENTER]Maske ist unterschiedlich. Probiere sie einfach[ENTER]mal aus. Fr\246hliches Halloween! "
gameforge.event_halloween_hair._130_say = "M\246chtest du deine K\252rbismasken-Karte jetzt gegen[ENTER]eine K\252rbismaske eintauschen? "
gameforge.event_halloween_hair._140_select_1 = "Ja "
gameforge.event_halloween_hair._140_select_2 = "Nein "
gameforge.event_halloween_hair._20_sayTitle = "Jack Pumpkin "
gameforge.event_halloween_hair._30_say = "Wo bin ich? Und wer bist du? "
gameforge.event_halloween_hair._40_say = "Pass auf, was du sagst! Ich bin kein[ENTER]K\252rbissch\228del! Mein Name ist Jack Pumpkin. Und[ENTER]das hier ist nur mein Kost\252m. Ich bin etwas[ENTER]verwirrt, denn eben war ich noch auf einer[ENTER]Halloween-Party und auf einmal hat sich alles um[ENTER]mich herum gedreht. Und nun bin ich hier \133 "
gameforge.event_halloween_hair._50_say = "Jetzt lass mich in Ruhe Halloween feiern! "
gameforge.event_halloween_hair._60_npcChat = "K\252rbismasken-Karte eintauschen "
gameforge.event_halloween_hair._70_say = "Du schon wieder! Soll ich dir was verraten? In[ENTER]der Halloween-Truhe kannst du mit ein bisschen[ENTER]Gl\252ck eine K\252rbismasken-Karte finden. "
gameforge.event_halloween_hair._80_say = "Mit dieser Karte erh\228ltst du auch so eine[ENTER]gruselige K\252rbismaske. M\246chtest du eine Maske[ENTER]haben? "
gameforge.event_halloween_hair._90_say = "Du hast keine K\252rbismasken-Karte? Dann erh\228ltst[ENTER]du auch keine K\252rbismaske! Haha! "
gameforge.event_ramadan = {}
gameforge.event_ramadan._010_npcChat = "Historiker? "
gameforge.event_ramadan._020_sayTitle = "Historiker: "
gameforge.event_ramadan._030_say = "Lerne aus der Vergangenheit und sei offen f\252r die[ENTER]Zukunft! Wie kann ich dir helfen? "
gameforge.event_ramadan._040_say = "Tut mir leid, kennen wir uns? "
gameforge.event_ramadan._050_say = "Entschuldige, ich verga\223, mich vorzustellen. Ich[ENTER]bin der viel gereiste Historiker. Wenn du Fragen[ENTER]zur Geschichte hast scheue dich nicht, mich zu[ENTER]fragen. "
gameforge.event_ramadan._060_say = "Es ehrt mich, dich kennen zu lernen. Ich sollte[ENTER]dich \246fter besuchen. "
gameforge.event_ramadan._070_npcChat = "Was S\252\223es "
gameforge.event_ramadan._100_say = "Schade, bis zum n\228chsten mal. "
gameforge.event_ramadan._110_say = "Dann wei\223t du ja was ich meine. Wenn du[ENTER]diese S\252\223igkeiten willst, bringe mir bitte[ENTER]ein Brot. "
gameforge.event_ramadan._120_say = "Ich w\252rde dir eine S\252\223igkeit f\252r[ENTER]10 Brote geben. Bist du damit[ENTER]einverstanden? "
gameforge.event_ramadan._130_select_1 = "Gerne "
gameforge.event_ramadan._130_select_2 = "Keine Zeit "
gameforge.event_ramadan._140_say = "Jedesmal, wenn du mir 10 Brote bringst,[ENTER]gebe ich dir eine S\252\223igkeit. "
gameforge.event_ramadan._150_say = "Das sind zu wenig Brote, damit kann ich nicht[ENTER]viel anfangen. "
gameforge.event_ramadan._160_say = "Das sind genug Brote, daf\252r gebe ich dir[ENTER]S\252\223igkeiten. "
gameforge.event_ramadan._170_say = "Sammle mehr und ich werde dir mehr[ENTER]davon geben "
gameforge.event_ramadan._180_npcChat = "Leckeres Brot "
gameforge.event_ramadan._180_say = "Ich bin sehr satt von dem Brot, das du mir[ENTER]gebracht hast. "
gameforge.event_ramadan._190_say = "Es gibt hier viele B\252rger, die fasten.[ENTER]Es w\228re sch\246n, wenn du auch mit[ENTER]ihnen das Fastenbrechen begehen w\252rdest. "
gameforge.event_ramadan._200_say = "Um deine Demut zu zeigen, solltest du es[ENTER]ihnen auf einem wertvollen Teller bringen. "
gameforge.event_ramadan._210_say = "Vielen Dank f\252r das k\246stliche Brot! Du[ENTER]bist ein weiser und barmherziger Mensch.[ENTER]Man wird es dir vergelten. "
gameforge.event_ramadan._220_npcChat = "Hunger... "
gameforge.event_ramadan._230_sayTitle = "Fastender B\252rger: "
gameforge.event_ramadan._240_say = "Ich bin wirklich hungrig. Hab Erbarmen und[ENTER]bringe mir ein Iftar. Bitte bringe es mir, damit[ENTER]ich nicht verhungere. "
gameforge.event_ramadan._250_say = "Das ist doch ein Iftar... das Brot riecht[ENTER]so gut. W\252rdest du es mir[ENTER]geben? Ich w\228re dir sehr dankbar. "
gameforge.event_ramadan._260_select_1 = "Nimm dir bitte davon "
gameforge.event_ramadan._260_select_2 = "Nein, ich behalte es "
gameforge.event_ramadan._270_say = "Du bist ein hartherziger und geiziger[ENTER]Mensch. Falls du deine Meinung[ENTER]\228nderst, wei\223t du, wo du mich findest. "
gameforge.event_ramadan._280_say = "Es sei dir gedankt. Du bist wahrlich ein[ENTER]weiser und gro\223herziger Mensch.[ENTER]M\246ge dir deine gute Tat reich belohnt[ENTER]werden. "
gameforge.event_ramadan._290_npcChat = "Die Frucht des Segens "
gameforge.event_ramadan._300_say = "Ich habe auf meinen Reisen die \"Frucht des[ENTER]Segens\" kennengelernt. Diese Frucht[ENTER]belohnt den Flei\223igen, der regelm\228\223ig[ENTER]zur selben Stunde wiederkehrt. "
gameforge.event_ramadan._310_say = "Dich habe ich heute schon gesehen[ENTER]und du wurdest bereits belohnt.[ENTER]Denke daran: Nur der Geduldige[ENTER]erreicht sein Ziel. "
gameforge.event_ramadan._320_npcChat = "Das Gl\252ck des T\252chtigen "
gameforge.event_ramadan._330_say = "Ich habe dich schon erwartet. Meine Zeit hier[ENTER]geht zu Ende und ich ziehe in die Welt, um neue[ENTER]Geschichten zu erforschen. "
gameforge.event_ramadan._340_say = "Du hast %d Fr\252chte des Segens[ENTER]f\252r mich verwahrt. "
gameforge.event_ramadan._350_say = "W\252rdest du mir diese f\252r meine[ENTER]lange Reise geben? Es soll nicht[ENTER]dein Schaden sein. "
gameforge.event_ramadan._360_select_1 = "Bitte, nimm "
gameforge.event_ramadan._360_select_2 = "Nein "
gameforge.event_ramadan._370_say = "\220berlege es dir gut... ich bin noch ein[ENTER]Weilchen hier. "
gameforge.event_ramadan._380_say = "Danke f\252r deine Gro\223z\252gigkeit[ENTER]und deinen Flei\223! "
gameforge.event_ramadan._390_sayReward = "Siegel des Rappen "
gameforge.event_ramadan._400_say = "Du hast weniger als 5? Schade, damit kann ich[ENTER]nicht viel anfangen. Vielleicht beim n\228chsten[ENTER]Mal. "
gameforge.event_ramadan._80_say = "Kennst du dich mit S\252\223igkeiten aus? Diese[ENTER]hier werden Baklava genannt. "
gameforge.event_ramadan._90_select_1 = "Ja, die kenne ich. "
gameforge.event_ramadan._90_select_2 = "Nein, tut mir leid. "
gameforge.find_brother_article = {}
gameforge.find_brother_article._100_select = "Ablehnen "
gameforge.find_brother_article._10_npcChat = "Warum weinst du? "
gameforge.find_brother_article._110_say = "Nat\252rlich helfe ich dir. Die Aufgabe ist nicht[ENTER]allzu schwer zu bewerkstelligen und ich kann gut[ENTER]verstehen, dass du das Andenken zur\252ckhaben[ENTER]willst. Bis bald! "
gameforge.find_brother_article._120_say = "Es gibt wichtigere Angelegenheiten, um die ich[ENTER]mich k\252mmern muss. Warum sollte ich ausgerechnet[ENTER]einer Waise helfen? "
gameforge.find_brother_article._130_sendLetter = "Besorge die schwarze Uniform "
gameforge.find_brother_article._140_sayReward = "Mirines Bruder ist tot und das einzige Andenken,[ENTER]das ihr von ihm blieb, haben die[ENTER]Schwarzwindbesessenen gestohlen.[ENTER]T\246te Schwarzwindbesessene, bis du die schwarze[ENTER]Uniform von Mirines Bruder bei ihnen findest. "
gameforge.find_brother_article._150_npcChat = "Wegen der Uniform deines Bruders... "
gameforge.find_brother_article._160_say = "Willst du die Suche aufgeben? Es ist doch nicht[ENTER]zuviel verlangt, worum ich dich bitte. Ich h\228tte[ENTER]so gerne ein Andenken an meinen Bruder.[ENTER]Bitte hilf mir! "
gameforge.find_brother_article._170_select = "Aufgeben "
gameforge.find_brother_article._180_sayReward = "Es ist beinahe unm\246glich, sich dem Wunsch[ENTER]des M\228dchens zu verweigern. Ein Kampf gegen[ENTER]100 Angeh\246rige der Schwarzwindbande scheint da um[ENTER]ein Vielfaches einfacher zu sein. "
gameforge.find_brother_article._190_say = "Es tut mir leid. Ich f\252hle mit dir, aber die[ENTER]Schwarzwindbande ist ein zu starker Gegner f\252r[ENTER]mich. Jemand mit mehr Erfahrung w\228re dir sicher[ENTER]eine bessere Hilfe. "
gameforge.find_brother_article._200_say = "Oh nein... Ich habe andere um Hilfe gebeten,[ENTER]aber keiner ist jemals zur\252ckgekommen. Du bist[ENTER]meine letzte Hoffnung. Schau her, dies ist das[ENTER]Wertvollste, was ich besitze. Es soll dir[ENTER]geh\246ren. "
gameforge.find_brother_article._205_sayReward = "Das M\228dchen zieht einen sorgf\228ltig in ein Tuch[ENTER]eingewickelten Gegenstand hervor - ein[ENTER]Schwert.[ENTER]Die Verzierungen am Griff lassen auf eine sehr[ENTER]wertvolle Waffe schlie\223en. "
gameforge.find_brother_article._20_sayTitle = "Mirine: "
gameforge.find_brother_article._210_select = "Herausforderung annehmen "
gameforge.find_brother_article._220_say = "Es geht mir nicht um die Belohnung, aber ich[ENTER]werde die Herausforderung annehmen. "
gameforge.find_brother_article._230_say = "Du hast Recht. Keiner kehrte jemals zur\252ck - sie[ENTER]alle haben ihr Leben gelassen. Leben ist viel[ENTER]kostbarer als jegliche Erinnerung. Es w\228re[ENTER]sinnlos, weitere Leben zu opfern. Leb wohl! "
gameforge.find_brother_article._240_npcChat = "Ich habe die schwarze Uniform gefunden! "
gameforge.find_brother_article._250_say = "Ich danke dir. Diese Uniform hat er immer[ENTER]getragen. Er wollte nie etwas anderes anziehen...[ENTER]Hier, nimm. Dies ist das Wertvollste, das ich[ENTER]besitze. Ich brauche es nicht. Bitte nimm es. "
gameforge.find_brother_article._260_sayReward = "Du hast Mirines Belohnung angenommen. "
gameforge.find_brother_article._270_sendLetter = "Mirines Belohnung "
gameforge.find_brother_article._280_say = "Vorsichtig entfernst du das Tuch von Mirines[ENTER]Geschenk und blickst auf ein Schwert mit einem[ENTER]aufw\228ndig verzierten Griff. "
gameforge.find_brother_article._290_say = "Eine gro\223artige Waffe. Aber... Was ist das?[ENTER]Die Klinge ist zerbrochen![ENTER]Diese vorz\252gliche Handwerkskunst ist zu schade[ENTER]zum Wegwerfen. Ich sollte die Bruchst\252cke zu[ENTER]zum Schmied bringen. "
gameforge.find_brother_article._300_sayReward = "Du hast ein zerbrochenes Schwert erhalten.[ENTER]Begib dich zum Schmied, um es reparieren zu[ENTER]lassen. "
gameforge.find_brother_article._30_say = "Oh entschuldige, ich habe dich nicht kommen[ENTER]h\246ren. Ich war in Gedanken bei meinem Bruder.[ENTER]Aber wer bist du? "
gameforge.find_brother_article._310_sendLetter = "Geh zum Schmied "
gameforge.find_brother_article._320_say = "Mirine war so dankbar f\252r deine Hilfe, dass sie[ENTER]dir ihren wertvollsten Besitz geschenkt hat: ein[ENTER]wundersch\246nes, aber leider zerbrochenes Schwert.[ENTER]Da du auf den ersten Blick feststellen kannst,[ENTER]dass es sich um eine wertvolle Waffe handelt,[ENTER]entschlie\223t du dich, sie zur Reparatur zu geben. "
gameforge.find_brother_article._330_targetVid = "Die Reparatur des Schwertes "
gameforge.find_brother_article._340_npcChat = "Kannst du dieses Schwert reparieren? "
gameforge.find_brother_article._350_say = "Das ist ein gro\223artiges Schwert! Es geh\246rte[ENTER]Mirine, nicht wahr? Ich habe geh\246rt, dass du ihr[ENTER]geholfen hast. Gut gemacht, das weist dich als[ENTER]rechtschaffenen Menschen aus. Daher werde ich dir[ENTER]nichts f\252r die Reparatur des Schwerts berechnen.[ENTER]Warte einen Moment... "
gameforge.find_brother_article._360_say = "Hier, die Klinge ist wie neu. Eine wirklich edle[ENTER]Waffe. Nimm sie an dich, mein Freund. "
gameforge.find_brother_article._370_sayReward = "Du erh\228ltst ein Silberschwert+2. "
gameforge.find_brother_article._380_sayReward = "Du erh\228ltst ein Orchideenschwert+2. "
gameforge.find_brother_article._390_sayReward = "Du erh\228ltst einen Anderthalbh\228nder+2. "
gameforge.find_brother_article._400_sayReward = "Du erh\228ltst ein Barbarenschwert+2. "
gameforge.find_brother_article._40_say = "Ich kam zuf\228llig hier vorbei und habe dich weinen[ENTER]geh\246rt. "
gameforge.find_brother_article._50_say = "Mir war nicht bewusst, dass jemand in der N\228he[ENTER]ist... Ich hei\223e Mirine. Vielleicht kann ich dich[ENTER]um deine Hilfe bitten? Mein gro\223er Bruder, er ist[ENTER]tot. Er war unterwegs, um Medizin zu besorgen,[ENTER]doch dann...[ENTER]Mir blieb nur der Anblick seines Grabes und ein[ENTER]einziges Andenken: seine schwarze Uniform. "
gameforge.find_brother_article._60_sayTitle = "Mirine: "
gameforge.find_brother_article._70_say = "Auf dem Weg nach Hause lauerte mir jedoch die[ENTER]Schwarzwindbande auf - eine in dieser Gegend[ENTER]ber\252chtigte Gruppe von Gesetzlosen und M\246rdern.[ENTER]Ich musste fliehen und verlor dabei das[ENTER]Erinnerungsst\252ck an meinen Bruder. Ich traue mich[ENTER]nicht, zur\252ck zu gehen und danach zu suchen.[ENTER]K\246nntest du dies f\252r mich tun? "
gameforge.find_brother_article._80_sayReward = "Hab Mitleid mit dem armen M\228dchen und hilf ihr[ENTER]bei der Suche nach der alten, schwarzen[ENTER]Uniform ihres Bruders! "
gameforge.find_brother_article._90_select = "Annehmen "
