gameforge.find_squareguard = {}
gameforge.find_squareguard._100_npcChat = "Wo kann ich den roten Trank kaufen? "
gameforge.find_squareguard._10_targetVid = "W\228chter des Dorfplatzes "
gameforge.find_squareguard._110_sayTitle = "W\228chter des Dorfplatzes: "
gameforge.find_squareguard._120_say = "Den roten Trank erh\228ltst du bei der[ENTER]Gemischtwarenh\228ndlerin. Sie steht gleich dort[ENTER]dr\252ben. Wenn du sie nicht gleich siehst, dann[ENTER]lauf in Richtung des blinkenden Kreises auf der[ENTER]Gro\223en Karte beziehungsweise des blinkenden roten[ENTER]Punktes auf der Minikarte! "
gameforge.find_squareguard._130_sayTitle = "Gemischtwarenh\228ndlerin: "
gameforge.find_squareguard._131_targetVid = "Gemischtwarenh\228ndlerin "
gameforge.find_squareguard._140_say = "Sei gegr\252\223t Abenteurer![ENTER]Oh, der W\228chter des Dorfplatzes schickt dich zu[ENTER]mir? Er ben\246tigt einen roten Trank? Ich gebe dir[ENTER]gleich 5 St\252ck.[ENTER]Hier, nimm sie. Sie dienen der Wieder-[ENTER]herstellung der Lebenskraft und schmecken[ENTER]sehr gut. "
gameforge.find_squareguard._150_say = "Du bist zwar neu hier in dieser Gegend, aber ich[ENTER]bin davon \252berzeugt, dass du bald ein[ENTER]regelm\228\223iger Kunde sein wirst. Aus diesem Grund[ENTER]\252berlasse ich dir die Tr\228nke kostenlos. Komm bald[ENTER]mal wieder. "
gameforge.find_squareguard._160_sayReward = "Du hast von der Gemischtwarenh\228ndlerin[ENTER]5 rote Tr\228nke erhalten. "
gameforge.find_squareguard._170_sayReward = "Der rote Trank unterst\252tzt die Wiederherstellung[ENTER]deiner Trefferpunkte (TP). "
gameforge.find_squareguard._180_sendLetter = "R\252ckkehr zum W\228chter des Dorfplatzes "
gameforge.find_squareguard._190_sayReward = "Kehre zum W\228chter des Dorfplatzes zur\252ck[ENTER]und h\228ndige ihm einen roten Trank aus. "
gameforge.find_squareguard._200_say = "Du hast keinen roten Trank bekommen?[ENTER]Schade! Aber nun gut, dann behalte das[ENTER]Wechselgeld f\252r deine M\252hen.[ENTER]\220brigens sind die Lehrer auf der Suche nach dir.[ENTER]Du solltest dich zu ihnen begeben. "
gameforge.find_squareguard._20_sayReward = "Gehe ins Dorf und sprich mit dem W\228chter des[ENTER]Dorfplatzes. Er gibt dir deinen ersten Auftrag.[ENTER]Du findest ihn in der Mitte des Dorfes. "
gameforge.find_squareguard._210_say = "Vielen Dank, dass du mir den Trank gebracht hast![ENTER]So musste ich meinen Platz hier im Dorf nicht[ENTER]verlassen und kann meine Pflicht nun besser[ENTER]erf\252llen. Du willst wissen, welche Aufgabe ich[ENTER]bekleide? Im Gro\223en und Ganzen verk\252nde ich[ENTER]n\252tzliche Informationen. Es kommt zudem vor, dass[ENTER]ich denjenigen meine Hilfe anbiete, die sich in[ENTER]Not befinden oder angegriffen werden.[ENTER]Haupts\228chlich bin ich f\252r die Gilden zust\228ndig.[ENTER]Wenn du eines Tages an einer Gilde interessiert[ENTER]sein solltest, dann komm einfach zu mir. "
gameforge.find_squareguard._220_say = "\220brigens sind die Lehrer auf der Suche nach dir.[ENTER]Du solltest dich zu ihnen begeben.[ENTER]Oh, eines h\228tte ich fast vergessen! Als Zeichen[ENTER]meiner Wertsch\228tzung kannst du das Wechselgeld[ENTER]behalten! Wir werden uns sicherlich sp\228ter[ENTER]wiedersehen. Bis dann! "
gameforge.find_squareguard._30_sayTitle = "W\228chter des Dorfplatzes: "
gameforge.find_squareguard._40_say = "Willkommen in unserem Dorf, Abenteurer! Ich w\228re[ENTER]dir dankbar, wenn du mir einen Gefallen erweisen[ENTER]k\246nntest. Wenn ich dir 200 Yang gebe, w\252rdest du[ENTER]f\252r mich einen Roten Trank kaufen? Du bekommst[ENTER]ihn bei der Gemischtwarenh\228ndlerin. Ich befinde[ENTER]mich im Dienst und kann den Dorfplatz daher im[ENTER]Moment nicht verlassen. "
gameforge.find_squareguard._50_select = "Ja "
gameforge.find_squareguard._60_sayReward = "Du hast vom W\228chter 200 Yang erhalten. Mit diesem[ENTER]Zahlungsmittel kannst du dich in[ENTER]Gesch\228ften mit Gegenst\228nden versorgen oder dir[ENTER]den Service der Handwerker sichern.[ENTER]Bei der Gemischtwarenh\228ndlerin kannst du[ENTER]einen roten Trank bekommen. "
gameforge.find_squareguard._70_say = "inaktiver key [%s] "
gameforge.find_squareguard._80_sendLetter = "Kaufe einen roten Trank "
gameforge.find_squareguard._90_sayReward = "Kaufe einen roten Trank bei der Gemischtwaren-[ENTER]h\228ndlerin und bringe ihn dem W\228chter des[ENTER]Dorfplatzes. "
gameforge.fisher = {}
gameforge.fisher._100_say = "Ich bin mir nicht sicher, ob meine F\228higkeiten[ENTER]ausreichen, um diese Angelrute zu verbessern. "
gameforge.fisher._10_npcChat = "Laden \246ffnen "
gameforge.fisher._110_say = "Es besteht sogar eine Wahrscheinlichkeit von %s[ENTER]zu 100, dass die Stufe deiner Angelrute reduziert[ENTER]wird. "
gameforge.fisher._120_say = "Soll ich es dennoch versuchen? "
gameforge.fisher._130_say = "Leider konte ich deine Angelrute nicht[ENTER]verbessern, aber gl\252cklicherweise hat sich ihre[ENTER]Qualit\228t auch nicht verschlechtert. Vielleicht[ENTER]haben wir beim n\228chsten Mal mehr Gl\252ck. "
gameforge.fisher._140_say = "Wunderbar, es hat funktioniert. Hier ist die[ENTER]verbesserte Angelrute! "
gameforge.fisher._150_say = "Der Versuch hat leider nicht funktioniert. Es tut[ENTER]mir leid, denn nun hat sich die Qualit\228t deiner[ENTER]Angelrute um eine Stufe reduziert. "
gameforge.fisher._160_say = "Wie du willst. Komm sp\228ter noch einmal wieder! "
gameforge.fisher._20_npcChat = "Angelrute verbessern "
gameforge.fisher._30_sayTitle = "Fischer: "
gameforge.fisher._40_say = "Du bist also an den Geheimnissen zur Verbesserung[ENTER]deiner Angelrute interessiert? Eigentlich gibt es[ENTER]da nicht wirklich ein Geheimnis. Wenn du Zeit mit[ENTER]Fischen verbringst, sammelt deine Angelrute[ENTER]Punkte. Sobald diese ihren H\246chststand erreicht[ENTER]haben, bringst du die Angel zu mir. Dann kann ich[ENTER]versuchen, sie f\252r dich zu verbessern.[ENTER]Gut. W\228hle also nun die Angelrute, die du zu[ENTER]verbessern w\252nschst und gib sie mir. "
gameforge.fisher._50_say = "Was soll ich denn damit? Ich kann nur Angelruten[ENTER]verbessern! "
gameforge.fisher._60_say = "Tut mir leid. Diese Angelrute kann nicht weiter[ENTER]verbessert werden. "
gameforge.fisher._70_say = "Diese Angelrute hat noch nicht genug Punkte[ENTER]gesammelt. Ich kann sie jetzt noch nicht[ENTER]verbessern. Komm wieder, wenn deine Angel die[ENTER]h\246chstm\246gliche Punktzahl erreicht hat! "
gameforge.fisher._80_say = "Du willst diese Angelrute verbessern?[ENTER]Lass mich mal sehen... "
gameforge.fisher._90_say = "Die Stufe deiner Angel betr\228gt momentan %s. "
