gameforge.fortune_telling._100_sayTitle = "Alte Frau: "
gameforge.fortune_telling._10_npcChat = "Wie ich h\246re, seid ihr Wahrsagerin. "
gameforge.fortune_telling._110_say = "Du bist zu jung, um so tief zu seufzen! M\246chtest[ENTER]du Einblick in dein Schicksal erhalten? Du musst[ENTER]wissen, dass es durchaus M\228chte gibt, die dir[ENTER]Antworten liefern k\246nnen, wo du keine mehr zu[ENTER]finden hofftest... "
gameforge.fortune_telling._120_select = "Vorhersagen lassen "
gameforge.fortune_telling._130_select = "Nicht vorhersagen lassen "
gameforge.fortune_telling._140_say = "Richtig. Das Wichtigste im Leben ist, dass man[ENTER]dem eigenen Willen folgt und sich bem\252ht, stets[ENTER]das Richtige zu tun. Lebt wohl! "
gameforge.fortune_telling._150_select = "Ja, gern. "
gameforge.fortune_telling._160_select = "Nein, danke. "
gameforge.fortune_telling._170_say = "Ich mag zwar freundlich sein, aber ich kann dir[ENTER]keinen Talisman schenken. Wenn du Pech und[ENTER]Ungl\252ck zu vermeiden suchst, bezahle mir den[ENTER]angemessenen Preis f\252r das Schmuckst\252ck.[ENTER]Dieser liegt bei %s Yang. "
gameforge.fortune_telling._180_say = "Du gehst? Vielleicht hast du Recht. Ungl\252ck und[ENTER]Leid geh\246ren zum Leben dazu. Leb wohl und pass[ENTER]auf dich auf. Falls du deine Meinung \228nderst,[ENTER]komm noch einmal wieder. "
gameforge.fortune_telling._20_say = "Deine Augen verraten mir, dass du noch nicht[ENTER]lange auf dieser Welt bist. Warum w\252nschst du[ENTER]bereits so fr\252h, etwas \252ber dein Schicksal zu[ENTER]erfahren? Gibt es einen bestimmten Grund?[ENTER]Dein Schicksal h\228lt noch einige Ereignisse f\252r[ENTER]dich bereit. Komme sp\228ter wieder. "
gameforge.fortune_telling._30_say = "M\246chtest du dein Leben so leben, wie es dir eine[ENTER]Wahrsagerin vorhersagt? Du solltest solche Dinge[ENTER]nicht allzu ernst nehmen. Das wirklich Wichtige[ENTER]sind deine Einstellung und die Art, wie du[ENTER]handelst. Wenn beides positiv ist, kann nichts[ENTER]schiefgehen.[ENTER]Wenn du immer noch dein Schicksal vorhergesagt[ENTER]bekommen m\246chtest, dann komm morgen wieder. "
gameforge.fortune_telling._40_sayTitle = "Alte Frau: "
gameforge.fortune_telling._50_say = "Wie ich dir bereits gesagt habe, lautet deine[ENTER]Vorhersage f\252r heute: "
gameforge.fortune_telling._60_say = "Das Pech wird dich finden, und noch hast du den[ENTER]Talisman zum Abwenden des B\246sen nicht gekauft.[ENTER]Hast du Interesse, meinen Reichtum-Talisman zu[ENTER]erwerben? "
gameforge.fortune_telling._70_select = "Ja, ich kaufe ihn. "
gameforge.fortune_telling._80_select = "Nein, ich brauche ihn nicht. "
gameforge.fortune_telling._90_say = "Ich mag zwar freundlich sein, aber ich kann dir[ENTER]keinen Talisman schenken. Wenn du Pech und[ENTER]Ungl\252ck zu vermeiden suchst, bezahle mir den[ENTER]angemessenen Preis f\252r das Schmuckst\252ck. "
