gameforge.gamesultan._010_sayTitle = "Nachricht der Turnier-Leitung "
gameforge.gamesultan._015_say = "Willkommen zum gro\223en Metin2-Turnier! In deinem[ENTER]Inventar findest du die R\228tselhafte Truhe. Sobald[ENTER]du mit der rechten Maustaste darauf klickst,[ENTER]wirst du in das Feuerland teleportiert - und die[ENTER]K\228mpfe k\246nnen beginnen! "
gameforge.gamesultan._020_say = "Nur die Besten kommen eine Runde weiter! Geh\246rst[ENTER]du dazu? Pr\252fe dein Itemshop-Lager, ob sich eine[ENTER]Truhe darin befindet und ziehe sie in dein[ENTER]Inventar. Sobald du mit der rechten Maustaste[ENTER]darauf klickst, wirst du auf die n\228chste Map[ENTER]teleportiert. "
gameforge.gamesultan._025_say = "Du hast nun alle Herausforderungen gemeistert.[ENTER]Vielen Dank f\252r deinen gro\223artigen Kampfeinsatz![ENTER]Die Finalteilnehmer stehen nach Ende des letzten[ENTER]Durchgangs fest. Wenn du Fragen hast, wende dich[ENTER]an die Turnier-Helfer vor Ort. "
gameforge.gamesultan._030_say = "Bevor der Kampf beginnt, musst du in deinen[ENTER]Spieloptionen den PvP-Modus auf \"Frei\" stellen.[ENTER]\214ffne die Optionen \252ber die Schaltfl\228che rechts[ENTER]unten auf deinem Bildschirm oder \252ber die Taste[ENTER]\"Esc\", w\228hle \"Spieloptionen\" und stelle[ENTER]deinen PvP-Modus auf \"Frei\". "
gameforge.gamesultan._040_say = "Leider sind alle Pl\228tze schon belegt. Warte auf[ENTER]den n\228chsten Durchgang, um am Turnier[ENTER]teilzunehmen. "
gameforge.gamesultan._050_notice_all = "Runde 1: Zerst\246re so viele Metinsteine wie[ENTER]m\246glich. "
gameforge.gamesultan._060_notice_all = "Runde 2: Vernichte so viele Bosse wie m\246glich! "
gameforge.gamesultan._070_notice_all = "Runde 3: Erledige m\246glichst viele Gegner im[ENTER]PvP-Duell! "
gameforge.gamesultan._080_notice_all = "Du hast noch 10 Minuten. "
gameforge.gamesultan._090_notice_all = "Du hast noch eine Minute. Gib alles! "
