gameforge.ghost_story = {}
gameforge.ghost_story._010_sayTitle = "Geist eines Sura: "
gameforge.ghost_story._020_npcChat = "Bist du ein Geist? "
gameforge.ghost_story._030_say = "Nein, ich bin deine Gro\223mutter... Nat\252rlich bin[ENTER]ich ein Geist! Hat man dich als Kind zu hei\223[ENTER]gebadet? "
gameforge.ghost_story._040_npcChat = "Hilfe, ein Geist! "
gameforge.ghost_story._050_say = "Sieh an, was f\252r ein furchtloser Krieger! Buh!! "
gameforge.ghost_story._060_npcChat = "Wer bist du? "
gameforge.ghost_story._070_say = "Mein Name ist Akuma. Ich war einst ein gro\223er[ENTER]K\228mpfer, der beste meiner Zeit sagt man. Auch ich[ENTER]- ja, ich ganz besonders! - habe das geglaubt.[ENTER]Doch sieh mich an. Sieh, was von mir blieb,[ENTER]nachdem ich die Grotte gefunden hatte... und[ENTER]zugrunde ging. "
gameforge.ghost_story._080_npcChat = "Kennst du die Geschichte dieses Ortes? "
gameforge.ghost_story._090_say = "Oh ja, ich wei\223, was damals passierte. Ich habe[ENTER]zu Lebzeiten lange geforscht, um die Hintergr\252nde[ENTER]aufzudecken und die Grotte finden zu k\246nnen. Und[ENTER]nach meinem Tod hatte ich genug Zeit, weiter[ENTER]dar\252ber nachzudenken. Sag mir einfach, was dich[ENTER]interessiert! "
gameforge.ghost_story._100_npcChat = "Was ist das f\252r ein Portal? "
gameforge.ghost_story._110_say = "Dieses Portal f\252hrt in die Kammer des dunklen[ENTER]Drachen, des gefallenen Gottes Beran-Setaou. Es[ENTER]wird mit einem magischen Schl\252ssel aktiviert, den[ENTER]nur die Anf\252hrer von Beran-Setaous Truppen[ENTER]erhalten... "
gameforge.ghost_story._120_npcChat = "Die drei G\246tter "
gameforge.ghost_story._130_say = "Einst bildeten drei g\246ttliche Geschwister die[ENTER]Grundpfeiler des Seins.[ENTER]Bahar-Taraji, die G\246ttin der Sch\246pfung, war die[ENTER]j\252ngste der drei. Ihre Aufgabe war das Erschaffen[ENTER]von Neuem - wo sie auch ging sprossen die Blumen[ENTER]und gedieh das Leben. "
gameforge.ghost_story._140_say = "Der \228lteste Bruder hie\223 Beran-Setaou. Er war[ENTER]zust\228ndig f\252r Ende und Aufl\246sung. Wann immer sich[ENTER]ein Lebenszyklus seinem Ende zu neigte, trennte[ENTER]er K\246rper und Geist voneinander und geleitete die[ENTER]Seele ins Jenseits.[ENTER]So war ein stetiges Werden und Vergehen - die[ENTER]Grundlage allen Lebens - gew\228hrleistet. "
gameforge.ghost_story._150_say = "Der mittlere Bruder schlie\223lich war[ENTER]Baljit-Elvedin. Als Gott des Gleichgewichts[ENTER]vermittelte er zwischen seinen Geschwister und[ENTER]gew\228hrleistete den Erden-Gesch\246pfen den ewig[ENTER]gleichf\246rmigen Kreis des Lebens. Das Kommen und[ENTER]Gehen der Jahreszeiten zum Beispiel fiel in[ENTER]seinen Aufgabenbereich. "
gameforge.ghost_story._160_npcChat = "Das Zerw\252rfnis "
gameforge.ghost_story._170_say = "Die Menschen beteten zu den drei G\246ttern und[ENTER]flehten sie in Notzeiten um Hilfe an. Nur[ENTER]Beran-Setaou f\252rchteten und missachteten sie, in[ENTER]ihrer Kurzsichtigkeit nicht verstehend, dass er[ENTER]als Gegenst\252ck zur Sch\246pfung ebenso existieren[ENTER]musste, wie es Licht und Schatten gab. "
gameforge.ghost_story._180_say = "Lange Zeit sah der Gott dar\252ber hinweg, doch im[ENTER]Laufe der Jahre wuchs Neid in ihm, der langsam zu[ENTER]Hass und Missgunst wurde. Zun\228chst kanalisierte[ENTER]er diese auf die Menschen, brachte ihnen Kriege[ENTER]und Krankheiten. Doch das vergr\246\223erte nur ihre[ENTER]Ablehnung ihm gegen\252ber und sie beteten vermehrt[ENTER]zu Bahar-Taraji, der Herrin des neu[ENTER]entspringenden Lebens. So entstand ein[ENTER]Teufelskreis, der ins Verderben f\252hrte. "
gameforge.ghost_story._190_say = "Als der Zorn des Gottes so gro\223 wurde, dass er[ENTER]ihn nicht mehr zur\252ckzuhalten vermochte,[ENTER]passierte das Unglaubliche: Er t\246tete seine[ENTER]Schwester, den Liebling der Menschen. Die Tat[ENTER]ben\246tigte weder Vorbereitung noch Taktik, denn[ENTER]sie begegnete ihm auch an diesem Tag mit nichts[ENTER]als Unschuld und Vertrauen. Er muss geradewegs in[ENTER]diese liebenden Augen geblickt haben - und f\252hrte[ENTER]dennoch den vernichtenden Schlag. "
gameforge.ghost_story._200_npcChat = "Die Folgen "
gameforge.ghost_story._210_say = "Bahar-Tarajis Tod hatte schreckliche Folgen,[ENTER]sowohl in der Welt der G\246tter als auch bei den[ENTER]Menschen: Ein langj\228hriger, grausamer Winter kam,[ENTER]t\246tete viele Kreaturen zu Land und zu Wasser. Die[ENTER]Erde gefror so fest, dass Steine zerbarsten und[ENTER]selbst die kr\228ftigsten, \228ltesten B\228ume den Tod[ENTER]fanden. "
gameforge.ghost_story._220_say = "Junge Menschen und Tiere starben, und als es[ENTER]endlich wieder w\228rmer wurde, war die Zahl der[ENTER]Neugeburten niedriger als jemals zuvor. Das[ENTER]ausgemergelte Land gab nicht mehr genug her, um[ENTER]die Erwachsenen zu versorgen - und erst recht[ENTER]nicht, um Nachwuchs in Aussicht zu stellen. Mit[ENTER]dem Leben war auch die Hoffnung gestorben und[ENTER]beide ben\246tigten lange, um sich zu erholen. "
gameforge.ghost_story._230_say = "Auch die G\246tter litten, wenngleich ihre Zeit[ENTER]langsamer verrann als die schnellen Stunden der[ENTER]Menschen. Beran-Setaou hatte die Einsamkeit[ENTER]gesucht, als ihm bewusst wurde, was er getan[ENTER]hatte. Bittere Reue und tiefe Genugtuung k\228mpften[ENTER]in seinem Inneren - bis letztere siegte. Sein[ENTER]Herz gefror endg\252ltig und aus dem Gott der[ENTER]Aufl\246sung wurde der Gott des Eises und der K\228lte,[ENTER]des Hasses und der Furcht. "
gameforge.ghost_story._240_npcChat = "Der Kampf "
gameforge.ghost_story._250_say = "Baljit-Elvedin, der Gott der Bewahrung, trauerte[ENTER]lange um seine Schwester. Als die starren Klauen[ENTER]des Schmerzes ihren Griff schlie\223lich lockerten,[ENTER]machte er sich auf die Suche nach seinem Bruder.[ENTER]Noch immer f\252hrten Besonnenheit und Klugheit[ENTER]seinen Weg und so erkannte er trotz seiner[ENTER]Trauer, dass im nun herrschenden Ungleichgewicht[ENTER]das Leben keine Chance hatte. "
gameforge.ghost_story._260_say = "Er folgte den Spuren seines Bruders und fand ihn[ENTER]schlie\223lich, nach langen Jahren, in einer H\246hle[ENTER]aus Eis, Hass und Einsamkeit, fernab allen[ENTER]Lebens. Baljit-Elvedin tat, was er tun musste,[ENTER]auch wenn es eine weitere Narbe in sein Herz[ENTER]riss: Er forderte seinen Bruder zum Kampf. Dieser[ENTER]wiederum war bereits so weit vom rechten Weg[ENTER]abgekommen, dass er keinen Augenblick z\246gerte... "
gameforge.ghost_story._270_say = "Man sagt, der Kampf sei furchtbar gewesen,[ENTER]jenseits aller Vorstellungskraft. Gewonnen hat[ENTER]ihn Baljit-Elvedin. Getreu seiner Ethik t\246tete er[ENTER]seinen Bruder jedoch nicht, sondern nahm ihm[ENTER]seine Kr\228fte und sperrte ihn in dieser Grotte[ENTER]ein. Und so kommt es, dass Beran-Setaou hier sein[ENTER]Leben fristet, zusammen mit den Kreaturen, die er[ENTER]im Laufe der Jahrhunderte schuf... "
gameforge.ghost_story._280_npcChat = "Ich habe genug geh\246rt. "
gameforge.ghost_story._290_say = "M\246ge dein Schicksal ein anderes sein als das[ENTER]meine. Ich w\252nsche dir Gl\252ck! "
gameforge.ghost_story._300_sayTitle = "Geist eines Kriegers: "
gameforge.ghost_story._310_npcChat = "Warum bist du durchsichtig? "
gameforge.ghost_story._320_say = "Was glaubst du denn?! Ich bin ein Geist,[ENTER]eingeschlossen in den Fels seit tausend Jahren... "
gameforge.ghost_story._330_say = "Hilfe, ein Geist! "
gameforge.ghost_story._340_say = "Richtig, ein Geist. Flieh schnell, sonst fresse[ENTER]ich dich! "
gameforge.ghost_story._350_npcChat = "Wer bist du? "
gameforge.ghost_story._360_say = "Ich war einst ein S\246ldner, ein einfacher Mann.[ENTER]Meine Eltern waren Bauern. Ich jedoch wollte[ENTER]nicht mein Leben lang dasselbe Feld bearbeiten,[ENTER]also ging ich zum Milit\228r. Es war hart und[ENTER]blutig, aber keine schlechte Zeit. Doch[ENTER]irgendwann war ich es leid, von nichtsnutzigen[ENTER]Adligen herumkommandiert zu werden und[ENTER]desertierte. Einem dummen Zufall verdanke ich nun[ENTER]mein Dasein an diesem d\252steren Ort. "
gameforge.ghost_story._370_npcChat = "Kennst du die Geschichte der Grotte? "
gameforge.ghost_story._380_say = "Nein, ich wei\223 nichts, ich hatte einfach nur[ENTER]Pech. Nachdem ich desertiert war, wollte ich mich[ENTER]in den Bergen verstecken und fand diese H\246hle.[ENTER]Sie war mir von Anfang an nicht geheuer, lag aber[ENTER]g\252nstig und schien v\246llig verlassen. Wenige Tage[ENTER]sp\228ter wurde ich Zeuge - und Opfer - eines[ENTER]unglaublichen Kampfes. Wenn du willst, kann ich[ENTER]dir davon erz\228hlen. "
gameforge.ghost_story._390_npcChat = "Der Beginn des Kampfes "
gameforge.ghost_story._400_say = "Eines Tages - ich sammelte gerade Wurzeln an den[ENTER]Bergh\228ngen - fuhr ohne jede Vorwarnung ein[ENTER]silberner Drache vom Himmel herab. Ich dachte, es[ENTER]sei um mich geschehen, doch er sah mich gar nicht[ENTER]- seine Aufmerksamkeit galt allein dem[ENTER]H\246hleneingang. Ohne seine Geschwindigkeit zu[ENTER]verringern, schwenkte er in das Tal ein und[ENTER]st\252rzte sich in die H\246hle. "
gameforge.ghost_story._410_say = "Es blieb eine Weile still und ich war unsicher,[ENTER]was ich tun sollte. All meine Ausr\252stung lag in[ENTER]der H\246hle, aber einem Drachen wollte ich auf[ENTER]keinen Fall begegnen! Dann bebte die Erde und aus[ENTER]der Tiefe des Berges drang dumpfes Br\252llen - doch[ENTER]nicht eine Stimme war es, sondern zwei! Kurz[ENTER]darauf schossen zwei Drachen aus der H\246hle, erst[ENTER]der silberne und und direkt dahinter ein blauer. "
gameforge.ghost_story._420_say = "Zwischen den beiden Drachen entbrannte ein Kampf,[ENTER]den ich kaum beschreiben kann. Mit ihren Krallen[ENTER]rissen sie sich gegenseitig die Flanken auf,[ENTER]verkeilten sich in einander, versenkten ihre[ENTER]meterlangen Z\228hne im Hals des Gegners... Es[ENTER]regnete Blut... Doch keiner der beiden lie\223 auch[ENTER]nur einen Moment lang nach. "
gameforge.ghost_story._430_npcChat = "Das Ende des Kampfes "
gameforge.ghost_story._440_say = "Die beiden Drachen w\228lzten sich \252ber das Gebirge[ENTER]wie ein Unwetter, brachten Bergspitzen zu Fall.[ENTER]Blitze verbrannten die Schnauze des blauen,[ENTER]Eishagel durchl\246cherte die Schwingen des[ENTER]silbernen Drachen. Der dicke Eispanzer, der die[ENTER]Erde seit Jahren bedeckte, schmolz unter diesem[ENTER]Ansturm und hinterlie\223 fleckigen Schlamm. Ich[ENTER]kauerte hinter einem Felsen, starr vor Angst,[ENTER]doch unf\228hig, den Blick abzuwenden. "
gameforge.ghost_story._450_say = "Erst nach Stunden schienen ihre Kr\228fte langsam[ENTER]nachzulassen. Ich sah meine Chance, riss mich los[ENTER]von diesem Anblick und rannte hinab ins Tal, um[ENTER]meine Ausr\252stung aus der H\246hle zu bergen. Das[ENTER]besiegelte mein Schicksal. Ich war bereits auf[ENTER]dem Weg zur\252ck, als die beiden Drachen von den[ENTER]Bergen herabschossen, vorneweg der blaue. Er[ENTER]hatte schreckliche Wunden davongetragen. "
gameforge.ghost_story._460_say = "Kurz bevor er in der H\246hle verschwand, holte der[ENTER]Silberne ihn ein und es geschah etwas Seltsames:[ENTER]Ein Flimmern lag in der Luft, wurde zu einem[ENTER]heftigen Luftzug, zu einem Energiewirbel; der[ENTER]blaue Drache war darin gefangen, br\252llte vor[ENTER]Schmerz und Wut... Er schrumpfte, sein Br\252llen[ENTER]wurde schw\228cher und seine Schuppen verloren ihren[ENTER]Glanz, wurden stumpf und farblos... "
gameforge.ghost_story._470_say = "Schlie\223lich entlie\223 der Silberdrache den anderen[ENTER]in die H\246hle. Mit letzter Kraft schleppte sich[ENTER]der Verlierer in die Dunkelheit unter dem Berg.[ENTER]Der Silberne jedoch lie\223 einen m\228chtigen[ENTER]Magiesturm los, der die H\246hle mit einer[ENTER]Energiebarriere versiegelte und einen Teil des[ENTER]Berges zum Einsturz brachte. Der dunkle Drache[ENTER]und ich waren gefangen. Verdammt zu einem[ENTER]qualvollen Hungertod... "
gameforge.ghost_story._480_npcChat = "Ich habe genug geh\246rt. "
gameforge.ghost_story._490_say = "Danke f\252r's Zuh\246ren. Die letzten tausend Jahre[ENTER]waren etwas einsam... "
gameforge.goldbar = {}
gameforge.goldbar._100_say = "Bevor ich dem Schwarzwind entkommen bin, konnte[ENTER]ich herausfinden, wo sie ihr Gold verstecken. Und[ENTER]da lagerte ein ganzer Stapel Goldbarren! Sie[ENTER]w\252rden es noch nicht mal bemerken, wenn welche[ENTER]fehlen. F\252r gute Bezahlung w\252rde ich das Wagnis[ENTER]auf mich nehmen und dir Goldbarren besorgen. Ich[ENTER]kann allerdings nicht mehr als einen Barren auf[ENTER]einmal zur\252ckbringen. "
gameforge.goldbar._104_say = "Zeit "
gameforge.goldbar._108_say = "Minute(n) "
gameforge.goldbar._10_npcChat = "Ein Opfer der Schwarzwindbande "
gameforge.goldbar._110_say = "Es dauert ungef\228hr %s %s, einen Goldbarren[ENTER]zur\252ckzubringen. "
gameforge.goldbar._120_say = "Sag bescheid, wenn du interessiert bist. "
gameforge.goldbar._130_say = "Wirklich? Dann kommen wir ins Gesch\228ft?[ENTER]Du musst es nur sagen und ich werde losziehen,[ENTER]um dir ein Exemplar zu besorgen! "
gameforge.goldbar._140_npcChat = "Ich m\246chte einen Goldbarren kaufen. "
gameforge.goldbar._150_say = "Was redest du da? Davon wei\223 ich nichts. "
gameforge.goldbar._160_say = "Was? Du willst Goldbarren kaufen?[ENTER]Nicht jetzt! Der Schwarzwind scheint[ENTER]misstrauisch zu sein. Ich riskiere meinen Hals,[ENTER]wenn ich nicht aufpasse! Wir werden es[ENTER]wieder versuchen, wenn sich die Lage beruhigt[ENTER]hat. "
gameforge.goldbar._170_sayReward = "Du kannst jetzt keine Goldbarren kaufen. "
gameforge.goldbar._180_say = "Ich war noch nicht in der Lage, einen Goldbarren[ENTER]zu besorgen. "
gameforge.goldbar._190_say = "Wir m\252ssen %s %s warten. "
gameforge.goldbar._200_say = "Ich habe einen Goldbarren besorgt.[ENTER]Das sollte schon 2,2 Millionen Yang wert sein,[ENTER]200.000 Yang gehen dabei an mich.[ENTER]Wie sieht es aus? Bist du interessiert? "
gameforge.goldbar._20_sayTitle = "Verr\228ter Balso: "
gameforge.goldbar._210_say = "Bitte sehr: ein Goldbarren! Du hast eine weise[ENTER]Entscheidung getroffen. Es ist stets eine gute[ENTER]Idee, sein Geld anzulegen. "
gameforge.goldbar._220_say = "Du verf\252gst nicht \252ber ausreichend Geld![ENTER]Das gute St\252ck kostet 2,2 Millionen Yang. "
gameforge.goldbar._230_say = "Warum bist du hier, wenn du gar nichts kaufen[ENTER]willst? So verschwendest du nur meine Zeit. "
gameforge.goldbar._240_npcChat = "GM: Goldbarrenverkaufszeit zur\252cksetzen "
gameforge.goldbar._250_say = "Die Goldbarrenverkaufszeit wurde zur\252ckgesetzt. "
gameforge.goldbar._260_npcChat = "Goldbarren verkaufen "
gameforge.goldbar._270_say = "Was redest du da? Davon wei\223 ich nichts. "
gameforge.goldbar._280_say = "Was? Du willst den Goldbarren verkaufen?[ENTER]Hast du noch nichts davon geh\246rt? Die[ENTER]Schwarzwindkrieger sind misstrauisch geworden und[ENTER]halten ihre Augen offen.[ENTER]Wenn du den Barren jetzt zum Kauf anbietest,[ENTER]wirst du viel \196rger am Hals haben. Am besten[ENTER]l\228sst du ihn, wo er ist. Versteck ihn gut! "
gameforge.goldbar._290_sayReward = "Du kannst jetzt keine Goldbarren verkaufen. "
gameforge.goldbar._300_say = "Wenn du den Goldbarren zur\252ckbringen willst, "
gameforge.goldbar._30_say = "Was? Ein Opfer der Schwarzwindbande? Ha, du bist[ENTER]ja noch ein Kind. Wo hast du das geh\246rt?[ENTER]Geh und spiel lieber mit den Wildhunden! "
gameforge.goldbar._310_say = "wirst du ungef\228hr %s %s warten m\252ssen. "
gameforge.goldbar._320_say = "Ich sehe, du besitzt keine Goldbarren.[ENTER]Wenn du mir welche bringst, werde[ENTER]ich dir gute Yang daf\252r geben. "
gameforge.goldbar._330_say = "Was? Du willst deinen Goldbarren zur\252ckgeben?[ENTER]Warum in aller Welt hast du ihn dann \252berhaupt[ENTER]gekauft? Aber gut, wenn das dein Wunsch ist, so[ENTER]soll es mir recht sein. Die Schwarzwindbande[ENTER]bewacht ihre Sch\228tze \228u\223erst gut, es ist mir[ENTER]daher nicht oft m\246glich. Bist du dir also ganz[ENTER]sicher, dass du ihn zur\252ckgeben willst? "
gameforge.goldbar._340_select = "Zur\252ckgeben "
gameforge.goldbar._350_select = "Nicht zur\252ckgeben "
gameforge.goldbar._360_say = "Hier sind deine Yang.[ENTER]Verdammnis, nun muss ich ihn zur\252ckbringen! "
gameforge.goldbar._370_say = "Hast du \252berhaupt Goldbarren bei dir?[ENTER]Ich bin sehr besch\228ftigt. Komm also nicht her,[ENTER]wenn du keine Gesch\228fte machen willst! "
gameforge.goldbar._40_sayReward = "Der Auftrag 'Ein Opfer der Schwarzwindbande'[ENTER]steht nur Charakteren mit einem Level von 30 oder[ENTER]h\246her offen. "
gameforge.goldbar._50_say = "Sei vorsichtig! Die Schwarzwindkrieger sind[ENTER]misstrauisch. Am besten verh\228lt man sich absolut[ENTER]ruhig. Lebe wohl. "
gameforge.goldbar._60_sayReward = "Der Auftrag 'Ein Opfer der Schwarzwindbande'[ENTER]ist momentan nicht verf\252gbar. "
gameforge.goldbar._70_say = "Pssst![ENTER]Hier k\246nnten sich einige[ENTER]Schwarzwindkrieger versteckt haben.[ENTER]Wo hast du davon geh\246rt?[ENTER]Nein, schon gut, es ist nicht so wichtig.[ENTER]Du wei\223t, was hier los ist?  "
gameforge.goldbar._80_select = "Nein, eigentlich nicht. "
gameforge.goldbar._90_select = "Ja, ich wei\223 Bescheid. "
