gameforge.guild_building = {}
gameforge.guild_building._100_say = "Ich bin nur der Grundst\252cksverwalter und kann[ENTER]den Preis daher nicht senken. Du ben\246tigst mehr[ENTER]Yang. "
gameforge.guild_building._105_say = "Die Gilde %s hat das Grundst\252ck erworben! "
gameforge.guild_building._10_sayTitle = "Grundst\252cksverwalter: "
gameforge.guild_building._110_say = "Komm wieder, wenn du es dir anders \252berlegt hast.[ENTER]Und bedenke: Wer zuerst kommt, mahlt zuerst. "
gameforge.guild_building._20_say = "Ich bin Grundst\252cksverwalter und zust\228ndig f\252r[ENTER]den Verkauf von Landfl\228chen. Bevor die Monster[ENTER]das Land in der Mitte des Kontinents besetzten,[ENTER]hatten wir nicht unter Landknappheit zu leiden[ENTER]und es ging allen gut. Jetzt verkaufe ich das[ENTER]Land nur noch an die Gildenleiter, die es als[ENTER]Gildenland nutzen.[ENTER]Willst du dieses Grundst\252ck kaufen? "
gameforge.guild_building._30_say = "Wie ich schon sagte, kann das Land nicht an jeden[ENTER]verkauft werden.[ENTER]Ich hoffe, du verstehst das. "
