gameforge.guild_building_npc._60_say = "Mein Name ist Stanton, ich bin f\252r das Verbessern[ENTER]von R\252stungen zust\228ndig. Und dabei bin ich[ENTER]wesentlich geschickter als der Dorfschmied: Meine[ENTER]Erfolgsrate ist um 10% h\246her! Gib mir einfach die[ENTER]R\252stung, die verbessert werden soll. "
gameforge.guild_building_npc._70_sayTitle = "Juwelier: "
