gameforge.heavens_cave_escape._030_say = "M\246chtest du die Grotte der Verbannung wirklich[ENTER]verlassen? "
gameforge.heavens_cave_escape._040_say = "Eine weise Entscheidung. Hier ist es zu[ENTER]gef\228hrlich, um noch l\228nger zu bleiben. Geh und[ENTER]versorge erst einmal deine Wunden. "
gameforge.heavens_cave_escape._050_say = "Du bist sehr tapfer. Ich w\252nsche dir viel Erfolg[ENTER]in den Tiefen dieses grauenvollen Ortes... "
gameforge.heavens_cave_keyquest = {}
gameforge.heavens_cave_keyquest._010_target = "Seon-Hae "
gameforge.heavens_cave_keyquest._020_npcChat = "In die Grotte "
gameforge.heavens_cave_keyquest._030_say = "H\246r mir gut zu, mein Junge! Ich werde dir diese[ENTER]Geschichte nur ein einziges Mal erz\228hlen... "
gameforge.heavens_cave_keyquest._040_say = "H\246r mir gut zu, M\228dchen! Ich werde dir diese[ENTER]Geschichte nur ein einziges Mal erz\228hlen... "
gameforge.heavens_cave_keyquest._050_say = "Heute verehren wir den Drachengott, doch einst[ENTER]zogen drei G\246tter \252ber den Himmel. Bahar-Taraji,[ENTER]die G\246ttin der Entstehung, wurde von ihrem Bruder[ENTER]Beran-Setaou aus Neid ermordet. Der dritte Gott -[ENTER]Baljit-Elvedin, den wir heute als Drachengott[ENTER]kennen - trauerte tief. "
gameforge.heavens_cave_keyquest._060_say = "Ein Kampf der beiden Br\252der entbrannte, den der[ENTER]Drachengott f\252r sich entschied. Am Ort der[ENTER]Auseinandersetzung sollen noch immer Spuren ihrer[ENTER]Schlacht zu finden sein. Beran-Setaou wurde nach[ENTER]seiner Niederlage in einer H\246hle eingeschlossen,[ENTER]die daraufhin Grotte der Verbannung genannt[ENTER]wurde. "
gameforge.heavens_cave_keyquest._070_say = "Diese Grotte ist versiegelt und wird vom Orden[ENTER]des Baljit-Elvedin bewacht. Nur, wer dem W\228chter[ENTER]einen Blutstein \252berreicht, darf passieren. Ich[ENTER]kenne einen Weg, einen solchen Stein[ENTER]herzustellen. Aber es ist nicht leicht. "
gameforge.heavens_cave_keyquest._080_say = "Alles begann mit den Tr\228nen, die der Drachengott[ENTER]um seine Schwester weinte. Sie wurden zu Stein,[ENTER]als sie auf die Erde trafen. Noch heute kann man[ENTER]sie im Feuerland von Doyyumhwan finden. Bringe[ENTER]mir sieben dieser Tr\228nen und vier St\252cke[ENTER]Vulkanglas von den Flammen, die dort leben. "
gameforge.heavens_cave_keyquest._090_say_reward = "Sammle 7 Versteinerte Tr\228nen und 4 St\252cke[ENTER]Vulkanglas in Doyyumhwan. "
gameforge.heavens_cave_keyquest._100_say = "Du brauchst einen weiteren Blutstein, um den[ENTER]W\228chter des Ordens passieren zu k\246nnen? Dann[ENTER]sammle erneut sieben versteinerte Tr\228nen und vier[ENTER]St\252cke Vulkanglas im Feuerland von Doyyumhwan. "
gameforge.heavens_cave_keyquest._110_say = "Du brauchst einen weiteren Blutstein? Dieser[ENTER]Koe-Pung ist zwar nicht der Hellste, aber du[ENTER]solltest dennoch etwas warten, da er sonst merkt,[ENTER]dass du nicht seinem Orden angeh\246rst. "
gameforge.heavens_cave_keyquest._120_say = "Einige Stunden, ich w\252rde sagen: %s "
gameforge.heavens_cave_keyquest._130_say = "Eine Stunde und %s Minuten. "
gameforge.heavens_cave_keyquest._140_say = "Warte noch %s Minuten. "
gameforge.heavens_cave_keyquest._150_say_title = "Versteinerte Tr\228ne "
gameforge.heavens_cave_keyquest._160_say = "Hier ist eine der versteinerten Tr\228nen des[ENTER]Drachengottes zur Erde gest\252rzt. "
gameforge.heavens_cave_keyquest._170_1_select = "Tr\228ne aufnehmen "
gameforge.heavens_cave_keyquest._170_2_select = "Hier nach weiteren Tr\228nen suchen "
gameforge.heavens_cave_keyquest._170_3_select = "Nichts tun "
gameforge.heavens_cave_keyquest._180_say = "Du erh\228ltst eine versteinerte Tr\228ne. "
gameforge.heavens_cave_keyquest._190_say_title = "Versteinerte Tr\228ne "
gameforge.heavens_cave_keyquest._200_say = "Du versuchst dein Gl\252ck, um mehr Tr\228nen zu[ENTER]erlangen und findest: %s "
gameforge.heavens_cave_keyquest._210_say = "Jedoch werden die Kreaturen in der Umgebung[ENTER]auf dich aufmerksam! "
gameforge.heavens_cave_keyquest._220_say = "Begib dich zum Feuerland von Doyyumhwan und suche[ENTER]nach den versteinerten Tr\228nen von[ENTER]Baljit-Elvedin, dem Drachengott. Sammle auch[ENTER]Vulkanglas, indem du Flammen t\246test. "
gameforge.heavens_cave_keyquest._230_say = "Versteinerte Tr\228nen ben\246tigt: %s "
gameforge.heavens_cave_keyquest._240_say = "Vulkanglas ben\246tigt: %s "
gameforge.heavens_cave_keyquest._250_notice = "Du hast gen\252gend Tr\228nen gesammelt! "
gameforge.heavens_cave_keyquest._260_notice = "Du hast Vulkanglas bei dieser Flamme gefunden! "
gameforge.heavens_cave_keyquest._270_notice = "Du hast alle ben\246tigten Vulkanglasst\252cke[ENTER]gesammelt! "
gameforge.heavens_cave_keyquest._280_say = "Kehre mit den versteinerten Tr\228nen und dem[ENTER]Vulkanglas zu Seon-Hae zur\252ck. "
gameforge.heavens_cave_keyquest._290_say = "Seon-Hae befindet sich in: %s "
gameforge.heavens_cave_keyquest._300_say = "Die Tr\228nen von Baljit-Elvedin! Ich wandle sie in[ENTER]ihre fl\252ssige Form zur\252ck und f\252lle sie in das[ENTER]Vulkanglas. Ihre Kraft erm\246glicht dir, die G\246ttin[ENTER]Bahar-Taraji zu rufen! "
gameforge.heavens_cave_keyquest._310_say = "Noch immer streift ihr Geist \252ber die Welt. Ihre[ENTER]Stimme wird zu dir sprechen, wenn du die Tr\228nen[ENTER]bei dir tr\228gst. Suche im roten Wald von Lungsam[ENTER]nach ihr! "
gameforge.heavens_cave_keyquest._320_say = "Hier, nimm dieses Gef\228\223 an dich und begib dich[ENTER]auf die Suche nach der Stimme Bahar-Tarajis. "
gameforge.heavens_cave_keyquest._330_say = "Suche im Gebiet des roten Waldes von Lungsam nach[ENTER]der Stimme von Bahar-Taraji. Auch wenn du den[ENTER]Geist der G\246ttin nicht sehen kannst, wirst du ihn[ENTER]wahrnehmen. "
gameforge.heavens_cave_keyquest._335_say = "Ein leises Fl\252stern schwingt im Wind:[ENTER]Geh zu einem sicheren Ort... Hier k\246nnen wir[ENTER]nicht reden...[ENTER]Klicke auf die Questrolle, um mit dem Geist zu[ENTER]sprechen. "
gameforge.heavens_cave_keyquest._340_say = "Im Wind erklingt die Stimme der erschlagenen[ENTER]G\246ttin Bahar-Taraji... "
gameforge.heavens_cave_keyquest._350_say = "Die Tr\228nen meines Bruders... so sehr trauerte er[ENTER]um mich. Aber dennoch konnte er Beran-Setaou[ENTER]nicht f\252r seine Tat bestrafen. "
gameforge.heavens_cave_keyquest._360_say = "Er konnte sich nicht gegen seinen Bruder stellen[ENTER]- gegen Beran-Setaou, den Zerst\246rer. Ihn f\252rchtet[ENTER]ihr Menschen. "
gameforge.heavens_cave_keyquest._370_say = "Aber du... Wer bist du? Du bist anders! Du[ENTER]f\252rchtest ihn nicht. Im Gegenteil, ich sehe, dass[ENTER]du den Kampf suchst. "
gameforge.heavens_cave_keyquest._380_say = "%s! Nimm diesen Tropfen meines Blutes. Forme[ENTER]daraus einen Blutstein und lass Beran-Setaou f\252r[ENTER]seine Tat bezahlen. Der Weg in die Grotte der[ENTER]Verbannung ist nicht mehr weit. "
gameforge.heavens_cave_keyquest._390_say = "Im Wind erklingt die Stimme der erschlagenen[ENTER]G\246ttin Bahar-Taraji... "
gameforge.heavens_cave_keyquest._400_say = "%s! Ich erkenne dich! "
gameforge.heavens_cave_keyquest._410_say = "Du bringst meines Bruders Tr\228nen zu meinem Trost[ENTER]und sollst daf\252r mein Blut erhalten, damit du[ENTER]weiter k\228mpfen kannst. "
gameforge.heavens_cave_keyquest._420_say = "Kehre mit dem Blut von Bahar-Taraji zu Seon-Hae[ENTER]zur\252ck. "
gameforge.heavens_cave_keyquest._430_say = "Seon-Haes Augen glitzern, als er von dir den[ENTER]Blutstropfen entgegen nimmt... "
gameforge.heavens_cave_keyquest._440_say = "Das Blut einer leibhaftigen G\246ttin! Schnell, lass[ENTER]es mich zu einem Blutstein formen, damit es nicht[ENTER]vergeht. "
gameforge.heavens_cave_keyquest._450_say = "Mit einem Blutstein wird dich der W\228chter[ENTER]Koe-Pung das Portal benutzen lassen, das dich in[ENTER]die Grotte der Verbannung f\252hrt. Allerdings nur[ENTER]ein einziges Mal. Wenn du weitere Blutsteine[ENTER]brauchst, dann kehre zu mir zur\252ck. Ich kann dir[ENTER]aber nur einmal am Tag einen solchen Blutstein[ENTER]herstellen, damit wir nicht den Zorn des Ordens[ENTER]auf uns ziehen. "
gameforge.heavens_cave_keyquest._460_say_reward = "Seon-Hae kann dir weitere Blutsteine herstellen,[ENTER]aber nur einen pro Tag. "
gameforge.heavens_cave_keyquest._470_say = "Ich werde wie bisher das Blut von Bahar-Taraji zu[ENTER]einem Blutstein formen. M\246ge er dir gute Dienste[ENTER]leisten. "
gameforge.heavens_cave_keyquest._480_say_reward = "Ich werde dir nur einmal am Tag einen Bluststein[ENTER]herstellen k\246nnen. Andernfalls k\246nnte Koe-Pung[ENTER]misstrauisch werden. "
