gameforge.horse_guard._10_npcChat = "Informationen \252ber Pferde "
gameforge.horse_guard._20_say = "Um eine Pferdequest zu starten, ben\246tigst[ENTER]du eine Pferdemedaille. Du bekommst sie[ENTER]im Affendungeon. "
gameforge.horse_guard._30_say = "Es gibt Pferde f\252r drei Arten von Reitern:[ENTER]Anf\228nger, Fortgeschrittene und Experten.[ENTER]Wenn du genug ge\252bt hast und in die n\228chste[ENTER]Kategorie aufsteigen m\246chtest, musst du einen[ENTER]Eignungstest bestehen. "
gameforge.horse_guard._40_say = "Je nach ihrer Belastung durch den Reiter[ENTER]ben\246tigen Pferde unterschiedliche Arten von[ENTER]Futter. Reitanf\228nger f\252ttern ihre Tiere am besten[ENTER]mit Heu, Fortgeschrittene mit Karotten und[ENTER]Experten, die ihrem Tier viel abverlangen,[ENTER]sollten ausschlie\223lich roten Ginseng verf\252ttern.[ENTER]In dieser Hinsicht k\246nnen Pferde sehr w\228hlerisch[ENTER]sein. "
gameforge.horse_guard._50_say = "Der Zustand des Pferdes wird durch einen[ENTER]einfachen Indikator angezeigt: Bei Gr\252n ist es[ENTER]gesund, im hungrigen Zustand Gelb. Rote Farbe ist[ENTER]gef\228hrlich, denn sie weist auf Unterern\228hrung[ENTER]hin. Du musst dein Pferd f\252ttern, wenn es in den[ENTER]gelben oder gar roten Bereich gekommen ist.[ENTER]Es ist eine ernste Angelegenheit, wenn dein[ENTER]Pferd stirbt. "
gameforge.horse_guard._60_say = "W\228hrend du ein Pferd reitest, nimmt seine[ENTER]Ersch\246pfung zu und seine Gesundheit ab.[ENTER]Du musst es daher ab und zu rasten lassen, damit[ENTER]es nicht zusammenbricht. "
gameforge.horse_guard._70_say = "Es sind Ger\252chte im Umlauf, dass ein totes Pferd[ENTER]mit Affenkraut wiederbelebt werden kann.[ENTER]Allerdings wird dieses Kraut von den Affen schwer[ENTER]bewacht und ist schwierig zu bekommen.[ENTER]Man sagt, die Affen belegen jeden Kr\228uterdieb,[ENTER]den sie erwischen, mit einem Fluch, der ihn[ENTER]ebenfalls in einen Affen verwandelt. "
gameforge.horse_guard._80_say = "Die F\228higkeiten eines Reiters k\246nnen[ENTER]unterschiedlich sein. Wenn du dich dazu noch im[ENTER]Besitz einer Pferdemedaille befindest, kannst du[ENTER]das Level deines Reittieres verbessern. "
