gameforge.locale.bookworm = {}
gameforge.locale.bookworm.accept_ask = "Weshalb bist du noch hier?[ENTER]Du hast den Auftrag angenommen, also vergeude[ENTER]nicht l\228nger deine Zeit und nimm die Aufgabe in[ENTER]Angriff! "
gameforge.locale.bookworm.accept_failure_info_label = "Kehre zu Soon zur\252ck. "
gameforge.locale.bookworm.accept_failure_info_text_1 = "Kehre zu Soon zur\252ck. "
gameforge.locale.bookworm.accept_failure_info_text_2 = "Kehre zum Dorf zur\252ck und teile Soon mit,[ENTER]dass du das Milgyo-Buch nicht finden konntest. "
gameforge.locale.bookworm.accept_failure_say_1 = "Kehre zum Dorf zur\252ck. "
gameforge.locale.bookworm.accept_failure_say_2 = "Das Pech scheint mir an den Fersen zu kleben -[ENTER]ich kann das Milgyo-Buch einfach nicht finden.[ENTER]Mir bleibt nichts anderes \252brig, als ins Dorf[ENTER]zur\252ckzukehren. "
gameforge.locale.bookworm.accept_success_info_label = "Besorge das Milgyo-Buch f\252r Soon! "
gameforge.locale.bookworm.accept_success_info_text_1 = "Besorge das Milgyo-Buch f\252r Soon! "
gameforge.locale.bookworm.accept_success_info_text_2 = "Kehre ins Dorf zur\252ck, gib Soon das Buch[ENTER]und nimm deine Belohnung in Empfang. "
gameforge.locale.bookworm.accept_success_say_1 = "Das Milgyo-Buch... hier ist es! "
gameforge.locale.bookworm.accept_success_say_2 = "Hier ist das Milgyo-Buch! Bring es ins Dorf zu[ENTER]Soon. "
gameforge.locale.bookworm.aranyeo_complete_say = "Welcher Trottel hat meinem Ehemann[ENTER]dieses merkw\252rdige Buch besorgt?[ENTER]Den lieben langen Tag starrt er nur noch hinein[ENTER]und lernt merkw\252rdige Ges\228nge auswendig. Er tut[ENTER]keinen Handschlag mehr![ENTER]Ich werde ihm alle Knochen brechen,[ENTER]wenn ich ihn erwische! "
gameforge.locale.bookworm.aranyeo_complete_say2 = "Was ist geschehen? Ist das etwa Angstschwei\223 auf[ENTER]deiner Stirn? "
gameforge.locale.bookworm.aranyeo_start_say = "Wo ist er nur wieder hin? Sein Verhalten macht[ENTER]mich wahnsinnig! Er verschwendet seine Tage, ohne[ENTER]auch nur einen Yang zu verdienen,[ENTER]indem er sich ausschlie\223lich mit seinen B\252chern[ENTER]besch\228ftigt. Und er sch\228mt sich noch nicht[ENTER]einmal, dass er den Kindern damit ein schlechtes[ENTER]Vorbild liefert. "
gameforge.locale.bookworm.aranyeo_start_say2 = "K\246nnen B\252cher einen Menschen ern\228hren oder[ENTER]einkleiden? Ich werde ihm alle Knochen brechen,[ENTER]wenn ich ihn erwische! "
gameforge.locale.bookworm.aranyeo_talk = "Sprechen. "
gameforge.locale.bookworm.complete_say = "Oha! Ja, ich sehe es! Ich sehe es! Ich sehe die[ENTER]neue Welt! "
gameforge.locale.bookworm.do_you_find_the_book = "Hast du das Milgyo-Buch gefunden? "
gameforge.locale.bookworm.do_you_mean_this_book = "Meinst du dieses Buch? "
gameforge.locale.bookworm.etc_shop_start_say = "Gestern ist er hier vorbeigekommen und hat nach[ENTER]dem Milgyo-Buch gefragt. Er hatte kein Yang, aber[ENTER]er fragte trotzdem dauernd danach.[ENTER]Milgyo hat vielleicht etwas mit diesen brutalen[ENTER]Kerlen im Tal von Seungryong zu tun.[ENTER]Keine Ahnung, warum er sich pl\246tzlich f\252r diese[ENTER]Gestalten interessiert! "
gameforge.locale.bookworm.etc_shop_start_say2 = "Aranyo kann einem nur leid tun.[ENTER]Warum tut sie sich die Ehe mit so einer Person[ENTER]nur an? "
gameforge.locale.bookworm.etc_shop_talk_about_bookworm = "\220ber den Gelehrten Soon. "
gameforge.locale.bookworm.order_accept = "Gut! Ich werde es dir besorgen! "
gameforge.locale.bookworm.order_accept_answer = "Danke! Ich verlasse mich auf dich. "
gameforge.locale.bookworm.order_find_book_label = "T\246te den J\252nger Milgyos! "
gameforge.locale.bookworm.order_find_book_text_1 = "T\246te den J\252nger Milgyos! "
gameforge.locale.bookworm.order_find_book_text_2 = "Nimm dem J\252nger Milgyos das Milgyo-Buch ab. "
gameforge.locale.bookworm.order_refuse = "Das d\252rfte recht schwer sein. "
gameforge.locale.bookworm.order_refuse_answer = "Warum versuchst du es nicht? Ich wei\223, dass du[ENTER]dazu in der Lage bist! "
gameforge.locale.bookworm.order_say1 = "Will du etwas Bemerkenswertes h\246ren?[ENTER]Ich kann wirklich von mir behaupten, alle B\252cher[ENTER]auf der Welt gelesen zu haben![ENTER]Momentan studiere ich eine Sammlung heiliger[ENTER]Schriften.[ENTER]Es ist das Ger\252cht im Umlauf, dass geheime[ENTER]Informationen und Hinweise dazu, wie[ENTER]man ein wahrer Heiliger wird, im Milgyo-Buch[ENTER]verborgen sind. "
gameforge.locale.bookworm.order_say2 = "Ich w\252rde dieses Buch gern lesen.Was meinst du,[ENTER]kannst du es mir besorgen? Ich w\252rde dich[ENTER]selbstverst\228ndlich belohnen! "
gameforge.locale.bookworm.order_too_late = "Jemand anderes hat mir das Milgyo-Buch bereits[ENTER]gebracht. Du musst es nicht mehr tun. "
gameforge.locale.bookworm.start_find_bookworm_label = "Gehe zu Soon. "
gameforge.locale.bookworm.start_find_bookworm_text_1 = "Gehe zu Soon. "
gameforge.locale.bookworm.start_find_bookworm_text_2 = "Begib dich zu Soon und frag nach dem Milgyo-Buch. "
gameforge.locale.bookworm.start_say = "Kannst du die tiefe Weisheit dieses Schriftst\252cks[ENTER]erkennen? Aus einzelnen Worten formt sich eine[ENTER]wundersch\246ne Geschichte. Man muss sich erst daran[ENTER]gew\246hnen, sich von der Phantasie anderer treiben[ENTER]zu lassen. Nicht jedem gef\228llt diese Vorstellung,[ENTER]aber ich genie\223e es sehr. "
gameforge.locale.bookworm.start_say2 = "Je mehr man hat, desto mehr bekommt man.[ENTER]Je mehr man wei\223, desto mehr Freude findet man im[ENTER]Leben.[ENTER]Ach, wenn ich doch nur bis an mein Lebensende[ENTER]B\252cher lesen k\246nnte... "
gameforge.locale.bookworm.success_thanks = "Oha! Das ist es! Ich werde es mit Freuden lesen! "
gameforge.locale.bookworm.talk = "Sprechen. "
gameforge.locale.bookworm.talk_about_milgyo_book = "Frage nach dem Milgyo-Buch. "
