gameforge.locale.christmas_santa = {}
gameforge.locale.christmas_santa.bye_msg = "Ganz wie du willst. Noch viel Gl\252ck heute![ENTER]Und ein sch\246nes Fest, ho, ho! "
gameforge.locale.christmas_santa.hairdye_msg = "Yang f\252r einen Gegenstand aus[ENTER]diesem Beutel. Es befinden sich verschiedene[ENTER]Materialien zur Gegenstandsverbesserung darin. Du[ENTER]darfst selbst ziehen, aber nicht hinsehen! Was[ENTER]meinst du? "
