gameforge.locale.christmas_santa.not_enough_money = "Es tut mir leid, aber du besitzt nicht genug[ENTER]Yang, um etwas zu kaufen. Ich w\252nsche dir dennoch[ENTER]ein sch\246nes Fest! "
