gameforge.locale.christmas_tree.gain_item_msg = "Such dir einfach einen freien Zweig und h\228ng die[ENTER]Socke auf... Fertig?[ENTER]Dann schlie\223e jetzt deine Augen und warte drei[ENTER]Sekunden.[ENTER][DELAY value;500]. . .[/DELAY][ENTER]Ich hoffe du freust dich \252ber dein Geschenk.[ENTER]Frohe Weihnachten! "
