gameforge.locale.forked_condition = "Wir m\252ssen den Schl\252ssel f\252r das Portal finden,[ENTER]ehe es eines der anderen Reiche tut.[ENTER]Es gilt, die Macht unseres Reiches zu[ENTER]demonstrieren und zu erweitern! "
gameforge.locale.forked_condition2 = "Nun m\252ssen wir nur noch jene ausmerzen, die das[ENTER]heilige Gebiet entweihen. Zum Angriff! "
gameforge.locale.forked_enter = "Teilnehmen "
gameforge.locale.forked_kill_boss = "Ich bin Thorr Sarch! Was wollt ihr schon gegen[ENTER]mich ausrichten? Ich bin nicht tot, sondern werde[ENTER]auferstehen. Heerscharen meiner Krieger werden[ENTER]mir folgen![ENTER]Ihr habt die Reichsschlacht beendet. Alle werden[ENTER]zum Dorf transportiert. "
gameforge.locale.forked_man_chat = "An Reichsschlacht teilnehmen "
gameforge.locale.forked_man_say = "Es wurde ein neues Gebiet entdeckt.[ENTER]Es befindet sich in der Mitte des Kontinents -[ENTER]m\246glicherweise verbindet es sogar alle Reiche.[ENTER]Dort wimmelt es von dunklen Kreaturen. Vielleicht[ENTER]kannst du dich dorthin aufmachen und dich ihnen[ENTER]entgegenstellen?[ENTER]Vernichte sie alle, um den Frieden im Reich[ENTER]wiederherzustellen. "
gameforge.locale.forked_man_say_cant = "He! Es wurde ein neues Gebiet im Inneren des[ENTER]Kontinents entdeckt. M\246glicherweise verbindet es[ENTER]alle Reiche.[ENTER]Sobald die Forschungen dort abgeschlossen sind,[ENTER]kannst du es betreten. "
gameforge.locale.forked_no_enter = "Nicht teilnehmen "
gameforge.locale.forked_open_gate = "Das bisher verschlossene Tor hat sich ge\246ffnet.[ENTER]Auf in das neue Land - wir werden es erobern![ENTER]Alle K\228mpfer werden ins Heilige Land[ENTER]teleportiert. "
gameforge.locale.forked_rule = "Regeln f\252r den Zugang zur Reichsschlacht:[ENTER]1. Wer in diesem Gebiet stirbt, wird ins Dorf[ENTER]teleportiert, kann sich aber vom[ENTER]Schlachtenverwalter sofort wieder hierher bringen[ENTER]lassen.[ENTER]2. Wenn die T\252r zum Heiligen Land ge\246ffnet wurde,[ENTER]wird dieses Gebiet geschlossen.[ENTER]3. Um die T\252r zum Heiligen Land zu \246ffnen, muss[ENTER]der passende Schl\252ssel gefunden werden. "
gameforge.locale.forked_rule_sungzi = "Regeln der Reichsschlacht:[ENTER]1. Das Reich, das die kleinste Anzahl von Siegen[ENTER]gegen ein anderes Reich errungen hat, scheidet[ENTER]als erstes aus.[ENTER]2. Gegnerische Monster erscheinen. Das erste[ENTER]Reich, das eine bestimmte Anzahl Monster t\246tet,[ENTER]hat gewonnen.[ENTER]3. Wenn im Anschluss der Neunschwanz get\246tet[ENTER]wird, endet die Schlacht.[ENTER]4. W\228hrend der Reichsschlacht sind keine[ENTER]Gegenst\228nde zu erbeuten.[ENTER]5. Wer dreimal im Heiligen Land stirbt, kehrt zum[ENTER]Dorf zur\252ck und scheidet aus der Reichsschlacht[ENTER]aus. "
gameforge.locale.fortune_words_1_body = "Wahrhaftig, du stehst in der Gunst der[ENTER]Gl\252cksg\246ttin! Du hast heute <Sehr gro\223es Gl\252ck>![ENTER]Wer von so viel Harmonie gesch\252tzt wird, dem wird[ENTER]am heutigen Tag noch etwas Gutes widerfahren. "
gameforge.locale.fortune_words_1_title = "Sehr gro\223es Gl\252ck! "
gameforge.locale.fortune_words_2_body = "Das ist gut. Wie hei\223t es so sch\246n? Wie man in[ENTER]den Wald hinein ruft, so schallt es heraus. Du[ENTER]hast heute <Gro\223es Gl\252ck>! Ich freue mich f\252r[ENTER]dich. Heute wirst du schon f\252r geringe[ENTER]Anstrengungen viel Gutes zur\252ckbekommen! "
gameforge.locale.fortune_words_2_title = "Gro\223es Gl\252ck! "
gameforge.locale.fortune_words_3_body = "Das ist nicht schlecht. Du hast heute <Etwas[ENTER]Gl\252ck>. Dein Tag wird ein wenig besser laufen als[ENTER]sonst, aber erwarte keine gro\223en Geschenke vom[ENTER]Schicksal! "
gameforge.locale.fortune_words_3_title = "Etwas Gl\252ck. "
gameforge.locale.fortune_words_4_body = "Nicht wirklich gut, aber auch nicht schlecht! Du[ENTER]hast heute <Normales Gl\252ck>. Das bringt dich zwar[ENTER]nicht gro\223artig weiter, aber immerhin hast du[ENTER]kein Pech. Normale Tage sind nicht zu verachten,[ENTER]genie\223e ihn! "
gameforge.locale.fortune_words_4_title = "Normales Gl\252ck. "
gameforge.locale.fortune_words_5_body = "Das Gl\252ck ist dir heute nicht hold. Auch wenn du[ENTER]deine Netze so gewissenhaft wie immer auswirfst,[ENTER]wirst du am heutigen Tag nur wenige Fische[ENTER]fangen. Auf der anderen Seite wirst du aber[ENTER]keinen schlimmen Hunger leiden. Du hast heute[ENTER]<Etwas Pech>! Aber nichts ist besser, als[ENTER]vorbereitet zu sein. Falls du es w\252nscht, kann[ENTER]ich dir einen Talisman verkaufen, der das[ENTER]Schlimmste abwenden wird. Hast du Interesse? "
gameforge.locale.fortune_words_5_title = "Etwas Pech. "
gameforge.locale.fortune_words_6_body = "Heute ist ein schlechter Tag. Ein Tag, an dem[ENTER]selbst gut bestellte Felder kaum Korn abwerfen.[ENTER]Du hast heute <Pech> und musst dich in Acht[ENTER]nehmen, wo du dich auch aufh\228ltst und was du auch[ENTER]tust. Ich k\246nnte dir allerdings helfen und dir[ENTER]einen Talisman verkaufen, damit schlimme Sch\228den[ENTER]abgewendet werden k\246nnen. Hast du Interesse? "
gameforge.locale.fortune_words_6_title = "Pech. "
gameforge.locale.fortune_words_7_body = "Dies ist der schlimmste aller Tage f\252r dich. Die[ENTER]G\246tter haben sich von dir abgewandt, nichts wird[ENTER]dir gelingen k\246nnen. Wenn du Feuer machen willst,[ENTER]wird es regnen und wenn du durstig bist, wird die[ENTER]Sonne auf dich herab brennen. Wie alle anderen[ENTER]wirst du hart arbeiten, aber keine Fr\252chte f\252r[ENTER]deine M\252hen ernten. Es ist <Ganz gro\223es Pech>,[ENTER]das du ertragen musst! Ohne Talisman steht dir[ENTER]eine schwere Zeit bevor. Hast du Interesse daran,[ENTER]einen solchen zu erstehen? "
gameforge.locale.fortune_words_7_title = "Ganz gro\223es Pech. "
