gameforge.locale.monkey_dungeon.notice = "1. Wenn du den Affendungeon betrittst, musst du[ENTER]den obersten Affen innerhalb von 20 Minuten[ENTER]t\246ten. 2. Du darfst keine Schriftrollen zur[ENTER]R\252ckkehr in die Stadt oder zu anderen Zielen[ENTER]verwenden.[ENTER]Viele, die sich nicht an diese Regeln halten,[ENTER]werden in Affen verwandelt. Du solltest dich[ENTER]daher vorsehen. "
gameforge.locale.monkey_dungeon.no_enter = "Nicht betreten "
gameforge.locale.monkey_dungeon.quest_rest_time = "Verbleibende Zeit: "
gameforge.locale.monkey_dungeon.quest_title = "Affendungeon "
gameforge.locale.monster_chat = {}
gameforge.locale.monster_chat_1001_1 = "Sie alle werden den Tod finden! "
gameforge.locale.monster_chat_1001_2 = "Kleine, kleine, kleine St\252cke... "
gameforge.locale.monster_chat_1001_3 = "Kein Entkommen! "
gameforge.locale.monster_chat_1001_4 = "Dein Blut wird den Boden tr\228nken. Stirb! "
gameforge.locale.monster_chat_1001_5 = "Bettle, aber es wird dir nichts n\252tzen! "
gameforge.locale.monster_chat_1001_6 = "Du kannst deine Furcht nicht vor mir verbergen! "
gameforge.locale.monster_chat_1002_1 = "Tod! Tod allen Menschen... "
gameforge.locale.monster_chat_1002_2 = "Ihr armseligen W\252rmer! "
gameforge.locale.monster_chat_1002_3 = "So langsam machst du mich w\252tend... "
gameforge.locale.monster_chat_1002_4 = {}
gameforge.locale.monster_chat_1002_5 = "Dein Blut wird flie\223en, Mensch. "
gameforge.locale.monster_chat_1003_1 = "Tod und Verderben...! "
gameforge.locale.monster_chat_1003_2 = "Hast du schon einmal die Wunden gesehen, die ein Speer rei\223en kann? "
gameforge.locale.monster_chat_1003_3 = "Ja, lauf ruhig davon! Wir werden sehen, wie weit du kommst... "
gameforge.locale.monster_chat_1003_4 = "Allein der Anblick deiner zitternden H\228nde ist diese Begegnung wert... "
gameforge.locale.monster_chat_1003_5 = "Du Abschaum wagst es, mich herauszufordern? "
gameforge.locale.monster_chat_1003_6 = "Der Tod wird zuk\252nftig dein einziger Gef\228hrte sein! "
gameforge.locale.monster_chat_1004_1 = "Deine Seele wird mir geh\246ren, Mensch! "
gameforge.locale.monster_chat_1004_2 = "Ah, Frischfleisch! "
gameforge.locale.monster_chat_1004_3 = "Es sieht aus, als w\252rde heute ein weiterer Mensch hier den Tod finden! "
gameforge.locale.monster_chat_1004_4 = "Leiden sollst du, leiden und all deine Qualen laut herausschreien... "
gameforge.locale.monster_chat_1004_5 = "Denkst du etwa, die l\228cherliche Waffe dort in deiner Hand wird dich sch\252tzen k\246nnen? "
gameforge.locale.monster_chat_1004_6 = "Dein Mut hat dich zu mir gebracht. Nun wird er dich verlassen... "
gameforge.locale.monster_chat_1035_1 = "Sollte ich sterben, wird dich meine Rache ewig verfolgen! "
gameforge.locale.monster_chat_1035_2 = "Ich werde dich langsam sterben lassen, sehr langsam... "
gameforge.locale.monster_chat_1035_3 = "Es wird mir ein Vergn\252gen sein, dich leiden zu lassen. "
gameforge.locale.monster_chat_1035_4 = "Dein K\246rper zittert wie der eines altersschwachen Weibes! "
gameforge.locale.monster_chat_1035_5 = "Ich kann deine Angst riechen, kleiner Mensch. "
gameforge.locale.monster_chat_1035_6 = "Ich denke es ist Zeit, dich um einige K\246rperteile zu erleichtern. "
gameforge.locale.monster_chat_1036_1 = "Ich werde dich in deine pers\246nliche H\246lle schicken! "
gameforge.locale.monster_chat_1036_2 = "Deine Schmerzen werden dich in den Wahnsinn treiben, noch ehe du stirbst... "
gameforge.locale.monster_chat_1036_3 = "Jammere! Flehe! Aber es wird dir nichts n\252tzen. "
gameforge.locale.monster_chat_1036_4 = "Du wirst den schlimmsten Tod erleiden, den du dir vorstellen kannst... "
gameforge.locale.monster_chat_1036_5 = {}
gameforge.locale.monster_chat_1036_6 = "Deine Kraft l\228sst nach. Du stehst bereits an der Schwelle des Todes... "
gameforge.locale.monster_chat_1037_1 = "Bereit, auf ewig in den Hallen des Todes zu wandeln? "
gameforge.locale.monster_chat_1037_2 = "Du solltest dich mit dem Gedanken anfreunden, die ewige Dunkelheit zu begr\252\223en... "
gameforge.locale.monster_chat_1037_3 = "Willkommen in der H\246lle! "
gameforge.locale.monster_chat_1037_4 = "Schrei, soviel du willst! Hier h\246rt dich niemand! "
gameforge.locale.monster_chat_1037_5 = "Wenn du glaubst, mich auf diese Weise t\246ten zu k\246nnen... dann bist du naiver, als du aussiehst! "
gameforge.locale.monster_chat_1037_6 = "Kein \252bler Angriff, aber vor dem Tod wird auch er dich nicht sch\252tzen k\246nnen. "
gameforge.locale.monster_chat_1038_1 = "Sieh dich um, dies ist deine H\246lle! "
gameforge.locale.monster_chat_1038_2 = "Ich werde dir dein Fleisch von den Knochen sch\228len. "
gameforge.locale.monster_chat_1038_3 = "Ich will dich wimmern h\246ren, ehe du stirbst. "
gameforge.locale.monster_chat_1038_4 = "Du wei\223t bereits, dass jegliche Hoffnung vergebens ist, nicht wahr? "
gameforge.locale.monster_chat_1038_5 = {}
gameforge.locale.monster_chat_1038_6 = "Nein, noch stirbst du nicht. Zun\228chst will ich wissen, wie viele Schwerthiebe dein K\246rper verkraften kann... "
gameforge.locale.monster_chat_1039_1 = "Ah, ein neuer Freiwilliger... "
gameforge.locale.monster_chat_1039_2 = "Glaubst du wirklich, auch nur die geringste Chance zu haben? "
gameforge.locale.monster_chat_1039_3 = "Das ist nicht der Boden, der sich bewegt... deine Knie schlottern vor Angst! "
gameforge.locale.monster_chat_1039_4 = "Willkommen an dem Ort, an dem du deinen Tod finden wirst! "
gameforge.locale.monster_chat_1039_5 = "Ich kann die Panik in deinen Augen leuchten sehen. "
gameforge.locale.monster_chat_1039_6 = "Oh, so jung und hilflos... "
gameforge.locale.monster_chat_1040_1 = "Wir sehen jede noch so kleine Bewegung deines K\246rpers. "
gameforge.locale.monster_chat_1040_2 = "Eile? W\252nschst du deinen Tod so sehr herbei? "
gameforge.locale.monster_chat_1040_3 = "Der Tod hat bereits seinen Platz an deiner Seite eingenommen... "
gameforge.locale.monster_chat_1040_4 = "H\246rst du mein Gl\246ckchen l\228uten? Es ist das letzte, das du h\246ren wirst! "
gameforge.locale.monster_chat_1040_5 = "Ich rieche Blut, viel Blut... lange wirst du so nicht mehr \252berleben... "
gameforge.locale.monster_chat_1040_6 = "Du kannst k\228mpfen... oder dich sofort vom Tod umarmen lassen... "
gameforge.locale.monster_chat_1041_1 = "Warum bist du hier, wenn du so sehr an deinem Leben h\228ngst? "
gameforge.locale.monster_chat_1041_2 = "Ah, neue K\246rper, die ich zerschmettern kann! "
gameforge.locale.monster_chat_1041_3 = "Es war deine Entscheidung herzukommen, Mensch! Nun lebe mit den Konsequenzen... "
gameforge.locale.monster_chat_1041_4 = "Unsere Kampfkraft wird niemals nachlassen. Wir k\246nnen nicht sterben! "
gameforge.locale.monster_chat_1041_5 = "Es macht keinen Sinn, uns anzugreifen! Du bist verloren... "
gameforge.locale.monster_chat_1041_6 = "Vielleicht wirst du an Ersch\246pfung sterben... oder an Angst... "
gameforge.locale.monster_chat_1091_1 = "Du hast es bis zu mir geschafft... und ich werde dich nun in den Tod schicken. "
gameforge.locale.monster_chat_1091_2 = "Opfere deine Seele und du kannst einer von uns werden! "
gameforge.locale.monster_chat_1091_3 = "Sieh dich an! Schwach und langsam... "
gameforge.locale.monster_chat_1091_4 = "Dein K\246rper und deine Seele geh\246ren mir! "
gameforge.locale.monster_chat_1091_5 = "Deine Beine zittern! Sieh es ein, du bist dem hier nicht gewachsen... "
gameforge.locale.monster_chat_1091_6 = "Wie lange willst du das noch durchhalten? "
gameforge.locale.monster_chat_1093_1 = "Wer konnte ahnen, dass es etwas Schlimmeres als den Tod gibt? "
gameforge.locale.monster_chat_1093_2 = "Willkommen, Todeshungriger. "
gameforge.locale.monster_chat_1093_3 = "F\252r deinen Leichtsinn wirst du bezahlen. Mit deinem Blut und deiner Seele. "
gameforge.locale.monster_chat_1093_4 = "Nachdem ich deinen K\246rper zerst\246rt habe, wird deine Seele mir geh\246ren! "
gameforge.locale.monster_chat_1093_5 = "Wie lange, denkst du, kannst du gegen mich bestehen? "
gameforge.locale.monster_chat_1093_6 = "Du am\252sierst mich. Deine Angst und deine Hast sind unterhaltsam... "
gameforge.locale.monster_chat_11000_1 = "H\246rt alle zu, die ihr euch Sorgen um eure Zukunft macht! "
gameforge.locale.monster_chat_11000_10 = "Wenn du die Macht der Natur und insbesondere der Blitze erlangen willst, empfehle ich die Lehre der Heilung! "
gameforge.locale.monster_chat_11000_11 = "Das Besondere am Krieger ist seine Einstellung zum Kampf. Konzentriere dich darauf, deinen K\246rper zu trainieren und dich vorzubereiten! "
gameforge.locale.monster_chat_11000_12 = "Die St\228rke des Sura ist die Magie. Arbeite an deiner Intelligenz und Schnelligkeit, aber vernachl\228ssige deine K\246rperkraft nicht! "
gameforge.locale.monster_chat_11000_13 = "Nutze die Eigenschaften der Ninja! Konzentriere dich auf Schnelligkeit und K\246rperkraft! "
gameforge.locale.monster_chat_11000_14 = "Schamanen nutzen Wiederherstellung, Unterst\252tzung und Fernkampfzauber. Daf\252r ist Intelligenz unerl\228sslich! "
gameforge.locale.monster_chat_11000_15 = "Vergiss nicht das Wissen, das du in deiner Ausbildung erh\228ltst! "
gameforge.locale.monster_chat_11000_16 = "Mach eine Ausbildung, wenn du deine Fertigkeiten verbessern willst! "
gameforge.locale.monster_chat_11000_17 = "Fertigkeiten? Du kannst bis zum Level des Meisters aufsteigen, mit zuf\228lliger Verteilung zwischen Level 17 und Level 21! "
gameforge.locale.monster_chat_11000_18 = "Du m\246chtest Gro\223meister werden? Dann ben\246tigst du ein besonderes Fertigkeitsbuch! "
gameforge.locale.monster_chat_11000_19 = "Sobald du ein Fertigkeitsbuch gelesen hast, verschwindet es! "
gameforge.locale.monster_chat_11000_2 = "Alle K\228mpfer bis Level 5, h\246rt mich an! "
gameforge.locale.monster_chat_11000_20 = "Du m\246chtest ein weiteres Fertigkeitsbuch lesen? Dann warte einen Tag. "
gameforge.locale.monster_chat_11000_21 = "Steigere deine Intelligenz, um deine Sura-Fertigkeiten zu verbessern! "
gameforge.locale.monster_chat_11000_22 = "Erlebe die gro\223e Macht eines Sura im Kampf! "
gameforge.locale.monster_chat_11000_23 = "Wei\223t du, wo sich der Tempel der esoterischen Sekte befindet? Er liegt mitten im Tal von Seungryong! "
gameforge.locale.monster_chat_11000_24 = "Die Spinnenh\246hlen sind wieder aufgetaucht. Ihre Eing\228nge liegen in der Yongbi-W\252ste! "
gameforge.locale.monster_chat_11000_25 = "Erledige Auftr\228ge und nutze die Belohnungen zur Verbesserung! "
gameforge.locale.monster_chat_11000_26 = "Angeln? Das klingt gut! Tr\228gst du bereits eine Angelrute und einen K\246der bei dir? "
gameforge.locale.monster_chat_11000_27 = "Suchst du eine gr\246\223ere Herausforderung beim Jagen? Mit der Hilfe eines Portals kannst du zu einem Jagdort gelangen, der deinem Level entspricht! "
gameforge.locale.monster_chat_11000_28 = "Nimm dich vor Feinden aus anderen L\228ndern in Acht. Man kann nie wissen, wann sie einem in den R\252cken fallen! "
gameforge.locale.monster_chat_11000_29 = "Du m\246chtest deine Fertigkeiten erneuern? Dann begib dich zu der alten Frau! Aber sorge daf\252r, dass du genug Yang dabei hast. "
gameforge.locale.monster_chat_11000_3 = "Bewirb dich beim Nahkampf-Lehrer, wenn du als angesehener Angriffskrieger bekannt werden willst! "
gameforge.locale.monster_chat_11000_30 = "Strebe das h\246chste Level an - das des Meisters. So wird dein Name gewiss die Zeit \252berdauern! "
gameforge.locale.monster_chat_11000_31 = "Wenn du eine andere Stadt oder ein Kampfgebiet betreten m\246chtest, dann such auf den Kontinenten nach alten Menschen! "
gameforge.locale.monster_chat_11000_4 = "Wenn du dich in den Fertigkeiten des Kriegers \252ben m\246chtest, gehe und lerne vom Meister der Kampfkunst. "
gameforge.locale.monster_chat_11000_5 = "Wenn du ein Sura werden willst, der magische Schwerter beherrscht, dann w\228hle die Lehre der magischen Waffen! "
gameforge.locale.monster_chat_11000_6 = "Wenn du stark im Einsatz dunkler Zauber werden m\246chtest, begib dich in die Lehre der schwarzen Magie! "
gameforge.locale.monster_chat_11000_7 = "Die Fernkampf-Lehre richtet sich an Ninja, die mindestens Level 5 erreicht haben! "
gameforge.locale.monster_chat_11000_8 = "W\228hle die Nahkampf-Lehre, wenn du in die geheimen R\228nge der Ninja aufsteigen willst! "
gameforge.locale.monster_chat_11000_9 = "Wenn du als Krieger des Drachengottes in die Schlacht ziehen m\246chtet, so w\228hle die g\246ttliche Drachenmacht-Lehre! "
gameforge.locale.monster_chat_11002_1 = "H\246rt alle zu, die Ihr euch Sorgen um eure Gesundheit macht! "
gameforge.locale.monster_chat_11002_10 = "Wenn du die Macht der Natur und insbesondere die Kraft der Blitze beherrschen willst, dann solltest du dich der Heilungs-Lehre zuwenden! "
gameforge.locale.monster_chat_11002_11 = "Das Besondere am Krieger ist seine Art, K\228mpfe anzugehen. Konzentriere dich darauf, die F\228higkeiten deines K\246rpers zu verbessern! "
gameforge.locale.monster_chat_11002_12 = "Die St\228rke des Sura ist die Magie. Arbeite an deiner Intelligenz, Schnelligkeit und K\246rperkraft! "
gameforge.locale.monster_chat_11002_13 = "F\252hre die typischen F\228higkeiten des Ninja auf ein h\246heres Level! Konzentriere dich auf Schnelligkeit und K\246rperkraft! "
gameforge.locale.monster_chat_11002_14 = "Schamanen nutzen Wiederherstellung und Fernkampfzauber zur Unterst\252tzung im Kampf. Daf\252r ist Intelligenz unerl\228sslich! "
gameforge.locale.monster_chat_11002_15 = "Vergiss nicht, was du gelernt hast! "
gameforge.locale.monster_chat_11002_16 = "Tritt eine Lehre an, wenn du deine Fertigkeiten zu verbessern w\252nschst! "
gameforge.locale.monster_chat_11002_17 = "Fertigkeiten? Du kannst bis zum Level des Meisters aufsteigen, mit zuf\228lliger Verteilung zwischen Level 17 und Level 21! "
gameforge.locale.monster_chat_11002_18 = "Du m\246chtest Gro\223meister werden? Dann ben\246tigst du ein besonderes Fertigkeitsbuch! "
gameforge.locale.monster_chat_11002_19 = "Sobald du ein Fertigkeitsbuch gelesen hast, verschwindet es! "
