gameforge.locale.monster_chat_11004_1 = "H\246rt alle zu, die ihr euch um euer Wohlergehen sorgt! "
gameforge.locale.monster_chat_11004_10 = "Wenn du die Macht der Natur und insbesondere die Kraft der Blitze beherrschen willst, dann mache dich mit der Heilungs-Lehre vertraut! "
gameforge.locale.monster_chat_11004_11 = "Das Besondere am Krieger ist seine Art, an den Kampf heran zu gehen. Konzentriere dich darauf, deinen K\246rper zu st\228hlen! "
gameforge.locale.monster_chat_11004_12 = "Die St\228rke des Sura ist die Magie. Verfeinere deine Intelligenz, Schnelligkeit und K\246rperkraft! "
gameforge.locale.monster_chat_11004_13 = "Nutze die F\228higkeiten des Ninja und verbessere deine Kampfkunst! Konzentriere dich daf\252r auf Schnelligkeit und K\246rperkraft! "
gameforge.locale.monster_chat_11004_14 = "Schamanen nutzen Wiederherstellung und Fernkampfzauber zur Unterst\252tzung im Kampf. Daf\252r ist Intelligenz unerl\228sslich! "
