gameforge.locale.monster_chat_1105_1 = "Der gefrorene Zustand ist gut... f\252r mich! "
gameforge.locale.monster_chat_1105_2 = "Der Berg Sohan ist sicherlich der beste Ort! "
gameforge.locale.monster_chat_1105_3 = "Welch sch\246nes Wetter. "
gameforge.locale.monster_chat_1105_4 = "Am Ende wirst du genauso kalt sein wie ich... "
gameforge.locale.monster_chat_1105_5 = "Du kannst ewig leben, wenn nicht das Eis schmilzt. "
gameforge.locale.monster_chat_1105_6 = "Wie, denkst du, wird es sich anf\252hlen, wenn du langsam zu einem St\252ck Eis wirst? "
gameforge.locale.monster_chat_1106_1 = "Menschen...hier?! "
gameforge.locale.monster_chat_1106_2 = "M\252de... aber wach genug f\252r dich... "
gameforge.locale.monster_chat_1106_3 = "Jemand hier, auf meinem Berg? "
gameforge.locale.monster_chat_1106_4 = "Du geh\246rst nicht hierher! "
gameforge.locale.monster_chat_1106_5 = "Verschwinde besser! "
gameforge.locale.monster_chat_1106_6 = "Fremdling... so allein? "
gameforge.locale.monster_chat_1191_1 = "Es ist lange her, dass sich ein erfahrener K\228mpfer in diese Gegend verirrt hat. "
gameforge.locale.monster_chat_1191_2 = "Nichts weiter zu tun als warten und Waffen polieren... "
gameforge.locale.monster_chat_1191_3 = "Sollte ich sie mir vornehmen? "
gameforge.locale.monster_chat_1191_4 = {}
gameforge.locale.monster_chat_1191_5 = "Etwas fehlt. Das gef\228llt mir nicht... "
gameforge.locale.monster_chat_1191_6 = "Ich werde deinen Schmerz rasch beenden - und es ist der letzte, den du f\252hlen wirst! "
gameforge.locale.monster_chat_1301_1 = "Ein Langnacken...! "
gameforge.locale.monster_chat_1301_2 = "Deine bleiche Haut wird gleich noch bleicher werden. "
gameforge.locale.monster_chat_1301_3 = "Du stellst dich mir entgegen? Nun gut! "
gameforge.locale.monster_chat_1301_4 = "Du greifst mich an? Das wirst du nicht \252berleben! "
gameforge.locale.monster_chat_1301_5 = "Schwacher, schwacher Mensch! "
gameforge.locale.monster_chat_1301_6 = "Mal sehen, wieviel du einstecken kannst! "
gameforge.locale.monster_chat_1302_1 = "Entkommen? Denk nicht einmal daran. "
gameforge.locale.monster_chat_1302_2 = "So ist es richtig... komm ruhig n\228her! "
gameforge.locale.monster_chat_1302_3 = "Das Schwert in meiner Hand zittert... "
gameforge.locale.monster_chat_1302_4 = "Du wirst diese Begegnung nicht \252berleben! "
gameforge.locale.monster_chat_1302_5 = "Nun wirst du mein Schwert kennenlernen! "
gameforge.locale.monster_chat_1302_6 = "Schmerzhaft, nicht? "
gameforge.locale.monster_chat_1303_1 = "Selbst das Gras, auf dem du l\228ufst, k\246nnte dich m\246glicherweise t\246ten. "
gameforge.locale.monster_chat_1303_2 = "An deiner Stelle w\228re ich vorsichtig... "
gameforge.locale.monster_chat_1303_3 = "So ist es richtig. Komm ruhig n\228her... "
gameforge.locale.monster_chat_1303_4 = "Du wagst dich in meine N\228he? Nun gut... dann lebe auch mit den Konsequenzen! "
gameforge.locale.monster_chat_1303_5 = "Es wird Zeit, dass du dich von dieser Welt verabschiedest! "
gameforge.locale.monster_chat_1303_6 = "Bedauerst du dein Kommen? "
gameforge.locale.monster_chat_1305_1 = "Wer glaubt, mich bezwingen zu k\246nnen? "
gameforge.locale.monster_chat_1305_2 = "Du? Du willst gegen mich k\228mpfen? "
gameforge.locale.monster_chat_1305_3 = "Greif mich an, wenn du den Mut dazu findest! "
gameforge.locale.monster_chat_1305_4 = "Du denkst doch nicht etwa daran, davonzurennen? "
gameforge.locale.monster_chat_1305_5 = "Du hast die Reichweite meines Schwertes untersch\228tzt. "
gameforge.locale.monster_chat_1305_6 = "F\252rchtest du dich? "
gameforge.locale.monster_chat_1901_1 = "Ich denke, dass du heute durch meine H\228nde sterben wirst. "
gameforge.locale.monster_chat_1901_2 = "Oh, du gef\228llst mir. "
gameforge.locale.monster_chat_1901_3 = "Ah, du willst ein wenig Abwechslung in mein Leben bringen? "
gameforge.locale.monster_chat_1901_4 = "He! Es wird dir nicht helfen, wie ein Schw\228chling davonzulaufen! "
gameforge.locale.monster_chat_1901_5 = "Hat mein Anblick dir bereits das Blut in den Adern gefrieren lassen? "
gameforge.locale.monster_chat_1901_6 = "Willst du nicht noch ein wenig schreien? "
gameforge.locale.monster_chat_20001_1 = "Du wirkst nerv\246s... Keine Sorge, es wird schon nichts explodieren. "
gameforge.locale.monster_chat_20001_2 = "Ab und zu m\246chte ich einfach spazieren gehen. "
gameforge.locale.monster_chat_20001_3 = "Die Zeit vergeht so langsam... Selbst meine Enkel besuchen mich nicht mehr. "
gameforge.locale.monster_chat_20001_4 = "Wenn man alt ist, mangelt es oft an Gesellschaft. "
gameforge.locale.monster_chat_20001_5 = "Meine besten Tage liegen weit hinter mir. "
gameforge.locale.monster_chat_20002_1 = "Die Sonne ist so warm. "
gameforge.locale.monster_chat_20002_2 = "Wunderbares Wetter, um W\228sche zu trocknen, nicht wahr? "
gameforge.locale.monster_chat_20002_3 = "Wo treibt sich nur mein unn\252tzer Ehemann herum? "
gameforge.locale.monster_chat_20002_4 = "Er sch\228mt sich nicht einmal vor seinen Kindern wegen seiner Marotte! Und so etwas schimpft sich Vater... "
gameforge.locale.monster_chat_20002_5 = "B\252cher, immer nur B\252cher! Er geht nicht arbeiten, bringt keinen Yang nach Hause. Er liest einfach nur! "
gameforge.locale.monster_chat_20003_1 = "Na mein Kleines, hast du gut geschlafen? "
gameforge.locale.monster_chat_20003_2 = "Mein kleiner Engel. "
gameforge.locale.monster_chat_20003_3 = "Mein Sonnenschein... "
gameforge.locale.monster_chat_20003_4 = "Was ist denn? Hast du Hunger? "
gameforge.locale.monster_chat_20003_5 = "So ist es richtig... schlaf, mein Kleines. "
gameforge.locale.monster_chat_20004_1 = "Und ein weiterer Tag... "
gameforge.locale.monster_chat_20004_2 = "Wo bekomme ich wohl heute etwas zu essen? "
gameforge.locale.monster_chat_20004_3 = "Es ist immer dasselbe mit diesen Schwerttr\228gern. "
gameforge.locale.monster_chat_20004_4 = "Mal sehen. Vielleicht sollte ich Octavios Lokal einen Besuch abstatten. "
gameforge.locale.monster_chat_20004_5 = "Ach ja, es soll \252brigens kein Krieg mehr toben... "
gameforge.locale.monster_chat_20005_1 = "Die Seele eines T\246pfermeisters flie\223t durch seine Fingerspitzen. "
gameforge.locale.monster_chat_20005_2 = "Seitdem das Land im Chaos versunken ist, treiben sich \252berall K\228mpfer herum. "
gameforge.locale.monster_chat_20005_3 = "Immer nur K\228mpfe, \252berall. "
gameforge.locale.monster_chat_20005_4 = "Ich bete f\252r eine ruhige und friedliche Welt. "
gameforge.locale.monster_chat_20005_5 = "Warum diese Eile? Nimm dir f\252r einen kurzen Augenblick Zeit, um zu entspannen und nachzudenken. "
gameforge.locale.monster_chat_20006_1 = "Oh nein, was soll ich blo\223 machen? "
gameforge.locale.monster_chat_20006_2 = "Ich kann meinen Bruder nirgendwo finden, dabei hatte er mir versprochen, mich hier zu treffen. "
gameforge.locale.monster_chat_20006_3 = "Doch au\223er mir sind hier lediglich bewaffnete Krieger unterwegs. "
gameforge.locale.monster_chat_20006_4 = "Ich vermisse meinen Bruder. "
gameforge.locale.monster_chat_20006_5 = "Hat irgendwer meinen Bruder gesehen? "
gameforge.locale.monster_chat_20007_1 = "Ha, dieses Fleisch ist frisch! "
gameforge.locale.monster_chat_20007_2 = "Wie gut, dass die Leute wieder mehr Fleisch essen. "
gameforge.locale.monster_chat_20007_3 = "Das Gesch\228ft l\228uft gut, aber das Fleisch ist knapp. "
gameforge.locale.monster_chat_20007_4 = "Wann kommt endlich das Fleisch, das wir bestellt haben? "
gameforge.locale.monster_chat_20007_5 = "Wenn es nicht rechtzeitig eintrifft, m\252ssen wir jagen gehen! "
gameforge.locale.monster_chat_20008_1 = "Ich hoffe, dass uns die Kunden bei so einem Wetter das Haus einrennen. "
gameforge.locale.monster_chat_20008_2 = "Oh! Der faule Hund kommt bestimmt bald vorbei und m\246chte etwas essen. "
gameforge.locale.monster_chat_20008_3 = "Armer Kerl! "
gameforge.locale.monster_chat_20008_4 = "Fr\252her war er ein sehr guter Krieger. "
gameforge.locale.monster_chat_20008_5 = "Ich frage mich, warum er nicht mehr k\228mpft? "
gameforge.locale.monster_chat_20009_1 = "Diese jungen Kerle... so lebhaft und voller Tatendrang! "
gameforge.locale.monster_chat_20009_2 = "Die K\228mpfer sehen eindrucksvoll aus, wenn sie Waffen tragen. "
gameforge.locale.monster_chat_20009_3 = "Die Lust am T\246ten w\228chst in diesen Zeiten. "
gameforge.locale.monster_chat_20009_4 = "Lenke dein Herz, fokussiere deinen Verstand und beruhige deine Seele. "
gameforge.locale.monster_chat_20009_5 = "Es gibt kein unfehlbares Rezept f\252r Gl\252ckseligkeit, aber einige einfache Richtlinien, an die man sich halten kann. "
gameforge.locale.monster_chat_20010_1 = "Hier, dies ist ein \228u\223erst n\252tzlicher Gegenstand! "
gameforge.locale.monster_chat_20010_2 = "Ware aus fernen L\228ndern! Sch\246ne, au\223ergew\246hnliche St\252cke! "
gameforge.locale.monster_chat_20010_3 = "Tretet n\228her, Leute! "
gameforge.locale.monster_chat_20010_4 = "Z\252ckt eure Beutel und kauft, Leute! Eine solche Gelegenheit erhaltet ihr nicht noch einmal! "
gameforge.locale.monster_chat_20010_5 = "Es treibt sich Diebesgesindel hier herum. Sie sollen sich von meiner Ware fern halten! "
gameforge.locale.monster_chat_20011_1 = "Das Land ist sehr trocken in den letzten Jahren. "
gameforge.locale.monster_chat_20011_2 = "Die Getreideernte f\228llt nicht mehr so gut aus wie fr\252her. "
gameforge.locale.monster_chat_20011_3 = "Ich frage mich, warum die Saat auf den Feldern verk\252mmert. "
gameforge.locale.monster_chat_20011_4 = "Das Korn ist spr\246de und schmeckt faulig. "
gameforge.locale.monster_chat_20011_5 = "Es ist ein schlechtes Zeichen. Die Landwirtschaft ist die Basis unseres Lebens. "
gameforge.locale.monster_chat_20012_1 = "Reiskuchen! K\246stliche Reiskuchen! "
gameforge.locale.monster_chat_20012_2 = "Ich verkaufe s\252\223e Reiskuchen. "
gameforge.locale.monster_chat_20012_3 = "Das Gesch\228ft l\228uft schlecht in letzter Zeit. "
gameforge.locale.monster_chat_20012_4 = "Vielleicht sollte ich es in einer anderen Stadt versuchen. "
gameforge.locale.monster_chat_20012_5 = "Aber dort drau\223en wimmelt es von wilden Raubtieren... "
gameforge.locale.monster_chat_20013_1 = "An Tagen wie diesem ist ein Boot der beste Ort, an dem du dich aufhalten kannst. "
gameforge.locale.monster_chat_20013_2 = "Perfektes Wetter zum Angeln. "
gameforge.locale.monster_chat_20013_3 = "Jetzt noch einen Knoten... So! Diesen Haken bei\223t mir kein Fisch ab! "
gameforge.locale.monster_chat_20013_4 = "Dieser verdammte B\228r hat meine Angelrute ruiniert. "
gameforge.locale.monster_chat_20013_5 = "Ich sollte mal wieder meine Netze flicken. "
gameforge.locale.monster_chat_20014_1 = "Huh! "
gameforge.locale.monster_chat_20014_2 = "Mach dir wegen mir keine Sorgen. So bin ich eben. "
gameforge.locale.monster_chat_20014_3 = "Ha! "
gameforge.locale.monster_chat_20014_4 = "Was soll ich nur tun, damit sie...  Oh nein, was habe ich da gerade gesagt? "
gameforge.locale.monster_chat_20014_5 = "Ich bin einfach nicht mutig genug. "
gameforge.locale.monster_chat_20015_1 = "Diese Axt leistet mir seit 20 Jahren treue Dienste. "
gameforge.locale.monster_chat_20015_2 = "Sie ist immer noch scharf, wenn auch nicht mehr so gut wie fr\252her. "
gameforge.locale.monster_chat_20015_3 = "Ich m\246chte sie weiterhin verwenden. Dazu muss sie gesch\228rft werden. "
gameforge.locale.monster_chat_20015_4 = "Ich ben\246tige daf\252r spezielle Mineralsteine. "
gameforge.locale.monster_chat_20015_5 = "Aber woher soll ich die nur bekommen? "
gameforge.locale.monster_chat_20016_1 = "Die Kunden rennen mir die T\252r ein. "
gameforge.locale.monster_chat_20016_2 = "Hoffentlich bekomme ich alles rechtzeitig fertig. "
gameforge.locale.monster_chat_20016_3 = "Schlag auf Schlag und nicht beklagt... "
gameforge.locale.monster_chat_20016_4 = "So muss ein Hammer klingen! "
gameforge.locale.monster_chat_20016_5 = "Ganz sch\246n hei\223 hier. "
gameforge.locale.monster_chat_20017_1 = "Mir ist nicht nach Musik. "
gameforge.locale.monster_chat_20017_2 = "Mein Instrument befindet sich in einem f\252rchterlichen Zustand. "
gameforge.locale.monster_chat_20017_3 = "Vielleicht sollte ich mir ein neues Instrument zulegen? "
gameforge.locale.monster_chat_20017_4 = "Mein Instrument ist alt und abgenutzt... Ich liebe alte Dinge! "
gameforge.locale.monster_chat_20017_5 = "Ich muss dringend Ersatz f\252r die gerissenen Saiten finden. "
gameforge.locale.monster_chat_20018_1 = "Ich bin ziemlich besch\228ftigt! "
gameforge.locale.monster_chat_20018_2 = "Jeden Tag treffen weitere Verwundete ein. "
gameforge.locale.monster_chat_20018_3 = "Da bleibt keine Zeit f\252r private Vergn\252gungen! "
gameforge.locale.monster_chat_20018_4 = "Zudem wird die Medizin knapp. "
gameforge.locale.monster_chat_20018_5 = "Wir br\228uchten jemanden, der einige Zutaten besorgt, um mehr Medizin herzustellen. "
gameforge.locale.monster_chat_20019_1 = "Seit 30 Jahren streife ich mit meinem Bogen durch die Berge. "
gameforge.locale.monster_chat_20019_2 = "Auf diese Weise habe ich meine Frau ern\228hrt und drei Kinder gro\223gezogen. "
gameforge.locale.monster_chat_20019_3 = "Es ist ein hartes Leben, aber das ist es wert. "
gameforge.locale.monster_chat_20019_4 = "Gestern ist mir die Bogensehne gerissen. So kann ich nicht jagen gehen und meine Familie nicht ern\228hren. "
gameforge.locale.monster_chat_20019_5 = "Wenn ich diesen Bogen nicht reparieren kann, m\252sste ich mir einen neuen zulegen. Daf\252r reichen aber die Ersparnisse nicht. "
gameforge.locale.monster_chat_20020_1 = "He! Was glotzt du denn so? "
gameforge.locale.monster_chat_20020_2 = "Bleib weg von mir! "
gameforge.locale.monster_chat_20020_3 = "Wie lange werde ich mich wohl noch verstecken m\252ssen? "
gameforge.locale.monster_chat_20020_4 = "Einsam und vergessen sterben ist nicht gerade das, was ich mir w\252nsche. "
gameforge.locale.monster_chat_20020_5 = "Irgendwer muss mir helfen! "
gameforge.locale.monster_chat_20021_1 = "Dieser Tag ist ein Tag wie jeder andere. "
gameforge.locale.monster_chat_20021_2 = "Was kann ich nur tun? "
gameforge.locale.monster_chat_20021_3 = "Nie habe ich gedacht, dass ich so enden w\252rde. "
gameforge.locale.monster_chat_20021_4 = "Ich kann noch immer nicht begreifen, dass er nicht mehr da ist. "
gameforge.locale.monster_chat_20021_5 = "Das hat er nicht verdient. "
gameforge.locale.monster_chat_20022_1 = "Und wieder ein wundervoller Tag. "
gameforge.locale.monster_chat_20022_2 = "Ariyoungs Mann ist verschwunden. "
gameforge.locale.monster_chat_20022_3 = "Ich wollte helfen, aber diese Sturheit... "
gameforge.locale.monster_chat_20022_4 = "W\228re sie meine Frau geworden, h\228tte sie ihr langweiliges Leben hinter sich lassen k\246nnen. "
gameforge.locale.monster_chat_20022_5 = "Vielleicht h\228tte ich ihr meine Gef\252he deutlicher zeigen sollen. "
gameforge.locale.monster_chat_20023_1 = "Oh nein! Was soll ich tun, wenn meine Frau das herausfindet? "
gameforge.locale.monster_chat_20023_2 = "Wenn ich doch nur vom B\252cherlesen leben k\246nnte! "
gameforge.locale.monster_chat_20023_3 = "Jedes Buch entf\252hrt in seine eigene, geheimnisvolle Welt. "
gameforge.locale.monster_chat_20023_4 = "Ich wei\223, ich kann nicht ewig so weitermachen, aber... "
gameforge.locale.monster_chat_20023_5 = "Ich w\252nschte, ich k\246nnte meiner Frau zuliebe etwas \228ndern, aber... "
gameforge.locale.monster_chat_20024_1 = "Na los, streng dich ein wenig mehr an! "
gameforge.locale.monster_chat_20024_2 = "Was tust du da? Geht das nicht schneller? "
gameforge.locale.monster_chat_20024_3 = "Stell dir einfach vor, wie ein Krieger sein Schwert f\252hrt und mach es genauso! "
gameforge.locale.monster_chat_20024_4 = "Wo steckt dieser Trottel denn nun? "
gameforge.locale.monster_chat_20024_5 = "Du willst ein Mann sein? "
gameforge.locale.monster_chat_2091_1 = "Schneiden, schneiden... Haare, H\228lse... "
gameforge.locale.monster_chat_2091_2 = "Ich habe etwas f\252r dich: Den ewigen Schlaf! "
gameforge.locale.monster_chat_2091_3 = "Sch\246n tief einatmen. Keine Sorge, es ist nur Gift! "
gameforge.locale.monster_chat_2091_4 = "Von dir lasse ich nur das Gesicht \252brig! Das gibt eine sch\246ne Dekoration... "
gameforge.locale.monster_chat_2091_5 = {}
gameforge.locale.monster_chat_2091_6 = "Mit Seide umwickelt ergibst du einen sch\246nen Appetithappen f\252r sp\228ter... "
gameforge.locale.monster_chat_2092_1 = "Es sind nicht mehr viele von uns \252brig. "
gameforge.locale.monster_chat_2092_2 = "Es sind nicht die zweibeinigen Wesen, die hier herrschen sollten. "
gameforge.locale.monster_chat_2092_3 = "Wie es aussieht, hat sich jemand in meinem Spinnennetz verfangen. "
gameforge.locale.monster_chat_2092_4 = "Im Grunde bin ich friedlich. Ich mag es nur nicht, gereizt zu werden. "
gameforge.locale.monster_chat_2092_5 = "Ist das alles, was du mir entgegensetzen kannst? "
gameforge.locale.monster_chat_2092_6 = "Niemand hier kann sich mit mir messen! "
gameforge.locale.monster_chat_2104_1 = "Warum sind Menschen innen so nass? Das macht mein Schwert rostig! "
gameforge.locale.monster_chat_2104_2 = "Ist das Gift in deinem Stachel schon vertrocknet? "
gameforge.locale.monster_chat_2104_3 = "Na, wie sieht's jetzt mit dem K\228mpfen aus? "
gameforge.locale.monster_chat_2104_4 = "Schon ersch\246pft von der Hitze? "
gameforge.locale.monster_chat_2104_5 = "Ich liebe es, tote K\246rper im W\252stensand zur\252ckzulassen. "
gameforge.locale.monster_chat_2104_6 = "Du armes Menschlein, so ohne jede Zeremonie im W\252stensand begraben... "
gameforge.locale.monster_chat_2105_1 = "Soll ich dir was verraten? Ich hasse Dreck! "
gameforge.locale.monster_chat_2105_2 = "Es ist ziemlich hei\223, was? "
gameforge.locale.monster_chat_2105_3 = "Dieser Ort ist gef\228hrlich. "
gameforge.locale.monster_chat_2105_4 = {}
gameforge.locale.monster_chat_2105_5 = "Ich erwische dich zwischen den Augenbrauen. "
gameforge.locale.monster_chat_2106_1 = "Es scheint, als g\228be es hier etwas, das ich niederm\228hen kann. "
gameforge.locale.monster_chat_2106_2 = "Ich sehe meine n\228chste Jagdbeute vor mir. "
gameforge.locale.monster_chat_2106_3 = "Das gef\228llt mir, das gef\228llt mir sehr! "
gameforge.locale.monster_chat_2106_4 = "Der da ist sch\246n fett. Der geh\246rt mir! "
gameforge.locale.monster_chat_2106_5 = {}
gameforge.locale.monster_chat_2106_6 = "Ich liebe den Geruch von Blut. "
gameforge.locale.monster_chat_2107_1 = "Wenig zu t\246ten in der letzten Zeit. "
gameforge.locale.monster_chat_2107_2 = "He! Die sind ordentlich fett! "
gameforge.locale.monster_chat_2107_3 = "Das wird dem Anf\252hrer gefallen... "
gameforge.locale.monster_chat_2107_4 = {}
gameforge.locale.monster_chat_2107_5 = "Lass uns das Tanzbein schwingen! "
gameforge.locale.monster_chat_2107_6 = "Dieser Pfeil ist nur f\252r dich. "
gameforge.locale.monster_chat_2108_1 = "Wenn ich einen erwische, werde ich... "
gameforge.locale.monster_chat_2108_2 = "He, was ist denn? "
gameforge.locale.monster_chat_2108_3 = "Glaubst du etwa, ich bin leicht zu besiegen? "
gameforge.locale.monster_chat_2108_4 = "Es ist dein gro\223es Pech, dass du ausgerechnet auf mich getroffen bist! "
gameforge.locale.monster_chat_2108_5 = "Ah, welche Wonne! Das werde ich nie vergessen! "
gameforge.locale.monster_chat_2108_6 = "Vielen Dank auch! "
gameforge.locale.monster_chat_2191_1 = "Ich rieche Menschen. Welch k\246stlicher Geruch! "
gameforge.locale.monster_chat_2191_2 = "So ist es richtig, komm sch\246n her... "
gameforge.locale.monster_chat_2191_3 = {}
gameforge.locale.monster_chat_2191_4 = "Mein Gl\252ck, dass du dich hierher verirrt hast! "
gameforge.locale.monster_chat_2191_5 = "Bleib sofort stehen! "
gameforge.locale.monster_chat_2191_6 = "St\252ck f\252r St\252ck werde ich aus deinem Fleisch bei\223en... "
gameforge.locale.monster_chat_2202_1 = "Komm n\228her, damit ich deine Haut verschmoren lassen kann. "
gameforge.locale.monster_chat_2202_2 = "Du wei\223t, welch Schmerzen gro\223e Hitze ausl\246sen kann? "
gameforge.locale.monster_chat_2202_3 = "Vielleicht sollte ich meine Flammen mit frischem Blut abk\252hlen. "
gameforge.locale.monster_chat_2202_4 = "Dein Blut... lass es mich schmecken. "
gameforge.locale.monster_chat_2202_5 = "Es hat keinen Sinn, sich zur Wehr zu setzen. "
gameforge.locale.monster_chat_2202_6 = "Werde wie ich! Nur Flammen und Hitze. "
gameforge.locale.monster_chat_2204_1 = "Solange ich hier bin, kommt niemand hinein! "
gameforge.locale.monster_chat_2204_2 = "Du wirst l\228stig, um ehrlich zu sein. "
gameforge.locale.monster_chat_2204_3 = {}
gameforge.locale.monster_chat_2204_4 = "Wei\223t du, wo du dich befindest? "
gameforge.locale.monster_chat_2204_5 = {}
gameforge.locale.monster_chat_2204_6 = "Du bist ein recht armseliger Gegner f\252r mich! "
gameforge.locale.monster_chat_2205_1 = "Ein Schwert taugt nur etwas in der Hand eines Kriegers. "
gameforge.locale.monster_chat_2205_2 = "Immer sch\246n das Schwert in der Hand behalten. "
gameforge.locale.monster_chat_2205_3 = "Krieg steht bevor. "
gameforge.locale.monster_chat_2205_4 = "Wir werden k\228mpfen, bis einer von uns den Tod findet! "
gameforge.locale.monster_chat_2205_5 = "Dein Tod kommt, unausweichlich! "
gameforge.locale.monster_chat_2205_6 = "Du sollst langsam sterben. "
gameforge.locale.monster_chat_2206_1 = "Lava ist das Elixier des Lebens. "
gameforge.locale.monster_chat_2206_2 = "Die Lava h\228lt mich am Leben und wird dein Tod sein! "
gameforge.locale.monster_chat_2206_3 = "Ist sie nicht wundersch\246n, diese Welt aus gl\252hender Lava? "
gameforge.locale.monster_chat_2206_4 = "Du wagst es, meine Ruhe zu st\246ren? "
gameforge.locale.monster_chat_2206_5 = "Du solltest verschwinden, wenn dir dein Leben lieb ist. "
gameforge.locale.monster_chat_2206_6 = "Du k\246nntest deine Anwesenheit hier bereuen. "
gameforge.locale.monster_chat_2291_1 = "Ein angenehmer Tag. Alles, was ich will, ist ein wenig Ruhe. "
gameforge.locale.monster_chat_2291_2 = "Es gibt einfach nichts Sch\246neres, als das Feuerland. "
gameforge.locale.monster_chat_2291_3 = "Ein wenig Frischfleich w\228re eine angenehme Abwechslung. "
gameforge.locale.monster_chat_2291_4 = "Du scheinst den Tod zu suchen, sonst w\252rdest du mich nicht st\246ren. "
gameforge.locale.monster_chat_2291_5 = "Bedauerst du dein Auftauchen bereits? "
gameforge.locale.monster_chat_2291_6 = "Es ist zu sp\228t f\252r eine Flucht. Stelle dich deinem Schicksal. "
gameforge.locale.monster_chat_301_1 = "Diese unruhigen Zeiten machen mich nerv\246s. "
gameforge.locale.monster_chat_301_2 = "Vor zwei Tagen wurde ein kleines M\228dchen ganz in der N\228he von wilden Tieren zerfleischt. "
gameforge.locale.monster_chat_301_3 = "Die Wildtiere werden immer aggressiver. Wir sollten so viele wie m\246glich t\246ten. "
gameforge.locale.monster_chat_301_4 = "Ich habe heute keine gute Laune. Fremde sollten mich besser in Ruhe lassen. "
gameforge.locale.monster_chat_301_5 = "Der letzte Krieger, der durch meine Hand gestorben ist, hat um sein Leben gefleht. "
gameforge.locale.monster_chat_302_1 = "Jemand m\252sste etwas gegen diese Steine unternehmen. "
gameforge.locale.monster_chat_302_2 = "Ich traue dem Frieden des Morgens nicht. "
gameforge.locale.monster_chat_302_3 = "Die Spannung in der Luft macht mich unruhig. "
gameforge.locale.monster_chat_302_4 = "Die Pfeilspitzen sind gut geschmiedet. "
gameforge.locale.monster_chat_302_5 = "An deiner Stelle w\228re ich vorsichtig. Der Pfeil zielt auf dein Herz. "
gameforge.locale.monster_chat_302_6 = "Ich sollte hingehen und einige dieser Bestien t\246ten. "
gameforge.locale.monster_chat_303_1 = "Eine gute Kampfausbildung ist in diesen Zeiten notwendig. "
gameforge.locale.monster_chat_303_2 = "Die Soldaten k\246nnen das Chaos im Land nicht mehr bew\228ltigen. "
gameforge.locale.monster_chat_303_3 = "Was starrst du mich so an? "
gameforge.locale.monster_chat_303_4 = "Feiglinge haben schlechte \220berlebenschancen. "
gameforge.locale.monster_chat_303_5 = "\220bersch\228tze dich nicht. "
gameforge.locale.monster_chat_303_6 = "Da scheint dich jemand recht gut trainiert zu haben. "
gameforge.locale.monster_chat_304_1 = "Schon meine Vorfahren haben sich in diesen Gegenden im Kampf behauptet. "
gameforge.locale.monster_chat_304_2 = "Man muss aufmerksam und geschickt sein hier drau\223en. "
gameforge.locale.monster_chat_304_3 = "Denk erst gar nicht daran, meine Zeit zu verschwenden. "
gameforge.locale.monster_chat_304_4 = "Na, wie f\252hlst du dich? Jetzt, wo dein Leben bedroht ist? "
gameforge.locale.monster_chat_304_5 = "Willst du etwa schon aufgeben? "
gameforge.locale.monster_chat_304_6 = "Gleich wirst du leiden. "
gameforge.locale.monster_chat_305_1 = "Oh, Mann! Dieses Schwert sieht gro\223artig aus! "
gameforge.locale.monster_chat_305_2 = "Bleib hartn\228ckig und trainiere deine Kraft! "
gameforge.locale.monster_chat_305_3 = "Glaubst du etwa, du k\246nntest so stark werden wie ich? "
gameforge.locale.monster_chat_305_4 = "Also los, kommen wir zur Sache! "
gameforge.locale.monster_chat_305_5 = "Oh, nein! Ich bin doch nur eine schwache Frau! "
gameforge.locale.monster_chat_305_6 = "Du siehst m\252de aus. Warum gibst du nicht einfach auf? "
gameforge.locale.monster_chat_306_1 = "Was wird Serangyi heute wohl machen? "
gameforge.locale.monster_chat_306_2 = "Mir ist so langweilig. Spiel mit mir! "
gameforge.locale.monster_chat_306_3 = "Ich pers\246nlich mag ja diese Sura-Typen am meisten. "
gameforge.locale.monster_chat_306_4 = "He! Wie w\228r's mit einem Kampf? "
gameforge.locale.monster_chat_306_5 = "Untersch\228tz mich nicht, blo\223 weil ich eine Frau bin! "
gameforge.locale.monster_chat_306_6 = "Schmerz vergeht... "
gameforge.locale.monster_chat_307_1 = "Ich muss hier raus, egal wie. "
gameforge.locale.monster_chat_307_2 = "Wie sicher sind denn die Wohnorte der einzelnen Mitglieder? "
gameforge.locale.monster_chat_307_3 = "M\228dels, Mund halten! "
gameforge.locale.monster_chat_307_4 = "Lass mich dich erledigen. Mit einem einzigen Schlag. "
gameforge.locale.monster_chat_307_5 = "Denk nicht mal dran, zu fliehen. "
gameforge.locale.monster_chat_307_6 = "Also, worauf warten wir? "
gameforge.locale.monster_chat_394_1 = "Nicht vergessen: Alle M\228nner sind Feinde. "
gameforge.locale.monster_chat_394_2 = "Bei einem h\252bschen Gesicht k\246nnen wir ja mal eine Ausnahme machen... "
gameforge.locale.monster_chat_394_3 = "Was, du willst k\228mpfen? "
gameforge.locale.monster_chat_394_4 = "Es wird nicht lange dauern, aber es wird wehtun. "
gameforge.locale.monster_chat_394_5 = "Oh, du scheinst ja richtig Schmerzen zu haben...? "
gameforge.locale.monster_chat_394_6 = "Auf Nimmerwiedersehen! Fahr zur H\246lle! "
gameforge.locale.monster_chat_401_1 = "Und, was treiben sie so im Wei\223en Eid? "
gameforge.locale.monster_chat_401_2 = "Wohin des Wegs? "
gameforge.locale.monster_chat_401_3 = "He! Willst du k\228mpfen? "
gameforge.locale.monster_chat_401_4 = "H\228, h\228, h\228! Du weichst meinen Schl\228gen aus...? "
gameforge.locale.monster_chat_401_5 = "Glaubst du, dass du entkommen kannst? "
gameforge.locale.monster_chat_401_6 = "Hier kommt mein Schlag! "
gameforge.locale.monster_chat_402_1 = "Gott, bin ich m\252de! "
gameforge.locale.monster_chat_402_2 = "He, nette R\252stung! Hat sie viel gekostet? "
gameforge.locale.monster_chat_402_3 = "Immerhin haben wir sch\246nes Wetter. "
gameforge.locale.monster_chat_402_4 = "Oh, du hast dich angestrengt! Gro\223artig! "
gameforge.locale.monster_chat_402_5 = "Was h\228ltst du von meiner Kampfkunst? Gut, was? H\228, h\228, h\228! "
gameforge.locale.monster_chat_402_6 = "Was ist los? Ach so, dich irritiert meine unglaubliche Geschwindigkeit! "
gameforge.locale.monster_chat_403_1 = "Wieso gehe ich nicht jagen? "
gameforge.locale.monster_chat_403_2 = "Heute greift niemand unser Dorf an. "
gameforge.locale.monster_chat_403_3 = "Wenn du k\228mpfen willst, dann k\228mpf! Bastard! "
gameforge.locale.monster_chat_403_4 = "Ha, ha, ha! Was bist du doch f\252r ein Anf\228nger! "
gameforge.locale.monster_chat_403_5 = "Wohin soll ich dir zuerst schie\223en: ins Bein oder in den Arm? "
gameforge.locale.monster_chat_403_6 = "Hier kommt mein Pfeil! "
gameforge.locale.monster_chat_404_1 = "Ich muss demn\228chst mal ins Dorf und \252ben. "
gameforge.locale.monster_chat_404_2 = "Ich f\252hle mich ganz steif. "
gameforge.locale.monster_chat_404_3 = "Was gibt's heute zu essen? "
gameforge.locale.monster_chat_404_4 = "Ich sehe zu, also schrei ruhig so viel du willst. "
gameforge.locale.monster_chat_404_5 = "Zu lange gewartet, hm? Wie w\228r's, wenn du mal dein Schwert schwingst! "
gameforge.locale.monster_chat_404_6 = "Dieses Schwert hat so einen wundervollen Klang! "
gameforge.locale.monster_chat_405_1 = "Dieses Schwert ist startbereit! "
gameforge.locale.monster_chat_405_2 = "Hmm, mal \252berlegen: Wen soll dieses Schwert als Ersten erschlagen... "
gameforge.locale.monster_chat_405_3 = "He! Was glotzt du so? "
gameforge.locale.monster_chat_405_4 = "Zuerst deinen Bauch! "
gameforge.locale.monster_chat_405_5 = "Ich werde eine Schwertscheide aus dir machen! "
gameforge.locale.monster_chat_405_6 = "Du wirst meine Schwertscheide sein! "
gameforge.locale.monster_chat_406_1 = "Ich bin am Verhungern! "
gameforge.locale.monster_chat_406_2 = "Gibt's was zu essen? "
gameforge.locale.monster_chat_406_3 = "Wieso habe ich nach all dem Essen immer noch Hunger? "
gameforge.locale.monster_chat_406_4 = "Jaaaah, stirb! "
gameforge.locale.monster_chat_406_5 = "Mein Bauch wird diesen Kampf entscheiden! "
gameforge.locale.monster_chat_406_6 = "Es ist die Wahl zwischen Himmel und H\246lle! "
gameforge.locale.monster_chat_491_1 = "Ich halte das nicht mehr aus! Es kribbelt \252berall! "
gameforge.locale.monster_chat_491_2 = "Oho, ich sehe da ein paar Schweine! "
gameforge.locale.monster_chat_491_3 = "Was denn, schon am Boden? "
gameforge.locale.monster_chat_491_4 = "Dich erledige ich mit einem einzigen Hieb. "
gameforge.locale.monster_chat_491_5 = "Das wird eine sch\246ne Erinnerung! "
gameforge.locale.monster_chat_491_6 = "Stirb! "
gameforge.locale.monster_chat_492_1 = "Mein K\246rper ist verweichlicht. "
gameforge.locale.monster_chat_492_2 = "Ich sollte mehr trainieren. "
gameforge.locale.monster_chat_492_3 = "Hast Angst, hm? "
gameforge.locale.monster_chat_492_4 = "Nur ein weiteres Opfer f\252r meine m\228chtige Waffe! "
gameforge.locale.monster_chat_492_5 = "Siehst du mein Angriffsmuster? Nein? Dein Pech! "
gameforge.locale.monster_chat_492_6 = "Auch kleine Schnitte beeintr\228chtigt die Gesundheit. Vor allem, wenn sie von einer gro\223en Keule stammen! "
gameforge.locale.monster_chat_493_1 = "Mist, diese H\228nde sind echt unpraktisch. "
gameforge.locale.monster_chat_493_2 = "Was glotzt du denn so? Hast du noch nie jemanden mit einer Eisenhand gesehen? "
gameforge.locale.monster_chat_493_3 = "Leute, ihr geht mir wirklich auf die Nerven. "
gameforge.locale.monster_chat_493_4 = "Soll ich dich zusammenschlagen? Wenn nicht, dann hau ab. Klar soweit? "
gameforge.locale.monster_chat_493_5 = "Pass auf, ich zeig' dir jetzt meinen gro\223en Schlag! "
gameforge.locale.monster_chat_493_6 = "H\246r auf, meine Hand anzustarren! "
gameforge.locale.monster_chat_494_1 = "He, du da! Willst du k\228mpfen? Dann komm her! "
gameforge.locale.monster_chat_494_2 = "Ich denke schon, dass ich verdammt gut aussehe... "
gameforge.locale.monster_chat_494_3 = "Lass uns doch etwas planen! "
gameforge.locale.monster_chat_494_4 = "Wer hat dir erlaubt, dich zu entfernen?! K\228mpf! "
gameforge.locale.monster_chat_494_5 = "Ha, da hast du's! "
gameforge.locale.monster_chat_494_6 = "Gleich bist du tot! "
gameforge.locale.monster_chat_501_1 = "Hey, bleib hier! Spiel mit mir! "
gameforge.locale.monster_chat_501_2 = "Ich k\246nnte etwas Sch\246nes aus deinen Knochen schnitzen... "
gameforge.locale.monster_chat_501_3 = "Wir haben heute noch nicht trainiert. "
gameforge.locale.monster_chat_501_4 = "Oh, was f\252r eine sch\246ne R\252stung! Die will ich haben. "
gameforge.locale.monster_chat_501_5 = "Ab jetzt wird es dir schwer fallen, meine Angriffe zu ignorieren! "
gameforge.locale.monster_chat_501_6 = "Ha, ha, ha! \220berrascht, was? "
gameforge.locale.monster_chat_502_1 = "Sch\246nheit ist nicht alles. "
gameforge.locale.monster_chat_502_2 = "Nicht glotzen, k\228mpfen! "
gameforge.locale.monster_chat_502_3 = "Deine Art, mich anzustarren, missf\228llt mir. Komm mal her! "
gameforge.locale.monster_chat_502_4 = "Es ist eine Ehre, von meiner Hand zu sterben! "
gameforge.locale.monster_chat_502_5 = {}
gameforge.locale.monster_chat_502_6 = "Gro\223artig! "
gameforge.locale.monster_chat_503_1 = "Heda! Finger weg! "
gameforge.locale.monster_chat_503_2 = "Sieht aus, als sei meine Bogensehne durchtrennt. "
gameforge.locale.monster_chat_503_3 = "Mist, diese Idioten sind hier gewesen. "
gameforge.locale.monster_chat_503_4 = "Nicht schlecht. Aber sterben wirst du trotzdem. "
gameforge.locale.monster_chat_503_5 = "Du bist damit einverstanden? Ausgezeichnet! "
gameforge.locale.monster_chat_503_6 = "Hier kommt der Pfeil! "
gameforge.locale.monster_chat_504_1 = "Kommt alle her! "
gameforge.locale.monster_chat_504_2 = "La, lala, ich pfeif' mir ein Lied... "
gameforge.locale.monster_chat_504_3 = "Welch fantastisches Wetter! "
gameforge.locale.monster_chat_504_4 = {}
gameforge.locale.monster_chat_504_5 = "Gut! Ich sch\228tze deine Kampfeslust! "
gameforge.locale.monster_chat_504_6 = "Hierher! Alle zu mir! "
gameforge.locale.monster_chat_601_1 = "Ich bin so ausgehungert! "
gameforge.locale.monster_chat_601_2 = "Ich h\228tte Appetit auf etwas Obst. "
gameforge.locale.monster_chat_601_3 = "Na, zur Not tut's auch ein Fisch. Angriff! "
gameforge.locale.monster_chat_601_4 = "He, nicht wegrennen! Stehen bleiben! "
gameforge.locale.monster_chat_601_5 = "Ich habe gewonnen. Das ist doch offensichtlich. "
gameforge.locale.monster_chat_601_6 = "Siehst du? Das ging daneben, haha! "
gameforge.locale.monster_chat_601_7 = "Du solltest besser aufpassen, haha! "
gameforge.locale.monster_chat_602_1 = "Wo bin ich? "
gameforge.locale.monster_chat_602_2 = "Angenehmes Wetter heute. "
gameforge.locale.monster_chat_602_3 = "Du willst mich zur Strecke bringen? L\228cherlich! "
gameforge.locale.monster_chat_602_4 = "Du bist mein n\228chstes Opfer. "
gameforge.locale.monster_chat_602_5 = "Ganz sch\246n schmerzhaft, was? Na komm, ich mach's kurz. "
gameforge.locale.monster_chat_602_6 = "Schau, wie stark ich bin: Ich kann diese riesige Keule schwingen! "
gameforge.locale.monster_chat_603_1 = "Langweilig! "
gameforge.locale.monster_chat_603_2 = "Mich juckt's \252berall. "
gameforge.locale.monster_chat_603_3 = "Mal sehn, wer schneller ist. "
gameforge.locale.monster_chat_603_4 = "Du hast damit angefangen. Also mach mich nicht verantwortlich f\252r deinen Tod! "
gameforge.locale.monster_chat_603_5 = "Wenn du einmal drin bist, ist alles zu sp\228t. Es gibt kein Entkommen! "
gameforge.locale.monster_chat_603_6 = "Jetzt kommt der letzte Schlag! Danach bist du hin\252ber! "
gameforge.locale.monster_chat_604_1 = "Ich habe ein leckeres neues Gift hergestellt. Wie w\228r's mit einer Kostprobe? "
gameforge.locale.monster_chat_604_2 = "Ich m\246chte sehen, wie es wirkt! Hier, nimm! "
gameforge.locale.monster_chat_604_3 = "He, du! Komm her, ich brauche eine Versuchsperson! "
gameforge.locale.monster_chat_604_4 = "Ich werde dich vergiften! "
gameforge.locale.monster_chat_604_5 = "Ah, sehr gut! Eine Laborrate! "
gameforge.locale.monster_chat_604_6 = "Es macht keinen Spa\223, wenn du zu schnell aufgibst! Wehr dich! "
gameforge.locale.monster_chat_631_1 = "Bleib mal stehen. Ich suche was zum Jagen. "
gameforge.locale.monster_chat_631_2 = "Wenn du so langsam bist, bringt das nichts. Beweg dich! "
gameforge.locale.monster_chat_631_3 = "Mann, hab ich Hunger! "
gameforge.locale.monster_chat_631_4 = "Wie gut, dass ich endlich was zum Jagen gefunden habe! "
gameforge.locale.monster_chat_631_5 = "Lass alle Hoffnung fahren! Mich \252berlebst du nicht! "
gameforge.locale.monster_chat_631_6 = "Jetzt wirst du lernen, was richtige Schmerzen sind! "
gameforge.locale.monster_chat_632_1 = "Laaangweilig! "
gameforge.locale.monster_chat_632_2 = "Ob es hier wohl brauchbare K\246der gibt? "
gameforge.locale.monster_chat_632_3 = "Komm und k\228mpf, wenn du unbedingt willst! "
gameforge.locale.monster_chat_632_4 = "Du willst ein Krieger sein? Na, dann zeig mal was du kannst! "
gameforge.locale.monster_chat_632_5 = {}
gameforge.locale.monster_chat_632_6 = "Renn schnell zur\252ck ins Dorf, wenn du weiterleben willst! "
gameforge.locale.monster_chat_633_1 = "Zu verhungern ist ein ruhmloses Ende. "
gameforge.locale.monster_chat_633_2 = "Sehr gut, sie kommen direkt auf uns zu. "
gameforge.locale.monster_chat_633_3 = "Wie w\228re es mit einem Duell? "
gameforge.locale.monster_chat_633_4 = "Vergleich mich nicht mit diesen Bastarden! "
gameforge.locale.monster_chat_633_5 = "Hier kommt mein Donnerschlag! Ha! "
gameforge.locale.monster_chat_633_6 = "Wer jetzt flieht, ist kein echter Krieger! "
gameforge.locale.monster_chat_634_1 = "Diesmal m\252sste das Gift besser wirken... "
gameforge.locale.monster_chat_634_2 = "Wenn man Hunger hat, sind Flederm\228use ein echter Leckerbissen! "
gameforge.locale.monster_chat_634_3 = "Wie w\228re es mit einem Kampf? "
gameforge.locale.monster_chat_634_4 = "Wenn du mein Gift erstmal im K\246rper hast, gibt es keine Heilung mehr. "
gameforge.locale.monster_chat_634_5 = "Mit meiner Magie werde ich alles niederbrennen, hihihi! "
gameforge.locale.monster_chat_634_6 = "Brenne! H\228, h\228! "
gameforge.locale.monster_chat_635_1 = "Vergiss niemals, dein Schwert zu sch\228rfen. Der n\228chste Kampf kommt schneller als du denkst. "
gameforge.locale.monster_chat_635_2 = "Na, ohnm\228chtig? "
gameforge.locale.monster_chat_635_3 = "Stirb, und erwache im Jenseits! "
gameforge.locale.monster_chat_635_4 = "Mich bezwingen? Bist du sicher? "
gameforge.locale.monster_chat_635_5 = "Stell dich wie ein Mann! "
gameforge.locale.monster_chat_635_6 = "Na komm, ein bisschen noch. "
gameforge.locale.monster_chat_636_1 = "Ha, ich freue mich auf einen sch\246nen Kampf. "
gameforge.locale.monster_chat_636_2 = "K\228mpfen macht Spa\223, haha! "
gameforge.locale.monster_chat_636_3 = "K\228mpfen! Immer und noch mehr! Jahaa! "
gameforge.locale.monster_chat_636_4 = "Ha, sehr gut! Versuch's nochmal! "
gameforge.locale.monster_chat_636_5 = "Sieh, wie mein Schwert wirbelt! "
gameforge.locale.monster_chat_636_6 = "Du wirst es noch bereuen, mich angegriffen zu haben! "
gameforge.locale.monster_chat_636_7 = "So schwach! Wie lachhaft! "
gameforge.locale.monster_chat_637_1 = "Ich will nicht gest\246rt werden. "
gameforge.locale.monster_chat_637_2 = "Geh schlafen. F\252r immer! "
gameforge.locale.monster_chat_637_3 = "Willst du immer noch nicht schlafen? "
gameforge.locale.monster_chat_637_4 = "Es gibt viel zu tun! Los geht's! "
gameforge.locale.monster_chat_637_5 = "Lass dich von meiner Kraft nicht einsch\252chtern, h\228h\228! "
gameforge.locale.monster_chat_637_6 = "Aus dir mach ich Staub! "
gameforge.locale.monster_chat_691_1 = "Sehr gut, starke Gegner halten l\228nger! Wehr dich! "
gameforge.locale.monster_chat_691_2 = "Was? Hast du ein Problem mit meinem Bruder? "
gameforge.locale.monster_chat_691_3 = "Vergleich mich nicht mit diesem Nichtsk\246nner. "
gameforge.locale.monster_chat_691_4 = "Du gef\228llst ihm nicht! Und mir gef\228llst du auch nicht! "
gameforge.locale.monster_chat_691_5 = "Lass uns k\228mpfen. "
gameforge.locale.monster_chat_691_6 = "Bis zum Tod! "
gameforge.locale.monster_chat_701_1 = "Schau, ein Schmetterling! Wie sch\246n! "
gameforge.locale.monster_chat_701_2 = "Siehst du nicht die Wahrheit von Himmel und Erde? "
gameforge.locale.monster_chat_701_3 = "Sp\228ter ist zu sp\228t. Du musst jetzt glauben! "
gameforge.locale.monster_chat_701_4 = "Glaub an die Lehre der Esoteriker! "
gameforge.locale.monster_chat_701_5 = "Alle Zweifler m\252ssen sterben! "
gameforge.locale.monster_chat_701_6 = "Erlange Erleuchtung in den Armen des Todes! "
gameforge.locale.monster_chat_702_1 = "Die Wahrheit des esoterischen Glaubens liegt im Verst\228ndnis der Ordnung des Himmels. "
gameforge.locale.monster_chat_702_2 = "Die Philosophie des esoterischen Glaubens ist die Ordnung des Himmels. "
gameforge.locale.monster_chat_702_3 = "Esoterische Wahrheit, Wahrheit des Tigergottes, Sabaha Sabaha. "
gameforge.locale.monster_chat_702_4 = "Du wagst es, an der Wahrheit von Himmel und Erde zu zweifeln? "
gameforge.locale.monster_chat_702_5 = {}
gameforge.locale.monster_chat_702_6 = "Sp\252r meine Krallen! "
gameforge.locale.monster_chat_703_1 = "Erst, wenn die Wahrheit des Tigergottes in Ewigkeit erklingt, endet alles Leid. "
gameforge.locale.monster_chat_703_2 = "Die Wahrheit des esoterischen Glaubens liegt im Verst\228ndnis der Ordnung des Himmels. "
gameforge.locale.monster_chat_703_3 = "Sabaha Sabaha. Sende uns Verst\228ndnis. "
gameforge.locale.monster_chat_703_4 = "Du solltest nicht zweifeln! "
gameforge.locale.monster_chat_703_5 = "Empfange den Donner des Himmels! "
gameforge.locale.monster_chat_703_6 = "Ein Hieb des Gerichts! "
gameforge.locale.monster_chat_704_1 = "Die Wahrheit des esoterischen Glaubens liegt im Verst\228ndnis der Ordnung des Himmels. "
gameforge.locale.monster_chat_704_2 = "Esoterische Wahrheit, Wahrheit des Tigergottes, Sabaha Sabaha. "
gameforge.locale.monster_chat_704_3 = "Du h\228ltst mich f\252r einen Clown, oder? Mal sehn wie lange! "
gameforge.locale.monster_chat_704_4 = "Der Anf\252hrer unserer Sekte ist ein Heiliger. Er steht \252ber allen Lebewesen! "
gameforge.locale.monster_chat_704_5 = "Brenn im H\246llenfeuer! "
gameforge.locale.monster_chat_704_6 = "So eine gro\223e Stimmgabel hast du noch nie gesehen, was? "
gameforge.locale.monster_chat_705_1 = "Esoterische Wahrheit, Wahrheit des Tigergottes, Sabaha Sabaha. "
gameforge.locale.monster_chat_705_2 = "Die Wahrheit des esoterischen Glaubens liegt im Verst\228ndnis der Ordnung des Himmels. "
gameforge.locale.monster_chat_705_3 = "Nur weil ich schmaler bin als meine Br\252der, lasse ich mir noch lange nicht alles gefallen! "
gameforge.locale.monster_chat_705_4 = "Ewiger Schmerz und immerw\228hrende Dunkelheit erwarten dich! "
gameforge.locale.monster_chat_705_5 = {}
gameforge.locale.monster_chat_705_6 = "Dies ist nicht das Ende. Im Gegenteil: Es kann nur besser werden. "
gameforge.locale.monster_chat_706_1 = "Wir wollen nur Frieden und Ruhe! Bitte! "
gameforge.locale.monster_chat_706_2 = "Wenn Angst dich beherrscht, vertrau auf die Wahrheit des Tigergottes. "
gameforge.locale.monster_chat_706_3 = "Die Wahrheit des esoterischen Glaubens liegt in Ordnung und Verst\228ndnis des Himmels. "
gameforge.locale.monster_chat_706_4 = "Lasst uns gemeinsam zur H\246lle fahren! "
gameforge.locale.monster_chat_706_5 = "Du bleibst hier! "
gameforge.locale.monster_chat_706_6 = "Ich werde dir alles um den Hals legen, was ich besitze! "
gameforge.locale.monster_chat_707_1 = "Ich flehe dich an, rette uns! "
gameforge.locale.monster_chat_707_2 = "Die Wahrheit des esoterischen Glaubens liegt im Verst\228ndnis der Ordnung des Himmels. "
gameforge.locale.monster_chat_707_3 = "Esoterische Wahrheit, Wahrheit des Tigergottes, Sabaha Sabaha. "
gameforge.locale.monster_chat_707_4 = "Das Tor zur H\246lle steht weit offen. Hinein mit dir! "
gameforge.locale.monster_chat_707_5 = "Ich warne dich: Zwing mich nicht, das Brett einzusetzen! "
gameforge.locale.monster_chat_707_6 = "Ich habe gesehen, dass du sterben wirst! "
gameforge.locale.monster_chat_791_1 = "Lass mich \252berlegen: Wie kann ich dir in wenigen Worten die Ordnung des Himmels und der Erde erkl\228ren? "
gameforge.locale.monster_chat_791_2 = "Ich h\246re die Ges\228nge der Gl\228ubigen. "
gameforge.locale.monster_chat_791_3 = "So ist es recht: Bereue und du wirst errettet werden. "
gameforge.locale.monster_chat_791_4 = "Du wirst ewigen Schmerz erdulden m\252ssen, wenn du weiter an der wahren Lehre zweifelst. "
gameforge.locale.monster_chat_791_5 = "Lass mich dich weiter unterweisen. "
gameforge.locale.monster_chat_791_6 = "Du darfst es nicht als Schmerz ansehen. Betrachte es als Lehrstunde. "
gameforge.locale.monster_chat_901_1 = "Ich bin vielleicht nicht sch\246n, aber ich hab jede Menge Spa\223, hihihi! "
gameforge.locale.monster_chat_901_2 = "Du musst werden wie wir! "
gameforge.locale.monster_chat_901_3 = "Komm zu uns, hihi! "
gameforge.locale.monster_chat_901_4 = "Haaa, haha! "
gameforge.locale.monster_chat_901_5 = "Und los geht's! "
gameforge.locale.monster_chat_903_1 = "Das ist die H\246lle! "
gameforge.locale.monster_chat_903_2 = "Ahhhhh! "
gameforge.locale.monster_chat_903_3 = "Wir k\246nnen das nicht alleine durchstehen! Niemals! "
gameforge.locale.monster_chat_903_4 = "Auch du sollst diesen Schmerz schmecken! "
gameforge.locale.monster_chat_903_5 = "Was h\228ltst du von einem Tausch? Du gibst mir deine Seele und ich gebe dir mein Leid! "
gameforge.locale.monster_chat_903_6 = "Gleich wirst du ewigen Frieden finden! "
gameforge.locale.monster_chat_904_1 = "Oh, dieser Schmerz! Dieser Schmerz! "
gameforge.locale.monster_chat_904_2 = "Ahh, verdammt! Mein Arm brennt! "
gameforge.locale.monster_chat_904_3 = "Warum m\252ssen wir so leiden? Was haben wir getan? "
gameforge.locale.monster_chat_904_4 = "Komm schon, so schlimm ist die Krankheit gar nicht! "
gameforge.locale.monster_chat_904_5 = {}
gameforge.locale.monster_chat_904_6 = "Ahhhh! "
gameforge.locale.monster_chat_905_1 = "Ahhhhh! "
gameforge.locale.monster_chat_905_2 = "Ich schlag dich toooot! "
gameforge.locale.monster_chat_905_3 = "Nicht nur zusehen. Mitmachen! "
gameforge.locale.monster_chat_905_4 = "Lass uns Freunde sein! "
gameforge.locale.monster_chat_905_5 = "Du bist schon infiziert. "
gameforge.locale.monster_chat_905_6 = "Jetzt bist du mein Freund. "
gameforge.locale.monster_chat_906_1 = "Hihihi, chrrn! "
gameforge.locale.monster_chat_906_2 = "Komm nur her und spie\223 dich auf meinen Pfeil. "
gameforge.locale.monster_chat_906_3 = "Du wirst mir langsam l\228stig... "
gameforge.locale.monster_chat_906_4 = "Ich werde dich mit der r\228tselhaften Krankheit anstecken. "
gameforge.locale.monster_chat_906_5 = "K\246stlicher Geruch! "
gameforge.locale.monster_chat_906_6 = "Stirb! "
gameforge.locale.monster_chat_907_1 = "Und wenn ich einen anderen Erreger finde... "
gameforge.locale.monster_chat_907_2 = "Har, har! Das wird ein Spa\223! "
gameforge.locale.monster_chat_907_3 = "Hmm, Peitsche oder Greifer...? "
gameforge.locale.monster_chat_907_4 = "Ahhhhh, jaaaaa! "
gameforge.locale.monster_chat_907_5 = "Lass mich diesen Erreger auf dich \252bertragen! "
gameforge.locale.monster_chat_907_6 = "Diesen hartn\228ckigen Erreger der r\228tselhaften Krankheit! "
gameforge.locale.need_item_postfix = "= Der ben\246tigte Gegenstand. "
