gameforge.locale.oldwoman = {}
gameforge.locale.oldwoman.not_enough_money = "Du hast nicht genug Yang! "
gameforge.locale.oldwoman.no_matter = "Ich habe nichts mit dir zu schaffen! "
gameforge.locale.oldwoman.skill_reset1 = "Wie ich sehe, hast du trotz deiner jungen Jahre[ENTER]schon Einiges erlebt. Armes Ding![ENTER][DELAY value;150] . . . [/DELAY][ENTER]Wei\223t du was? Lass mich deine Fertigkeitspunkte[ENTER]zur\252cksetzen. Dann kannst du neu \252ber die beste[ENTER]Verteilung entscheiden.[ENTER]Nat\252rlich hat das seinen Preis,[ENTER]n\228mlich  "
gameforge.locale.oldwoman.skill_reset2 = "Yang. M\246chtest du sie zur\252cksetzen? Diese[ENTER]Erfahrung ist momentan im Sonderangebot, also[ENTER]\252berleg es dir. "
gameforge.locale.oldwoman.skill_reset_no = "Danke. Sp\228ter vielleicht. "
gameforge.locale.oldwoman.skill_reset_ok = "In Ordnung. "
gameforge.locale.old_pirate = {}
gameforge.locale.old_pirate.accept_ask = "Alter Pirat:[ENTER]Wenn du Zeit f\252r solches Gefasel hast,[ENTER]hast du auch Zeit, um zum Arzt zu gehen! "
gameforge.locale.old_pirate.accept_failure_info_label = "Zur\252ck zum alten Piraten "
gameforge.locale.old_pirate.accept_failure_info_text_1 = "Kehr zum alten Piraten zur\252ck. "
gameforge.locale.old_pirate.accept_failure_info_text_2 = "Sag dem alten Piraten, dass du die Arznei nicht[ENTER]besorgen konntest. "
gameforge.locale.old_pirate.accept_failure_say_1 = "Kehr zum alten Piraten zur\252ck. "
gameforge.locale.old_pirate.accept_failure_say_2 = "Ich kann die Arznei nicht finden![ENTER]Was soll ich nur dem alten Piraten sagen? "
gameforge.locale.old_pirate.accept_success_info_label = "Bring dem alten Piraten die Arznei "
gameforge.locale.old_pirate.accept_success_info_text_1 = "Bring dem alten Piraten die Arznei. "
gameforge.locale.old_pirate.accept_success_info_text_2 = "Bring dem alten Piraten die Arznei und hol dir[ENTER]eine Belohnung. "
gameforge.locale.old_pirate.accept_success_say_1 = "Ich habe die Arznei. "
gameforge.locale.old_pirate.accept_success_say_2 = "Ich habe die Arznei f\252r den alten Piraten. Ich[ENTER]bringe sie ihm. "
gameforge.locale.old_pirate.baekgo_accept_ask = "Baek-Go:[ENTER]Du hast noch nichts gefunden?[ENTER]Wir m\252ssen die Krankheit aufhalten, bevor sie[ENTER]sich im ganzen Dorf ausbreitet! Beeil dich! "
gameforge.locale.old_pirate.baekgo_accept_failure_info_label = "Zur\252ck zu Baek-Go "
gameforge.locale.old_pirate.baekgo_accept_failure_info_text_1 = "Geh zur\252ck zu Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_failure_info_text_2 = "Erkl\228re Baek-Go, dass du keine Probe des Erregers[ENTER]der r\228tselhaften Krankheit finden konntest. "
gameforge.locale.old_pirate.baekgo_accept_failure_say_1 = "Kehre zur\252ck zu Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_failure_say_2 = "Ich kann keine Probe des Erregers der[ENTER]r\228tselhaften Krankheit finden! Was soll ich nur[ENTER]Baek-Go sagen? "
gameforge.locale.old_pirate.baekgo_accept_success_info_label = "Bring die Probe zu Baek-Go "
gameforge.locale.old_pirate.baekgo_accept_success_info_text_1 = "Bring die Probe des Erregers der r\228tselhaften[ENTER]Krankheit zu Baek-Go. "
gameforge.locale.old_pirate.baekgo_accept_success_info_text_2 = "Gib ihm die Probe des Erregers der r\228tselhaften[ENTER]Krankheit und erhalte die Arznei f\252r den alten[ENTER]Piraten. "
gameforge.locale.old_pirate.baekgo_accept_success_say_1 = "Ich habe eine Probe des Erregers der r\228tselhaften[ENTER]Krankheit. "
gameforge.locale.old_pirate.baekgo_accept_success_say_2 = "Ich habe eine Probe des Erregers der r\228tselhaften[ENTER]Krankheit. Ich sollte sie zu Baek-Go bringen. "
gameforge.locale.old_pirate.baekgo_do_you_get_the_virus = "Ich wei\223 noch nicht, was hinter der r\228tselhaften[ENTER]Krankheit steckt. "
gameforge.locale.old_pirate.baekgo_iv_got_the_virus = "Ich habe den Erreger der r\228tselhaften Krankheit[ENTER]entdeckt. "
gameforge.locale.old_pirate.baekgo_order_find_virus_label = "T\246te alle Infizierten "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_1 = "T\246tet alle, die sich mit der r\228tselhaften[ENTER]Krankheit angesteckt haben! "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_2 = "T\246te jene, die den Erreger der r\228tselhaften[ENTER]Krankheit in sich tragen, und bring eine Probe[ENTER]des Erregers zu Baek-Go. Er wird eine Arznei f\252r[ENTER]den alten Piraten herstellen. "
gameforge.locale.old_pirate.baekgo_order_too_late = "Baek-Go:[ENTER]Jemand anderes hat mir bereits eine Probe des[ENTER]Erregers gebracht. Ich habe dem alten Piraten die[ENTER]Arznei geschickt, und es sollte ihm wieder gut[ENTER]gehen. "
gameforge.locale.old_pirate.baekgo_start_say = "Baek-Go:[ENTER]Er hatte nur einmal Kontakt zu einer angesteckten[ENTER]Person, und dann begann seine Wunde zu eitern und[ENTER]juckte?! "
gameforge.locale.old_pirate.baekgo_start_say2 = "Baekgo:[ENTER]Du meine G\252te! Ich bin mir fast sicher, dass er[ENTER]an der r\228tselhaften Krankheit erkrankt ist! Wenn[ENTER]er nicht behandelt wird, breitet sich die[ENTER]Krankheit im ganzen Dorf aus! "
gameforge.locale.old_pirate.baekgo_start_say3 = "Baek-Go:[ENTER]Er darf niemanden anstecken! Du musst ihn sofort[ENTER]behandeln. Daf\252r brauchen wir eine Probe des[ENTER]Erregers der r\228tselhaften Krankheit. Diese Probe[ENTER]kannst du von Kranken erhalten, die in gro\223er[ENTER]Zahl auf dem Berg Sohan im Norden anzutreffen[ENTER]sind. "
gameforge.locale.old_pirate.baekgo_success_say = "Baek-Go:[ENTER]Du hast es geschafft! Warte einen Augenblick auf[ENTER]die Arznei! [DELAY value;1000]Ich habe das so rasch hergestellt, dass ich nicht[ENTER]wei\223, ob es wirkt. Zumindest wird es ihm besser[ENTER]gehen. Bring ihm dieses Medikament so schnell wie[ENTER]m\246glich. "
gameforge.locale.old_pirate.baekgo_talk = "Der alte Pirat schickt mich. "
gameforge.locale.old_pirate.baekgo_talk_about_old_pirate = "Die Krankheit des alten Piraten "
gameforge.locale.old_pirate.complete_say = "Alter Pirat:[ENTER]Es juckt immer noch. Aber ich f\252hle mich schon[ENTER]viel besser. So kann ich wohl leben. "
gameforge.locale.old_pirate.do_you_get_the_medicine = "Ich habe die Medizin noch nicht. "
gameforge.locale.old_pirate.do_you_mean_this_medicine = "Hier ist das Heilmittel! "
gameforge.locale.old_pirate.etc_shop_start_say = "Gemischtwarenh\228ndlerin:[ENTER]Der alte Pirat? Nat\252rlich kenne ich ihn. Du[ENTER]sprichst von diesem ewig fluchenden Kerl, der[ENTER]sich dauernd kratzt, nicht wahr? Er kommt oft[ENTER]vorbei, um ein fl\252ssiges Heilmittel zu kaufen. Er[ENTER]hat schon viele tausend Yang f\252r das rote[ENTER]Heilmittel ausgegeben. "
gameforge.locale.old_pirate.etc_shop_start_say2 = "Gemischtwarenh\228ndlerin:[ENTER]Woher um alles in der Welt nimmt er so viel Yang,[ENTER]wenn er nicht einmal arbeitet? Ich habe ihm schon[ENTER]mehrfach gesagt, er soll sich von einem Arzt[ENTER]untersuchen lassen, aber er h\246rt nicht auf mich.[ENTER]Das rote Heilmittel lindert nur die Symptome und[ENTER]heilt nicht die Krankheit. Ich f\252rchte, es wird[ENTER]b\246se mit ihm enden. "
gameforge.locale.old_pirate.etc_shop_talk_about_old_pirate = "Kennst du den alten Piraten? "
gameforge.locale.old_pirate.order_accept = "Ich helfe dir. "
gameforge.locale.old_pirate.order_accept_answer = "Alter Pirat:[ENTER]Gro\223artig. Viel Gl\252ck![ENTER]Der Arzt ist vermutlich in der Stadt. "
gameforge.locale.old_pirate.order_find_medicine_label = "Arznei f\252r den alten Piraten "
gameforge.locale.old_pirate.order_find_medicine_text_1 = "Besorge eine Arznei f\252r den alten Piraten. "
gameforge.locale.old_pirate.order_find_medicine_text_2 = "Geh zu Baek-Go in der Stadt und frage ihn nach[ENTER]einer Arznei f\252r den alten Piraten. "
gameforge.locale.old_pirate.order_refuse = "Bedaure, ich kann nicht. "
gameforge.locale.old_pirate.order_refuse_answer = "Alter Pirat:[ENTER]Na, dann hab' ich dir nichts mehr zu sagen! "
gameforge.locale.old_pirate.order_say1 = "Alter Pirat:[ENTER]Verflucht! Was willst du von mir? Mist! Diese[ENTER]Ramschladenbesitzerin hat dir was erz\228hlt, hm?[ENTER]Ja, was sie sagt, stimmt. Aber ich hab keine[ENTER]Zeit, zum Arzt zu gehen. Ich habe so viele[ENTER]Feinde! "
gameforge.locale.old_pirate.order_say2 = "Alter Pirat:[ENTER]Man wei\223 nie, ob so ein Bastard nicht pl\246tzlich[ENTER]vor einem steht und einfach zusticht! Aber es[ENTER]juckt so schrecklich, dass ich es wirklich nicht[ENTER]mehr aushalte! Wie sieht es aus? Kannst du f\252r[ENTER]mich zum Arzt gehen und eine Arznei gegen den[ENTER]Juckreiz besorgen? Wenn du die Arznei besorgst,[ENTER]werde ich dich gut belohnen. "
gameforge.locale.old_pirate.order_too_late = "Alter Pirat:[ENTER]Jemand anderes hat mir die Arznei bereits[ENTER]besorgt. Tja, dann gibt's eben auch keine[ENTER]Belohnung f\252r dich. "
gameforge.locale.old_pirate.start_find_old_pirate_label = "Geh zum alten Piraten "
gameforge.locale.old_pirate.start_find_old_pirate_text_1 = "Geh zum alten Piraten. "
gameforge.locale.old_pirate.start_find_old_pirate_text_2 = "Geh zum alten Piraten und frag ihn, wieso er[ENTER]nicht zum Arzt geht. "
gameforge.locale.old_pirate.start_say = "Alter Pirat:[ENTER]Es juckt mich \252berall! H\228tte nicht mit diesem[ENTER]Kerl zusammensto\223en d\252rfen. War nur eine einzige[ENTER]Ber\252hrung! Seither eitert die Stelle und mein[ENTER]ganzer K\246rper juckt! Es ist, als w\252rde ich bei[ENTER]lebendigem Leibe verfaulen. Schweinehund! "
gameforge.locale.old_pirate.success_thanks = "Alter Pirat:[ENTER]Was? Ich hab' mich mit der r\228tselhaften[ENTER]Krankheit angesteckt?! Und das ist das n\246tige[ENTER]Medikament? Vielen, vielen Dank! Du hast mir[ENTER]vermutlich das Leben gerettet. Ich wei\223 das zu[ENTER]sch\228tzen. "
gameforge.locale.old_pirate.talk = "Bist du der alte Pirat? "
gameforge.locale.old_pirate.talk_about_medicine = "Warum gehst du nicht zum Arzt? "
gameforge.locale.questscroll = {}
gameforge.locale.questscroll.exist = "Anderer Auftrag ist bereits in Arbeit. "
gameforge.locale.questscroll.finish = "Auftrag abgeschlossen![ENTER]Folgende Belohnung erhalten: "
