gameforge.locale.questscroll5 = {}
gameforge.locale.questscroll5.mission_10_hunt = "Marsch der hungernden B\228ren "
gameforge.locale.questscroll5.mission_10_mis = "Erlege 25 Schwarzb\228ren und 25 Grizzlys. "
gameforge.locale.questscroll5.mission_10_text = "Oh, bitte hilf uns. In letzter Zeit pl\252ndert eine[ENTER]zunehmende Zahl Grizzlyb\228ren und Schwarzb\228ren[ENTER]unsere Bienenst\246cke und Plantagen. Bitte hilf uns[ENTER]und t\246te die Untiere, sonst verhungern wir! "
gameforge.locale.questscroll5.mission_11_hunt = "Der Sturm der Blauw\246lfe "
gameforge.locale.questscroll5.mission_11_mis = "Erlege 35 Blauw\246lfe und 25 Alpha-Blauw\246lfe. "
gameforge.locale.questscroll5.mission_11_text = "Hast du schon vom Sturm der Blauw\246lfe geh\246rt? Das[ENTER]bezieht sich auf die Untaten der Blauw\246lfe in[ENTER]letzter Zeit. Sie vernichten alles, was ihnen im[ENTER]Wege ist, als w\228ren sie ein Sturm aus Pelz und[ENTER]Z\228hnen. Kannst du diesen Sturm b\228ndigen? "
gameforge.locale.questscroll5.mission_12_hunt = "Vertreiben der wei\223en Armee "
gameforge.locale.questscroll5.mission_12_mis = "T\246te 20 Wei\223er-Eid Kommandantinnen. "
gameforge.locale.questscroll5.mission_12_text = "In letzter Zeit hat die Armee des Wei\223en-Eides[ENTER]uns sehr zu schaffen gemacht. Sie entf\252hrt oft[ENTER]fahrende H\228ndler und richtet im Dorf Verw\252stungen[ENTER]an. Bitte halte sie auf. Schalte Mitglieder der[ENTER]Armee und ihre Anf\252hrerinnen aus. "
gameforge.locale.questscroll5.mission_13_hunt = "Unruhiger schwarzer Wind "
gameforge.locale.questscroll5.mission_13_mis = "T\246te 25 Jak-To und 25 To-Su der Schwarzwindbande. "
gameforge.locale.questscroll5.mission_13_text = "Es hei\223t neuerdings, dass die Schwarzwindbande[ENTER]sich anschickt, das Land in einem einzigen[ENTER]Handstreich zu \252bernehmen.[ENTER]Bevor sie gen\252gend Truppen rekrutieren k\246nnen,[ENTER]sollten wir sie ihrer F\252hrung berauben.[ENTER]Ich bitte dich: Schalte ihre Anf\252hrer aus! "
gameforge.locale.questscroll5.mission_14_hunt = "Gro\223er Aufstand der Orks 1 "
gameforge.locale.questscroll5.mission_14_mis = "T\246te 30 Stolze Orks und 30 Stolze Ork-Sp\228her. "
gameforge.locale.questscroll5.mission_14_text = "Geheime Informationen legen die Vermutung nahe,[ENTER]dass die Anf\252hrer der Orks im Tal von Seungryong[ENTER]an Weltherrschaftspl\228nen arbeiten. Schau dich[ENTER]dort bitte einmal um und \252berpr\252fe die[ENTER]Richtigkeit dieser Informationen. Und damit sich[ENTER]die Reise lohnt, k\246nntest du gleich noch ein paar[ENTER]Orks aus dem Weg schaffen. "
gameforge.locale.questscroll5.mission_15_hunt = "\220berfall der Wilden "
gameforge.locale.questscroll5.mission_15_mis = "T\246te 30 Wilde Infanteristen und 30 Wilde[ENTER]Ergebene. "
gameforge.locale.questscroll5.mission_15_text = "Wir haben einen Spion der Wilden geschnappt und[ENTER]ihm wichtige Informationen entlockt. Offenbar[ENTER]planen sie einen \220berfall auf das Reich. Wir[ENTER]m\252ssen ihrem Angriff zuvorkommen. Beweise deine[ENTER]Treue zum Reich! "
gameforge.locale.questscroll5.mission_16_hunt = "Metin der Dunkelheit zerst\246ren "
gameforge.locale.questscroll5.mission_16_mis = "Zerst\246re 3 Metin der Dunkelheit. "
gameforge.locale.questscroll5.mission_16_text = "Seit kurzem regnet es Steine in der N\228he der[ENTER]Stadt. Sie scheinen b\246ses Chi zu besitzen, denn[ENTER]seitdem geb\228rden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte k\252mmere dich darum, dass diese[ENTER]Steine zerst\246rt werden. Du wirst f\252r deine M\252he[ENTER]angemessen entlohnt werden. "
gameforge.locale.questscroll5.mission_17_hunt = "Metin der Schw\228rze zerst\246ren "
gameforge.locale.questscroll5.mission_17_mis = "Zerst\246re 2 Metin der Schw\228rze. "
gameforge.locale.questscroll5.mission_17_text = "Seit kurzem regnet es Steine in der N\228he der[ENTER]Stadt. Sie scheinen b\246ses Chi zu besitzen, denn[ENTER]seitdem geb\228rden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte k\252mmere dich darum, dass diese[ENTER]Steine zerst\246rt werden. Du wirst f\252r deine M\252he[ENTER]angemessen entlohnt werden. "
gameforge.locale.questscroll5.mission_18_hunt = "Der Angriff der Se-Rang "
gameforge.locale.questscroll5.mission_18_mis = "T\246te 10 Se-Rang vom Wei\223en-Eid. "
gameforge.locale.questscroll5.mission_18_text = "Krieger, es sind neue Informationen zur wei\223en[ENTER]Armee eingetroffen. Als Reaktion auf unseren[ENTER]Druck haben die Se-Rang, Anf\252hrerinnen des[ENTER]Wei\223en-Eid, eine Gegenoffensive gestartet. Du[ENTER]musst sofort etwas gegen die Se-Rang unternehmen[ENTER]und ihre Pl\228ne vereiteln. "
gameforge.locale.questscroll5.mission_19_hunt = "Gro\223er Aufstand der Orks 2 "
gameforge.locale.questscroll5.mission_19_mis = "T\246te 20 Stolze Ork-K\228mpfer und 15 Stolze[ENTER]Ork-Zauberer. "
gameforge.locale.questscroll5.mission_19_text = "Geheime Informationen deuten darauf hin, dass die[ENTER]Anf\252hrer der Orks im Tal von Seungryong planen,[ENTER]die ganze Welt zu unterwerfen. So l\228cherlich das[ENTER]auch klingen mag, solltest du dieses Ger\252cht[ENTER]dennoch \252berpr\252fen. Und wenn du schon mal dort[ENTER]bist, k\246nntest du auch gleich noch ihre Truppen[ENTER]dezimieren. "
gameforge.locale.questscroll5.mission_1_hunt = "Metin des Kampfs zerst\246ren "
gameforge.locale.questscroll5.mission_1_mis = "Zerst\246re 3 Metin des Kampfs. "
gameforge.locale.questscroll5.mission_1_text = "Seit kurzem regnet es Steine in der N\228he der[ENTER]Stadt. Sie scheinen b\246ses Chi zu besitzen, denn[ENTER]seitdem geb\228rden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte k\252mmere dich darum, dass diese[ENTER]Steine zerst\246rt werden. Du wirst f\252r deine M\252he[ENTER]angemessen entlohnt werden. "
gameforge.locale.questscroll5.mission_20_hunt = "Geheimnis des normalen Affendungeons 1 "
gameforge.locale.questscroll5.mission_20_mis = "T\246te 30 Affensoldaten und 30 Affenwerfer. "
gameforge.locale.questscroll5.mission_20_text = "Die Lage des normalen Affendungeons in der W\252ste[ENTER]wurde endlich entdeckt. Normalerweise stellen die[ENTER]dort lebenden Affen keine Gefahr dar, aber wenn[ENTER]sie sich zusammenrotten, k\246nnten sie das Reich[ENTER]gef\228hrden.[ENTER]Begib dich zum normalen Affendungeon und sieh[ENTER]nach, wie es um die Affenpopulation steht. "
gameforge.locale.questscroll5.mission_21_hunt = "Geheimnis des leichten Affendungeons 1 "
gameforge.locale.questscroll5.mission_21_mis = "T\246te 30 Schwache Affensoldaten und 30 Schwache[ENTER]Affenwerfer. "
gameforge.locale.questscroll5.mission_21_text = "Die Lage des leichten Affendungeons in der W\252ste[ENTER]wurde endlich ermittelt. Normalerweise stellen[ENTER]die dort lebenden Affen keine Gefahr dar, aber[ENTER]wenn sie sich zusammenrotten, k\246nnten sie das[ENTER]Reich gef\228hrden.[ENTER]Begib dich zum leichten Affendungeon und sieh[ENTER]nach, wie es um die Affenpopulation steht. "
gameforge.locale.questscroll5.mission_22_hunt = "Wer Wind s\228t, wird Sturm ernten "
gameforge.locale.questscroll5.mission_22_mis = "T\246te 4 Chuong der Schwarzwindbande. "
gameforge.locale.questscroll5.mission_22_text = "Die Chuong, Anf\252hrer der Schwarzwindbande, machen[ENTER]\196rger. Als Meister des Schwertkampfs haben sie[ENTER]nur zum Spa\223 andere Krieger herausgefordert.[ENTER]Schalte sie aus, bevor sie die gesamte[ENTER]Schwarzwindbande mit ihrem \220bermut anstecken. "
gameforge.locale.questscroll5.mission_23_hunt = "Metin der Eifersucht zerst\246ren "
gameforge.locale.questscroll5.mission_23_mis = "Zerst\246re 2 Metin der Eifersucht. "
gameforge.locale.questscroll5.mission_23_text = "Seit kurzem regnet es Steine in der N\228he der[ENTER]Stadt. Sie scheinen b\246ses Chi zu besitzen, denn[ENTER]seitdem geb\228rden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte k\252mmere dich darum, dass diese[ENTER]Steine zerst\246rt werden. Du wirst f\252r deine M\252he[ENTER]angemessen entlohnt werden. "
