gameforge.locale.questscroll5.mission_24_mis = "T\246te 15 Affenk\228mpfer und 15 Affengener\228le. "
gameforge.locale.questscroll5.mission_24_text = "Die Lage des normalen Affendungeons in der W\252ste[ENTER]wurde endlich ermittelt. Normalerweise stellen[ENTER]die dort lebenden Affen keine Gefahr dar, aber[ENTER]wenn sie sich zusammenrotten, k\246nnten sie das[ENTER]Reich gef\228hrden.[ENTER]Begib dich zum normalen Affendungeon und sieh[ENTER]nach, wie es um die Affenpopulation steht. "
