gameforge.locale.questscroll5.mission_25_mis = "T\246te 15 Affensoldaten und 15 Schwache[ENTER]Affengener\228le. "
gameforge.locale.questscroll5.mission_25_text = "Die Lage des leichten Affendungeons in der W\252ste[ENTER]wurde endlich ermittelt. Normalerweise stellen[ENTER]die dort lebenden Affen keine Gefahr dar, aber[ENTER]wenn sie sich zusammenrotten, k\246nnten sie das[ENTER]Reich gef\228hrden.[ENTER]Begib dich zum leichten Affendungeon und sieh[ENTER]nach, wie es um die Affenpopulation steht. "
