gameforge.locale.questscroll5.mission_26_mis = "Zerst\246re 2 Metin der Seele. "
gameforge.locale.questscroll5.mission_26_text = "Seit kurzem regnet es Steine in der N\228he der[ENTER]Stadt. Sie scheinen b\246ses Chi zu besitzen, denn[ENTER]seitdem geb\228rden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte k\252mmere dich darum, dass diese[ENTER]Steine zerst\246rt werden. Du wirst f\252r deine M\252he[ENTER]angemessen entlohnt werden. "
gameforge.locale.questscroll5.mission_27_hunt = "Wut der Spinne 1 "
gameforge.locale.questscroll5.mission_27_mis = "T\246te 40 Babyspinnen. "
gameforge.locale.questscroll5.mission_27_text = "Spinnen, die normalerweise friedlich in der[ENTER]Yongbi-W\252ste leben, haben angefangen, Reisende[ENTER]anzugreifen und zu t\246ten. Abgesehen davon, dass[ENTER]die Betroffenen wenig erfreut sind, haben diese[ENTER]Angriffe unangenehme Auswirkungen auf die[ENTER]Handelsbeziehungen im Reich. Sorge bitte daf\252r,[ENTER]dass das aufh\246rt. "
gameforge.locale.questscroll5.mission_28_hunt = "Wut der Spinne 2 "
gameforge.locale.questscroll5.mission_28_mis = "T\246te 40 Giftspinnen. "
gameforge.locale.questscroll5.mission_28_text = "Spinnen, die normalerweise friedlich in der[ENTER]Yongbi-W\252ste leben, haben angefangen, Reisende[ENTER]anzugreifen und zu t\246ten. Abgesehen davon, dass[ENTER]die Betroffenen wenig erfreut sind, haben diese[ENTER]Angriffe unangenehme Auswirkungen auf die[ENTER]Handelsbeziehungen im Reich. Sorge bitte daf\252r,[ENTER]dass das aufh\246rt. "
gameforge.locale.questscroll5.mission_29_hunt = "Anh\228nger des Schw. Glaubens 2 "
gameforge.locale.questscroll5.mission_29_mis = "T\246te 20 Dunkle K\228mpfer und 25 Obere dunkle[ENTER]Arahan. "
gameforge.locale.questscroll5.mission_29_text = "Es ist endlich der Befehl ergangen, einen der[ENTER]gef\228hrlichsten Gegner des Reiches auszumerzen:[ENTER]die esoterische Sekte im Tal von Seungryong. Geh[ENTER]dorthin und heize ihnen ordentlich ein! Aber mach[ENTER]nicht den Fehler, sie zu untersch\228tzen. Auch wenn[ENTER]sie oft nur unverst\228ndliches Zeug plappern, sind[ENTER]sie doch erfahrene K\228mpfer. "
