gameforge.locale.questscroll5.mission_2_mis = "Zerst\246re 2 Metin des Kummers. "
gameforge.locale.questscroll5.mission_2_text = "Seit kurzem regnet es Steine in der N\228he der[ENTER]Stadt. Sie scheinen b\246ses Chi zu besitzen, denn[ENTER]seitdem geb\228rden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte k\252mmere dich darum, dass diese[ENTER]Steine zerst\246rt werden. Du wirst f\252r deine M\252he[ENTER]angemessen entlohnt werden. "
