gameforge.locale.questscroll5.mission_30_mis = "T\246te 30 Dunkle Fanatiker und 30 Dunkle Arahan. "
gameforge.locale.questscroll5.mission_30_text = "Es ist endlich der Befehl ergangen, einen der[ENTER]gef\228hrlichsten Gegner des Reiches auszumerzen:[ENTER]die esoterische Sekte im Tal von Seungryong. Geh[ENTER]dorthin und heize ihnen ordentlich ein! Aber mach[ENTER]nicht den Fehler, sie zu untersch\228tzen. Auch wenn[ENTER]sie oft nur unverst\228ndliches Zeug plappern, sind[ENTER]sie doch erfahrene K\228mpfer. "
