gameforge.locale.questscroll5.mission_32_hunt = "Metin des Schattens zerst\246ren "
gameforge.locale.questscroll5.mission_32_mis = "Zerst\246re 2 Metin des Schattens. "
gameforge.locale.questscroll5.mission_32_text = "Seit kurzem regnet es Steine in der N\228he der[ENTER]Stadt. Sie scheinen b\246ses Chi zu besitzen, denn[ENTER]seitdem geb\228rden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte k\252mmere dich darum, dass diese[ENTER]Steine zerst\246rt werden. Du wirst f\252r deine M\252he[ENTER]angemessen entlohnt werden. "
gameforge.locale.questscroll5.mission_33_hunt = "Sie haben acht Beine 1 "
gameforge.locale.questscroll5.mission_33_mis = "T\246te 35 Babygiftspinnen und 35 T\246dliche[ENTER]Giftspinnen. "
gameforge.locale.questscroll5.mission_33_text = "In der Yongbi-W\252ste wurde ein H\246hlensystem[ENTER]entdeckt, das den dort lebenden Spinnen als[ENTER]Unterschlupf dient. Wir haben keine genaueren[ENTER]Informationen \252ber diese Spinnenh\246hlen, aber die[ENTER]Gegend ist als sehr gef\228hrlich bekannt.[ENTER]Andererseits ergibt sich durch die Ansammlung[ENTER]vieler Spinnen auf engem Raum eine gute[ENTER]Gelegenheit, ihre Zahl und damit auch ihre[ENTER]Bedrohlichkeit zu verringern. Also mach dich auf[ENTER]den Weg! Und sei vorsichtig! "
gameforge.locale.questscroll5.mission_34_hunt = "Sie haben acht Beine 2 "
gameforge.locale.questscroll5.mission_34_mis = "T\246te 35 Babygiftspinnen und 35 T\246dliche[ENTER]Giftspinnen. "
gameforge.locale.questscroll5.mission_34_text = "In der Yongbi-W\252ste wurde ein H\246hlensystem[ENTER]entdeckt, das den dort lebenden Spinnen als[ENTER]Unterschlupf dient. Wir haben keine genaueren[ENTER]Informationen \252ber diese Spinnenh\246hlen, aber die[ENTER]Gegend ist als sehr gef\228hrlich bekannt.[ENTER]Andererseits ergibt sich durch die Ansammlung[ENTER]vieler Spinnen auf engem Raum eine gute[ENTER]Gelegenheit, ihre Zahl und damit auch ihre[ENTER]Bedrohlichkeit zu verringern. Also mach dich auf[ENTER]den Weg! Und sei vorsichtig! "
gameforge.locale.questscroll5.mission_35_hunt = "Sie haben acht Beine 3 "
gameforge.locale.questscroll5.mission_35_mis = "T\246te 35 Rote t\246dliche Giftspinnen und 35[ENTER]Klauengiftspinnen. "
gameforge.locale.questscroll5.mission_35_text = "In der Yongbi-W\252ste wurde ein H\246hlensystem[ENTER]entdeckt, das den dort lebenden Spinnen als[ENTER]Unterschlupf dient. Wir haben keine genaueren[ENTER]Informationen \252ber diese Spinnenh\246hlen, aber die[ENTER]Gegend ist als sehr gef\228hrlich bekannt.[ENTER]Andererseits ergibt sich durch die Ansammlung[ENTER]vieler Spinnen auf engem Raum eine gute[ENTER]Gelegenheit, ihre Zahl und damit auch ihre[ENTER]Bedrohlichkeit zu verringern. Also mach dich auf[ENTER]den Weg! Und sei vorsichtig! "
gameforge.locale.questscroll5.mission_36_hunt = "Sie haben acht Beine 4 "
gameforge.locale.questscroll5.mission_36_mis = "T\246te 40 Soldatengiftspinnen. "
gameforge.locale.questscroll5.mission_36_text = "In der Yongbi-W\252ste wurde ein H\246hlensystem[ENTER]entdeckt, das den dort lebenden Spinnen als[ENTER]Unterschlupf dient. Wir haben keine genaueren[ENTER]Informationen \252ber diese Spinnenh\246hlen, aber die[ENTER]Gegend ist als sehr gef\228hrlich bekannt.[ENTER]Andererseits ergibt sich durch die Ansammlung[ENTER]vieler Spinnen auf engem Raum eine gute[ENTER]Gelegenheit, ihre Zahl und damit auch ihre[ENTER]Bedrohlichkeit zu verringern. Also mach dich auf[ENTER]den Weg! Und sei vorsichtig! "
gameforge.locale.questscroll5.mission_37_hunt = "Metin der H\228rte zerst\246ren "
gameforge.locale.questscroll5.mission_37_mis = "Zerst\246re 2 Metin der H\228rte. "
gameforge.locale.questscroll5.mission_37_text = "Seit kurzem regnet es Steine in der N\228he der[ENTER]Stadt. Sie scheinen b\246ses Chi zu besitzen, denn[ENTER]seitdem geb\228rden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte k\252mmere dich darum, dass diese[ENTER]Steine zerst\246rt werden. Du wirst f\252r deine M\252he[ENTER]angemessen entlohnt werden. "
gameforge.locale.questscroll5.mission_38_hunt = "Skorpionplage "
gameforge.locale.questscroll5.mission_38_mis = "T\246te 30 K\246nigsskorpione und 20 Junge[ENTER]Skorpionm\228nner. "
gameforge.locale.questscroll5.mission_38_text = "Diese Skorpionwesen tyrannisieren Reisende und[ENTER]H\228ndler,[ENTER]was sich schlecht auf die Wirtschaft des Reiches[ENTER]auswirkt. Bitte hilf dabei, dieser Plage Herr zu[ENTER]werden. "
gameforge.locale.questscroll5.mission_39_hunt = "Gesellschaft des Todes 1 "
gameforge.locale.questscroll5.mission_39_mis = "T\246te 30 D\228monensoldaten und 20[ENTER]D\228monenbogensch\252tzen. "
gameforge.locale.questscroll5.mission_39_text = "Hast du schon vom D\228monenturm geh\246rt? Dort haben[ENTER]esoterische Sekten mit m\228chtiger Magie[ENTER]D\228monensoldaten beschworen. Bek\228mpfe sie und[ENTER]finde so heraus, wie m\228chtig sie sind. "
gameforge.locale.questscroll5.mission_3_hunt = "Auftauchen der Grauw\246lfe 2 "
gameforge.locale.questscroll5.mission_3_mis = "Erlege 30 Alpha-Grauw\246lfe. "
gameforge.locale.questscroll5.mission_3_text = "Hast du von den Alpha-Grauw\246lfen geh\246rt? Sie[ENTER]waren meist alleine unterwegs, aber durch den[ENTER]Einfluss des b\246sen Chi in letzter Zeit haben sie[ENTER]begonnen, in Rudeln Reisende zu jagen.[ENTER]K\246nntest du bitte diese Alpha-Grauw\246lfe zur[ENTER]Strecke bringen? Es soll dein Schaden nicht sein. "
gameforge.locale.questscroll5.mission_40_hunt = "Gesellschaft des Todes 2 "
gameforge.locale.questscroll5.mission_40_mis = "T\246te 30 D\228monenspeerk\228mpfer und 25[ENTER]D\228monenschamanen. "
gameforge.locale.questscroll5.mission_40_text = "Hast du schon vom D\228monenturm geh\246rt? Dort haben[ENTER]Esoterische Sekten mit m\228chtiger Magie[ENTER]D\228monensoldaten beschworen. Bek\228mpfe sie und[ENTER]finde so heraus, wie m\228chtig sie sind. "
gameforge.locale.questscroll5.mission_41_hunt = "Geheimnis des schweren Affendungeons 2 "
gameforge.locale.questscroll5.mission_41_mis = "T\246te 15 Starke Affenk\228mpfer und 15 Starke[ENTER]Affengener\228le. "
gameforge.locale.questscroll5.mission_41_text = "Die Lage des schweren Affendungeons in der W\252ste[ENTER]wurde endlich ermittelt. Normalerweise stellen[ENTER]die dort lebenden Affen keine Gefahr dar, aber[ENTER]wenn sie sich zusammenrotten, k\246nnten sie das[ENTER]Reich gef\228hrden.[ENTER]Begib dich zum schweren Affendungeon und sieh[ENTER]nach, wie es um die Affenpopulation steht. "
gameforge.locale.questscroll5.mission_42_hunt = "Das Eis wird schmelzen "
gameforge.locale.questscroll5.mission_42_mis = "T\246te 25 Eisgolems auf dem Berg Sohan. "
gameforge.locale.questscroll5.mission_42_text = "Kennst du den von ewigem Eis bedeckten Berg[ENTER]Sohan? Viele Forscher und K\228mpfer haben sich[ENTER]dorthin aufgemacht, sind jedoch nie[ENTER]zur\252ckgekehrt. Finde heraus, warum dies so ist[ENTER]und ob sie angegriffen wurden. Vielleicht kannst[ENTER]du etwas erfahren, wenn du dort Monster jagst. "
gameforge.locale.questscroll5.mission_43_hunt = "Geheimnis des schweren Affendungeons 1 "
gameforge.locale.questscroll5.mission_43_mis = "T\246te 30 Starke Affensoldaten und 30 Starke[ENTER]Affenwerfer. "
gameforge.locale.questscroll5.mission_43_text = "Die Lage des schweren Affendungeons in der W\252ste[ENTER]wurde endlich ermittelt. Normalerweise stellen[ENTER]die dort lebenden Affen keine Gefahr dar, aber[ENTER]wenn sie sich zusammenrotten, k\246nnten sie das[ENTER]Reich gef\228hrden.[ENTER]Begib dich zum schweren Affendungeon und sieh[ENTER]nach, wie es um die Affenpopulation steht. "
gameforge.locale.questscroll5.mission_44_hunt = "Die rechte Hand des Gelben Tigergeists "
gameforge.locale.questscroll5.mission_44_mis = "T\246te 30 Ochsenfrosch-Gener\228le. "
gameforge.locale.questscroll5.mission_44_text = "Dir ist sicherlich schon aufgefallen, dass die[ENTER]Tiere in letzter Zeit sehr wild und[ENTER]angriffslustig sind. Der Geheimdienst des Reichs[ENTER]vermutet als Grund daf\252r, dass der Gelbe[ENTER]Tigergeist, K\246nig aller Tiere auf diesem[ENTER]Kontinent, gerade seine Untertanen mobilisiert.[ENTER]Als Gegenma\223nahme sollten wir die Anf\252hrer[ENTER]beseitigen, die als seine rechte Hand fungieren. "
gameforge.locale.questscroll5.mission_45_hunt = "Eigent\252mer des Bergs Sohan? "
gameforge.locale.questscroll5.mission_45_mis = "T\246te 35 Frostige Eism\228nner und 30 Yetis. "
gameforge.locale.questscroll5.mission_45_text = "Der Neunschwanz, Herr des Bergs Sohan, schart[ENTER]dort angeblich D\228monen um sich. Bevor er seine[ENTER]Truppen zusammen hat, m\252ssen wir das R\252ckgrat[ENTER]seiner Armee zerschlagen und so seine Pl\228ne[ENTER]vereiteln. Bitte hilf uns. Du wirst gro\223z\252gig[ENTER]belohnt. "
gameforge.locale.questscroll5.mission_46_hunt = "Chunwa Bong-ki "
gameforge.locale.questscroll5.mission_46_mis = "T\246te 45 Baumfrosch-Soldaten und 35[ENTER]Baumfrosch-Anf\252hrer. "
gameforge.locale.questscroll5.mission_46_text = "Der gelbe Tigergeist hat sich anscheinend mit den[ENTER]Baumfrosch-Monstern verschworen. Zerschlage[ENTER]umgehend ihre gemeinsamen Einheiten. Wenn du sie[ENTER]ignorierst, wird dies \252bel f\252r das Reich[ENTER]ausgehen! "
gameforge.locale.questscroll5.mission_47_hunt = "Eismonster! Ihr wahres Wesen "
gameforge.locale.questscroll5.mission_47_mis = "Zerst\246re 45 Verzaubertes Eis. "
gameforge.locale.questscroll5.mission_47_text = "Wir haben herausgefunden, wie die Eismonster auf[ENTER]dem Berg Sohan sich untereinander verst\228ndigen:[ENTER]Sie verbreiten ihre Informationen \252ber die[ENTER]schwebenden Eissplitter, die dort \252berall[ENTER]anzutreffen sind.[ENTER]Um die Truppen des Eislandes zu schw\228chen, m\252ssen[ENTER]wir diese Informations\252bertragung st\246ren. Ich[ENTER]bitte dich: Beseitige das Verzauberte Eis! "
gameforge.locale.questscroll5.mission_48_hunt = "Das Geheimnis des D\228monenturms "
gameforge.locale.questscroll5.mission_48_mis = "T\246te 45 Gemeine Geist K\228mpfer. "
gameforge.locale.questscroll5.mission_48_text = "Einige Ger\252chte besagen, dass die Gemeinen[ENTER]Speerk\228mpfer im D\228monenturm unbesiegbar seien.[ENTER]Angeblich stehen sie jedes Mal wieder auf, wenn[ENTER]man sie t\246tet. Wenn das stimmt, stehen uns dunkle[ENTER]Zeiten bevor. Bitte finde mehr dar\252ber heraus! "
gameforge.locale.questscroll5.mission_49_hunt = "Der Herr des D\228monenturms "
gameforge.locale.questscroll5.mission_49_mis = "T\246te 60 Gemeine Geist Schamanen. "
gameforge.locale.questscroll5.mission_49_text = "Nach genauerer Untersuchung wurde festgestellt,[ENTER]dass die Geistersoldaten fortw\228hrend wiederbelebt[ENTER]wurden. Wir m\252ssen Gemeine Geist Schamanen[ENTER]vernichten, um das zu verhindern. "
gameforge.locale.questscroll5.mission_4_hunt = "Auftauchen der Grauw\246lfe 1 "
gameforge.locale.questscroll5.mission_4_mis = "Erlege 35 Grauw\246lfe. "
gameforge.locale.questscroll5.mission_4_text = "Hast du von den Grauw\246lfen geh\246rt? Sie waren[ENTER]meist alleine unterwegs, aber durch den Einfluss[ENTER]des b\246sen Chi in letzter Zeit haben sie begonnen,[ENTER]in Rudeln Reisende zu jagen.[ENTER]K\246nntest du bitte diese Grauw\246lfe zur Strecke[ENTER]bringen? Es soll dein Schaden nicht sein. "
gameforge.locale.questscroll5.mission_50_hunt = "Doyyumhwan erforschen "
gameforge.locale.questscroll5.mission_50_mis = "T\246te 45 Kampftigersklaven. "
gameforge.locale.questscroll5.mission_50_text = "Doyyumhwan ist ein Lavagebiet, das von noch[ENTER]unbekannten Monstern bev\246lkert wird.[ENTER]Wir m\252ssen diese Region erforschen. Kannst du uns[ENTER]dabei helfen? "
gameforge.locale.questscroll5.mission_51_hunt = "Flammengeist! Seine Identit\228t "
gameforge.locale.questscroll5.mission_51_mis = "T\246te 45 Flammengeister. "
gameforge.locale.questscroll5.mission_51_text = "Eine Gruppe, die Kampftiger jagen sollte, wurde[ENTER]selbst von noch unbekannten Gegnern vernichtet.[ENTER]Es hei\223t, dass diese Gegner wie brennende M\228dchen[ENTER]aussehen, also finde heraus, worum es sich[ENTER]handelt. "
gameforge.locale.questscroll5.mission_52_hunt = "Reduziere die Zahl der Kampftiger "
gameforge.locale.questscroll5.mission_52_mis = "T\246te 60 Kampftigersklaven und 40 Kampftiger. "
gameforge.locale.questscroll5.mission_52_text = "Jetzt, da wir die Feuergeister bek\228mpfen k\246nnen,[ENTER]m\252ssen wir sie im offenen Kampf komplett[ENTER]vernichten. Diese Aufgabe wird vom Milit\228r[ENTER]\252bernommen, aber um mit voller Kampfst\228rke zu den[ENTER]Feuergeistern durchdringen zu k\246nnen, brauchen[ENTER]wir eine Einfallschneise.[ENTER]Bitte sorge daf\252r, dass uns keine Kampftiger in[ENTER]die Quere kommen. "
gameforge.locale.questscroll5.mission_53_hunt = "Erforsche die Flammen "
gameforge.locale.questscroll5.mission_53_mis = "T\246te 40 Flammen. "
gameforge.locale.questscroll5.mission_53_text = "Die Flammen sind unglaublich brutal. Sie erg\246tzen[ENTER]sich am Schmerz der Menschen, deren Haut sie[ENTER]gerade verzehren. Wir haben noch keine Ahnung,[ENTER]wie wir sie ausschalten k\246nnen.[ENTER]Kannst du mehr \252ber diese Flammen herausfinden? "
gameforge.locale.questscroll5.mission_54_hunt = "Flammenkrieger "
gameforge.locale.questscroll5.mission_54_mis = "T\246te 60 Flammenkrieger. "
gameforge.locale.questscroll5.mission_54_text = "Vor kurzem wurde das Kind eines Adligen, das sich[ENTER]in das Feuerland begab, von einem Flammenkrieger[ENTER]erschlagen. Wenn du die Flammenkrieger t\246test,[ENTER]erh\228ltst du eine Belohnung. Warum forderst du sie[ENTER]nicht heraus? "
gameforge.locale.questscroll5.mission_55_hunt = "Untersuche die Geisterb\228ume "
gameforge.locale.questscroll5.mission_55_mis = "F\228lle 30 Geisterb\228ume. "
gameforge.locale.questscroll5.mission_55_text = "Sie stehen wie normale, etwas finster aussehende[ENTER]B\228ume in der Landschaft herum \150 doch dann werden[ENTER]sie pl\246tzlich lebendig und greifen Tiere und[ENTER]Menschen an.[ENTER]Finde heraus, wie die Geisterb\228ume vernichtet[ENTER]werden k\246nnen. "
gameforge.locale.questscroll5.mission_56_hunt = "Das Geheimnis des Geisterwaldes "
gameforge.locale.questscroll5.mission_56_mis = "T\246te 40 Geisterbaumst\252mpfe und 30 Dryaden. "
gameforge.locale.questscroll5.mission_56_text = "Nachforschungen haben ergeben, dass der[ENTER]Geisterwald ein Gebiet ist, das von[ENTER]Geisterbaumstumpf und Dryade dominiert wird. Wenn[ENTER]du sie vernichtest, kannst du vielleicht[ENTER]verhindern, dass sich die Geisterb\228ume weiter[ENTER]ausbreiten. "
gameforge.locale.questscroll5.mission_5_hunt = "Sorge um die D\246rfer "
gameforge.locale.questscroll5.mission_5_mis = "Erlege 40 Keiler. "
gameforge.locale.questscroll5.mission_5_text = "Die Sorgen der Dorfbewohner in der N\228he der Stadt[ENTER]haben in letzter Zeit zugenommen. Keiler, die[ENTER]bisher h\246chstens kleine Tiere in den Bergen[ENTER]angefallen haben, sind aggressiv geworden. Sie[ENTER]sind in die Felder eingefallen und haben die[ENTER]Bauern angegriffen. Kannst du diese Keiler[ENTER]vertreiben? "
gameforge.locale.questscroll5.mission_6_hunt = "Tiger und B\228ren "
gameforge.locale.questscroll5.mission_6_mis = "Erlege 25 Tiger und 30 B\228ren. "
gameforge.locale.questscroll5.mission_6_text = "Hast du das schon geh\246rt? Wenn Tiger und B\228ren[ENTER]100 Tage lang nur Knoblauch und Zwiebeln fressen,[ENTER]k\246nnen sie sich in Gro\223tiger und Feuerb\228ren[ENTER]verwandeln. Ich glaube nicht, dass das schon[ENTER]jemals passiert ist, aber es schadet nicht,[ENTER]sicher zu gehen. Erlege ein paar Tiger und B\228ren[ENTER]und schau nach, was sich in ihren M\228gen befindet. "
gameforge.locale.questscroll5.mission_7_hunt = "Metin der Gier zerst\246ren "
gameforge.locale.questscroll5.mission_7_mis = "Zerst\246re 2 Metin der Gier. "
gameforge.locale.questscroll5.mission_7_text = "Seit kurzem regnet es Steine in der N\228he der[ENTER]Stadt. Sie scheinen b\246ses Chi zu besitzen, denn[ENTER]seitdem geb\228rden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte k\252mmere dich darum, dass diese[ENTER]Steine zerst\246rt werden. Du wirst f\252r deine M\252he[ENTER]angemessen entlohnt werden. "
gameforge.locale.questscroll5.mission_8_hunt = "Metin der Schlacht zerst\246ren "
gameforge.locale.questscroll5.mission_8_mis = "Zerst\246re 2 Metin der Schlacht. "
gameforge.locale.questscroll5.mission_8_text = "Seit kurzem regnet es Steine in der N\228he der[ENTER]Stadt. Sie scheinen b\246ses Chi zu besitzen, denn[ENTER]seitdem geb\228rden sich die Tiere in der Umgebung[ENTER]wie toll. Bitte k\252mmere dich darum, dass diese[ENTER]Steine zerst\246rt werden. Du wirst f\252r deine M\252he[ENTER]angemessen entlohnt werden. "
gameforge.locale.questscroll5.mission_9_hunt = "Sorge um die D\246rfer 2 "
gameforge.locale.questscroll5.mission_9_mis = "Erlege 30 Rote Keiler. "
gameforge.locale.questscroll5.mission_9_text = "Seit kurzem suchen Gruppen von Keilern mit[ENTER]jeweils einem Roten Keiler, der sie anf\252hrt, die[ENTER]D\246rfer in der N\228he der Hauptstadt heim.[ENTER]Die Regierung hat befohlen, die Roten Keiler zu[ENTER]t\246ten: Jeder Krieger soll 30 von ihnen erlegen.[ENTER]Wir bitten dich um deine Mithilfe. "
gameforge.locale.questscroll_10_hunt = "Schlangenmenschensoldaten "
gameforge.locale.questscroll_10_mis = "T\246te die Soldaten, die halb Mensch, halb Schlange[ENTER]sind. "
gameforge.locale.questscroll_10_text = "Man kann sie eigentlich nicht als Menschen[ENTER]bezeichnen. Aber es ist genauso falsch zu sagen,[ENTER]dass sie keine Menschen w\228ren. Sie sehen aus wie[ENTER]Menschen, aber Kopf, Haut und Verhalten gleichen[ENTER]dem giftiger Schlangen. Sie durchstreifen die[ENTER]W\252ste und greifen H\228ndler an.[ENTER]T\246te 20 dieser Soldaten, die halb Mensch, halb[ENTER]Schlange sind. Wenn du sie vernichtest, erh\228ltst[ENTER]du folgende Belohnung: "
gameforge.locale.questscroll_11_hunt = "Schlangenmenschensch\252tzen "
gameforge.locale.questscroll_11_mis = "T\246te die Sch\252tzen, die halb Mensch, halb Schlange[ENTER]sind. "
gameforge.locale.questscroll_11_text = "Sie sind so intelligent wie Menschen. Sie sind[ENTER]verschlagen und verstehen sich hervorragend auf[ENTER]den Umgang mit Waffen. Bogensch\252tzen, die halb[ENTER]Mensch und halb Schlange sind, greifen die[ENTER]H\228ndler auf Distanz an. Viele der H\228ndler sind[ENTER]bereits gestorben.[ENTER]T\246te 20 der Bogensch\252tzen, die halb Mensch und[ENTER]halb Schlange sind. Wenn du diesen Auftrag[ENTER]erfolgreich abschlie\223t, erh\228ltst du folgende[ENTER]Belohnung: "
gameforge.locale.questscroll_12_hunt = "W\252stenbanditen "
gameforge.locale.questscroll_12_mis = "T\246te die W\252stenbanditen. "
gameforge.locale.questscroll_12_text = "In der Yongbi-W\252ste leben b\246se Wesen. Sie sind[ENTER]als W\252stenbanditen bekannt und ihre Untaten[ENTER]schreien zum Himmel. Sie rauben H\228ndler aus und[ENTER]t\246ten sie zum Spa\223. Sie haben auch einige D\246rfer[ENTER]in der W\252ste zerst\246rt.[ENTER]Erschlage 12 W\252stenbanditen, dann erh\228ltst du[ENTER]folgende Belohnung: "
gameforge.locale.questscroll_13_hunt = "Kampftiger "
gameforge.locale.questscroll_13_mis = "T\246te die Kampftiger. "
gameforge.locale.questscroll_13_text = "Es gibt Wesen, die Kampftiger genannt werden. Ihr[ENTER]Blut ist aus Feuer, und ihre K\246rper wurden aus[ENTER]vulkanischem Granit geformt. Sie sind[ENTER]ungew\246hnlich m\228chtige Monster! Diese Monster[ENTER]ern\228hren sich von der Lava und dem Feuer des[ENTER]Vulkans. Manchmal steigen sie vom Vulkan herab,[ENTER]greifen Menschen an und fressen sie.[ENTER]Erschlage 20 der Kampftiger. Wenn du sie[ENTER]vernichtest, erh\228ltst du folgende Belohnung: "
gameforge.locale.questscroll_14_hunt = "Kriegsmannen "
gameforge.locale.questscroll_14_mis = "T\246te die Kriegsmannen. "
gameforge.locale.questscroll_14_text = "Doyyumhwan ist gro\223 und hei\223 und beherbergt wilde[ENTER]Tiere. Dort treffen sich Krieger aus Chunjo,[ENTER]Jinno und Shinsoo. Furchterregende, m\228chtige[ENTER]Monster warten dort auf die Krieger. Kriegsmannen[ENTER]sind die Beherrscher von Doyyumhwan.[ENTER]Willst du sie herausfordern? Wenn du 20 von ihnen[ENTER]erschl\228gst, erh\228ltst du folgende Belohnung: "
gameforge.locale.questscroll_15_hunt = "Taehwa-Krieger "
gameforge.locale.questscroll_15_mis = "T\246te die Taehwa-Krieger. "
gameforge.locale.questscroll_15_text = "H\246rt her, alle, die Ihr Euch f\252r starke K\228mpfer[ENTER]haltet! Dies ist das Flammenschlachtfeld der[ENTER]Tr\228nen, des Leids, des Kampfes und des Todes! Ich[ENTER]lebe hier mit vielen Monstern und B\246sewichten![ENTER]Wer wagt es, mich zu herauszufordern? Findet sich[ENTER]jemand, der mir mit dem Schwert in der Hand[ENTER]gegen\252bertritt? Wenn du auf deinen Schwertarm[ENTER]vertraust, dann komm heraus und fordere mich![ENTER]Wenn du mich und 12 meiner Kameraden bezwingst,[ENTER]erh\228ltst du folgende Belohnung: "
gameforge.locale.questscroll_16_hunt = "Dunkelb\228ren "
gameforge.locale.questscroll_16_mis = "T\246te die Dunkelb\228ren. "
gameforge.locale.questscroll_16_text = "Wenn du diesen Brief liest, bin ich bereits tot[ENTER]oder verschwunden. Ich lebte im Tal von[ENTER]Seungryong, wo ich Heilpflanzen sammelte. Aber[ENTER]Monster, die Dunkelb\228ren genannt werden, fingen[ENTER]an, allerlei Untaten zu begehen. Sie t\246teten[ENTER]meine Familie. Bitte r\228che mich und meine[ENTER]Familie. Wenn du 25 Dunkelb\228ren erschl\228gst,[ENTER]erh\228ltst du folgende Belohnung: "
gameforge.locale.questscroll_17_hunt = "Riesendunkelb\228ren "
gameforge.locale.questscroll_17_mis = "T\246te die Riesendunkelb\228ren. "
gameforge.locale.questscroll_17_text = "Eine neue Art Monster wurde entdeckt: Es handelt[ENTER]sich um Riesendunkelb\228ren, gr\246\223er und[ENTER]st\228rker als Dunkelb\228ren und von unglaublicher[ENTER]B\246sartigkeit. Solange es diese Wesen im Tal von[ENTER]Seungryong gibt, werden die Menschen leiden.[ENTER]T\246te 20 Riesendunkelb\228ren. Wenn du Erfolg hast,[ENTER]erh\228ltst du folgende Belohnung: "
gameforge.locale.questscroll_18_hunt = "Soldaten, die an der r\228tselhaften Krankheit[ENTER]leiden "
gameforge.locale.questscroll_18_mis = "Soldaten t\246ten, die an der r\228tselhaften Krankheit[ENTER]leiden. "
gameforge.locale.questscroll_18_text = "Das Dorf wurde wohl ausgel\246scht. Diejenigen, die[ENTER]an der r\228tselhaften Krankheit leiden, greifen die[ENTER]Ungl\252ckseligen an, die vorbeikommen. Sie greifen[ENTER]fahrende H\228ndler an und fressen Menschen. Sie[ENTER]sind extrem gef\228hrlich. Erschlag 35 Soldaten, die[ENTER]an der r\228tselhaften Krankheit leiden. Wenn Du[ENTER]Erfolg hast, erh\228ltst Du folgende Belohnung: "
gameforge.locale.questscroll_19_hunt = "Sch\252tzen, die an der r\228tselhaften Krankheit[ENTER]leiden "
gameforge.locale.questscroll_19_mis = "Sch\252tzen t\246ten, die an der r\228tselhaften Krankheit[ENTER]leiden. "
gameforge.locale.questscroll_19_text = "Die r\228tselhafte Krankheit ist die Ursache der[ENTER]Sch\228den, die diejenigen hervorrufen, die an ihr[ENTER]leiden. Aber am gef\228hrlichsten sind die[ENTER]Bogensch\252tzen, die die Krankheit erfasste. Diese[ENTER]Sch\252tzen verschie\223en Giftpfeile, die Reisende[ENTER]l\228hmen, sodass sie ergriffen und verschleppt[ENTER]werden k\246nnen. T\246te 25 Bogensch\252tzen, die an der[ENTER]r\228tselhaften Krankheit leiden. Wenn Du Erfolg[ENTER]hast, erh\228ltst Du folgende Belohnung: "
gameforge.locale.questscroll_1_hunt = "Feuerb\228ren "
gameforge.locale.questscroll_1_mis = "25 Feuerb\228ren erlegen. "
gameforge.locale.questscroll_1_text = "Feuerb\228ren sind oft in der N\228he der Hauptstadt[ENTER]anzutreffen. Sie durchstreifen die Pr\228rie und die[ENTER]breiten Stra\223en der Menschen. Sie finden[ENTER]zunehmend mehr Opfer. Einige Menschen wurden[ENTER]get\246tet. Jag diese Feuerb\228ren. Wenn Du 25[ENTER]Feuerb\228ren erlegst, erh\228ltst Du folgende[ENTER]Belohnung: "
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "4 Feinde erschlagen. "
gameforge.locale.questscroll_20_text = "Ich f\252rchte, ich bin erledigt! Mein Blick[ENTER]verschwimmt. Wenn Du diesen Brief liest, wird[ENTER]mein K\246rper bereits verfault sein. Die Schweine[ENTER]haben mich gepackt und verschleppt. Ich bin zwar[ENTER]entkommen, aber die Wunde war so tief, dass ich[ENTER]zusammenbrach. Ich kenne Dich nicht. Aber bitte[ENTER]r\228cht mich! Erschlag vier Feinde am Ort des[ENTER]Kampfes. Wenn Du Erfolg hast, erh\228ltst Du[ENTER]folgende Belohnung: "
gameforge.locale.questscroll_2_hunt = "Gro\223tiger "
gameforge.locale.questscroll_2_mis = "20 Gro\223tiger erlegen. "
gameforge.locale.questscroll_2_text = "Der Name der Bosheit, Gro\223tiger, durchdringt die[ENTER]Luft. Diese Tiger finden sich meist in der N\228he[ENTER]der Hauptstadt. Sie greifen Menschen an und[ENTER]fressen die Leichen der H\228ndler. Ihre Opfer sind[ENTER]zahllos. Jag die Gro\223tiger. Wenn Du 20 Gro\223tiger[ENTER]erlegst, erh\228ltst Du folgende Belohnung: "
gameforge.locale.questscroll_3_hunt = "Hundegott des Berges "
gameforge.locale.questscroll_3_mis = "Den Hundegott des Berges t\246ten. "
gameforge.locale.questscroll_3_text = "Der Hundegott des Berges f\252hrt ein Rudel von[ENTER]Hundemonstern in der N\228he an. Er ist stark und[ENTER]wild. Vor kurzem ist er in der N\228he des Dorfes[ENTER]aufgetaucht und hat begonnen, H\228ndler[ENTER]anzugreifen. Viele sind diesem Monster schon zum[ENTER]Opfer gefallen. Seine Untaten k\246nnen nicht l\228nger[ENTER]ignoriert werden. T\246te den Hundegott des Berges.[ENTER]Wenn Du Erfolg hast, erh\228ltst Du folgende[ENTER]Belohnung: "
gameforge.locale.questscroll_4_hunt = "Schweinegott "
gameforge.locale.questscroll_4_mis = "Den Schweinegott t\246ten. "
gameforge.locale.questscroll_4_text = "In dieser Jahreszeit steht das reife Korn auf den[ENTER]Feldern. Es ist Zeit f\252r die Ernte, Zeit f\252r die[ENTER]Bauern, den Lohn ihrer harten Arbeit des Jahres[ENTER]einzubringen. Doch der Schweinegott und seine[ENTER]Genossen fressen das ganze Korn. Da ihre Gier das[ENTER]Leben der Bauern bedroht, m\252ssen wir sie[ENTER]erschlagen. T\246te den Schweinegott. Er ist meisst[ENTER]in der N\228he der Hauptstadt anzutreffen. Wenn Du[ENTER]ihn besiegst, erh\228ltst Du folgende Belohnung: "
gameforge.locale.questscroll_5_hunt = "B\228rengott "
gameforge.locale.questscroll_5_mis = "Den B\228rengott t\246ten. "
gameforge.locale.questscroll_5_text = "In seiner nat\252rlichen Umgebung war der B\228rengott[ENTER]brav. Seit kurzem taucht er jedoch in der N\228he[ENTER]der Hauptstadt auf und greift Menschen an. Er[ENTER]findet mehr und mehr Opfer. Wie viele schon[ENTER]gestorben sind, ist kaum noch festzustellen. Er[ENTER]muss von hier verschwinden. T\246te den B\228rengott.[ENTER]Wenn Du ihn tats\228chlich los wirst, erh\228ltst Du[ENTER]folgende Belohnung: "
gameforge.locale.questscroll_6_hunt = "Tigergott "
gameforge.locale.questscroll_6_mis = "Den Tigergott t\246ten. "
gameforge.locale.questscroll_6_text = "Ich kann es kaum glauben. Wie konnte der[ENTER]Tigergott nur so etwas Schreckliches tun? Ich bin[ENTER]nur eine einfache Frau, die jeden Tag dem[ENTER]Tigergott huldigte, der gelegentlich auf den[ENTER]Bergpfaden auftauchte. Aber eines Tages griffen[ENTER]der Tigergott und seine Anh\228nger meine Familie[ENTER]an! Alle wurden get\246tet, und ich verlor einen[ENTER]Arm. Bitte, r\228che meine Familie. Wenn Du den[ENTER]Tigergott t\246test, erh\228ltst Du folgende Belohnung: "
gameforge.locale.questscroll_7_hunt = "Anf\252hrerin der wei\223en Armee "
gameforge.locale.questscroll_7_mis = "Die Anf\252hrerin der wei\223en Armee t\246ten. "
gameforge.locale.questscroll_7_text = "Die wei\223e Armee ist eine Gruppe von Frauen, die[ENTER]von ihren M\228nnern und der Welt im Stich gelassen[ENTER]wurden. Sie sind zwar arm, aber wie sie die[ENTER]Dorfbewohner qu\228len, ist einfach nur brutal. Eine[ENTER]der Frauen wurde gesteinigt, als sie in das Dorf[ENTER]kam. Wir d\252rfen nicht zulassen, dass sie ins Dorf[ENTER]kommen und die B\252rger angreifen. T\246te 20 Anf\252hrer[ENTER]der wei\223en Armee. Wenn Du diesen Auftrag[ENTER]erfolgreich abschlie\223t, erh\228ltst Du folgende[ENTER]Belohnung: "
gameforge.locale.questscroll_8_hunt = "Anf\252hrer der Schwarzwindbande "
gameforge.locale.questscroll_8_mis = "Den Anf\252hrer der Schwarzwindbande t\246ten. "
gameforge.locale.questscroll_8_text = "Unsere Stra\223en sind nicht mehr sicher: Die[ENTER]Schwarzwindbande raubt seit einiger Zeit Reisende[ENTER]und H\228ndler aus. Sie sind so furchterregend, dass[ENTER]sich niemand traut, zur\252ckzuschlagen.[ENTER]Aber das kann so nicht weitergehen![ENTER]T\246te 20 Anf\252hrer der Schwarzwindbande. Wenn du[ENTER]diesen Auftrag erfolgreich abschlie\223t, erh\228ltst[ENTER]du folgende Belohnung: "
gameforge.locale.questscroll_9_hunt = "Barbarenh\228uptling "
gameforge.locale.questscroll_9_mis = "Den Barbarenh\228uptling t\246ten. "
gameforge.locale.questscroll_9_text = "Es ist schon eine Weile her, dass die Barbaren[ENTER]die Grenzen \252berschritten und das Dorf angriffen.[ENTER]Die Anzahl der Leute, die sie erschlugen, ging in[ENTER]die Hunderte. Die Anzahl derer, die gesch\228digt[ENTER]wurden, ist weitaus h\246her. Diese b\246sen Barbaren[ENTER]sind so brutal, dass sich niemand traute, Rache[ENTER]zu nehmen. Aber wir k\246nnen sie nicht l\228nger[ENTER]tolerieren. Erschlag 25 Barbarenh\228uptlinge. Wenn[ENTER]Du diesen Auftrag erfolgreich abschlie\223t,[ENTER]erh\228ltst Du folgende Belohnung: "
gameforge.locale.quest_temp_reward_1 = "Auftragsbelohnung "
gameforge.locale.quest_temp_reward_2 = "W\228hrend des Testzeitraums f\252r Auftr\228ge gibt es[ENTER]keine Belohnungen. Sp\228ter, nachdem eine Belohnung[ENTER]erhalten wurde, kann der aktuelle Auftrag erneut[ENTER]gespielt werden. "
