gameforge.locale.skeleton_gem = {}
gameforge.locale.skeleton_gem.accept_ask = "Fahrender H\228ndler:[ENTER]Oh, endlich! Du siehst aus, als w\252sstest du[ENTER]deine Waffen zu gebrauchen.[ENTER]Mein Leben steht auf dem Spiel. Bitte, hilf mir! "
gameforge.locale.skeleton_gem.accept_failure_info_label = "Zum Fahrenden H\228ndler zur\252ckkehren. "
gameforge.locale.skeleton_gem.accept_failure_info_text_1 = "Kehre zum Fahrenden H\228ndler zur\252ck. "
gameforge.locale.skeleton_gem.accept_failure_info_text_2 = "Erkl\228re dem Fahrenden H\228ndler, dass du den[ENTER]D\228monenedelstein+ nicht finden konntest. "
gameforge.locale.skeleton_gem.accept_failure_say_1 = "Kehre zur\252ck zum Fahrenden H\228ndler. "
gameforge.locale.skeleton_gem.accept_failure_say_2 = "Ich kann den D\228monenedelstein+ nicht finden.[ENTER]Was soll ich dem Fahrenden H\228ndler blo\223 sagen? "
gameforge.locale.skeleton_gem.accept_success_info_label = "Zur\252ck zum Fahrenden H\228ndler "
gameforge.locale.skeleton_gem.accept_success_info_text_1 = "Bring den D\228monenedelstein+ zum Fahrenden[ENTER]H\228ndler. "
gameforge.locale.skeleton_gem.accept_success_info_text_2 = "Du hast dem D\228monenmagier den D\228monenedelstein+[ENTER]abnehmen k\246nnen. Bringe ihn dem Fahrenden H\228ndler[ENTER]zur\252ck. "
gameforge.locale.skeleton_gem.accept_success_say_1 = "D\228monenedelstein+ erhalten. "
gameforge.locale.skeleton_gem.accept_success_say_2 = "Du hast den D\228monenedelstein+.[ENTER]Bring ihn dem Fahrenden H\228ndler. "
gameforge.locale.skeleton_gem.i_dont_have_the_skeleton_gem_yet = "Ich habe den D\228monenedelstein+ noch nicht[ENTER]gefunden. "
gameforge.locale.skeleton_gem.i_have_the_skeleton_gem = "Hier habe ich deinen D\228monenedelstein+! "
gameforge.locale.skeleton_gem.order_accept = "Ich werde ihn dir zur\252ckholen! "
gameforge.locale.skeleton_gem.order_accept_answer = "Fahrender H\228ndler:[ENTER]Oh, tausend Dank. Das werde ich dir nie[ENTER]vergessen! "
gameforge.locale.skeleton_gem.order_get_skeleton_gem_ = "Den D\228monenedelstein+ suchen. "
gameforge.locale.skeleton_gem.order_get_skeleton_gem_text = "Stell den D\228monenmagier und nimm ihm den[ENTER]D\228monenedelstein+ ab. "
gameforge.locale.skeleton_gem.order_refuse = "Das ist mir zu gef\228hrlich. "
gameforge.locale.skeleton_gem.order_refuse_answer = "Fahrender H\228ndler:[ENTER]Ich verstehe deine Bedenken. Die Aufgabe ist[ENTER]durchaus gef\228hrlich. Aber wenn nicht bald etwas[ENTER]geschieht, ist das mein Untergang! "
gameforge.locale.skeleton_gem.order_say = "Fahrender H\228ndler:[ENTER]Jetzt ist alles zu Ende. Mir bleibt nichts \252brig,[ENTER]als auf den Tod zu warten. Wenn mich doch blo\223[ENTER]diese Diebe nicht angegriffen h\228tten! Warum[ENTER]musste das gerade mir passieren? "
gameforge.locale.skeleton_gem.order_say2 = "Fahrender H\228ndler:[ENTER]Bitte hilf mir. Wenn du dem D\228monenmagier den[ENTER]D\228monenedelstein+ entrei\223en kannst, werde ich[ENTER]dich gro\223z\252gig belohnen. "
gameforge.locale.skeleton_gem.order_too_late = "Fahrender H\228ndler:[ENTER]Jemand anderes hat ihn mir bereits besorgt.[ENTER]Du musst dich nicht mehr darum k\252mmern. "
gameforge.locale.skeleton_gem.start_find_peddler_label = "Zum Fahrenden H\228ndler gehen. "
gameforge.locale.skeleton_gem.start_find_peddler_text_1 = "Geh zum Fahrenden H\228ndler. "
gameforge.locale.skeleton_gem.start_find_peddler_text_2 = "Frage den Fahrenden H\228ndler nach dem[ENTER]D\228monenedelstein+. "
gameforge.locale.skeleton_gem.start_say = "Brief des H\228ndlers:[ENTER]Ich wei\223 nicht, was ich tun soll.[ENTER]Mir wurde mein D\228monenedelstein+ gestohlen.[ENTER]Jetzt bin ich ruiniert, denn ihn zu kaufen hat[ENTER]mich all mein Geld gekostet.[ENTER]K\246nntest du mir bitte helfen? Es ist wirklich[ENTER]dringend! "
gameforge.locale.skeleton_gem.success_say = "Fahrender H\228ndler:[ENTER]Du hast es wirklich geschafft? Komm in meine[ENTER]Arme, geliebter Stein! Hab Dank. Du kannst dir[ENTER]nicht vorstellen, wie erleichtert ich bin. "
gameforge.locale.skeleton_gem.talk_about_skeleton_gem = "Nach D\228monenedelstein+ fragen. "
gameforge.locale.skill_group = {}
gameforge.locale.skill_group.board = "Das Flugblatt enth\228lt folgende Mitteilung:[ENTER]Wir rekrutieren mutige M\228nner und Frauen, die[ENTER]bereit sind, f\252r den Frieden des Reichs und seiner[ENTER]B\252rger zu k\228mpfen![ENTER]Voraussetzung f\252r den Eintritt ins Milit\228r:[ENTER]Mindestens Level 5. "
gameforge.locale.skill_group.dialog_assassin_1 = "Hier werden die Ninja ausgebildet, die gut im[ENTER]Verstecken und in Angriffen aus dem Hinterhalt[ENTER]sind. Sie konzentrieren sich auf die Handhabung[ENTER]des Dolches und von Giften.[ENTER]Nur Ninja in der Ausbildung und ab Level 5 k\246nnen[ENTER]beitreten. Sobald du dieses Level erreicht hast,[ENTER]erh\228ltst du ein Rekrutierungsschreiben.[ENTER]Wenn du bereit bist, als Ninja auf dunklen Pfaden[ENTER]zu schleichen, halte nach mir Ausschau. Dann[ENTER]unterhalten wir uns eingehender. "
gameforge.locale.skill_group.dialog_assassin_2 = "Hier werden die Ninja ausgebildet, die gut im[ENTER]Verstecken und in Angriffen aus dem Hinterhalt[ENTER]sind. Sie konzentrieren sich auf die Handhabung[ENTER]des Dolches und von Giften.[ENTER]Wenn du bereit bist, als Ninja auf dunklen Pfaden[ENTER]zu schleichen, bist du hier jederzeit willkommen. "
gameforge.locale.skill_group.dialog_assassin_3 = "Hier werden die Ninja ausgebildet, die Meister[ENTER]des Bogens sind. Es werden Fertigkeiten gelehrt,[ENTER]die einen Bogen erfordern, zum Beispiel[ENTER]Pfeilsalven gezielt auf alle Feinde in Reichweite[ENTER]zu verschie\223en. Nur Ninja in der Ausbildung und[ENTER]ab Level 5 k\246nnen beitreten. Sobald du dieses[ENTER]Level erreicht hast, erh\228ltst du ein[ENTER]Rekrutierungsschreiben. Wenn es dich[ENTER]interessiert, schau bei mir vorbei. "
gameforge.locale.skill_group.dialog_assassin_4 = "Hier werden die Ninja ausgebildet, die Meister[ENTER]des Bogens sind. Es werden Fertigkeiten gelehrt,[ENTER]die einen Bogen erfordern, zum Beispiel[ENTER]Pfeilsalven gezielt auf alle Feinde in Reichweite[ENTER]zu verschie\223en. Folg mir. Ich mache dich zum[ENTER]besten Sch\252tzen des Kontinents. "
gameforge.locale.skill_group.dialog_assassin_5 = "W\228hle zwischen der Nahkampf-Lehre und der[ENTER]Fernkampf-Lehre und schon erh\228ltst du die[ENTER]entsprechenden Fertigkeiten. "
gameforge.locale.skill_group.dialog_shaman_1 = "Dies ist der Ort, an dem sich die Schamanen[ENTER]treffen, die dem Pfad des Drachengottes folgen.[ENTER]Es werden Fertigkeiten f\252r den Umgang mit[ENTER]Amuletten und mit der Geistesmacht gelehrt, die[ENTER]es dem Schamanen erm\246glicht, Techniken des[ENTER]Feindes auf diesen zur\252ckzuwerfen, den eigenen[ENTER]Verteidigungswert durch heiligen Schutz zu[ENTER]verst\228rken und befreundete K\228mpfer zu[ENTER]unterst\252tzen. Nur Schamanen in der Ausbildung und[ENTER]ab Level 5 k\246nnen beitreten. Sobald du dieses[ENTER]Level erreicht hast, erh\228ltst du ein[ENTER]Rekrutierungsschreiben. Wenn du bereit bist f\252r[ENTER]die Lehren der Drachenmacht, dann such mich auf. "
gameforge.locale.skill_group.dialog_shaman_2 = "Dies ist der Ort, an dem sich die Schamanen[ENTER]treffen, die dem Pfad des Drachengottes folgen.[ENTER]Es werden Fertigkeiten f\252r den Umgang mit[ENTER]Amuletten und mit der Geistesmacht gelehrt, die[ENTER]es dem Schamanen erm\246glicht, Techniken des[ENTER]Feindes auf diesen zur\252ckzuwerfen, den eigenen[ENTER]Verteidigungswert durch heiligen Schutz zu[ENTER]verst\228rken und befreundete K\228mpfer zu[ENTER]unterst\252tzen. Meinst du, dass du bereit bist, die[ENTER]Lehren des Drachengottes mit mir zu verbreiten?[ENTER]Ein Gl\228ubiger voller Demut ist allzeit[ENTER]willkommen. "
gameforge.locale.skill_group.dialog_shaman_3 = "Hier verehren die Schamanen die Macht der Natur[ENTER]und des Lichts. Es werden Fertigkeiten gelehrt,[ENTER]die im Zusammenhang mit Blitz und Wind stehen,[ENTER]aber auch solche, die die Kr\228fte der Heilung[ENTER]aktivieren. Schamanen, die der Lehre der Heilung[ENTER]folgen, arbeiten h\228ufig als Gruppe, um sich[ENTER]gegenseitig zu unterst\252tzen.[ENTER]Nur Schamanen in der Ausbildung und ab Level 5[ENTER]k\246nnen beitreten. Sobald du dieses Level erreicht[ENTER]hast, erh\228ltst du ein Rekrutierungsschreiben.[ENTER]Ich erwarte dich hier. "
gameforge.locale.skill_group.dialog_shaman_4 = "Hier verehren die Schamanen die Macht der Natur[ENTER]und des Lichts. Es werden Fertigkeiten gelehrt,[ENTER]die im Zusammenhang mit Blitz und Wind stehen,[ENTER]aber auch solche, die die Kr\228fte der Heilung[ENTER]aktivieren. Schamanen, die der Lehre der Heilung[ENTER]folgen, arbeiten h\228ufig als Gruppe, um sich[ENTER]gegenseitig zu unterst\252tzen.[ENTER]M\246chtest du, zusammen mit mir, anderen helfen?[ENTER]Deine Unterst\252tzung k\228me allen Leidenden zugute.[ENTER]Bitte hilf mir dabei. "
gameforge.locale.skill_group.dialog_shaman_5 = "W\228hle zwischen der Lehre der Drachenmacht und der[ENTER]Lehre der Heilung und schon erh\228ltst du die[ENTER]entsprechenden Fertigkeiten. "
gameforge.locale.skill_group.dialog_sura_1 = "Ich lehre diejenigen, die mit der teuflischen[ENTER]Saat gesegnet sind, wie sie deren Magie nutzen[ENTER]k\246nnen. Sie lernen, Schwerter und R\252stungen mit[ENTER]Zaubern zu belegen, die Angriff und Verteidigung[ENTER]erh\246hen. Au\223erdem beschw\246ren sie Geister aus der[ENTER]H\246lle herauf und senken so die Moral des Feindes.[ENTER]Nur Sura in der Ausbildung und ab Level 5 k\246nnen[ENTER]beitreten. Sobald du dieses Level erreicht hast,[ENTER]erh\228ltst du ein Rekrutierungsschreiben.[ENTER]Wenn du bereit bist, dein teuflisches Erbe[ENTER]anzunehmen, komm hierher. "
gameforge.locale.skill_group.dialog_sura_2 = "Ich lehre diejenigen, die mit der teuflischen[ENTER]Saat gesegnet sind, wie sie deren Magie nutzen[ENTER]k\246nnen. Sie lernen, Schwerter und R\252stungen mit[ENTER]Zaubern zu belegen, die Angriff und Verteidigung[ENTER]erh\246hen. Au\223erdem beschw\246ren sie Geister aus der[ENTER]H\246lle herauf und senken so die Moral des Feindes.[ENTER]Bist du bereit, verzauberte Schwerter zu[ENTER]schwingen und finstere Fl\252che zu schleudern? Ich[ENTER]kann dir versichern: Die Macht, die du hier[ENTER]findest, sucht ihresgleichen. "
gameforge.locale.skill_group.dialog_sura_3 = "Wenn du dich f\252r diesen Ort interessierst: Hier[ENTER]findest du nur jene, die sich der Dunkelheit[ENTER]verschrieben haben. Sie lehren den Umgang mit[ENTER]Geistern und Teufeln - und mit den Flammen der[ENTER]H\246lle. Nur Sura in der Ausbildung und ab Level 5[ENTER]k\246nnen beitreten. Sobald du dieses Level erreicht[ENTER]hast, erh\228ltst du ein Rekrutierungsschreiben.[ENTER]Wenn du die Dunkelheit dein Zuhause nennst,[ENTER]findest du hier deine Br\252der und Schwestern. "
gameforge.locale.skill_group.dialog_sura_4 = "Wenn du dich f\252r diesen Ort interessierst: Hier[ENTER]findest du nur jene, die sich der Dunkelheit[ENTER]verschrieben haben. Sie lehren den Umgang mit[ENTER]Geistern und Teufeln - und mit den Flammen der[ENTER]H\246lle. Wenn du dich daf\252r interessierst,[ENTER]Freundschaft mit b\246sen Geistern zu schlie\223en, die[ENTER]dich St\252ck f\252r kleines St\252ckchen verzehren, dann[ENTER]komm! Tritt unserem Orden bei und lass deine[ENTER]Menschlichkeit zur\252ck... "
gameforge.locale.skill_group.dialog_sura_5 = "W\228hle zwischen der Schwarze-Magie-Lehre und der[ENTER]Magische-Waffen-Lehre und schon erh\228ltst du die[ENTER]entsprechenden Fertigkeiten. "
gameforge.locale.skill_group.dialog_warrior_1 = "Wei\223t du, wo du dich befindest? Hier werden[ENTER]K\228mpfer ausgebildet, Krieger, die St\228rksten und[ENTER]Mutigsten! Es werden Techniken f\252r schnelle[ENTER]Schlagfolgen gelehrt und m\228chtige Angriffsstile[ENTER]mit Schwert oder Speer.[ENTER]Nur Krieger in der Ausbildung und ab Level 5[ENTER]k\246nnen beitreten. Sobald du dieses Level erreicht[ENTER]hast, erh\228ltst du ein Rekrutierungsschreiben.[ENTER]Wenn du die wahre St\228rke deines K\246rpers[ENTER]herausfinden m\246chtest, komm zu mir! "
gameforge.locale.skill_group.dialog_warrior_2 = "Wei\223t du, wo du dich befindest? Hier werden[ENTER]K\228mpfer ausgebildet, Krieger, die St\228rksten und[ENTER]Mutigsten! Es werden Techniken f\252r schnelle[ENTER]Schlagfolgen gelehrt und m\228chtige Angriffsstile[ENTER]mit Schwert oder Speer.[ENTER]Wie sieht es aus? Willst du trainieren? "
gameforge.locale.skill_group.dialog_warrior_3 = "Bei mir lernen angehende Krieger, ihr Chi richtig[ENTER]zu fokussieren. Das bedingt einen langsamen,[ENTER]geistig ersch\246pfenden Kampfstil. Daf\252r k\246nnen die[ENTER]Angriffe mehrere Gegner gleichzeitig treffen. Und[ENTER]die undurchdringliche Verteidigung der gro\223en[ENTER]Mental-Krieger ist geradezu legend\228r.[ENTER]Nur Krieger in der Ausbildung und ab Level 5[ENTER]k\246nnen beitreten. Sobald du dieses Level erreicht[ENTER]hast, erh\228ltst du ein Rekrutierungsschreiben.[ENTER]Wenn du interessiert bist, schau bei mir vorbei. "
gameforge.locale.skill_group.dialog_warrior_4 = "Bei mir lernen angehende Krieger, ihr Chi richtig[ENTER]zu fokussieren. Das bedingt einen langsamen,[ENTER]geistig ersch\246pfenden Kampfstil. Daf\252r k\246nnen die[ENTER]Angriffe mehrere Gegner gleichzeitig treffen. Und[ENTER]die undurchdringliche Verteidigung der gro\223en[ENTER]Mental-Krieger ist geradezu legend\228r.[ENTER]Was meinst du? Bist du geeignet f\252r den[ENTER]Mental-Kampf? "
gameforge.locale.skill_group.dialog_warrior_5 = "W\228hle zwischen der K\246rper-Kampf-Lehre und der[ENTER]Mental-Kampf-Lehre und schon erh\228ltst du die[ENTER]entsprechenden Fertigkeiten. "
gameforge.locale.skill_group.invite = "Rekrutierungsmitteilung des Milit\228rs: "
gameforge.locale.skill_group.lets_join_skill_group_1 = "[COLOR r;1|g;0.6|b;0.6]Bekanntmachung der[ENTER]Kriegerrekrutierung[/COLOR][ENTER]Wenn du einen Krieger wegen seiner Schnelligkeit[ENTER]und Angriffskraft bewunderst, empfehle ich dir die[ENTER]K\246rper-Kampf-Lehre.[ENTER]Wenn du unangreifbar bleiben und ganze Gruppen von[ENTER]Monstern mit einem Schlag ausl\246schen m\246chtet,[ENTER]empfehle ich die Mental-Kampf-Lehre.[ENTER]Ich erwarte dich am Dorfplatz. "
gameforge.locale.skill_group.lets_join_skill_group_2 = "[COLOR r;1|g;0.6|b;0.6]Bekanntmachung der[ENTER]Ninjarekrutierung[/COLOR][ENTER]Wenn du dir einen Namen als hervorragender Sch\252tze[ENTER]machen willst, lerne beim Fernkampf Lehrer.[ENTER]Wenn du bereit bist, mit den Schatten der Nacht zu[ENTER]verschmelzen und deine ahnungslosen Opfer[ENTER]hinterr\252cks anzugreifen, ist der Nahkampf das[ENTER]Richtige f\252r dich.[ENTER]Ich erwarte dich am Dorfplatz. "
gameforge.locale.skill_group.lets_join_skill_group_3 = "[COLOR r;1|g;0.6|b;0.6]Bekanntmachung der[ENTER]Sura-Rekrutierung[/COLOR][ENTER]M\246chtest du ein \252bermenschlicher[ENTER]Hexen-Schwertmeister sein und deine Gegner die[ENTER]verzauberte Klinge sp\252ren lassen? Dann empfehle[ENTER]ich dir, die Kunst der magischen Waffen zu erlernen.[ENTER]Wenn du jedoch willst, dass du als Beherrscher der[ENTER]Flammen und der Fl\252che gef\252rchtet wirst, dann[ENTER]lerne die Kunst der Schwarzen Magie.[ENTER]Ich erwarte dich am Dorfplatz. "
gameforge.locale.skill_group.lets_join_skill_group_4 = "[COLOR r;1|g;0.6|b;0.6]Bekanntmachung der[ENTER]Schamanenrekrutierung[/COLOR][ENTER]Wenn du die Kr\228fte des Drachengottes in deinen[ENTER]Mitstreitern wecken und seinen feurigen Atem gegen[ENTER]eure Feinde einsetzen m\246chtest, dann empfehle ich[ENTER]dir die Lehre der Drachenmacht.[ENTER]Wenn du jedoch die Schmerzen der Leidenden lindern[ENTER]willst, indem du wiederherstellst und heilst, dann[ENTER]solltest du den Lehrer der Heilung aufsuchen.[ENTER]Ich erwarte dich am Dorfplatz. "
gameforge.locale.stamina_food = {}
gameforge.locale.stamina_food.accept_ask = "Oakgu:[ENTER]Was, das ist alles?[ENTER]Als ich jung war,[ENTER]konnte ich mehr als zehn gr\252ne Fr\246sche fangen! "
gameforge.locale.stamina_food.accept_failure_say_1 = "Zu Oakgu zur\252ckkehren. "
gameforge.locale.stamina_food.accept_failure_say_2 = "Ich komme nicht an gr\252nes Froschfleisch.[ENTER]Was soll ich Oakgu blo\223 sagen? "
gameforge.locale.stamina_food.accept_success_info_label = "Das gr\252ne Froschfleisch zu Oakgu bringen. "
gameforge.locale.stamina_food.accept_success_info_text_1 = "Das gr\252ne Froschfleisch zu Oakgu bringen. "
gameforge.locale.stamina_food.accept_success_info_text_2 = "Gib ihm das gr\252ne Froschfleisch,[ENTER]und schon bald kannst Du gr\252ne Froschsuppe essen. "
gameforge.locale.stamina_food.accept_success_say_1 = "Ich habe gr\252nes Froschfleisch. "
gameforge.locale.stamina_food.accept_success_say_2 = "Ich habe gr\252nes Froschfleisch.[ENTER]Bringe es zu Oakgu. "
gameforge.locale.stamina_food.baekgo_accept_failure_info_label = "Zu Oakgu zur\252ckkehren. "
gameforge.locale.stamina_food.baekgo_accept_failure_info_text_1 = "Zu Oakgu zur\252ckkehren. "
gameforge.locale.stamina_food.baekgo_accept_failure_info_text_2 = "Erkl\228re Oakgu, dass Du kein gr\252nes Froschfleisch[ENTER]besorgen konntest. "
gameforge.locale.stamina_food.butcher = {}
gameforge.locale.stamina_food.butcher.start_say = "Alter Mann im Restaurant Suhpyung:[ENTER]Mein K\246rper ist nicht mehr so in Schuss wie[ENTER]fr\252her. Als ich jung war, konnte ich eine ganze[ENTER]Woche durcharbeiten, und danach hatte ich immer[ENTER]noch genug Energie, jeden Abend zu trinken![ENTER]Aber inzwischen f\228llt mir sogar das Stehen[ENTER]schwer. In solchen Momenten erscheint mir eine[ENTER]Schale gr\252ner Froschsuppe als ein gutes Mittel,[ENTER]um die Energie wiederherzustellen. "
gameforge.locale.stamina_food.butcher.start_say2 = "Alter Mann im Restaurant Suhpyung:[ENTER]Ihr m\246chtet wissen, was gr\252ne Froschsuppe ist?[ENTER]Wenn Ihr eine Schale davon esst, erm\252det Ihr[ENTER]nicht! Selbst wenn Ihr eine Woche auf den Feldern[ENTER]arbeiten w\252rdet, h\228ttet Ihr abends noch Energie![ENTER]Ein Freund von mir namens Oakgu ist der beste[ENTER]Koch f\252r gr\252ne Froschsuppe, den ich kenne.[ENTER]Aber aus irgendeinem Grund macht er die Suppe[ENTER]nicht mehr. "
gameforge.locale.stamina_food.butcher.talk = "Sprechen. "
gameforge.locale.stamina_food.complete_say = "Oakgu:[ENTER]Hast Du es? Erz\228hl niemandem[ENTER]von der gr\252nen Froschsuppe.[ENTER]Und ganz besonders nicht diesem Bastard im[ENTER]Restaurant Suhpyung! Das ist nicht genug. Wenn[ENTER]die Leute von der gr\252nen Froschsuppe h\246ren,[ENTER]kommen sie her und essen sie auf! "
gameforge.locale.stamina_food.food_manager = {}
gameforge.locale.stamina_food.food_manager.order_say = "Oakgu:[ENTER]Gr\252ne Froschsuppe? Ja! Die habe ich fr\252her[ENTER]gekocht. Aber das konnte ich nur in meiner[ENTER]Jugend. Damals machte ich mir keine Sorgen wegen[ENTER]der gef\228hrlichen Monster. Daher konnte ich immer[ENTER]gr\252ne Fr\246sche jagen. "
gameforge.locale.stamina_food.food_manager.order_say2 = "Oakgu:[ENTER]Aber jetzt?[ENTER]Jetzt bin ich alt und habe nicht gen\252gend Energie[ENTER]f\252r so etwas. Ich m\246chte selbst gern gr\252ne[ENTER]Froschsuppe essen. Aber gr\252ne Fr\246sche sind nicht[ENTER]leicht zu erlegen! Wenn Du mir etwas gr\252nes[ENTER]Froschfleisch besorgst, koche ich Dir die beste[ENTER]gr\252ne Froschsuppe \252berhaupt! "
gameforge.locale.stamina_food.food_manager.talk = "Sprechen. "
gameforge.locale.stamina_food.food_manager.talk_about_greeenfrog_soup = "\220ber gr\252ne Froschsuppe "
gameforge.locale.stamina_food.i_dont_have_the_greeenfrog_meat_yet = "Ich habe noch kein gr\252nes Froschfleisch. "
gameforge.locale.stamina_food.i_have_the_greenfrog_meat = "Ich habe das gr\252ne Froschfleisch! "
gameforge.locale.stamina_food.order_accept = "Na gut, dann besorge ich es. "
gameforge.locale.stamina_food.order_accept_answer = "Oakgu:[ENTER]Gro\223artig! Viel Gl\252ck! "
gameforge.locale.stamina_food.order_get_greenfrog_general_meat_label = "Gr\252nes Froschfleisch besorgen. "
gameforge.locale.stamina_food.order_get_greenfrog_general_meat_text = "Jage gr\252ne Fr\246sche und besorg so gr\252nes[ENTER]Froschfleisch. "
gameforge.locale.stamina_food.order_refuse = "Interessiert mich nicht. "
gameforge.locale.stamina_food.order_refuse_answer = "Oakgu:[ENTER]Die Chance, gr\252ne Froschsuppe zu essen, hat man[ENTER]nicht alle Tage! "
gameforge.locale.stamina_food.order_too_late = "Oakgu:[ENTER]Du hast es nicht verdient, gr\252ne Froschsuppe zu[ENTER]essen! Sayonara! "
