gameforge.locale.stash.enlarge_2_have_mark = "Ich habe das Symbol. "
gameforge.locale.stash.enlarge_2_have_mark2 = "Du willst mich wohl f\252r dumm verkaufen. Da ist[ENTER]nicht das Symbol der alten Frau![ENTER]Hast du es etwa verloren?[ENTER]Ich hasse L\252gner. Los, such das Symbol. "
gameforge.locale.stash.enlarge_2_have_mark3 = "Sieh an, die alte Frau hat dir ihren Segen[ENTER]gegeben. Du hast tats\228chlich das Zeug zum Helden.[ENTER]Und wer hat es von Anfang an gesagt? Der gute[ENTER]alte Lagerverwalter! Also vergiss nicht, mich f\252r[ENTER]meine Dienste zu belohnen, wenn du ber\252hmt bist.[ENTER]Ich werde dein Lager um 15 F\228cher vergr\246\223ern. "
gameforge.locale.stash.enlarge_2_msg1 = "Ich soll dein Lager noch einmal vergr\246\223ern? Sehe[ENTER]ich aus wie ein Wohlt\228ter?[ENTER]Andererseits... Du hast das Gesicht eines Helden.[ENTER]Hmm...  "
gameforge.locale.stash.enlarge_2_msg2 = "Pass auf: Ich gebe dir ein Empfehlungsschreiben,[ENTER]damit gehst du zu der alten Frau. Sie wird dich[ENTER]pr\252fen und dir sagen, ob tats\228chlich die Energie[ENTER]und der Wille eines Helden durch deinen K\246rper[ENTER]str\246men. "
gameforge.locale.stash.enlarge_2_no_mark = "Die alte Frau wollte mich nicht pr\252fen. "
gameforge.locale.stash.enlarge_2_no_mark2 = "Milchbubi? Das hat sie zu dir gesagt?? Ha, ha,[ENTER]ha! Ja, so ist sie.[ENTER]Aber kein Grund, den Kopf h\228ngen zu lassen. Komm[ENTER]einfach wieder, wenn du ein h\246heres Level hast! "
gameforge.locale.stash.enlarge_2_oldwoman_accept = "Hmm, ja... Du wirst sehr erfolgreich sein in der[ENTER]Zukunft. Gib dein Bestes f\252r das Reich und du[ENTER]wirst sehen, es zahlt sich aus.[ENTER]Hier hast du ein Symbol, als Zeichen meiner[ENTER]Wertsch\228tzung. Gib es dem Lagerverwalter. "
gameforge.locale.stash.enlarge_2_oldwoman_greet = "Soso, ein Empfehlungsschreiben des[ENTER]Lagerverwalters. Gut, lass mich mal dein Gesicht[ENTER]ansehen. "
gameforge.locale.stash.enlarge_2_oldwoman_reject = "Dieser verr\252ckte Lagerverwalter schickt mir[ENTER]dauernd Milchbubis! Du bist noch nicht reif. Komm[ENTER]wieder, wenn du erwachsen bist. "
gameforge.locale.stash.enlarge_2_oldwoman_title1 = "Geh zur\252ck zum Lagerverwalter. "
gameforge.locale.stash.enlarge_2_oldwoman_title2 = "Geh zur\252ck zum Lagerverwalter und zeige ihm das[ENTER]Symbol der alten Frau. "
gameforge.locale.stash.enlarge_2_recommendation = "Empfehlungsschreiben des Lagerverwalters "
gameforge.locale.stash.enlarge_2_title = "Ich soll das Empfehlungsschreiben zu der alten[ENTER]Frau bringen. "
gameforge.locale.stash.enlarge_3_complete = "Ich habe die esoterische Sekte ausgel\246scht. "
gameforge.locale.stash.enlarge_3_counter = "Verbleibende Sekten-Mitglieder "
gameforge.locale.stash.enlarge_3_msg1 = "Du schon wieder![ENTER]Wie w\228re es, dem Reich erneut zu dienen? Es gibt[ENTER]irgendwo eine esoterische Sekte eines d\252steren[ENTER]Glaubens. T\246te 100 Mitglieder dieser esoterischen[ENTER]Sekte und bring sie her. Du hast 30 Minuten Zeit. "
gameforge.locale.stash.enlarge_3_notyet = "Die esoterische Sekte ist noch immer stark.[ENTER]Streng dich an! "
gameforge.locale.stash.enlarge_3_success = "Gute Arbeit![ENTER]Ich werde deinen Einsatz belohnen, indem ich dein[ENTER]Lager vergr\246\223ere. "
gameforge.locale.stash.enlarge_3_timer = "Verbleibende Zeit "
gameforge.locale.stash.enlarge_3_title = "Vergr\246\223ere das Lager, indem du die esoterische[ENTER]Sekte ausschaltest! "
gameforge.locale.stash.enlarge_4_msg = "Schon wieder? Du kriegst wohl nie genug?[ENTER]Nein, jetzt ist Schluss! Ich bin doch nicht der[ENTER]Weihnachtsmann! "
gameforge.locale.stash.enlarge_first1 = "Du willst dein Lager vergr\246\223ern? Hmm, lass mich[ENTER]erst herausfinden, ob du dem Reich gut dienst. "
gameforge.locale.stash.enlarge_first1_cannot = "Tut mir leid, aber im Moment kann ich nichts f\252r[ENTER]dich tun.[ENTER]Ich habe den Stauraum so vieler Leute vergr\246\223ert,[ENTER]dass jetzt kein Platz mehr ist. Es wird etwas[ENTER]dauern, bis ich mein Lager weiter ausgebaut habe.[ENTER]Warum verwendest du nicht den Platz, den du[ENTER]momentan hast? "
gameforge.locale.stash.enlarge_first2 = "Ist gegen B\228rengalle erh\228ltlich.[ENTER]Ich gebe dir 30 Minuten, um mir 30 B\228rengallen zu[ENTER]bringen. Dann werde ich dich anerkennen![ENTER]Aber du ben\246tigst   "
gameforge.locale.stash.enlarge_first3 = ". "
gameforge.locale.stash.enlarge_no_need = "Klar, klar, einfach mit mir sprechen, wenn du[ENTER]etwas brauchst! "
gameforge.locale.stash.enlarge_try_no = "Ich werde es sp\228ter versuchen. "
gameforge.locale.stash.enlarge_try_ok = "Ich werde es versuchen. "
gameforge.locale.stash.enlarge_try_ok_answer = "Na dann: Bis in 30 Minuten! "
gameforge.locale.stash.first_open = "So, dein Lager ist er\246ffnet.[ENTER]Wenn du es verwenden m\246chtest, sprich einfach mit[ENTER]mir. Das Passwort f\252r dein Lager lautet momentan[ENTER]000000. Aus Sicherheitsgr\252nden solltest du das[ENTER]aber sofort \228ndern.[ENTER]Du meinst, dass 45 F\228cher zu wenig sind? Na, dann[ENTER]sei mal lieber nett zu mir, vielleicht \252berlasse[ENTER]ich dir irgendwann noch ein paar mehr. Ha, ha, ha! "
gameforge.locale.stash.gold_bar_beginner_info = "Wei\223t du, was ein Goldbarren ist? Nat\252rlich wei\223t[ENTER]du das.[ENTER]Aber wei\223t du auch, wof\252r er gut ist?[ENTER]Ganz einfach. Wenn du viel Yang mit dir[ENTER]herumtr\228gst, ist das, als w\252rdest du laut rufen:[ENTER]\"Hallo, bitte t\246te mich und nimm all mein Geld!\"[ENTER]Darum tausche ich das Yang der Leute gegen[ENTER]Goldbarren und lagere diese Barren hier f\252r sie.[ENTER]Dann k\246nnen sie nicht verloren gehen.[ENTER]Zugegeben, ich verlange etwas mehr Yang, als der[ENTER]Goldbarren wert ist. Aber schlie\223lich habe ich ja[ENTER]auch einige Arbeit damit, nicht wahr? Es gibt[ENTER]keinen Grund, sich betrogen zu f\252hlen. Wie du[ENTER]wei\223t, ist es da drau\223en sehr gef\228hrlich. "
gameforge.locale.stash.greet1 = "Du willst das Lager benutzen?[ENTER]Es gibt nichts umsonst und Lagernutzung schon gar[ENTER]nicht.[ENTER]Aber du hast Gl\252ck: ich bin heute so guter Laune,[ENTER]dass ich dir meinen Lagerplatz f\252r nur 500 Yang[ENTER]anbiete.[ENTER]Na, wie w\228re das? Ist doch billig, oder? Ha, ha,[ENTER]ha! "
