gameforge.locale.years_greetings.give_msg = "Ich danke dir vielmals! M\246ge der Drachengott dich[ENTER]segnen. Zum Dank erh\228ltst du von mir diesen[ENTER]Beutel mit Yang. Eine friedvolle Neujahrsnacht[ENTER]w\252nsche ich! "
