gameforge.main_quest_flame_lv100 = {}
gameforge.main_quest_flame_lv100._010_sendLetter = "Schwarze Materie "
gameforge.main_quest_flame_lv100._020_say = "Yak-Hwan sucht nach dir. Bitte gehe zu ihm. "
gameforge.main_quest_flame_lv100._030_say = "Willkommen. Yon-I-Walker konnte seine[ENTER]Untersuchungen abschlie\223en. Das Ph\228nomen, das du[ENTER]im Feuerland beobachtet das, wird als Schwarze[ENTER]Materie bezeichnet. "
gameforge.main_quest_flame_lv100._040_say = "Sie str\246mt aus dem Inneren der Festung und[ENTER]ver\228ndert die D\228monen der Umgebung. Je l\228nger sie[ENTER]unter ihrem Einfluss stehen, desto st\228rker und[ENTER]aggressiver werden sie. Wir m\252ssen verhindern,[ENTER]dass diese Schwarze Materie sich weiter ausbreitet! "
gameforge.main_quest_flame_lv100._050_say = {}
gameforge.main_quest_flame_lv100._060_say = "W\228hrend unser Alchemist nach einer L\246sung sucht,[ENTER]sollten wir nicht unt\228tig herumsitzen. Kehre ins[ENTER]Feuerland zur\252ck und erledige 300 D\228monen um die[ENTER]Festung herum. So sollten wir die Schwarze Materie[ENTER]eind\228mmen k\246nnen. "
gameforge.main_quest_flame_lv100._070_say = "Selbstverst\228ndlich. "
gameforge.main_quest_flame_lv100._080_say = "Danke. Und nun beeile dich! "
gameforge.main_quest_flame_lv100._090_notice = "Erledige 300 Feuerland-D\228monen in der N\228he der[ENTER]Festung und dem Fundort der Sonnenkr\228uter. "
gameforge.main_quest_flame_lv100._100_sayTitle = "D\228monenhatz "
gameforge.main_quest_flame_lv100._110_say = "Erledige 300 Feuerland-D\228monen in der N\228he der[ENTER]Festung und dem Fundort der Sonnenkr\228uter. "
gameforge.main_quest_flame_lv100._120_say = "Ich f\252rchte, du hast noch nicht genug D\228monen[ENTER]erledigt. Kehre ins Feuerland zur\252ck und k\228mpfe[ENTER]weiter. "
gameforge.main_quest_flame_lv100._130_notice = "Du hast alle erforderlichen D\228monen besiegt.[ENTER]Erstatte nun Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv100._140_say = "Suche Yak-Hwan auf. "
gameforge.main_quest_flame_lv100._150_say = "Sehr gut, das sollte die Verbreitung der Schwarzen[ENTER]Materie aufgehalten haben. Ruhe dich etwas auf,[ENTER]w\228hrend ich mich mit dem Alchemisten berate. "
gameforge.main_quest_flame_lv100._160_sendLetter = "Nimbustinktur "
gameforge.main_quest_flame_lv100._170_say = "Der Alchemist sucht nach dir. Es scheint dringend[ENTER]zu sein! "
gameforge.main_quest_flame_lv100._180_say = "Eine Katastrophe! Ich hatte Yak-Hwan angewiesen,[ENTER]mit Bedacht zu handeln. Und was macht er? St\252rzt[ENTER]uns erhobenen Schwertes ins Chaos! Die Schwarze[ENTER]Materie w\228chst und verbreitet sich schneller, wenn[ENTER]der Wirt, in dem sie sich eingenistet hat, stirbt.[ENTER]Nun erfahre ich, dass bereits 300 infizierte[ENTER]D\228monen get\246tet wurden! Das ist nicht gut ... "
gameforge.main_quest_flame_lv100._190_say = "Unter diesen Bedingungen reicht nat\252rlich auch[ENTER]meine Nimbustinktur, die die Schwarze Materie[ENTER]bannen soll, nicht mehr. Ich brauche dringend[ENTER]Zutaten, um mehr davon herzustellen. "
gameforge.main_quest_flame_lv100._200_say = {}
gameforge.main_quest_flame_lv100._210_say = "Bringe mir 10 Fundamentsteine, 50 B\228rengallen, 10[ENTER]Spinnen-Gifts\228cke und 200 Energiesplitter. Einem[ENTER]erfahrenen K\228mpfer wie dir muss ich sicherlich[ENTER]nicht erkl\228ren, wo du all diese Dinge findest, oder? "
gameforge.main_quest_flame_lv100._220_say = "Ich mache mich gleich auf den Weg. "
gameforge.main_quest_flame_lv100._230_say = "Sehr gut. Beeile dich, denn mit jeder Minute, in[ENTER]der wir nichts unternehmen, verbreitet sich die[ENTER]Schwarze Materie weiter. "
gameforge.main_quest_flame_lv100._240_notice = "Besorge die Zutaten, mit denen der Alchemist die[ENTER]Nimbustinktur herstellen kann. "
gameforge.main_quest_flame_lv100._250_say = "Verbleibende Zutaten "
gameforge.main_quest_flame_lv100._260_sayTitle = "Nimbustinktur "
gameforge.main_quest_flame_lv100._270_say = "Besorge 10 Fundamentsteine, 50 B\228rengallen, 10[ENTER]Spinnen-Gifts\228cke und 200 Energiesplitter. Bringe[ENTER]die Zutaten zum Alchemisten. "
gameforge.main_quest_flame_lv100._280_say = "Du hast alle Zutaten gefunden! Gro\223artig, dann[ENTER]werde ich mich jetzt an die Arbeit machen. Ich[ENTER]rufe dich, sobald die Nimbustinktur fertig ist. "
gameforge.main_quest_flame_lv100._290_say = "Wenn wir die Schwarze Materie nicht bald[ENTER]aufhalten, sieht es zappenduster aus. Los, bringe[ENTER]mir alle Zutaten f\252r die Nimbustinktur. "
gameforge.main_quest_flame_lv100._300_notice = "Du hast alle n\246tigen Zutaten beisammen. Kehre nun[ENTER]zum Alchemisten zur\252ck. "
gameforge.main_quest_flame_lv100._310_say = "Sprich mit dem Alchemisten. "
gameforge.main_quest_flame_lv100._320_sendLetter = "Schwarze Materie aufhalten "
gameforge.main_quest_flame_lv100._330_say = "So ein ... hmpf ... Ich habe mich beim Schmied[ENTER]beschwert, weil die Fundamentsteine zu grob[ENTER]gemahlen waren. Und nun? Ist er beleidigt und[ENTER]weigert sich, die restlichen Fundamentsteine zu[ENTER]Pulver zu verarbeiten. Alter Sturkopf! K\246nntest du[ENTER]nicht mal mit ihm reden? "
gameforge.main_quest_flame_lv100._340_say = "Sicher. "
gameforge.main_quest_flame_lv100._350_say = "Danke. Hier sind die Fundamentsteine. Und bringe[ENTER]ihm diesen Korb mit Leckereien als Entschuldigung. "
gameforge.main_quest_flame_lv100._360_sayTitle = "Schmied bes\228nftigen "
gameforge.main_quest_flame_lv100._370_say = "Bes\228nftige den Schmied und \252berzeuge ihn davon,[ENTER]die Fundamentsteine zu feinem Pulver zu mahlen. "
gameforge.main_quest_flame_lv100._380_say = "Fundamentsteinpulver: 1 St\252ck "
gameforge.main_quest_flame_lv100._390_say = "Was kann ich f\252r dich tun? Soll ich dein Schwert[ENTER]sch\228rfen? Deine R\252stung aufpolieren? "
gameforge.main_quest_flame_lv100._400_say = "Nein, heute nicht. Ich bin gekommen, weil der[ENTER]Alchemist dich um Verzeihung f\252r seine vorschnelle[ENTER]Zunge bitten m\246chte. Er schickt dir diesen Korb[ENTER]mit Leckereien. "
gameforge.main_quest_flame_lv100._410_say = "Hm, das Fundamentsteinpulver scheint ihm wichtig[ENTER]zu sein. Es widerstrebt mir, diesem undankbaren[ENTER]Knilch zu helfen, aber weil du es bist, werde ich[ENTER]die Fundamentsteine mahlen. Warte einen Augenblick. "
gameforge.main_quest_flame_lv100._420_say = "Ich danke dir. "
gameforge.main_quest_flame_lv100._430_say = "Stellt sich der Schmied etwa stur? Gib ihm den[ENTER]Korb und bitte ihn um Hilfe. Bei dir wird er nicht[ENTER]nein sagen k\246nnen. "
gameforge.main_quest_flame_lv100._440_notice = "Das Fundamentsteinpulver ist fertig. Bringe es zum[ENTER]Alchemisten. "
gameforge.main_quest_flame_lv100._450_say = "Oh, fein wie Babypuder, ausgezeichnet! Der alte[ENTER]Sturkopf kann es also doch, hehe. Nun kann ich die[ENTER]Nimbustinktur mischen. Ruhe dich etwas aus. Ich[ENTER]werde dich rufen, wenn sie fertig ist. "
gameforge.main_quest_flame_lv101 = {}
gameforge.main_quest_flame_lv101._010_sendLetter = "Geheimnisvolle Festung "
gameforge.main_quest_flame_lv101._020_say = "Yak-Hwan sucht nach dir. Gehe zu ihm und finde[ENTER]heraus, was er m\246chte. "
gameforge.main_quest_flame_lv101._030_say = "Der Alchemist hat mich bereits \252ber meinen gro\223en[ENTER]Fehler in Kenntnis gesetzt. Hoffentlich ist es[ENTER]noch nicht zu sp\228t, ihn zu korrigieren. "
gameforge.main_quest_flame_lv101._040_say = "Hier ist die Nimbustinktur des Alchemisten. Trage[ENTER]sie auf deine Waffe auf. Wenn du nun infizierte[ENTER]D\228monen t\246test, wird die Schwarze Materie gebannt[ENTER]und kann sich nicht weiter ausbreiten. "
gameforge.main_quest_flame_lv101._050_say = "Unter diesen Voraussetzungen kannst du dich auch[ENTER]in das Innere der geheimnisvollen Festung wagen[ENTER]und die D\228monen direkt in ihrer Heimst\228tte[ENTER]bek\228mpfen. Bestimmt entdeckst du darin Hinweise[ENTER]auf die Machenschaften der Diener der Dunkelheit[ENTER]und auf den Verbleib meines vermissten Sp\228hers. "
gameforge.main_quest_flame_lv101._060_say = {}
gameforge.main_quest_flame_lv101._070_say = "Ich mache mich sogleich auf den Weg. "
gameforge.main_quest_flame_lv101._080_say = "Danke. Ich w\252nsche dir das Beste. "
gameforge.main_quest_flame_lv101._090_notice = "Dringe in die Festung ein und besiege die D\228monen.[ENTER]Halte die Augen offen nach Hinweisen und dem[ENTER]vermissten Sp\228her! "
gameforge.main_quest_flame_lv101._100_sayTitle = "Festung erkunden "
gameforge.main_quest_flame_lv101._110_say = "Dringe in die unbekannte Festung ein und besiege[ENTER]die D\228monen. Halte die Augen offen nach Hinweisen[ENTER]auf die Machenschaften der Diener als auch auf den[ENTER]vermissten Sp\228her! "
gameforge.main_quest_flame_lv101._120_sayReward = "Du kannst diesen Dungeon nicht alleine betreten.[ENTER]Bilde eine Gruppe, um passieren zu d\252rfen.[ENTER]Du erh\228ltst keinen weiteren Passierschein. "
gameforge.main_quest_flame_lv101._130_say = "Warst du schon im Inneren der Festung? Es m\252ssen[ENTER]Hinweise auf die Machenschaften der Diener der[ENTER]Dunkelheit als auch auf den Verbleib meines[ENTER]Sp\228hers darin zu finden sein! Reise erneut ins[ENTER]Feuerland und durchsuche die Festung. "
gameforge.main_quest_flame_lv101._140_say = "Der Sp\228her ist schon eine Weile tot. In seiner[ENTER]Tasche findest du einen Brief. \220berbringe ihn[ENTER]Yak-Hwan. "
gameforge.main_quest_flame_lv101._150_notice = "Du hast Yak-Hwans Sp\228her entdeckt. "
gameforge.main_quest_flame_lv101._160_say = "Hast du Neuigkeiten? "
gameforge.main_quest_flame_lv101._170_say = {}
gameforge.main_quest_flame_lv101._180_say = "Deinem Gesichtsausdruck zu urteilen, keine guten[ENTER]... Das hatte ich bereits bef\252rchtet. Einen Brief[ENTER]trug er bei sich? Zeig her. In dieser Festung muss[ENTER]noch ein Hinweis auf die Machenschaften der Diener[ENTER]der Dunkelheit zu finden sein. Kehre zur\252ck und[ENTER]suche danach. Den Brief lesen wir sp\228ter. "
gameforge.main_quest_flame_lv101._190_notice = "Du hast ein Nietenhalsband der Diener der[ENTER]Dunkelheit entdeckt. Zeige es Yak-Hwan. "
gameforge.main_quest_flame_lv101._200_say = "Interessant, das Nietenhalsband geh\246rt den Dienern[ENTER]der Dunkelheit. Vielleicht enth\228lt es einen[ENTER]Hinweis auf ihre Machenschaften! Aber noch keine[ENTER]Spur von meinem Sp\228her? Bitte suche weiter nach[ENTER]ihm. Er muss in dieser Festung sein. "
gameforge.main_quest_flame_lv101._210_notice = "Du hast sowohl ein Nietenhalsband als auch den[ENTER]Sp\228her entdeckt. Erstatte nun Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv101._220_say = "Erstatte Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv101._230_say = "Du warst also erfolgreich! Dieses Nietenhalsband[ENTER]geh\246rt den Dienern der Dunkelheit. Es enth\228lt[ENTER]bestimmt einen versteckten Hinweis auf ihre[ENTER]Machenschaften. Und was hast du da in deiner[ENTER]anderen Hand? "
gameforge.main_quest_flame_lv101._240_say = {}
gameforge.main_quest_flame_lv101._250_say = "Ein Brief ... den mir mein Sp\228her hinterlassen[ENTER]hat? Ich bin ersch\252ttert. Lass uns gemeinsam seine[ENTER]letzten Worte lesen. "
gameforge.main_quest_flame_lv101._260_sayTitle = "Hastig geschriebene Worte: "
gameforge.main_quest_flame_lv101._270_say = "Yak-Hwan, ich hoffe, dieser Brief erreicht dich,[ENTER]da ich nicht lebend heimkehren werde. Ich habe im[ENTER]Feuerland eine Festung entdeckt, die auf keiner[ENTER]Karte verzeichnet ist. Ihr Herrscher ist ein[ENTER]m\228chtiger Feuerland-D\228mon \150 eine eigenartige Aura[ENTER]umgibt ihn, so wie alle D\228monen seines Gefolges.[ENTER]Sein Gebr\252ll ist ohrenbet\228ubend und er scheint[ENTER]etwas zu bewachen. Entsende jemanden, um diesen[ENTER]Ort zu erkunden! Denn ich habe versagt ... "
gameforge.main_quest_flame_lv101._280_say = "Irgendetwas verbirgt sich in dieser Festung und[ENTER]wir m\252ssen herausfinden, was.[ENTER]Sieh her, auf der Innenseite des Nietenhalsbandes[ENTER]ist eine Gravur. Es muss mit dem Kult der Diener[ENTER]zusammenh\228ngen, dass sie immer wieder \252ber diesen[ENTER]Gegenstand kommunizieren ... Ich werde[ENTER]Yon-I-Walker um Rat fragen. Er wird dich rufen[ENTER]lassen, sobald er dich braucht. "
gameforge.main_quest_flame_lv101._290_sendLetter = "Gravur entschl\252sseln "
gameforge.main_quest_flame_lv101._300_say = "Yon-I-Walker sucht nach dir. Gehe zu ihm. "
gameforge.main_quest_flame_lv101._310_say = "Willkommen, ich habe dich bereits erwartet. Ich[ENTER]brauche etwas Hilfe dabei, die Gravur in diesem[ENTER]Nietenhalsband zu entschl\252sseln. "
gameforge.main_quest_flame_lv101._320_say = {}
gameforge.main_quest_flame_lv101._330_say = "Die Schriftzeichen auf der Innenseite des[ENTER]Nietenhalsbandes entstammen einer uralten Kultur,[ENTER]die vor langer Zeit existierte. Um sie lesbar zu[ENTER]machen, brauche ich das Blut des Flammenk\246nigs. Es[ENTER]flie\223t so hei\223 wie Lava durch seine Adern. Nimm[ENTER]dieses feuerfeste Gef\228\223, um es aufzufangen. "
gameforge.main_quest_flame_lv101._340_say = "Wird erledigt. "
gameforge.main_quest_flame_lv101._350_say = "Wenn du das Blut erhalten hast, musst du so[ENTER]schnell wie m\246glich zu mir zur\252ckkehren. Denn[ENTER]selbst dieses Gef\228\223 kann seine Hitze nur f\252r eine[ENTER]begrenzte Zeit ohne Schaden \252berstehen. "
gameforge.main_quest_flame_lv101._360_notice = "Besorge das Blut des Flammenk\246nigs. "
gameforge.main_quest_flame_lv101._370_say = "Ohne das Blut des Flammenk\246nigs k\246nnen wir die[ENTER]Gravur nicht entschl\252sseln. Erledige ihn, los! "
gameforge.main_quest_flame_lv101._380_notice = "Du hast das Blut des Flammenk\246nigs erhalten. Kehre[ENTER]rasch zu Yon-I-Walker zur\252ck. "
gameforge.main_quest_flame_lv101._390_say = "Sprich mit Yon-I-Walker. "
gameforge.main_quest_flame_lv101._400_say = "Ah, sehr gut. Das Gef\228\223 ist noch nicht unter der[ENTER]Hitze geschmolzen. Mithilfe des Blutes werde ich[ENTER]nun die Gravur wieder lesbar machen k\246nnen. Das[ENTER]erfordert etwas Zeit. Kehre morgen wieder zur\252ck. "
gameforge.main_quest_flame_lv101._410_say = "Gedulde dich noch %d Stunde(n) und %d Minute(n). "
gameforge.main_quest_flame_lv101._420_say = "Ich brauche noch etwas mehr Zeit. Komme sp\228ter wieder! "
gameforge.main_quest_flame_lv101._430_sendLetter = "Die Gravur "
gameforge.main_quest_flame_lv101._440_say = "Du kommst zur rechten Zeit! Ich habe die Gravur[ENTER]auf dem Nietenhalsband entschl\252sselt. "
gameforge.main_quest_flame_lv101._450_say = "Sie verr\228t uns, dass die Diener der Dunkelheit[ENTER]einen der m\228chtigesten Feuerd\228monen entsandt[ENTER]haben, um die Siegel der Tore zu schmelzen, hinter[ENTER]denen die Sechs Drachen an einem verborgenen Ort[ENTER]gefangen gehalten werden. Es wird auch ein[ENTER]spezieller Schmelzofen erw\228hnt. Ich habe alles in[ENTER]diesem Schreiben an Yak-Hwan festgehalten. Bringe[ENTER]es bitte zu ihm! "
gameforge.main_quest_flame_lv101._460_say = {}
gameforge.main_quest_flame_lv101._470_notice = "\220berbringe Yak-Hwan den Brief von Yon-I-Walker. "
gameforge.main_quest_flame_lv101._480_sayTitle = "Post f\252r Yak-Hwan "
gameforge.main_quest_flame_lv101._490_say = "\220berbringe Yak-Hwan den Brief von Yon-I-Walker. "
gameforge.main_quest_flame_lv101._500_say = "Konnte Yon-I-Walker die Gravur lesen? Oh, ein[ENTER]Brief mit allen Informationen von ihm? Sehr gut,[ENTER]zeig her! "
gameforge.main_quest_flame_lv101._510_say = "Die Siegel der Sechs Drachen ... soso ... ein[ENTER]magischer Schmelzofen ... aha ... Bei der Festung,[ENTER]die wir entdeckt haben, muss es sich um die[ENTER]sagenumwobene Rotdrachenfestung handeln! Dort soll[ENTER]einer der Drachen gefangen sein, die die Diener[ENTER]zur Gewinnung der Perlen der Nacht t\246ten m\252ssen.[ENTER]Ich werde mich nun zur\252ckziehen und mit meinen[ENTER]Strategen \252ber unser weiteres Vorgehen beraten. "
gameforge.main_quest_flame_lv101._520_say = "T\246te den Flammenk\246nig und fange sein brennendes[ENTER]Blut auf. "
gameforge.main_quest_flame_lv101._530_say = {}
gameforge.main_quest_flame_lv102 = {}
gameforge.main_quest_flame_lv102._010_sendLetter = "Sturm der Festung "
gameforge.main_quest_flame_lv102._020_say = "Yak-Hwan sucht nach dir. Er m\246chte dich in die[ENTER]weitere Planung einweihen. "
gameforge.main_quest_flame_lv102._030_say = "Wir haben die Rotdrachenfestung nun[ENTER]verbarrikadiert. Auf diese Weise gelangen keine[ENTER]infizierten D\228monen mehr hinaus und wir[ENTER]verhindern, dass sich die Schwarze Materie weiter[ENTER]verbreitet. "
gameforge.main_quest_flame_lv102._040_say = "Deine Aufgabe wird es nun sein, in die Festung[ENTER]einzufallen, so viele D\228monen wie m\246glich[ENTER]unsch\228dlich zu machen und herauszufinden, ob darin[ENTER]tats\228chlich der legend\228re Rotdrache gefangen ist. "
gameforge.main_quest_flame_lv102._050_say = "Einverstanden. "
gameforge.main_quest_flame_lv102._060_say = "Erledige 30 D\228monen und bringe mir als Beweis[ENTER]daf\252r ihre D\228monenkrallen. "
gameforge.main_quest_flame_lv102._070_notice = "Erledige 30 D\228monen und bringe Yak-Hwan als Beweis[ENTER]ihre D\228monenkrallen. "
gameforge.main_quest_flame_lv102._080_sayTitle = "St\252rme die Rotdrachenfestung! "
gameforge.main_quest_flame_lv102._090_say = "Besiege 30 D\228monen in der Rotdrachenfestung und[ENTER]bringe Yak-Hwan ihre D\228monenkrallen als Beweis. "
gameforge.main_quest_flame_lv102._100_say = "D\228monenkralle des %s: %d St\252ck[ENTER]D\228monenkralle des %s: %d St\252ck "
gameforge.main_quest_flame_lv102._110_say = "R\252stungsfragment des %s: %d St\252ck, Waffenfragment[ENTER]des %s: %d St\252ck "
gameforge.main_quest_flame_lv102._120_say = "Du hast noch nicht gen\252gend D\228monen besiegt.[ENTER]Erledige insgesamt 30 St\252ck und bringe mir ihre[ENTER]D\228monenkrallen als Beweis! "
gameforge.main_quest_flame_lv102._130_notice = "Du hast alle D\228monen besiegt. Bringe Yak-Hwan die[ENTER]D\228monenkrallen. "
gameforge.main_quest_flame_lv102._140_say = "Kehre zu Yon-I-Walker zur\252ck. "
gameforge.main_quest_flame_lv102._150_say = "Du bist zur\252ck \150 und wie ich sehe hattest du[ENTER]Erfolg! Was kannst du mir berichten? "
gameforge.main_quest_flame_lv102._160_say = {}
gameforge.main_quest_flame_lv102._170_say = "Ein m\228chtiger Flammend\228mon, sagst du? Das muss[ENTER]Razador, Herrscher des Feuers, sein! Du hast Gl\252ck[ENTER]\150 nicht viele, die ihm begegneten, konnten lebend[ENTER]davon berichten. Wenn die Diener ihn geschickt[ENTER]haben, muss sich in der Tat etwas von Bedeutung in[ENTER]der Festung befinden. Wom\246glich der legend\228re[ENTER]Rotdrache! Ich werde mich mit meinen Beratern[ENTER]besprechen und dich dann rufen lassen. Danke vorerst! "
gameforge.main_quest_flame_lv102._180_sendLetter = "Razador "
gameforge.main_quest_flame_lv102._190_say = "Yon-I-Walker sucht nach dir. Gehe zu ihm, um[ENTER]Genaueres zu erfahren. "
gameforge.main_quest_flame_lv102._200_say = "Du hast also eine Begegnung mit dem ungeheuren[ENTER]Razador \252berlebt. Ich verneige mich in Respekt. "
gameforge.main_quest_flame_lv102._210_say = {}
gameforge.main_quest_flame_lv102._220_say = "Der Herrscher des Feuers geh\246rt neben dem[ENTER]Frostk\246nig zu den b\246sartigsten und t\246dlichsten[ENTER]Unterweltgesch\246pfen, die die Menschheit kennt.[ENTER]Doch alles, was wir \252ber Razador wissen, stammt[ENTER]aus uralten Schriften und \252berlieferten[ENTER]Gruselgeschichten. Es ist m\246glich, dass Razador[ENTER]die Quelle der Schwarzen Materie ist. "
gameforge.main_quest_flame_lv102._230_say = {}
gameforge.main_quest_flame_lv102._240_say = {}
gameforge.main_quest_flame_lv102._250_say = "Wenn dem so ist, macht ihn das zu einem[ENTER]\252berm\228chtigen Gegner. Vernichte zun\228chst die[ENTER]rangniederen D\228monen in der Rotdrachenfestung. Die[ENTER]Schwarze Materie im K\246rper ist kugelf\246rmig. Sammle[ENTER]zehn dieser Materiekugeln. Vielleicht finden wir[ENTER]so einen Weg, die Macht der Schwarzen Materie zu[ENTER]neutralisieren, bevor wir Razador entgegentregen. "
gameforge.main_quest_flame_lv102._260_say = "Ich mache mich sofort auf den Weg. "
gameforge.main_quest_flame_lv102._270_notice = "Bek\228mpfe die Flammend\228monen in der Rotdrachenfestung. "
gameforge.main_quest_flame_lv102._280_sayTitle = "Materie-Kugeln "
gameforge.main_quest_flame_lv102._290_say = "St\252rme die Rotdrachenfestung, bek\228mpfe die[ENTER]Flammend\228monen und sammle zehn Materiekugeln. "
gameforge.main_quest_flame_lv102._300_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein! "
gameforge.main_quest_flame_lv102._310_say = "Das sind noch nicht genug Materiekugeln. Ich[ENTER]brauche zehn St\252ck f\252r meine Forschung. Sammle[ENTER]bitte weiter. "
gameforge.main_quest_flame_lv102._320_notice = "Du hast zehn Materiekugeln gesammelt. Bringe sie[ENTER]zu Yon-I-Walker. "
gameforge.main_quest_flame_lv102._330_say = "Alleine der Anblick der Schwarzen Materie l\228sst[ENTER]mich erschaudern! Also gut, an die Arbeit ... Ich[ENTER]lasse dich rufen, wenn ich erfolgreich war. "
gameforge.main_quest_flame_lv102._340_say = {}
gameforge.main_quest_flame_lv102._350_sendLetter = "Neutralisierung der Schwarzen Materie "
gameforge.main_quest_flame_lv102._360_say = "Gute Neuigkeiten! Ich habe herausgefunden, wie[ENTER]sich die Kraft der Schwarzen Materie[ENTER]neutralisieren l\228sst. "
gameforge.main_quest_flame_lv102._370_say = {}
gameforge.main_quest_flame_lv102._380_say = "Alle Kr\228fte der Natur besitzen ein Gegengewicht \150[ENTER]Licht und Schatten, Feuer und Wasser, Gut und[ENTER]B\246se. Auch die Schwarze Materie hat einen[ENTER]Gegenspieler, der die Macht hat, sie zu[ENTER]neutralisieren: Reines Lumen! "
gameforge.main_quest_flame_lv102._390_say = "Um Reines Lumen zu produzieren, muss man[ENTER]Energiesplitter in Mong-Wasser schmelzen. Kannst[ENTER]du bitte 50 Flaschen Mong-Wasser sowie 100[ENTER]Energiesplitter holen und sie zu Yu-Hwan bringen?[ENTER]Danke. "
gameforge.main_quest_flame_lv102._400_say = "Wird gemacht. "
gameforge.main_quest_flame_lv102._410_notice = "Sammle 50 Flaschen Mong-Wasser sowie 100[ENTER]Energiesplitter und bringe sie zu Yu-Hwan. "
gameforge.main_quest_flame_lv102._420_sayTitle = "Reines Lumen "
gameforge.main_quest_flame_lv102._430_say = "Sammle 50 Flaschen Mong-Wasser sowie 100[ENTER]Energiesplitter und bringe sie zu Yu-Hwan. "
gameforge.main_quest_flame_lv102._440_say = "Oha, Yon-I-Walker hat mich schon vorgewarnt, dass[ENTER]du kommen w\252rdest \150 aber du warst schneller, als[ENTER]ich es erwartet h\228tte! Sehr gut, desto fr\252her kann[ENTER]ich mit meiner Arbeit beginnen. Wieso ruhst du[ENTER]dich in der Zeit nicht etwas aus? "
gameforge.main_quest_flame_lv102._450_say = "Oha, Yon-I-Walker hat mich schon vorgewarnt, dass[ENTER]du kommen w\252rdest \150 aber er sprach von mehr[ENTER]Material. Das ist noch nicht genug. Geh und sammle[ENTER]noch weiter. "
gameforge.main_quest_flame_lv102._460_notice = "Du hast gen\252gend Mong-Wasser und Energiesplitter[ENTER]gesammelt. Bringe sie zu Yu-Hwan. "
gameforge.main_quest_flame_lv102._470_say = "Gehe zu Yu-Hwan. "
gameforge.main_quest_flame_lv102._480_sendLetter = "Reines Lumen \252berbringen "
gameforge.main_quest_flame_lv102._490_say = "Yu-Hwan hat das Reine Lumen hergestellt. Gehe zu ihm. "
gameforge.main_quest_flame_lv102._500_say = "Da bist du ja! Gerade zur rechten Zeit. Das Reine[ENTER]Lumen ist soeben fertig geworden. Hier, bitte[ENTER]sehr. Bringe es nun zu Yak-Hwan. "
gameforge.main_quest_flame_lv102._510_say = {}
gameforge.main_quest_flame_lv102._520_say = {}
gameforge.main_quest_flame_lv102._530_say = {}
gameforge.main_quest_flame_lv102._540_notice = "Kehre mit dem Reinen Lumen zu Yak-Hwan zur\252ck. "
gameforge.main_quest_flame_lv102._550_say = "Du bist noch hier? Es eilt sehr! Bringe das Reine[ENTER]Lumen zu Yak-Hwan. "
gameforge.main_quest_flame_lv102._560_say = "Ah, willkommen! Du hast das Reine Lumen bei dir?[ENTER]Phantastisch! "
gameforge.main_quest_flame_lv102._570_say = {}
gameforge.main_quest_flame_lv102._580_say = "Beeindruckend. Ja, damit haben wir im Kampf um die[ENTER]Rotdrachenfestung ein Ass im \196rmel. Hier, nimm du[ENTER]ein Reines Lumen und ich bewahre den Rest sicher[ENTER]auf. Ruhe dich nun etwas aus, w\228hrend ich die[ENTER]Truppen zusammenrufe. "
gameforge.main_quest_flame_lv103 = {}
gameforge.main_quest_flame_lv103._010_sendLetter = "Sturm der Rotdrachenfestung "
gameforge.main_quest_flame_lv103._020_say = "Yak-Hwan l\228sst dich rufen. Er hat letzte[ENTER]Anweisungen, ehe du in den Kampf ziehst. "
gameforge.main_quest_flame_lv103._030_say = "Es ist soweit. Der Kampf hat begonnen. Ich habe[ENTER]einen Trupp meiner besten M\228nner zur[ENTER]Rotdrachenfestung entsandt. Sie alle sind mit[ENTER]Reinem Lumen ausger\252stet und der Effekt ist[ENTER]ungeheuerlich! Eine eine starke, wei\223e Aura umgab[ENTER]sie und ihr Verstand wurde messerscharf. "
gameforge.main_quest_flame_lv103._040_say = "Folge ihnen und treffe sie in der[ENTER]Rotdrachenfestung! Suche nach dem Kommandanten. Er[ENTER]wird dich in den Angriffsplan einweihen. "
gameforge.main_quest_flame_lv103._060_say = "Ich z\228hle auf dich. "
gameforge.main_quest_flame_lv103._070_notice = "Folge dem Angriffstrupp in die Rotdrachenfestung[ENTER]und suche nach dem Kommandanten. "
gameforge.main_quest_flame_lv103._080_sayTitle = "Auf zur Festung! "
gameforge.main_quest_flame_lv103._090_say = "Folge dem Angriffstrupp in die Rotdrachenfestung[ENTER]und suche nach dem Kommandanten. "
gameforge.main_quest_flame_lv103._100_say = "Du bist noch hier? Los, folge meinen M\228nnern zur[ENTER]Rotdrachenfestung! "
gameforge.main_quest_flame_lv103._110_say = "Gut, dass du hier bist. Wir wurden entdeckt und[ENTER]mussten die Festung fr\252her als geplant st\252rmen.[ENTER]Zuerst lief es gut, doch dann ... gegen Razador[ENTER]waren wir chancenlos \150 das ganze Bataillon ist[ENTER]gefallen. Ich bin der letzte. Kannst du Yak-Hwan[ENTER]Bericht erstatten? Danke. "
gameforge.main_quest_flame_lv103._120_say = "Berichte Yak-Hwan von den Ereignissen in der[ENTER]Rotdrachenfestung. "
gameforge.main_quest_flame_lv103._130_say = "Du bist schon zur\252ck? Was ... etwas ist[ENTER]schiefgegangen? Sprich! "
gameforge.main_quest_flame_lv103._140_say = {}
gameforge.main_quest_flame_lv103._150_say = "Das ganze Bataillon ist gefallen? Oh, nein ... Das[ENTER]ist meine Schuld. Der Sturm war \252berhastet und[ENTER]meine M\228nner haben das mit ihrem Leben bezahlt. "
gameforge.main_quest_flame_lv103._160_say = {}
gameforge.main_quest_flame_lv103._170_say = "Ich muss meine Strategie noch einmal \252berdenken.[ENTER]Es muss einen anderen Weg geben, diesen D\228mon zu[ENTER]vernichten. Mach dich bereit. Ich lasse dich[ENTER]rufen, sobald der Plan steht. "
gameforge.main_quest_flame_lv103._180_sendLetter = "Schritt f\252r Schritt "
gameforge.main_quest_flame_lv103._190_say = "Gut, dass du gekommen bist. Wir haben uns dazu[ENTER]entschlossen, erst die Reihen der D\228monen[ENTER]auszud\252nnen, ehe wir Razador erneut angreifen. Und[ENTER]du wirst dabei eine Schl\252sselrolle \252bernehmen. "
gameforge.main_quest_flame_lv103._200_say = "W\228hrend meine M\228nner vor den Toren der[ENTER]Rotdrachenfestung Wache halten und alle Gegner[ENTER]erledigen, die ins Freie st\252rmen, wirst du hinein[ENTER]gehen und die Flammend\228monen im Inneren bek\228mpfen.[ENTER]Das Reine Lumen wird dich vor dem Einfluss der[ENTER]Schwarzen Materie sch\252tzen und ihre Kraft[ENTER]neutralisieren. "
gameforge.main_quest_flame_lv103._210_say = "Wenn du es schaffst, 1000 Flammend\228monen zu[ENTER]besiegen, wird die Verteidigungslinien um Razador[ENTER]empfindlich schw\228chen. "
gameforge.main_quest_flame_lv103._220_say = "An die Waffen! "
gameforge.main_quest_flame_lv103._230_notice = "St\252rme die Rotdrachenfestung und besiege 1000[ENTER]Flammend\228monen. "
gameforge.main_quest_flame_lv103._240_sayTitle = "Schritt 1: 1000 D\228monen "
gameforge.main_quest_flame_lv103._250_say = "St\252rme die Rotdrachenfestung und besiege 1000[ENTER]Flammend\228monen. "
gameforge.main_quest_flame_lv103._260_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein! "
gameforge.main_quest_flame_lv103._270_say = "Die feindlichen Verteidigungslinien sind noch zu[ENTER]stark. Besiege noch mehr D\228monen, um sie zu[ENTER]schw\228chen. Wir z\228hlen auf dich! "
gameforge.main_quest_flame_lv103._280_notice = "Du hast 1000 Flammend\228monen besiegt. Erstatte[ENTER]Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv103._290_say = "Gute Arbeit! Die Verteidigungslinien der[ENTER]Flammend\228monen wurde durch dich empfindlich[ENTER]geschw\228cht. Warte einen Moment, w\228hrend ich mich[ENTER]mit meinen Strategen \252ber das weitere Vorgehen berate. "
gameforge.main_quest_flame_lv103._300_sendLetter = "Schritt 2 "
gameforge.main_quest_flame_lv103._310_say = "Es ist Zeit f\252r den n\228chsten Schritt. Nun sollten[ENTER]wir die hochrangigen D\228monenkrieger angreifen.[ENTER]Dringe erneut in die Rotdrachenfestung ein und[ENTER]besiege jeweils 50 Glut-Flammenk\246nige,[ENTER]Glut-Flammenb\228rte, Glut-Flammengolem,[ENTER]Glut-Flammengener\228le und Glut-Flammenf\252rste. "
gameforge.main_quest_flame_lv103._320_say = {}
gameforge.main_quest_flame_lv103._330_notice = "Dringe erneut in die Rotdrachenfestung ein und[ENTER]besiege jeweils 50 Glut-Flammenk\246nige,[ENTER]Glut-Flammenb\228rte, Glut-Flammengolem,[ENTER]Glut-Flammengener\228le und Glut-Flammenf\252rste. "
gameforge.main_quest_flame_lv103._340_sayTitle = "Schritt 2 "
gameforge.main_quest_flame_lv103._350_say = "Dringe erneut in die Rotdrachenfestung ein und[ENTER]besiege jeweils 50 Glut-Flammenk\246nige,[ENTER]Glut-Flammenb\228rte, Glut-Flammengolem,[ENTER]Glut-Flammengener\228le und Glut-Flammenf\252rste. "
gameforge.main_quest_flame_lv103._360_say = "Die gegnerischen Truppen sind noch immer zu stark.[ENTER]Du hast noch nicht genug hochrangige[ENTER]Glut-Flammend\228monen erledigt. Kehre in die Festung[ENTER]zur\252ck und k\228mpfe weiter! "
gameforge.main_quest_flame_lv103._370_notice = "Du hast die hochrangigen Glut-Flammend\228monen[ENTER]besiegt. Erstatte Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv103._380_say = "Phantastisch! Die Reihen der Glut-Flammend\228monen[ENTER]sind geschw\228cht und meine M\228nner k\246nnen nun die[ENTER]Rotdrachenfestung st\252rmen. Gute Arbeit! Sobald ich[ENTER]Neuigkeiten habe, gebe ich dir Bescheid. "
gameforge.main_quest_flame_lv103._390_sendLetter = "Razador "
gameforge.main_quest_flame_lv103._400_say = "Meine M\228nner sind nun in der Rotdrachenfestung und[ENTER]dank deiner Vorarbeit halten sich die Verluste auf[ENTER]unserer Seite in Grenzen. Yon-I-Walker wird dir[ENTER]unsere weitere Strategie erl\228utern. Gehe zu ihm. "
gameforge.main_quest_flame_lv103._410_notice = "Gehe zu Yon-I-Walker und h\246re dir seine Strategie an. "
gameforge.main_quest_flame_lv103._420_say = "Gehe zu Yon-I-Walker und h\246re dir seine Strategie an. "
gameforge.main_quest_flame_lv103._430_say = "Ich habe dich bereits erwartet. Wir stehen kurz[ENTER]davor, die Pl\228ne der Diener der Dunkelheit ein[ENTER]weiteres Mal zu durchkreuzen. Lass mich dir[ENTER]erl\228utern, wie unser weiteres Vorgehen ist. "
gameforge.main_quest_flame_lv103._440_say = "Durch unsere Spione haben wir erfahren, dass[ENTER]Razador einen gro\223en Teil seiner Kraft aus dem[ENTER]Metin des Fegefeuers sch\246pft. Er hat diesen Stein[ENTER]in die Rotdrachenfestung bringen lassen, wo er[ENTER]schwer bewacht wird. Zerst\246re diesen Metin! Das[ENTER]wird den Kampf gegen Razador erheblich vereinfachen. "
gameforge.main_quest_flame_lv103._450_say = {}
gameforge.main_quest_flame_lv103._460_say = "Wir wissen nicht, wo genau sich der Metin des[ENTER]Fegefeuers befindet. Doch er muss irgendwo in[ENTER]dieser Festung sein! Wenn du dein Ziel erreicht[ENTER]hast, erstatte Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv103._470_say = {}
gameforge.main_quest_flame_lv103._480_notice = "Zerst\246re den Metin des Fegefeuers in der[ENTER]Rotdrachefestung. "
gameforge.main_quest_flame_lv103._490_sayTitle = "Flammen des Fegefeuers "
gameforge.main_quest_flame_lv103._500_say = "Begib dich auf die Suche nach dem Metin des[ENTER]Fegefeuers in der Rotdrachenfestung und zerst\246re ihn. "
gameforge.main_quest_flame_lv103._510_say = "Verbleibend "
gameforge.main_quest_flame_lv103._520_say = "Wir m\252ssen den Metin des Fegefeuers zerst\246ren,[ENTER]oder der Kampf gegen Razador ist aussichtslos.[ENTER]Los, du schaffst es! "
gameforge.main_quest_flame_lv103._530_notice = "Du hast den Metin des Fegefeuers zerst\246rt.[ENTER]Erstatte Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv103._540_say = "Gute Arbeit. Nun k\246nnen wir der Schlange den Kopf[ENTER]abschlagen. Diesmal werden wir Razador vernichten![ENTER]Nimm schon mal das Reine Lumen an dich. Ich werde[ENTER]ein paar letzte Vorbereitungen treffen. Ruhe dich[ENTER]so lange aus. "
gameforge.main_quest_flame_lv104 = {}
gameforge.main_quest_flame_lv104._010_sendLetter = "Kampf gegen Razador "
gameforge.main_quest_flame_lv104._020_say = "Gehe zu Yak-Hwan und h\246re dir seinen Schlachtplan an. "
gameforge.main_quest_flame_lv104._030_say = "Der Tag des Triumphes ist zum Greifen nahe![ENTER]Diesmal sind wir vorbereitet und werden Razador[ENTER]besiegen. "
gameforge.main_quest_flame_lv104._040_say = "Hast du noch das Reine Lumen? Beachte, dass seine[ENTER]Wirkung nur eine Stunde anh\228lt. Also nimm es erst[ENTER]zum rechten Zeitpunkt. An die Waffen! "
gameforge.main_quest_flame_lv104._050_say = "Verstanden. "
gameforge.main_quest_flame_lv104._060_notice = "St\252rme die Rotdrachenfestung und vernichte Razador. "
gameforge.main_quest_flame_lv104._070_sayTitle = "Kampf gegen Razador "
gameforge.main_quest_flame_lv104._080_say = "St\252rme die Rotdrachenfestung und vernichte[ENTER]Razador, Herrscher des Feuers. "
gameforge.main_quest_flame_lv104._090_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein! "
gameforge.main_quest_flame_lv104._100_say = "Es wird nicht leicht, es mit Razador aufzunehmen.[ENTER]Doch uns bleibt keine andere Wahl, wenn wir die[ENTER]Pl\228ne der Diener der Dunkelheit aufhalten wollen.[ENTER]Sch\246pfe neue Kraft und stelle dich dem Herrscher[ENTER]des Feuers entgegen, ehe es zu sp\228t ist! "
gameforge.main_quest_flame_lv104._110_say = "Sterblicher, h\246re meine Worte! Genie\223e deinen[ENTER]kurzen Augenblick des Triumphs. Er wird nicht[ENTER]lange dauern. Denn ich werde zur\252ckkehren in eure[ENTER]erb\228rmliche Welt. Der Rotdrache will aus seinem[ENTER]Gef\228ngnis heraus und wird nicht zulassen, dass ich[ENTER]unverrichteter Dinge gehe, har, har, har! "
gameforge.main_quest_flame_lv104._120_notice = "Razador, Herrscher des Feuers, wurde besiegt.[ENTER]Erstatte Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv104._130_say = "Kehre zu Yak-Hwan zur\252ck. "
gameforge.main_quest_flame_lv104._140_say = "Welch Triumph! Niemals zurvor ist es jemandem[ENTER]gelungen, den Herrscher des Feuers zu bezwingen.[ENTER]Das ist ein wahrhaft gro\223er Tag. "
gameforge.main_quest_flame_lv104._150_say = {}
gameforge.main_quest_flame_lv104._160_say = "Was sagst du da? Der Rotdrachen wird Razador[ENTER]wieder auferstehen lassen? Wie ist das m\246glich?[ENTER]Wir wissen wenig \252ber die Elementdrachen ... doch[ENTER]ihre Macht scheint gro\223 zu sein. "
gameforge.main_quest_flame_lv104._170_sendLetter = "Pl\228ne vereiteln I "
gameforge.main_quest_flame_lv104._180_say = "Schlechte Nachrichten! Die Macht des Rotdrachens[ENTER]hat Razador auferstehen lassen. Seine Kr\228fte sind[ENTER]dadurch noch gewachsen und auch der Einfluss der[ENTER]Schwarzen Materie scheint gr\246\223er als zuvor zu sein. "
gameforge.main_quest_flame_lv104._190_say = "Sprich mit Yon-I-Walker. Er wei\223, wie man Razador[ENTER]endg\252ltig besiegen kann. "
gameforge.main_quest_flame_lv104._200_notice = "Gehe zu Yon-I-Walker und erfahre, wie Razador[ENTER]endg\252ltig besiegt werden kann. "
gameforge.main_quest_flame_lv104._210_sayTitle = "Sprich mit Yon-I-Walker. "
gameforge.main_quest_flame_lv104._220_say = "Gehe zu Yon-I-Walker und erfahre, wie Razador[ENTER]endg\252ltig besiegt werden kann. "
gameforge.main_quest_flame_lv104._230_say = "Du warst noch nicht bei Yon-I-Walker? Wie willst[ENTER]du dann Razador besiegen? Los, worauf wartest du noch! "
gameforge.main_quest_flame_lv104._240_say = "Ja, es ist wahr. Razador ist zur\252ck. Und noch[ENTER]schlechter gelaunt als vorher. Um zu verhindern,[ENTER]dass die Diener der Dunkelheit ihren Plan[ENTER]ausf\252hren k\246nnen, bleibt uns nur eine M\246glichkeit:[ENTER]Der Rotdrache muss verbannt werden. "
gameforge.main_quest_flame_lv104._250_say = "Razador wird nicht ruhen, ehe er seinen Auftrag[ENTER]ausgef\252hrt und den Rotdrachen befreit hat. Um dies[ENTER]zu verhindern, werden wir den Drachen in die[ENTER]Verbannung schicken. "
gameforge.main_quest_flame_lv104._260_say = {}
gameforge.main_quest_flame_lv104._270_say = "Das Element des Rotdrachen ist das Feuer ... und[ENTER]Feuer bek\228mpft man am Besten mit \150 Feuer! Jeder[ENTER]Flammend\228mon tr\228gt einen Magmakern in sich.[ENTER]Beschaffe mir jeweils f\252nf Kerne der folgenden[ENTER]Monster: Glut-Flammenk\246nig, Glut-Flammenbart,[ENTER]Glut-Flammengolem, Glut-Flammengeneral und[ENTER]Glut-Flammenf\252rst "
gameforge.main_quest_flame_lv104._280_notice = "Beschaffe die Magmakerne der Flammend\228monen. "
gameforge.main_quest_flame_lv104._290_say = "Beschaffe jeweils f\252nf Magmakerne dieser Gegner:[ENTER]Glut-Flammenk\246nig[ENTER]Glut-Flammenbart[ENTER]Glut-Flammengolem[ENTER]Glut-Flammengeneral[ENTER]Glut-Flammenf\252rst[ENTER]Kehre damit zu Yon-I-Walker zur\252ck. "
gameforge.main_quest_flame_lv104._300_say = "Oh ja, du hast schon einige gefunden. Bringe noch[ENTER]%d, das sollte dann reichen. "
gameforge.main_quest_flame_lv104._310_say = "Gut, das sind jetzt alle Magmakerne. Ich werde sie[ENTER]etwas abk\252hlen, damit ich sie verarbeiten kann.[ENTER]Wenn ich deine Hilfe wieder brauche, lasse ich[ENTER]dich rufen. "
gameforge.main_quest_flame_lv104._320_say = "Hm, diese Magmakerne sind schon zu weit[ENTER]runtergek\252hlt. Ich kann sie nicht mehr verwenden.[ENTER]Bringe mir noch weitere. "
gameforge.main_quest_flame_lv104._330_sendLetter = "Pl\228ne vereiteln II "
gameforge.main_quest_flame_lv104._340_say = "Yon-I-Walker sucht nach dir. Gehe zu ihm. "
gameforge.main_quest_flame_lv104._350_say = "Ich werde noch etwas Zeit ben\246tigen, bis ich die[ENTER]Magmakerne soweit runtergek\252hlt habe, dass sie[ENTER]sich verarbeiten lassen. Kannst du mir in der[ENTER]Zwischenzeit Dok-Wasser besorgen? Darin lassen[ENTER]sich die Kerne zersetzen und ich kann eine[ENTER]Suspension herstellen. "
gameforge.main_quest_flame_lv104._360_say = "Mit dieser Magmasuspension werden wir den[ENTER]Rotdrachen verbannen k\246nnen. Yak-Hwan wird dich[ENTER]dann sp\228ter \252ber das genaue Prozedere aufkl\228ren.[ENTER]Bitte beschaffe mir nun 100 Flaschen Dok-Wasser.[ENTER]Ich mache hier so lange weiter. "
gameforge.main_quest_flame_lv104._370_notice = "Beschaffe 100 Flaschen Dok-Wasser und bringe sie[ENTER]zu Yon-I-Walker. "
gameforge.main_quest_flame_lv104._380_say = "Beschaffe 100 Flaschen Dok-Wasser und bringe sie[ENTER]zu Yon-I-Walker. "
gameforge.main_quest_flame_lv104._390_say = "Nun habe ich alles beisammen und kann den[ENTER]Verbannungszauber herstellen. "
gameforge.main_quest_flame_lv104._400_say = "Bald? Brauchst du noch etwas? "
gameforge.main_quest_flame_lv104._410_say = "Eine letzte Zutat fehlt mir noch. Allerdings muss[ENTER]ich mich jetzt auf den Schmelzprozess[ENTER]konzentrieren. Es darf nichts schiefgehen![ENTER]Deswegen melde ich mich sp\228ter bei dir. "
gameforge.main_quest_flame_lv104._420_say = "Das sind noch keine 100 Flaschen. Bitte bringe mir[ENTER]noch den Rest des Blutgifts. "
gameforge.main_quest_flame_lv104._430_notice = "Du hast 100 Flaschen Dok-Wasser gesammelt. Kehre[ENTER]nun zu Yon-I-Walker zur\252ck. "
gameforge.main_quest_flame_lv104._440_say = "Gehe zu Yon-I-Walker. "
gameforge.main_quest_flame_lv104._450_sendLetter = "Pl\228ne vereiteln III "
gameforge.main_quest_flame_lv104._460_say = "Ich komme gut voran mir der Suspension. Doch ein[ENTER]weiteres Mal bin ich noch auf deine Hilfe angewiesen. "
gameforge.main_quest_flame_lv104._470_say = "Nun ben\246tige ich noch ein geeignetes Gef\228\223 f\252r den[ENTER]Verbannungszauber. Die Fl\252gelhaut Martyaxwars,[ENTER]H\228uptling der Mantikore, sollte uns gute Dienste[ENTER]leisten. Beschaffe f\252nf St\252cke. "
gameforge.main_quest_flame_lv104._480_notice = "Bringe Yon-I-Walker f\252nf St\252cke aus der Fl\252gelhaut[ENTER]Martyaxwars. "
gameforge.main_quest_flame_lv104._490_say = "Bringe Yon-I-Walker f\252nf St\252cke aus der Fl\252gelhaut[ENTER]Martyaxwars in guter Qualit\228t. "
gameforge.main_quest_flame_lv104._500_say = "Wir sind so dicht am Ziel \150 gib jetzt nicht auf.[ENTER]Los, bringe mir die Fl\252gelhaut! "
gameforge.main_quest_flame_lv104._510_say = "Perfekt! Die Fl\252gelhaut ist sehr widerstandsf\228hig.[ENTER]Aus ihr kann ich nun Lederbeutel f\252r den[ENTER]Verbannungszauber herstellen. Yak-Hwan wird dich[ENTER]sp\228ter noch genauer instruieren. Aber nun mache[ENTER]ich mich erstmal an die Arbeit! "
gameforge.main_quest_flame_lv104._520_notice = "Du hast alle St\252cke der Fl\252gelhaut. Bringe sie zu[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv105 = {}
gameforge.main_quest_flame_lv105._010_sendLetter = "Beginn der Schlacht "
gameforge.main_quest_flame_lv105._020_say = "Mach dich bereit \150 die Schlacht beginnt. Yak-Hwan[ENTER]wird dir letzte Anweisungen geben. "
gameforge.main_quest_flame_lv105._030_say = "Es ist soweit. Unsere Truppen stehen bereit. Der[ENTER]Kampf kann beginnen. Hast du die Bannbeutel dabei? "
gameforge.main_quest_flame_lv105._040_say = "Ja, hier sind sie. "
gameforge.main_quest_flame_lv105._050_say = "Ah, da sind sie ja. Sehr gut. Ich werde dir sp\228ter[ENTER]erkl\228ren, wie man sie verwendet. Doch zun\228chst[ENTER]m\252ssen wir die neu aufgestellte Verteidigungslinie[ENTER]der Flammend\228monen durchbrechen. Kehre zur[ENTER]Rotdrachenfestung zur\252ck und besiege jeweils 10[ENTER]Flammenk\246nige, Glut-Flammenb\228rte,[ENTER]Glut-Flammengolem, Glut-Flammengener\228le und[ENTER]Glut-Flammenf\252rste. "
gameforge.main_quest_flame_lv105._060_say = {}
gameforge.main_quest_flame_lv105._070_say = "Verstanden. "
gameforge.main_quest_flame_lv105._080_notice = "Besiege jeweils 10 Glut-Flammenk\246nige,[ENTER]Glut-Flammenb\228rte, Glut-Flammengolem,[ENTER]Glut-Flammengener\228le und Glut-Flammenf\252rste. "
gameforge.main_quest_flame_lv105._090_sayTitle = "Starte die Offensive "
gameforge.main_quest_flame_lv105._100_say = "St\252rme die Rotdrachenfestung! "
gameforge.main_quest_flame_lv105._110_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein! "
gameforge.main_quest_flame_lv105._120_say = "Wir k\246nnen die feindliche Verteidigungslinie noch[ENTER]nicht durchbrechen. Besiege alle Flammend\228monen,[ENTER]die ich dir aufgez\228hlt habe. "
gameforge.main_quest_flame_lv105._130_notice = "Du hast alle Flammend\228monen besiegt. Erstatte[ENTER]Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv105._140_say = "Kehre zu Yak-Hwan zur\252ck. "
gameforge.main_quest_flame_lv105._150_say = "Du hast gute Arbeit geleistet. Wir sind unserem[ENTER]Ziel ein ganzes St\252ck n\228her gekommen \150 der[ENTER]Rotdrache wird nicht mehr lange eine Bedrohung f\252r[ENTER]uns sein! "
gameforge.main_quest_flame_lv105._160_sendLetter = "Gunst und Groll "
gameforge.main_quest_flame_lv105._170_say = "Dein Erzfeind, Razador, scheint es dir sehr[ENTER]\252belgenommen zu haben, dass du ihn get\246tet hast.[ENTER]Sein Gebr\252ll ist auch au\223erhalb der Festung zu[ENTER]h\246ren und schallt weit \252ber die Ebenen Doyyumhwans. "
gameforge.main_quest_flame_lv105._180_say = "Es wird Zeit, ihn ein weiteres Mal in die[ENTER]Schranken zu weisen. Denn er wacht mit Argusaugen[ENTER]\252ber das Tor, hinter dem der Rotdrache gefangen[ENTER]gehalten wird. Doch nimm dich in Acht! Er wird aus[ENTER]seiner Niederlage gelernt haben und die gleichen[ENTER]Fehler nicht noch einmal begehen. "
gameforge.main_quest_flame_lv105._190_notice = "Besiege Razador, Herrscher des Feuers. "
gameforge.main_quest_flame_lv105._200_sayTitle = "Spiel mit dem Feuer "
gameforge.main_quest_flame_lv105._210_say = "Besiege Razador, Herrscher des Feuers, in der[ENTER]Rotdrachenfestung. "
gameforge.main_quest_flame_lv105._220_say = "Ist dir Razador diesmal \252berlegen? Das kann ich[ENTER]fast nicht glauben! Du hast es einmal geschafft \150[ENTER]und wirst auch diesmal obsiegen! "
gameforge.main_quest_flame_lv105._230_notice = "Razador wurde besiegt. Erstatte Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv105._240_say = "Ich wusste, du w\252rdest es schaffen! Gro\223artig. Nun[ENTER]werden wir alles f\252r die Verbannung des Rotdrachen[ENTER]vorbereiten. Ich lasse dich rufen, sobald wir[ENTER]bereit sind. "
gameforge.main_quest_flame_lv105._250_sendLetter = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._260_say = "Es ist soweit. Alles steht bereit, um den[ENTER]Rotdrachen f\252r alle Zeit zu verbannen. "
gameforge.main_quest_flame_lv105._270_say = "Meine M\228nner haben bereits bereits zwei Bannkreise[ENTER]aufgestellt. Deine Aufgabe ist es nun, sie zu[ENTER]entz\252nden. Wirf den Bannbeutel auf die Kreise und[ENTER]sie werden sich entflammen. Das wird die[ENTER]Verbannung des Rotdrachen vollziehen. "
gameforge.main_quest_flame_lv105._280_notice = "Entz\252nde die Bannkreise und schicke den Rotdrachen[ENTER]in die Verbannung. "
gameforge.main_quest_flame_lv105._290_say = "Restliche Verbannungsanzahl "
gameforge.main_quest_flame_lv105._300_sayTitle = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._310_say = "Entz\252nde mithilfe der Bannbeutel die magischen[ENTER]Kreissymbole und schicke den Rotdrachen in die[ENTER]Verbannung. "
gameforge.main_quest_flame_lv105._320_say = "Grabstein des Taramor: 1 St\252ck "
gameforge.main_quest_flame_lv105._330_sayTitle = "Rotdrachen Flammenschauspiel "
gameforge.main_quest_flame_lv105._340_say = "War das schon alles, du Wurm?! Das hat h\246chstens[ENTER]gekitzelt \150 verbannen wirst du mich damit nicht![ENTER]Ich werde Razador aus dem Reich der Toten[ENTER]zur\252ckholen. Dann wird er die Versiegelung l\246sen[ENTER]und mich endlich aus der Gefangenschaft befreien.[ENTER]Es gibt nichts, was ihr dagegen tun k\246nnt! "
gameforge.main_quest_flame_lv105._350_notice = "Die Verbannung des Rotdrachen ist fehlgeschlagen.[ENTER]Erstatte Yak-Hwan Bericht. "
gameforge.main_quest_flame_lv105._360_say = "Die Verbannung ist fehlgeschlagen? Wie konnte das[ENTER]passieren? "
gameforge.main_quest_flame_lv105._370_say = "Ja. Eigentlich wurden die Bannkreise aktiviert und[ENTER]die Entflammung hat auch stattgefunden und die[ENTER]Verbannung hatte begonnen, aber der Rotdrache war[ENTER]so m\228chtig, dass dies fehlgeschlagen ist. Er[ENTER]sagte, dass er Yamachun (6091) wiederbeleben wird[ENTER]und er die Versiegelung entfernen wird. Aber er[ENTER]hat auch gro\223en Schaden durch unseren[ENTER]Verbannungs-Versuch erlitten. "
gameforge.main_quest_flame_lv105._380_say = "Ach so. Gute Arbeit. Dank dir, konnten wir es so[ENTER]weit bringen. Ich habe bereits mit Yon-I-Walker[ENTER](20380) gesprochen und \252berlegt, was wir nun tun[ENTER]k\246nnen. Meine M\228nner werden weiterhin die Lage[ENTER]beobachten und wir werden  ach anderen Methoden[ENTER]suchen, wie wir die Verbannung vollziehen k\246nnen.[ENTER]Wenn wir eine perfekte Methoe gefunden haben, den[ENTER]Rotdrachen zu verbannen, werde ich nach dir rufen[ENTER]lassen. Gute Arbeit! "
gameforge.main_quest_flame_lv99 = {}
gameforge.main_quest_flame_lv99._010_sendLetter = "Lauf ins Feuer "
gameforge.main_quest_flame_lv99._020_say = "Yak-Hwan sucht nach dir. Gehe zu ihm und bringe in[ENTER]Erfahrung, was er m\246chte. "
gameforge.main_quest_flame_lv99._030_say = "Willkommen zur\252ck! Wie ich bef\252rchtet hatte,[ENTER]sollte uns nur eine kurze Ruhepause verg\246nnt sein[ENTER]\150 die Diener der Dunkelheit sind wieder in[ENTER]Bewegung. Das bedeutet nichts Gutes. "
gameforge.main_quest_flame_lv99._040_say = {}
gameforge.main_quest_flame_lv99._050_say = "Allerdings sind meine Informationen nur sehr vage.[ENTER]Wir wissen, dass sie sich nun im Feuerland aufhalten. "
gameforge.main_quest_flame_lv99._060_say = "Wir haben bereits einen Sp\228her dorthin geschickt.[ENTER]Doch vor kurzem brach der Kontakt ab und ich bin[ENTER]sehr beunruhigt. Kannst du auf deinem Weg ins[ENTER]Feuerland Ausschau nach ihm halten? "
gameforge.main_quest_flame_lv99._070_say = "Nat\252rlich. "
gameforge.main_quest_flame_lv99._080_say = "Danke. Ich markiere dir seine letzte uns bekannte[ENTER]Position auf der Karte. Viel Erfolg! "
gameforge.main_quest_flame_lv99._090_notice = "Schaue dich an folgenden Koordinaten nach dem[ENTER]vermissten Sp\228her um: (%d,%d) "
gameforge.main_quest_flame_lv99._100_sayTitle = "Erkunde das Feuerland! "
gameforge.main_quest_flame_lv99._110_say = "Reise in das Feuerland und suche an dem Ort, den[ENTER]Yak-Hwan dir genannt hat, nach dem Sp\228her und[ENTER]weiteren Hinweisen auf die Machenschaften der Diener. "
gameforge.main_quest_flame_lv99._120_say = "An dem markierten Ort muss sich irgendetwas[ENTER]befinden. Vielleicht hast du einen Hinweis[ENTER]\252bersehen? Schaue dich noch einmal genauer dort um. "
gameforge.main_quest_flame_lv99._130_notice = "Dies ist der Ort, den Yak-Hwan auf der Karte[ENTER]markiert hat. Schaue dich um und kehre dann zu[ENTER]Yak-Hwan zur\252ck. "
gameforge.main_quest_flame_lv99._140_say = "Yak-Hwan wartet auf dem Fels der Dunklen Drachen[ENTER]auf deinen Bericht. "
gameforge.main_quest_flame_lv99._150_say = "Du bist zur\252ck! Hast du etwas herausgefunden? "
gameforge.main_quest_flame_lv99._160_say = "Vom Sp\228her leider keine Spur. Doch ich konnte eine[ENTER]mir bis jetzt unbekannte Festung entdecken. Eine[ENTER]seltsame Aura ging von ihr aus und schien auch die[ENTER]Umgebung zu beeinflussen. "
gameforge.main_quest_flame_lv99._170_say = "Hm, das gef\228llt mir gar nicht. Ich werde[ENTER]versuchen, mehr \252ber diese Festung in Erfahrung zu[ENTER]bringen und mich dann wieder bei dir melden. "
gameforge.main_quest_flame_lv99._180_sendLetter = "Festung erforschen "
gameforge.main_quest_flame_lv99._190_say = "Hm, wir tappen im Dunkeln. Ich habe rein gar[ENTER]nichts \252ber diese geheimnisvolle Festung[ENTER]herausfinden k\246nnen. In diesem Brief habe ich[ENTER]alles zusammengetragen, was wir bis jetzt wissen.[ENTER]Bitte \252berbringe ihn Yon-I-Walker. Er wird wissen,[ENTER]was zu tun ist. "
gameforge.main_quest_flame_lv99._200_say = "Gehe zu Yon-I-Walker. "
gameforge.main_quest_flame_lv99._210_say = "Was kann ich f\252r dich tun? ... Ah, ein Brief.[ENTER]Yak-Hwan bittet also um meine Hilfe. Dann werden[ENTER]wir mal versuchen, Licht in die Dunkelheit zu bringen. "
gameforge.main_quest_flame_lv99._220_say = {}
gameforge.main_quest_flame_lv99._230_say = {}
gameforge.main_quest_flame_lv99._240_say = "Eine geheimnisvolle Aura, die aus dem Inneren[ENTER]einer Festung str\246mt? Interessant ...[ENTER]Schaue dich zun\228chst einmal in der n\228heren[ENTER]Umgebung dort um. Ich habe da einen Verdacht,[ENTER]worum es sich bei dieser Aura handeln k\246nnte.[ENTER]Hier, nimm dieses Papier und wickel es um deine[ENTER]Waffe. Wenn sich mein Verdacht best\228tigt, sollte[ENTER]sich das Papier schwarz f\228rben, sobald du damit[ENTER]D\228monen t\246test, die unter dem Einfluss der dunklen[ENTER]Aura stehen. "
gameforge.main_quest_flame_lv99._250_notice = "Besiege D\228monen, die um die Festung herumstreunen. "
gameforge.main_quest_flame_lv99._260_sayTitle = "D\228monenjagd "
gameforge.main_quest_flame_lv99._270_say = "Besiege Feuerland-D\228monen, die in der Umbebung der[ENTER]Festung herumstreunen und pr\252fe, ob deine Waffe[ENTER]sich verf\228rbt. "
gameforge.main_quest_flame_lv99._280_say = "Hm, ich bin mir sicher, im Feuerland muss ein[ENTER]Hinweis auf diese Aura zu finden sein. Kehre noch[ENTER]einmal zur\252ck in erschlage D\228monen, die sich in[ENTER]unmittelbarer N\228he dieser Festung befinden. "
gameforge.main_quest_flame_lv99._290_notice = "Das Papier hat sich schwarz verf\228rbt. Kehre zu[ENTER]Yon-I-Walker zur\252ck. "
gameforge.main_quest_flame_lv99._300_say = "Ah, so wie ich es erwartet hatte! Das ist h\246chst[ENTER]bemerkenswert. Ich werde dieses Papier etwas n\228her[ENTER]untersuchen. Ruhe dich solange aus. "
gameforge.main_quest_flame_lv99._310_sendLetter = "Aura erforschen "
gameforge.main_quest_flame_lv99._320_say = "Yon-I-Walker sucht nach dir. Gehe zu ihm, um[ENTER]Genaueres zu erfahren. "
gameforge.main_quest_flame_lv99._330_say = "Willkommen. Ich stecke noch mitten in den[ENTER]Untersuchungen des Papiers, das die Aura[ENTER]aufgefangen hat. Doch mein Verstand ist getr\252bt.[ENTER]Ich ben\246tige Sonnenkr\228uter, um ihn zu erhellen.[ENTER]Kannst du mir welche besorgen? "
gameforge.main_quest_flame_lv99._340_say = "Nat\252rlich. "
gameforge.main_quest_flame_lv99._350_say = "Die Sonnenkr\228uter wachsen an hei\223en, trockenen[ENTER]Orten \150 im Feuerland sind sie ganzj\228hrig zu[ENTER]finden. Ich markiere dir meinen letzten Fundort[ENTER]auf der Karte. Obwohl ich mir gerade nicht mehr so[ENTER]sicher bin, ob das tats\228chlich auch dort war ... "
gameforge.main_quest_flame_lv99._360_say = "Ich mache mich sofort auf den Weg. "
gameforge.main_quest_flame_lv99._370_notice = "Gehe zum markiert Ort und suche dort nach[ENTER]Sonnenkr\228utern. "
gameforge.main_quest_flame_lv99._380_sayTitle = "Sonnenkr\228uter besorgen "
gameforge.main_quest_flame_lv99._390_say = "Gehe zu dem Ort, den Yon-I-Walker auf der Karte[ENTER]markiert hat, und suche dort nach Sonnenkr\228utern. "
gameforge.main_quest_flame_lv99._400_say = "Du kommst mit leeren H\228nden? Das ist nicht gut.[ENTER]Ich f\252hle, wie mein Verstand immer mehr durch die[ENTER]Aura getr\252bt wird. Bitte hole mir diese Sonnenkr\228uter. "
gameforge.main_quest_flame_lv99._410_notice = "Du hast die Sonnenkr\228uter gefunden. Bringe sie zu[ENTER]Yon-I-Walker. "
gameforge.main_quest_flame_lv99._420_say = "Ah, du hast die Sonnenkr\228uter gefunden![ENTER]Ausgezeichnet. Nun kann ich meine Untersuchungen[ENTER]fortsetzen. Yak-Hwan wird dich dann davon[ENTER]unterrichten. "
gameforge.main_quest_flame_lv99._430_say = "Das Abenteuer geht weiter, sobald du Level 100[ENTER]erreicht hast. "
gameforge.main_quest_lv1 = {}
gameforge.main_quest_lv1._10_sendLetter = "Willkommen bei Metin2 "
gameforge.main_quest_lv1._20_say = "Die spannenden Abenteuer von Metin2 stehen kurz[ENTER]bevor. Zun\228chst solltest du den Stadtw\228chter[ENTER]aufsuchen. Er versorgt dich mit einigen[ENTER]grundlegenden Informationen und unterschiedlichen[ENTER]Aufgaben.[ENTER]Wenn du jagen m\246chtest, findest du wilde Tiere[ENTER]au\223erhalb der Dorfgrenzen. Sie werden als rote[ENTER]Punkte auf der Minikarte angezeigt. Du solltest[ENTER]dich zun\228chst auf die Wildhunde konzentrieren, da[ENTER]sie die einfachsten Gegner darstellen.[ENTER]Viel Erfolg! "
gameforge.main_quest_lv1._30_targetVid = "Finde den Stadtw\228chter "
gameforge.main_quest_lv1._40_sayTitle = "Finde den Stadtw\228chter "
gameforge.main_quest_lv1._50_sayReward = "Sprich mit dem Stadtw\228chter, indem du ihn[ENTER]anklickst. Er ist der NPC, auf den der gro\223e rote[ENTER]Pfeil zeigt. Wenn du ihn nicht siehst, bist du[ENTER]vermutlich zu weit entfernt. Folge den blinkenden[ENTER]Kreisen auf der Karte, bis du zum Stadtw\228chter[ENTER]gelangst. "
gameforge.main_quest_lv1._60_sayTitle = "Stadtw\228chter: "
gameforge.main_quest_lv1._70_say = "Du scheinst neu hier im Ort zu sein! Wie ich[ENTER]sehe, haben sie aus dir noch keinen Soldaten[ENTER]gemacht. Hast du \252berhaupt irgendeine Ausbildung[ENTER]erhalten? Sieh dich nur an! Du hast bestimmt noch[ENTER]nie in deinem Leben eine Waffe benutzt![ENTER]Also h\246r zu! Du musst stets wachsam sein, wenn du[ENTER]im Krieg \252berleben willst. Bis du Level 10[ENTER]erreichst, werde ich dir helfen. Aber glaub[ENTER]nicht, dass es einfach wird![ENTER]Und jetzt beweg dich! "
gameforge.main_quest_lv1._80_say = "Mach dich auf den Weg und lerne die grundlegenden[ENTER]Methoden f\252r Kampf und Jagd![ENTER]Sobald du das n\228chste Level erreicht hast,[ENTER]solltest du ins Dorf zur\252ckkehren, um erneut mit[ENTER]mir zu reden.[ENTER]Was stehst du noch hier herum? Los! "
gameforge.main_quest_lv10 = {}
gameforge.main_quest_lv10._100_sayReward = "Du erh\228ltst 5.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 2.000 Yang. "
gameforge.main_quest_lv10._10_sendLetter = "Gehe zum Hauptmann "
gameforge.main_quest_lv10._110_sayTitle = "Ausbildung beim Hauptmann "
gameforge.main_quest_lv10._120_sayReward = "Der erste Auftrag des Hauptmanns f\252hrt dich ins[ENTER]Nachbardorf. Du sollst dort den Musiker Yu-Hwan[ENTER]aufsuchen und nach den geheimen Dokumenten f\252r[ENTER]den Hauptmann fragen. "
gameforge.main_quest_lv10._130_sayTitle = "Musiker Yu-Hwan: "
gameforge.main_quest_lv10._140_say = "Das Leben ist ein Traum, so wie jedwede Existenz[ENTER]in den Weiten der Zeit. Woher kommen wir und[ENTER]wohin gehen wir? Die Welt ist voller Zwiespalt[ENTER]und Streit. Der Same der Ehrlichkeit f\228llt nie[ENTER]auf fruchtbaren Boden...[ENTER]Bist du hier, um meinem Gesang zu lauschen? "
gameforge.main_quest_lv10._150_say = "Ah, der Hauptmann schickt dich! Dann musst du ein[ENTER]vertrauensw\252rdiger Mensch sein.[ENTER]Psst, sprich leise... Niemand im Dorf darf von[ENTER]meiner Identit\228t erfahren. Hier, nimm dies an[ENTER]dich. Das Dokument enth\228lt wichtige[ENTER]Informationen, die ich sammeln konnte. Bringe sie[ENTER]zum Hauptmann. "
gameforge.main_quest_lv10._160_sayTitle = "Musiker Yu-Hwan: "
gameforge.main_quest_lv10._170_say = "Geh und beeil dich! Es ist nicht gut, wenn du zu[ENTER]lange z\246gerst. Denn denk immer daran: Das Leben[ENTER]ist kurz und daher kostbar. Genie\223e es,[ENTER]solange du kannst.  "
gameforge.main_quest_lv10._180_targetVid = "Zur\252ck zum Hauptmann "
gameforge.main_quest_lv10._190_sayReward = "Der Musiker Yu-Hwan, der heimlich als Spion[ENTER]arbeitet, hat dir wichtige Dokumente \252berreicht.[ENTER]Bringe sie dem Hauptmann im ersten Dorf. "
gameforge.main_quest_lv10._200_say = "Das ist das Dokument, das der Musiker dir[ENTER]\252berreicht hat? Keine schlechte Arbeit f\252r[ENTER]einen neuen Abenteurer![ENTER]Ich setze gro\223e Hoffnungen in dich. Nimm dies[ENTER]als Anerkennung f\252r deine Zuverl\228ssigkeit. Und[ENTER]setze dich weiter so engagiert f\252r das Land ein. "
gameforge.main_quest_lv10._20_sayReward = "Du hast gen\252gend Erfahrung gesammelt, um deinem[ENTER]Reich als vollwertiger K\228mpfer zu dienen. Von nun[ENTER]an wird der Hauptmann dein Auftraggeber sein. Du[ENTER]findest ihn im ersten Dorf. Z\246gere nicht zu lange[ENTER]damit, ihn aufzusuchen. "
gameforge.main_quest_lv10._30_sayTitle = "Hauptmann: "
gameforge.main_quest_lv10._40_say = "Du kommst mir bekannt vor... Ja, ich erinnere[ENTER]mich. Du bist der neue Abenteurer, von dem man[ENTER]mir erz\228hlt hat.[ENTER]Ich wei\223 nicht, wie gut du bislang ausgebildet[ENTER]wurdest, aber hier warten einige Aufgaben auf[ENTER]dich, die wom\246glich eine Herausforderung[ENTER]darstellen k\246nnten. "
gameforge.main_quest_lv10._50_say = "Es werden einige Herausforderungen auf dich[ENTER]zukommen, also sei bereit.[ENTER]Kennst du die Geschichte der drei Reiche vom[ENTER]Kontinent des Strahlenden Himmels? Du kennst sie[ENTER]nicht? Was bringen die Ausbilder den jungen[ENTER]Leuten heutzutage nur bei? Sollte ich dich[ENTER]wirklich so Grundlegendes lehren m\252ssen? "
gameforge.main_quest_lv10._60_say = "Also gut. Dies ist wichtig, denn es ist die[ENTER]Geschichte des Kontinents. Ich werde es f\252r dich[ENTER]zusammenfassen.[ENTER]Einst gab es ein vereintes Reich.[ENTER]Dann kamen die Metinsteine und f\252hrten Krieg und[ENTER]Zwietracht mit sich. Das Land wurde geteilt:[ENTER]Shinsoo ist das Reich des Handels,[ENTER]Chunjo das Reich der Religion,[ENTER]und Jinno das Reich des Milit\228rs. "
gameforge.main_quest_lv10._70_say = "Jedes Reich versucht, sich von den Unruhen[ENTER]zu erholen, die nach Einschlag der Metinsteine[ENTER]\252ber die L\228ndereien hereinbrachen. Viele[ENTER]w\252nschen sich die Vereinigung des Kontinents.[ENTER]Das ist etwas, f\252r das auch du einstehen[ENTER]solltest! Vergiss das niemals. "
gameforge.main_quest_lv10._80_say = "Ich werde dir nun deinen ersten Auftrag erteilen.[ENTER]Entspanne dich, es ist eine leicht zu[ENTER]bew\228ltigende Aufgabe.[ENTER]Im Nachbardorf lebt ein Musiker namens Yu-Hwan.[ENTER]Die Leute sind der \220berzeugung, er habe den[ENTER]Armeedienst quittiert, um Musiker zu werden. Aber[ENTER]in Wahrheit arbeitet er als geheimer Sp\228her, um[ENTER]wichtige Dokumente zu beschaffen. Es gibt eines,[ENTER]das ich von ihm ben\246tige. Bringe es mir \150 und[ENTER]vergiss nicht, dass dies ein geheimer Auftrag[ENTER]ist. "
gameforge.main_quest_lv10._90_say = "Dr\252cke die M-Taste, um herauszufinden, wie du in[ENTER]das n\228chste Dorf auf der Karte gelangst. Benutze[ENTER]das Teleportationsportal, das den entsprechenden[ENTER]Dorfnamen tr\228gt.[ENTER]Beeile dich! Yu-Hwan ist ein hochgewachsener Kerl[ENTER]- aber du wirst ihn an seinem Musikinstrument[ENTER]erkennen. "
gameforge.main_quest_lv12 = {}
gameforge.main_quest_lv12._100_sayTitle = "Alpha-Grauw\246lfe t\246ten: "
gameforge.main_quest_lv12._10_sayReward = "Der Hauptmann hat eine neue Aufgabe f\252r[ENTER]dich. Gehe zu ihm. "
gameforge.main_quest_lv12._110_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.main_quest_lv12._120_say = "Bist du erfolgreich gewesen? Gut gemacht! Ich[ENTER]nehme an, du hattest nicht allzu viele Probleme?[ENTER]Wie auch immer, lass uns zur n\228chsten Stufe[ENTER]\252bergehen. "
gameforge.main_quest_lv12._130_targetVid = "Finde den Hauptmann "
gameforge.main_quest_lv12._140_sendLetter = "Aufgabe abgeschlossen "
gameforge.main_quest_lv12._150_say = "Aufgabe abgeschlossen "
gameforge.main_quest_lv12._160_sayReward = "Du hast die geforderte Zahl an Alpha-Grauw\246lfen[ENTER]get\246tet. Kehre zum Hauptmann zur\252ck und berichte[ENTER]von deinem Erfolg. "
gameforge.main_quest_lv12._170_say = "Du hast die Alpha-Grauw\246lfe erledigt? Gute[ENTER]Arbeit. Dank dir ist es jetzt einfacher, die[ENTER]Sicherheit im Dorf zu gew\228hrleisten. Das ist[ENTER]einmal eine gute Nachricht in Kriegszeiten wie[ENTER]diesen. "
gameforge.main_quest_lv12._180_sayReward = "Du erh\228ltst 10.000 Erfahrungspunkte und 3.500[ENTER]Yang. "
gameforge.main_quest_lv12._20_say = "Mehrere Alpha-Grauw\246lfe haben au\223erhalb des[ENTER]Dorfes gro\223es Unheil angerichtet. Sie waren[ENTER]schon immer wild, aber nun geb\228rden sie sich[ENTER]unberechenbar! Sie greifen das Dorf und die Leute[ENTER]auf der Stra\223e an. Um dieser Situation Herr zu[ENTER]werden, m\252ssen wir einige Alpha-Grauw\246lfe[ENTER]t\246ten. Kannst du helfen? Erledige 10[ENTER]Alpha-Grauw\246lfe f\252r uns. "
gameforge.main_quest_lv12._30_sayReward = "Als Belohnung warten 10.000 Erfahrungspunkte und[ENTER]3.500 Yang auf dich. "
gameforge.main_quest_lv12._40_sendLetter = "T\246te 10 Alpha-Grauw\246lfe "
gameforge.main_quest_lv12._50_sayReward = "Die Alpha-Grauw\246lfe st\246ren den Dorffrieden.[ENTER]Um der Gefahr Herr zu werden, musst du 10[ENTER]von ihnen t\246ten. "
gameforge.main_quest_lv12._60_sayReward = "Bis jetzt hast du %s Alpha-Grauw\246lfe get\246tet. "
gameforge.main_quest_lv12._65_counter = "Verbleibende Anzahl "
gameforge.main_quest_lv12._70_sayReward = "Du hast alle 10 Alpha-Grauw\246lfe get\246tet.[ENTER]Kehre zum Hauptmann zur\252ck. "
gameforge.main_quest_lv12._80_npcChat = "Alpha-Grauw\246lfe t\246ten "
gameforge.main_quest_lv12._90_say = "Du hast die Aufgabe noch nicht erledigt?[ENTER]Hast du Probleme damit, 10 Alpha-Grauw\246lfe zu[ENTER]t\246ten? Wenn du f\252r dein Reich k\228mpfen willst,[ENTER]solltest du es weiter versuchen. "
gameforge.main_quest_lv14 = {}
gameforge.main_quest_lv14._100_sayTitle = "Aufgabe abgeschlossen "
gameforge.main_quest_lv14._10_sayReward = "Der Hauptmann hat eine neue Aufgabe f\252r[ENTER]dich. Du solltest ihn aufsuchen. "
gameforge.main_quest_lv14._110_sayReward = "Du hast einen Metin der Schlacht zerst\246rt.[ENTER]Geh zum Hauptmann und berichte ihm von deinem[ENTER]Erfolg. "
gameforge.main_quest_lv14._120_say = "Gute Arbeit! Du hast dich wirklich als[ENTER]zuverl\228ssiger Helfer erwiesen. Nun wei\223 ich,[ENTER]dass ich dir jede Aufgabe \252bertragen kann. Hier[ENTER]ist deine Belohnung. Weiter so! "
gameforge.main_quest_lv14._130_sayReward = "Du erh\228ltst 20.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 10.000 Yang. "
gameforge.main_quest_lv14._140_sayReward = "Du erh\228ltst einen %s. "
gameforge.main_quest_lv14._20_say = "Ich wei\223 von der dunklen Kraft der Metinsteine -[ENTER]Yu-Hwan, der Musiker, hat mich informiert.[ENTER]Die Steine machen die Tiere wild und \252berall[ENTER]verbreiten sich Seuchen. "
gameforge.main_quest_lv14._30_say = "Wenn wir nichts gegen die Metinsteine[ENTER]unternehmen, greifen die Tiere die Dorfbewohner[ENTER]an oder schlimmer noch, eine Seuche bricht aus.[ENTER]Kannst du dich um die Steine k\252mmern, die[ENTER]au\223erhalb des Dorfes am Boden aufgeschlagen sind? "
gameforge.main_quest_lv14._40_sayReward = "Als Belohnung warten 20.000 Erfahrungspunkte und[ENTER]10.000 Yang auf dich sowie ein Geiststein (+0 bis[ENTER]+2). "
gameforge.main_quest_lv14._50_sendLetter = "Zerst\246re den Metin der Schlacht "
gameforge.main_quest_lv14._60_sayReward = "Die Metinsteine stellen eine ernstzunehmende[ENTER]Gefahr dar. Hilf dem Hauptmann und zerst\246re einen[ENTER]Metin der Schlacht. "
gameforge.main_quest_lv14._70_sayTitle = "Aufgabe abgeschlossen "
gameforge.main_quest_lv14._80_sayReward = "Du hast einen Metin der Schlacht zerst\246rt.[ENTER]Geh und informiere den Hauptmann dar\252ber. "
gameforge.main_quest_lv14._90_sendLetter = "Zur\252ck zum Hauptmann "
gameforge.main_quest_lv15 = {}
gameforge.main_quest_lv15._100_say = "Unser Reich, Jinno, besa\223 schon immer eine starke[ENTER]Milit\228rmacht. Der Kaiser vereinte den Kontinent[ENTER]mit seiner m\228chtigen und erprobten Kavallerie.[ENTER]Auch wenn wir durch die Unruhen, die von den[ENTER]Metinsteinen verursacht werden, nun geteilt sind,[ENTER]besitzt unser Reich rechtm\228\223ig die Macht von[ENTER]Iryung. "
gameforge.main_quest_lv15._10_qSetTitle = "Die aktuelle Lage "
gameforge.main_quest_lv15._110_say = "Wir besitzen noch immer das m\228chtigste Milit\228r[ENTER]aller drei K\246nigreiche, obwohl wir wegen der[ENTER]Metinsteine nichts unternehmen. Wenn wir wirklich[ENTER]wollten, k\246nnten wir die anderen L\228nder mit[ENTER]Leichtigkeit besiegen. Du solltest hart[ENTER]trainieren, um ein guter Soldat zu werden. "
gameforge.main_quest_lv15._120_say = "Ich habe einen neuen Auftrag f\252r dich.[ENTER]Bringe diese Munition zu Yu-Hwan, der im[ENTER]Nachbardorf lebt. Wir lagern diese Munition zur[ENTER]Sicherheit an verschiedenen Orten, auf die wir[ENTER]bei Bedarf raschen Zugriff haben. Wenn du Yu-Hwan[ENTER]aufsuchst, leistest du einen gro\223en Beitrag f\252r[ENTER]die milit\228rische Aufr\252stung des Dorfes. "
gameforge.main_quest_lv15._130_sayReward = "Du erh\228ltst 20.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 10.000 Yang. "
gameforge.main_quest_lv15._140_sayTitle = "Die aktuelle Lage "
gameforge.main_quest_lv15._150_sayReward = "Der Hauptmann hat dir eine Lieferung f\252r Yu-Hwan[ENTER]anvertraut. Begib dich ins zweite Dorf und bringe[ENTER]sie ihm. "
gameforge.main_quest_lv15._160_say = "Einst gab es eine blutige Schlacht zwischen[ENTER]Sung Mahi und dem Drachengott. Seitdem sind die[ENTER]Menschen entzweit und stehen sich in niemals[ENTER]endenden Kriegen gegen\252ber...[ENTER]Du bist es wieder! Ben\246tigst du etwas?[ENTER]Der Hauptmann sendet mir etwas Wichtiges? Danke.[ENTER]Und nun mach dich wieder auf den Weg. Es ist[ENTER]nicht gut, wenn uns die Leute zusammen sehen. "
gameforge.main_quest_lv15._170_makequestbutton = "Sprich mit dem Hauptmann "
gameforge.main_quest_lv15._175_say = "Du hast Yu-Hwan die Lieferung[ENTER]des Hauptmanns \252berbracht.[ENTER]Gehe nun zur\252ck zum Hauptmann[ENTER]und hole deine Belohnung ab. "
gameforge.main_quest_lv15._180_say = "Gut gemacht! Wenn du so weitermachst, k\246nntest[ENTER]du ein wichtiger Helfer f\252r unser Dorf werden.[ENTER]Hier ist deine Belohnung. "
gameforge.main_quest_lv15._20_say = "Wie du sicher bereits geh\246rt hast, steht es um[ENTER]dem Frieden innerhalb der Reiche momentan nicht[ENTER]gut. Geh zum Hauptmann, er kann dir n\228here[ENTER]Informationen liefern. "
gameforge.main_quest_lv15._30_say = "Ich denke, du solltest mehr \252ber die gegenw\228rtige[ENTER]Lage erfahren. Richte deine Aufmerksamkeit[ENTER]zun\228chst auf unser Reich. Um einen Krieg zu[ENTER]gewinnen, muss man sich zuerst selbst kennen, ehe[ENTER]man seine Feinde kennen lernt. "
gameforge.main_quest_lv15._40_say = "Unser Reich, Shinsoo, war schon immer ein Zentrum[ENTER]des Handels. Ausgedehnte Handelsrouten brachten[ENTER]Kaufleute und Ware aus allen Himmelsrichtungen[ENTER]hier zusammen. Seit dem Einschlag der Metinsteine[ENTER]brechen diese Beziehungen zusammen, unsere[ENTER]Wirtschaft verschlechtert sich. Einst waren wir[ENTER]wohlhabend, aber niemals eine gro\223e Milit\228rmacht.[ENTER]Daher heuerten wir S\246ldner an. Diese K\228mpfer sind[ENTER]verl\228sslich und loyal demjenigen gegen\252ber, der[ENTER]sie bezahlt. "
gameforge.main_quest_lv15._50_say = "Dank der S\246ldner hat sich die Lage unseres[ENTER]Landes einigerma\223en stabilisiert.[ENTER]Um uns aber auf zuk\252nftige Kriege vorzubereiten,[ENTER]ben\246tigen wir sowohl mehr K\228mpfer als auch eine[ENTER]starke Wirtschaft. Das wird nicht leicht werden,[ENTER]f\252r niemanden von uns. "
gameforge.main_quest_lv15._60_say = "Ich habe einen weiteren Auftrag f\252r dich.[ENTER]Bringe diese Spezialit\228t zu Yu-Hwan, der im[ENTER]Nachbardorf lebt. Unser Land war und ist noch[ENTER]immer ein Reich des Handels, und so handeln wir[ENTER]mit Spezialit\228ten verschiedener Regionen. Die[ENTER]Gegenleistungen, die wir so erhalten, kommen dem[ENTER]Dorf zugute. "
gameforge.main_quest_lv15._70_say = "Unser Reich, Chunjo, wird von Gouverneur[ENTER]Yoon-Young gef\252hrt und ist auf den starken Mauern[ENTER]des Glaubens gegr\252ndet worden. Daher wussten wir[ENTER]vor allen anderen von der Existenz des Sung Mahi.[ENTER]Unsere Schamanen haben uns auf das Erscheinen der[ENTER]Metinsteine vorbereitet. Ohne sie k\246nnte die[ENTER]Sicherheit unseres Landes nicht gew\228hrleistet[ENTER]werden. Ihr Glaube verleiht ihnen F\228higkeiten,[ENTER]die sich dem Normalsterblichen niemals[ENTER]erschlie\223en werden. Ohne die Schamanen w\228re es[ENTER]nur eine Frage der Zeit, bis ein anderes Land uns[ENTER]im Krieg besiegen w\252rde. "
gameforge.main_quest_lv15._80_say = "Die Bev\246lkerung unseres Landes besitzt einen[ENTER]starken Glauben und betet jeden Tag zum[ENTER]Drachengott. Dieser unser Wohlt\228ter besch\252tzt[ENTER]uns und bewahrt uns vor der Auferstehung[ENTER]Sung Mahis. Mit seiner Hilfe werden wir uns[ENTER]weiterhin gegen barbarische Angriffe von[ENTER]au\223erhalb verteidigen und eines Tages den[ENTER]Kontinent mit unserem Glauben wieder vereinen. "
gameforge.main_quest_lv15._90_say = "Ich habe einen neuen Auftrag f\252r dich.[ENTER]Bringe diese Steinstatue unseres Drachengottes zu[ENTER]Yu-Hwan, der im Nachbardorf lebt. Unser Land ist[ENTER]sehr religi\246s, und der tiefe Glaube an den[ENTER]Drachengott ist uns sehr wichtig. Mit diesem[ENTER]Botengang hilfst du, den Glauben der Bewohner zu[ENTER]festigen. "
gameforge.main_quest_lv16 = {}
gameforge.main_quest_lv16._100_sayReward = "Du erh\228ltst 40.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 5.000 Yang. "
gameforge.main_quest_lv16._10_sendLetter = "Fang den Spion "
gameforge.main_quest_lv16._20_sayTitle = "Fang den Spion "
gameforge.main_quest_lv16._30_sayReward = "Im Dorf gibt es einen feindlichen Spion. Der[ENTER]Hauptmann wird dich mit den entsprechenden[ENTER]Informationen versorgen. "
gameforge.main_quest_lv16._40_say = "Ich habe das Gef\252hl, dass sich ein Spion in[ENTER]unserer Mitte befindet. Jemand aus den Reihen der[ENTER]Dorfbewohner macht gemeinsame Sache mit den[ENTER]K\228mpferinnen vom Clan des Wei\223en Eid. Ich brauche[ENTER]deine Hilfe bei dieser Sache: Geh und t\246te[ENTER]Wei\223er-Eid Soldaten, vielleicht findest du bei[ENTER]ihnen einen Hinweis auf den Spion. "
gameforge.main_quest_lv16._50_sayReward = "Als Belohnung warten 40.000 Erfahrungspunkte[ENTER]und 5.000 Yang auf dich. "
gameforge.main_quest_lv16._60_sendLetter = "Entlarve den Spion "
gameforge.main_quest_lv16._70_sayReward = "Der Hauptmann vermutet einen Spion des[ENTER]Wei\223en-Eid im Dorf. T\246te so lange Kriegerinnen[ENTER]vom Wei\223en-Eid, bis du einen Hinweis auf den[ENTER]Spion findest. "
gameforge.main_quest_lv16._75_say = "Du hast einen Brief gefunden.[ENTER]Bringe ihn zum Hauptmann. "
gameforge.main_quest_lv16._80_sayReward = "Du hast bei den Wei\223er-Eid Kriegerinnen einen[ENTER]Brief gefunden. Vielleicht enth\228lt er einen[ENTER]Hinweis auf den Spion, den der Hauptmann sucht.[ENTER]Bringe den Brief zum Hauptmann. "
gameforge.main_quest_lv16._90_say = "Hast du irgendwelche Beweise finden k\246nnen? Einen[ENTER]Brief? Lass mich mal sehen...[ENTER]Das k\246nnte ausreichen, um herauszufinden, wer der[ENTER]Spion ist. Dank dir k\246nnen wir dieses Problem[ENTER]wom\246glich beseitigen. Gut gemacht![ENTER]Ruhe dich eine Weile aus. Und nimm dies als[ENTER]Zeichen meines Dankes. "
gameforge.main_quest_lv2 = {}
gameforge.main_quest_lv2._100_sendLetter = "Erste \220bung "
gameforge.main_quest_lv2._10_npcChat = "Was machst du? "
gameforge.main_quest_lv2._110_sayTitle = "Erste \220bung: "
gameforge.main_quest_lv2._120_sayReward = "T\246te 9 Wildhunde. Du findest sie direkt vor den[ENTER]Toren der Stadt. "
gameforge.main_quest_lv2._130_sayReward = "Bis jetzt hast du %s Wildhunde get\246tet. "
gameforge.main_quest_lv2._135_counter = "Verbleibende Anzahl "
gameforge.main_quest_lv2._140_sayTitle = "Erste \220bungsaufgabe abgeschlossen. "
gameforge.main_quest_lv2._150_sayReward = "Du hast alle 9 Wildhunde get\246tet. Kehre zum[ENTER]Stadtw\228chter zur\252ck und erstatte ihm Bericht. "
gameforge.main_quest_lv2._160_npcChat = "Bez\252glich der ersten Aufgabe... "
gameforge.main_quest_lv2._170_say = "Wenn du Probleme damit hast, 9 Wildhunde zu[ENTER]t\246ten, so kannst du dich nicht wirklich[ENTER]Abenteurer nennen, oder? "
gameforge.main_quest_lv2._180_sayTitle = "\220bungsaufgabe: "
gameforge.main_quest_lv2._182_say = "Willst du die Quest f\252r immer aufgeben?[ENTER]Sie wird dann aus deiner Auftrags\252bersicht[ENTER]gel\246scht und nie wieder verf\252gbar sein. "
gameforge.main_quest_lv2._190_say = "Wie hast du das nur geschafft?[ENTER]Du hast doch nicht geschummelt, oder?[ENTER]Wie auch immer, lass uns[ENTER]zur n\228chsten Stufe \252bergehen.  "
gameforge.main_quest_lv2._200_sendLetter = "\220bungsaufgabe abgeschlossen "
gameforge.main_quest_lv2._20_say = "Stadtw\228chter:[ENTER]Dein Interesse ist l\246blich, doch du solltest erst[ENTER]noch mehr Erfahrungspunkte sammeln. Komm zur\252ck,[ENTER]wenn du ein h\246heres Level erreicht hast! "
gameforge.main_quest_lv2._210_say = "Du bist besser, als ich erwartet habe! Aber das[ENTER]h\228tte jeder erledigen k\246nnen, ha ha! Zu meiner[ENTER]Zeit waren die Pr\252fungen viel h\228rter. Sei also[ENTER]auf die n\228chste gefasst. Hier, du hast dir einige[ENTER]Tr\228nke und etwas Yang verdient. Geh und kauf dir[ENTER]eine bessere Ausr\252stung. Ich werde dich rufen[ENTER]lassen, sobald es eine weitere Aufgabe f\252r dich[ENTER]gibt. "
gameforge.main_quest_lv2._220_sayReward = "Du erh\228ltst 250 Erfahrungspunkte.[ENTER]Du erh\228ltst 1.000 Yang. "
gameforge.main_quest_lv2._230_sayReward = "Du erh\228ltst %s, %s St\252ck. "
gameforge.main_quest_lv2._30_sendLetter = "Der Brief vom Stadtw\228chter "
gameforge.main_quest_lv2._40_targetVid = "Finde den Stadtw\228chter "
gameforge.main_quest_lv2._50_sayReward = "Wenn du diese Nachricht liest, hast du ein neues[ENTER]Level erreicht. Herzlichen Gl\252ckwunsch! Gehe nun[ENTER]zum Stadtw\228chter, damit er dir deine erste[ENTER]\220bungsaufgabe erl\228utern kann! "
gameforge.main_quest_lv2._60_say = "Dir mangelt es noch immer an Disziplin.[ENTER]Anscheinend hast du aber immerhin gelernt, wie du[ENTER]mit deiner Waffe umzugehen hast. Glaubst du[ENTER]wirklich, dass du so weit bist, es mit wilden[ENTER]Tieren aufzunehmen? Ich werde besser zun\228chst[ENTER]pr\252fen, wie gewandt du bist.[ENTER]Verlasse das Dorf und t\246te 9 Wildhunde, dann komm[ENTER]zu mir zur\252ck und erhalte deine Belohnung. "
gameforge.main_quest_lv2._70_say = "Sie sind nicht sehr stark, es d\252rfte also nicht[ENTER]schwer sein. Wenn du diese Aufgabe nicht[ENTER]erledigst, wirst du in dieser Gegend nicht[ENTER]\252berleben k\246nnen! Und jetzt zieh los - je eher du[ENTER]es erledigst, desto besser! "
gameforge.main_quest_lv2._80_sayReward = "Die Dorfbewohner stellen dir von Zeit zu Zeit[ENTER]Aufgaben, die dir Erfahrungpunkte und Yang[ENTER]einbringen. Es lohnt sich also, die Augen nach[ENTER]Auftraggebern offen zu halten! "
gameforge.main_quest_lv2._90_sayReward = "F\252r das T\246ten der Wildhunde warten auf dich[ENTER]Erfahrungspunkte: 250[ENTER]Yang: 1000[ENTER]Gegenstand: %s, Menge: %s "
gameforge.main_quest_lv2._95_counter = "Wildhunde: "
gameforge.main_quest_lv27 = {}
gameforge.main_quest_lv27._100_makequestbutton = "Metinstein zerst\246rt "
gameforge.main_quest_lv27._105_say = "Du hast einen Metin der Schw\228rze zerst\246rt.[ENTER]Geh zum Hauptmann und berichte ihm von deinem[ENTER]Erfolg. "
gameforge.main_quest_lv27._10_makequestbutton = "Zerst\246re die Metinsteine "
gameforge.main_quest_lv27._110_say = "Du hast den Metinstein zerst\246rt? Danke. Nun ist[ENTER]das Dorf vorl\228ufig sicher.[ENTER]Wo kamen diese Metinsteine \252berhaupt her? Es[ENTER]gibt kaum Informationen \252ber sie, obwohl sie[ENTER]solch ernste Probleme verursachen. Ich h\246rte, der[ENTER]Gelehrte Uriel untersucht die Metinsteine. Aber[ENTER]ich wei\223 nicht, was er herausgefunden hat.[ENTER]Na, jedenfalls hast du gute Arbeit geleistet! "
gameforge.main_quest_lv27._120_sayTitle = "Belohnung: "
gameforge.main_quest_lv27._130_sayReward = "Du erh\228ltst 300.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 15.000 Yang. "
gameforge.main_quest_lv27._140_sayReward = "Du erh\228ltst: %s "
gameforge.main_quest_lv27._20_say = "Die Metinsteine verursachen immer mehr Schaden.[ENTER]Das Land leidet. Die Metinsteine m\252ssen zerst\246rt[ENTER]werden! Geh und melde dich beim Hauptmann. "
gameforge.main_quest_lv27._30_say = "Die Metinsteine verursachen immer mehr Schaden.[ENTER]Das Land leidet. Die Metinsteine m\252ssen[ENTER]zerst\246rt werden! Geh und melde dich beim[ENTER]Hauptmann. "
gameforge.main_quest_lv27._40_say = "Wie ich h\246re, hast du hart gearbeitet. Die Leute[ENTER]reden \252ber deine guten Taten. Du schuldest mir[ENTER]was, weil ich dich an den rechten Ort beordert[ENTER]habe! Ha, ha! Reg dich nicht auf, ich mache nur[ENTER]Spa\223. Du machst deine Sache sehr gut.[ENTER]Aber die Metinsteine werden immer mehr. Das ist[ENTER]ein ernstes Problem. "
gameforge.main_quest_lv27._50_say = "Wenn die Metinsteine so zahlreich fallen, leidet[ENTER]das Volk. Manchmal frage ich mich, ob die[ENTER]Schamanen vielleicht Recht haben und der b\246se[ENTER]Gott Sung Mahi tats\228chlich auferstanden ist...[ENTER]Aber jetzt sollten wir uns erst einmal um das[ENTER]Naheliegende k\252mmern. Gib mir Bescheid, wenn du[ENTER]einen Metinstein zerst\246rt hast! "
gameforge.main_quest_lv27._60_sayTitle = "Auftrag: "
gameforge.main_quest_lv27._70_say = "Die Metinsteinart, die du zerst\246ren sollst, ist[ENTER]der Metin der Schw\228rze. Suche ihn! "
gameforge.main_quest_lv27._80_say = "In letzter Zeit h\228ufen sich die Sichtungen von[ENTER]niedergehenden Metinsteinen. Ihre b\246se Strahlung[ENTER]muss aufgehalten werden! Suche einen Metin der[ENTER]Schw\228rze und zerst\246re ihn. "
gameforge.main_quest_lv27._90_say = "Du hast den Metin der Schw\228rze zerst\246rt.[ENTER]Geh zur\252ck zum Hauptmann. "
gameforge.main_quest_lv3 = {}
gameforge.main_quest_lv3._100_say = "Sei gegr\252\223t. Wurdest du vom Stadtw\228chter[ENTER]geschickt? Ich habe eine einfache Aufgabe f\252r[ENTER]dich. Mein Vater hat heute Morgen ein wichtiges[ENTER]Buch hier liegen lassen. Er braucht es dringend. "
gameforge.main_quest_lv3._10_npcChat = "Ich habe die erste Aufgabe erledigt. "
gameforge.main_quest_lv3._110_say = "K\246nntest du das Buch meinem Vater bringen? Ich[ENTER]w\252rde es selbst tun, muss aber im Laden bleiben.[ENTER]Wenn du mir diesen Gefallen erweist und ihm sein[ENTER]Buch bringst, wird er dich angemessen belohnen.[ENTER]Du musst wissen, dass er hier im Dorf R\252stungen[ENTER]verkauft. "
gameforge.main_quest_lv3._120_sayItem = "Herstellung von R\252stungen "
gameforge.main_quest_lv3._130_targetVid = "Finde den R\252stungsh\228ndler "
gameforge.main_quest_lv3._140_sendLetter = "\220berbringe das Buch "
gameforge.main_quest_lv3._150_sayReward = "\220berbringe dem Vater der Gemischtwarenh\228ndlerin[ENTER]das Buch, das er bei ihr vergessen hat.[ENTER]Er ist der R\252stungsh\228ndler des Dorfes. "
gameforge.main_quest_lv3._160_sayTitle = "R\252stungsh\228ndler: "
gameforge.main_quest_lv3._170_say = "Was f\252hrt dich zu mir?[ENTER]Ah, meine Tochter hat dich geschickt! Vielen[ENTER]Dank. Ich ben\246tige dieses Buch, um neue R\252stungen[ENTER]herzustellen. "
gameforge.main_quest_lv3._180_say = "Meine Tochter muss sehr besch\228ftigt sein,[ENTER]wenn sie dich schickt, um mir das Buch zu[ENTER]bringen. Mal sehen, was w\228re denn eine[ENTER]angemessene Belohnung...? "
gameforge.main_quest_lv3._190_say = "Ich werde dir als Belohnung einige Yang geben,[ENTER]damit du dir eine passende Ausr\252stung zulegen[ENTER]kannst. Das hier sollte reichen, oder?[ENTER]Ich danke dir. Wenn ich mal wieder Hilfe[ENTER]ben\246tige, wende ich mich an dich. Und wenn du[ENTER]eine neue R\252stung brauchst, dann komm ruhig zu[ENTER]mir. Mein Laden hat immer ge\246ffnet! "
gameforge.main_quest_lv3._200_sayReward = "Du erh\228ltst 450 Erfahrungspunkte.[ENTER]Du erh\228ltst 5.000 Yang.[ENTER]Du erh\228ltst 20 blaue Tr\228nke. "
gameforge.main_quest_lv3._20_say = "Es sieht so aus, als h\228tte die erste Aufgabe dir[ENTER]Spa\223 gemacht.[ENTER]Du wartest bereits auf die n\228chste? Suche mich[ENTER]erneut auf, wenn du das n\228chste Level erreicht[ENTER]hast. Dann werde ich dich mit einer weiteren[ENTER]Aufgabe versorgen. "
gameforge.main_quest_lv3._30_sendLetter = "Nachricht vom Stadtw\228chter "
gameforge.main_quest_lv3._40_sayReward = "H\246r auf zu jagen und begib dich zum Stadtw\228chter.[ENTER]Er hat eine weitere Aufgabe f\252r dich. "
gameforge.main_quest_lv3._50_say = "Ich bin froh, dass du vorbeigekommen bist. Du[ENTER]kennst doch bestimmt die Gemischtwarenh\228ndlerin,[ENTER]oder? Sie hat um Hilfe gebeten. K\246nntest du[ENTER]herausfinden, was sie ben\246tigt? Hoffentlich[ENTER]handelt es sich nicht um eine ernste[ENTER]Angelegenheit. Ich bin sicher, dass du ihr helfen[ENTER]kannst. "
gameforge.main_quest_lv3._60_say = "Zu deiner Information: Die[ENTER]Gemischtwarenh\228ndlerin verkauft[ENTER]Regenerationstr\228nke und andere Gegenst\228nde, die[ENTER]dir in Zukunft n\252tzlich sein k\246nnten. Es kann[ENTER]also nicht schaden, sich mit ihr gut zu stellen![ENTER]Geh jetzt. "
gameforge.main_quest_lv3._70_targetVid = "Finde die Gemischtwarenh\228ndlerin "
gameforge.main_quest_lv3._80_sendLetter = "Hilf der H\228ndlerin "
gameforge.main_quest_lv3._90_sayReward = "Begib dich zur Gemischtwarenh\228ndlerin, sie[ENTER]ben\246tigt deine Hilfe. "
gameforge.main_quest_lv30 = {}
gameforge.main_quest_lv30._100_say = "Auf der Steins\228ule befinden sich Inschriften.[ENTER]Schnell fertigst du eine Abschrift an. "
gameforge.main_quest_lv30._10_targetVid = "Finde Uriel "
gameforge.main_quest_lv30._110_say = "Uriel hatte Recht: Auf dem Steindenkmal befand[ENTER]sich tats\228chlich eine Inschrift. Du konntest sie[ENTER]zwar nicht lesen, aber immerhin eine Abschrift[ENTER]anfertigen. Bringe deine Notizen zu Uriel. "
gameforge.main_quest_lv30._120_say = "Hast du das Hasun Steindenkmal gefunden? Oh, du[ENTER]hast sogar eine Abschrift dabei. Sehr gut! Das[ENTER]ist eine Entdeckung von wahrhaft historischen[ENTER]Ausma\223en! Zeig her.[ENTER]Hmm... Es scheint sich tats\228chlich um[ENTER]Informationen \252ber die Metinsteine zu handeln.[ENTER]Allerdings kann ich nicht alles entziffern. Diese[ENTER]Schrift ist sehr altert\252mlich, einige der[ENTER]Buchstaben wirken fast antik. Was machen wir nur? "
gameforge.main_quest_lv30._130_say = "Ah, ich habe eine Idee! Kennst du das Tal von[ENTER]Seungryong? Dort steht eine r\228tselhafte Anlage[ENTER]aus der Antike. Wenn du dort alte Inschriften[ENTER]findest, k\246nnte ich vielleicht R\252ckschl\252sse auf[ENTER]die fehlenden Buchstaben ziehen. Geh ins Tal von[ENTER]Seungryong und suche das Seul Rong Steindenkmal! "
gameforge.main_quest_lv30._140_targetVid = "Steindenkmal im Tal von Seungryong "
gameforge.main_quest_lv30._150_say = "Der Gelehrte Uriel ben\246tigt weitere alte Texte,[ENTER]um R\252ckschl\252sse auf einige ihm unbekannte[ENTER]Buchstaben ziehen zu k\246nnen.[ENTER]Geh ins Tal von Seungryong und suche dort nach[ENTER]Inschriften auf dem Seul Rong Steindenkmal. "
gameforge.main_quest_lv30._160_say = "Du hast weitere Inschriften gefunden? Oh! Dank[ENTER]dir werde ich bald in der Lage sein, das[ENTER]Geheimnis der Metinsteine zu l\252ften. Meine[ENTER]Forschung kommt vielleicht schneller voran als[ENTER]ich dachte. Danke, ich danke dir! Wenn ich wieder[ENTER]einmal deine Hilfe brauche, lasse ich es dich[ENTER]wissen. Und hier, nimm bitte diese Belohnung f\252r[ENTER]deine M\252hen an! "
gameforge.main_quest_lv30._20_sendLetter = "Das Geheimnis der Metinsteine "
gameforge.main_quest_lv30._30_say = "Uriel hat endlich neue Informationen \252ber das[ENTER]Geheimnis der Metinsteine.[ENTER]Geh und suche Uriel, den Gelehrten. "
gameforge.main_quest_lv30._40_sayTitle = "Uriel: "
gameforge.main_quest_lv30._50_say = "Du wurdest schon einmal vom Hauptmann zu mir[ENTER]geschickt. Du scheinst sehr f\228hig zu sein.[ENTER]Ich muss dich um einen Gefallen bitten.[ENTER]Du wei\223t Bescheid \252ber die Metinsteine, oder? Die[ENTER]Metinsteine kommen vom Himmel. Sie besitzen b\246se[ENTER]Kr\228fte und verbreiten Seuchen und die Tiere[ENTER]werden wild. Wir wissen nicht, wie sie in unsere[ENTER]Welt gelangt sind oder woraus sie bestehen. Das[ENTER]erschwert meine Untersuchung.[ENTER]K\252rzlich habe ich aber einen Schl\252ssel zu den[ENTER]Geheimnissen der Metinsteine gefunden. "
gameforge.main_quest_lv30._60_say = "Es gibt eine Tafel, ein Denkmal eines antiken[ENTER]K\246nigreichs in einer H\246hle im leichten[ENTER]Affendungeon. Ich glaube, dass es bei den[ENTER]Schriften auf dieser Tafel um die Geheimnisse der[ENTER]Metinsteine geht.[ENTER]Wenn du mir diese Informationen bringen[ENTER]k\246nntest, w\228re ich vielleicht in der Lage, die[ENTER]Geheimnisse der Metinsteine zu l\252ften.[ENTER]Bitte bringe mir die Informationen vom[ENTER]Hasun-Steindenkmal im leichten Affendungeon! "
gameforge.main_quest_lv30._70_sayReward = "Du erh\228ltst 420.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 20.000 Yang. "
gameforge.main_quest_lv30._80_targetVid = "Steindenkmal im leichten Affendungeon "
gameforge.main_quest_lv30._90_say = "Der Gelehrte Uriel glaubt eine Spur gefunden zu[ENTER]haben, die ihm die Entr\228tselung der Metinsteine[ENTER]erm\246glichen k\246nnte.[ENTER]Geh zum leichten Affendungeon und suche dort nach[ENTER]dem Hasun Steindenkmal. "
gameforge.main_quest_lv32 = {}
gameforge.main_quest_lv32._100_sayReward = "Tipp: Wenn man mit dem Pferd reitet,[ENTER]kann man es schneller und bequemer schaffen. "
gameforge.main_quest_lv32._10_sendLetter = "Das geheime Buch "
gameforge.main_quest_lv32._110_npcChat = "Die Seiten des geheimen Buches "
gameforge.main_quest_lv32._120_sayTitle = "Fahrender H\228ndler: "
gameforge.main_quest_lv32._130_say = "Jetzt, wo die ganze Welt in Unruhe geraten ist,[ENTER]ist der Handel auch schwierig geworden. Was[ENTER]m\246chtest du kaufen?[ENTER]Ach, du wurdest vom Gelehrten Uriel geschickt? Er[ENTER]ist ein Stammkunde, er sucht immer alte B\252cher[ENTER]aus verschiedenen Gebieten. F\252r mich ist das[ENTER]eher l\228stig. Ha, ha, ha.[ENTER]Du m\246chtest etwas \252ber die alten B\252cher[ENTER]wissen? Hm, die alten B\252cher... "
gameforge.main_quest_lv32._140_say = "Ich habe da etwas geh\246rt, aber das kann ich nicht[ENTER]umsonst weitererz\228hlen. Eine Hand w\228scht die[ENTER]andere, nicht wahr?[ENTER]Was zur Zeit gut l\228uft, ist der Handel mit[ENTER]Waffen. Aber allein kann ich unm\246glich die[ENTER]geforderten Mengen besorgen. Ich werde mit[ENTER]Anfragen geradezu \252berh\228uft! Du stehst doch hier[ENTER]sowieso nur nutzlos in der Gegend herum. Warum[ENTER]tust du zur Abwechslung nicht mal was Sinnvolles[ENTER]und besorgst mir 20 Silberschwerter+0?[ENTER]Sobald du mir diese gebracht hast, gebe ich dir[ENTER]die Information, die die brauchst. "
gameforge.main_quest_lv32._150_targetVid = "Suche den Fahrenden H\228ndler "
gameforge.main_quest_lv32._160_sayTitle = "Du hast 20 Silberschwerter+0 "
gameforge.main_quest_lv32._170_say = "Der Fahrende H\228ndler hat von den alten Seiten[ENTER]geh\246rt. Bringe ihm die 20 Silberschwerter+0, dann[ENTER]verr\228t er dir, was er wei\223. "
gameforge.main_quest_lv32._180_sayTitle = "Besorge 20 Silberschwerter+0 "
gameforge.main_quest_lv32._190_say = "Der Fahrende H\228ndler hat von den alten Seiten[ENTER]geh\246rt, wollte sein Wissen aber nicht umsonst[ENTER]preisgeben. Besorge 20 Silberschwerter+0 und[ENTER]bringe sie dem Fahrenden H\228ndler als[ENTER]Gegenleistung f\252r die Information. "
gameforge.main_quest_lv32._200_npcChat = "Ich habe die Schwerter besorgt. "
gameforge.main_quest_lv32._20_targetVid = "Suche nach dem Gelehrten Uriel "
gameforge.main_quest_lv32._210_say = "Gut. Du bist begabter als ich dachte. Dank deiner[ENTER]Hilfe wird mein Gesch\228ft bald besser laufen.[ENTER]Was deine Buchseite betrifft... Vor ein paar[ENTER]Tagen kam ich an einem Pavillon vorbei, neben dem[ENTER]ein Denkmal stand. Ich machte dort Rast und[ENTER]bemerkte dabei ein zerfetztes St\252ck Papier am Fu\223[ENTER]des Denkmals. "
gameforge.main_quest_lv32._220_say = "Ich habe mir in dem Moment nichts weiter dabei[ENTER]gedacht. Aber jetzt glaube ich, dass das eine der[ENTER]alten Seiten gewesen sein k\246nnte, die du suchst.[ENTER]Der Name des Denkmals? Hmm... War es das Weol[ENTER]Denkmal? Ja, so hei\223t es. Das Weol Denkmal in der[ENTER]N\228he des Nachbardorfes. Dort solltest du suchen! "
gameforge.main_quest_lv32._230_sayTitle = "Fahrender H\228ndler: "
gameforge.main_quest_lv32._240_say = "Bring mir 20 Silberschwerter+0. Dann erst gebe[ENTER]ich dir die Information \252ber die alten Seiten. "
gameforge.main_quest_lv32._250_sendLetter = "Suche nach der ersten Seite "
gameforge.main_quest_lv32._260_targetVid = "Ein Denkmal neben dem Pavillon "
gameforge.main_quest_lv32._270_say = "Der Fahrende H\228ndler hat am Fu\223 des Weol Denkmals[ENTER]eine alte Buchseite gesehen, als er im Pavillon[ENTER]neben dem Denkmal Rast machte.[ENTER]Geh zum Weol Denkmal in der N\228he des ersten[ENTER]Dorfes und sieh nach, ob es sich wirklich um die[ENTER]gesuchte Seite handelt. "
gameforge.main_quest_lv32._280_npcChat = "Das Weol Denkmal "
gameforge.main_quest_lv32._290_say = "Das ist das Denkmal. Oh, da ist sie! Ich habe die[ENTER]Seite! "
gameforge.main_quest_lv32._300_sendLetter = "Die erste Seite "
gameforge.main_quest_lv32._30_say = "Der Gelehrte Uriel schickt nach dir. Er braucht[ENTER]Hilfe bei seinen Forschungen \252ber ein altes[ENTER]geheimes Buch. Geh zu Uriel und sieh nach, was du[ENTER]f\252r ihn tun kannst. "
gameforge.main_quest_lv32._310_targetVid = "Suche den Gelehrten Uriel "
gameforge.main_quest_lv32._320_sayTitle = "Die erste Seite gefunden "
gameforge.main_quest_lv32._330_say = "Du bist den Hinweisen des Fahrenden H\228ndlers[ENTER]gefolgt und hast die erste der fehlenden Seiten[ENTER]gefunden. Bringe sie dem Gelehrten Uriel. "
gameforge.main_quest_lv32._340_say = "Hast du die alte Seite gefunden?[ENTER]Oh, du hast sie, sehr gut! Mal sehen, was da[ENTER]geschrieben steht. Hm...[ENTER]Das sieht aus wie ein Tagebuch. H\246r zu! "
gameforge.main_quest_lv32._350_sayTitle = "Erste Buchseite: "
gameforge.main_quest_lv32._360_sayReward = "Lee Seop vom Taejo Reich erweitert sein[ENTER]Territorium durch Eroberungsz\252ge. Er will mit[ENTER]seiner Streitmacht alle L\228nder erobern. Wir[ENTER]m\252ssen ihn aufhalten, bevor er unser Land[ENTER]einnimmt. Ungl\252cklicherweise gibt es nicht viele[ENTER]M\246glichkeiten, denn sein Heer ist zu gro\223 und zu[ENTER]stark.[ENTER]Daher haben wir uns zu einer Verzweiflungstat[ENTER]entschlossen: Wir m\252ssen die verbotene Schwarze[ENTER]Hexerei anwenden. "
gameforge.main_quest_lv32._370_sayTitle = "Fortsetzung der ersten Buchseite: "
gameforge.main_quest_lv32._380_sayReward = "Das ist die einzige M\246glichkeit, zu \252berleben.[ENTER]Wir k\246nnen nicht wissen, ob wir erfolgreich sein[ENTER]werden, aber versuchen m\252ssen wir es. Noch bevor[ENTER]sie uns angreifen, m\252ssen wir Informationen \252ber[ENTER]die Schwarze Hexerei bekommen.[ENTER]Wenn die alten Geschichten stimmen, kann man[ENTER]solche Informationen im Drachental finden. "
gameforge.main_quest_lv32._390_say = "Aus dem Inhalt ersehe ich, dass in dem Land, aus[ENTER]dem dieses Buch stammt, ein alter Glaube[ENTER]geherrscht hat.[ENTER]Bevor Lee Seop vom Taejo Reich alle L\228nder unter[ENTER]sich vereinigte, hatte jedes Land seine ganz[ENTER]speziellen Eigenheiten. Soweit ich wei\223, hatte[ENTER]zum Beispiel jedes Land einen eigenen Glauben.[ENTER]Der Schreiber dieses Buches scheint sehr gebildet[ENTER]gewesen zu sein. Wahrscheinlich geh\246rte er einer[ENTER]der Gilden an oder war sogar ihr Oberhaupt. Die[ENTER]Gildenmitglieder waren damals die oberste Schicht[ENTER]der Gesellschaft. "
gameforge.main_quest_lv32._400_say = "Hier ist von alten Geschichten \252ber das[ENTER]Drachental die Rede. Ich kenne auch einige alte[ENTER]M\228rchen dar\252ber. Vielleicht sind dort auch heute[ENTER]noch Informationen zu finden oder sogar weitere[ENTER]Seiten des Buches. Leider habe ich nie[ENTER]nachgeforscht, wo dieses Tal sich befindet.[ENTER]Geh zum J\228ger Yang-Shin im Nachbardorf, er kennt[ENTER]sich gut aus in der Umgebung. Vielleicht wei\223 er,[ENTER]wo das Drachental ist und ob es dort etwas zu[ENTER]entdecken gibt. "
gameforge.main_quest_lv32._40_say = "Sei gegr\252\223t! Was du mir das letzte Mal gebracht[ENTER]hast, war wirklich sehr hilfreich. Mit deiner[ENTER]Hilfe bin ich mit meinen Forschungen gut voran[ENTER]gekommen. Nun habe ich aber ein Problem.[ENTER]Bei der Untersuchung einiger Informationen \252ber[ENTER]die Meteoriten habe ich ein altes Buch gefunden.[ENTER]Soweit ich das \252berblicken kann, werden darin[ENTER]interessante Vermutungen \252ber die Ursachen der[ENTER]Ver\228nderungen beschrieben, die unser Land[ENTER]heimsuchen. Es ist also von h\246chster Wichtigkeit. "
gameforge.main_quest_lv32._410_say = "Ist das aufregend! Oh, bevor ich es vergesse:[ENTER]Hier hast du deine Belohnung f\252r die erste Seite! "
gameforge.main_quest_lv32._420_sayReward = "Du erh\228ltst 1.000.000 Erfahrungspunkte. "
gameforge.main_quest_lv32._430_sayReward = "Du erh\228ltst 50.000 Yang. "
gameforge.main_quest_lv32._440_sayReward = "Du erh\228ltst eine Tr\228ne der G\246ttin. "
gameforge.main_quest_lv32._450_sendLetter = "Gehe zum J\228ger "
gameforge.main_quest_lv32._460_targetVid = "Suche den J\228ger Yang-Shin auf "
gameforge.main_quest_lv32._470_sayTitle = "Frage Yang-Shin nach dem Drachental "
gameforge.main_quest_lv32._480_say = "Auf der ersten Seite des geheimen Buches ist von[ENTER]einem Drachental die Rede. Uriel kennt[ENTER]Geschichten dar\252ber, wei\223 aber nicht, wo es[ENTER]liegt. Geh ins Nachbardorf und frage den J\228ger[ENTER]Yang-Shin, ob er N\228heres wei\223. "
gameforge.main_quest_lv32._490_sayReward = "Tipp: Der J\228ger befindet sich im Nachbardorf. "
gameforge.main_quest_lv32._500_npcChat = "Informationen \252ber das Drachental "
gameforge.main_quest_lv32._50_say = "Das Problem: Das Buch ist sehr mitgenommen und[ENTER]ziemlich zerrissen. Wahrscheinlich war es lange[ENTER]Zeit von Hand zu Hand unterwegs und ist daher so[ENTER]stark besch\228digt.[ENTER]Es fehlen insgesamt 13 Seiten aus diesem Buch.[ENTER]Kannst du sie mir besorgen? Wahrscheinlich stehen[ENTER]in den Seiten wichtige Informationen, mit denen[ENTER]man den Krieg beenden kann. "
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin: "
gameforge.main_quest_lv32._520_say = "Du m\246chtest wissen, wo das Drachental ist? Das[ENTER]ist eine sehr alte Bezeichnung f\252r das Tal von[ENTER]Seungryong. Heute gibt es dort keine Drachen[ENTER]mehr, daf\252r jede Menge Orks und sogar eine[ENTER]geheime Sekte. Warum m\246chtest du an so einen[ENTER]gef\228hrlichen Ort? Selbst ich, ein geschickter[ENTER]J\228ger, gehe nicht gerne dorthin. Es w\228re besser,[ENTER]du h\228ltst dich fern davon. "
gameforge.main_quest_lv32._530_say = "Wie? Du suchst nach alten Buchseiten? Hm![ENTER]Fr\252her habe ich von den anderen J\228gern geh\246rt,[ENTER]dass die Zauberer der Orks etwas Papier haben.[ENTER]Aber ob das wahr ist? Wenn du so neugierig bist,[ENTER]such selber danach. Ich habe bereits erw\228hnt,[ENTER]dass es dort sehr gef\228hrlich ist. Pass gut auf[ENTER]dich auf! "
gameforge.main_quest_lv32._540_sendLetter = "Suche nach der zweiten Seite "
gameforge.main_quest_lv32._550_say = "Nach dem, was der J\228ger erz\228hlt hat, m\252ssen die[ENTER]Stolzen Ork-Zauberer, die sich im Tal von[ENTER]Seungryong befinden, im Besitz der zweiten alten[ENTER]Seite sein.[ENTER]T\246te die Stolzen Ork-Zauberer und hole dir die[ENTER]zweite Seite. Bringe diese anschlie\223end dem[ENTER]Gelehrten Uriel. "
gameforge.main_quest_lv32._560_sendLetter = "Die zweite Seite "
gameforge.main_quest_lv32._570_sayTitle = "Die zweite Seite gefunden "
gameforge.main_quest_lv32._580_say = "Die Jagd auf die Stolzen Ork-Zauberer war[ENTER]erfolgreich: Du hast die zweite Seite des[ENTER]geheimen Buches gefunden.[ENTER]Bringe sie dem Gelehrten Uriel. "
gameforge.main_quest_lv32._590_say = "Ist das die zweite Seite? Lass mich sehen.[ENTER]Hmm, ist gar nicht so leicht, sie zu entziffern.[ENTER]Hier steht geschrieben: "
gameforge.main_quest_lv32._600_sayTitle = "Zweite Buchseite: "
gameforge.main_quest_lv32._60_say = "Sobald du die alten Seiten findest, bring sie zu[ENTER]mir. Dann werde ich versuchen, sie zu entziffern.[ENTER]Hmm...Wo k\246nnte man zuerst suchen?[ENTER]Vor einiger Zeit habe ich von einem Fahrenden[ENTER]H\228ndler im Nachbardorf geh\246rt, dass er eine[ENTER]alte Buchseite gefunden hat. Geh zu ihm und[ENTER]schau, ob du etwas in Erfahrung bringen kannst. "
gameforge.main_quest_lv32._610_sayReward = "Die Anh\228nger der dunklen Magie sind gefunden. Sie[ENTER]hatten sich im Drachental versteckt. Sie kennen[ENTER]sich in der Schwarzen Hexerei gut aus, die aus[ENTER]fr\252heren Zeiten \252berliefert worden ist.[ENTER]Es brauchte einige \220berredungskunst, Drohungen[ENTER]und Schmeicheleien, bis sie uns weiterhalfen.[ENTER]Das Ergebnis: Man braucht einen speziellen Ort,[ENTER]um die Schwarze Hexerei anzuwenden. Einen Ort[ENTER]voller b\246ser Energie.[ENTER]Die Zeit dr\228ngt. Ich muss so schnell wie m\246glich[ENTER]den angemessen Ort finden. "
gameforge.main_quest_lv32._620_say = "Hm, f\252r die Schwarze Hexerei braucht man also[ENTER]einen Ort, der voll von b\246ser Energie ist. Wo[ENTER]jede Anstrengung, jeder Zauber umgewandelt wird[ENTER]in b\246se Energie. Hmm... Wo k\246nnte das passieren?[ENTER]Hm... Hm... Bestimmt ist es der Hwang-Tempel![ENTER]Der Volksmund nennt ihn nicht ohne Grund Dunkler[ENTER]Tempel. Das ist ein Ort, an den niemand, der[ENTER]guten Herzens ist, gerne geht. Selbst Tiere[ENTER]meiden ihn. Und eine geheime Sekte treibt dort[ENTER]ihr Unwesen. "
gameforge.main_quest_lv32._630_say = "Es gibt bestimmt einen Zusammenhang zwischen der[ENTER]Schwarzen Hexerei und dieser geheimen Sekte. Im[ENTER]Hwang-Tempel ist der Schl\252ssel zu diesem R\228tsel[ENTER]zu finden.[ENTER]Finde heraus, was es mit dem Hwang-Tempel auf[ENTER]sich hat und sieh nach, ob du dort weitere[ENTER]Buchseiten findest![ENTER]Und hier ist nat\252rlich auch deine Belohnung f\252r[ENTER]die zweite Seite. "
gameforge.main_quest_lv32._640_sayReward = "Du erh\228ltst 1.000.000 Erfahrungspunkte. "
gameforge.main_quest_lv32._650_sayReward = "Du erh\228ltst 50.000 Yang. "
gameforge.main_quest_lv32._660_sayReward = "Du erh\228ltst 10 Wei\223e Flaggen. "
gameforge.main_quest_lv32._670_sendLetter = "Die dritte Seite "
gameforge.main_quest_lv32._680_say = "Du hast die ersten beiden Seiten des geheimen[ENTER]Buches zu Uriel gebracht. Die n\228chste Seite ist[ENTER]im Hwang-Tempel zu finden. "
gameforge.main_quest_lv32._690_sayReward = "Tipp: Diese Questreihe wird fortgef\252hrt, sobald[ENTER]du Level 40 erreicht hast. "
gameforge.main_quest_lv32._70_targetVid = "Geh zum Fahrenden H\228ndler "
gameforge.main_quest_lv32._80_sayTitle = "Suche die Seiten des geheimen Buches "
gameforge.main_quest_lv32._90_say = "Der Gelehrte Uriel hat erz\228hlt, dass er von dem[ENTER]Fahrenden H\228ndler etwas \252ber eine alte[ENTER]Buchseite geh\246rt hat.[ENTER]Geh zum Fahrenden H\228ndler und frag ihn nach der[ENTER]alten Buchseite. Den Fahrenden H\228ndler findest[ENTER]du im zweiten Dorf. "
gameforge.main_quest_lv40 = {}
gameforge.main_quest_lv40._100_sayReward = "Du erh\228ltst 2.000.000 Erfahrungspunkte. "
gameforge.main_quest_lv40._10_sayTitle = "Der Dunkle Tempel "
gameforge.main_quest_lv40._110_sayReward = "Du erh\228ltst 50.000 Yang. "
gameforge.main_quest_lv40._120_sayReward = "Du erh\228ltst einen Segen des Lebens. "
gameforge.main_quest_lv40._130_sendLetter = "Auf in die Yongbi-W\252ste "
gameforge.main_quest_lv40._140_targetVid = "Die Suche nach dem Denkmal "
gameforge.main_quest_lv40._150_targetVid = "Die Suche nach dem Wha Denkmal "
gameforge.main_quest_lv40._160_sayTitle = "Suche nach der vierten Seite "
gameforge.main_quest_lv40._170_say = "Der Gelehrte Uriel glaubt, dass man eine weitere[ENTER]Seite im Affendungeon Jungsun Dong in der[ENTER]Yongbi-W\252ste finden kann. Dort gibt es auch zwei[ENTER]Denkm\228ler. Vielleicht ist an einem von ihnen die[ENTER]vierte Seite versteckt.[ENTER]Geh in die Yongbi-W\252ste und suche dort nach den[ENTER]Denkm\228lern im Jungsun Dong. "
gameforge.main_quest_lv40._180_say = "Das ist das Wha Denkmal! "
gameforge.main_quest_lv40._190_say = "Aber keine alte Tagebuchseite zu sehen.[ENTER]Ich muss weiter, das andere Denkmal suchen. "
gameforge.main_quest_lv40._200_npcChat = "Die Suche nach dem Su Denkmal "
gameforge.main_quest_lv40._20_say = "Der Gelehrte Uriel ist auf der Suche nach alten[ENTER]Tagebuchseiten. Zwei davon hast du ihm bereits[ENTER]gebracht. Nun geht die abenteuerliche Jagd um das[ENTER]Geheimnis des alten Buches weiter.[ENTER]Die bisherigen Entdeckungen deuten darauf hin,[ENTER]dass die Stolzen dunklen Fanatiker im[ENTER]Hwang-Tempel die n\228chste alte Seite besitzen.[ENTER]Mach dich auf den Weg! "
gameforge.main_quest_lv40._210_say = "Das muss es sein! Das Su Denkmal. "
gameforge.main_quest_lv40._220_say = "Aber keine alte Tagebuchseite zu sehen.[ENTER]Ich muss weiter, das andere Denkmal suchen. "
gameforge.main_quest_lv40._230_sendLetter = "Die vierte Seite "
gameforge.main_quest_lv40._240_sayTitle = "Die vierte Seite gefunden "
gameforge.main_quest_lv40._250_say = "Die antiken Denkm\228ler erweisen sich als treue[ENTER]Bewahrer ihrer Sch\228tze: Du hast die vierte alte[ENTER]Seite im Jungsun Dong gefunden. Bringe sie zum[ENTER]Gelehrten Uriel. "
gameforge.main_quest_lv40._260_npcChat = "Die vierte alte Seite "
gameforge.main_quest_lv40._270_say = "Oh! Du hast die vierte alte Seite gefunden.[ENTER]Hoffentlich kommen wir weiter mit der[ENTER]Information, die uns das Buch gibt. "
gameforge.main_quest_lv40._280_sayTitle = "Vierte Seite: "
gameforge.main_quest_lv40._290_sayReward = "Ich bin nun in der tiefen H\246hle, wo die Affen[ENTER]wohnen. Alle meine Begleiter zittern vor Angst,[ENTER]aber auch hier reicht die angesammelte b\246se[ENTER]Energie nicht aus.[ENTER]Die Zeit vergeht viel zu schnell und Lee Seops[ENTER]Armee kommt immer n\228her. Ob wir es noch[ENTER]rechtzeitig schaffen? "
gameforge.main_quest_lv40._300_sayTitle = "Fortsetzung der vierten Buchseite: "
gameforge.main_quest_lv40._30_sayTitle = "Die dritte Seite gefunden "
gameforge.main_quest_lv40._310_sayReward = "Ich muss so schnell wie m\246glich den n\228chsten Ort[ENTER]finden, der uns weiterhelfen k\246nnte. Noch ist[ENTER]nichts verloren.[ENTER]Ich werde es in den Spinnenh\246hlen versuchen. M\246ge[ENTER]sich diesmal unser Wunsch erf\252llen... "
gameforge.main_quest_lv40._320_say = "Hm. Der Affendungeon ist also nicht der Ort, den[ENTER]wir suchen. Dann auf ein Neues! Nach dem, was[ENTER]hier geschrieben steht, m\252ssen wir zu den[ENTER]Spinnenh\246hlen gehen.[ENTER]Aber zun\228chst ist eine dringlichere Angelegenheit[ENTER]zu regeln: Der Hauptmann ist in gro\223er Sorge,[ENTER]weil sich zur Zeit viele Fremde in der N\228he des[ENTER]Dorfes herumtreiben und seltsame Fragen stellen.[ENTER]Du solltest zu ihm gehen und nachsehen, was da[ENTER]los ist. "
gameforge.main_quest_lv40._330_say = "Ich habe ein unangenehmes Gef\252hl bei dieser[ENTER]Sache. Mal sehen, was der Hauptmann sagt.[ENTER]Oh, fast h\228tte ich es vergessen: Hier ist deine[ENTER]Belohnung f\252r die vierte Seite. "
gameforge.main_quest_lv40._340_sayReward = "Du erh\228ltst 2.000.000 Erfahrungspunkte. "
gameforge.main_quest_lv40._350_sayReward = "Du erh\228ltst einen Segen der Magie. "
gameforge.main_quest_lv40._360_sendLetter = "Die unheimlichen Fremden "
gameforge.main_quest_lv40._370_targetVid = "Suche den Hauptmann auf "
gameforge.main_quest_lv40._380_sayTitle = "Frage den Hauptmann nach den Fremden "
gameforge.main_quest_lv40._390_say = "Man sagt, dass zur Zeit viele Fremde im Dorf[ENTER]auftauchen. Sie stellen verd\228chtig viele Fragen[ENTER]\252ber die Denkm\228ler. Der Hauptmann will etwas[ENTER]dagegen unternehmen. Geh zu ihm, um mehr zu[ENTER]erfahren. "
gameforge.main_quest_lv40._400_npcChat = "Die Fremden im Dorf "
gameforge.main_quest_lv40._40_say = "Uriels Vermutungen \252ber die Stolzen dunklen[ENTER]Fanatiker waren korrekt. Du hast die dritte[ENTER]Tagebuchseite bei ihnen gefunden. Bringe die[ENTER]Seite dem Gelehrten Uriel. "
gameforge.main_quest_lv40._410_say = "Zur Zeit kommen vermehrt Fremde in unser Dorf.[ENTER]Sie fragen die Bewohner \252ber die Denkm\228ler und[ENTER]alten B\252cher aus. Es gibt einige Leute, die[ENTER]etwas dar\252ber wissen, aber den Fremden nichts[ENTER]verraten wollen. Ich f\252rchte, das bringt uns[ENTER]alle in Gefahr. Wer wei\223, von wem diese Fremden[ENTER]geschickt wurden und wie weit sie gehen w\252rden,[ENTER]um Informationen zu erhalten. Immerhin befinden[ENTER]wir uns im Krieg... "
gameforge.main_quest_lv40._420_say = "Wenn ich richtig informiert bin, steht Nakajima[ENTER]aus dem Nachbardorf irgendwie damit in[ENTER]Zusammenhang. Versuch bitte von ihm[ENTER]herauszufinden, was die Fremden hier wollen. "
gameforge.main_quest_lv40._430_sendLetter = "Geh zu Nakajima "
gameforge.main_quest_lv40._440_say = "Der Hauptmann meint, es g\228be eine Verbindung[ENTER]zwischen Nakajima und den Fremden, die \252berall[ENTER]im Dorf nach den Denkm\228lern fragen.[ENTER]Geh zu Nakajima und finde heraus, was er wei\223.[ENTER]Du findest ihn au\223erhalb des zweiten Dorfes. "
gameforge.main_quest_lv40._450_npcChat = "Was wei\223t du \252ber die Fremden im Dorf? "
gameforge.main_quest_lv40._460_sayTitle = "Nakajima: "
gameforge.main_quest_lv40._470_say = "Wie bitte? Was soll die Frage? Was f\252r[ENTER]verd\228chtige Fremde? Tut mir leid. Ich kann dir[ENTER]nicht helfen. Ich habe nicht die geringste[ENTER]Ahnung, wovon du \252berhaupt redest. Nein, nein.[ENTER]Es ist schwer genug, in diesen Zeiten Arbeit zu[ENTER]finden. Wovon soll ich mich denn ern\228hren, h\228? "
gameforge.main_quest_lv40._480_say = "Na gut, ich geb's ja zu. Aber ich habe nur[ENTER]zugesagt, weil sie mir eine Menge Yang[ENTER]versprochen haben.[ENTER]Was die Fremden hier wollen, das wei\223 ich nicht.[ENTER]Aber sie haben mir einen Auftrag gegeben: Ich[ENTER]soll die Brutalen Hauptm\228nner t\246ten. "
gameforge.main_quest_lv40._490_say = "Von den Brutalen Hauptm\228nnern k\246nntest du sicher[ENTER]mehr erfahren. Die Fremden waren ganz hei\223[ENTER]darauf, dass ich sie t\246te.[ENTER]Oh, ich habe eine Idee: Am besten gehst du und[ENTER]t\246test sie f\252r mich, ja? Bitte? "
gameforge.main_quest_lv40._500_sendLetter = "T\246te die Brutalen Hauptm\228nner "
gameforge.main_quest_lv40._50_say = "Oh, du hast den n\228chsten Hinweis gefunden?![ENTER]Das ist die dritte Seite.[ENTER]Lass sehen, was dort geschrieben steht. "
gameforge.main_quest_lv40._510_say = "Nakajima hat mir verraten, dass die Fremden die[ENTER]Brutalen Hauptm\228nner t\246ten wollen. Da die[ENTER]Fremden nach den Tagebuchseiten gefragt haben,[ENTER]ist zu vermuten, dass die Brutalen Hauptm\228nner[ENTER]eine dieser Seiten bei sich tragen.[ENTER]Um mehr herauszufinden, muss ich Brutale[ENTER]Hauptm\228nner t\246ten. Sie sind au\223erhalb des zweiten[ENTER]Dorfes zu finden. "
gameforge.main_quest_lv40._520_sendLetter = "Die f\252nfte Seite gefunden "
gameforge.main_quest_lv40._530_say = "Ich konnte den Fremden zuvorkommen und habe den[ENTER]Brutalen Hauptm\228nnern die f\252nfte Tagebuchseite[ENTER]abgenommen. Bestimmt verschwinden die Fremden[ENTER]jetzt, denn es gibt hier nichts mehr zu finden.[ENTER]Die Seite bringe ich am Besten zum Gelehrten[ENTER]Uriel, damit er sie entziffern kann. "
gameforge.main_quest_lv40._540_sayTitle = "Die f\252nfte Seite "
gameforge.main_quest_lv40._550_sayReward = "Tipp: Du kannst die f\252nfte Seite des geheimen[ENTER]Buches erst zu Uriel bringen, wenn du Level 47[ENTER]erreicht hast. Bewahre die Seite bis dahin gut[ENTER]auf! "
gameforge.main_quest_lv40._60_sayTitle = "Dritte Buchseite: "
gameforge.main_quest_lv40._70_sayReward = "Wir haben einen Ort gefunden, an dem die Energie[ENTER]des B\246sen regiert. Aber das reicht nicht aus. Der[ENTER]Ort ist b\246se, aber er ist ungeeignet zum[ENTER]Praktizieren von Hexerei. Das ist ein herber[ENTER]R\252ckschlag.[ENTER]Aber unsere Sp\228her sprechen von einem versteckten[ENTER]Ort in der W\252ste, der vielversprechend sein soll.[ENTER]Voller Hoffnung begeben wir uns nun dorthin. "
gameforge.main_quest_lv40._80_say = "Im Drachental konnten sie ihr Ziel also nicht[ENTER]erreichen. Hm...[ENTER]Und jetzt die W\252ste Yongbi? Dort trifft man sehr[ENTER]selten Menschen und das Gebiet ist weitgehend[ENTER]unerforscht. Das ist sehr kompliziert. Wo genau[ENTER]mag dieser Ort sein, von dem hier die Rede ist?[ENTER]Ich vermute, dass der Affendungeon Jungsun Dong[ENTER]gemeint ist. Das ist eine tiefe H\246hle, die gut[ENTER]geeignet ist, um b\246se Energien zu sammeln. "
gameforge.main_quest_lv40._90_say = "Geh bitte zum Jungsun Dong und suche dort nach[ENTER]weiteren Steindenkm\228lern. Mit ein bisschen Gl\252ck[ENTER]sind bei den Denkm\228lern auch weitere Buchseiten[ENTER]zu finden. Oh, und nat\252rlich sollten wir deine[ENTER]Belohnung f\252r die dritte Seite nicht vergessen. "
gameforge.main_quest_lv47 = {}
gameforge.main_quest_lv47._100_sayTitle = "Die Seite im Spinnendungeon "
gameforge.main_quest_lv47._10_sayTitle = "Die Seite der Brutalen Hauptm\228nner "
gameforge.main_quest_lv47._110_say = "Uriel meint, dass im Spinnendungeon weitere[ENTER]Informationen \252ber die Schwarze Hexerei zu[ENTER]finden sein k\246nnten. Vielleicht gibt es dort[ENTER]auch so ein Denkmal wie im Affendungeon.[ENTER]Zum Spinnendungeon kommt man \252ber die[ENTER]Yongbi-W\252ste. "
gameforge.main_quest_lv47._120_npcChat = "Das Mok Denkmal "
gameforge.main_quest_lv47._130_say = "Tats\228chlich! Hier ist ein Denkmal und auch eine[ENTER]Tagebuchseite. Nun schnell zur\252ck zu Uriel. "
gameforge.main_quest_lv47._140_sayTitle = "Die sechste Seite gefunden "
gameforge.main_quest_lv47._150_say = "Du hast im Spinnendungeon ein weiteres altes[ENTER]Denkmal gefunden und auch die dort versteckte[ENTER]sechste Tagebuchseite. Bringe sie zu Uriel dem[ENTER]Gelehrten. "
gameforge.main_quest_lv47._160_npcChat = "Die sechste Seite "
gameforge.main_quest_lv47._170_say = "Wie war der Spinnendungeon? Hast du die sechste[ENTER]Seite gefunden? Das ist ja fantastisch![ENTER]Ich habe mir schon Sorgen gemacht, dass du zu[ENTER]sp\228t kommen k\246nntest. Man h\246rt immer wieder[ENTER]von anderen Leuten, die ebenfalls nach den[ENTER]Geheimnissen der Schwarzen Hexerei suchen. Es[ENTER]scheinen sehr wichtige Informationen zu sein.[ENTER]Schauen wir mal, was uns diese Seite bringt. "
gameforge.main_quest_lv47._180_say = "Oje, diese Seite ist sehr schlecht zu lesen.[ENTER]Daf\252r werde ich wohl l\228nger brauchen. Aber es[ENTER]sieht wichtig aus. Dieses Zeichen hier bedeutet[ENTER]\"Schwarze Hexerei\", wir sind also auf der[ENTER]richtigen Spur.[ENTER]Ich m\246chte zu gerne wissen, warum die Schwarze[ENTER]Hexerei verboten ist. Das hat sicher einen guten[ENTER]Grund... "
gameforge.main_quest_lv47._190_say = "W\228hrend ich diese Seite \252bersetze, kannst du[ENTER]zum Musiker Yu-Hwan gehen. Ich habe geh\246rt, er[ENTER]h\228tte interessante Informationen f\252r unsere[ENTER]Suche. Wenn du wiederkommst, kann ich dir sagen,[ENTER]was hier auf der Seite steht. Deine Belohnung[ENTER]sollst du aber nat\252rlich jetzt schon bekommen. "
gameforge.main_quest_lv47._200_sayReward = "Du erh\228ltst 3.000.000 Erfahrungspunkte. "
gameforge.main_quest_lv47._20_say = "Mit Level 40 hast du den Brutalen Hauptm\228nnern[ENTER]die f\252nfte Seite des geheimen Tagebuchs[ENTER]abgenommen. Du solltest diese nun zu Uriel[ENTER]bringen. "
gameforge.main_quest_lv47._210_sayReward = "Du erh\228ltst 75.000 Yang. "
gameforge.main_quest_lv47._220_sayReward = "Du erh\228ltst einen Segen des Drachen. "
gameforge.main_quest_lv47._230_sendLetter = "Geh zu Yu-Hwan "
gameforge.main_quest_lv47._240_targetVid = "Suche den Musiker Yu-Hwan "
gameforge.main_quest_lv47._250_sayTitle = "Die geheimen Kr\228fte "
gameforge.main_quest_lv47._260_say = "Der Musiker Yu-Hwan hat vielleicht Informationen[ENTER]\252ber die alten Tagebuchseiten. Suche ihn auf und[ENTER]frage ihn danach. "
gameforge.main_quest_lv47._270_npcChat = "Gibt es Neuigkeiten? "
gameforge.main_quest_lv47._280_say = "Genie\223e das Leben, denn es ist verg\228nglich![ENTER]Trallalaaa...[ENTER]Ah, du bist es wieder. Du kommst sicher vom[ENTER]Gelehrten Uriel. Er hat mich vor ein paar Tagen[ENTER]gefragt, ob ich mich etwas umh\246ren kann. Ich[ENTER]habe herausgefunden, dass in allen Reichen Leute[ENTER]unterwegs sind, die wichtige Dokumente suchen.[ENTER]Leider konnte mir niemand sagen, worum es da[ENTER]genau geht. "
gameforge.main_quest_lv47._290_say = "Wenn man bedenkt, dass wir uns im Krieg befinden,[ENTER]kann einem schon seltsam zumute werden bei all[ENTER]diesen herumschleichenden Gestalten. Dich[ENTER]nat\252rlich ausgenommen![ENTER]Au\223erdem habe ich geh\246rt, dass die W\252stenbanditen[ENTER]ein paar Sachan erbeuten konnten, die f\252r uns von[ENTER]gr\246\223ter Wichtigkeit sein k\246nnten. Vielleicht[ENTER]solltest du mal schauen, ob etwas aus ihnen[ENTER]herauspr\252geln kannst.  "
gameforge.main_quest_lv47._300_say = "Die W\252stenbanditen sind nicht ganz ungef\228hrlich,[ENTER]also sei auf der Hut. Aber ich denke, es wird[ENTER]sich lohnen. Ich werde dir ein Lied widmen und es[ENTER]dem Wind anvertrauen, damit er es dir in die[ENTER]W\252ste hinterhertr\228gt. Viel Erfolg! "
gameforge.main_quest_lv47._30_npcChat = "Die f\252nfte Seite "
gameforge.main_quest_lv47._310_sendLetter = "Die W\252stenbanditen "
gameforge.main_quest_lv47._320_sayTitle = "Die Suche nach den geheimen Informationen "
gameforge.main_quest_lv47._330_say = "Uriel braucht jegliche Informationen zur[ENTER]Schwarzen Hexerei. Der Musiker Yu-Hwan sagte,[ENTER]dass die W\252stenbanditen etwas gestohlen h\228tten,[ENTER]das uns weiterhelfen k\246nnte. Ich sollte mich auf[ENTER]den Weg machen und ein paar W\252stenbanditen[ENTER]t\246ten. "
gameforge.main_quest_lv47._340_sendLetter = "Die siebte Seite gefunden "
gameforge.main_quest_lv47._350_targetVid = "Die Suche nach dem Musiker Yu-Hwan "
gameforge.main_quest_lv47._360_say = "Nach den Informationen, die dir der Musiker[ENTER]Yu-Hwan gegeben hatte, konntest du die siebte[ENTER]Seite des geheimen Buchs bei den W\252stenbanditen[ENTER]finden.[ENTER]Geh zu Yu-Hwan und teile ihm mit, dass seine[ENTER]Information richtig war. "
gameforge.main_quest_lv47._370_say = "Deine Augen sind so sch\246n wie ein Bergsee,[ENTER]lalalala... He, da bist du ja wieder. Hast du bei[ENTER]den W\252stenbanditen Erfolg gehabt?[ENTER]Wie, das ist alles? Ein altes St\252ck Papier? Damit[ENTER]kann ich nichts anfangen. Aber wenn es euch[ENTER]gl\252cklich macht...[ENTER]Du solltest es zu Uriel bringen. Und richte meine[ENTER]Gr\252\223e aus! "
gameforge.main_quest_lv47._380_sendLetter = "Geh zu Uriel "
gameforge.main_quest_lv47._390_targetVid = "Geh zu Uriel "
gameforge.main_quest_lv47._400_sayTitle = "Die siebte Seite "
gameforge.main_quest_lv47._40_say = "Du hast die f\252nfte Seite? Unglaublich. Was f\252r[ENTER]ein Gl\252ck, dass diese Seiten \252berhaupt noch[ENTER]existieren, nach all den Jahren. Du bist sehr[ENTER]t\252chtig. Jetzt lass uns nachsehen, was darin[ENTER]geschrieben steht. "
gameforge.main_quest_lv47._410_say = "Du hast die siebte Seite des alten Tagebuchs[ENTER]gefunden. Bringe sie zu Uriel. "
gameforge.main_quest_lv47._420_say = "Hallo, sch\246n dich wiederzusehen! Ich habe eine[ENTER]gute Nachricht: Die Entzifferung der sechsten[ENTER]Seite ist bereits fertig. Nicht schlecht, was?[ENTER]Ich muss zugeben, ich bin ein wenig stolz auf[ENTER]mich. Mir ist n\228mlich aufgefallen, dass die[ENTER]Schriftzeichen... Wie bitte? Du hast schon wieder[ENTER]eine gefunden? Meine G\252te! Das ging wirklich[ENTER]schnell. Zeig her. Oho, woher hast du die denn[ENTER]bekommen? Wenn mich nicht alles t\228uscht, sind[ENTER]das Schriftzeichen, die nur von der kaiserlichen[ENTER]Familie benutzt wurden. "
gameforge.main_quest_lv47._430_say = "Da diese Schriftzeichen nur von sehr wenigen[ENTER]Menschen und auch nur selten benutzt wurden, wird[ENTER]es sehr schwierig werden, sie zu \252bersetzen. Aber[ENTER]der Mensch braucht Herausforderungen, haha! Ich[ENTER]freue mich darauf.[ENTER]Die W\252stenbanditen haben diese Seite von den[ENTER]geheimnisvollen Fremden gestohlen? Hmm... Hei\223t[ENTER]das, dass die Fremden diese Schriftzeichen[ENTER]kennen? Es wird immer verworrener. Wir m\252ssen[ENTER]aufpassen, dass wir nichts \252bersehen. "
gameforge.main_quest_lv47._440_say = "Ach ja, \252bersehen: Bevor ich mich der n\228chsten[ENTER]Seite zuwende, sollte ich dir wohl erstmal[ENTER]mitteilen, was auf der sechsten Seite stand.[ENTER]Hrm-hrm... "
gameforge.main_quest_lv47._450_sayTitle = "Sechste Buchseite: "
gameforge.main_quest_lv47._460_sayReward = "Uns l\228uft die Zeit davon. Nun haben wir die[ENTER]Schwarze Hexerei sogar im Spinnendungeon[ENTER]anzuwenden versucht, ohne Ergebnis. Was fehlt uns[ENTER]zum Erfolg? Einige unserer Mystiker vermuten,[ENTER]dass die Schwarze Hexerei nach h\246heren Opfern[ENTER]verlangt. Wenn dem so ist, muss sie wahrhaft[ENTER]m\228chtig sein. "
gameforge.main_quest_lv47._470_sayReward = "In den M\228rchen und Legenden braucht diese Art von[ENTER]Magie immer Menschenopfer. Aber wenn ich ihre[ENTER]Liebsten auf einem Altar t\246te, wird mein Ansehen[ENTER]bei den Menschen rasch schwinden. Wir brauchen[ENTER]geeigneten Ersatz. Versuchen wir es mit den[ENTER]Schlangenschwertk\228mpfern aus der W\252ste. "
gameforge.main_quest_lv47._480_say = "Soso. Da sie keine Menschen als Opfer benutzen[ENTER]konnten, haben sie sich entschieden,[ENTER]Schlangenk\228mpfer zu nehmen. Ich kann nicht[ENTER]behaupten, dass mir diese neue Entwicklung[ENTER]gef\228llt. Das wird b\246se enden...[ENTER]Dennoch m\252ssen wir ihrer Spur folgen. Du solltest[ENTER]dich in die W\252ste begeben und dort einige[ENTER]Schlangen-Schwertk\228mpfer und[ENTER]Schlangen-Bogensch\252tzen t\246ten. Wer wei\223, was wir[ENTER]dort noch so finden. A propos finden: In dieser[ENTER]B\246rse findest du deine Belohnung! "
gameforge.main_quest_lv47._490_sendLetter = "T\246te die Schlangenk\228mpfer "
gameforge.main_quest_lv47._500_sayTitle = "Die achte Seite "
gameforge.main_quest_lv47._50_sayTitle = "F\252nfte Buchseite: "
gameforge.main_quest_lv47._510_say = "Das Tagebuch beschreibt den Versuch,[ENTER]Schlangenschwertk\228mpfer und[ENTER]Schlangenbogensch\252tzen f\252r das Gelingen der[ENTER]Schwarzen Hexerei zu opfern. Geh in die W\252ste[ENTER]Yongbi und t\246te Schlangenk\228mpfer. Halte dabei[ENTER]nach weiteren Informationen Ausschau. "
gameforge.main_quest_lv47._520_sendLetter = "Die achte Seite gefunden "
gameforge.main_quest_lv47._530_targetVid = "Geh zum Gelehrten Uriel "
gameforge.main_quest_lv47._540_say = "Du hat die achte Seite des geheimen Tagebuchs bei[ENTER]den Schlangenk\228mpfern in der W\252ste gefunden.[ENTER]Bringe sie zum Gelehrten Uriel. "
gameforge.main_quest_lv47._550_say = "Du hast die achte Seite. Sehr gut. Sie ist sehr[ENTER]kurz. Ich denke, ich kann sie direkt vorlesen.[ENTER]Einen Moment bitte... Ah, ja. "
gameforge.main_quest_lv47._560_sayTitle = "Achte Buchseite: "
gameforge.main_quest_lv47._570_sayReward = "Die n\246tigen Opfer sind gefunden. Wir haben[ENTER]Gl\252ck. Ob das ein Zeichen ist? Als N\228chstes[ENTER]brauchen wir ein zeremonielles Gl\246ckchen. Wenn[ENTER]ich mich richtig erinnere, habe ich so etwas bei[ENTER]den Spinnen gesehen. Wir machen uns auf dem Weg. "
gameforge.main_quest_lv47._580_say = "Schon wieder der Spinnendungeon, seltsam. Du[ENTER]musst unbedingt dort hin und nach diesem[ENTER]Gl\246ckchen suchen. Aber es wird eine anstrengende[ENTER]Reise, also ruh dich erst einmal aus und komm[ENTER]sp\228ter wieder. Ich werde noch etwas nachdenken[ENTER]und weitere Fragmente \252bersetzen. Wenn du[ENTER]wiederkommst, gebe ich dir einen neuen Auftrag.[ENTER]Und keine Sorge. Deine Belohnung f\252r die achte[ENTER]Seite bekommst du nat\252rlich jetzt schon. "
gameforge.main_quest_lv47._590_sayReward = "Du erh\228ltst 3.000.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 70.000 Yang.[ENTER]Du erh\228ltst 20 Tapferkeitsumh\228nge.[ENTER]Tipp:[ENTER]F\252r die n\228chste Aufgabe musst du mindestens[ENTER]Level 50 erreicht haben. "
gameforge.main_quest_lv47._60_sayReward = "Lee Seop ist mit seiner Reiterei im Reich Taejo[ENTER]angekommen und scheint vorerst dort verweilen zu[ENTER]wollen. Unterdessen regnen Meteoriten auf das[ENTER]Land nieder. Sie bringen Chaos, Zerst\246rung und[ENTER]Zwietracht. Das gro\223e Reich hat sich in drei[ENTER]kleinere Reiche aufgespalten. Sie bek\228mpfen sich[ENTER]untereinander, statt gemeinsam gegen das \220bel[ENTER]vorzugehen. Der Drachengott spricht nicht mehr zu[ENTER]uns. Seine Unterst\252tzung scheint mal dem einen,[ENTER]mal dem anderen Reich zu gelten. So k\228mpfen alle[ENTER]um seine Gunst und w\228hrenddessen breitet sich das[ENTER]Unheil weiter aus... "
gameforge.main_quest_lv47._70_sayTitle = "Uriel: "
gameforge.main_quest_lv47._80_say = "Ein Augenzeugenbericht aus den Anfangstagen[ENTER]unseres Zeitalters. Absolut unbezahlbar! Ach ja,[ENTER]bezahlen. Hier hast du deine Belohnung f\252r diese[ENTER]hervorragende Arbeit. Und noch etwas: Jemand[ENTER]anderes stellt offensichtlich die gleichen[ENTER]Untersuchungen an, wie wir. Wir haben also keine[ENTER]Zeit zu verlieren. Am Ende dieser Seite hier[ENTER]steht, dass Lee Seop als N\228chstes im[ENTER]Spinnendungeon nach b\246ser Energie gesucht hat.[ENTER]Wenn du dort etwas findest, komm sofort zu mir![ENTER]Ich brenne vor Ungeduld! "
gameforge.main_quest_lv47._90_sendLetter = "Die sechste Seite "
gameforge.main_quest_lv50 = {}
gameforge.main_quest_lv50._100_say = "He, nicht so schnell, junger Hei\223sporn! Vergiss[ENTER]deine Belohnung f\252r die neunte Seite nicht! "
gameforge.main_quest_lv50._10_sayTitle = "T\246te Stolze Soldat-Giftspinnen "
gameforge.main_quest_lv50._110_sayReward = "Du erh\228ltst 5.000.000 Erfahrungspunkte. "
gameforge.main_quest_lv50._120_sayReward = "Du erh\228ltst 125.000 Yang. "
gameforge.main_quest_lv50._130_sayReward = "Du erh\228ltst ein Symbol des weisen Kaisers. "
gameforge.main_quest_lv50._140_sendLetter = "Die Spur im Eisland "
gameforge.main_quest_lv50._150_targetVid = "Die alte Box mit Papieren "
gameforge.main_quest_lv50._160_sayTitle = "Suche die alte Box mit Papieren "
gameforge.main_quest_lv50._170_say = "Auf dem Berg Sohan sind die feindlichen Heere[ENTER]schlie\223lich aufeinandergetroffen. Suche dort nach[ENTER]weiteren Tagebuchseiten oder anderen[ENTER]schriftlichen Hinweisen auf den Verlauf der[ENTER]Schlacht. "
gameforge.main_quest_lv50._180_npcChat = "Eine alte Truhe mit Schriftst\252cken! "
gameforge.main_quest_lv50._190_say = "Das sind milit\228rische Pl\228ne und Aufzeichnungen.[ENTER]Und hier ist auch eine weitere Tagebuchseite![ENTER]Ich sollte sie zu Uriel bringen. "
gameforge.main_quest_lv50._200_sendLetter = "Die zehnte Seite "
gameforge.main_quest_lv50._20_say = "Die bisherigen Untersuchungen deuten auf Spuren[ENTER]im Spinnendungeon hin. Geh und t\246te Stolze[ENTER]Soldat-Giftspinnen im Kuahlo Dong. Wenn du eine[ENTER]weitere Seite des alten Buches findest, bringe[ENTER]sie zum Gelehrten Uriel. "
gameforge.main_quest_lv50._210_sayTitle = "Die zehnte Seite gefunden "
gameforge.main_quest_lv50._220_say = "Du hast die zehnte Seite des geheimen Tagebuchs[ENTER]im Eisland gefunden. Sie war in einer alten Box[ENTER]mit Papieren. Bringe sie zu Uriel. "
gameforge.main_quest_lv50._230_say = "Ah, du hast die zehnte Tagebuchseite gefunden![ENTER]Wir kommen dem Ende der Geschichte immer n\228her.[ENTER]Nur gut, dass damals alles aufgeschrieben wurde,[ENTER]sonst w\228re dieses Wissen jetzt verloren. Schauen[ENTER]wir mal, was uns diese Seite sagt. "
gameforge.main_quest_lv50._235_sayTitle = "Zehnte Buchseite: "
gameforge.main_quest_lv50._240_sayReward = "Es ist uns gelungen, den ersten Angriff[ENTER]abzuwehren. Aber der n\228chste wird bald folgen.[ENTER]Das Terrain behindert Lee Seops schwere[ENTER]Eisensoldaten und verschafft uns Vorteile, aber[ENTER]es sind einfach zu viele. Wir k\246nnen nicht[ENTER]gewinnen. Uns bleibt nur noch eine letzte Chance,[ENTER]unsere Forschungen \252ber die Schwarze Hexerei zu[ENTER]vollenden. Im Schutze der Nacht werden wir die[ENTER]feindlichen Linien durchbrechen und zu den[ENTER]Spinnenh\246hlen zur\252ckkehren. Ich bete. Nicht f\252r[ENTER]den Sieg, aber f\252r ein kleines bisschen[ENTER]Hoffnung... "
gameforge.main_quest_lv50._250_say = "Ooohh. Ich glaube, wir sind kurz vor dem Ziel![ENTER]Bald werden wir herausfinden, was es mit der[ENTER]Schwarzen Hexerei auf sich hat. Ich kann es kaum[ENTER]erwarten! Du musst einmal mehr zum Spinnendungeon[ENTER]zur\252ckgehen. Dort ist hoffentlich die elfte[ENTER]Seite des Buches zu finden. "
gameforge.main_quest_lv50._260_say = "Und hier ist - einmal mehr - deine wohlverdiente[ENTER]Belohnung! "
gameforge.main_quest_lv50._270_sayReward = "Du erh\228ltst 5.500.000 Erfahrungspunkte. "
gameforge.main_quest_lv50._280_sayReward = "Du erh\228ltst 137.500 Yang. "
gameforge.main_quest_lv50._290_sayReward = "Du erh\228ltst einen Handschuh weiser Kaiser. "
gameforge.main_quest_lv50._300_sayTitle = "T\246te Klauengiftspinnen "
gameforge.main_quest_lv50._30_sendLetter = "Die neunte Seite "
gameforge.main_quest_lv50._310_say = "Die Forschungen zur Schwarzen Hexerei wurden in[ENTER]den Spinnenh\246hlen fortgesetzt. Gehe dorthin und[ENTER]t\246te Klauengiftspinnen, um die ben\246tigten[ENTER]Informationen zu bekommen. "
gameforge.main_quest_lv50._320_sendLetter = "Die elfte Seite "
gameforge.main_quest_lv50._330_targetVid = "Gehe zur\252ck zum Gelehrten Uriel "
gameforge.main_quest_lv50._335_sayTitle = "Die elfte Seite gefunden "
gameforge.main_quest_lv50._340_say = "Im Spinnendungeon hast du die elfte Seite des[ENTER]geheimen Tagebuchs gefunden. Bringe sie zu Uriel. "
gameforge.main_quest_lv50._350_say = "Hast du etwas Neues herausgefunden?[ENTER]Oho, die elfte Seite! Lass sehen...[ENTER]Ah ja, das sieht recht einfach aus. Inzwischen[ENTER]bin ich richtig gut darin, diese Schriftzeichen[ENTER]zu lesen. Pass auf! "
gameforge.main_quest_lv50._355_sayTitle = "Elfte Buchseite: "
gameforge.main_quest_lv50._360_sayReward = "Es ist misslungen.[ENTER]Trotz aller Vorbereitung mussten wir schlie\223lich[ENTER]schnell handeln. Zu schnell. Nun sind viele von[ENTER]uns verwundet, andere sind verr\252ckt geworden. Die[ENTER]Schwarze Hexerei ist wahrlich b\246se.[ENTER]Lee Seops Reiterei ist uns dicht auf den Fersen,[ENTER]aber das ist jetzt egal. Wir haben nicht mehr[ENTER]genug Leute, um ihm etwas entgegenzusetzen.[ENTER]Sterben werden wir sowieso. "
gameforge.main_quest_lv50._365_sayTitle = "Fortsetzung der elften Buchseite: "
gameforge.main_quest_lv50._370_sayReward = "Ein letzter Gedanke h\228lt den Rest der Truppe[ENTER]zusammen und verleiht uns Kraft: Die Informanten[ENTER]im Drachental haben gelogen. Sie haben uns[ENTER]absichtlich nicht vor den schrecklichen[ENTER]Nebenwirkungen der Schwarzen Hexerei gewarnt.[ENTER]Daf\252r werden sie bezahlen. Es wird unsere letzte[ENTER]Tat auf dieser Erde sein. "
gameforge.main_quest_lv50._380_say = "Tja, letztendlich ist es wohl anders ausgegangen,[ENTER]als sie gehofft hatten. Eine traurige Geschichte.[ENTER]Man kann keinem Menschen trauen, der sich mit der[ENTER]Schwarzen Hexerei besch\228ftigt. Das h\228tten sie[ENTER]bedenken sollen. Es ist schon seltsam genug, dass[ENTER]der Schreiber dieser Zeilen \252berhaupt[ENTER]Informationen \252ber diese verbotenen[ENTER]Machenschaften erhalten konnte. Wer wei\223, welches[ENTER]Ziel seine Informanten verfolgten.[ENTER]Wir aber sollten diesen Weg zuende gehen, auch[ENTER]wenn es gef\228hrlich ist. Wir wissen schon so viel,[ENTER]es w\228re schade, jetzt[ENTER]aufzugeben.  "
gameforge.main_quest_lv50._390_say = "Im Tal von Seungryong warst du ja bereits. Ich[ENTER]denke nicht, dass wir dort noch etwas finden.[ENTER]Hmm, wo k\246nnten wir noch suchen...[ENTER]Ich wei\223! Die Denkm\228ler haben eine gro\223e Rolle[ENTER]bei unserer Suche gespielt. Und es gibt[ENTER]Denkm\228ler, die wir noch nicht untersucht haben.[ENTER]N\228mlich die in den anderen Reichen! Es ist sehr[ENTER]gef\228hrlich dort. Man wird dich oft angreifen.[ENTER]Also bereite dich gut vor und komm zu mir, wenn[ENTER]du bereit bist. "
gameforge.main_quest_lv50._400_say = "Aber zun\228chst bekommst du nat\252rlich noch deine[ENTER]Belohnung f\252r die elfte Seite. "
gameforge.main_quest_lv50._40_targetVid = "Geh zum Gelehrten Uriel "
gameforge.main_quest_lv50._410_sayReward = "Du erh\228ltst 6.000.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 150.000 Yang.[ENTER]Du erh\228ltst eine Medaille des Drachen.[ENTER]Tipp:[ENTER]F\252r die n\228chste Aufgabe musst du mindestens[ENTER]Level 55 erreicht haben. "
gameforge.main_quest_lv50._50_sayTitle = "Die neunte Seite gefunden "
gameforge.main_quest_lv50._60_say = "Du hast die neunte Seite im Spinnendungeon[ENTER]gefunden. Bringe sie zum Gelehrten Uriel. "
gameforge.main_quest_lv50._70_say = "Du hast eine weitere Spur der Schwarzen Hexerei[ENTER]gefunden? Tats\228chlich, die neunte Seite! Ich bin[ENTER]gespannt, ob der Zauber funktioniert hat. Lass[ENTER]uns schnell nachsehen. Hmm, hier steht... "
gameforge.main_quest_lv50._75_sayTitle = "Neunte Buchseite: "
gameforge.main_quest_lv50._80_sayReward = "Lee Seops Angriff hat begonnen. Ich bin sehr[ENTER]nerv\246s, denn wir wissen immer noch nicht genau,[ENTER]wie wir die Schwarze Hexerei benutzen k\246nnen. Wir[ENTER]sind hier an vorderster Front, um unser Reich zu[ENTER]verteidigen. Doch unsere Mittel reichen nicht[ENTER]aus. Die feindliche Armee ist viel zu stark und[ENTER]wenn nicht bald etwas geschieht, werden wir die[ENTER]Schlacht verlieren. Wir m\252ssen uns an einen Ort[ENTER]zur\252ckziehen, an dem sie ihre Pferde nicht[ENTER]richtig einsetzen k\246nnen: Die Eisw\252ste. Mit etwas[ENTER]Gl\252ck bleibt dann genug Zeit, um weiter zu[ENTER]forschen. Oh, Gott hilf uns... "
gameforge.main_quest_lv50._90_say = "Hmm... Der Angriff begann, noch bevor sie die[ENTER]Schwarze Hexerei ausreichend erforschen konnten.[ENTER]Sie mussten sich in der \"Eisw\252ste\" verschanzen.[ENTER]Damit kann nur der Berg Sohan gemeint sein, den[ENTER]man heute auch Eisland nennt. Wir sollten dort[ENTER]nach weiteren Spuren suchen. Geh zum Berg Sohan[ENTER]und sieh nach, was du herausfinden kannst. "
gameforge.main_quest_lv55 = {}
gameforge.main_quest_lv55._100_say = "Du hast die zw\246lfte Seite im Gebiet Joan[ENTER]gefunden. Bringe sie zu Uriel im Gebiet Yongan. "
gameforge.main_quest_lv55._10_sendLetter = "Die Suche nach den Denkm\228lern "
gameforge.main_quest_lv55._110_say = "Du hast die zw\246lfte Seite im Gebiet Yongan[ENTER]gefunden. Bringe sie zu Uriel im Gebiet Pyungmoo. "
gameforge.main_quest_lv55._120_say = "Ich freue mich, dich gesund und munter[ENTER]wiederzusehen. Es tut mir leid, dich so viel[ENTER]umherschicken zu m\252ssen, aber der Erfolg gibt uns[ENTER]recht, findest du nicht auch?[ENTER]Schauen wir mal, was dort steht. Ich hoffe, die[ENTER]M\252he hat sich gelohnt.  "
gameforge.main_quest_lv55._130_sayTitle = "Zw\246lfte Buchseite: "
gameforge.main_quest_lv55._140_sayReward = "Wir haben die Informanten gefunden und sie haben[ENTER]f\252r unsere Irref\252hrung mit ihrem Leben bezahlt.[ENTER]Doch viel wichtiger ist, dass wir ihnen noch eine[ENTER]letzte Information entrei\223en konnten: Nicht die[ENTER]Spinnenh\246hlen brauchen wir, sondern den Dunklen[ENTER]Tempel. An diesem Ort haben seit Anbeginn der[ENTER]Zeit die Anh\228nger des Alten Glaubens ihre dunklen[ENTER]Rituale vollf\252hrt. "
gameforge.main_quest_lv55._145_sayTitle = "Fortsetzung der zw\246lften Buchseite: "
gameforge.main_quest_lv55._150_sayReward = "Damit bietet sich uns nun eine weitere Chance,[ENTER]Lee Seop aufzuhalten.[ENTER]Wir m\252ssen zum Dunklen Tempel reisen, um doch[ENTER]noch die Schwarze Hexerei ausf\252hren zu k\246nnen.[ENTER]Es sind nur noch wenige von uns \252brig und die[ENTER]Strapazen der letzten Monate wiegen schwer. Doch[ENTER]selbst eine m\252de Handvoll M\228nner kann das[ENTER]Schicksal der Welt \228ndern, wenn sie solch[ENTER]m\228chtige Informationen besitzt.[ENTER]Wir haben unser Ziel vor Augen. Es geht los. "
gameforge.main_quest_lv55._160_say = "Dann haben sie den richtigen Ort also doch noch[ENTER]gefunden. Und ich hatte von Anfang an recht! Es[ENTER]ist tats\228chlich der Hwang-Tempel. Du erinnerst[ENTER]dich sicher an diesen dunklen Ort, der vor b\246ser[ENTER]Energie schon fast brummt. Seit jeher finden dort[ENTER]Rituale und Zeremonien statt, von denen brave[ENTER]B\252rger lieber nichts wissen sollten. "
gameforge.main_quest_lv55._170_say = "Heute bewohnen nur noch Monster den Tempel,[ENTER]Menschen gibt es dort schon lange nicht mehr.[ENTER]Zwar ist es sehr gef\228hrlich, aber ich bin sicher,[ENTER]dass du es schaffen kannst. Geh ins Tal von[ENTER]Seungryong und suche im Hwang-Tempel nach der[ENTER]letzten Seite. Die Geschichte, die dieses[ENTER]Tagebuch erz\228hlt, hat sich dort vollendet. Ich[ENTER]muss wissen, wie sie ausgeht. Alles Gute![ENTER]Ach, warte kurz, hier ist noch deine Belohnung[ENTER]f\252r die zw\246lfte Seite. "
gameforge.main_quest_lv55._180_sayReward = "Du erh\228ltst 6.500.000 Erfahrungspunkte. "
gameforge.main_quest_lv55._190_sayReward = "Du erh\228ltst 162.500 Yang. "
gameforge.main_quest_lv55._200_sendLetter = "Die letzte Seite "
gameforge.main_quest_lv55._20_say = "Da ihr bereits mehrere Tagebuchseiten in der[ENTER]N\228he von Denkm\228lern gefunden habt, geht Uriel[ENTER]davon aus, dass sich weitere Informationen \252ber[ENTER]die geheime Schwarze Hexerei in der N\228he von[ENTER]noch nicht untersuchten Denkm\228lern finden[ENTER]lassen. Begib dich in das Reich Chunjo und[ENTER]untersuche dort das Denkmal im Gebiet Joan. "
gameforge.main_quest_lv55._210_sayTitle = "T\246te Buhm\228nner im Tempel "
gameforge.main_quest_lv55._220_say = "Du hast bisher zw\246lf der dreizehn verloren[ENTER]gegangenen Tagebuchseiten gefunden. Nun stehst du[ENTER]vor dem letzten Schritt.[ENTER]Uriel sagt, im Hwang-Tempel sei die Schwarze[ENTER]Hexerei letztendlich ausgef\252hrt worden. Deshalb[ENTER]solltest du dich dorthin auf den Weg machen und[ENTER]nach Informationen suchen. Beginne deine Suche[ENTER]mit dem T\246ten von Buhm\228nnern im Tempel. "
gameforge.main_quest_lv55._230_say = "Ich muss tiefer in den Tempel! "
gameforge.main_quest_lv55._240_sendLetter = "Der Dunkle Tempel "
gameforge.main_quest_lv55._250_sayTitle = "Die b\246se Energie des Tempels "
gameforge.main_quest_lv55._260_sayReward = "Nachdem du dich eine Weile im Tempel aufgehalten[ENTER]hast, entwickelst du ein Gesp\252r f\252r die[ENTER]Eigenheiten dieses finsteren Ortes:[ENTER]Tr\228ge Schatten flackern in jedem Winkel.[ENTER]B\246se Energie sickert wie \214l aus allen Fugen und[ENTER]Ritzen.[ENTER]Es ist offensichtlich, dass der Tempel selbst die[ENTER]Ursache daf\252r ist.[ENTER]Hier hat alles begonnen... "
gameforge.main_quest_lv55._270_say = "Dir wird klar, dass die Boshaftigkeit, die hier[ENTER]\252berall in der Luft liegt, st\228rker wird, je[ENTER]weiter du in das Innere des Tempels vordringst.[ENTER]Du solltest versuchen, die Mitte des Tempels zu[ENTER]finden. Dort muss die Dunkelheit ihren Ursprung[ENTER]haben. "
gameforge.main_quest_lv55._280_npcChat = "Das Gum-Denkmal "
gameforge.main_quest_lv55._290_say = "Im Herzen des Tempels steht unscheinbar das Gum[ENTER]Denkmal. Du n\228herst dich vorsichtig und findest[ENTER]tats\228chlich die letzte Tagebuchseite. "
gameforge.main_quest_lv55._300_say = "Du hast die letzte Seite des geheimen Tagebuchs[ENTER]im Dunklen Tempel gefunden. Geh zu Uriel und[ENTER]berichte ihm von deinem Fund. "
gameforge.main_quest_lv55._30_say = "Da ihr bereits mehrere Tagebuchseiten in der[ENTER]N\228he von Denkm\228lern gefunden habt, geht Uriel[ENTER]davon aus, dass sich weitere Informationen \252ber[ENTER]die geheime Schwarze Hexerei in der N\228he von[ENTER]noch nicht untersuchten Denkm\228lern finden[ENTER]lassen. Begib dich in das Reich Jinno und[ENTER]untersuche dort das Denkmal im Gebiet Pyungmoo. "
gameforge.main_quest_lv55._310_say = "Da ist sie endlich, die dreizehnte, die letzte[ENTER]Seite! Ich kann dir gar nicht sagen, wie dankbar[ENTER]ich bin, dass du das f\252r mich getan hast.[ENTER]Sieh nur, wie meine H\228nde zittern. Ich wage[ENTER]kaum, die Seite zu lesen, so aufgeregt bin ich.[ENTER]Puh...[ENTER]Na gut, dann wollen wir mal sehen, wie die[ENTER]Geschichte ausging. "
gameforge.main_quest_lv55._320_sayTitle = "Dreizehnte Buchseite: "
gameforge.main_quest_lv55._330_sayReward = "Wir sind endlich angekommen.[ENTER]Nach all den Strapazen folgt nun die gro\223e[ENTER]Aufgabe: Wir m\252ssen die Zeremonie abhalten und[ENTER]den alten Zauber der Schwarzen Hexerei[ENTER]aktivieren. Ich hoffe nur, wir sind stark genug.[ENTER]Viele von uns schwanken bereits im Stehen, weil[ENTER]sie so ersch\246pft sind von der langen Reise und[ENTER]der stetigen Flucht vor Lee Seops Kriegern.[ENTER]Dennoch m\252ssen wir es versuchen, oder unser Reich[ENTER]wird untergehen. "
gameforge.main_quest_lv55._335_sayTitle = "Fortsetzung der dreizehnten Buchseite: "
gameforge.main_quest_lv55._340_sayReward = "Sieben Leute sind wir. Wir haben unsere besten[ENTER]Kleider angelegt, auch wenn selbst diese[ENTER]inzwischen wie Lumpen aussehen.[ENTER]Wir werden uns im Kreis aufstellen und uns an den[ENTER]H\228nden fassen, so dass die Kraftlinien[ENTER]geschlossen sind. Dann werden wir den steten[ENTER]Singsang der magischen Worte beginnen und hoffen,[ENTER]dass die Schwarze Hexerei keine weiteren Opfer[ENTER]von uns verlangt.[ENTER]\133 "
gameforge.main_quest_lv55._350_sayReward = "... Es ist vorbei ...[ENTER]Der Anfang war vielversprechend. Der Raum f\252llte[ENTER]sich mit Energie und Gesang, aber pl\246tzlich[ENTER]\252berkam mich ein seltsames Gef\252hl. Meine sechs[ENTER]Mitstreiter gingen in die Knie. Der Tempel begann[ENTER]zu beben. Dann gab es einen Lichblitz und wir[ENTER]wurden r\252ckw\228rts geschleudert. Die Kraftlinien[ENTER]brachen...[ENTER]Nun ist es still. Meine Kameraden liegen tot am[ENTER]Boden. Der Zauber ist misslungen.[ENTER]Wir haben versagt. "
gameforge.main_quest_lv55._360_say = "Was? Das ist alles?!?[ENTER]Da soll mich doch der Schlag treffen! Die ganze[ENTER]M\252he umsonst? Wir sind gereist, haben gek\228mpft,[ENTER]haben stundenlang \252bersetzt und nachgedacht. F\252r[ENTER]nichts! Wir sind genauso schlau wie vorher.[ENTER]Na jedenfalls scheint es besser zu sein, wenn wir[ENTER]die Finger von der Schwarzen Hexerei lassen. Habe[ENTER]ich ja von Anfang an vermutet. Aber wissen ist[ENTER]besser als glauben, nicht wahr? "
gameforge.main_quest_lv55._370_say = "Wir machen jetzt erstmal Pause. Ich habe schon[ENTER]Kopfschmerzen und du bist sicher auch recht[ENTER]mitgenommen. Ich muss mir das alles noch einmal[ENTER]durch den Kopf gehen lassen. Wenn ich damit[ENTER]fertig bin, reden wir weiter.[ENTER]Trotz allem hast du mir einen unglaublich[ENTER]wertvollen Dienst erwiesen. Das soll nicht ohne[ENTER]Belohnung bleiben! "
gameforge.main_quest_lv55._380_sayReward = "Du erh\228ltst 7.000.000 Erfahrungspunkte. "
gameforge.main_quest_lv55._390_sayReward = "Du erh\228ltst 175.000 Yang. "
gameforge.main_quest_lv55._400_sayReward = "Du erh\228ltst ein Buch des Anf\252hrers. "
gameforge.main_quest_lv55._40_say = "Da ihr bereits mehrere Tagebuchseiten in der[ENTER]N\228he von Denkm\228lern gefunden habt, geht Uriel[ENTER]davon aus, dass sich weitere Informationen \252ber[ENTER]die geheime Schwarze Hexerei in der N\228he von[ENTER]noch nicht untersuchten Denkm\228lern finden[ENTER]lassen. Begib dich in das Reich Shinsoo und[ENTER]untersuche dort das Denkmal im Gebiet Yongan. "
gameforge.main_quest_lv55._50_npcChat = "Das ist es! "
gameforge.main_quest_lv55._60_say = "Das ist das Denkmal, das Uriel gesucht hat. Eine[ENTER]zusammengefaltete Tagebuchseite liegt auch[ENTER]darunter! Ich sollte sie schnell zu Uriel[ENTER]bringen. "
gameforge.main_quest_lv55._70_sendLetter = "Die zw\246lfte Seite gefunden "
gameforge.main_quest_lv55._80_targetVid = "Geh zur\252ck zu Uriel "
gameforge.main_quest_lv55._90_say = "Du hast die zw\246lfte Seite im Gebiet Pyungmoo[ENTER]gefunden. Bringe sie zu Uriel im Gebiet Joan. "
gameforge.main_quest_lv6 = {}
gameforge.main_quest_lv6._100_sayReward = "Gehe zum Schmied. Er ben\246tigt deine Hilfe. "
gameforge.main_quest_lv6._10_targetVid = "Gehe zum Stadtw\228chter "
gameforge.main_quest_lv6._110_say = "Wer bist du und was willst du hier?[ENTER]Ich bin sehr besch\228ftigt, also st\246re mich nicht.[ENTER]Oh, der Stadtw\228chter schickt dich? Ich dachte[ENTER]schon, es w\252rde nie jemand kommen. Es ist keine[ENTER]schwierige Aufgabe und sie wird nicht lange[ENTER]dauern. Genau das Richtige f\252r einen jungen[ENTER]Abenteurer wie dich. "
gameforge.main_quest_lv6._120_say = "Heute sollte ich eine Lieferung des[ENTER]Lagerverwalters erhalten - ich ben\246tige dringend[ENTER]eine Schweinenase. Bisher warte ich jedoch[ENTER]vergeblich. Kannst du mir helfen und die[ENTER]Schweinenase beschaffen? Es ist wirklich wichtig. "
gameforge.main_quest_lv6._130_targetVid = "Finde den Lagerverwalter "
gameforge.main_quest_lv6._140_sendLetter = "Geh zum Lagerverwalter "
gameforge.main_quest_lv6._150_sayReward = "Der Schmied wartet auf eine dringende Lieferung[ENTER]vom Lagerverwalter. Geh zum Lagerverwalter und[ENTER]frage ihn nach der Schweinenase f\252r den Schmied. "
gameforge.main_quest_lv6._160_sayTitle = "Lagerverwalter: "
gameforge.main_quest_lv6._170_say = "Willkommen. Ich bin der Lagerverwalter dieses[ENTER]Dorfes. Du kannst meine Dienste in Anspruch[ENTER]nehmen, wenn du nicht dein gesamtes Hab und Gut[ENTER]mit dir herumtragen m\246chtest. In meinem[ENTER]Lagerhaus kannst du einen Teil davon aufbewahren. "
gameforge.main_quest_lv6._180_say = "M\246chtest du etwas aufbew... Ah, der Schmied[ENTER]schickt dich wegen der Schweinenase! "
gameforge.main_quest_lv6._190_say = "Ich f\252rchte, ich werde alt und vergesslich.[ENTER]Fr\252her ist mir so etwas nicht passiert. Hier hast[ENTER]du die Schweinenase. Bringe sie bitte gleich dem[ENTER]Schmied. Wir sehen uns sp\228ter. "
gameforge.main_quest_lv6._200_sendLetter = "Zur\252ck zum Schmied "
gameforge.main_quest_lv6._20_sayReward = "Der Stadtw\228chter hat eine neue Aufgabe f\252r dich.[ENTER]Gehe zu ihm und erkundige dich, worum es geht. "
gameforge.main_quest_lv6._210_sayReward = "Der Lagerverwalter hatte die Lieferung v\246llig[ENTER]vergessen. Nun hat er die Schweinenase dir[ENTER]\252berreicht. Bringe sie schnell zum Schmied, damit[ENTER]er nicht noch l\228nger warten muss. "
gameforge.main_quest_lv6._220_say = "Du bist schneller wieder zur\252ck als ich dachte![ENTER]Diese Schnelligkeit solltest du beibehalten, kann[ENTER]dir in Zukunft sehr n\252tzlich sein. Und jetzt h\246r[ENTER]gut zu, ich habe eine wichtige Information f\252r[ENTER]dich. "
gameforge.main_quest_lv6._230_say = "Bist du mit der Veredelung vertraut?[ENTER]Nat\252rlich nicht, du bist ein noch junger[ENTER]Abenteurer! Es geht um Folgendes:[ENTER]Wenn du mir ein St\252ck deiner Ausr\252stung[ENTER]\252berl\228sst, kann ich es f\252r nur wenige Yang so[ENTER]bearbeiten, dass seine Eigenschaften verbessert[ENTER]werden. "
gameforge.main_quest_lv6._240_say = "Die Kunst der Veredelung kann auf[ENTER]unterschiedliche Weisen erfolgen - je h\246her das[ENTER]angestrebte Ziel, desto schwieriger die[ENTER]Durchf\252hrung. Eine Verbesserung +3 oder darunter[ENTER]ben\246tigt lediglich einige Yang, f\252r alles[ENTER]Weitere ist ein zus\228tzlicher Gegenstand[ENTER]notwendig. So wie die Schweinenase, die du mir[ENTER]gebracht hast. Allerdings kann es stets[ENTER]vorkommen, dass der Gegenstand, den man zu[ENTER]veredeln w\252nscht, zerst\246rt wird - selbst wenn[ENTER]man in diesen Dingen ge\252bt ist, so wie ich.[ENTER]Komm vorbei, wenn es deine Zeit erlaubt. Ich kann[ENTER]dir wunderbare Waffen schmieden! "
gameforge.main_quest_lv6._250_sayReward = "Du erh\228ltst %s Erfahrungspunkte. "
gameforge.main_quest_lv6._260_sayReward = "Du erh\228ltst %s Yang. "
gameforge.main_quest_lv6._270_sayReward = "Du erh\228ltst ein Wolfsfell+. "
gameforge.main_quest_lv6._30_say = "Du da vorn! Es ist nicht die Zeit, um in der[ENTER]Gegend herumzustehen und sich dem Nichtstun[ENTER]hinzugeben. Du musst hart trainieren! Das ist der[ENTER]einzige Weg, um sich in diesen Zeiten der Unruhe[ENTER]eine Chance auf \220berleben zu sichern! "
gameforge.main_quest_lv6._40_say = "Aber wenn du schon mal da bist, habe ich einen[ENTER]Auftrag f\252r dich: Der Schmied war vorhin hier und[ENTER]erz\228hlte irgendwas von Schweinen und[ENTER]Lieferproblemen. Vielleicht braucht er Hilfe. Geh[ENTER]zu ihm und sag, dass ich dich geschickt habe.[ENTER]Los! "
gameforge.main_quest_lv6._50_sayReward = "Wenn du diese Aufgabe f\252r den Schmied erledigst,[ENTER]erh\228ltst du als Belohnung "
gameforge.main_quest_lv6._60_sayReward = "Erfahrungspunkte: %s "
gameforge.main_quest_lv6._70_sayReward = "Yang: %s  "
gameforge.main_quest_lv6._80_targetVid = "Finde den Schmied "
gameforge.main_quest_lv6._90_sendLetter = "Der Auftrag des Schmieds "
gameforge.main_quest_lv60 = {}
gameforge.main_quest_lv60._100_say = "Berg Sohan? Dort habe ich wirklich einmal einen[ENTER]alten Grabstein gesehen! "
gameforge.main_quest_lv60._10_sendLetter = "Eine neue Spur "
gameforge.main_quest_lv60._110_say = "Du erinnerst dich nicht zuf\228llig an eine[ENTER]Inschrift?![ENTER]Offenbar nicht. Dieser Grabstein kann uns[ENTER]wichtige Informationen \252ber die Dunkle Nation[ENTER]verraten. K\246nntest du bitte zum Berg Sohan reisen[ENTER]und eine Kopie der Inschrift f\252r mich anfertigen? "
gameforge.main_quest_lv60._120_say = "Laut Uriels Nachforschungen geh\246rten die sieben[ENTER]Drachenpriesterinnen der Dunklen Nation an.[ENTER]Untersuche den alten Grabstein auf dem Berg[ENTER]Sohan. Dort soll sich vor ewigen Zeiten die[ENTER]Hauptstadt der Dunklen Nation befunden haben. "
gameforge.main_quest_lv60._130_say = "Du erinnerst dich nicht zuf\228llig an eine[ENTER]Inschrift?![ENTER]Offenbar nicht. Dieser Grabstein kann uns[ENTER]wichtige Informationen \252ber die Dunkle Nation[ENTER]verraten. K\246nntest du bitte zum Berg Sohan reisen[ENTER]und eine Kopie der Inschrift f\252r mich anfertigen? "
gameforge.main_quest_lv60._140_sayReward = "Du hast den alten Grabstein aus den Zeiten der[ENTER]Dunklen Nation gefunden und eine Kopie der[ENTER]Inschrift angefertigt. Bring sie zu Uriel. "
gameforge.main_quest_lv60._150_say = "Laut Uriels Nachforschungen geh\246rten die sieben[ENTER]Drachenpriesterinnen der Dunklen Nation an.[ENTER]Untersuche den alten Grabstein auf dem Berg[ENTER]Sohan. Dort soll sich vor ewigen Zeiten die[ENTER]Hauptstadt der Dunklen Nation befunden haben. "
gameforge.main_quest_lv60._160_say = "Endlich! Lass mich die Inschrift analysieren. Sie[ENTER]beinhaltet Folgendes: Die Dunkle Nation hatte[ENTER]sich der Schwarzen Hexerei verschrieben und[ENTER]diente Sung Mahi, dem Gott der D\228monen. "
gameforge.main_quest_lv60._170_say = "Um Himmels willen ... Sung Mahi! Dann haben die[ENTER]sieben Drachenpriesterinnen etwa versucht,[ENTER]mithilfe der verbotenen Hexerei Sung Mahi zu[ENTER]beschw\246ren? "
gameforge.main_quest_lv60._180_say = "Du hast gute Arbeit geleistet. Daf\252r sollst du[ENTER]nat\252rlich auch eine Belohnung erhalten. "
gameforge.main_quest_lv60._190_sayReward = "Du erh\228ltst %d Erfahrungspunkte. "
gameforge.main_quest_lv60._200_sayReward = "Du erh\228ltst %d Yang. "
gameforge.main_quest_lv60._20_say = "Uriel hat Neuigkeiten \252ber die Geschichte aus dem[ENTER]alten Tagebuch herausgefunden. Suche Uriel auf[ENTER]und erfahre mehr dar\252ber. "
gameforge.main_quest_lv60._210_sayReward = "Du erh\228ltst %s. "
gameforge.main_quest_lv60._220_sendLetter = "Dunkle Nation II "
gameforge.main_quest_lv60._230_say = "Laut Uriel geh\246rte der Geisterwald fr\252her zum[ENTER]Reich der Dunklen Nation. Vielleicht lassen sich[ENTER]dort weitere Hinweise entdecken.[ENTER]Dieser Wald steckt voller Gefahren. Die[ENTER]Metinsteine machen alle Kreaturen rasend.[ENTER]Finde den B\246sen Baum, um weitere Anhaltspunkte zu[ENTER]erhalten. Sprich Uriel darauf an. "
gameforge.main_quest_lv60._240_say = "Um die Dunkle Nation ranken sich unz\228hlige[ENTER]Geheimnisse. Dank dir konnten wir einige l\252ften,[ENTER]aber uns fehlen noch immer notwendige[ENTER]Informationen. Bitte begib dich auf die Suche[ENTER]nach einem alten Dokument. Es soll sich im[ENTER]Geisterwald nahe des Bergs Sohan befinden. "
gameforge.main_quest_lv60._250_counter = "Verbleibende Seiten: "
gameforge.main_quest_lv60._260_say = "Um die Dunkle Nation ranken sich unz\228hlige[ENTER]Geheimnisse. Dank dir konnten wir einige l\252ften,[ENTER]aber uns fehlen noch immer notwendige[ENTER]Informationen. Bitte begib dich auf die Suche[ENTER]nach einem alten Dokument. Es soll sich im[ENTER]Geisterwald nahe des Bergs Sohan befinden. "
gameforge.main_quest_lv60._270_sayReward = "Du hast den B\246sen Baum besiegt und das Dokument[ENTER]an dich genommen. Es ist in einer[ENTER]fremden Sprache verfasst. Lass es von Uriel[ENTER]\252bersetzen. "
gameforge.main_quest_lv60._280_say = "Endlich! Du hast das alte Dokument gefunden. Es[ENTER]wird hoffentlich Licht ins Dunkel bringen! "
gameforge.main_quest_lv60._290_say = "Aber was ...?! Da steht ja kaum etwas drin! Das[ENTER]Dokument besteht eigentlich aus zehn Seiten.[ENTER]Bitte geh zur\252ck in den Geisterwald und finde[ENTER]die \252brigen neun Seiten. "
gameforge.main_quest_lv60._300_say = "Du musst noch %d Seiten finden. "
gameforge.main_quest_lv60._30_say = "Wie geht es dir? Erinnerst du dich noch an das[ENTER]Tagebuch und die Geschichte, die mit der[ENTER]dreizehnten und letzten Seite abrupt endete? "
gameforge.main_quest_lv60._310_say = "So, nun wollen wir doch mal sehen ...[ENTER]Anscheinend belegte die Dunkle Nation die[ENTER]Hohepriesterin des Drachenkults mit[ENTER]einem Fluch und missbrauchte die heiligen Kr\228fte[ENTER]der sieben Frauen, um die uralte Kunst der[ENTER]Schwarzen Hexerei auszu\252ben. "
gameforge.main_quest_lv60._320_say = "Um Sung Mahi zu beschw\246ren, muss die Schwarze[ENTER]Hexerei zur selben Zeit an sieben verschiedenen[ENTER]Orten durchgef\252hrt werden.[ENTER]Doch Lee Seop und seine Armee haben das Ritual[ENTER]rechtzeitig gest\246rt und den unheilvollen Plan der[ENTER]Dunklen Nation vereitelt. "
gameforge.main_quest_lv60._330_say = "Diese Nation war in der Tat furchteinfl\246\223end. Sie[ENTER]war imstande, durch schwarze Magie das[ENTER]menschliche Bewusstsein zu kontrollieren! "
gameforge.main_quest_lv60._340_sendLetter = "Der Hinweis "
gameforge.main_quest_lv60._350_say = "Uriel hat in den alten Schriften Hinweise \252ber[ENTER]das Gum-Denkmal entdeckt. Geh zu ihm, um mehr zu[ENTER]erfahren. "
gameforge.main_quest_lv60._360_say = "Fassen wir mal zusammen, was wir bis jetzt[ENTER]herausgefunden haben:[ENTER]Einst existierte ein Volk, das sich die Dunkle[ENTER]Nation nannte und dem D\228monengott Sung Mahi[ENTER]diente. Um ihn zu beschw\246ren, verf\252hrte es die[ENTER]sieben Drachenpriesterinnen und missbrauchte die[ENTER]heiligen Kr\228fte von ihnen f\252r die verbotene[ENTER]Kunst der Schwarzen Hexerei. Diese musste[ENTER]unbedingt an sieben Orten gleichzeitig ausgef\252hrt[ENTER]werden. "
gameforge.main_quest_lv60._370_say = "Die Drachenpriesterinnen haben die Schwarze[ENTER]Hexerei aber nur in einem Turm ausgef\252hrt[ENTER]und nicht an sieben verschiedenen Orten ...[ENTER]Deswegen ist die Beschw\246rung Sung Mahis[ENTER]fehlgeschlagen! "
gameforge.main_quest_lv60._380_say = "Die Dunkle Nation muss den sieben[ENTER]Drachenpriesterinnen die falschen Informationen[ENTER]gegeben haben. "
gameforge.main_quest_lv60._390_say = "Vielleicht wussten sie es auch nicht besser ...[ENTER]Es mag ein Zufall sein, aber die alten Schriften[ENTER]erw\228hnen diesen Turm im Zusammenhang mit dem[ENTER]Gum-Denkmal. Es scheint sich hierbei um den[ENTER]D\228monenturm am Hwang-Tempel zu handeln. "
gameforge.main_quest_lv60._400_say = "Wir haben endlich die entscheidende Spur der[ENTER]sieben Drachenpriesterinnen gefunden![ENTER]Ruhe dich kurz aus und lass uns dann dar\252ber[ENTER]sprechen, was wir als N\228chstes unternehmen[ENTER]werden. Denn ich f\252rchte, dir steht eine Reise[ENTER]zum D\228monenturm bevor ... "
gameforge.main_quest_lv60._40_say = "Ja, nat\252rlich. Sieben Personen sind vor Lee Seop[ENTER]und seiner Kavallerie in den Hwang-Tempel[ENTER]geflohen und haben dort in letzter Verzweiflung[ENTER]die verbotene Schwarze Hexerei vollzogen ... Am[ENTER]Ende hat das nur eine von ihnen \252berlebt. "
gameforge.main_quest_lv60._410_sayReward = "Der n\228chste Teil dieses Abenteuers erwartet dich,[ENTER]sobald du Level 66 erreicht hast. "
gameforge.main_quest_lv60._50_say = "Richtig. Ich habe weitere Nachforschungen[ENTER]betrieben und herausgefunden, dass diese sieben[ENTER]Personen Mitglieder des heiligen Kults der[ENTER]Drachenpriesterinnen waren. In alten Schriften[ENTER]werden sie in den Zusammenhang mit einem[ENTER]theokratischen Volk, genannt die Dunkle Nation,[ENTER]gebracht.[ENTER]Ob die sieben Drachenpriesterinnen wohl dieser[ENTER]mysteri\246sen Nation angeh\246rten? Hier, lies dir[ENTER]diese Schriftrolle gut durch und sprich mich[ENTER]anschlie\223end noch einmal an. "
gameforge.main_quest_lv60._60_sendLetter = "Dunkle Nation I "
gameforge.main_quest_lv60._70_say = "Laut Uriels Nachforschungen stammen die sieben[ENTER]Drachenpriesterinnen aus der Dunklen Nation.[ENTER]Untersuche den alten Grabstein auf dem Berg[ENTER]Sohan. Dort soll sich auch die Hauptstadt der[ENTER]Dunklen Nation befunden haben. Sprich vorher noch[ENTER]einmal mit Uriel. "
gameforge.main_quest_lv60._80_say = "Ihre unglaublich hochentwickelte Hexenkunst und[ENTER]die Tatsache, dass sie laut Tagebuch von Lee[ENTER]Seop vernichtet wurden, deuten darauf hin, dass[ENTER]die sieben Drachenpriesterinnen tats\228chlich der[ENTER]Dunklen Nation angeh\246rten. "
gameforge.main_quest_lv60._90_say = "In den alten Schriften gibt es eine Karte. Bei[ENTER]genauerer Betrachtung stellt man fest, dass die[ENTER]Hauptstadt der Dunklen Nation sich tats\228chlich[ENTER]auf dem Berg Sohan befunden haben muss. "
gameforge.main_quest_lv66 = {}
gameforge.main_quest_lv66._100_say = "Unfassbar! Verstehst du, was das bedeutet? Im[ENTER]D\228monenturm gab es urspr\252nglich gar keine D\228monen[ENTER]und Geister. Es ist das Verm\228chtnis der[ENTER]Drachenpriesterin. Mit einem verzweifelten[ENTER]letzten Versuch, die Kavallerie Lee Seops[ENTER]zu vernichten, \246ffnete sie den D\228monen durch[ENTER]dieses verfluchte dunkle Ritual das Tor zu[ENTER]unserer Welt. Am Ende bezahlte sie daf\252r mit[ENTER]ihrem Leben. "
gameforge.main_quest_lv66._10_sendLetter = "Das Tagebuch "
gameforge.main_quest_lv66._110_say = "Auf diesem Weg ist also der Sensenmann und sein[ENTER]d\228monisches Gefolge in unsere Welt gekommen.[ENTER]Dennoch scheiterte die gro\223e Mission der Dunklen[ENTER]Nation und der Drachenpriesterinnen: Die[ENTER]Beschw\246rung Sung Mahis schlug fehl, Lee Seop[ENTER]hingegen gewann an Macht und schuf letztendlich[ENTER]ein vereintes Weltreich.[ENTER]Dank deiner Hilfe konnte ich endlich das gr\246\223te[ENTER]Mysterium meines Lebens l\246sen! "
gameforge.main_quest_lv66._120_say = "Als Belohnung m\246chte ich dir eine[ENTER]Segensschriftrolle geben. Bitte nimm mein[ENTER]Geschenk an, ich bestehe darauf! "
gameforge.main_quest_lv66._130_sendLetter = "Du hast Post. "
gameforge.main_quest_lv66._140_say = "Der W\228chter des Dorfplatzes hat einen Brief f\252r[ENTER]dich. Lies ihn und finde heraus, wer der[ENTER]geheimnisvolle Absender ist. "
gameforge.main_quest_lv66._150_say = "Du hast dich in letzter Zeit ziemlich rar[ENTER]gemacht, was? Ich soll dir diesen Brief hier[ENTER]geben - keine Ahnung, von wem der ist, er hat[ENTER]sich mir nicht vorgestellt. "
gameforge.main_quest_lv66._160_say = "Das Papier, auf dem der Brief verfasst wurde,[ENTER]scheint sehr alt zu sein. In hastigen Worten[ENTER]steht darauf geschrieben:[ENTER]Habe wichtige Informationen zu den sieben[ENTER]Drachenpriesterinnen und Sung Mahi. Warte auf der[ENTER]R\252ckseite des D\228monenturms im Hwang-Tempel auf[ENTER]dich. Du findest mich im Schatten des Baumes.[ENTER]Beeil dich, die Zeit dr\228ngt! "
gameforge.main_quest_lv66._170_sendLetter = "Anonymer Brief "
gameforge.main_quest_lv66._180 = "Gehe zum Hwang-Tempel und triff dort auf der[ENTER]R\252ckseite des D\228monenturms den geheimnisvollen[ENTER]Briefschreiber. "
gameforge.main_quest_lv66._190_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._200_say = "Ich hei\223e dich willkommen! Wenn ich mich zuerst[ENTER]einmal vorstellen darf: Mein Name ist Lee Chung.[ENTER]Es ist sehr mutig von dir, den Anweisungen eines[ENTER]Unbekannten zu folgen. Ich habe mich nicht in dir[ENTER]get\228uscht - und du wirst es auch nicht bereuen.[ENTER]H\246r, was ich zu sagen habe! "
gameforge.main_quest_lv66._20_say = "Uriel hat Neuigkeiten \252ber die letzte \220berlebende[ENTER]der Drachenpriesterinnen. Ihr Tagebuch muss sich[ENTER]im D\228monenturm befinden. Geh zu Uriel, um mehr[ENTER]dar\252ber zu erfahren. "
gameforge.main_quest_lv66._210_sendLetter = "Neues \220bel "
gameforge.main_quest_lv66._220_say = "H\246re dir an, was Lee Chung zu berichten hat. "
gameforge.main_quest_lv66._230_say = "Es gibt einen Grund, warum du zum Hwang-Tempel[ENTER]kommen solltest: In letzter Zeit ereignen sich[ENTER]hier seltsame Dinge. Und vor Kurzem haben wir auf[ENTER]der R\252ckseite des D\228monenturms den Zugang zu[ENTER]einer riesigen H\246hle entdeckt! "
gameforge.main_quest_lv66._240_say = "Eine riesige H\246hle? Und was befindet sich darin? "
gameforge.main_quest_lv66._250_say = "In dieser H\246hle erwartet uns ein weiteres,[ENTER]unvorstellbares \220bel: Unsere Sp\228her haben von[ENTER]einem grauenhaften Wesen berichtet, das selbst[ENTER]D\228monen in den Schatten stellt.[ENTER]Seine erschreckende Erscheinung und die[ENTER]unstillbare Gier nach Leben lassen uns vermuten,[ENTER]dass es sich hierbei um den legend\228ren Agwi[ENTER]handelt - einer der zehn gro\223en Teufel der[ENTER]D\228monenwelt.[ENTER]Wenn wir Recht behalten, droht der Menschheit[ENTER]gro\223e Gefahr. "
gameforge.main_quest_lv66._260_say = "Furchteinfl\246\223ender als D\228monen ... Dieses Wesen[ENTER]muss wahrhaft m\228chtig und b\246sartig sein. "
gameforge.main_quest_lv66._270_say = "So ist es. Meine M\228nner und ich haben mehrfach[ENTER]versucht, die Devil's Catacomb zu st\252rmen. Doch[ENTER]wir haben jedes Mal versagt und gro\223e Verluste[ENTER]davon getragen.[ENTER]In dieser Angelegenheit ben\246tigen wir die[ENTER]Unterst\252tzung eines herausragenden K\228mpfers -[ENTER]deswegen haben wir dich hierher gerufen. Wirst du[ENTER]uns helfen? "
gameforge.main_quest_lv66._280_say = "Ja, ich werde dir helfen. "
gameforge.main_quest_lv66._290_say = "Oh, das gibt uns neue Hoffnung![ENTER]Nun, da ich wei\223, dass du auf unserer Seite[ENTER]stehst, werde ich dir die ganze Wahrheit[ENTER]verraten: Ich, Lee Chung, bin Kommandant der[ENTER]Schattenkrieger. Wir sind eine geheime[ENTER]Elite-Einheit der Armee Lee Seops. "
gameforge.main_quest_lv66._300_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._30_say = "Ah, sch\246n, dich gesund und wohlbehalten[ENTER]wiederzusehen. Bist du bereit f\252r ein neues[ENTER]Abenteuer? Uns fehlen noch immer wichtige[ENTER]Informationen zur Dunklen Nation[ENTER]und den sieben Drachenpriesterinnen. Die letzte[ENTER]Drachenpriesterin muss ihr Tagebuch im[ENTER]D\228monenturm verborgen haben, bevor sie die[ENTER]Schwarze Hexerei ausf\252hrte. Ziehe los und bringe[ENTER]mir das Tagebuch. Der D\228monenk\246nig k\246nnte es in[ENTER]seinen F\228ngen haben. "
gameforge.main_quest_lv66._310_say = "Die Schattenkrieger verfolgen seit je her im[ENTER]Geheimen das Ziel, die Wiederauferstehung Sung[ENTER]Mahis zu verhindern. Das ist unsere Mission.[ENTER]Lass uns nun gemeinsam versuchen, den Agwi wieder[ENTER]zur\252ck in seine H\246lle zu bef\246rdern, und[ENTER]herausfinden, wie er in unsere Welt gelangen[ENTER]konnte! "
gameforge.main_quest_lv66._320_sendLetter = "Keine Zeit "
gameforge.main_quest_lv66._330_say = "Lee Chung, der Kommandant der Schattenkrieger,[ENTER]sucht nach dir. Es ist sehr dringend! "
gameforge.main_quest_lv66._340_say = "Ich habe eine dringende Bitte. Siehst du dort[ENTER]dr\252ben den verletzten Soldaten?[ENTER]Das ist einer meiner Sp\228her, der in meinem[ENTER]Auftrag die Devil's Catacomb erkundet hat. Dabei[ENTER]wurde er vom Agwi angegriffen und vergiftet.[ENTER]Das Gift breitet sich bereits in seinem K\246rper[ENTER]aus und ihm bleibt nicht mehr viel Zeit. "
gameforge.main_quest_lv66._350_say = "Er braucht ein Gegengift - und zwar so schnell[ENTER]wie m\246glich![ENTER]K\246nntest du es holen? Du findest es im Roten[ENTER]Wald bei den Roten Dryaden.[ENTER]Er ist einer meiner wichtigsten K\228mpfer - rette[ENTER]sein Leben und ich werde dir %s geben. "
gameforge.main_quest_lv66._360_say = "Ich werde das Gegengift holen! "
gameforge.main_quest_lv66._370_say = "Ich danke dir! Noch ist er am Leben, aber er wird[ENTER]von Minute zu Minute schw\228cher. Wir haben[ENTER]keine Zeit zu verlieren! "
gameforge.main_quest_lv66._380_notice = "Dir bleiben noch %d Minuten. "
gameforge.main_quest_lv66._390_sendLetter = "Das Gegengift "
gameforge.main_quest_lv66._400_say = "Von Lee Chung wei\223t du, dass du das Gegengift[ENTER]im Roten Wald findest. Fange daf\252r %d Rote[ENTER]Dryaden.[ENTER]Im Roten Wald drohen noch gr\246\223ere Gefahren[ENTER]als im Geisterwald, also sieh dich vor. "
gameforge.main_quest_lv66._40_say = "Du hast den D\228monenk\246nig besiegt und das Tagebuch[ENTER]der Drachenpriesterin erhalten. Bringe es zum[ENTER]Gelehrten Uriel. Er wird es durchsehen. "
gameforge.main_quest_lv66._410_say = "Die Zeit ist abgelaufen. Der Soldat liegt im[ENTER]Sterben, also bringe ihm schnellstm\246glich das[ENTER]Gegengift. "
gameforge.main_quest_lv66._420_say = "Dir bleiben noch %d Minuten. "
gameforge.main_quest_lv66._430_say = "Du hast endlich das Gegengift gefunden! Bringe[ENTER]es schnell zu Lee Chung. "
gameforge.main_quest_lv66._440_say = "Hierher, schnell! Ich glaube, du bist gerade noch[ENTER]rechtzeitig gekommen. Mir f\228llt ein Stein vom[ENTER]Herzen. Meine M\228nner und ich sind dir unendlich[ENTER]dankbar. "
gameforge.main_quest_lv66._450_say = "Dank deiner Hilfe hat mein Soldat \252berlebt. Hier[ENTER]ist deine Belohnung f\252r seine Rettung. "
gameforge.main_quest_lv66._460_say = "Du hast sehr lange gebraucht. Er klammert sich[ENTER]nur noch mit letzter Kraft an sein Leben.[ENTER]Zum Gl\252ck bist du gerade noch rechtzeitig[ENTER]gekommen. "
gameforge.main_quest_lv66._470_say = "Er scheint durchzukommen. Doch es war sehr[ENTER]knapp und er w\228re fast gestorben, weil du so[ENTER]lange gebraucht hast, um das Gegengift zu[ENTER]finden.[ENTER]Es tut mir leid, aber das hier ist alles, was ich[ENTER]dir als Belohnung geben kann. "
gameforge.main_quest_lv66._480_sendLetter = "Der Bericht "
gameforge.main_quest_lv66._490_say = "Der Sp\228her ist wieder bei Bewusstsein.[ENTER]H\246r dir an, was er in der Devil's Catacomb[ENTER]beobachtet hat. "
gameforge.main_quest_lv66._500_say = "Danke, dass du mich gerettet hast. Ich habe[ENTER]Unglaubliches in der Devil's Catacomb[ENTER]beobachten k\246nnen. Aber dann wurde ich[ENTER]entdeckt und ... "
gameforge.main_quest_lv66._50_say = "Du hast es gefunden! Das Tagebuch der letzten[ENTER]Drachenpriesterin. Meine H\228nde sind ganz zittrig[ENTER]vor Aufregung.[ENTER]Ich werde etwas Zeit ben\246tigen, um ihre[ENTER]Aufzeichnungen durchzusehen. Ruhe dich inzwischen[ENTER]aus. Ich werde dich zu mir rufen, wenn ich dir[ENTER]mehr sagen kann. "
gameforge.main_quest_lv66._510_say = "Was hast du gesehen? "
gameforge.main_quest_lv66._520_say = "Da waren Leute in schwarzen Umh\228ngen mit[ENTER]Kapuzen, tief ins Gesicht gezogen.[ENTER]Ihren Gespr\228chsfetzen konnte ich entnehmen, dass[ENTER]es sich bei dieser Gruppe um die Diener der[ENTER]Dunkelheit handelt. Doch das ist noch nicht[ENTER]alles:[ENTER]Ein gr\228sslicher Geist, der einer Frauengestalt[ENTER]glich, schwebte \252ber ihren K\246pfen. Die Diener[ENTER]der Dunkelheit nannten sie Banshee. "
gameforge.main_quest_lv66._530_say = "Das klingt nicht gut. Was haben die Diener der[ENTER]Dunkelheit und diese Banshee vor? "
gameforge.main_quest_lv66._540_say = "Die Banshee beschwor durch einen schwarzen[ENTER]Zauber die Agwi, teuflische Wesen,[ENTER]die direkt aus dem H\246llenschlund kommen. Den[ENTER]K\246nig der Agwi rief sie Azrael. "
gameforge.main_quest_lv66._550_say = "Ich eilte sofort los, um Lee Chung davon zu[ENTER]berichten. Doch ich stolperte und wurde entdeckt.[ENTER]Ah, da f\228llt mir ein, dass Kommandant Lee[ENTER]Chung dir noch etwas Wichtiges mitteilen[ENTER]m\246chte. Gehe am besten gleich zu ihm. "
gameforge.main_quest_lv66._560_sendLetter = "Dunkle Bedrohung "
gameforge.main_quest_lv66._570_say = "Geh zu Lee Chung. Sprich mit ihm \252ber die neue[ENTER]Bedrohung, die in der Devil's Catacomb lauert. "
gameforge.main_quest_lv66._580_say = "Was mein Sp\228her berichtet hat, ist[ENTER]erschreckend. Die Diener der[ENTER]Dunkelheit, eine Art Sekte, sind verantwortlich[ENTER]f\252r das Erscheinen der Agwi. Und sie haben den[ENTER]Geist der letzten Drachenpriesterin erweckt.[ENTER]Als Banshee, eine Manifestation des B\246sen,[ENTER]kehrte sie in diese Welt zur\252ck und mithilfe[ENTER]ihrer magischen Kr\228fte soll nun der D\228monengott[ENTER]Sung Mahi beschworen werden. "
gameforge.main_quest_lv66._590_say = "Was? Diese Banshee ist der Geist der letzten[ENTER]Drachenpriesterin? "
gameforge.main_quest_lv66._600_say = "Zweifellos. Selbst unter ihren Schwestern des[ENTER]Drachenkults besa\223 sie als Einzige die Macht, die[ENTER]heiligen vier W\228chter des Himmels anzurufen und[ENTER]die Schwarze Hexerei durchzuf\252hren.[ENTER]Nun wissen wir, wer hinter der neuen Bedrohung[ENTER]steckt: Die Diener der Dunkelheit und die Banshee[ENTER]planen, das grauenvolle Werk der Dunklen Nation[ENTER]zu vollenden und Sung Mahi zu erwecken! "
gameforge.main_quest_lv66._60_sendLetter = "Des R\228tsels L\246sung "
gameforge.main_quest_lv66._610_say = "Wir haben dir viel zu verdanken: Du hast einen[ENTER]meiner besten M\228nner vor dem sicheren Tod bewahrt[ENTER]und nur so konnten wir alles \252ber das pl\246tzliche[ENTER]Erscheinen der Agwi und die neue Bedrohung in der[ENTER]Devil's Catacomb erfahren.[ENTER]Nun ruhe dich erst einmal aus - und dann denken[ENTER]wir \252ber eine geeignete Taktik nach. "
gameforge.main_quest_lv66._620_say = "Das Abenteuer geht weiter, sobald du Level 72[ENTER]erreicht hast. "
gameforge.main_quest_lv66._70_say = "Uriel sucht nach dir. Er hat das Tagebuch nun[ENTER]gelesen. "
gameforge.main_quest_lv66._80_say = "Ah, sehr sch\246n! Da bist du ja.[ENTER]Die Aufzeichnungen der letzten Drachenpriesterin[ENTER]sind in der Tat erstaunlich. H\246r gut zu: "
gameforge.main_quest_lv66._90_say = "Mein Schicksal ist besiegelt! Ich habe mich im[ENTER]obersten Stock dieses Turms verbarrikadiert und[ENTER]die M\228nner Lee Seops stehen kurz davor, die T\252r[ENTER]zu meinem letzten Gef\228ngnis zu durchbrechen. Es[ENTER]gibt keinen Ausweg... Ich habe verloren.[ENTER]Nein, so darf es nicht enden! Es kann nicht alles[ENTER]vergebens gewesen sein. Ich muss die Schwarze[ENTER]Hexerei, diese uralte Kraft des B\246sen, alleine[ENTER]beschw\246ren und die dunklen M\228chte[ENTER]herbeirufen.[ENTER]Das wird meinen sicheren Tod bedeuten. Doch meine[ENTER]Feinde werde ich mit mir ins Verderben rei\223en -[ENTER]und wenn es das Letzte ist, was ich tue! "
gameforge.main_quest_lv7 = {}
gameforge.main_quest_lv7._100_say = "Du hast sie noch nicht abgeliefert? Die Angelrute[ENTER]ist f\252r den Fischer unten am Fluss. Beeile dich,[ENTER]er ben\246tigt sie dringend! "
gameforge.main_quest_lv7._10_targetVid = "Ein weiterer Gefallen "
gameforge.main_quest_lv7._110_npcChat = "Der Schmied sendet diese neue Angelrute! "
gameforge.main_quest_lv7._120_say = "Ich danke dir. Nun kann ich endlich meine zwar[ENTER]treue, aber schon recht abgenutzte alte Angel[ENTER]ausmustern.[ENTER]Mit dem Angeln verdiene ich nicht nur meinen[ENTER]Lebensunterhalt, sondern es ist f\252r mich auch[ENTER]eine der gr\246\223ten Freuden des Tages![ENTER]Bist du mit der Angelkunst vertraut? "
gameforge.main_quest_lv7._130_say = "Nimm zuerst die Angel in die Hand, dann verwende[ENTER]einen K\246der, indem du ihn anklickst. Wirf die[ENTER]Angel dadurch aus, dass du die Fertigkeit Fischen[ENTER]benutzt. Wenn du denkst, dass ein Fisch[ENTER]angebissen haben k\246nnte, nutze die Fertigkeit[ENTER]erneut. Falls du dich geirrt hast, versuche es[ENTER]einfach noch einmal. Diese Gew\228sser sind aufgrund[ENTER]ihrer Artenvielfalt sehr gut zu befischen. Zudem[ENTER]ist Fisch nicht nur nahrhaft und gesund, sondern[ENTER]kann auch wertvolle Sch\228tze mit sich bringen.[ENTER]Versuch es ruhig einmal. "
gameforge.main_quest_lv7._140_say = "Ach ja, hier ist der Beleg f\252r den Erhalt der[ENTER]Angel. Bitte \252berreiche sie dem Schmied, wenn du[ENTER]in die Stadt zur\252ckkehrst. "
gameforge.main_quest_lv7._150_sayItem = "Lieferschein f\252r die Angelrute "
gameforge.main_quest_lv7._160_sayReward = "Du hast dem Fischer die Angelrute \252berbracht.[ENTER]Kehre nun mit dem Beleg zum Schmied zur\252ck[ENTER]und nimm deine Belohnung entgegen. "
gameforge.main_quest_lv7._170_say = "Hast du den Fischer gefunden?[ENTER]Wunderbar. Du hast mir mit diesem Botengang viel[ENTER]Zeit gespart. Als Dank gebe ich dir einige Yang[ENTER]als Belohnung. "
gameforge.main_quest_lv7._180_sendLetter = "Wertschein "
gameforge.main_quest_lv7._190_sayReward = "Mit diesem Schreiben bekommst du vom Schmied[ENTER]ein St\252ck deiner Ausr\252stung kostenlos veredelt.[ENTER]Ziehe dazu einfach das entsprechende St\252ck auf[ENTER]den Schmied, um das Veredelungsfenster zu[ENTER]\246ffnen. "
gameforge.main_quest_lv7._200_sayItem = "Wertschein f\252r das kostenlose Veredeln eines[ENTER]Gegenstands "
gameforge.main_quest_lv7._20_sayReward = "Begib dich bitte zum Schmied. Er sucht jemanden,[ENTER]der einen Botengang f\252r ihn erledigen kann. "
gameforge.main_quest_lv7._210_sayTitle = "Hinweis: "
gameforge.main_quest_lv7._220_sayReward = "1) Der Wertschein wird nicht im Inventar[ENTER]angezeigt.[ENTER]2) Der Erfolg der Veredelung ist - wie bei jeder[ENTER]Veredelung - nicht 100-prozentig garantiert. "
gameforge.main_quest_lv7._230_sayTitle = "Der Wertschein wurde bereits benutzt. "
gameforge.main_quest_lv7._240_sayReward = "Du hast den Wertschein f\252r kostenloses Veredeln[ENTER]bereits genutzt. Er ist nur f\252r eine Veredelung[ENTER]g\252ltig. "
gameforge.main_quest_lv7._30_say = "Sei gegr\252\223t, Abenteurer! K\246nntest du mir noch[ENTER]einmal einen Gefallen erweisen? Normalerweise[ENTER]bitte ich andere Leute nicht oft um solche, aber[ENTER]du scheinst mir vertrauensw\252rdig zu sein.[ENTER]Betrachte es als Ehre! "
gameforge.main_quest_lv7._40_say = "Ich habe eine Angelrute f\252r den Fischer[ENTER]gefertigt. Leider habe ich am heutigen Tag zu[ENTER]viele Anfragen zu bearbeiten und kann sie ihm[ENTER]daher nicht pers\246nlich bringen. Kannst du das f\252r[ENTER]mich erledigen? "
gameforge.main_quest_lv7._50_sayItem = "Eine \228u\223erst biegsame Angelrute "
gameforge.main_quest_lv7._60_say = "Der Fischer muss irgendwo am Fluss sein.[ENTER]Wenn du ihm die Angel bringst, werde[ENTER]ich ein Teil deiner Ausr\252stung veredeln.[ENTER]Das klingt doch nach einem fairen Gesch\228ft,[ENTER]oder? "
gameforge.main_quest_lv7._70_sendLetter = "Finde den Fischer "
gameforge.main_quest_lv7._80_sayReward = "Der Schmied hat dem Fischer eine Angelrute[ENTER]gefertigt. Finde den Fischer am Fluss und bringe[ENTER]sie ihm. "
gameforge.main_quest_lv7._90_npcChat = "F\252r wen ist die Angelrute? "
gameforge.main_quest_lv72 = {}
gameforge.main_quest_lv72._100_say = "Durch die magische Verbindung von Geweihtem[ENTER]Baumharz, Blauer Kristallessenz und Rotem[ENTER]H\246llenquarz erh\228lt die Tr\228ne des Himmels ihre[ENTER]vollkommene Brillanz.[ENTER]Die Blaue Kristallessenz muss vom Herrscher des[ENTER]Eislandes besorgt werden. "
gameforge.main_quest_lv72._10_sendLetter = "Verwitterte Steintafel "
gameforge.main_quest_lv72._110_say = "Du hast dir eine Notiz von dieser bemerkenswerten[ENTER]Inschrift gemacht.[ENTER]Erstatte Lee Chung sofort Bericht \252ber[ENTER]das, was du soeben gelesen hast. "
gameforge.main_quest_lv72._120_say = "Du bist wohlbehalten zur\252ckgekehrt! Wenn ich[ENTER]deinen Gesichtsausdruck richtig deute, hattest du[ENTER]Erfolg. "
gameforge.main_quest_lv72._130_say = "Ja, allerdings! Durch die Inschrift auf der[ENTER]verwitterten Steintafel habe ich herausgefunden,[ENTER]dass man die Heiligen M\228chte durch einen[ENTER]magischen Edelstein, genannt die Tr\228ne des[ENTER]Himmels, beschw\246ren kann. "
gameforge.main_quest_lv72._140_say = "Die Tr\228ne des Himmels ... Es gibt sie also[ENTER]wirklich. Hast du Hinweise finden k\246nnen, wie man[ENTER]sie erhalten kann? "
gameforge.main_quest_lv72._150_say = "Um die Tr\228ne des Himmels herzustellen, ben\246tigt[ENTER]man Geweihtes Baumharz, Blaue Kristallessenz und[ENTER]Roten H\246llenquarz. Blaue Kristallessenz, so stand[ENTER]es geschrieben, erh\228lt man vom Herrscher des[ENTER]Eislandes. "
gameforge.main_quest_lv72._160_say = "Der Herrscher des Eislandes? Hmm ... Damit wird[ENTER]Berg Sohan gemeint sein.[ENTER]Ich werde deine Notizen sofort den Magiern[ENTER]der Schattenkrieger zeigen und diese mit ihnen[ENTER]gemeinsam auswerten.[ENTER]Ich gebe dir Bescheid, sobald ich mehr wei\223! "
gameforge.main_quest_lv72._170_say = "Nimm dies als Belohnung f\252r deine Taten. Ich[ENTER]z\228hle auch weiterhin auf deine Hilfe! "
gameforge.main_quest_lv72._180_sendLetter = "Eisiger Schatz "
gameforge.main_quest_lv72._190_say = "Kommandant Lee Chung hat dir mitgeteilt,[ENTER]dass es sich beim ersten Element f\252r die[ENTER]Tr\228ne des Himmels, der Blauen Kristallessenz,[ENTER]um den legend\228ren Schatz des Neunschwanzes[ENTER]auf dem Berg Sohan handelt.[ENTER]Er wird mit Argusaugen von Eisgolems, Yetis und[ENTER]Frostigen Eism\228nnern bewacht. Jage diese Monster,[ENTER]um in den Besitz der Blauen Kristallessenz zu[ENTER]gelangen.[ENTER]Sprich noch einmal mit Lee Chung, bevor du[ENTER]dich in den Kampf st\252rzt. "
gameforge.main_quest_lv72._200_say = "Die Magier der Schattenkrieger haben[ENTER]herausgefunden, dass der gef\252rchtete Neunschwanz[ENTER]vom Berg Sohan die Blaue Essenz h\252tet wie seinen[ENTER]Augapfel. "
gameforge.main_quest_lv72._20_say = "Lee Chung, der Kommandant der Schattenkrieger,[ENTER]m\246chte mit dir sprechen. Er hat herausgefunden,[ENTER]wie man die Agwi in der Devil's Catacomb[ENTER]besiegen kann. "
gameforge.main_quest_lv72._210_say = "Der Schatz des Neunschwanzes wird von Eisgolems,[ENTER]Yetis und Frostigen Eism\228nnern bewacht.[ENTER]50 Blaue Kristallessenzen werden zur Herstellung[ENTER]der Tr\228ne des Himmels ben\246tigt. "
gameforge.main_quest_lv72._220_say = "Roter H\246llenquarz wird entweder im[ENTER]Hwang-Tempel oder im Feuerland vermutet.[ENTER]Ich habe einen Sp\228her ausgesandt, um[ENTER]Genaueres herauszufinden. "
gameforge.main_quest_lv72._230 = "Kommandant Lee Chung hat dir mitgeteilt,[ENTER]dass es sich beim ersten Element f\252r die[ENTER]Tr\228ne des Himmels, der Blauen Kristallessenz,[ENTER]um den legend\228ren Schatz des Neunschwanzes[ENTER]auf dem Berg Sohan handelt.[ENTER]Er wird mit Argusaugen von Eisgolems, Yetis und[ENTER]Frostigen Eism\228nnern bewacht. Jage diese Monster,[ENTER]um in den Besitz der Blauen Kristallessenz zu[ENTER]gelangen. "
gameforge.main_quest_lv72._240_notice = "Du durchsuchst den Kadaver des besiegten Monsters[ENTER]und findest einen blau schimmernden Edelstein.[ENTER]Das muss die Blaue Kristallessenz sein. "
gameforge.main_quest_lv72._250_notice = "Du musst noch %d Blaue Kristallessenz(en) suchen. "
gameforge.main_quest_lv72._260_say = "F\252r heute hast du gen\252gend Ratschl\228ge erhalten.[ENTER]Komm morgen wieder. "
gameforge.main_quest_lv72._270_say = "Diese Kristalle sind nutzlos. Hier, sieh selbst:[ENTER]Sie haben Risse. Um sie verwenden zu k\246nnen,[ENTER]m\252ssen sie makellos sein. Suche weiter! "
gameforge.main_quest_lv72._280_say = "Diese sind von hervorragender Qualit\228t.[ENTER]Weiter so! Bringe mir noch %d St\252ck. "
gameforge.main_quest_lv72._290_say = "Du hast alle Blauen Kristallessenzen gesammelt.[ENTER]Ich kann die Macht des Neunschwanzes, die darin[ENTER]steckt, sp\252ren. Unglaublich ... Sie vibrieren[ENTER]f\246rmlich vor Energie. Gut gemacht! "
gameforge.main_quest_lv72._300_say = "Das Abenteuer geht weiter, sobald du Level 78[ENTER]erreicht hast. "
gameforge.main_quest_lv72._30_say = "Anders als gew\246hnliche D\228monen kann man die Agwi[ENTER]nicht so einfach t\246ten. Wir Schattenkrieger haben[ENTER]bereits alles Erdenkliche versucht - doch stets[ENTER]ohne Erfolg. "
gameforge.main_quest_lv72._40_say = "Doch nun habe ich herausgefunden, dass die[ENTER]Drachenpriesterinnen die F\228higkeit besa\223en,[ENTER]die Heiligen M\228chte zu beschw\246ren, um b\246se[ENTER]Geister zu vertreiben. "
gameforge.main_quest_lv72._50_say = "Im Roten Wald befand sich einst der geweihte[ENTER]Tempel der Drachenpriesterinnen. Suche dort nach[ENTER]Ruinen und alten Zeugnissen ihres Kults. Sp\228her[ENTER]haben von einer verwitterten Steintafel[ENTER]berichtet, die vom Unterholz \252berwuchert wurde[ENTER]... Vielleicht finden wir darauf weitere[ENTER]Hinweise. "
gameforge.main_quest_lv72._60_sendLetter = "Die Entdeckung "
gameforge.main_quest_lv72._70_say = "Von Lee Chung wei\223t du, dass die[ENTER]Drachenpriesterinnen die Heiligen M\228chte, einen[ENTER]uralten wei\223en Zauber, beschw\246ren konnten,[ENTER]um b\246se Geister zu vertreiben.[ENTER]Suche im Roten Wald nach der verwitterten[ENTER]Steintafel, von der Lee Chung sprach, und[ENTER]erhalte weitere Hinweise. "
gameforge.main_quest_lv72._80_say = "Nach langer Suche st\246\223t du im Unterholz auf eine[ENTER]Steintafel, die schon seit Jahrhunderten hier zu[ENTER]liegen scheint. Das muss die alte Tafel sein, von[ENTER]der Lee Chung gesprochen hat![ENTER]M\252hsam entzifferst du die verwitterte Inschrift. "
gameforge.main_quest_lv72._90_say = "Die Tr\228ne des Himmels ist das wertvollste[ENTER]Geheimnis der Drachenpriesterinnen. Die Kunst[ENTER]ihrer Herstellung wird seit Generationen[ENTER]streng geh\252tet und notfalls mit Blut verteidigt.[ENTER]Dem Tr\228ger dieses magischen Edelsteines k\246nnen[ENTER]sich Agwi und D\228monen nicht ohne Weiteres[ENTER]n\228hern. Ist die Tr\228ne des Himmels erst einmal[ENTER]erf\252llt von der Kraft der Heiligen M\228chte, ist[ENTER]ihre Wirkung einfach \252berw\228ltigend. Sieben[ENTER]Sonnenscheiben lang strahlt sie hell wie der[ENTER]Polarstern am Firmament. "
gameforge.main_quest_lv78 = {}
gameforge.main_quest_lv78._100_say = "Ah, phantastisch! Es hat geklappt. Hier hast du[ENTER]den Roten H\246llenquarz. "
gameforge.main_quest_lv78._10_sendLetter = "Roter H\246llenquarz "
gameforge.main_quest_lv78._110_sendLetter = "Letztes Element "
gameforge.main_quest_lv78._120_say = "Lee Chung und der Rat der Magier haben[ENTER]entdeckt, dass man das letzte Element, das[ENTER]Geweihte Baumharz, aus Roten B\246sen B\228umen[ENTER]gewinnt. Gehe auf die Jagd nach Roten B\246sen[ENTER]B\228umen im Roten Wald und sammle 100 Portionen des[ENTER]Geweihten Baumharzes.[ENTER]Sprich vorher unbedingt noch einmal mit Lee[ENTER]Chung. "
gameforge.main_quest_lv78._130_say = "Lee Chung und der Rat der Magier haben[ENTER]entdeckt, dass man das letzte Element, das[ENTER]Geweihte Baumharz, aus Roten B\246sen B\228umen[ENTER]gewinnt. Gehe auf die Jagd nach Roten B\246sen[ENTER]B\228umen im Roten Wald und sammle 100 Portionen[ENTER]des Geweihten Baumharzes. "
gameforge.main_quest_lv78._140_say = "Das ist der letzte Schritt f\252r die Herstellung[ENTER]der Tr\228ne des Himmels. Pass gut auf dich auf, im[ENTER]Roten Wald wimmelt es vor todbringenden[ENTER]Kreaturen! "
gameforge.main_quest_lv78._150_say = "Du musst noch %d Portion(en) des Geweihten[ENTER]Baumharzes sammeln. "
gameforge.main_quest_lv78._160_notice = "Du hast genug Geweihtes Baumharz gefunden! Bring[ENTER]es zu Kommandant Lee Chung. "
gameforge.main_quest_lv78._170_say = "Ist dies das Geweihte Baumharz? Ich kann seine[ENTER]enorme Kraft sp\252ren. Sagenhaft![ENTER]Leider musste ich s\228mtliche Magier auf eine[ENTER]Mission schicken. Sie werden eine Weile weg sein.[ENTER]Gibt es in deinem Heimatdorf nicht einen[ENTER]Apotheker namens Baek-Go? "
gameforge.main_quest_lv78._180_say = "Ja, den gibt es tats\228chlich. "
gameforge.main_quest_lv78._190_say = "Ah, das trifft sich gut! Nimm die drei Elemente[ENTER]und bringe sie zu Baek-Go. Er wird die Tr\228ne des[ENTER]Himmels daraus fertigen k\246nnen. "
gameforge.main_quest_lv78._200_say = "Du hast eine anstrengende Reise hinter dir. Bitte[ENTER]nimm diese Belohnung f\252r all deine M\252hen[ENTER]entgegen. "
gameforge.main_quest_lv78._20_say = "Lee Chung, Kommandant der Schattenkrieger, hat[ENTER]mehr \252ber den Roten H\246llenquarz herausgefunden.[ENTER]Um es herzustellen, ben\246tigt man drei[ENTER]verschiedene Substanzen: Vulkanerde des[ENTER]Doyyumhwan, eine Flammenm\228hne und einen[ENTER]Fundamentstein. Jage Flammen, Flammenkrieger und[ENTER]Kampftiger im Feuerland, um an diese Substanzen[ENTER]zu kommen und lasse sie anschlie\223end zu 20 St\252ck[ENTER]des Roten H\246llenquarzes formen.[ENTER]Bevor du in den Kampf ziehst, suche Lee Chung[ENTER]auf. "
gameforge.main_quest_lv78._210_sendLetter = "Tr\228ne des Himmels "
gameforge.main_quest_lv78._220_say = "Kehre zur\252ck in dein Heimatdorf, suche dort[ENTER]Baek-Go auf und bitte ihn im Namen Lee Chungs,[ENTER]die Tr\228ne des Himmels aus den drei Elementen zu[ENTER]fertigen. "
gameforge.main_quest_lv78._230_say = "Du warst lange fort. Ich habe mich schon gefragt,[ENTER]ob dir etwas passiert ist. Was f\252hrt dich zu[ENTER]mir? "
gameforge.main_quest_lv78._240_say = "Lee Chung hat mich beauftragt, dich um einen[ENTER]Gefallen zu bitten. "
gameforge.main_quest_lv78._250_say = "Lee Chung?! Der Kommandant der Schattenkrie...[ENTER]oh, shhhh! Leise! Vor dir steht ein Magier der[ENTER]Schattenkrieger. Doch das ist streng geheim und[ENTER]keiner im Dorf darf davon erfahren.[ENTER]Um welchen Gefallen m\246chte Lee Chung mich bitten? "
gameforge.main_quest_lv78._260_say = "Er m\246chte, dass du aus diesen drei Elementen die[ENTER]Tr\228ne des Himmels fertigst. "
gameforge.main_quest_lv78._270_say = "Die Tr\228ne des Himmels, soso ... Er hat so viele[ENTER]Magier unter sich. Warum \252berl\228sst er aber immer[ENTER]mir die schwierigen Aufgaben?[ENTER]...[ENTER]Na, also. Da h\228tten wir sie - die Tr\228ne des[ENTER]Himmels. Wundersch\246n! Ich werde sie mit einem[ENTER]Boten direkt zu Lee Chung schicken und er wird[ENTER]nach dir rufen, wenn alles bereit ist.[ENTER]Verr\228tst du mir, wozu sie dient? "
gameforge.main_quest_lv78._280_say = "Ich kann dir leider nichts Genaueres erz\228hlen.[ENTER]Nur so viel: Dieser Stein ruft die Heiligen[ENTER]M\228chte herbei, um D\228monen und andere b\246se[ENTER]Wesen zu vertreiben. "
gameforge.main_quest_lv78._290_say = "Sehr interessant. Ich w\252nsche dir viel Erfolg bei[ENTER]deiner Aufgabe. Als Belohnung f\252r deine Taten[ENTER]bekommst du zwei Schrumpfk\246pfe.[ENTER]Nun, da ich wei\223, wie es geht, stehe ich dir[ENTER]gerne zu Diensten, sobald du eine weitere Tr\228ne[ENTER]des Himmels brauchst.[ENTER]Ach, und w\252rdest du Lee Chung bitte meine besten[ENTER]Gr\252\223e ausrichten? "
gameforge.main_quest_lv78._300_say = "Das Abenteuer geht weiter, sobald du Level 84[ENTER]erreicht hast. "
gameforge.main_quest_lv78._30_say = "Unsere Magier haben herausgefunden, dass[ENTER]Roter H\246llenquarz, welcher der Herstellung der[ENTER]Tr\228ne des Himmels dient, die M\228chte des Feuers[ENTER]in sich tr\228gt. Dieser Quarz muss auch die[ENTER]Ursache f\252r die unglaublichen Kr\228fte der[ENTER]Feuerland-Kreaturen sein. "
gameforge.main_quest_lv78._40_say = "Roter H\246llenquarz wird aus drei Substanzen[ENTER]hergestellt: Vulkanerde, Flammenm\228hne und[ENTER]Fundamentstein. Du findest alles im Feuerland. "
gameforge.main_quest_lv78._50_say = "Du hast es geschafft! Endlich haben wir die[ENTER]erforderlichen %d St\252cke des Roten H\246llenquarzes.[ENTER]Deine Tapferkeit und Kampfst\228rke beeindrucken[ENTER]mich stets aufs Neue! "
gameforge.main_quest_lv78._60_say = "Eine Substanz fehlt. Wir ben\246tigen Vulkanerde,[ENTER]Flammenm\228hne sowie Fundamentstein. "
gameforge.main_quest_lv78._70_say = "Es tut mir leid, aber ich kann an einem Tag nur[ENTER]sieben St\252ck des Roten H\246llenquarzes herstellen.[ENTER]Diese Prozedur ist eine Herausforderung f\252r meine[ENTER]Zauberf\228higkeiten. Schlie\223lich bin ich kein[ENTER]Magier! "
gameforge.main_quest_lv78._80_say = "Also dann! Ich werde nun die drei Substanzen[ENTER]miteinander vermischen und versuchen, einen Roten[ENTER]H\246llenquarz herzustellen. "
gameforge.main_quest_lv78._90_say = "Argh! Der Zauber ist fehlgeschlagen. Anscheinend[ENTER]habe ich meine magischen F\228higkeiten \252bersch\228tzt.[ENTER]Das n\228chste Mal klappt es bestimmt. "
gameforge.main_quest_lv84 = {}
gameforge.main_quest_lv84._100_say = "Nachdem du General Tartaros besiegt hast,[ENTER]\246ffnet sich ein Zugang zu einer bisher[ENTER]verborgenen Ebene der Devil's Catacomb.[ENTER]Dort muss sich F\252rst Charon befinden![ENTER]Teleportiere dich in die sechste Ebene und[ENTER]stelle dich dem F\252rsten der Agwi. Doch Vorsicht![ENTER]Er ist \228u\223erst stark und gerissen wie ein Teufel. "
gameforge.main_quest_lv84._10_sendLetter = "Der Kampf beginnt "
gameforge.main_quest_lv84._110_say = "So wie du dich in der Devil's Catacomb bewegst -[ENTER]frei und ohne Angst -, kannst du unm\246glich ein[ENTER]Normalsterblicher sein![ENTER]Der Basalt-Obelisk auf der f\252nften Ebene dient[ENTER]dir als Portal zur verborgenen sechsten Ebene. "
gameforge.main_quest_lv84._120_say = "Von dort erteilt F\252rst Charon all seine Befehle[ENTER]an Agwi-General Tartaros.[ENTER]Worauf wartest du noch? Vernichte Charon und[ENTER]vereitle die d\252steren Pl\228ne der Diener der[ENTER]Dunkelheit und der Banshee! "
gameforge.main_quest_lv84._130_sayReward = "Du hast es geschafft! Charon, F\252rst der Agwi,[ENTER]wurde vernichtend geschlagen. "
gameforge.main_quest_lv84._140_say = "Ersch\246pft und erleichtert wischst du dir den[ENTER]Schwei\223 von der Stirn.[ENTER]Pl\246tzlich ersch\252ttert ein schrilles[ENTER]Gel\228chter die Devil's Catacomb, so[ENTER]durchdringend, dass es dir bis ins Mark f\228hrt:[ENTER]Ahahahah! Zu sp\228t, ihr erb\228rmlichen Menschen![ENTER]Unser Meister, Sung Mahi, ist bereits auferstanden[ENTER]und ihr k\246nnt nichts tun, um das jetzt noch zu[ENTER]verhindern.[ENTER]Der Tag ist nah, an dem Sung Mahi auf der Insel, wo[ENTER]die b\246sen Drachen schlafen, zu seiner vollkommenen[ENTER]Macht gelangen wird. Eure Welt ist dem Untergang[ENTER]geweiht! "
gameforge.main_quest_lv84._150_sendLetter = "Unvollendete Geschichte "
gameforge.main_quest_lv84._160_say = "Gehe zu Lee Chung und berichte ihm \252ber[ENTER]die bedrohliche Botschaft der Banshee. "
gameforge.main_quest_lv84._170_say = "Nachdem du dem Kommandanten von deinem Sieg \252ber[ENTER]Tartaros und Charon berichtet hast, wiederholst[ENTER]du die bedr\252ckende Botschaft der Banshee.[ENTER]Mit ernster Miene beginnt er zu sprechen: "
gameforge.main_quest_lv84._180_say = "Ich hatte angenommen, dass wir auch die[ENTER]finsteren Pl\228ne der Diener der Dunkelheit und[ENTER]der Banshee vereiteln, wenn wir den[ENTER]F\252rsten der Agwi st\252rzen. Weit gefehlt ... "
gameforge.main_quest_lv84._190_say = "Die Banshee muss zusammen mit Azrael, dem dunklen[ENTER]K\246nig der Agwi, bereits die Auferstehung[ENTER]des D\228monengottes Sung Mahi vollzogen haben. Ich[ENTER]erschaudere bei der Vorstellung ... "
gameforge.main_quest_lv84._200_say = "Die Insel, auf der die b\246sen Drachen schlafen ...[ENTER]Hm, damit muss der Fels der Dunklen Drachen[ENTER]gemeint sein, eine unerforschte Insel, weit[ENTER]entfernt von hier.[ENTER]Auch wenn wir nicht erreicht haben, was wir[ENTER]wollten, sind wir dir dennoch zu gro\223em Dank[ENTER]verpflichtet. Ohne dich h\228tten wir die Ursache[ENTER]f\252r das Unheil, das in den Untiefen der Devil's[ENTER]Catacomb lauerte, nie aufdecken k\246nnen. "
gameforge.main_quest_lv84._20_say = "Lee Chung hat die Tr\228ne des Himmels erhalten und[ENTER]alles f\252r deinen Einsatz in der Devil's Catacomb[ENTER]vorbereitet. Gehe zu ihm, um mehr zu erfahren. "
gameforge.main_quest_lv84._210_say = "Du hast wahrhaft gro\223e Taten vollbracht,[ENTER]niemand au\223er dir w\228re dazu in der Lage[ENTER]gewesen. Ich werde dir f\252r alle Zeit zur Seite[ENTER]stehen, wenn du mich brauchst. Leb wohl! "
gameforge.main_quest_lv84._30_say = "Jetzt, da wir die Tr\228ne des Himmels in unseren[ENTER]H\228nden halten, ist es nur noch eine Frage der[ENTER]Zeit, bis wir die Diener der Dunkelheit besiegt[ENTER]und die Agwi aus unserer Welt vertrieben haben![ENTER]Doch ihre gesamte Macht entfaltet sich nur, wenn[ENTER]sie an einem bestimmten Ort in der Devil's[ENTER]Catacomb eingesetzt wird. "
gameforge.main_quest_lv84._40_say = "Wir wissen von f\252nf Ebenen in der Devil's[ENTER]Catacomb. Auf dieser f\252nften und letzten uns[ENTER]bekannten Ebene wirst du auf Tartaros treffen,[ENTER]grausamer Agwi-General und Dritter in der[ENTER]Rangfolge hinter K\246nig Azrael und F\252rst Charon.[ENTER]Vernichte ihn mithilfe der Tr\228ne des Himmels! "
gameforge.main_quest_lv84._50_say = "Aber wo versteckt sich nur F\252rst Charon? "
gameforge.main_quest_lv84._60_sendLetter = "General Tartaros "
gameforge.main_quest_lv84._70_say = "Verwende die Tr\228ne des Himmels erst, wenn du[ENTER]die f\252nfte Ebene der Devil's Catacomb erreicht[ENTER]hast. Den Eingang zur Devil's Catacomb befindet[ENTER]sich auf der R\252ckseite des D\228monenturms. "
gameforge.main_quest_lv84._80_say = "Die Heiligen M\228chte beginnen, in der Tr\228ne des[ENTER]Himmels zu wirken. Du sp\252rst eine ungeheure[ENTER]Energie durch deinen K\246rper flie\223en. Die Kraft[ENTER]dieses Steines ist \252berw\228ltigend![ENTER]Vernichte General Tartaros. "
gameforge.main_quest_lv84._90_sendLetter = "F\252rst Charon "
gameforge.main_quest_lv9 = {}
gameforge.main_quest_lv9._10_targetVid = "Finde den Stadtw\228chter "
gameforge.main_quest_lv9._20_sendLetter = "Sprich mit dem Stadtw\228chter "
gameforge.main_quest_lv9._30_sayReward = "Die ersten Schritte auf dem Weg zu wahrem[ENTER]Heldentum liegen hinter dir. Nun ist es Zeit f\252r[ENTER]gr\246\223ere Taten. Geh zum Stadtw\228chter und hole dir[ENTER]deinen letzten Anf\228nger-Auftrag ab. "
gameforge.main_quest_lv9._40_say = "Bist du bereit, schwierigere Aufgaben zu[ENTER]bew\228ltigen? Bedenke, dass die Zeit der leichten[ENTER]Erledigungen vorbei ist, wenn du f\252r die Zukunft[ENTER]deines Reiches einstehen willst. Du wirst viele[ENTER]Schlachten und N\246te durchleben. Sei also immer[ENTER]auf der Hut. Hier, diese Belohnung geb\252hrt dir[ENTER]als Anerkennung deines bisherigen Einsatzes. M\246ge[ENTER]es dir von Nutzen sein. "
gameforge.main_quest_lv9._50_say = "Von jetzt an wird der Hauptmann dir zur Seite[ENTER]stehen. Er wird dich und deine Fortschritte[ENTER]beaufsichtigen und dir Aufgaben stellen, um dich[ENTER]zu trainieren. \220be dich noch ein wenig im Kampf[ENTER]und begib dich anschlie\223end zu ihm. Alles Gute! "
gameforge.main_quest_lv90 = {}
gameforge.main_quest_lv90._010_sendLetter = "Fels der Dunklen Drachen "
gameforge.main_quest_lv90._020_say = "Deine Reise war lang und beschwerlich. Doch[ENTER]endlich hast du dein Ziel erreicht: den Fels der[ENTER]Dunklen Drachen.[ENTER]Suche nach Admiral Angmur. Du findest ihn am Kap[ENTER]des Drachenfeuers. "
gameforge.main_quest_lv90._030_say = "Willkommen auf dem Fels der Dunklen Drachen,[ENTER]Fremder! Bist du gekommen, um uns im Kampf gegen[ENTER]Sung Mahi zu unterst\252tzen? "
gameforge.main_quest_lv90._040_say = "Ja, genau. Lee Chung, Kommandant der[ENTER]Schattenkrieger, schickt mich. "
gameforge.main_quest_lv90._050_say = "Lee Chung! Wir sind langj\228hrige Weggef\228hrten. Du[ENTER]bist also in seinem Auftrag hier. Aye, dann wei\223[ENTER]ich, dass ich dir vertrauen kann. "
gameforge.main_quest_lv90._060_say = "Ich danke dir. Wie sieht die Lage hier aus? "
gameforge.main_quest_lv90._070_say = "D\228monen beherrschen weite Teile der Insel. Nichts[ENTER]und niemand ist vor ihnen sicher. Sie fressen sich[ENTER]sogar gegenseitig. Der dunkle Einfluss von Sung[ENTER]Mahi bringt alle um ihren Verstand. "
gameforge.main_quest_lv90._080_say = "Ich k\246nnte deine Hilfe gebrauchen. W\252rdest du die[ENTER]Insel auskundschaften und mir einen aktuellen[ENTER]Lagebericht bringen? "
gameforge.main_quest_lv90._090_say = "Nat\252rlich. "
gameforge.main_quest_lv90._1000_say = "Einverstanden. "
gameforge.main_quest_lv90._100_say = "Ich danke dir. Warte, ich zeige dir den Weg. "
gameforge.main_quest_lv90._1010_say = "Du bist sehr flei\223ig, aber leider reicht das noch[ENTER]nicht. Sammle weiter! "
gameforge.main_quest_lv90._1020_sayTitle = "Ziegel sammeln "
gameforge.main_quest_lv90._1030_say = "Ziehe in den Kampf gegen die Mantikore, um[ENTER]Ziegel zu sammeln. "
gameforge.main_quest_lv90._1040_1_notice = "Du hast gen\252gend Ziegel gesammelt. "
gameforge.main_quest_lv90._1040_2_notice = "Liefere sie bei Admiral Angmur ab. "
gameforge.main_quest_lv90._1050_say = "Sprich mit Admiral Angmur. "
gameforge.main_quest_lv90._1060_say = "Sehr gut, dank dir haben wir genug Materialien, um[ENTER]den Abwehrwall zu verst\228rken. Sobald wir damit[ENTER]fertig sind, werde ich dich rufen lassen. "
gameforge.main_quest_lv90._1070_sendLetter = "Lee Chungs Auftrag "
gameforge.main_quest_lv90._1080_say = "Lee Chung hat einen Auftrag f\252r dich. "
gameforge.main_quest_lv90._1090_say = "Leider sind es schlechte Neuigkeiten, die[ENTER]uns wieder zusammenf\252hren: Die Diener der[ENTER]Dunkelheit sind ihrem Ziel nahe. Schon bald wird[ENTER]Sung Mahi unbesiegbar sein.[ENTER]Wir haben keine Zeit zu verlieren! Gehe zum[ENTER]Teleporter. Von dort aus wird dich ein Schiff zum[ENTER]Fels der Dunklen Drachen bringen. Suche dort nach[ENTER]Admiral Angmur. Ich habe bereits einen Brief[ENTER]vorausgeschickt, der deine Ankunft ank\252ndigt. "
gameforge.main_quest_lv90._1100_say = "Ich breche sofort auf. "
gameforge.main_quest_lv90._110_sayReward = "Kundschafte den Fels der Dunklen Drachen aus. Gehe[ENTER]als Erstes hierher: (%d, %d). "
gameforge.main_quest_lv90._1110_sayTitle = "Aufbruch zur Insel "
gameforge.main_quest_lv90._1120_say = "Gehe zum Teleporter. Er bringt dich zum Fels der[ENTER]Dunklen Drachen. "
gameforge.main_quest_lv90._1160_targetInfo = "Der Pfeil \252ber dem NPC zeigt dir, dass dieser mit[ENTER]dir sprechen m\246chte. Solltest du den NPC nicht auf[ENTER]deinem Bildschirm sehen, folge dem blinkenden[ENTER]Punkt auf der Minimap. "
gameforge.main_quest_lv90._1170_posInfo = "Folge dem blinkenden Punkt auf der Minimap. "
gameforge.main_quest_lv90._1180_say = "Verbleibend "
gameforge.main_quest_lv90._1180_say_count = "Das Item %s bekommst du in %s kills. "
gameforge.main_quest_lv90._1190_say = "%s : %d St\252ck "
gameforge.main_quest_lv90._1200_say = "Das Abenteuer geht weiter, sobald du Level 91[ENTER]erreicht hast. "
gameforge.main_quest_lv90._120_sayTitle = "Lagebericht "
gameforge.main_quest_lv90._130_say = "Schaue dich auf der Insel um und erstatte Admiral[ENTER]Angmur anschlie\223end Bericht. "
gameforge.main_quest_lv90._140_sayReward = "Das ist dein erstes Ziel: %d, %d "
gameforge.main_quest_lv90._150_sayReward = "Du hast dein erstes Ziel erreicht.[ENTER]Das n\228chste ist: (%d, %d) "
gameforge.main_quest_lv90._160_say = "Du hast noch nicht alle Gebiete ausgekundschaftet.[ENTER]Bitte schaue dich \252berall um. "
gameforge.main_quest_lv90._170_sayReward = "Dein zweites Ziel ist: %d, %s "
gameforge.main_quest_lv90._180_sayReward = "Du hast dein zweites Ziel erreicht.[ENTER]Das n\228chste ist: (%d, %d) "
gameforge.main_quest_lv90._190_say = {}
gameforge.main_quest_lv90._200_say = {}
gameforge.main_quest_lv90._210_sayReward = "Dein drittes Ziel  ist: %d, %d "
gameforge.main_quest_lv90._220_sayReward = "Du hast alle Gebiete ausgekundschaftet.[ENTER]Kehre zu Admiral Angmur zur\252ck. "
gameforge.main_quest_lv90._230_say = "Sprich mit Admiral Angmur. "
gameforge.main_quest_lv90._240_say = "Nachdem du die komplette Insel durchwandert hast,[ENTER]ist dir folgende Erkenntnis sicher: \220berall[ENTER]wimmelt es vor D\228monen. "
gameforge.main_quest_lv90._250_say = "Du hast gute Arbeit geleistet. Nimm das hier als[ENTER]Dank f\252r deine Hilfe. "
gameforge.main_quest_lv90._260_sendLetter = "Lee Chungs Brief "
gameforge.main_quest_lv90._270_say = "W\228hrend du die aktuelle Lage auf dem Fels der[ENTER]Dunklen Drachen schilderst, verfinstert sich[ENTER]Admiral Angmurs Gesichtsausdruck. "
gameforge.main_quest_lv90._280_say = "Ich h\228tte dir gerne bessere Nachrichten gebracht. "
gameforge.main_quest_lv90._290_say = "Die D\228monen auf der Insel werden immer st\228rker.[ENTER]Wenn wir Sung Mahi und die Diener der Dunkelheit[ENTER]nicht aufhalten k\246nnen, m\246ge uns der Drachengott[ENTER]gn\228dig sein. "
gameforge.main_quest_lv90._300_say = "Ja, ich gebe zu, es sieht ein wenig d\252ster aus. "
gameforge.main_quest_lv90._310_say = "Aye, das kannst du laut sagen ...[ENTER]Lee Chung muss einen entscheidenden Hinweis[ENTER]entdeckt haben. Er sandte mir einen Brief mit[ENTER]wichtigen Informationen. Doch der erreichte mich[ENTER]nie. Der Bote wurde von Gnollen \252berfallen. "
gameforge.main_quest_lv90._320_say = "Wir m\252ssen diesen Brief finden. Kannst du uns[ENTER]helfen? "
gameforge.main_quest_lv90._330_say = "Nat\252rlich. Ich bin schon auf dem Weg. "
gameforge.main_quest_lv90._340_say = "Ich danke dir. Die Gnolle siedeln hier ganz in der[ENTER]N\228he. "
gameforge.main_quest_lv90._350_sayTitle = "Finde Lee Chungs Brief. "
gameforge.main_quest_lv90._360_say = "Einer der folgenden Kreaturen besitzt Lee Chungs[ENTER]Brief: Gnoll-K\228mpfer, Gnoll-Bogensch\252tze,[ENTER]Gnoll-Verteidiger, Gnoll-Magier, Gnoll-General, Lord[ENTER]Gnoll oder die Oberste Gnoll-Wache "
gameforge.main_quest_lv90._370_say = "Wenn wir Sung Mahi aufhalten wollen, brauchen wir[ENTER]diesen Brief! Der Dieb stammt aus den Reihen des[ENTER]Gnoll-Stammes. "
gameforge.main_quest_lv90._380_1_notice = "Du hast den Brief gefunden. "
gameforge.main_quest_lv90._380_2_notice = "Bringe ihn zu Admiral Angmur! "
gameforge.main_quest_lv90._390_say = "Sprich mit Admiral Angmur. "
gameforge.main_quest_lv90._400_say = "Du bist zur\252ck. Und du hast den Brief! Aye, ich[ENTER]wusste, dass ich auf dich z\228hlen kann. Zeig her. "
gameforge.main_quest_lv90._410_say = "Sei gegr\252\223t Angmur![ENTER]Mein Freund, in den verlassenen Lagern Sung Mahis[ENTER]sind wir auf Folgendes gesto\223en: Die Diener der[ENTER]Dunkelheit haben ihren Verb\252ndeten auf der Insel[ENTER]geheime Nachrichten zukommen lassen. Ein Brief[ENTER]ging an den Gnoll-Stamm. Wenn ihr diesen abfangen[ENTER]k\246nnt, w\228ren wir den D\228monen einen wichtigen[ENTER]Schritt voraus! Ich sende %s als[ENTER]Unterst\252tzung und w\252nsche euch Mut und St\228rke in[ENTER]dieser dunklen Zeit.[ENTER]L.C. "
gameforge.main_quest_lv90._420_say = "Meine Sp\228her werden in Erfahrung bringen, ob die[ENTER]Gnolle den Brief bereits erhalten haben. Nimm[ENTER]derweil das hier als Dank. "
gameforge.main_quest_lv90._430_sendLetter = "Der Gnoll-Brief I "
gameforge.main_quest_lv90._440_say = "Admiral Angmur sucht nach dir. Finde heraus, was[ENTER]er m\246chte. "
gameforge.main_quest_lv90._450_say = "Der Gnoll-General hat den Brief der Diener bereits[ENTER]erhalten. Kannst du ihn uns beschaffen? Doch[ENTER]Vorsicht: Gnolle sind \228u\223erst aggressiv. Sie[ENTER]greifen zuerst an und stellen dann die Fragen. "
gameforge.main_quest_lv90._460_say = "Ich bin schon weg. "
gameforge.main_quest_lv90._470_say = "Danke. Ich wusste, dass wir auf dich z\228hlen k\246nnen. "
gameforge.main_quest_lv90._480_sayTitle = "Finde den Gnoll-Brief! "
gameforge.main_quest_lv90._490_say = "Finde den Gnoll-General. Er hat den Brief! "
gameforge.main_quest_lv90._500_say = "Wir haben keine Zeit zu verlieren. Bitte beeile[ENTER]dich und bringe mir den Brief. "
gameforge.main_quest_lv90._510_1_notice = "Du hast den Gnoll-Brief erhalten. "
gameforge.main_quest_lv90._510_2_notice = "Bringe ihn zu Admiral Angmur. "
gameforge.main_quest_lv90._520_say = "Sprich mit Admiral Angmur. "
gameforge.main_quest_lv90._530_say = "Du hast den Brief! Das sind endlich mal gute[ENTER]Neuigkeiten.[ENTER]Hm ...[ENTER]Ich kann kein Wort lesen. Der Brief ist[ENTER]anscheinend verschl\252sselt.[ENTER]Unser Gelehrter versteht sich auf Kryptologie. Ich[ENTER]werde ihn sogleich aufsuchen. Sobald ich mehr[ENTER]wei\223, gebe ich dir Bescheid. "
gameforge.main_quest_lv90._540_say = {}
gameforge.main_quest_lv90._550_say = {}
gameforge.main_quest_lv90._560_sendLetter = "Der Gnoll-Brief II "
gameforge.main_quest_lv90._570_say = "Admiral Angmur sucht nach dir. Es scheint wichtig[ENTER]zu sein. Finde heraus, was er von dir m\246chte. "
gameforge.main_quest_lv90._580_say = "Der verschl\252sselte Brief besteht aus zwei Seiten.[ENTER]Nur wenn man beide Bl\228tter \252bereinanderlegt,[ENTER]kann man die Nachricht dekodieren.[ENTER]Lord Gnoll besitzt die zweite Seite.[ENTER]Kannst du uns helfen? "
gameforge.main_quest_lv90._590_say = "Nat\252rlich. "
gameforge.main_quest_lv90._600_say = "Danke. Deine Hilfe ist von unsch\228tzbarem Wert! "
gameforge.main_quest_lv90._610_sayTitle = "Der Gnoll-Brief II "
gameforge.main_quest_lv90._620_say = "Finde die zweite Seite des Gnoll-Briefes! Du[ENTER]erh\228ltst sie von Lord Gnoll. "
gameforge.main_quest_lv90._630_say = "Die Zeit l\228uft uns davon! Beeile dich und finde[ENTER]die zweite Briefseite. "
gameforge.main_quest_lv90._640_1_notice = "Du hast die zweite Seite gefunden. Bringe sie zu[ENTER]Admiral Angmur. "
gameforge.main_quest_lv90._650_say = "Gro\223artig, jetzt k\246nnen wir die Botschaft[ENTER]entschl\252sseln:[ENTER]Hm, hier ist von Drachen die Rede, die tief im[ENTER]Herzen der Welt schlafen. Und von einer Methode, mit der[ENTER]man sie erwecken und rasend machen kann.[ENTER]Oh, oh, das klingt nicht gut ... "
gameforge.main_quest_lv90._660_say = {}
gameforge.main_quest_lv90._670_say = "Anscheinend haben die Mantikore und Rotdiebe[ENTER]ebenfalls Briefe erhalten. Ich werde mehr dar\252ber[ENTER]in Erfahrung bringen und dich dann rufen lassen. "
gameforge.main_quest_lv90._680_say = "Admiral Angmur hat einen Auftrag f\252r dich. "
gameforge.main_quest_lv90._690_sendLetter = "Die Mantikore "
gameforge.main_quest_lv90._700_say = "Admiral Angmur hat einen neuen Auftrag f\252r dich. "
gameforge.main_quest_lv90._710_say = "Gut, du bist hier! Unsere Informationen \252ber die[ENTER]Mantikore sind veraltet. Wir m\252ssen herausfinden,[ENTER]wie stark ihre Streitkr\228fte derzeit sind. "
gameforge.main_quest_lv90._720_say = "Kannst du sie ausspionieren? Ihr Lager befindet[ENTER]sich nicht weit von hier. "
gameforge.main_quest_lv90._730_say = "Nat\252rlich. Was soll ich tun? "
gameforge.main_quest_lv90._740_say = "Erledige 50 Mantikor-K\228mpfer, 40[ENTER]Mantikor-Soldaten, 20 Mantikor-Henker sowie 10-mal[ENTER]General Kor.[ENTER]Erstatte mir anschlie\223end Bericht. "
gameforge.main_quest_lv90._750_say = "Verbleibend "
gameforge.main_quest_lv90._760_say = "%s: %d[ENTER]%s: %d "
gameforge.main_quest_lv90._770_say = "Die Informationen reichen nicht aus. Du musst[ENTER]noch mehr herausfinden. "
gameforge.main_quest_lv90._780_1_notice = "Du hast die n\246tigen Informationen \252ber die[ENTER]Mantikore in Erfahrung gebracht. "
gameforge.main_quest_lv90._780_2_notice = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv90._790_say = "Hast du deinen Auftrag erledigt? Sehr gut.[ENTER]Dann erstatte mir Bericht \252ber die aktuelle[ENTER]Lage. "
gameforge.main_quest_lv90._800_say = "Die Streitmacht der Mantikore ist nicht besonders[ENTER]gro\223. Zahlenm\228\223ig seid ihr ihnen \252berlegen.[ENTER]Aber ihre K\228mpfer sind gut ausgebildet[ENTER]und \228u\223erst z\228h.[ENTER]Ich w\252rde euch raten, den Schutzwall um das Fort[ENTER]zu verst\228rken. Einem Ansturm der Mantikore h\228lt er[ENTER]nicht stand. "
gameforge.main_quest_lv90._810_say = "Aye, das sind die Informationen, die wir[ENTER]brauchen. Ich werde auf deinen Rat h\246ren und den[ENTER]Schutzwall verst\228rken.[ENTER]Bitte nimm das hier als Belohnung. "
gameforge.main_quest_lv90._820_say = "Sprich mit Admiral Angmur "
gameforge.main_quest_lv90._830_sayTitle = "Streitmacht der Mantikore "
gameforge.main_quest_lv90._840_say = "Erledige 50 Mantikor-K\228mpfer,[ENTER]40 Mantikor-Soldaten, 20 Mantikor-Henker[ENTER]sowie 10-mal General Kor. "
gameforge.main_quest_lv90._850_sendLetter = "Schutzwall verst\228rken I "
gameforge.main_quest_lv90._860_say = "Admiral Angmur sucht nach dir. Es scheint wichtig[ENTER]zu sein. Gehe sofort zu ihm. "
gameforge.main_quest_lv90._870_say = "Ah, da bist du ja.  Du hattest recht, unser[ENTER]Schutzwall wird keinem Angriff standhalten.[ENTER]Doch uns fehlt es an Material, um ihn zu verst\228rken. "
gameforge.main_quest_lv90._880_say = "Wir brauchen Ziegel und feinen Sand. Kannst du[ENTER]uns diese Baumaterialien beschaffen? "
gameforge.main_quest_lv90._890_say = "Selbstverst\228ndlich. "
gameforge.main_quest_lv90._900_say = "Sehr gut. Suche zuerst nach dem feinen Sand. Die[ENTER]Gnolle besitzen gro\223e Vorkommen davon. 50 Eimer[ENTER]sollten gen\252gen. "
gameforge.main_quest_lv90._910_sayTitle = "Feiner Sand "
gameforge.main_quest_lv90._920_say = "K\228mpfe gegen die Gnolle und besorge 50[ENTER]Eimer voll feinem Sand. "
gameforge.main_quest_lv90._930_say = "Leider reicht uns das noch nicht. Wir brauchen mehr[ENTER]von dem feinen Sand. Sammle bitte weiter. "
gameforge.main_quest_lv90._940_1_notice = "Du hast nun genug feinen Sand gesammelt. "
gameforge.main_quest_lv90._940_2_notice = "Liefere ihn bei Admiral Angmur ab. "
gameforge.main_quest_lv90._950_say = "Ok. "
gameforge.main_quest_lv90._960_say = "Ich danke dir! Mit dem feinen Sand k\246nnen wir nun[ENTER]den Schutzwall verst\228rken.[ENTER]Meine M\228nner machen sich gleich an die Arbeit.[ENTER]Ich rufe dich, sobald ich deine Hilfe wieder[ENTER]ben\246tige. "
gameforge.main_quest_lv90._970_sendLetter = "Schutzwall verst\228rken II "
gameforge.main_quest_lv90._980_say = "Admiral Angmur bittet dich um Hilfe. Finde heraus,[ENTER]was er m\246chte. "
gameforge.main_quest_lv90._990_say = "Um den Bau abzuschlie\223en, ben\246tigen wir Ziegel.[ENTER]Die Mantikore horten diese wie Gold. Ich denke, 100[ENTER]St\252ck werden gen\252gen. F\252r deine Hilfe sollst du[ENTER]nat\252rlich gro\223z\252gig belohnt werden. "
gameforge.main_quest_lv91 = {}
gameforge.main_quest_lv91._010_sendLetter = "Der Mantikor-Brief "
gameforge.main_quest_lv91._020_say = "Admiral Angmur hat einen Auftrag f\252r dich. "
gameforge.main_quest_lv91._030_say = "Aye, es wird Zeit, sich wieder den Machenschaften[ENTER]der Diener der Dunkelheit zuzuwenden.[ENTER]Wir m\252ssen die Briefe, die sie den Mantikoren[ENTER]und den Rotdieben gesandt haben, in unseren[ENTER]Besitz bringen![ENTER]Statte zuerst den Mantikoren einen Besuch ab. "
gameforge.main_quest_lv91._040_say = {}
gameforge.main_quest_lv91._050_say = "Alles klar. "
gameforge.main_quest_lv91._060_say = "General Kor hat sich mit dem Brief auf den Weg[ENTER]gemacht, um ihn Martyaxwar zu \252berbringen.[ENTER]Du musst die \220bergabe verhindern! "
gameforge.main_quest_lv91._070_sayTitle = "Der Mantikor-Brief "
gameforge.main_quest_lv91._080_say = "Erledige General Kor und finde den Brief. "
gameforge.main_quest_lv91._090_1_notice = "Du bist zu sp\228t gekommen. Martyaxwar hat den Brief[ENTER]bereits erhalten. "
gameforge.main_quest_lv91._090_2_notice = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv91._100_say = "Du kommst zu sp\228t. Ich habe den Brief bereits[ENTER]Martyaxwar \252berbracht. Das Schicksal der Menschen[ENTER]ist besiegelt! "
gameforge.main_quest_lv91._110_say = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv91._120_say = "Da bist du endlich. Hast du den Brief? "
gameforge.main_quest_lv91._130_say = "Nein, ich kam zu sp\228t - General Kor hat den Brief[ENTER]bereits Martyaxwar \252bergeben. "
gameforge.main_quest_lv91._140_say = {}
gameforge.main_quest_lv91._150_say = "Aye, das macht die Sache nicht leichter ...[ENTER]Meine Sp\228her werden Martyaxwars Aufenthaltsort[ENTER]ausfindig machen.[ENTER]Hier, bitte nimm derweil das als Belohnung. Ich[ENTER]werde dich informieren, sobald ich Neues wei\223. "
gameforge.main_quest_lv91._160_sendLetter = "Martyaxwars Versteck "
gameforge.main_quest_lv91._170_say = "Admiral Angmur sucht dich. Er kennt den[ENTER]Aufenthaltsort von Martyaxwar. "
gameforge.main_quest_lv91._180_say = "Da bist du endlich! Wir kennen nun Martyaxwars[ENTER]Aufenthaltsort. Mein Sp\228her hat beobachtet, dass[ENTER]er den Brief in seinem Stachelhalsband versteckt,[ENTER]welches er niemals ablegt. "
gameforge.main_quest_lv91._190_say = "Ich mache mich sofort auf den Weg. "
gameforge.main_quest_lv91._200_sayTitle = "Besiege Martyaxwar. "
gameforge.main_quest_lv91._210_say = "Jage Martyaxwar und nimm ihm das Stachelhalsband ab. "
gameforge.main_quest_lv91._220_say = "Wir d\252rfen keine Zeit verlieren. Beeile dich und[ENTER]bringe mir das Stachelhalsband! "
gameforge.main_quest_lv91._230_1_notice = "Du hast das Stachelhalsband erhalten. Der Brief[ENTER]befindet sich in einer Tasche auf der Innenseite. "
gameforge.main_quest_lv91._230_2_notice = "Bringe ihn Admiral Angmur. "
gameforge.main_quest_lv91._240_say = "Gehe zu Admiral Angmur. "
gameforge.main_quest_lv91._250_say = "Gute Arbeit. Das war kein einfacher Gegner.[ENTER]Wollen wir hoffen, dass uns der Brief mehr \252ber[ENTER]die dunklen Pl\228ne der D\228monen verr\228t. "
gameforge.main_quest_lv91._260_say = "Verdammt, das habe ich mir fast schon gedacht -[ENTER]wieder verschl\252sselt! Yon-I-Walker, unser[ENTER]Gelehrte, soll einen Blick darauf werfen. Gehe[ENTER]bitte zu ihm. "
gameforge.main_quest_lv91._270_sendLetter = "Dekodierung "
gameforge.main_quest_lv91._280_say = "Gehe zu Yon-I-Walker, um den Brief entschl\252sseln[ENTER]zu lassen. "
gameforge.main_quest_lv91._290_say = "*murmel* Huch, habe ich mich erschrocken![ENTER]Wer bist du? "
gameforge.main_quest_lv91._300_say = "Admiral Angmur schickt mich. "
gameforge.main_quest_lv91._310_say = "Ah, ja! Du kommst wegen dem Brief. Angmur hat[ENTER]schon von dir berichtet. "
gameforge.main_quest_lv91._320_say = "Ich konnte den Brief noch nicht entschl\252sseln.[ENTER]Aber es scheint sich um die Schrift des[ENTER]Krustenstammes aus der Nephritbucht zu handeln. "
gameforge.main_quest_lv91._330_say = "Um diese Zeichen interpretieren zu k\246nnen,[ENTER]ben\246tige ich die Carapax-Skripte des[ENTER]Krustenstammes. Kannst du mir zehn St\252ck besorgen? "
gameforge.main_quest_lv91._340_say = "Nat\252rlich. "
gameforge.main_quest_lv91._350_sayTitle = "Carapax-Skripte "
gameforge.main_quest_lv91._360_say = "Ziehe in den Kampf gegen den Krustenstamm und[ENTER]besorge zehn Carapax-Skripte. "
gameforge.main_quest_lv91._370_say = "Dieses Carapax-Skript wurde leider besch\228digt[ENTER]und ich kann es nicht verwenden. Bringe mir[ENTER]ein anderes. "
gameforge.main_quest_lv91._380_say = "Du hast die Carapax-Skripte gefunden. Sie haben die[ENTER]Form von Schildkr\246tenpanzern. "
gameforge.main_quest_lv91._390_say = "Perfekt, nun kann ich den Brief entschl\252sseln.[ENTER]Gute Arbeit! Nimm das hier als Zeichen meiner[ENTER]Dankbarkeit. "
gameforge.main_quest_lv91._400_say = "Bringe mir noch %s St\252ck. "
gameforge.main_quest_lv91._410_1_notice = "Du hast ein Carapax-Skript gefunden. "
gameforge.main_quest_lv91._410_2_notice = "Liefere es bei Yon-I-Walker ab. "
gameforge.main_quest_lv91._420_sendLetter = "Mantikor-Brief entschl\252sselt "
gameforge.main_quest_lv91._430_say = "Yon-I-Walker sucht nach dir. Gehe zu ihm und[ENTER]finde heraus, ob er den Brief bereits[ENTER]entschl\252sseln konnte. "
gameforge.main_quest_lv91._440_say = "*murmel* ... Ah, da bist du ja! Dank deiner Hilfe[ENTER]konnte ich bereits einen Gro\223teil der Nachricht[ENTER]entschl\252sseln. Doch beim letzten Teil komme ich[ENTER]nicht weiter.[ENTER]Ich f\252rchte, ich muss dich noch einmal um Hilfe[ENTER]bitten. Ich brauche dringend Carapax-Pulver.[ENTER]Du findest es bei General Lobster oder K\246nig[ENTER]Krabbs vom Krustenstamm. "
gameforge.main_quest_lv91._450_say = "Carapax-Pulver? "
gameforge.main_quest_lv91._460_say = "Ja, nur der Krustenstamm besitzt es. Bereits eine[ENTER]winzige Dosis dieses Pulvers ist t\246dlich! Drei[ENTER]Dosen davon sollten reichen. Viel Gl\252ck. "
gameforge.main_quest_lv91._470_say = "Ich mache mich sogleich auf den Weg. "
gameforge.main_quest_lv91._480_sayTitle = "Carapax-Pulver "
gameforge.main_quest_lv91._490_say = "Tritt gegen General Lobster und K\246nig Krabbs vom[ENTER]Krustenstamm an und beschaffe drei Dosen[ENTER]Carapax-Pulver. "
gameforge.main_quest_lv91._500_say = "Carapax-Pulver ist \228u\223erst giftig. Ich muss einen[ENTER]Tag warten, damit seine Wirkung etwas nachl\228sst.[ENTER]Komme morgen wieder, dann kann ich dir[ENTER]hoffentlich mehr sagen. "
gameforge.main_quest_lv91._510_say = "Du hast das Carapax-Pulver! "
gameforge.main_quest_lv91._520_say = "Gute Arbeit. Nun kann ich den Brief endlich[ENTER]entschl\252sseln. Bitte nimm dies als Belohnung. "
gameforge.main_quest_lv91._530_say = "Bringe mir noch %d St\252ck! "
gameforge.main_quest_lv91._540_say = "Das Carapax-Pulver ist verunreinigt. Bringe mir[ENTER]bitte eine neue Dosis. "
gameforge.main_quest_lv91._550_1_notice = "Du hast eine Dosis Carapax-Pulver gefunden. "
gameforge.main_quest_lv91._550_2_notice = "Bringe es Yon-I-Walker. "
gameforge.main_quest_lv91._560_sendLetter = "Vergiftet! "
gameforge.main_quest_lv91._570_say = "Admiral Angmur sucht dringend nach dir. Finde[ENTER]heraus, was er m\246chte. "
gameforge.main_quest_lv91._580_say = "Da bist du endlich! Dem Drachengott sei Dank.[ENTER]Yon-I-Walker hat sich am Carapax-Pulver vergiftet. "
gameforge.main_quest_lv91._590_say = "Er wollte sich beeilen und wurde unvorsichtig. Zu[ENTER]allem Ungl\252ck ist unser Vorrat an Heilkr\228utern[ENTER]aufgebraucht.[ENTER]Suche nach der Felsenblume - ihre Wurzel kann das[ENTER]Gift neutralisieren. Auf dieser Landkarte habe ich[ENTER]eingezeichnet, wo du sie finden kannst. "
gameforge.main_quest_lv91._600_say = "Nat\252rlich. "
gameforge.main_quest_lv91._610_say = "Ich wusste, dass ich mich auf dich verlassen kann.[ENTER]Bitte beeile dich, uns bleibt nicht viel Zeit! "
gameforge.main_quest_lv91._620_sayTitle = "Rette Yon-I-Walker! "
gameforge.main_quest_lv91._630_say = "Finde die Wurzel der Felsenblume, um den vergifteten Yon-I-Walker zu heilen. "
gameforge.main_quest_lv91._640_1_notice = "Bringe Yon-I-Walker die Felsenblumenwurzel. "
gameforge.main_quest_lv91._650_say = "*keuch*[ENTER]*hust*[ENTER]Ach, du bist es. Mir geht es sehr schlecht. Hast[ENTER]du die Wurzel der Felsenblume gefunden? "
gameforge.main_quest_lv91._660_say = "Ja, ich habe sie hier. "
gameforge.main_quest_lv91._670_say = "Ah, ich f\252hle mich schon besser.[ENTER]Meine Zeit ist wohl noch nicht gekommen. Ich danke dir. Nimm das als Belohnung. Nun kann ich meine Arbeit vollenden. Admiral Angmur wird dich informieren, sobald ich den Brief entschl\252sseln konnte. "
gameforge.main_quest_lv91._680_say = "Yon-I-Walker m\246chte mir dir sprechen. "
gameforge.main_quest_lv91._760_say = "Verbleibend "
gameforge.main_quest_lv91._770_say = "%s: %d "
gameforge.main_quest_lv91._780_say = "Das Abenteuer geht weiter, sobald du Level 92[ENTER]erreicht hast. "
gameforge.main_quest_lv92 = {}
gameforge.main_quest_lv92._010_sendLetter = "Der Rotdieb-Brief "
gameforge.main_quest_lv92._020_say = "Der letzte Brief der Diener der Dunkelheit[ENTER]befindet sich bei der Rotdieb-Bande. Admiral[ENTER]Angmur hat weitere Informationen f\252r dich. "
gameforge.main_quest_lv92._030_say = "Wir kommen der Verschw\246rung der Diener der[ENTER]Dunkelheit immer n\228her. Der letzte Brief befindet[ENTER]sich in der Hand der Rotdieb-Bande. "
gameforge.main_quest_lv92._040_say = "Die Rotdieb-Bande? "
gameforge.main_quest_lv92._050_say = "Das ist eine Gruppe von Kriminellen, die auf den[ENTER]Fels der Dunklen Drachen verbannt wurde.[ENTER]Das Ungew\246hnliche an den Rotdieben ist, dass sich[ENTER]hier Menschen mit D\228monen verb\252ndet haben. "
gameforge.main_quest_lv92._060_say = "D\228monen, die sich mit Menschen verb\252nden, anstatt[ENTER]sie zu fressen? Bemerkenswert. "
gameforge.main_quest_lv92._070_say = "Sie verbindet ein gemeinsames Ziel: Gold.[ENTER]Das Lager der Rotdieb-Bande ist nicht weit von[ENTER]hier. Erledige den Rotdieb-Henker und den[ENTER]Schwarzen General. Einer von ihnen besitzt[ENTER]den Brief. "
gameforge.main_quest_lv92._080_say = "Doch sie wurden rechtzeitig vor uns gewarnt und[ENTER]haben den Brief in vier St\252cke gerissen. Wir m\252ssen[ENTER]sie alle finden. "
gameforge.main_quest_lv92._090_say = "Alles klar. "
gameforge.main_quest_lv92._100_say = "Ich danke dir. "
gameforge.main_quest_lv92._110_sayTitle = "Der Rotdieb-Brief "
gameforge.main_quest_lv92._120_say = "K\228mpfe gegen den Rotdieb-Henker und den Schwarzen[ENTER]General. Finde alle vier Teile des Briefes. "
gameforge.main_quest_lv92._130_say = "Der Brief ist noch nicht vollst\228ndig. Finde alle[ENTER]Teile. "
gameforge.main_quest_lv92._140_1_notice = "Du hast alle Teile des Rotdieb-Briefes gefunden. "
gameforge.main_quest_lv92._140_2_notice = "Zeige sie Admiral Angmur. "
gameforge.main_quest_lv92._150_say = "Sprich mit Admiral Angmur. "
gameforge.main_quest_lv92._160_say = "Gute Arbeit. Hier, nimm das als Zeichen meiner[ENTER]Dankbarkeit. "
gameforge.main_quest_lv92._170_sendLetter = "Der Rotdieb-Brief "
gameforge.main_quest_lv92._180_say = "Admiral Angmur braucht deine Hilfe. "
gameforge.main_quest_lv92._190_say = "Gut, dass du gekommen bist. Wir haben ein Problem. "
gameforge.main_quest_lv92._200_say = "Worum geht es? "
gameforge.main_quest_lv92._210_say = "Es gibt noch einen f\252nften Teil des[ENTER]Rotdieb-Briefes. Ohne diesen ist der Rest wertlos.[ENTER]Ich habe bereits Bae-Yong, einen meiner tapfersten[ENTER]M\228nner, losgeschickt - aber es muss etwas passiert[ENTER]sein. Er h\228tte schon l\228ngst zur\252ck sein m\252ssen.[ENTER]Kannst du nach ihm suchen? "
gameforge.main_quest_lv92._220_say = "Nat\252rlich! Hast du eine Vermutung, wo er sich[ENTER]jetzt befinden k\246nnte? "
gameforge.main_quest_lv92._230_say = "Eine Vermutung, ja. Zuletzt wollte er zur[ENTER]Nephritbucht. Aber niemand kann sagen, ob er dort[ENTER]angekommen ist. "
gameforge.main_quest_lv92._240_say = "Ich mache mich sofort auf den Weg. "
gameforge.main_quest_lv92._250_sayTitle = "Der verschollene Soldat "
gameforge.main_quest_lv92._260_say = "Finde das f\252nfte Briefst\252ck. Suche daf\252r nach[ENTER]Bae-Yong in der Nephritbucht. "
gameforge.main_quest_lv92._270_say = "Du hast Bae-Yong noch nicht gefunden?[ENTER]Es geht um Leben und Tod! Bitte suche weiter nach ihm. "
gameforge.main_quest_lv92._280_say = "*keuch*[ENTER]Danke, dass du mich gefunden hast. Ich wurde im[ENTER]Kampf schwer verletzt und f\252rchte, mir bleibt[ENTER]nicht mehr viel Zeit ...[ENTER]Hier, das habe ich einem Rotdieb abgenommen. Bring[ENTER]es zum Admiral. Los, geh! Ich komme schon zu ...[ENTER](Er stirbt in deinen Armen.) "
gameforge.main_quest_lv92._290_1_notice = "Bevor Bae-Yong starb, hat er dir das fehlende[ENTER]Briefst\252ck gegeben. "
gameforge.main_quest_lv92._290_2_notice = "Geh nun zur\252ck zu Admiral Angmur. "
gameforge.main_quest_lv92._300_say = "Du bist zur\252ck! Hast du Bae-Yong gefunden? "
gameforge.main_quest_lv92._310_say = "Ja, aber ... "
gameforge.main_quest_lv92._320_say = "Aber?[ENTER]Oh nein. Er ist tot? "
gameforge.main_quest_lv92._330_say = "Ich konnte nichts mehr f\252r ihn tun. Mein Beileid.[ENTER]Er war ein mutiger Mann \150 das letzte Briefst\252ck[ENTER]hat er mit seinem Leben verteidigt. Hier ist es. "
gameforge.main_quest_lv92._340_say = "Der Verlust von Bae-Yong schmerzt uns sehr. Doch[ENTER]ich bin sehr stolz auf ihn. Er hat seine Mission[ENTER]erf\252llt \150 wir haben nun alle Teile des Briefes. "
gameforge.main_quest_lv92._350_say = "Ich danke dir f\252r alles. Hier, nimm das hier als[ENTER]Belohnung.[ENTER]Nun werde ich im Tempel ein R\228ucherst\228bchen f\252r[ENTER]Bae-Yong anz\252nden.[ENTER]Ich melde mich sp\228ter bei dir. "
gameforge.main_quest_lv92._360_say = "Geh zu Admiral Angmur. "
gameforge.main_quest_lv92._370_sendLetter = "Rotdieb-Brief entschl\252sseln "
gameforge.main_quest_lv92._380_say = "Admiral Angmur hat wichtige Neuigkeiten zu dem[ENTER]Brief der Rotdieb-Bande.[ENTER]H\246re dir an, was er zu sagen hat. "
gameforge.main_quest_lv92._390_say = "Ah, da bist du ja. Die Diener der Dunkelheit[ENTER]bereiten mir Kopfschmerzen. Dieser Brief ist[ENTER]ebenfalls verschl\252sselt. Bringe ihn bitte zu[ENTER]Yon-I-Walker. "
gameforge.main_quest_lv92._400_say = "In Ordnung. "
gameforge.main_quest_lv92._410_say = "Bring den verschl\252sselten Brief zu Yon-I-Walker. "
gameforge.main_quest_lv92._420_say = "Huch! Musst du dich denn immer so anschleichen?[ENTER]Was kann ich f\252r dich tun? "
gameforge.main_quest_lv92._430_say = "Hier ist der Brief der Rotdiebe. Doch er ist wie[ENTER]die anderen verschl\252sselt. "
gameforge.main_quest_lv92._440_say = "Lass mich mal einen Blick darauf werfen.[ENTER]Hm, das sind Schriftzeichen der Tritonen. Sie zu[ENTER]entschl\252sseln, sollte nicht schwer sein. "
gameforge.main_quest_lv92._450_say = "Prima. Wie lange brauchst du daf\252r? "
gameforge.main_quest_lv92._460_say = "Nicht so voreilig. Die Verschl\252sselung ist nicht[ENTER]besonders kompliziert. Aber ohne weitere[ENTER]Hilfsmittel wird es nicht gehen. "
gameforge.main_quest_lv92._470_say = "Nat\252rlich nicht. Das w\228re auch zu einfach gewesen. "
gameforge.main_quest_lv92._480_say = "Ich sehe, du hast deinen Humor nicht verloren, hehe. Um den Brief zu entschl\252sseln, brauche ich Oin-Schuppen. Nur General Kappa und Triton selbst vom Stamm der Tritonen d\252rfen diese seltenen Schuppen tragen. Hole bitte zehn St\252ck. "
gameforge.main_quest_lv92._490_say = "Ich mache mich gleich auf den Weg. "
gameforge.main_quest_lv92._500_sayTitle = "Finde Oin-Schuppen! "
gameforge.main_quest_lv92._510_say = "Nur Triton, K\246nig der Tritonen, und General Kappa[ENTER]tragen Oin-Schuppen. "
gameforge.main_quest_lv92._520_say = "Ohne diese Schuppen kann ich den Brief nicht[ENTER]entschl\252sseln. Ich brauche sie unbedingt. "
gameforge.main_quest_lv92._530_1_notice = "Du hast die tritonischen Oin-Schuppen gefunden. "
gameforge.main_quest_lv92._530_2_notice = "Bringe sie rasch zu Yon-I-Walker. "
gameforge.main_quest_lv92._540_say = "Du hast gute Arbeit geleistet. Sobald ich den[ENTER]Brief entschl\252sselt habe, werde ich Admiral Angmur[ENTER]Bescheid geben.[ENTER]Du solltest dich etwas ausruhen. Hier, nimm das[ENTER]als Zeichen meiner Dankbarkeit. "
gameforge.main_quest_lv92._550_say = "Yon-I-Walker m\246chte mit dir sprechen. "
gameforge.main_quest_lv92._560_sendLetter = "Dunkle Pl\228ne "
gameforge.main_quest_lv92._570_say = "Der Brief der Diener der Dunkelheit wurde[ENTER]entschl\252sselt. Admiral Angmur wird dich in ihre[ENTER]d\252steren Pl\228ne einweihen. "
gameforge.main_quest_lv92._580_say = "Es ist uns gelungen, die geheime Botschaft[ENTER]vollst\228ndig zu entschl\252sseln. Erinnerst du dich an[ENTER]den Brief der Gnolle? Darin war bereits die Rede[ENTER]von Drachen, die tief im Herzen der Insel schlafen,[ENTER]sowie von einer Methode, diese zu erwecken und[ENTER]rasend zu machen. Nun erfahren wir, welchen Zweck[ENTER]die Diener der Dunkelheit damit verfolgen. "
gameforge.main_quest_lv92._590_say = "T\246tet man einen Drachen genau dann, wenn sein[ENTER]Verstand so schwarz wie der H\246llenschlund ist,[ENTER]speit er die Perle der Nacht aus. Und mithilfe[ENTER]dieser Perle k\246nnen die unermesslichen[ENTER]Kr\228fte Sung Mahis in unsere Welt gerufen werden.[ENTER]Das ist also ihr d\252sterer Plan! "
gameforge.main_quest_lv92._600_say = "Unsere n\228chsten Schritte m\252ssen wohl\252berlegt sein.[ENTER]Wenn ich Neuigkeiten f\252r dich habe, lasse ich nach[ENTER]dir rufen. Danke f\252r alles. "
gameforge.main_quest_lv92._610_say = "Das Abenteuer geht weiter, sobald du Level 93[ENTER]erreicht hast. "
gameforge.main_quest_lv93 = {}
gameforge.main_quest_lv93._010_sendLetter = "Kraft tanken I "
gameforge.main_quest_lv93._020_say = "Admiral Angmur m\246chte mir dir sprechen. "
gameforge.main_quest_lv93._030_say = "Wir sind den Dienern der Dunkelheit dicht auf den[ENTER]Fersen. "
gameforge.main_quest_lv93._040_say = "Um sie besiegen zu k\246nnen, m\252ssen wir deine[ENTER]Kr\228fte st\228rken.[ENTER]Kennst du das Innere Licht? Das ist geballte[ENTER]Energie. Einige mythische Wesen oder Pflanzen[ENTER]tragen es in sich. Yon-I-Walker kann daraus ein[ENTER]St\228rkungsmittel herstellen. Geh gleich zu ihm. "
gameforge.main_quest_lv93._050_say = "Einverstanden. "
gameforge.main_quest_lv93._060_say = "Ah, da ist ja mein Retter![ENTER]Das Innere Licht, oh ja ... Mein St\228rkungsmittel[ENTER]wird dich zu einem ebenb\252rtigen Gegner f\252r[ENTER]die Diener der Dunkelheit machen. "
gameforge.main_quest_lv93._070_say = "Daf\252r ben\246tige ich das Innere Licht der[ENTER]Zyklopen und der Giganten. Nur die jeweiliigen[ENTER]Stammesf\252hrer tragen es in sich.[ENTER]Nimm dir zuerst die Zyklopen vor. "
gameforge.main_quest_lv93._080_say = "Einverstanden. "
gameforge.main_quest_lv93._090_sayTitle = "Das Innere Licht I "
gameforge.main_quest_lv93._100_say = "Besiege Polyphemos, K\246nig der Zyklopen,[ENTER]und raube sein Inneres Licht. "
gameforge.main_quest_lv93._110_say = "Du kommst mit leeren H\228nden? So kann ich dir nicht[ENTER]weiterhelfen. Bringe mir das Innere Licht! "
gameforge.main_quest_lv93._120_1_notice = "Du hast das Innere Licht gefunden. Bringe es zu[ENTER]Yon-I-Walker. "
gameforge.main_quest_lv93._130_say = "Sprich mit Yon-I-Walker. "
gameforge.main_quest_lv93._140_say = "Das ist also das Innere Licht ... Bevor ich es[ENTER]verarbeiten kann, muss es gereinigt werden. Das[ENTER]wird eine Weile dauern. Ich gebe dir dann Bescheid. "
gameforge.main_quest_lv93._150_sendLetter = "Kraft tanken II "
gameforge.main_quest_lv93._160_say = "Yon-I-Walker sucht nach dir. "
gameforge.main_quest_lv93._170_say = "Das Innere Licht des Polyphemos ist nun gereinigt.[ENTER]Als N\228chstes ben\246tigen wir das der Giganten.[ENTER]Besiege daf\252r K\246nig Wobba. "
gameforge.main_quest_lv93._180_say = "Ich mache mich gleich auf den Weg. "
gameforge.main_quest_lv93._190_sayTitle = "Das Innere Licht II "
gameforge.main_quest_lv93._200_say = "Besiege Gigantenk\246nig Wobba und[ENTER]raube sein Inneres Licht. "
gameforge.main_quest_lv93._210_say = "Du kommst mir leeren H\228nden? Es w\252rde mich[ENTER]wundern, wenn du dieser Aufgabe nicht gewachsen[ENTER]w\228rst. Ziehe los und versuche es erneut! "
gameforge.main_quest_lv93._220_1_notice = "Du h\228ltst das Innere Licht der Giganten in deinen[ENTER]H\228nden. "
gameforge.main_quest_lv93._220_2_notice = "Bringe es Yon-I-Walker. "
gameforge.main_quest_lv93._230_say = "Sprich mit Yon-I-Walker. "
gameforge.main_quest_lv93._240_say = "Das Innere Licht des K\246nig Wobba besitzt[ENTER]ungeheure Kraft. Ich sch\228tze, das macht die Masse.[ENTER]Nun muss ich es noch reinigen. Das wird eine Weile[ENTER]dauern. "
gameforge.main_quest_lv93._250_sendLetter = "Kraft tanken III "
gameforge.main_quest_lv93._260_say = "Yon-I-Walker sucht nach dir. "
gameforge.main_quest_lv93._270_say = "Sehr gut, du bist hier. Ich brauche deine Hilfe.[ENTER]Damit sich die Wirkung meines St\228rkungselixiers[ENTER]vollst\228ndig entfalten kann, brauche ich noch eine[ENTER]weitere Komponente: die Millennium-Essenz. "
gameforge.main_quest_lv93._280_say = "Millennium-Essenz? Noch nie davon geh\246rt. "
gameforge.main_quest_lv93._290_say = "Das ist eine sehr wirkungsvolle Mixtur aus[ENTER]verschiedenen Kr\228uteressenzen.[ENTER]Kennst du Octavio? Er wohnt auf dem Festland und[ENTER]ist der einzige, der die Millennium-Essenz[ENTER]herzustellen vermag. Gehe zu ihm. Ich hoffe, er[ENTER]wird uns helfen. Er ist manchmal etwas stur ... "
gameforge.main_quest_lv93._300_say = "Einverstanden. "
gameforge.main_quest_lv93._310_sayTitle = "Sprich mit Octavio! "
gameforge.main_quest_lv93._320_say = "Suche nach Octavio. Er lebt auf dem Festland und[ENTER]kann als Einziger die Millennium-Essenz brauen. "
gameforge.main_quest_lv93._330_say = "Hallo! Was kann ich dir bringen? Ein Samgyetang[ENTER]vielleicht? Die Spezialit\228t des Hauses mit ... "
gameforge.main_quest_lv93._340_say = "Octavio, ich bin nicht wegen deiner guten K\252che[ENTER]hier! Ich brauche etwas Anderes:[ENTER]die Millennium-Essenz. "
gameforge.main_quest_lv93._350_say = "Oi, psssst, nicht so laut! Die Millennium-Essenz ...[ENTER]Nein, das geht nicht. Von wem wei\223t du[ENTER]davon? Nur Wenige k\246nnen mit der Macht umgehen,[ENTER]die sie verleiht. Das Risiko will ich nicht[ENTER]eingehen. Und jetzt geh, ehe dich noch jemand h\246rt. "
gameforge.main_quest_lv93._360_say = "Octavio, warte und h\246re mir zu! Yon-I-Walker vom[ENTER]Fels der Dunklen Drachen schickt mich.[ENTER]Wir brauchen diese Essenz unbedingt. Ohne ihn[ENTER]haben wir keine Chance gegen die Diener der[ENTER]Dunkelheit. Und die Welt, wie wir sie kennen, ist[ENTER]dem Untergang geweiht. Nur du kannst sie[ENTER]herstellen. Bitte "
gameforge.main_quest_lv93._370_say = "Yon-I-Walker sagst du? Hm, ist ein alter Freund von[ENTER]mir. Wir haben so manches gute Gespr\228ch bei einer[ENTER]noch besseren Flasche Wein gef\252hrt.[ENTER]Ich muss nachdenken. Komm morgen wieder, dann[ENTER]werde ich dir Antwort geben. "
gameforge.main_quest_lv93._380_say = {}
gameforge.main_quest_lv93._390_say = "Ich habe mich noch nicht entschieden.[ENTER]Komme sp\228ter wieder. "
gameforge.main_quest_lv93._400_npcChat = "Die Millennium-Essenz "
gameforge.main_quest_lv93._410_say = "Octavio m\246chte mit dir sprechen. "
gameforge.main_quest_lv93._420_say = "Also, ich habe die ganze Nacht \252ber deine Bitte[ENTER]nachgedacht. Ich gehe ein gro\223es Risiko ein.[ENTER]Doch ich wei\223, dass ich damit das Richtige tue.[ENTER]Ja, ich werde dir helfen. "
gameforge.main_quest_lv93._430_say = "Gro\223artig! "
gameforge.main_quest_lv93._440_say = "Allerdings habe ich sie nicht vorr\228tig.[ENTER]Kannst du mir ein paar Zutaten besorgen? Dann[ENTER]werde ich dir die Essenz herstellen. "
gameforge.main_quest_lv93._450_say = "Nat\252rlich. Was brauchst du denn? "
gameforge.main_quest_lv93._460_say = "Mir fehlen Gango-Wurzeln, Tue-Pilze und Alpenrosen.[ENTER]Von jeder Zutat brauche ich 200 St\252ck. "
gameforge.main_quest_lv93._470_say = "Ich mache mich sofort auf den Weg. Wo finde ich[ENTER]das alles? "
gameforge.main_quest_lv93._480_say = "Du findest diese Pflanzen an den verschiedensten[ENTER]Orten des Kontinents.[ENTER]W\228hrend du unterwegs bist, beginne ich hier mit[ENTER]meinen Vorbereitungen. "
gameforge.main_quest_lv93._490_sayTitle = "Die Millennium-Rezeptur "
gameforge.main_quest_lv93._500_say = "Suche nach der Gango-Wurzel, dem Tue-Pilz und der[ENTER]Alpenrose.[ENTER]Du ben\246tigst jeweils 200 St\252ck. "
gameforge.main_quest_lv93._510 = "Du findest diese Pflanzen an den verschiedensten[ENTER]Orten des Kontinents.[ENTER]W\228hrend du unterwegs bist, beginne ich hier mit[ENTER]meinen Vorbereitungen. "
gameforge.main_quest_lv93._520_say = "Ah, sehr gut, du bist zur\252ck. Und hast alles[ENTER]dabei. Dann mache ich mich sofort an die Arbeit.[ENTER]Daf\252r muss ich ungest\246rt sein. Komme[ENTER]morgen um die gleiche Uhrzeit wieder.[ENTER]Bis dahin sollte die Essenz fertig sein. "
gameforge.main_quest_lv93._530_say = "Alles klar. Bis morgen. "
gameforge.main_quest_lv93._540_say = "Ich verstehe, dass du es eilig hast. Doch du wirst[ENTER]dich noch etwas gedulden m\252ssen. Komme sp\228ter wieder. "
gameforge.main_quest_lv93._550_say = "Octavio sucht nach dir. "
gameforge.main_quest_lv93._560_say = "Du kommst zur rechten Zeit: Die Millennium-Essenz ist gerade fertig geworden! Du kannst sie nun Yon-I-Walker bringen. "
gameforge.main_quest_lv93._570_say = "Ich danke dir. "
gameforge.main_quest_lv93._580_sendLetter = "Millennium-Essenz "
gameforge.main_quest_lv93._590_say = "Yon-I-Walker sucht nach dir. "
gameforge.main_quest_lv93._600_say = "Du hast die Millennium-Essenz![ENTER]Nun habe ich alle Zutaten f\252r mein[ENTER]St\228rkungselixier. Ich rufe dich, sobald es fertig[ENTER]ist. "
gameforge.main_quest_lv93._610_say = "Alles klar. "
gameforge.main_quest_lv93._620_say = "Das Abenteuer geht weiter, sobald du Level 94[ENTER]erreicht hast. "
gameforge.main_quest_lv93._630_say = "%s: %d St\252ck, %s: %d St\252ck,[ENTER]%s: %d St\252ck "
gameforge.main_quest_lv93._640_say = "Ich habe ein Gasthaus zu f\252hren und nicht alle[ENTER]Zeit der Welt. Bringe mir alle fehlenden Zutaten[ENTER]\150 und beeile dich bitte. "
gameforge.main_quest_lv93._650_1_notice = "Du hast alle n\246tigen Zutaten f\252r die[ENTER]Millennium-Essenz gefunden. "
gameforge.main_quest_lv93._650_2_notice = "Kehre zu Octavio zur\252ck. "
gameforge.main_quest_lv94 = {}
gameforge.main_quest_lv94._010_sendLetter = "Perlen des Leviathan "
gameforge.main_quest_lv94._020_say = "Yon-I-Walker sucht nach dir. "
gameforge.main_quest_lv94._030_say = "Ich habe es geschafft. Die wirkungsvollsten[ENTER]Essenzen, die uns bekannt sind, habe ich[ENTER]miteinander kombiniert. Ich pr\228sentiere:[ENTER]die Perlen des Leviathan! "
gameforge.main_quest_lv94._040_say = "Ich danke dir. "
gameforge.main_quest_lv94._050_say = "Wenn du diese Kapseln einnimmst, wirst du[ENTER]vielleicht keine Ver\228nderung versp\252ren. Doch ein[ENTER]ge\252btes Auge, wie meines oder Angmurs, wird es[ENTER]erkennen.[ENTER]Angmur m\246chte mit dir sprechen. Gehe sofort zu ihm. "
gameforge.main_quest_lv94._060_sayTitle = "St\228rke dich! "
gameforge.main_quest_lv94._070_say = "Nimm die Perlen des Leviathan ein und suche[ENTER]Admiral Angmur auf. "
gameforge.main_quest_lv94._080_sendLetter = "Ruf der Donnerberge "
gameforge.main_quest_lv94._090_say = "Admiral Angmur hat Neuigkeiten f\252r dich. "
gameforge.main_quest_lv94._1000_say = "Ich werde f\252r die Analyse der Proben etwas Zeit[ENTER]brauchen. Komme morgen wieder, dann werde ich[ENTER]hoffentlich schon Ergebnisse haben. "
gameforge.main_quest_lv94._100_say = "Ah, die Perlen des Leviathan zeigen ihre Wirkung:[ENTER]Ich erkenne deutlich eine Aura der Macht um dich[ENTER]herum.[ENTER]Meine Sp\228her haben eine Vermutung, wo sich das[ENTER]Hauptquartier der Diener der Dunkelheit befinden[ENTER]k\246nnte. Dieser Ort ist stark bewacht. K\246nntest du[ENTER]dich dort umsehen? "
gameforge.main_quest_lv94._1010_say = "Ich werde Angmur meine Ergebnisse mitteilen.[ENTER]Er wird dich dann informieren. "
gameforge.main_quest_lv94._1020_say = "Admiral Angmur hat Informationen \252ber das Schwarze[ENTER]Gold. Gehe zu ihm. "
gameforge.main_quest_lv94._1030_say = "Aye, da bist du ja. Die Analyse des Schwarzen[ENTER]Goldes ist noch nicht abgeschlossen. Ich hoffe,[ENTER]dass ich dir bald mehr sagen kann.[ENTER]Hier, nimm das als Lohn f\252r deine M\252hen. "
gameforge.main_quest_lv94._1040_say = "Wir d\252rfen keine Zeit verlieren. Schnell, bring[ENTER]mir Proben des Schwarzen Goldes! "
gameforge.main_quest_lv94._1050_say = "Das Abenteuer geht weiter, sobald du Level 95[ENTER]erreicht hast. "
gameforge.main_quest_lv94._1060_say = "Verbleibend "
gameforge.main_quest_lv94._1070_say = "%s: %d[ENTER]%s: %d[ENTER]%s: %d "
gameforge.main_quest_lv94._1080_say = "Fehlende Anzahl: "
gameforge.main_quest_lv94._1090_say = "%s: %d "
gameforge.main_quest_lv94._110_say = "Nat\252rlich. "
gameforge.main_quest_lv94._120_say = "Ich danke dir. Komm, ich zeige dir, welche Gebiete[ENTER]du auskundschaften musst. Erstatte mir[ENTER]anschlie\223end Bericht. "
gameforge.main_quest_lv94._130_say = {}
gameforge.main_quest_lv94._140_say = "In Admiral Angmurs Auftrag kundschaftest du die[ENTER]Donnerberge aus. Dein erstes Ziel ist: (%d, %d) "
gameforge.main_quest_lv94._150_sayTitle = "Die Donnerberge "
gameforge.main_quest_lv94._160_say = "Kundschafte die Donnerberge aus und erstatte[ENTER]Admiral Angmur Bericht. "
gameforge.main_quest_lv94._170_say = "Du hast noch nicht alle Orte erkundet, oder? Wir[ENTER]sind auf diese Informationen angewiesen. Bitte[ENTER]f\252hre meinen Auftrag aus. "
gameforge.main_quest_lv94._180_say = "Dein erstes Ziel ist: %d, %d "
gameforge.main_quest_lv94._190_say = "Dein zweites Ziel ist: %d, %d "
gameforge.main_quest_lv94._200 = {}
gameforge.main_quest_lv94._210_say = "Das dritte Ziel ist: %d, %d "
gameforge.main_quest_lv94._220_say = "Du hast dein erstes Ziel erreicht. Der n\228chste Ort[ENTER]ist: (%d, %d) "
gameforge.main_quest_lv94._230_say = "Du hast das zweite Ziel erreicht. Der n\228chste Ort[ENTER]ist: (%d, %d) "
gameforge.main_quest_lv94._240 = "Du hast das dritte Ziel erreicht. "
gameforge.main_quest_lv94._250_say = "Du konntest dir ein Bild von der Lage in den[ENTER]Donnerbergen machen.[ENTER]Erstatte nun Admiral Angmur Bericht. "
gameforge.main_quest_lv94._260_say = "Kehre zu Admiral Angmur zur\252ck. "
gameforge.main_quest_lv94._270_say = "Ah, du bist zur\252ck! Sehr gut, dann werden wir die[ENTER]Informationen, die du gesammelt hast, auswerten[ENTER]und eine Strategie ausarbeiten. "
gameforge.main_quest_lv94._280_say = "Hier ist deine Belohnung. "
gameforge.main_quest_lv94._290_sendLetter = "Rotdiebe schw\228chen "
gameforge.main_quest_lv94._300_say = "Admiral Angmur sucht nach dir. "
gameforge.main_quest_lv94._310_say = "Ein direkter Angriff erscheint mir zu diesem[ENTER]Zeitpunkt noch zu riskant. Bevor wir in die[ENTER]Offensive gehen, sollten wir die gegnerischen[ENTER]Truppen schw\228chen. "
gameforge.main_quest_lv94._320_say = "Folgende Gruppen leben in den Donnerbergen:[ENTER]Giganten, Zyklopen und Rotdiebe.[ENTER]Als Erstes werden wir die Rotdiebe angreifen! "
gameforge.main_quest_lv94._330_say = "Welche Schwachstellen haben die Rotdiebe? "
gameforge.main_quest_lv94._340_say = "Der Rote H\228uptling tr\228gt stets einen speziellen[ENTER]Umhang, Symbol der St\228rke und Unbesiegbarkeit.[ENTER]Entrei\223e dem H\228uptling diesen Umhang - das wird[ENTER]die Motivation der Rotdiebe zerschlagen! "
gameforge.main_quest_lv94._350_say = "Der Rote H\228uptling? Das wird keine leichte[ENTER]Aufgabe ... "
gameforge.main_quest_lv94._360_say = "Du hast recht. Doch wenn es einer mit ihm[ENTER]aufnehmen kann, dann du. Viel Erfolg! "
gameforge.main_quest_lv94._370_sayTitle = "Der Rote H\228uptling "
gameforge.main_quest_lv94._380_say = "Besiege den Roten H\228uptling und entrei\223e ihm[ENTER]seinen Umhang. "
gameforge.main_quest_lv94._390_say = "... versagt? Nein, das glaube ich nicht. Nimm es[ENTER]erneut mit dem Roten H\228uptling auf. Ich bin mir[ENTER]sicher, diesmal wirst du ihn besiegen. "
gameforge.main_quest_lv94._400_1_notice = "Du hast den Roten H\228uptling besiegt. "
gameforge.main_quest_lv94._400_2_notice = "Nimm seinen Umhang und bring ihn Admiral Angmur. "
gameforge.main_quest_lv94._410_say = "Admiral Angmur erwartet dich. "
gameforge.main_quest_lv94._420_say = "Der Umhang! Ich wusste, dass du es schaffst. Als[ENTER]N\228chstes werden wir ihn sichtbar in der N\228he ihres[ENTER]Lagers aufh\228ngen \150 das wird die Rotdieb-Bande[ENTER]verunsichern.[ENTER]Meine Leute werden das \252bernehmen. Dann kannst du[ENTER]dich erholen. "
gameforge.main_quest_lv94._430_sendLetter = "Zyklopen schw\228chen "
gameforge.main_quest_lv94._440_say = "Admiral Angmur m\246chte mit dir sprechen. "
gameforge.main_quest_lv94._450_say = "Unser Plan ist aufgegangen: Als die Rotdiebe den[ENTER]Umhang gesehen haben, ist gro\223e Unruhe zwischen[ENTER]ihnen ausgebrochen. Am Ende haben sich D\228monen und[ENTER]Menschen gegenseitig angegriffen. Nun ist diese[ENTER]Bande v\246llig unorganisiert.[ENTER]Als N\228chstes k\252mmern wir uns um die Zyklopen. "
gameforge.main_quest_lv94._460_say = "Und wie gehen wir vor? "
gameforge.main_quest_lv94._470_say = "Die Zyklopen beten ihre Anf\252hrer an. Wenn wir die[ENTER]F\252hrungsriege beseitigen, werden die Zyklopen in[ENTER]Panik geraten und sich zerstreuen. Besiege %d-mal[ENTER]General Outis, %d-mal Arges und %d-mal Polyphemos. "
gameforge.main_quest_lv94._480_say = "Wird mir ein Vergn\252gen sein. "
gameforge.main_quest_lv94._490_say = "Pass auf dich auf. "
gameforge.main_quest_lv94._500_sayTitle = "Kampf den Zyklopen! "
gameforge.main_quest_lv94._510_say = "Besiege %d-mal General Outis, %d-mal Arges und[ENTER]%d-mal Polyphemos. "
gameforge.main_quest_lv94._520 = "Ich kann kaum glauben, dass dir ausgerechnet die[ENTER]Zyklopen \252berlegen sein sollen. Los, ich wei\223,[ENTER]dass du es schaffen kannst! "
gameforge.main_quest_lv94._530_1_notice = "Du hast die Anf\252hrer der Zyklopen besiegt. "
gameforge.main_quest_lv94._530_2_notice = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv94._540_say = "Gehe zu Admiral Angmur. "
gameforge.main_quest_lv94._550_say = "Die Kunde deiner Taten eilt dir voraus! Die[ENTER]Zyklopen sind auf der Flucht.[ENTER]Bleiben noch die Giganten. Ich werde Informationen[ENTER]\252ber ihre Schwachstellen einholen und dich dann[ENTER]rufen lassen. "
gameforge.main_quest_lv94._560_sendLetter = "Giganten schw\228chen "
gameforge.main_quest_lv94._570_say = "Admiral Angmur l\228sst dich rufen. "
gameforge.main_quest_lv94._580_say = "Meine Sp\228her haben die Schwachstelle der Giganten[ENTER]entdeckt. "
gameforge.main_quest_lv94._590_say = "Lass h\246ren! "
gameforge.main_quest_lv94._600_say = "Die Giganten besitzen ein Totem mit gro\223em[ENTER]spirituellen Wert. Wenn wir es ihnen wegnehmen,[ENTER]k\246nnen wir ihren Willen brechen. "
gameforge.main_quest_lv94._610_say = "Wo finde ich dieses Totem? "
gameforge.main_quest_lv94._620_say = "Das Totem hat die Form eines gro\223en Bernsteins.[ENTER]Zum Schutz vor Dieben wurde er in %d Teile[ENTER]gespalten. K\246nig Wobba und seine Offiziere tragen[ENTER]diese bei sich. "
gameforge.main_quest_lv94._630_say = "Verstanden. "
gameforge.main_quest_lv94._640_sayTitle = "Giganten-Totem "
gameforge.main_quest_lv94._650_say = "Bringe alle St\252cke des Totems in deinen Besitz. "
gameforge.main_quest_lv94._660_say = "Die Giganten sind sehr m\228chtige Gegner.[ENTER]Aber du musst sie besiegen und mir dieses Totem[ENTER]bringen! "
gameforge.main_quest_lv94._670_say_1_notice = "Du hast alle St\252cke des Totems erhalten. "
gameforge.main_quest_lv94._670_say_2_notice = "Kehre zu Admiral Angmur zur\252ck. "
gameforge.main_quest_lv94._680_say = "Aye, ich habe mir schon Sorgen gemacht! Du hast es[ENTER]tats\228chlich geschafft. Nun sind wir im Besitz des[ENTER]heiligen Totems der Giganten. Daf\252r sollst du[ENTER]reich belohnt werden. "
gameforge.main_quest_lv94._690_sendLetter = "Zu den Donnerbergen "
gameforge.main_quest_lv94._700_say = "Admiral Angmur sucht nach dir. "
gameforge.main_quest_lv94._710_say = "Meine Sp\228her haben Zyklopen dabei beobachtet,[ENTER]wie sie in den Donnerbergen irgendetwas sammeln[ENTER]und wegtragen. "
gameforge.main_quest_lv94._720_say = "Finde heraus, was die Zyklopen im Auge haben.[ENTER]Mit Sicherheit nichts Gutes ... Und ich bezweifle,[ENTER]dass sie ihr Geheimnis freiwillig preisgeben. "
gameforge.main_quest_lv94._730_say = "Verstanden. "
gameforge.main_quest_lv94._740_sayTitle = "Was planen die Zyklopen? "
gameforge.main_quest_lv94._750_say = "Finde heraus, was die Zyklopen in den Donnerbergen[ENTER]sammeln. "
gameforge.main_quest_lv94._760_say = "Finde heraus, was die Zyklopen beabsichtigen.[ENTER]Mit Sicherheit nichts Gutes ... Und ich bezweifle,[ENTER]dass sie ihr Geheimnis freiwillig preisgeben. "
gameforge.main_quest_lv94._770_1_notice = "Du h\228ltst einen schwarzgl\228nzenden Stein sowie[ENTER]einen Zettel in der Hand. "
gameforge.main_quest_lv94._770_2_notice = "Zeig Admiral Angmur deinen Fund. "
gameforge.main_quest_lv94._780_say = "Geh zu Admiral Angmur. "
gameforge.main_quest_lv94._790_say = "Hast du herausgefunden, was die Zyklopen in den[ENTER]Donnerbergen machen? "
gameforge.main_quest_lv94._800_say = "Die Zyklopen wollten zwar nicht freiwillig mit der[ENTER]Sprache rausr\252cken, aber letztendlich konnte ich[ENTER]sie \252berzeugen, mir das hier zu geben: einen[ENTER]schwarzen Stein und diesen Zettel. "
gameforge.main_quest_lv94._810_say = "Wir haben die Adern des Schwarzen Goldes in den[ENTER]Donnerbergen lokalisiert und bauen es nun f\252r Euch[ENTER]ab. Zur \220bergabe treffen wir uns, wie vereinbart,[ENTER]im Inneren des Donnerberges. "
gameforge.main_quest_lv94._820_say = "Schwarzes Gold ... Das ist ein Erz, das nur in den[ENTER]Donnerbergen vorkommt. Wof\252r brauchen es die[ENTER]Diener der Dunkelheit? "
gameforge.main_quest_lv94._830_say = "Wir m\252ssen unbedingt herausfinden, was sie damit[ENTER]vorhaben. "
gameforge.main_quest_lv94._840_say = "Hier steht: "
gameforge.main_quest_lv94._850_sendLetter = "Schwarzes Gold "
gameforge.main_quest_lv94._860_say = "Admiral Angmur m\246chte mit dir \252ber das Schwarze[ENTER]Gold sprechen. "
gameforge.main_quest_lv94._870_say = "Der Alchemist konnte das Schwarze Gold nicht[ENTER]analysieren. Das St\252ck ist zu klein.[ENTER]Wir m\252ssen herausfinden, welche Eigenschaften es[ENTER]hat und warum die Diener der Dunkelheit es begehren![ENTER]Kannst du in die Donnerberge zur\252ckkehren und[ENTER]weitere Proben des Schwarzen Goldes sichern? "
gameforge.main_quest_lv94._880_say = "Geh vorher zum Alchemisten. Er kann dir sagen,[ENTER]wie viele Proben er ben\246tigt. "
gameforge.main_quest_lv94._890_say = "Sprich mit dem Alchemisten. "
gameforge.main_quest_lv94._900_say = "Ich gr\252\223e dich. Wurdest du bereits von Angmur \252ber[ENTER]deinen Auftrag in Kenntnis gesetzt? "
gameforge.main_quest_lv94._910_say = "Ja. Wie viele Proben des Schwarzen Goldes wirst du[ENTER]brauchen? "
gameforge.main_quest_lv94._920_say = "Hm, lass mal \252berlegen. Ich denke, dass %d Proben[ENTER]f\252r eine Analyse reichen sollten. "
gameforge.main_quest_lv94._930_say = "Verstanden. "
gameforge.main_quest_lv94._940_sayTitle = "Das Gold der Donnerberge "
gameforge.main_quest_lv94._950_sayTitle = "Geh zum Alchemisten. "
gameforge.main_quest_lv94._960_say = "Suche in den Donnerbergen nach Proben des[ENTER]Schwarzen Goldes. "
gameforge.main_quest_lv94._970_1_notice = "Du hast eine Schwarze Goldader entdeckt und dir[ENTER]eine Probe des Erzes gesichert. "
gameforge.main_quest_lv94._970_2_notice = "Bring sie zum Alchemisten. "
gameforge.main_quest_lv94._980_say = "Ah, du hast Schwarzes Gold gefunden. Zeig her! Hm,[ENTER]keine Risse, gro\223 genug ist das St\252ck auch[ENTER]... ja, das kann ich f\252r meine Analysen nutzen.[ENTER]Jetzt brauche ich nur noch %d. "
gameforge.main_quest_lv94._990_say = "Mit dieser Probe kann ich leider nichts anfangen.[ENTER]Sie ist zu leicht f\252r eine ordentliche Analyse.[ENTER]Bring mir eine andere! "
gameforge.main_quest_lv95 = {}
gameforge.main_quest_lv95._010_sendLetter = "Goldfieber "
gameforge.main_quest_lv95._020_say = "Admiral Angmur sucht nach dir. Er hat neue[ENTER]Informationen \252ber das Schwarze Gold. "
gameforge.main_quest_lv95._030_say = "Das Schwarze Gold entzieht den Lebewesen in seiner[ENTER]N\228he Energie und setzt sie in einem anderen K\246rper[ENTER]wieder frei. So wollen die Diener der Dunkelheit[ENTER]Sung Mahi gestohlene Macht einfl\246\223en! Der Gigant Kapit\228n Huk hortet gro\223e Vorr\228te des Schwarzen Goldes in den Donnerbergen. Hol sie dir! "
gameforge.main_quest_lv95._040_say = "Wird gemacht! "
gameforge.main_quest_lv95._050_say = {}
gameforge.main_quest_lv95._060_say = {}
gameforge.main_quest_lv95._070_sayTitle = "Am Haken: Kapit\228n Huk "
gameforge.main_quest_lv95._080_say = "Besiege Kapit\228n Huk von den Giganten und sichere[ENTER]das Schwarze Gold! "
gameforge.main_quest_lv95._090_say = "Wir haben keine Zeit zu verlieren. Besiege Kapit\228n[ENTER]Huk und sichere das Schwarze Gold! "
gameforge.main_quest_lv95._100_1_notice = "Vom Schwarzen Gold keine Spur. Stattdessen trug Kapit\228n Huk einen Brief bei sich. "
gameforge.main_quest_lv95._100_2_notice = {}
gameforge.main_quest_lv95._110_say = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv95._120_say = "Aye, du konntest dich also gegen Kapit\228n Huk[ENTER]behaupten. Was ist das? Ein Brief? Zeig her! "
gameforge.main_quest_lv95._130_say = {}
gameforge.main_quest_lv95._140_say = "Verflucht. Kapit\228n Huk hat das Schwarze Gold[ENTER]bereits der Banshee \252bersandt.[ENTER]Der letzte Satz gibt mir R\228tsel auf:[ENTER]Der Fluch des Lebens wird die Armee der Finsternis[ENTER]aus den Nebeln der Zeit heraufbeschw\246ren. "
gameforge.main_quest_lv95._150_say = "Wir m\252ssen die Lieferung aufhalten! Das Versteck der Banshee vermuten wir am Gautamakliff im Westen \150[ENTER]ein gottverlassener Ort, stets in dichten Nebel geh\252llt. Oger und Lemuren hausen dort. "
gameforge.main_quest_lv95._160_say = {}
gameforge.main_quest_lv95._170_say = "Sobald ich wei\223, auf welcher Route das Schwarze Gold zur Banshee gebracht wird, gebe ich dir Bescheid. "
gameforge.main_quest_lv95._180_sendLetter = "Lieferung abfangen "
gameforge.main_quest_lv95._190_say = "Gehe zu Admiral Angmur. Er hat n\228here[ENTER]Informationen \252ber die Lieferung des[ENTER]Schwarzen Goldes. "
gameforge.main_quest_lv95._200_say = "Meine Sp\228her haben herausgefunden, dass Kapit\228n[ENTER]Shrack, Kommandant der Oger, das Schwarze Gold[ENTER]zum Gautamakliff \252berf\252hrt. Er tr\228gt es in einem[ENTER]Beutel an seinem G\252rtel. Nimm es ihm ab! "
gameforge.main_quest_lv95._210_say = {}
gameforge.main_quest_lv95._220_say = "Verstanden. Ich mache mich gleich auf die Suche. "
gameforge.main_quest_lv95._230_sayTitle = "Fange die Lieferung ab! "
gameforge.main_quest_lv95._240_say = "Sp\252re Kapit\228n Shrack auf und sichere den Beutel[ENTER]mit dem Schwarzen Gold, bevor er die Banshee[ENTER]erreicht. "
gameforge.main_quest_lv95._250_say = "Kapit\228n Shrack ist kein Leichtgewicht. Doch du[ENTER]kannst ihn besiegen! Versuche es noch einmal. "
gameforge.main_quest_lv95._260_1_notice = "Du hast den Beutel erhalten. "
gameforge.main_quest_lv95._260_2_notice = "Kehre damit zu Admiral Angmur zur\252ck. "
gameforge.main_quest_lv95._270_say = "Bringe deine Beute zu Admiral Angmur. "
gameforge.main_quest_lv95._280_say = "Ist in diesem Beutel das Schwarze Gold? Zeig her! Nanu? Hier ist nur ein Zettel ... "
gameforge.main_quest_lv95._290_say = "Die Lieferung des Schwarzen Goldes erfolgt, sobald[ENTER]es vollst\228ndig bearbeitet wurde. "
gameforge.main_quest_lv95._300_say = "Verflucht, das Schwarze Gold ist noch immer in den[ENTER]falschen H\228nden. Zumindest wissen wir nun, dass[ENTER]es bearbeitet werden muss, bevor die Banshee es[ENTER]f\252r ihre Zwecke nutzen kann. "
gameforge.main_quest_lv95._310_say = "Noch ist es nicht zu sp\228t. Ich werde herausfinden,[ENTER]wer das Schwarze Gold nun besitzt und ob es[ENTER]bereits bearbeitet wurde. Sobald ich etwas[ENTER]erfahre, werde ich nach dir rufen. Hier, nimm das[ENTER]als Belohnung. Bis bald! "
gameforge.main_quest_lv95._320_sendLetter = "Bearbeitungsprozess aufhalten "
gameforge.main_quest_lv95._330_say = "Geh zu Admiral Angmur. Er hat Neuigkeiten \252ber das[ENTER]Schwarze Gold. "
gameforge.main_quest_lv95._340_say = "Wir haben herausgefunden, dass der Gro\223e Oger den[ENTER]Bearbeitungsprozess des Schwarzen Goldes pers\246nlich[ENTER]\252berwacht und es anschlie\223end der Banshee[ENTER]\252berbringt. "
gameforge.main_quest_lv95._350_say = "Derzeit h\228lt er sich am Gautamakliff auf.[ENTER]Verhindere, dass das Schwarze Gold sein Ziel erreicht. Schnell, ehe es zu sp\228t ist! "
gameforge.main_quest_lv95._360_say = {}
gameforge.main_quest_lv95._370_sayTitle = "Der Gro\223e Oger "
gameforge.main_quest_lv95._380_say = "Besiege das Oberhaupt der Oger und halte die[ENTER]Vollendung des Schwarzen Goldes auf. "
gameforge.main_quest_lv95._390_say = "Jede Minute z\228hlt! Halte den Gro\223en Oger auf! "
gameforge.main_quest_lv95._400_notice = "Du hast den Gro\223en Oger besiegt. "
gameforge.main_quest_lv95._410_say = "Ihr k\246nnt uns nicht aufhalten! Die Banshee hat das[ENTER]Schwarze Gold bereits erhalten. Zu sp\228t, ihr Narren! "
gameforge.main_quest_lv95._420_say = "Die Schlinge zieht sich weiter zu. Kehre zu[ENTER]Admiral Angmur zur\252ck und erstatte ihm Bericht. "
gameforge.main_quest_lv95._430_say = "Sprich mit Admiral Angmur. "
gameforge.main_quest_lv95._440_say = "Das ging schnell! Hast du das Schwarze Gold? "
gameforge.main_quest_lv95._450_say = "Nein, ich kam zu sp\228t. Es ist bereits im Besitz der Banshee. "
gameforge.main_quest_lv95._460_say = "Der Drachengott sei uns gn\228dig. Doch so leicht[ENTER]geben wir uns nicht geschlagen! Ich werde meine[ENTER]Sp\228her auschicken, um den Aufenthaltsort der[ENTER]Banshee ausfindig zu machen. Sobald ich ihn kenne,[ENTER]gebe ich dir Bescheid. Ruhe dich etwas aus und[ENTER]nimm dies als Belohnung. "
gameforge.main_quest_lv95._470_sendLetter = "Fluch des Lebens "
gameforge.main_quest_lv95._480_say = "Admiral Angmur hat neue Informationen f\252r dich.[ENTER]Geh zu ihm. "
gameforge.main_quest_lv95._490_say = "Wir wissen nun, was mit dem Fluch des Lebens und[ENTER]der Armee der Finsternis gemeint ist. Einst lebte[ENTER]ein ruchloser Magier auf dem Fels der Dunklen[ENTER]Drachen. Er strebte die Herrschaft \252ber den[ENTER]gesamten Kontinent an und ging daf\252r buchst\228blich[ENTER]\252ber Leichen: Durch einen schwarzen Zauber, Fluch[ENTER]des Lebens genannt, lie\223 er die Toten auferstehen[ENTER]und als seine Armee in die Schlacht ziehen. "
gameforge.main_quest_lv95._500_say = {}
gameforge.main_quest_lv95._510_say = "Totenbeschw\246rung \150 die blo\223e Vorstellung l\228sst mich erschaudern. Die Diener der Dunkelheit stellen[ENTER]mithilfe des Schwarzen Goldes eine Armee aus Untoten auf. Wir m\252ssen sie aufhalten! "
gameforge.main_quest_lv95._520_say = "Suche bei den alten Ruinen am Gautamakliff nach dem Lemuren-Magier. Er wei\223 etwas \252ber diesen Fluch.[ENTER]Wenn du ihn nett bittest, wird er dir mit Sicherheit alles verraten. "
gameforge.main_quest_lv95._530_say = "Nett bitten, soso. Verstanden. "
gameforge.main_quest_lv95._540_sayTitle = "Fluch des Lebens "
gameforge.main_quest_lv95._550_say = "Besiege den Lemuren-Magier und sammle[ENTER]Informationen \252ber den Fluch des Lebens und die[ENTER]Totenbeschw\246rung. "
gameforge.main_quest_lv95._560_say = "Wir haben keine Zeit zu verlieren. Besiege den[ENTER]Lemuren-Magier und quetsche die Informationen \252ber[ENTER]den Fluch des Lebens aus ihm raus. "
gameforge.main_quest_lv95._570_1_notice = "Du hast den Lemuren-Magier besiegt und eine[ENTER]Steintafel mit einer Inschrift gefunden. "
gameforge.main_quest_lv95._570_2_notice = "Zeige sie Admiral Angmur. "
gameforge.main_quest_lv95._580_say = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv95._590_say = "Aye, der Lemuren-Magier hatte diese Steintafel bei[ENTER]sich? Lass sehen. "
gameforge.main_quest_lv95._600_sayReward = "Drei Dinge sind vonn\246ten, um die Toten erwachen zu[ENTER]lassen:[ENTER]1. ein menschlicher K\246rper[ENTER]2. ...[ENTER]Die Lemurentafel ist hier zerbrochen. Der Rest der[ENTER]Inschrift fehlt. "
gameforge.main_quest_lv95._610_say = "Ich f\252rchte, du wirst noch einmal losziehen[ENTER]m\252ssen. Wir brauchen den Rest dieser Inschrift.[ENTER]Es m\252ssten noch zwei weitere St\252cke der Lemurentafel existieren. "
gameforge.main_quest_lv95._620_say = "Hier ist deine Belohnung f\252r alles, was du bis[ENTER]jetzt erreicht hast. Bitte begib dich nun auf die[ENTER]Suche nach den restlichen Lemurentafeln! "
gameforge.main_quest_lv95._630_sendLetter = "Die Inschrift "
gameforge.main_quest_lv95._640_sayTitle = "Finde die Lemurentafeln! "
gameforge.main_quest_lv95._650_say = "Besiege die Lemuren-Magier und finde die[ENTER]restlichen St\252cke der Steintafel. "
gameforge.main_quest_lv95._660_say = "Bitte, wir m\252ssen wissen, was diese Inschrift[ENTER]besagt. Gib nicht auf! "
gameforge.main_quest_lv95._670_say = "Bringe die beiden fehlenden Bruchst\252cke der[ENTER]Lemurentafel zu Admiral Angmur. "
gameforge.main_quest_lv95._680_say = "Aye, du bist zur\252ck! Lass uns die Lemurentafel[ENTER]zusammensetzen und die Inschrift lesen. "
gameforge.main_quest_lv95._690_sayReward = "Drei Dinge sind vonn\246ten, um die Toten erwachen zu[ENTER]lassen:[ENTER]1. ein menschlicher K\246rper[ENTER]2. Schwarzes Gold[ENTER]3. die Rinde von Baumd\228monen[ENTER]Nur ein Magier mit herausragenden F\228higkeiten kann[ENTER]den Fluch des Lebens hinaufbeschw\246ren und[ENTER]aufrechterhalten. Und wenn er stirbt, f\228llt die[ENTER]gesamte Armee der Untoten mit ihm. "
gameforge.main_quest_lv95._700_say = "Deswegen werden in letzter Zeit unsere Friedh\246fe[ENTER]gesch\228ndet und die Leichen aus den Gr\228bern[ENTER]gestohlen. Sie sollen zum Leben erweckt werden und[ENTER]als untote Armee gegen uns marschieren. Welch[ENTER]abscheuliche Vorstellung! "
gameforge.main_quest_lv95._710_say = "Wir m\252ssen diese frevelhafte Tat aufhalten! "
gameforge.main_quest_lv95._720_say = "Aye, doch die Zeit spielt gegen uns. Nur die[ENTER]Banshee selbst ist m\228chtig genug, um einen Fluch[ENTER]dieser Gr\246\223e zu beschw\246ren \150 doch wir wissen[ENTER]nicht, wo sie sich versteckt. Ich werde noch mehr[ENTER]M\228nner ausschicken, um das Versteck der dunklen[ENTER]Hohepriesterin ausfindig zu machen. Sobald ich[ENTER]Neues erfahre, werde ich dich rufen lassen. "
gameforge.main_quest_lv95._730_say = {}
gameforge.main_quest_lv95._740_say = "Das Abenteuer geht weiter, sobald du Level 96[ENTER]erreicht hast. "
gameforge.main_quest_lv95._750_say = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv95._760_say = "Verbleibend "
gameforge.main_quest_lv95._770_sayReward = "%s : %d "
gameforge.main_quest_lv96 = {}
gameforge.main_quest_lv96._010_sendLetter = "Fluch verhindern "
gameforge.main_quest_lv96._020_say = "Admiral Angmur m\246chte mit dir sprechen. "
gameforge.main_quest_lv96._030_say = "Gut, dass du hier bist. Wir haben einen Weg[ENTER]gefunden, um die Pl\228ne der Diener und der Banshee[ENTER]zu sabotieren. "
gameforge.main_quest_lv96._040_say = {}
gameforge.main_quest_lv96._050_say = {}
gameforge.main_quest_lv96._060_say = "Damit die Seelen der Toten ihre K\246rper freigeben,[ENTER]wird ein Medium ben\246tigt. Hierbei handelt es sich[ENTER]um geweihte Erde, die von den Giganten in S\228cken[ENTER]aufbewahrt wird. Wenn es dir gelingt, 100 S\228cke zu[ENTER]erbeuten, k\246nnen wir den Fluch des Lebens aufhalten. "
gameforge.main_quest_lv96._070_say = "Ich mache mich sofort auf den Weg! "
gameforge.main_quest_lv96._080_sayTitle = "Geweihte Erde "
gameforge.main_quest_lv96._090_say = "Besiege die Giganten und erbeute 100 S\228cke voll[ENTER]geweihter Erde. "
gameforge.main_quest_lv96._100_say = "Die Zeit arbeitet gegen uns. Schnell, beeile dich[ENTER]und erbeute die S\228cke voll geweihter Erde! "
gameforge.main_quest_lv96._110_1_notice = "Du hast alle S\228cke voll geweihter Erde erbeutet. "
gameforge.main_quest_lv96._110_2_notice = "Bringe sie Admiral Angmur. "
gameforge.main_quest_lv96._120_say = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv96._130_say = "Auf dich ist wie immer Verlass! Danke. Bitte nimm[ENTER]dies als Belohnung. "
gameforge.main_quest_lv96._140_sendLetter = "Fluch verhindern "
gameforge.main_quest_lv96._150_say = "Admiral Angmur hat einen weiteren Auftrag f\252r dich. "
gameforge.main_quest_lv96._160_say = "Die Oger bewachen ebenfalls ein Medium f\252r die Totenbeschw\246rung. Doch wir wissen nicht, wie es aussieht. Gehe zu den Ogern und bringe her, was auch immer[ENTER]dir verd\228chtig vorkommt. "
gameforge.main_quest_lv96._170_say = {}
gameforge.main_quest_lv96._180_say = {}
gameforge.main_quest_lv96._190_say = "Verstanden. "
gameforge.main_quest_lv96._200_sayTitle = "Das Medium der Oger "
gameforge.main_quest_lv96._210_say = "Besiege die Oger und finde heraus, welche Form ihr[ENTER]Medium hat. "
gameforge.main_quest_lv96._220_say = "Ich wei\223, du hast nicht viele Anhaltspunkte. Aber[ENTER]irgendetwas muss doch zu finden sein! "
gameforge.main_quest_lv96._230_1_notice = "Du hast einen M\252nzbeutel und einen goldenen Orden[ENTER]gefunden. "
gameforge.main_quest_lv96._230_2_notice = "Bringe beide Gegenst\228nde zu Admiral Angmur. "
gameforge.main_quest_lv96._240_say = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv96._250_say = "Gut gemacht! Ich werde Yon-I-Walker bitten, diese Gegenst\228nde zu analysieren. "
gameforge.main_quest_lv96._260_say = "Suche Yon-I-Walker auf und lass dir das Ergebnis seiner Analysen mitteilen. "
gameforge.main_quest_lv96._270_say = "Ah, da bist du ja. Ich habe bereits einen Blick[ENTER]auf die Gegenst\228nde, die du bei den Ogern gefunden[ENTER]hast, werfen k\246nnen. "
gameforge.main_quest_lv96._280_say = {}
gameforge.main_quest_lv96._290_say = "Von den Goldm\252nzen aus dem Beutel geht[ENTER]eine starke dunkle Kraft aus. Sie sind das Medium.[ENTER]Berichte das Angmur. "
gameforge.main_quest_lv96._300_sendLetter = "Fluch verhindern "
gameforge.main_quest_lv96._310_say = "Gehe zu Admiral Angmur. "
gameforge.main_quest_lv96._320_say = "Hier, nimm das Band des Goldj\228gers. Benutze es, um die M\252nzbeutel der[ENTER]Oger zu ersp\228hen. "
gameforge.main_quest_lv96._330_say = "Wir brauchen 100 Goldm\252nzen. Doch ich f\252rchte,[ENTER]nicht alle, die du finden wirst, werden als Medium[ENTER]verwendet. Es liegt also eine Menge Arbeit vor dir. "
gameforge.main_quest_lv96._340_say = "Kein Problem. "
gameforge.main_quest_lv96._350_sayTitle = "Jagd nach Gold "
gameforge.main_quest_lv96._360_say = "Ziehe gegen die Oger in den Kampf und sammle M\252nzbeutel. Nicht alle Goldm\252nzen darin dienen als Medium \150 lasse sie von Yon-I-Walker pr\252fen. "
gameforge.main_quest_lv96._370_say = "Ja, hier kann ich deutlich die dunkle Magie sp\252ren. "
gameforge.main_quest_lv96._380_say = "Phantastisch, wir haben nun alle Goldm\252nzen, die[ENTER]als Medium dienen k\246nnen. Das wird der Banshee mit[ENTER]Sicherheit nicht gefallen! Hier, nimm das als[ENTER]Belohnung. Angmur wird dir deine n\228chste Aufgabe[ENTER]erteilen. "
gameforge.main_quest_lv96._390_say = "Es fehlen noch Goldm\252nzen. Sammle %d weitere. "
gameforge.main_quest_lv96._400_sendLetter = "Fluch verhindern "
gameforge.main_quest_lv96._410_say = "Admiral Angmur sucht nach dir. "
gameforge.main_quest_lv96._420_say = "Wir m\252ssen daf\252r sorgen, dass die Diener der[ENTER]Dunkelheit die Rinde der Baumd\228monen nicht in ihre[ENTER]H\228nde bekommen. "
gameforge.main_quest_lv96._430_say = "Baumd\228monen geh\246ren zu den r\228tselhaftesten[ENTER]Gattungen unserer Welt und dienen niemandem,[ENTER]nicht einmal Sung Mahi.[ENTER]Am Gautamakliff wandeln drei Arten: Aku-Boku,[ENTER]Arboretum und Sycomor. Ziehe ihnen die Rinde ab! "
gameforge.main_quest_lv96._440_say = {}
gameforge.main_quest_lv96._450_say = "Verstanden. "
gameforge.main_quest_lv96._460_sayTitle = "Baumd\228monen stutzen "
gameforge.main_quest_lv96._470_say = "Ziehe die Rinde eines Aku-Boku, eines Arboretum[ENTER]und eines Sycomor ab. "
gameforge.main_quest_lv96._480_counterName = "Verbleibend "
gameforge.main_quest_lv96._490_say = "%s: %d[ENTER]%s: %d[ENTER]%s: %d "
gameforge.main_quest_lv96._500_say = "Die Zeit dr\228ngt. Mach Kleinholz aus den[ENTER]Baumd\228monen und sichere ihre Rinde, ehe es die[ENTER]Diener tun! "
gameforge.main_quest_lv96._510_1_notice = "Du hast alle Baumd\228monen besiegt, aber jemand ist[ENTER]dir zuvorgekommen: Die Rinde wurde bereits von[ENTER]ihren St\228mmen abgezogen. "
gameforge.main_quest_lv96._510_2_notice = "Berichte Admiral Angmur davon. "
gameforge.main_quest_lv96._520_say = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv96._530_say = "Sch\246n, du bist unversehrt zur\252ck! Hattest du Erfolg?[ENTER]Was?! Die Rinde aller Baumd\228monen war bereits[ENTER]abgezogen und es gab frische Kampfspuren? Dann[ENTER]m\252ssen uns die Diener der Dunkelheit[ENTER]zurvorgekommen sein. "
gameforge.main_quest_lv96._540_say = {}
gameforge.main_quest_lv96._550_say = "Wenn sie die Rinde haben, finden sie bestimmt auch[ENTER]einen Weg, den Fluch des Lebens zu beschw\246ren.[ENTER]Dann ist es also unvermeidbar \150 wir ziehen in den[ENTER]Krieg. Die Banshee wird sich nicht mehr lange vor[ENTER]uns verstecken k\246nnen. Meine M\228nner sind ihr schon[ENTER]auf der Spur. Ich lasse dich rufen, sobald wir sie[ENTER]gefunden haben. "
gameforge.main_quest_lv96._560_sayTitle = "Das Abenteuer geht weiter, sobald du Level 97[ENTER]erreicht hast. "
gameforge.main_quest_lv96._570_counterName = "Verbleibend "
gameforge.main_quest_lv96._580_sayReward = "%s: %d St\252ck "
gameforge.main_quest_lv96._590_say = "Die Goldm\252nzen dienen also als Medium. Gut, dann[ENTER]werde ich mich nun mit Yon-I-Walker \252ber unser[ENTER]weiteres Vorgehen beraten. Ich melde mich gleich[ENTER]wieder bei dir. "
gameforge.main_quest_lv96._600_say = {}
gameforge.main_quest_lv96._610_say = {}
gameforge.main_quest_lv96._620_1_notice = "Du hast einen M\252nzbeutel erhalten. "
gameforge.main_quest_lv96._620_2_notice = "Bringe ihn Yon-I-Walker. "
gameforge.main_quest_lv96._630_say = "Das ist nur eine normale M\252nze, kein Medium. Suche[ENTER]weiter! "
gameforge.main_quest_lv97 = {}
gameforge.main_quest_lv97._010_sendLetter = "Banshee aufhalten "
gameforge.main_quest_lv97._020_say = "Das Versteck der Banshee wurde entdeckt! Gehe zu[ENTER]Admiral Angmur, um mehr zu erfahren. "
gameforge.main_quest_lv97._030_say = "Meine M\228nner haben endlich die Basis der Banshee[ENTER]am Gautamakliff gefunden. Sie hat sich tief in die[ENTER]Dunkelheit der W\228lder dieser Gegend verkrochen und[ENTER]wirkt von dort aus ihre schwarze Magie. Au\223erdem[ENTER]hat sie eine ihrer fr\252heren Tempeldienerinnen des[ENTER]Drachenkultes wiedererweckt. Mit ihr zusammen wird[ENTER]sie den Fluch des Lebens beschw\246ren. "
gameforge.main_quest_lv97._040_say = "Ohne ihre Hilfe wird die Banshee den Fluch nicht[ENTER]aufrechterhalten k\246nnen. Besiege die[ENTER]Tempeldienerin Mu-Shu und bes\228nftige die Seelen[ENTER]unserer Kameraden, ehe ihre K\246rper sich gegen uns[ENTER]erheben. "
gameforge.main_quest_lv97._050_say = "Es ist fast unm\246glich, sich der Tempeldienerin[ENTER]unbemerkt zu n\228hern, um sie anzugreifen. Nutze den[ENTER]Moment, wenn sie so in ihren dunklen Zauber[ENTER]vertieft ist, dass sie in eine Trance verf\228llt! "
gameforge.main_quest_lv97._060_say = "In Ordnung. "
gameforge.main_quest_lv97._070_say = "Sieh dich vor! Zu Lebzeiten war sie die erste[ENTER]Leibw\228chterin der Hohepriesterin und nicht nur in[ENTER]der Magie, sondern auch im Schwertkampf bestens[ENTER]ausgebildet. "
gameforge.main_quest_lv97._080_sayTitle = "Die Tempeldienerin "
gameforge.main_quest_lv97._090_say = "Besiege Mu-Shu, die Tempeldienerin der Banshee,[ENTER]am Gautamakliff. "
gameforge.main_quest_lv97._100_notice = "T\246dlich getroffen, sinkt die Tempeldienerin zu Boden. "
gameforge.main_quest_lv97._110_say = "Ihr Narren! Bereitwillig habt ihr den K\246der[ENTER]geschluckt, den die Banshee f\252r euch ausgelegt[ENTER]hat. W\228hrend du deine Zeit mit mir vergeudet hast,[ENTER]haben die Herrin und Yah-Ki, die wahre Tempeldienerin, den[ENTER]Fluch schon begonnen. Ich bete daf\252r, dass er[ENTER]gelingt! "
gameforge.main_quest_lv97._120_say = "Eine Doppelg\228ngerin hat euch auf die falsche[ENTER]F\228hrte gelockt! Nachdem du sie durchsuchst hast,[ENTER]findest du ein \228hnliches Halsband wie zuvor bei[ENTER]Martyaxwar. In der Innentasche befindet sich ein[ENTER]Dokument. "
gameforge.main_quest_lv97._130_say = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv97._140_say = "Du bist zur\252ck! Ist die Tempeldienerin besiegt? "
gameforge.main_quest_lv97._150_say = "Nein, wir sind von einer Doppelg\228ngerin get\228uscht[ENTER]worden. Die echte Tempeldienerin konnte[ENTER]in Ruhe die Totenbeschw\246rung vorbereiten. Hier,[ENTER]dieses Dokument habe ich gefunden. "
gameforge.main_quest_lv97._160_say = "Verflucht! Wie konnten wir nur auf ihre Spielchen[ENTER]reinfallen?! Bitte zeige mir das Dokument. "
gameforge.main_quest_lv97._170_say = {}
gameforge.main_quest_lv97._180_say = {}
gameforge.main_quest_lv97._190_say = "Hm, verschl\252sselt. Aber vielleicht verr\228t uns[ENTER]diese Nachricht, wo sich ihre Basis tats\228chlich[ENTER]befindet. Schriftzeichen wie diese habe ich doch[ENTER]schon einmal gesehen ... Ich glaube, Yak-Hwan, der[ENTER]Palastw\228chter, hat mir erst k\252rzlich etwas[ENTER]\196hnliches gezeigt. Gehe zu ihm. Er soll einen[ENTER]Blick darauf werfen. "
gameforge.main_quest_lv97._200_sendLetter = "Dokument entschl\252sseln "
gameforge.main_quest_lv97._210_say = "Gehe zu Yak-Hwan und zeige ihm das verschl\252sselte[ENTER]Dokument. "
gameforge.main_quest_lv97._220_say = "Sei gegr\252\223t! Mein Name ist Yak-Hwan. Es ist mir[ENTER]eine Ehre, dich kennenzulernen. Deine Taten sind[ENTER]bereits legend\228r! Was kann ich f\252r dich tun? Ah,[ENTER]eine verschl\252sselte Nachricht. Lass mich mal sehen. "
gameforge.main_quest_lv97._230_say = "Ja, diese Schriftzeichen sollte ich problemlos[ENTER]entschl\252sseln k\246nnen. Doch daf\252r ben\246tige ich[ENTER]Fossilerde. Der Alchemist m\252sste noch einen[ENTER]Klumpen davon haben. Bitte frage ihn danach. "
gameforge.main_quest_lv97._240_say = {}
gameforge.main_quest_lv97._250_say = {}
gameforge.main_quest_lv97._260_say = "Nat\252rlich. "
gameforge.main_quest_lv97._270_sayTitle = "Fossilerde "
gameforge.main_quest_lv97._280_say = "Gehe zum Alchemisten und frage ihn nach der[ENTER]Fossilerde. "
gameforge.main_quest_lv97._290_say = "Hast du nicht was vergessen? Du solltest mir doch[ENTER]die Fossilerde bringen. "
gameforge.main_quest_lv97._300_notice = "Der Alchemist hat dir die Fossilerde gegeben. Gehe[ENTER]nun zur\252ck zu Yak-Hwan. "
gameforge.main_quest_lv97._310_say = "Ah, die Fossilerde. Sehr gut, dann mache ich mich[ENTER]jetzt ans Werk. Das Ergebnis werde ich dem Admiral[ENTER]mitteilen. "
gameforge.main_quest_lv97._320_sendLetter = "Durch die Hintert\252r "
gameforge.main_quest_lv97._330_say = "Admiral Angmur sucht nach dir. "
gameforge.main_quest_lv97._340_say = "Wir kennen nun den Aufenthaltsort der[ENTER]Tempeldienerin Yah-Ki. Doch die Basis gleicht einer[ENTER]Festung \150 Wachtruppen patroullieren dort rund um[ENTER]die Uhr. Ein Frontalangriff w\228re zu diesem[ENTER]Zeitpunkt reiner Selbstmord. "
gameforge.main_quest_lv97._350_say = "Deswegen wollen wir aus dem Hinterhalt angreifen.[ENTER]Meine M\228nner sind auf der Suche nach einer[ENTER]geeigneten Stelle. Lenke die Wachen ab,[ENTER]um uns mehr Zeit zu verschaffen. "
gameforge.main_quest_lv97._360_say = {}
gameforge.main_quest_lv97._370_say = "Die gr\246\223te Gefahr geht von einem Wachtrupp, der[ENTER]sich die Brigade des Schwarzen Todes nennt, aus.[ENTER]Diese Brigade besteht aus Moghu, Carnifex und[ENTER]General Albus. Ihr Anf\252hrer ist Skeletos.[ENTER]Beseitige sie, bevor sie meinen Sp\228htrupp entdecken. "
gameforge.main_quest_lv97._380_say = "Alles klar. "
gameforge.main_quest_lv97._390_sayTitle = "Brigade des Schwarzen Todes "
gameforge.main_quest_lv97._400_say = "Beseitige die Brigade des Schwarzen Todes,[ENTER]bestehend aus Moghu, Carnifex, General Albus und[ENTER]Skeletos. "
gameforge.main_quest_lv97._410_say = "Erledige die Mitglieder der Brigade des Schwarzen[ENTER]Todes, bevor sie den Sp\228htrupp entdecken. "
gameforge.main_quest_lv97._420_say = "Erstatte Admiral Angmur Bericht. "
gameforge.main_quest_lv97._430_say = "Unser Plan ist aufgegangen! W\228hrend du die Brigade[ENTER]des Schwarzen Todes abgelenkt hast, haben meine[ENTER]M\228nner eine geeignete Stelle f\252r einen Hinterhalt[ENTER]ausgemacht. Sobald unsere Angriffsstrategie steht,[ENTER]lasse ich dich rufen. "
gameforge.main_quest_lv97._440_sendLetter = "Die Tempeldienerin "
gameforge.main_quest_lv97._450_say = "Admiral Angmur ben\246tigt deine Hilfe! "
gameforge.main_quest_lv97._460_say = "Gut, du bist hier. Skeletos, Anf\252hrer der Brigade[ENTER]des Schwarzen Todes, hat \252berlebt und meine[ENTER]M\228nner angegriffen, als sie gerade die Basis[ENTER]st\252rmen wollten. Niemand kommt an ihm vorbei. "
gameforge.main_quest_lv97._470_say = {}
gameforge.main_quest_lv97._480_say = "Du hast ihn schon einmal besiegt, also bitte hilf[ENTER]meinen Leuten am Gautamakliff! Tritt gegen[ENTER]Skeletos an. St\252rme anschlie\223end die Basis[ENTER]und t\246te die Tempeldienerin Yah-Ki. "
gameforge.main_quest_lv97._490_say = "Verstanden! "
gameforge.main_quest_lv97._500_say = {}
gameforge.main_quest_lv97._510_sayTitle = "Yah-Ki vernichten "
gameforge.main_quest_lv97._520_say = "Besiege die Tempeldienerin Yah-Ki und halte sie[ENTER]davon ab, die Armee der Toten zu beschw\246ren. "
gameforge.main_quest_lv97._530_say = "Der Tag der Entscheidung ist gekommen. Wenn wir[ENTER]fallen, f\228llt die ganze Welt. Doch wenn wir[ENTER]siegreich sind, werden unsere Taten noch[ENTER]Jahrhunderte sp\228ter in Liedern besungen werden.[ENTER]Halte die Diener der Dunkelheit auf. Vernichte die[ENTER]Tempeldienerin Yah-Ki! "
gameforge.main_quest_lv97._540_say = "Warum bist du hier? Der Kampf ist noch nicht[ENTER]gewonnen! Besiege die Tempeldienerin Yah-Ki. All[ENTER]unsere Hoffnungen liegen auf dir. "
gameforge.main_quest_lv97._550_1_notice = "Du hast deinen Gegner in die Knie gezwungen und der Sieg ist dein! "
gameforge.main_quest_lv97._550_2_notice = "Dir bleibt keine Zeit zum Ausruhen \150 die[ENTER]Tempeldienerin Yah-Ki erwartet dich schon. "
gameforge.main_quest_lv97._560_notice = "Du hast gesiegt! Mit einem markersch\252tternden Schrei sinkt Yah-Ki zu Boden. "
gameforge.main_quest_lv97._570_say = "Ahhhhh! Das kann nicht sein! Geschlagen von einem[ENTER]Sterblichen ... Oh, Banshee, verzeih! Ich habe[ENTER]versagt. Meine Aufgabe konnte ich nicht erf... "
gameforge.main_quest_lv97._580_say = "Du durchsuchst ihren leblosen K\246rper und findest[ENTER]einen versiegelten Brief. Kehre damit zu Admiral[ENTER]Angmur zur\252ck. "
gameforge.main_quest_lv97._590_say = "Aye, dem Drachengott sei Dank! Du bist unversehrt[ENTER]zur\252ck. Hast du die Tempeldienerin besiegt? "
gameforge.main_quest_lv97._600_say = "Ja, ich habe sie wieder in die H\246lle[ENTER]zur\252ckbef\246rdert, aus der sie gekrochen kam. Im[ENTER]Sterben hat sie die Banshee um Vergebung f\252r ihr[ENTER]Versagen angefleht. Das trug sie bei sich. "
gameforge.main_quest_lv97._610_say = "Einen versiegelten Brief. Zeig her! "
gameforge.main_quest_lv97._620_sayReward = "Meine Herrin,[ENTER]sie haben unseren K\246der geschluckt und Euer Plan[ENTER]ist aufgegangen. Die Beschw\246rung Eurer untoten[ENTER]Armee schreitet voran und niemand wird uns jetzt[ENTER]noch aufhalten k\246nnen. Wenn die seelenlosen K\246rper[ENTER]erst marschieren, ziehen wir gegen das Kap des[ENTER]Drachenfeuers und werden seine Bewohner unter uns[ENTER]begraben. Anschlie\223end werden wir zum Festland[ENTER]hin\252bersetzen und Euch im Feuerland treffen. Die[ENTER]Welt wird unter unseren Schritten brennen![ENTER]Ich verneige mich tief[ENTER]Eure ewige Dienerin "
gameforge.main_quest_lv97._630_say = "Eine Botschaft an die Banshee! Aye, die[ENTER]sch\228ndliche Hexe wartet im Feuerland nun vergebens[ENTER]auf ihre Armee der Finsternis.[ENTER]Ich danke dir. Ohne deine Hilfe w\228re das Kap und[ENTER]seine Bewohner von dem Heer der Untoten dem[ENTER]Erdboden gleichgemacht worden. Du hast nicht nur[ENTER]uns gerettet, sondern auch den Seelenfrieden[ENTER]unserer Ahnen wiederhergestellt. Diese Belohnung[ENTER]\252berreiche ich dir stellvertretend f\252r das ganze[ENTER]Fort. "
gameforge.main_quest_lv97._640_sayTitle = "Das Abenteuer geht weiter, sobald du Level 98[ENTER]erreicht hast. "
gameforge.main_quest_lv97._650_say = "Wir haben lange gebraucht, um die Basis ausfindig[ENTER]zu machen. Bitte, wir d\252rfen nicht noch mehr Zeit[ENTER]verlieren! "
gameforge.main_quest_lv97._660_say = "Braucht Yak-Hwan Fossilerde? Was f\252r ein Gl\252ck,[ENTER]dass ich sie noch nicht verbraucht habe. Hier,[ENTER]bitte sehr. Nun bringe sie ihm und richte einen[ENTER]sch\246nen Gru\223 von mir aus. "
gameforge.main_quest_lv97._670_counterName = "Verbleibend "
gameforge.main_quest_lv97._680_sayReward = "%s: %d[ENTER]%s: %d "
gameforge.main_quest_lv97._690_1_notice = "Du hast die Brigade des Schwarzen Todes vernichtet. "
gameforge.main_quest_lv97._690_2_notice = "Erstatte nun Admiral Angmur Bericht. "
gameforge.main_quest_lv97._700_sayTitle = "Besiege Skeletos, Anf\252hrer der Brigade[ENTER]des Schwarzen Todes! "
gameforge.main_quest_lv97._710_say = "Die Tempeldienerin kann erst endg\252ltig vernichtet[ENTER]werden, wenn du Skeletos besiegt hast. "
gameforge.main_quest_lv98 = {}
gameforge.main_quest_lv98._010_sendLetter = "Wiederaufbau des Forts "
gameforge.main_quest_lv98._020_say = "Admiral Angmur bittet um deine Hilfe. Gehe zu ihm. "
gameforge.main_quest_lv98._030_say = "Danke, dass du gekommen bist. Der Kampf ist nicht[ENTER]spurlos an uns vorbeigezogen. Auch das Fort wurde[ENTER]angegriffen und der Schutzwall an vielen Stellen[ENTER]niedergerissen. Dieser Frieden wird nicht lange[ENTER]w\228hren. Wir sollten die Ruhe f\252r den Wiederaufbau[ENTER]nutzen. "
gameforge.main_quest_lv98._040_say = "Um den Schutzwall zu befestigen, ben\246tigen wir die[ENTER]Panzer des Krustenstammes. "
gameforge.main_quest_lv98._050_say = "Verstanden. Wie viele dieser Panzer braucht ihr? "
gameforge.main_quest_lv98._060_say = "100 St\252ck sollten ausreichen. Der Krustenstamm[ENTER]haust noch immer in der Nephritbucht. "
gameforge.main_quest_lv98._070_say = "Aye, das sind noch nicht genug Krustenpanzer.[ENTER]Bitte sammle noch mehr. "
gameforge.main_quest_lv98._080_1_notice = "Du hast nun alle Krustenpanzer gesammelt. "
gameforge.main_quest_lv98._080_2_notice = "Bringe sie zu Admiral Angmur. "
gameforge.main_quest_lv98._090_say = "Aye, sehr gut. Mit den Krustenpanzern k\246nnen wir[ENTER]den Schutzwall wieder befestigen. Bitte nimm dies[ENTER]als Belohnung. Ich werde meine Ingenieure fragen,[ENTER]ob sie noch weitere Materialien ben\246tigen, und dir[ENTER]dann Bescheid geben. "
gameforge.main_quest_lv98._130_sendLetter = "Wiederaufbau des Forts "
gameforge.main_quest_lv98._140_say = "Admiral Angmur braucht noch einmal deine Hilfe.[ENTER]Gehe zu ihm. "
gameforge.main_quest_lv98._150_say = "Zur weiteren Befestigung ben\246tigen wir[ENTER]Tritonspeere. Wie der Name schon sagt, findest du[ENTER]sie bei den Tritonen. Bitte bringe mir 100 St\252ck. "
gameforge.main_quest_lv98._160_say = "Verstanden. "
gameforge.main_quest_lv98._170_say = "Da bist du ja! Aye, aber das sind noch nicht genug[ENTER]Tritonspeere. Bitte sammle weiter. "
gameforge.main_quest_lv98._180_1_notice = "Du hast alle Tritonspeere gesammelt. "
gameforge.main_quest_lv98._180_2_notice = "Bringe sie Admiral Angmur. "
gameforge.main_quest_lv98._190_say = "Perfekt! Nun k\246nnen wir eine sichere[ENTER]Verteidigungsanlage bauen. Ich danke dir f\252r deine[ENTER]Hilfe. \220brigens sucht Yak-Hwan nach dir. Finde[ENTER]heraus, was er m\246chte. "
gameforge.main_quest_lv98._200_sendLetter = "Notstand "
gameforge.main_quest_lv98._210_say = "Gehe zu Yak-Hwan. Er hat eine wichtige Aufgabe f\252r[ENTER]dich. "
gameforge.main_quest_lv98._220_say = "Ah, sehr gut, du bist hier! Wir sind ein weiteres[ENTER]Mal auf deine Hilfe angewiesen. "
