gameforge.main_quest_lv98._240_say = {}
gameforge.main_quest_lv98._250_say = {}
gameforge.main_quest_lv98._260_say = "Die harte Zeit des Krieges ist nicht spurlos an[ENTER]den Bewohnern des Forts vorbeigezogen. Sie leiden[ENTER]Hunger und mit jedem Tag wird ihr Elend gr\246\223er.[ENTER]Wenn wir nicht bald etwas unternehmen, sieht es[ENTER]nicht gut f\252r sie aus. "
gameforge.main_quest_lv98._270_say = {}
gameforge.main_quest_lv98._280_say = "Ogerbanden lauern unseren Versorgungstransporten[ENTER]auf und greifen sie an. Wir m\252ssen diesen[ENTER]Pl\252nderern Einhalt gebieten. Kapit\228n Shrack und[ENTER]seine Gener\228le stecken dahinter. T\246te den Kapit\228n[ENTER]der Oger und 50 Gener\228le Ogg! "
gameforge.main_quest_lv98._290_say = {}
gameforge.main_quest_lv98._300_say = "Bist du schon zur\252ck? Es sind aber noch immer[ENTER]einige Oger unterwegs. Erledige bitte alle! "
gameforge.main_quest_lv98._310_1_notice = "Du hast alle Oger besiegt. "
gameforge.main_quest_lv98._310_2_notice = "Kehre nun zu Yak-Hwan zur\252ck. "
gameforge.main_quest_lv98._320_say = "Endlich erreichen die Lebensmitteltransporte das[ENTER]Fort und unsere B\252rger k\246nnen mit Nahrung und[ENTER]Medikamenten versorgt werden! Die Not hat ein[ENTER]Ende. Du bist wahrlich ein Held. "
gameforge.main_quest_lv98._330_sendLetter = "Danksagung "
gameforge.main_quest_lv98._340_say = "Yak-Hwan m\246chte mit dir sprechen. "
gameforge.main_quest_lv98._350_say = "Dank deiner Hilfe ist die Gefahr auf dem Fels der[ENTER]Dunklen Drachen einstweilen gebannt. Hierf\252r[ENTER]m\246chten dir seine Bewohner gerne pers\246nlich ihren[ENTER]Dank aussprechen. "
gameforge.main_quest_lv98._360_say = "Drehe doch bitte eine Runde durch das Fort und[ENTER]sprich mit den Leuten. "
gameforge.main_quest_lv98._370_say = {}
gameforge.main_quest_lv98._380_say = "Danke. Ich werde nun alle Bewohner besuchen. "
gameforge.main_quest_lv98._390_say = "Nicht alle B\252rger hatten die Chance, dir zu[ENTER]danken. Sie werden sehr entt\228uscht sein. Bitte[ENTER]stelle sicher, dass du keinen vergisst. "
gameforge.main_quest_lv98._400_say = "Mut und Weisheit teilen sich dein Herz[ENTER]gleicherma\223en. Deine Taten werden noch[ENTER]Generationen sp\228ter besungen werden. Ich verneige[ENTER]mich vor dir. "
gameforge.main_quest_lv98._410_say = "M\246gest du stets gegen alle Gefahren gut gewappnet[ENTER]sein! "
gameforge.main_quest_lv98._420_say = "Du wirst f\252r alle Zeit einen Ehrenplatz in unseren[ENTER]Herzen haben. "
gameforge.main_quest_lv98._430_say = "Das waren turbulente Zeiten, nicht wahr? Ich bin[ENTER]mir sicher, der Drachengott pers\246nlich hat deine[ENTER]Wege auf unsere Insel geleitet. "
gameforge.main_quest_lv98._440_1_notice = "Du hast mit allen Bewohnern gesprochen. "
gameforge.main_quest_lv98._440_2_notice = "Kehre nun zu Yak-Hwan zur\252ck. "
