gameforge.manwoo._10_npcChat = "Die Fischzucht "
gameforge.manwoo._20_sayTitle = "Fischer: "
gameforge.manwoo._30_say = "Ich will meine Fischzucht erweitern. Deshalb[ENTER]brauche ich lebende Karpfen. Diese Fische eignen[ENTER]sich gut f\252r die Zucht und sind bei Anglern sehr[ENTER]beliebt. Aber sie sind nicht leicht zu fangen. "
gameforge.manwoo._40_say = "Wenn du mir ein Karpfen bringst, werde ich dich[ENTER]belohnen. Ich habe eine Truhe, die steht schon[ENTER]seit Ewigkeiten auf meinem Speicher. Ich wei\223[ENTER]nicht mehr, was sie enth\228lt. Vielleicht etwas[ENTER]Nutzloses, vielleicht etwas Wertvolles. Es[ENTER]k\246nnen sich aber auch Monster in ihr versteckt[ENTER]haben.[ENTER]Wenn du sie haben m\246chtest, dann bringe[ENTER]mir einen lebenden Karpfen. "
gameforge.manwoo._50_npcChat = "Tausche Karpfen gegen Truhe "
gameforge.manwoo._60_say = "Du bringst mir einen Karpfen f\252r meine[ENTER]Fischzucht? Ich danke dir! Hier ist die[ENTER]versprochene Truhe. Viel Gl\252ck! "
gameforge.manwoo._70_sayReward = "Du hast eine Truhe erhalten![ENTER]\214ffne sie mit einem Rechtsklick. "
