gameforge.map_warp._260_npcChat = "Fels der Dunklen Drachen "
gameforge.map_warp._270_say = "Vor kurzem wurde eine geheimnisvolle Insel[ENTER]entdeckt. Sie wird der Fels der Dunklen Drachen[ENTER]genannt. Doch wer dort \252berleben m\246chte, muss[ENTER]einiges an Erfahrung besitzen. Aus diesem Grund[ENTER]werde ich nur K\228mpfer ab Level 90 hinbringen.[ENTER]Bist du bereit, diese Reise anzutreten? "
