gameforge.map_warp._280_sayReward = "Diese Reise kostet dich %d Yang. "
gameforge.map_warp._30_say = "Dies ist eine faszinierende Gegend. Aber passiert[ENTER]hier denn auch mal etwas Au\223ergew\246hnliches? Wohl[ENTER]eher nicht. In anderen Teilen des Landes sieht es[ENTER]mitunter ganz anders aus! Es gibt daher sicher[ENTER]einen interessanten Ort, an den ich dich[ENTER]teleportieren k\246nnte. Da jedoch die Kr\228fte des[ENTER]B\246sen wieder st\228rker geworden sind, wurden Raum[ENTER]und Zeit ins Chaos gest\252rzt. Deshalb kann es[ENTER]passieren, dass deine R\252ckkehr nicht[ENTER]funktioniert. M\246chtest du dennoch teleportiert[ENTER]werden? "
gameforge.map_warp._40_say = "Hm... Mit deinem derzeitigen Level bist du noch[ENTER]zu schwach f\252r die Reise durch Zeit und Raum.[ENTER]Komm wieder, wenn du h\246her als Level 10[ENTER]bist. "
