gameforge.marriage_manage._990_say = "Da du dir sicher bist, werde ich die Scheidung[ENTER]nun vollziehen. Ich w\252nsche euch dennoch alles[ENTER]Gute f\252r die Zukunft. "
gameforge.mining = {}
