gameforge.neutral_warp = {}
gameforge.neutral_warp._10_npcChat = "Hallo! "
gameforge.neutral_warp._20_sayTitle = "Alter Mann: "
gameforge.neutral_warp._30_say = "Hallo![ENTER]Ich wei\223, wie man von hier in eine andere Region[ENTER]kommt. Wenn du mir etwas Yang gibst, kann ich[ENTER]dich dorthin transportieren. "
gameforge.neutral_warp._40_say = "Wohin m\246chtest du?[ENTER]Das kostet dich %s Yang. "
gameforge.neutral_warp._50_select = "Berg Sohan "
gameforge.neutral_warp._60_select = "Doyyumhwan "
gameforge.neutral_warp._65_npcChat = "Ich m\246chte zur Schwester der Alten Frau. "
gameforge.neutral_warp._70_say = "Die Alte Frau hat mir schon gesagt, dass du[ENTER]kommen w\252rdest. Sie sagte, ich solle dir nichts[ENTER]berechnen f\252r diese Reise, weil du ihr einen[ENTER]Gefallen tust. Wir trinken \246fter mal einen Tee[ENTER]zusammen und ich mache das gern f\252r sie. Aber[ENTER]bilde dir nicht ein, dass das auch in Zukunft so[ENTER]bleibt![ENTER]Pass auf dich auf dort dr\252ben, Angeh\246rige fremder[ENTER]Reiche sind nicht unbedingt gern gesehen. "
gameforge.new_christmas = {}
gameforge.new_christmas._010_npcChat = "Ho ho ho! "
gameforge.new_christmas._020_say = "Ah, du bist es![ENTER]Wir haben uns ja schon lange nicht mehr gesehen.[ENTER]Es ist nun schon ein Jahr her, ho ho![ENTER]Vielleicht fragst du dich, warum ich wieder im[ENTER]Dorf bin.[ENTER]Ich will es dir erkl\228ren \133 "
gameforge.new_christmas._030_say = "Die Zeiten sind hart. Niemand m\246chte in diesen[ENTER]Tagen B\252cher oder andere Sachen kaufen.[ENTER]Und in meinem fortgeschrittenen Alter ist es viel[ENTER]zu m\252hselig, st\228ndig im Rentierschlitten durch[ENTER]die L\252fte zu fliegen. Deswegen habe ich[ENTER]beschlossen, Weihnachten dieses Jahr hier im Dorf[ENTER]zu feiern. "
gameforge.new_christmas._040_say = "Wenn du noch Fragen hast, kannst du jederzeit[ENTER]zu mir kommen. Fr\246hliche Weihnachten! "
gameforge.new_christmas._050_npcChat = "M\246chtest du einen Gl\252hwein? "
gameforge.new_christmas._060_say = "Ho ho ho! Du wei\223t doch bestimmt, was das ist,[ENTER]oder? Es gibt kein besseres Getr\228nk f\252r die[ENTER]Winterzeit! Man nehme einen guten Wein, eine[ENTER]Prise Zimt, ein paar Nelken \133 mmmmmh! "
gameforge.new_christmas._070_say = "Bei dieser K\228lte wird dir ein Schluck Gl\252hwein[ENTER]guttun! Er verleiht dir Kraft und du kannst dich[ENTER]schneller bewegen. M\246chtest du probieren? Sehr[ENTER]sch\246n, er kommt sofort! "
gameforge.new_christmas._080_say = "Der Gl\252hwein scheint dir gut zu schmecken, ho ho![ENTER]Sp\252rst du, wie er dich von innen w\228rmt? Und[ENTER]dieser Geschmack, so s\252\223 und fruchtig. Fr\246hliche[ENTER]Weihnachten! "
gameforge.new_christmas._090_npcChat = "Mehr Gl\252hwein, bitte! "
gameforge.new_christmas._100_say = "Ah, Moment![ENTER]Eine Kleinigkeit habe ich vergessen![ENTER]Gl\252hwein kann ich dir nur einmal am Tag[ENTER]zubereiten, f\252r mehr reichen meine Zutaten nicht[ENTER]aus. Und er ist nur 20 Stunden haltbar. In einer[ENTER]Flasche sind jeweils 6 Portionen, die Wirkung[ENTER]eines Schlucks h\228lt 30 Minuten an. Teile ihn dir[ENTER]also gut ein! "
gameforge.new_christmas._110_say = "Bitte sehr! Du hast lange genug darauf warten[ENTER]m\252ssen. Dieses wunderbare Getr\228nk wird dir Fl\252gel[ENTER]verleihen, ho ho ho! So, lass es dir[ENTER]schmecken. Fr\246hliche Weihnachten! "
gameforge.new_christmas._120_say = "Was, du m\246chtest noch mehr?[ENTER]Tut mir leid, aber du hast genug getrunken. Seit[ENTER]deiner letzten Portion Gl\252hwein sind noch keine[ENTER]24 Stunden vergangen. Zu viel davon ist nicht gut[ENTER]f\252r dich! Komm sp\228ter wieder.[ENTER]Dennoch ein frohes Fest! "
gameforge.new_christmas_gift_box = {}
gameforge.new_christmas_gift_box._010_say = "Von %d kannst du noch %d auspacken. "
gameforge.new_christmas_gift_box._020_say = "Packe in %d Min. das n\228chste Geschenk aus. "
gameforge.new_christmas_sock = {}
gameforge.new_christmas_sock._010_npcChat = "Was ist mit den Socken? "
gameforge.new_christmas_sock._020_say = "Die Socken! Beinahe h\228tte ich sie vergessen! Ich[ENTER]wollte meine Geschenke in den Socken, die \252ber[ENTER]die Kamine geh\228ngt wurden, verstecken. Aber[ENTER]unweihnachtliche Kreaturen haben alle gestohlen![ENTER]Hilf mir dabei, sie zur\252ckzuholen. "
gameforge.new_christmas_sock._030_say = "Socken sind gar nicht so leicht zu finden. Du[ENTER]wirst das Rentierjunge brauchen, um welche[ENTER]aufzusp\252ren. "
gameforge.new_christmas_sock._040_say = "Ist es nicht niedlich?[ENTER]Und es hat einen ausgezeichneten Geruchssinn. Ein[ENTER]Spezialist im Sockenfinden![ENTER]Es bleibt 2 Stunden lang bei dir und hilft dir[ENTER]bei der Suche. Danach ist es m\252de und kann[ENTER]erst nach 24 Stunden weitermachen.[ENTER]Wenn du nicht so lange warten m\246chtest, dann[ENTER]schau mal unten links hinter der drehenden M\252nze[ENTER]- ich habe geh\246rt, da wartet ein weiteres[ENTER]Rentierjunges. Ich freue mich aber auch, wenn du[ENTER]mich morgen wieder besuchen kommst! "
gameforge.new_christmas_sock._050_npcChat = "Ich bringe dir Socken! "
gameforge.new_christmas_sock._060_say = "Bring mir mindestens 5 Socken, dann[ENTER]erh\228ltst du eine Belohnung.[ENTER]Urrgh, der Geruch von getragenen Socken ist[ENTER]unertr\228glich! Komm wieder, wenn du gen\252gend[ENTER]gesammelt hast. Fr\246hliche Weihnachten! "
gameforge.new_christmas_sock._070_say = "Ho ho ho, du hast gen\252gend Socken gesammelt.[ENTER]Dann lass mich mal sehen.[ENTER]Urrgh, dieser Geruch \133 Das sind auf jeden Fall[ENTER]die richtigen Socken![ENTER]Fr\246hliche Weihnachten! "
gameforge.new_christmas_sock._080_npcChat = "Rentierjunges "
gameforge.new_christmas_sock._090_say = "Heute hast du bereits ein Rentierjunges-Siegel[ENTER]von mir erhalten. Ich f\252rchte, das kleine Rentier[ENTER]braucht jetzt eine Pause. Es kann erst[ENTER]morgen weitersuchen. Wenn du nicht so lange[ENTER]warten m\246chtest, dann[ENTER]schau mal unten links hinter der drehenden M\252nze[ENTER]- ich habe geh\246rt, da wartet ein weiteres[ENTER]Rentierjunges. Ich freue mich aber auch, wenn du[ENTER]mich morgen wieder besuchen kommst! "
gameforge.new_christmas_sock._100_say = "Du hast mir heute schon deine Socken gebracht.[ENTER]Denke daran, dass du nur alle 24 Stunden welche[ENTER]abgeben kannst. "
gameforge.new_quest_lv17 = {}
gameforge.new_quest_lv17._010_target = "Wonda-Rim "
gameforge.new_quest_lv17._012_say_title = "Wonda-Rim: "
gameforge.new_quest_lv17._020_say_title = "Das Geschenk f\252r Chaegirab "
gameforge.new_quest_lv17._021_say = "Mein Onkel Chaegirab hat sein Leben der[ENTER]Wissenschaft verschrieben und steckt all sein[ENTER]Yang in die Forschung. Er war stets gut zu mir,[ENTER]daher m\246chte ich ihn mit einem Geschenk[ENTER]\252berraschen. W\252rdest du zu Uriel gehen und ihn[ENTER]fragen, ob er eine Idee hat? Er ist der alte[ENTER]Lehrer meines Onkels und kennt ihn sehr gut. "
gameforge.new_quest_lv17._030_say = "Aber verrate meinem Onkel nichts! "
gameforge.new_quest_lv17._031_say = "Wirst du mir helfen? "
gameforge.new_quest_lv17._039_say_title = "Uriel: "
gameforge.new_quest_lv17._040_say_title = "Sprich mit Uriel "
gameforge.new_quest_lv17._040_target = "Uriel "
gameforge.new_quest_lv17._041_say = "Sprich mit Uriel \252ber seinen ehemaligen Sch\252ler[ENTER]Chaegirab. "
gameforge.new_quest_lv17._042_say = "Uriel befindet sich in %s. "
gameforge.new_quest_lv17._050_say_title = "Wonda-Rim m\246chte Chaegirab beschenken... "
gameforge.new_quest_lv17._051_say = "Des Forschers Freude ist schlicht und einfach die[ENTER]Forschung. Du wirst Chaegirab die gr\246sste Freude[ENTER]machen, wenn du seine Arbeit unterst\252tzt. Der[ENTER]Mu-Rang-Wolf ist ein seltener Gast in unseren[ENTER]Landen, sein Fell die Freude eines jeden[ENTER]Biologen. F\252nf Felle sollten gen\252gen. Sag das[ENTER]Wonda-Rim. "
gameforge.new_quest_lv17._052_say = "Ein solches Fell w\252rde den Biologen sicher[ENTER]beeindrucken. "
gameforge.new_quest_lv17._060_select = "Ja, ich werde es ihm sagen. "
gameforge.new_quest_lv17._065_say_title = "Zur\252ck zu Wonda-Rim "
gameforge.new_quest_lv17._066_say = "Uriel hatte eine gute Idee, was man Chaegirab[ENTER]schenken k\246nnte. Geh zur\252ck zu Wonda-Rim und[ENTER]berichte ihm davon. "
gameforge.new_quest_lv17._067_say = "Wonda-Rim befindet sich in %s. "
gameforge.new_quest_lv17._070_say = "Der Rat Uriels klingt gut. Da ich meinen Onkel[ENTER]Chaegirab wirklich \252berraschen m\246chte, muss ich[ENTER]an diese Felle gelangen. Kannst du losziehen und[ENTER]5 Mu-Rangs f\252r mich t\246ten? "
gameforge.new_quest_lv17._071_say = "Ich soll Mu-Rang-W\246lfe t\246ten, um an ihre Felle zu[ENTER]gelangen. "
gameforge.new_quest_lv17._072_say = "5 St\252ck reichen f\252r ein gutes Geschenk. "
gameforge.new_quest_lv17._073_say = "Los geht's! "
gameforge.new_quest_lv17._074_notice = "Du hast ein gut erhaltenes Fell erbeutet. "
gameforge.new_quest_lv17._075_say = "Jage Mu-Rang-W\246lfe und erbeute ihre Felle. "
gameforge.new_quest_lv17._076_say_reward = "Bis jetzt hast du %s von 5 Fellen gesammelt. "
gameforge.new_quest_lv17._081_say_title = "Felle f\252r Wonda Rim "
gameforge.new_quest_lv17._082_say = "Du hast gen\252gend Felle erbeutet, bringe sie zu[ENTER]Wonda-Rim. "
gameforge.new_quest_lv17._092_say_reward = "Du hast bereits %s Wolfsfelle gesammelt. "
gameforge.new_quest_lv17._110_say = "Das sind wirklich sch\246ne Felle, ich danke dir.[ENTER]Kannst du sie meinem Onkel Chaegirab bringen? "
gameforge.new_quest_lv17._120_target = "Onkel Chaegirab "
gameforge.new_quest_lv17._121_say = "Wonda-Rim hat dich gebeten, die Wolfsfelle weiter[ENTER]zu Chaegirab zu bringen. "
gameforge.new_quest_lv17._122_say = "Chaegirab befindet sich in %s. "
gameforge.new_quest_lv17._130_say = "Aha. So versucht er es nun. "
gameforge.new_quest_lv17._131_say = "Von wem sind diese Felle? Von Wonda-Rim, aber du[ENTER]hast die W\246lfe f\252r ihn erlegt?[ENTER]Es besch\228mt mich, einen Neffen zu haben, der[ENTER]andere f\252r sich arbeiten l\228sst. Daher werde ich[ENTER]die Felle nicht annehmen, auch wenn es mir um[ENTER]deine Zeit und M\252he Leid tut. "
gameforge.new_quest_lv17._132_say_reward = "Sag Wonda-Rim, dass ich ihn durchschaut habe![ENTER]Wenn er mir eine wirkliche Freude machen will,[ENTER]soll er selbst auf die Jagd gehen. "
gameforge.new_quest_lv17._140_say = "Chaegirab hat die Felle nicht angenommen und ist[ENTER]\252ber Wonda-Rims Tun ver\228rgert. Er hat dich zu[ENTER]Wonda-Rim zur\252ckgeschickt. "
gameforge.new_quest_lv17._141_say = "Was hat mein Onkel gesagt? Ich hoffe, ihm hat das[ENTER]Geschenk gefallen? "
gameforge.new_quest_lv17._142_1_select = "Ja, er war begeistert. "
gameforge.new_quest_lv17._142_2_select = "Nein, gar nicht. "
gameforge.new_quest_lv17._143_say = "Sehr sch\246n! Es ist ein gutes Gef\252hl, anderen[ENTER]Menschen Freude zu bereiten. Und du sollst[ENTER]nat\252rlich belohnt werden. Hier, nimm! "
gameforge.new_quest_lv17._144_say_reward_a = "Du erh\228ltst 20.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 20.000 Yang.[ENTER]Du erh\228ltst einen Goldklumpen. "
gameforge.new_quest_lv17._144_say_reward_b = "Du hast Wonda-Rim belogen und deshalb[ENTER]Rangpunkte verloren! "
gameforge.new_quest_lv17._145_say = "Er hat die Felle nicht angenommen?[ENTER]Hmm, es war wirklich keine gute Idee, dich an[ENTER]meiner Stelle auf die Jagd zu schicken. N\228chstes[ENTER]Mal werde ich es anders machen. "
gameforge.new_quest_lv17._146_say_reward = "Aber du sollst dir die ganze Arbeit nicht umsonst[ENTER]gemacht haben: Geh zu Yang-Shin. Er wird dir die[ENTER]Felle zu einem guten Preis abkaufen. "
gameforge.new_quest_lv17._147_say = "Was f\252r ein ern\252chternder Ausgang der Ereignisse.[ENTER]Wenigstens hast du noch die Felle. Geh zum J\228ger[ENTER]Yang-Shin in Yayang und verkaufe sie ihm. "
gameforge.new_quest_lv17._148_say = "Was f\252r ein ern\252chternder Ausgang der Ereignisse.[ENTER]Wenigstens hast du noch die Felle. Geh zum J\228ger[ENTER]Yang-Shin in Bokjung und verkaufe sie ihm. "
gameforge.new_quest_lv17._149_say = "Was f\252r ein ern\252chternder Ausgang der Ereignisse.[ENTER]Wenigstens hast du noch die Felle. Geh zum J\228ger[ENTER]Yang-Shin in Bakra und verkaufe sie ihm. "
gameforge.new_quest_lv17._151_say = "Mu-Rang-Felle? Die kann ich gut gebrauchen.[ENTER]Ich mache mir daraus eine neue W\228schegarnitur.[ENTER]Hier, nimm einen Beutel Yang daf\252r. Und dieses[ENTER]Buch habe ich gestern gefunden, vielleicht kannst[ENTER]du etwas damit anfangen. "
gameforge.new_quest_lv17._152_say_reward = "Du erh\228ltst 40.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 10.000 Yang.[ENTER]Du erh\228ltst ein Fertigkeitsbuch. "
gameforge.new_quest_lv17._160_target = "Yang-Shin "
gameforge.new_quest_lv17._161_say_title = "Yang-Shin: "
gameforge.new_quest_lv22 = {}
gameforge.new_quest_lv22._010_target = "W\228chter des Dorfplatzes "
gameforge.new_quest_lv22._011_say = "Der W\228chter des Dorfplatzes hat eine Aufgabe f\252r[ENTER]dich. Gehe zu ihm und erkundige dich, worum es[ENTER]geht. "
gameforge.new_quest_lv22._015_npcChat = "Der kranke Bruder "
gameforge.new_quest_lv22._016_send_letter = "Der kranke W\228chter "
gameforge.new_quest_lv22._017_say_title = "W\228chter des Dorfplatzes: "
gameforge.new_quest_lv22._018_say_title = "Baek-Go: "
gameforge.new_quest_lv22._019_say_title = "W\228chter des D\228monenturms: "
gameforge.new_quest_lv22._021_say = "Ich sorge mich um meinen Bruder, den W\228chter des[ENTER]D\228monenturms. Er f\252hlt sich seit einiger Zeit[ENTER]unwohl und nun hat die Krankheit vollends[ENTER]zugeschlagen: Ihn plagen Kopfschmerzen und[ENTER]Hautr\246tungen, aber er kann seinen Posten nicht[ENTER]verlassen. K\246nntest du ihm Medizin von Baek-Go[ENTER]besorgen? "
gameforge.new_quest_lv22._022_say = "Ich w\252rde ja selbst gehen, aber der D\228monenturm[ENTER]befindet sich innerhalb des Hwang-Tempels, mitten[ENTER]im Tal von Seungryong. Dort wimmelt es nur so von[ENTER]gef\228hrlichen Kreaturen... "
gameforge.new_quest_lv22._023_say = "Da bist du ja schon wieder. Du hast die Symptome[ENTER]vergessen? Du solltest besser zuh\246ren, wenn dir[ENTER]jemand etwas sagt.[ENTER]Meinen Bruder plagen Kopfschmerzen und[ENTER]Hautr\246tungen. Sag das Baek-Go! "
gameforge.new_quest_lv22._024_select = "Dem Bruder helfen "
gameforge.new_quest_lv22._025_say_title = "Medizin von Baek-Go "
gameforge.new_quest_lv22._026_say = "Sprich mit Baek-Go \252ber die Medizin f\252r den[ENTER]W\228chter des D\228monenturms. "
gameforge.new_quest_lv22._027_say = "Baek-Go befindet sich in %s. "
gameforge.new_quest_lv22._030_target = "Baek-Go "
gameforge.new_quest_lv22._031_say = "Du ben\246tigst also Medizin? Es kann gef\228hrlich[ENTER]sein, auf gut Gl\252ck etwas zu verabreichen! Du[ENTER]musst mir schon die Symptome der Krankheit[ENTER]nennen, die bek\228mpft werden soll. "
gameforge.new_quest_lv22._032_1_select = "Kopfschmerzen und Hautr\246tungen "
gameforge.new_quest_lv22._032_2_select = "Halsschmerzen und Kr\228mpfe "
gameforge.new_quest_lv22._032_3_select = "Das wei\223 ich nicht. "
gameforge.new_quest_lv22._035_say = "Das klingt f\252r mich ganz nach D\228monenkr\228tze - das[ENTER]bleibt nicht aus, wenn zu viele dieser[ENTER]milbenverseuchten Biester in der N\228he sind.[ENTER]Ich kann dir ein Mittel herstellen, das ihm[ENTER]helfen wird. Du musst mir daf\252r allerdings einige[ENTER]Zutaten besorgen. "
gameforge.new_quest_lv22._040_say = "Ich brauche: "
gameforge.new_quest_lv22._041_say_reward = "Jage daf\252r: "
gameforge.new_quest_lv22._042_say = "Ich brauche au\223erdem: "
gameforge.new_quest_lv22._043_say = "Von solch einer Krankheit habe ich noch niemals[ENTER]geh\246rt. Bist du sicher, dass der W\228chter des[ENTER]Dorfplatzes dir die richtigen Symptome genannt[ENTER]hat? Frage besser noch einmal nach. "
gameforge.new_quest_lv22._044_say = "Ohne Symptome kann ich keine Diagnose stellen.[ENTER]Geh und frage noch einmal nach. "
gameforge.new_quest_lv22._050_set_title = "Medizin "
gameforge.new_quest_lv22._056_notice = "Gut, jetzt fehlen nur noch %s B\252ndel Kr\228uter. "
gameforge.new_quest_lv22._057_notice = "Das m\252ssten alle Kr\228uter sein, die ich brauche.[ENTER]Nun schnell zur\252ck zu Baek-Go. "
gameforge.new_quest_lv22._058_notice = "Gut, jetzt fehlen nur noch %s Lebern. "
gameforge.new_quest_lv22._060_notice = "Ah, eine Leber. Nun fehlen mir noch %s. "
gameforge.new_quest_lv22._061_notice = "Das m\252ssten alle Lebern sein, die ich brauche.[ENTER]Nun schnell zur\252ck zu Baek-Go. "
gameforge.new_quest_lv22._062_notice = "Leider ist diese Leber nicht zu gebrauchen. "
gameforge.new_quest_lv22._063_say = "Du brauchst noch %s x Medizinische Kr\228uter+. "
gameforge.new_quest_lv22._064_say = "Du brauchst noch %s x Tigerleber+. "
gameforge.new_quest_lv22._065_say = "Du hast nun alle Zutaten, die f\252r die Medizin[ENTER]ben\246tigt werden. Geh und bringe sie zu Baek-Go. "
gameforge.new_quest_lv22._066_say = "Sammle die Zutaten f\252r Baek-Gos Medizin: "
gameforge.new_quest_lv22._070_say = "Danke, damit kann ich die Medizin gegen die[ENTER]D\228monenkr\228tze herstellen. "
gameforge.new_quest_lv22._071_say = "Fertig! Hier hast du das gew\252nschte Mittel. Durch[ENTER]die frischen Zutaten verdirbt die Medizin jedoch[ENTER]schnell - du solltest sie daher innerhalb von %s[ENTER]Minuten abliefern! "
gameforge.new_quest_lv22._072_say = "Du findest den Bruder des W\228chters in der Mitte[ENTER]des Hwang-Tempels. Sei jedoch vorsichtig auf dem[ENTER]Weg dorthin - das Tal von Seungryong wird von[ENTER]vielen gef\228hrlichen Kreaturen bev\246lkert! "
gameforge.new_quest_lv22._073_say = "Das reicht nicht aus. Hast du auf dem Weg hierher[ENTER]Zutaten verloren? Ohne die restlichen[ENTER]Bestandteile kann ich nichts f\252r dich tun. "
gameforge.new_quest_lv22._080_target = "W\228chter des D\228monenturms "
gameforge.new_quest_lv22._082_set_clock = "Verbleibende Zeit "
gameforge.new_quest_lv22._083_say = "Noch hast du genug Zeit, aber du musst dich[ENTER]beeilen. Also auf nach Seungryong zum W\228chter[ENTER]des D\228monenturms, bevor die Medizin verdirbt! "
gameforge.new_quest_lv22._084_say = "Du warst zu langsam, die Zeit ist abgelaufen.[ENTER]Aber du solltest die Medizin dennoch zum W\228chter[ENTER]des D\228monenturms bringen. Vielleicht ist sie noch[ENTER]wirksam. "
gameforge.new_quest_lv22._085_say = "Danke, dass du mir diese Medizin bringst. Der[ENTER]Juckreiz bringt mich beinahe um. "
gameforge.new_quest_lv22._086_say = "Oh, das schmeckt sogar ziemlich gut. Ich sp\252re[ENTER]bereits, wie der Juckreiz nachl\228sst. "
gameforge.new_quest_lv22._087_say = "Daf\252r hast du dir eine besondere Belohnung[ENTER]verdient! "
gameforge.new_quest_lv22._088_say_reward = "Du erh\228ltst 50.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 12.000 Yang.[ENTER]Du erh\228ltst Goldverzierte Schuhe+4.[ENTER]Du erh\228ltst 5 Violette Tr\228nke. "
gameforge.new_quest_lv22._089_say = "\196h, das schmeckt ja furchtbar. Die Medizin ist[ENTER]verdorben - wie lange hast du f\252r den Weg[ENTER]gebraucht? Meine Zunge f\252hlt sich an wie[ENTER]gep\246kelter Affendung. "
gameforge.new_quest_lv22._090_say = "Hmm, moment... es scheint besser zu werden. Ja,[ENTER]es wirkt! Dann will ich mal nicht so sein. Du[ENTER]erh\228ltst trotzdem eine Belohnung. "
gameforge.new_quest_lv22._091_say = "Du scheinst die Medizin verloren zu haben. Bitte[ENTER]gehe noch einmal auf die Jagd und bringe Baek-Go[ENTER]die Zutaten f\252r eine neue Medizin. Ich werde[ENTER]sonst selbst zum D\228mon, wenn das mit dem Juckreiz[ENTER]so weiter geht. "
gameforge.new_quest_lv22._095_say_reward = "Du erh\228ltst 50.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 8.000 Yang. "
gameforge.new_quest_lv22._098_say = "Du hast schon wieder die Medizin verloren? Ein so[ENTER]schusseliger Mensch ist mir noch nie begegnet![ENTER]Aber gut, da kann man wohl nichts machen. "
gameforge.new_quest_lv22._100_say_reward = "Du erh\228ltst 25.000 Erfahrungspunkte. "
gameforge.new_quest_lv26 = {}
gameforge.new_quest_lv26._010_target = "Yang-Shin "
gameforge.new_quest_lv26._020_say_title = "Yang-Shin: "
gameforge.new_quest_lv26._020_set_title = "Der Deserteur "
gameforge.new_quest_lv26._021_say = "Der J\228ger Yang-Shin hat Probleme, gute Jagdgr\252nde[ENTER]zu finden. Geh zu ihm und sieh nach, ob du ihm[ENTER]helfen kannst. "
gameforge.new_quest_lv26._025_say = "Seit dem Auftauchen der Metinsteine ist nichts[ENTER]mehr, wie es einmal war. Auch die Jagd ist in[ENTER]vielen Gegenden unm\246glich geworden, da die[ENTER]Wildtiere sich beinahe tollw\252tig geb\228rden.[ENTER]Irgendwo dort drau\223en in der Wildnis soll jedoch[ENTER]der Wanderer Nakajima leben - ich bin sicher,[ENTER]dass er wei\223, wo sich gute Jagdgr\252nde befinden.[ENTER]Kannst du ihn suchen und danach fragen? "
gameforge.new_quest_lv26._030_target = "Nakajima "
gameforge.new_quest_lv26._031_say = "So so, du willst also wissen, wo man hier am[ENTER]besten jagt? Nicht so hastig. Wenn ich etwas f\252r[ENTER]dich tun soll, musst du auch mir einen Gefallen[ENTER]erweisen. "
gameforge.new_quest_lv26._032_say = "Du sollst wissen... ich lebe nicht freiwillig[ENTER]hier drau\223en. Ich muss mich verstecken, da ich[ENTER]vor den Gr\228ueltaten des Milit\228rs gefl\252chtet bin.[ENTER]Ich w\252nschte nur, meine geliebte Frau Ah-Yu w\252rde[ENTER]wissen, dass ich noch lebe. Kannst du ihr diese[ENTER]Nachricht \252berbringen?[ENTER]Aber denk daran, sie ist nur f\252r Ah-Yus Ohren[ENTER]bestimmt! Daf\252r soll sie dir verraten, wo ich sie[ENTER]zum ersten Mal gek\252sst habe - dort will ich sie[ENTER]treffen, und dort findest du deinen Jagdgrund. "
gameforge.new_quest_lv26._034_say_title = "Nakajima: "
gameforge.new_quest_lv26._035_say_title = "Ah-Yu: "
gameforge.new_quest_lv26._036_say_title = "Suche nach Nakajima "
gameforge.new_quest_lv26._037_say = "Nakajima soll Kenntnis von guten Jagdgr\252nden[ENTER]haben. Suche nach ihm. "
gameforge.new_quest_lv26._038_say = "Nakajima befindet sich in %s. "
gameforge.new_quest_lv26._040_say = "Bist du Nakajima? Yang-Shin schickt mich! Er ist[ENTER]auf der Suche nach guten Jagdgr\252nden - vielleicht[ENTER]hast du einen Rat, wo es nicht ganz so gef\228hrlich[ENTER]ist? "
gameforge.new_quest_lv26._050_target = "Ah-Yu "
gameforge.new_quest_lv26._051_say = "Nakajima ist ein Deserteur und muss sich nun vor[ENTER]der Armee verstecken. Seine Frau Ah-Yu denkt, er[ENTER]sei im Krieg gefallen. Bring ihr die Kunde, dass[ENTER]Nakajima noch lebt. "
gameforge.new_quest_lv26._052_say = "Ah-Yu befindet sich in %s. "
gameforge.new_quest_lv26._057_say = "Nakajima... er lebt? Mein geliebter Mann lebt? Oh[ENTER]ich danke dir f\252r diese Information![ENTER]Es ist das Tal von Yonjang, von dem er gesprochen[ENTER]hat. Ich werde mich sofort auf den Weg machen und[ENTER]mich dort mit ihm treffen. "
gameforge.new_quest_lv26._058_say = "Danke, dass du uns dieses Wiedersehen erm\246glicht[ENTER]hast. Nimm diese Rose, vielleicht kannst du sie[ENTER]einem geliebten Menschen schenken? Und nun...[ENTER]entschuldige mich, aber ich muss mich beeilen! "
gameforge.new_quest_lv26._061_say = "Das Tal von Yonjang - wo Nakajima und Ah-Yu sich[ENTER]zum ersten Mal gek\252sst haben - ist also auch[ENTER]heute noch gutes Jagdgebiet. "
gameforge.new_quest_lv26._062_say = "Yang-Shin wird zufrieden sein, wenn er das h\246rt.[ENTER]Geh nach %s und \252berbringe ihm die gute[ENTER]Nachricht. "
gameforge.new_quest_lv26._063_say = "Das Tal von Yonjang? Das klingt einleuchtend,[ENTER]denn ich habe noch nie von einem Metinstein[ENTER]geh\246rt, der dort die Gegend verseuchen soll. Ich[ENTER]werde in den n\228chsten Tagen sicher gute Beute[ENTER]machen! Hier, die Belohnung hast du dir verdient. "
gameforge.new_quest_lv26._064_sayReward = "Du erh\228ltst 35.000 Erfahrungspunkte. "
gameforge.new_quest_lv26._065_sayReward = "Du erh\228ltst 17.500 Yang. "
gameforge.new_quest_lv28 = {}
gameforge.new_quest_lv28._010_target = "Yu-Hwan "
gameforge.new_quest_lv28._011_say = "Der Musiker Yu-Hwan braucht deine Hilfe.[ENTER]Geh schnell und sieh nach, was los ist! "
gameforge.new_quest_lv28._015_npcChat = "Ah-Yus Sorgen "
gameforge.new_quest_lv28._016_say = "Ah-Yu scheint Sorgen zu haben, die sie Yu-Hwan[ENTER]nicht anvertrauen m\246chte. Geh zu ihr und sieh[ENTER]nach, ob sie dir gegen\252ber offener ist. "
gameforge.new_quest_lv28._017_say = "Ah-Yu befindet sich in %s. "
gameforge.new_quest_lv28._018_select = "Ich spreche gleich mit Ah-Yu! "
gameforge.new_quest_lv28._019_say_title = "Ah-Yu: "
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan: "
gameforge.new_quest_lv28._021_say = "Kennst du Ah-Yu? Sie sammelt Kr\228uter f\252r meine[ENTER]Tr\228nke. Bisher war sie stets gut gelaunt, doch[ENTER]gestern schien sie mir vollkommen aufgel\246st zu[ENTER]sein. \220ber ihre Sorgen reden wollte sie[ENTER]allerdings nicht - wom\246glich weil sie f\252r mich[ENTER]arbeitet? Bitte gehe zu ihr und stelle fest, wie[ENTER]es ihr geht. Vielleicht vertraut sie dir mehr an! "
gameforge.new_quest_lv28._022_say = "Es ist sehr freundlich von Yu-Hwan, sich um mich[ENTER]zu sorgen. Ja, es gibt da etwas... ich wollte[ENTER]nicht dar\252ber reden, aber der Kummer frisst mich[ENTER]innerlich auf! Es geht um Yang-Shin, den J\228ger.[ENTER]Er erpresst mich, seitdem er herausgefunden hat,[ENTER]dass mein Mann Nakajima ein Deserteur ist.[ENTER]Yang-Shin droht, ihn zu verraten! Sie werden ihn[ENTER]t\246ten... "
gameforge.new_quest_lv28._023_say = "Dieses Mal fordert er von mir eine B\228rentatze,[ENTER]um sein Schweigen zu wahren. Ich kann aber nicht[ENTER]hier weg und auf die Jagd gehen. Wirst du mir[ENTER]helfen und Yang-Shin bringen, was er verlangt? "
gameforge.new_quest_lv28._024_set_title = "B\228renjagd "
gameforge.new_quest_lv28._025_notice = "Auf zur Jagd! Bera zu t\246ten ist die beste[ENTER]M\246glichkeit, um an B\228rentatzen zu gelangen. "
gameforge.new_quest_lv28._026_notice = "Ich habe eine B\228rentatze erbeutet! "
gameforge.new_quest_lv28._027_notice = "Das d\252rfte alles sein. Auf zu Yang-Shin! "
gameforge.new_quest_lv28._028_notice = "Die Tatze dieses B\228ren war unbrauchbar. "
gameforge.new_quest_lv28._029_say = "Du ben\246tigst noch %s x B\228rentatze. "
gameforge.new_quest_lv28._031_say_reward = "Jage daf\252r: "
gameforge.new_quest_lv28._032_say = "Ah-Yu hat dich gebeten, die Forderung von[ENTER]Yang-Shin zu erf\252llen. "
gameforge.new_quest_lv28._032_say_reward = "Du ben\246tigst noch %s x B\228rentatze.[ENTER]Jage Bera, um sie zu erbeuten. "
gameforge.new_quest_lv28._035_target = "Yang-Shin "
gameforge.new_quest_lv28._036_say = "Du hast die geforderte B\228rentatze erbeutet.[ENTER]Bringe sie zu Yang-Shin und l\246se Ah-Yus Schuld[ENTER]ein. "
gameforge.new_quest_lv28._037_say = "Yang-Shin befindet sich in %s. "
gameforge.new_quest_lv28._038_say_title = "Yang-Shin: "
gameforge.new_quest_lv28._040_npcChat = "Die Erpressung "
gameforge.new_quest_lv28._041_say_title = "B\228rentatzen "
gameforge.new_quest_lv28._042_say = "Du bringst mir B\228rentatzen? Du darfst nicht[ENTER]schlecht von mir denken! Wir leben in schweren[ENTER]Zeiten und ich muss sehen, wie ich \252ber die[ENTER]Runden komme - jetzt, wo das Jagdwild rar[ENTER]geworden ist oder sich durch die Metinsteine in[ENTER]m\246rderische Bestien verwandelt hat. Das Leben als[ENTER]J\228ger ist sehr gef\228hrlich geworden. "
gameforge.new_quest_lv28._043_say = "Bitte richte Ah-Yu aus, dass sie nichts mehr zu[ENTER]bef\252rchten hat. Sie kann sich darauf verlassen.[ENTER]Zumindest bis ich wieder etwas brauche... hehehe! "
gameforge.new_quest_lv28._044_say = "Du willst mich ohne Beute abspeisen? Ich habe[ENTER]frische B\228rentatzen verlangt! "
gameforge.new_quest_lv28._045_say_reward = "Es ist nett von dir, Ah-Yu zu helfen. Es bedeutet[ENTER]aber auch, dass du tun musst, was ich verlange.[ENTER]Gehe also wieder auf die Jagd, bis du mir zwei[ENTER]B\228rentatzen bringen kannst! "
gameforge.new_quest_lv28._046_say = "Bringe Ah-Yu die Kunde, dass Yang-Shin aufgrund[ENTER]deiner Hilfe aufh\246ren wird, sie zu erpressen. "
gameforge.new_quest_lv28._051_say = "Du bist unser Retter! Ich bin dir so unendlich[ENTER]dankbar. Hier, nimm all mein Yang. Es ist nicht[ENTER]viel, aber du hast es dir redlich verdient. "
gameforge.new_quest_lv28._055_1_select = "Vielen Dank, ich kann es gut gebrauchen! "
gameforge.new_quest_lv28._055_2_select = "Nein, das kann ich nicht annehmen. "
gameforge.new_quest_lv28._056_say = "Hier ist alles was ich habe. Solange ich diesen[ENTER]unmenschlichen Halsabschneider damit loswerde,[ENTER]ist es das wert. "
gameforge.new_quest_lv28._057_say = "Oh, hab Dank! Daf\252r ist dir ein Platz an der[ENTER]Seite des Drachengottes sicher! "
gameforge.new_quest_lv28._058_say_reward = "Du erh\228ltst %s Yang. "
gameforge.new_quest_lv28._059_say_reward = "Du erh\228ltst %s Erfahrungspunkte. "
gameforge.new_quest_lv28._070_say = "Ich brauche: "
gameforge.new_quest_lv29 = {}
gameforge.new_quest_lv29._010_target = "Yonah "
gameforge.new_quest_lv29._015_npcChat = "Das zerbrochene Porzellan "
gameforge.new_quest_lv29._020_say_title = "Yonah: "
gameforge.new_quest_lv29._021_say = "Mein geliebtes Seladon-Porzellan! Seit drei[ENTER]Generationen befindet es sich in meiner Familie,[ENTER]und nun sind drei der kostbaren Vasen zerbrochen.[ENTER]Vor kurzem habe ich Taurean beobachtet, den[ENTER]kleinen Taugenichts, wie er um das Lagerhaus[ENTER]schlich. Ich bin sicher, er ist f\252r das Ungl\252ck[ENTER]verantwortlich! "
gameforge.new_quest_lv29._022_say = "Es w\228re nicht die erste Dummheit, die er[ENTER]anstellt, aber dieses Mal ist er eindeutig zu[ENTER]weit gegangen. Jemand sollte ihm eine geh\246rige[ENTER]Tracht Pr\252gel verpassen! Vielleicht hast du daf\252r[ENTER]Zeit? "
gameforge.new_quest_lv29._023_1_select = "Aber mit Vergn\252gen! "
gameforge.new_quest_lv29._023_2_select = "Das geht mich nichts an. "
gameforge.new_quest_lv29._024_say = "Ich habe keine Zeit, um b\246se Kinder zu erziehen.[ENTER]Du wirst ihn schon selbst einfangen m\252ssen. Ich[ENTER]bezweifle allerdings, dass du das schaffst... "
gameforge.new_quest_lv29._030_target = "Taurean "
gameforge.new_quest_lv29._031_say = "Yonahs wertvolle Familienerbst\252cke, drei Vasen[ENTER]aus Seladon-Porzellan, sind zerbrochen. Er[ENTER]glaubt, dass Taurean daran schuld sei.[ENTER]Geh zu Taurean und stelle ihn zur Rede. "
gameforge.new_quest_lv29._032_say = "Taurean befindet sich in %s. "
gameforge.new_quest_lv29._033_say_title = "Taurean: "
gameforge.new_quest_lv29._034_say_reward = "Warum guckst du mich so finster an? Ich habe[ENTER]nichts B\246ses getan... "
gameforge.new_quest_lv29._035_say_reward = "Was hast du mit Yonahs Vasen gemacht? "
gameforge.new_quest_lv29._036_say_reward = "Vasen? Yonah? Ich wei\223 wirklich nicht, wovon du[ENTER]redest! "
gameforge.new_quest_lv29._037_say_reward = "Dann erkl\228r mir doch einmal, warum drei von ihnen[ENTER]zu Bruch gegangen sind. "
gameforge.new_quest_lv29._038_say_reward = "Ich schw\246re dir, ich bin heute weder in die N\228he[ENTER]einer Vase gekommen, noch habe ich Yonah gesehen.[ENTER]Im Gegenteil, den gesamten Tag \252ber habe ich mit[ENTER]Harang gek\228mpft. Sie hat mich sogar f\252r ein paar[ENTER]Stunden im Heuschober eingesperrt! Geh doch und[ENTER]frag sie! Ich sage die Wahrheit! "
gameforge.new_quest_lv29._040_target = "Harang "
gameforge.new_quest_lv29._041_say = "Taurean behauptet, unschuldig zu sein: Er habe[ENTER]den ganzen Tag mit Harang gespielt und k\246nne die[ENTER]Vasen daher nicht zerbrochen haben.[ENTER]Geh zu Harang und frage sie, ob das stimmt. "
gameforge.new_quest_lv29._042_say_reward = "Harang, hast du Taurean heute gesehen? "
gameforge.new_quest_lv29._043_say_title = "Harang: "
gameforge.new_quest_lv29._044_say_reward = "Taurean? Ja, wir haben den ganzen Tag gespielt.[ENTER]Stimmt was nicht? "
gameforge.new_quest_lv29._045_say_reward = "Yonah sagt, dass Taurean heute drei seiner Vasen[ENTER]zerbrochen habe. "
gameforge.new_quest_lv29._046_say_reward = "Yonah ist gemein. Er verjagt Taurean und mich[ENTER]schon, wenn wir nur in seine N\228he kommen.[ENTER]St\228ndig hat er Angst um sein Porzellan.[ENTER]Seine kostbaren Vasen darf nur sein Freund, der[ENTER]Stallbursche, ber\252hren. Vielleicht hat der sie ja[ENTER]kaputt gemacht?! "
gameforge.new_quest_lv29._047_say = "Harang befindet sich in %s. "
gameforge.new_quest_lv29._050_target = "Stallbursche "
gameforge.new_quest_lv29._051_say = "Harang hat Taureans Aussage, er sei unschuldig,[ENTER]best\228tigt. Mag sein, dass die beiden unter einer[ENTER]Decke stecken. Doch bevor du ein Urteil f\228llst,[ENTER]solltest du noch Yonahs Freund, den[ENTER]Stallburschen, befragen. "
gameforge.new_quest_lv29._052_say = "Ach, der gute Yonah. Er sorgt sich um sein[ENTER]Porzellan und verd\228chtigt die Dorfkinder. Dabei[ENTER]sind die Metinsteine Schuld - seitdem sie das[ENTER]Land vergiften, sind unsere Bodensch\228tze nicht[ENTER]mehr das, was sie mal waren. Auch das Porzellan[ENTER]ist br\252chig geworden. Doch Yonah will das nicht[ENTER]wahrhaben... "
gameforge.new_quest_lv29._053_say = "Wenn du etwas Heu f\252r ihn sammelst, k\246nnte er das[ENTER]Porzellan in seinen Truhen besser polstern.[ENTER]Auf diese Weise kannst du ihn sicher wieder milde[ENTER]stimmen. "
gameforge.new_quest_lv29._054_say = "Der Stallbursche befindet sich in[ENTER]%s oder %s. "
gameforge.new_quest_lv29._061_say = "Taurean tr\228gt offensichtlich keine Schuld an[ENTER]Yonahs zerbrochenen Vasen. Es liegt an der b\246sen[ENTER]Strahlung der Metinsteine, die das Material[ENTER]spr\246de macht.[ENTER]Sammle Heu f\252r Yonah, damit er sein Porzellan[ENTER]besser lagern kann! Einige der Dorfbewohner[ENTER]k\246nnen dir sicher welches geben. "
gameforge.new_quest_lv29._062_say = "Vor den Toren des Dorfes sind %s und %s zu[ENTER]finden. Sie tragen Strohh\252te, die bestimmt eine[ENTER]akzeptable Menge Heu ergeben. "
gameforge.new_quest_lv29._063_notice = "Daraus bekomme ich ein sch\246nes B\252ndel Stroh.[ENTER]Jetzt fehlen mir nur noch %s weitere. "
gameforge.new_quest_lv29._064_notice = "Dieser Hut ist nicht aus Stroh gefertigt, sondern[ENTER]aus Kokosfasern. Das kann ich nicht gebrauchen. "
gameforge.new_quest_lv29._065_1_say = "Wie ich sehe, hast du einen Menge Heu bei dir.[ENTER]Wenn du Yonah etwas davon gibst, beruhigt er sich[ENTER]bestimmt. "
gameforge.new_quest_lv29._065_notice = "Der Hut ist nicht aus Stroh gefertigt, sondern[ENTER]aus Kokosfasern. Dazu ist er stark besch\228digt... "
gameforge.new_quest_lv29._066_say = "Du kannst auch Wilde Infanteristen oder Starke[ENTER]wilde Infanteristen t\246ten. Aus ihren Strohh\252ten[ENTER]kann man ebenfalls Heu gewinnen. "
gameforge.new_quest_lv29._067_say_reward = "Bis jetzt hast du %s von %s B\252ndeln Heu[ENTER]gesammelt. "
gameforge.new_quest_lv29._068_notice = "Du hast ein B\252ndel Heu erbeutet. "
gameforge.new_quest_lv29._070_npcChat = "Der Heuschober "
gameforge.new_quest_lv29._071_say_reward = "Taurean, du hast doch vorhin erw\228hnt, dass du im[ENTER]Heuschober gewesen bist. Hast du zuf\228llig etwas[ENTER]Heu mitgenommen? "
gameforge.new_quest_lv29._072_say_reward = "Hihi, mal sehen... es steckte \252berall in meinen[ENTER]Haaren und meinen Schuhen. Siehst du? Da sind[ENTER]noch ein paar Halme. Hier nimm! "
gameforge.new_quest_lv29._073_notice = "Viel Heu ist das nicht, aber f\252r ein kleines[ENTER]B\252ndel sollte es reichen. Jetzt fehlen nur noch[ENTER]%s weitere. "
gameforge.new_quest_lv29._074_say_reward = "Ich war es wirklich nicht! Hat dir Harang nicht[ENTER]gesagt, dass wir uns im Heuschober gepr\252gelt[ENTER]haben? "
gameforge.new_quest_lv29._075_say_reward = "Du warst doch vorhin im Heuschober, oder? Hast du[ENTER]zuf\228llig etwas Heu von dort mitgenommen? "
gameforge.new_quest_lv29._076_say_reward = "Woher wei\223t du das mit dem Heuschober?[ENTER]Habe ich etwa noch Heu in meinen Kleidern?[ENTER]Tats\228chlich, hier sind noch einige Halme! "
gameforge.new_quest_lv29._077_say_reward = "Kann ich das haben? "
gameforge.new_quest_lv29._078_say_reward = "Von mir aus... "
gameforge.new_quest_lv29._079_say_reward = "Ich habe jetzt keine Zeit. Ich muss zu Taurean[ENTER]und ihn wegen der Geschichte mit den Vasen[ENTER]beruhigen! "
gameforge.new_quest_lv29._080_npcChat = "Heu f\252r Yonah "
gameforge.new_quest_lv29._081_say_reward = "Liegt im Stall vielleicht noch Heu, das ich Yonah[ENTER]mitbringen k\246nnte? "
gameforge.new_quest_lv29._082_say_title = "Stallbursche: "
gameforge.new_quest_lv29._083_say_reward = "Wir haben nicht mehr viel Heu. Die wilden Tiere[ENTER]und die Banditen ausserhalb des Dorfes[ENTER]verhindern, dass wir neues schneiden k\246nnen. "
gameforge.new_quest_lv29._084_say_reward = "Aber ein klein wenig kann ich dir schon geben! "
gameforge.new_quest_lv29._085_notice = "Es ist wirklich nicht viel, aber f\252r ein B\252ndel[ENTER]reicht es. Jetzt fehlen nur noch %s weitere. "
gameforge.new_quest_lv29._086_say_reward = "Ich kann leider nichts f\252r dich tun. "
gameforge.new_quest_lv29._090_send_letter = "Heu statt Haue "
gameforge.new_quest_lv29._091_say = "Du hast gen\252gend Heu f\252r Yonah gesammelt.[ENTER]Geh nach %s und bringe es ihm. "
gameforge.new_quest_lv29._101_say_reward = "Taurean ist nicht der Schuldige. Die Strahlung[ENTER]der Metinsteine hat das Porzellan br\252chig werden[ENTER]lassen. "
gameforge.new_quest_lv29._102_say_title = "Yonah: "
gameforge.new_quest_lv29._103_say_reward = "Was sagst du da? Das ist kompletter Unsinn, der[ENTER]kleine Nichtsnutz hat dich angelogen. "
gameforge.new_quest_lv29._104_say_reward = "Taurean hat heute den ganzen Tag mit Harang im[ENTER]Heuschober gespielt. "
gameforge.new_quest_lv29._105_say_reward = "Ich soll dich auch von deinem Freund, dem[ENTER]Stallburschen, sch\246n gr\252ssen - und ich habe dir[ENTER]etwas Heu mitgebracht, damit du deine Vasen[ENTER]besser sch\252tzen kannst. "
gameforge.new_quest_lv29._106_say_reward = "Ich gebe zu, ich sch\228me mich wegen meiner[ENTER]Reaktion. Aber du musst wissen, dass ich sehr an[ENTER]meinem Porzellan h\228nge, da es mich an meine[ENTER]Familie erinnert. Wenn eine Vase zu Bruch geht,[ENTER]ist das f\252r mich mehr als nur ein verlorener[ENTER]Gegenstand... "
gameforge.new_quest_lv29._107_say_reward = "Ich muss mich bei dir und Taurean entschuldigen.[ENTER]Hier hast du eine kleine Belohnung f\252r deine[ENTER]M\252hen! "
gameforge.new_quest_lv29._108_notice = "Du erh\228ltst einen Bonus von %s Erfahrungspunkten! "
gameforge.new_quest_lv29._109_say_reward = "Ich soll dich auch von deinem Freund, dem[ENTER]Stallburschen, sch\246n gr\252ssen - und ich habe dir[ENTER]etwas Heu mitgebracht, damit du deine Vasen[ENTER]besser sch\252tzen kannst. "
gameforge.new_quest_lv29._110_say_reward = "Das ist sehr freundlich von dir, aber kannst du[ENTER]mir noch %s weitere B\252ndel Heu besorgen, damit[ENTER]meine Vasen wirklich sicher sind? "
gameforge.new_quest_lv29._111_say_reward = "Ich sch\228tze, dass es schwer werden wird, noch[ENTER]mehr Heu zu finden. Aber meine Vasen sind mir[ENTER]heilig. Ich w\228re dir wirklich dankbar und w\252rde[ENTER]dir daf\252r auch etwas Yang geben. "
gameforge.new_quest_lv29._112_say_reward = "Dann steckt wohl die vorlaute G\246re Harang mit[ENTER]Taurean unter einer Decke. "
gameforge.new_quest_lv29._113_say_reward = "Anscheinend glaubt mir hier niemand, wenn ich[ENTER]sage, dass ich den Jungen vorhin in der N\228he des[ENTER]Lagerhauses gesehen habe. "
gameforge.new_quest_lv29._114_say_reward = "Lass gut sein. Hier hast du eine Entsch\228digung[ENTER]f\252r deine M\252hen. "
gameforge.new_quest_lv29._115_say_reward = "Hier, %s Yang. "
gameforge.new_quest_lv42 = {}
gameforge.new_quest_lv42._010_send_letter = "Grumgrrr "
gameforge.new_quest_lv42._020_target = "Octavio "
gameforge.new_quest_lv42._021_say = "Mein Magen knurrt wie ein Roter Keiler.[ENTER]Vielleicht sollte ich mal wieder bei Octavio[ENTER]vorbeischauen. Er macht den besten Fischeintopf[ENTER]weit und breit. "
gameforge.new_quest_lv42._022_say_title = "Octavio: "
gameforge.new_quest_lv42._023_say = "Du m\246chtest Fischeintopf? Den mit den ganzen[ENTER]K\246pfen? Oh das tut mir leid, meine K\252che hat seit[ENTER]Tagen keinen Fisch mehr gesehen. Normalerweise[ENTER]liefert der Fischer mir den guten Hochseefisch,[ENTER]den ich f\252r meinen Eintopf verwende. "
gameforge.new_quest_lv42._024_say = "Nun hat er sich aber seit Tagen nicht blicken[ENTER]lassen. Kannst du vielleicht gehen und ihn[ENTER]fragen, was los ist? "
gameforge.new_quest_lv42._025_say = "Octavio befindet sich in %s. "
gameforge.new_quest_lv42._026_select = "Ich gehe den Fischer suchen! "
gameforge.new_quest_lv42._030_target = "Fischer "
gameforge.new_quest_lv42._031_say = "Die friedlichen Tage auf dem Meer sind vorbei![ENTER]T\228glich verschwinden Fischer, es ist schrecklich![ENTER]Seit die Metinsteine ins Meer gest\252rzt sind,[ENTER]haben sich friedliche Wale in grausame[ENTER]Seeungeheuer verwandelt. Das Fischen ist einfach[ENTER]zu gef\228hrlich geworden. "
gameforge.new_quest_lv42._032_say = "Unsere Lanzen k\246nnen die Wale nicht mehr[ENTER]verletzen. Ihre Haut ist z\228her geworden als die[ENTER]eines Ogers! "
gameforge.new_quest_lv42._033_say = "Vielleicht wei\223 Yonah, was zu tun ist. Er ist[ENTER]fr\252her selbst zur See gefahren und hat viele[ENTER]Jahre lang Wale gejagt. "
gameforge.new_quest_lv42._034_say_title = "Fischer: "
gameforge.new_quest_lv42._035_say = "Octavio wartet auf seinen Hochseefisch. Frage den[ENTER]Fischer, warum sich die Lieferung verz\246gert. "
gameforge.new_quest_lv42._036_say = "Der Fischer befindet sich in %s. "
gameforge.new_quest_lv42._037_send_letter = "Grimmige Seeungeheuer "
gameforge.new_quest_lv42._038_say = "Der Fischer hat dich gebeten, Yonah um Rat zu[ENTER]fragen, wie die b\246sartigen Wale gejagt werden[ENTER]k\246nnen. "
gameforge.new_quest_lv42._039_say = "Yonah befindet sich in %s. "
gameforge.new_quest_lv42._040_target = "Yonah "
gameforge.new_quest_lv42._041_say = "Ich habe bereits geh\246rt, was mit den Walen[ENTER]geschehen ist. F\252r die Fischer ist es eine[ENTER]schlimme Sache. Selbst wenn sie sich auf das Meer[ENTER]wagen, sind ihre Lanzen zu schwach, um die[ENTER]Walhaut zu durchdringen. Damals, als ich auf[ENTER]einem Walf\228nger gearbeitet habe, nutzten wir[ENTER]spezielle Waffen - f\252r die Wale, deren Haut[ENTER]bereits alt und narbig war. Die konnten alles[ENTER]durchdringen... "
gameforge.new_quest_lv42._042_say = "Es handelt sich um mit einer besonderen Technik[ENTER]geh\228rtete Walfanglanzen. Nur der Schmied kann[ENTER]solche Lanzen herstellen. "
gameforge.new_quest_lv42._043_say_reward = "Gehe zum Schmied. "
gameforge.new_quest_lv42._044_say_title = "Yonah: "
gameforge.new_quest_lv42._045_say = "Yonah empfiehlt besonders harte und scharfe[ENTER]Lanzen f\252r die Waljagd. Begib dich zum Schmied[ENTER]und frage ihn, ob er solche Lanzen herstellen[ENTER]kann. "
gameforge.new_quest_lv42._050_target = "Schmied "
gameforge.new_quest_lv42._051_say = "Ja, von derartigen Lanzen habe ich geh\246rt und ich[ENTER]kann sie auch herstellen. Um die n\246tige H\228rte zu[ENTER]erreichen, ben\246tige ich allerdings Diamantstein. "
gameforge.new_quest_lv42._052_say = "Ich brauche: "
gameforge.new_quest_lv42._053_say_reward = "Bearbeite daf\252r: "
gameforge.new_quest_lv42._054_say_title = "Schmied: "
gameforge.new_quest_lv42._060_set_title = "Diamantstein "
gameforge.new_quest_lv42._061_notice = "Mal sehen. Ich brauche eine Spitzhacke, um den[ENTER]Stein abzubauen. Habe ich meine noch irgendwo,[ENTER]oder muss ich mir bei Deokbae eine neue besorgen? "
gameforge.new_quest_lv42._062_say = "Du brauchst noch %s x Diamantstein. "
gameforge.new_quest_lv42._063_say = "Du hast alles, was du brauchst.[ENTER]Nun schnell zur\252ck zum Schmied. "
gameforge.new_quest_lv42._064_say = "Wunderbar, das ist alles, was ich brauche. Komm[ENTER]morgen um die gleiche Zeit wieder, um die Lanze[ENTER]abzuholen. Solch ein Eisen muss wohl geschmiedet[ENTER]werden! "
gameforge.new_quest_lv42._065_say = "Du findest Diamantstein, wenn du Diamantadern mit[ENTER]der Spitzhacke bearbeitest. "
gameforge.new_quest_lv42._066_say = "Der Schmied ben\246tigt Diamantstein, um die[ENTER]besonderen Walfanglanzen herstellen zu k\246nnen.[ENTER]Suche Diamantadern, um Diamantstein abzubauen.[ENTER]Wenn du noch keine Spitzhacke f\252r den Bergbau[ENTER]besitzt, kannst du bei Deokbae eine erwerben. "
gameforge.new_quest_lv42._067_say = "Der Schmied befindet sich in %s. "
gameforge.new_quest_lv42._068_say = "Wir brauchen noch %s x Diamantstein, bevor wir[ENTER]mit der Arbeit an den Lanzen beginnen k\246nnen. "
gameforge.new_quest_lv42._070_set_title = "Die Lanzen "
gameforge.new_quest_lv42._071_set_clock = "Wartezeit "
gameforge.new_quest_lv42._072_say = "Der Schmied sollte jetzt fertig sein mit deinem[ENTER]Auftrag. Geh zu ihm und hole die speziellen[ENTER]Walfanglanzen ab. "
gameforge.new_quest_lv42._073_say = "Die Lanzen sind leider noch nicht fertig.[ENTER]Du musst noch ein wenig Geduld aufbringen. "
gameforge.new_quest_lv42._074_say = "Hier hast du die Lanzen. Bring sie dem Fischer. "
gameforge.new_quest_lv42._075_say = "Ich habe dich doch gebeten zu warten, bis die[ENTER]Lanzen fertig sind. Komm sp\228ter wieder. "
gameforge.new_quest_lv42._079_say = "Du hast vom Schmied die Waljagdlanzen bekommen.[ENTER]Bringe sie zum Fischer. "
gameforge.new_quest_lv42._080_say = "Wunderbar! Diese Lanzen sind wahrlich[ENTER]eindrucksvoll! Nun k\246nnen wir uns endlich vor den[ENTER]Angriffen der Wale sch\252tzen und uns verteidigen.[ENTER]Richte doch bitte Octavio aus, dass er bald[ENTER]wieder mit frischem Fisch rechnen kann! "
gameforge.new_quest_lv42._081_say_reward = "Du erh\228ltst 500.000 Yang. "
gameforge.new_quest_lv42._082_say_reward = "Als besondere Anerkennung erh\228ltst du 3x: "
gameforge.new_quest_lv42._083_say = "Das sind zu wenig Lanzen, um einen Wal zu[ENTER]vertreiben. Damit k\246nnen wir ihn gerade mal am[ENTER]Speck kitzeln! "
gameforge.new_quest_lv42._084_say_reward = "Bitte geh noch einmal zum Schmied und lass dir[ENTER]weitere Lanzen anfertigen. "
gameforge.new_quest_lv42._090_say = "Die Fischer sind nun gut ger\252stet und k\246nnen[ENTER]wieder auf dem offenen Meer jagen. Geh zu Octavio[ENTER]und beruhige ihn, dass er in K\252rze neue[ENTER]Lieferungen erhalten wird. "
gameforge.new_quest_lv42._095_say = "Was sagst du da? Friedliche Wale sind zu[ENTER]aggressiven Seeungeheuern geworden? Das ist ja[ENTER]schrecklich...[ENTER]Danke, dass du den Fischern geholfen hast. Ein[ENTER]gro\223er Teil meiner Speisekarte ist von ihren[ENTER]Lieferungen abh\228ngig. "
gameforge.new_quest_lv42._096_say = "Und was deinen Hunger betrifft: Fischeintopf kann[ENTER]ich dir nat\252rlich noch keinen bieten, aber wie[ENTER]w\228re es mit etwas Sushi? "
gameforge.new_quest_lv42._098_say_reward = "Du erh\228ltst 750.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 2 St\252ck Sushi. "
gameforge.new_quest_lv43 = {}
gameforge.new_quest_lv43._005_send_letter = "Besuch bei Wonda-Rim "
gameforge.new_quest_lv43._006_send_letter = "Das Waisenkind "
gameforge.new_quest_lv43._010_target = "Wonda-Rim "
gameforge.new_quest_lv43._011_say = "Du hast lange nichts von Wonda-Rim geh\246rt.[ENTER]Vielleicht hat sich das Verh\228ltnis zu seinem[ENTER]Onkel mittlerweile gebessert und die Episode mit[ENTER]den Mu-Rang-Fellen ist vergessen.[ENTER]Besuche ihn doch einmal. "
gameforge.new_quest_lv43._012_say = "Wonda-Rim befindet sich in %s. "
gameforge.new_quest_lv43._020_say = "Sch\246n, dass du wieder vorbeischaust. "
gameforge.new_quest_lv43._021_say_title = "Wonda-Rim: "
gameforge.new_quest_lv43._022_say = "Ich bin bei meinem Onkel Chaegirab aufgewachsen.[ENTER]Im Grunde hatten wir stets ein gutes Verh\228ltnis[ENTER]zueinander... aber wenn ich nach meinen Eltern[ENTER]frage, weicht er mir aus. Sie sind tot - das ist[ENTER]auch schon alles, was er mir verr\228t. "
gameforge.new_quest_lv43._023_say_reward = "Irgendwann will ich aber auch heiraten und eine[ENTER]Familie gr\252nden. Ich sollte daher wissen, wer ich[ENTER]bin, woher ich stamme. Kannst du mit meinem Onkel[ENTER]reden und ihn nach meinen Eltern fragen? Aber[ENTER]verrate bitte nicht, dass ich dich schicke. "
gameforge.new_quest_lv43._024_select = "Ich werde mit ihm sprechen! "
gameforge.new_quest_lv43._025_say = "Wonda-Rim ist nicht der leibliche Neffe[ENTER]Chaegirabs, er ist nur bei ihm aufgewachsen.[ENTER]Es ist nun an der Zeit f\252r ihn, zu erfahren, wer[ENTER]seine wahren Eltern sind. Befrage Chaegirab zu[ENTER]Wonda-Rims Herkunft. "
gameforge.new_quest_lv43._026_say = "Chaegirab befindet sich in %s. "
gameforge.new_quest_lv43._030_target = "Chaegirab "
gameforge.new_quest_lv43._031_say_title = "Chaegirab: "
gameforge.new_quest_lv43._032_say = "Wonda-Rim... ja, ich bin nicht sein richtiger[ENTER]Onkel. Wer seine Eltern sind, wei\223 ich nicht.[ENTER]Bisher habe ich ihn mit der Wahrheit geschont, da[ENTER]er noch nicht bereit war, sie zu erfahren. Aber[ENTER]vielleicht ist es nun an der Zeit. "
gameforge.new_quest_lv43._033_say = "Ich hab ihn im Tal von Seungryong gefunden, bei[ENTER]einer Horde von Ork-K\228mpfern. Wenn sich noch[ENTER]Hinweise auf Wonda-Rims Herkunft finden lassen,[ENTER]dann dort bei den Orks. "
gameforge.new_quest_lv43._034_say = "Auch wenn ich streng zu ihm bin, werde ich ihm[ENTER]doch immer ein Onkel sein. Sogar, wenn er[ENTER]weiterhin so ein Taugenichts bleibt. "
gameforge.new_quest_lv43._035_say_reward = "Begib dich ins Tal von Seungryong und jage dort[ENTER]Ork-K\228mpfer, bis du einen Hinweis auf Wonda-Rims[ENTER]Abstammung findest. "
gameforge.new_quest_lv43._036_say = "In der verschmutzten Tasche eines erschlagenen[ENTER]Ork-K\228mpfers hast du einen alten Brief entdeckt.[ENTER]Er ist kaum noch zu entziffern, aber du kannst[ENTER]den Namen Wonda-Rim darauf erkennen. Das ist der[ENTER]ben\246tigte Hinweis, bringe ihn zu Wonda-Rim. "
gameforge.new_quest_lv43._041_say = "Dann los! Die beste M\246glichkeit, etwas \252ber[ENTER]Wonda-Rims Herkunft zu erfahren, besteht wohl[ENTER]darin, Ork-K\228mpfer zu t\246ten. Vielleicht tragen[ENTER]sie einen entsprechenden Hinweis bei sich! "
gameforge.new_quest_lv43._043_notice = "Hinweise auf Wonda-Rim... "
gameforge.new_quest_lv43._045_say = "Ich hab dir alles gesagt, was ich wei\223. Der[ENTER]einzige Anhaltspunkt, den wir haben, sind die[ENTER]Ork-K\228mpfer. Nur kann man leider nicht vern\252nftig[ENTER]mit denen reden... "
gameforge.new_quest_lv43._049_say = "Ein Brief? Mal sehen... Die Schriftzeichen sind[ENTER]undeutlich... Es geht um einen \220berfall, Orks[ENTER]haben die Farm niedergebrannt, nun rennen sie um[ENTER]ihr Leben. Sie mussten ihr Kind zur\252cklassen...[ENTER]Und hier steht mein Name. "
gameforge.new_quest_lv43._050_say = "Danke, dass du mir das gebracht hast. Nun wei\223[ENTER]ich endlich, was passiert ist. "
gameforge.new_quest_lv43._051_say = "Ich sollte mit Chaegirab sprechen. Er hat[ENTER]offensichtlich einige Gefahren auf sich genommen,[ENTER]um mich zu retten. Ich werde versuchen, ihm ein[ENTER]besserer Neffe zu sein. Bis bald, Freund! "
gameforge.new_quest_lv43._052_say_title = "Information: "
gameforge.new_quest_lv43._053_say_reward = "Du erh\228ltst 32.000 Yang. "
gameforge.new_quest_lv43._054_say_reward = "Du erh\228ltst 1.250.000 Erfahrungspunkte. "
gameforge.new_quest_lv43._060_say = "Hast du mit meinen Onkel Chaegirab[ENTER]gesprochen? Ein Hinweis? Wovon[ENTER]redest du? Wenn du nichts[ENTER]vorzuweisen hast, solltest du dich[ENTER]mit Vermutungen zur\252ckhalten![ENTER]Bitte frage nochmal meinen Onkel.[ENTER]Schlie\223lich bezahle ich dich daf\252r. "
gameforge.new_quest_lv52 = {}
gameforge.new_quest_lv52._010_send_letter = "Brief vom Hauptmann "
gameforge.new_quest_lv52._020_say_title = "Treuer Landsmann "
gameforge.new_quest_lv52._021_say_reward = "Ich m\246chte dich bitten, mir einen Gefallen zu[ENTER]erweisen. Ich kann nachts nicht mehr schlafen,[ENTER]trotz der Medizin von Baek-Go w\228lze ich mich nur[ENTER]herum. Kannst du ihn aufsuchen und nach einem[ENTER]st\228rkeren Schlafmittel f\252r mich fragen? "
gameforge.new_quest_lv52._022_say = "Baek-Go befindet sich in %s. "
gameforge.new_quest_lv52._030_set_title = "Nachtruhe "
gameforge.new_quest_lv52._035_target = "Baek-Go "
gameforge.new_quest_lv52._040_say = "Der Hauptmann hat Probleme, nachts[ENTER]durchzuschlafen. Geh zu Baek-Go und frage ihn[ENTER]nach einem st\228rkeren Schlafmittel f\252r den[ENTER]Hauptmann. "
gameforge.new_quest_lv52._041_say = "Ein Schlafmittel f\252r den Hauptmann? Ich habe[ENTER]leider nichts St\228rkeres, das ich dir \252berlassen[ENTER]k\246nnte. Nur Yu-Hwan k\246nnte auf Kr\228uterbasis etwas[ENTER]herstellen, das die gew\252nschte Wirkung zeigt. "
gameforge.new_quest_lv52._042_say = "Ah, du hast meinen Brief erhalten. Ich wei\223[ENTER]wirklich nicht mehr weiter. Ich finde des Nachts[ENTER]einfach keine Ruhe mehr. Bitte hilf mir und frage[ENTER]Baek-Go um Rat. "
gameforge.new_quest_lv52._042_select = "Dann gehe ich besser zu Yu-Hwan! "
gameforge.new_quest_lv52._043_say = "Baek-Go befindet sich in %s. "
gameforge.new_quest_lv52._044_say_title = "Baek-Go: "
gameforge.new_quest_lv52._045_say = "Yu-Hwan befindet sich in %s. "
gameforge.new_quest_lv52._046_say = "Dann geh zum Hauptmann und sag ihm, dass du[ENTER]ihm nicht helfen kannst. "
gameforge.new_quest_lv52._049_say_title = "Yu-Hwan: "
gameforge.new_quest_lv52._050_target = "Yu-Hwan "
gameforge.new_quest_lv52._051_say = "Baek-Go hat keine st\228rkere Medizin mehr im[ENTER]Sortiment. Aber wom\246glich kann Yu-Hwan helfen,[ENTER]wenn er ein Kraut kennt, das die gew\252nschte[ENTER]Wirkung besitzt. "
gameforge.new_quest_lv52._052_say = "Ich kenne den Hauptmann gut. Wie du sicher wei\223t,[ENTER]erledige ich bereits seit langer Zeit geheime[ENTER]Auftr\228ge f\252r ihn. Daher kann ich dir sagen, dass[ENTER]Kr\228uter ihm bei seinem Problem nicht helfen[ENTER]werden. "
gameforge.new_quest_lv52._053_say = "Es gibt einen anderen Grund, warum der Hauptmann[ENTER]nicht mehr schlafen kann. Und glaub mir, er kennt[ENTER]ihn selbst sehr gut. Aber das ist eine Sache, die[ENTER]er kl\228ren muss - ich kann es nicht f\252r ihn tun.[ENTER]Geh zu ihm und sprich ihn darauf an. "
gameforge.new_quest_lv52._054_say_title = "Hauptmann: "
gameforge.new_quest_lv52._055_say_reward = "Ah, du hast meinen Brief erhalten. Ich wei\223[ENTER]wirklich nicht mehr weiter. Bitte geh und frage[ENTER]Baek-Go um Rat, damit ich nachts wieder Schlaf[ENTER]finde. "
gameforge.new_quest_lv52._055_select = "Ja, Sir! "
gameforge.new_quest_lv52._056_say = "Ich danke dir! "
gameforge.new_quest_lv52._056_say_reward = "Das habe ich bereits getan, aber er hat keine[ENTER]st\228rkere Medizin in seinem Sortiment. Aber ich[ENTER]werde Yu-Hwan aufsuchen und fragen, ob er helfen[ENTER]kann. "
gameforge.new_quest_lv52._060_target = "Hauptmann "
gameforge.new_quest_lv52._061_say = "Yu-Hwan will keine Geheimnisse ausplaudern,[ENTER]wahrscheinlich geht es um etwas Unangenehmes.[ENTER]Aber es hilft nichts: Du musst mit dem Hauptmann[ENTER]dar\252ber sprechen. Ohne Kenntnis der Ursache kann[ENTER]es keine L\246sung des Schlafproblems geben.[ENTER]Also auf nach %s. "
gameforge.new_quest_lv52._062_say_reward = "Es gibt kein st\228rkeres Schlafmittel mehr. Aber[ENTER]vielleicht kann ich euch helfen, Hauptmann, wenn[ENTER]ich den Grund f\252r eure Schlaflosigkeit erfahre. "
gameforge.new_quest_lv52._063_say_reward = "Das ist nichts, was ich einem jungen Mann wie dir[ENTER]gerne erz\228hlen w\252rde. "
gameforge.new_quest_lv52._064_say_reward = "Das ist nichts, was ich einer jungen Frau wie dir[ENTER]gerne erz\228hlen w\252rde. "
gameforge.new_quest_lv52._065_say_reward = "Aber wenn ich nicht bald durchschlafe, werde ich[ENTER]fr\252her oder sp\228ter den Verstand verlieren. Es[ENTER]muss wohl sein...[ENTER]Aber denk daran, dies ist nur f\252r deine Ohren[ENTER]bestimmt: Jede Nacht werde ich von vier Geistern[ENTER]heimgesucht. Das ist aber noch nicht das[ENTER]Schlimmste... Ich bin f\252r ihren Tod[ENTER]verantwortlich. "
gameforge.new_quest_lv52._066_say_reward = "Es sind vier Soldaten. Sie sagen, dass sie im Tal[ENTER]von Seungryong von Beschw\246rern und Peinigern[ENTER]gefoltert und get\246tet wurden. Ich war derjenige,[ENTER]der sie dorthin beordert hat - in ihren Tod! "
gameforge.new_quest_lv52._067_say_reward = "Was tun gegen solche Geister? "
gameforge.new_quest_lv52._068_say_reward = "Sie wollen Rache! Aber was kann ich tun? Wenn ich[ENTER]nun losziehe, um Vergeltung zu \252ben, ist das Dorf[ENTER]ohne F\252hrung und wird \252berrannt. Gehe ich nicht,[ENTER]werde ich noch verr\252ckt. "
gameforge.new_quest_lv52._069_say_reward = "Wenn ich nicht f\252r den Schutz des Dorfes mit all[ENTER]seinen Bewohnern verantwortlich w\228re, w\252rde ich[ENTER]sofort gehen. So sehe ich nur einen Ausweg: "
gameforge.new_quest_lv52._070_say_reward = "Jemand anderes muss an meiner Stelle Rache \252ben![ENTER]Aber wie kann ich weitere M\228nner in dieses Tal[ENTER]und somit in ihr Verderben schicken!? Wie kann[ENTER]ich das verlangen, nur damit ich ruhig schlafen[ENTER]kann? "
gameforge.new_quest_lv52._071_say_reward = "So eine Entscheidung ist nicht leicht. "
gameforge.new_quest_lv52._080_1_select = "Das Wohl des Dorfes... "
gameforge.new_quest_lv52._080_2_select = "Es wird ein Leichtes sein... "
gameforge.new_quest_lv52._080_3_select = "Das kann man nicht verlangen! "
gameforge.new_quest_lv52._081_say_reward = "...wiegt mehr als eure Skrupel. Ich werde eure[ENTER]M\228nner r\228chen. Und wenn ich nicht wiederkomme,[ENTER]sehen wir uns heute Nacht! "
gameforge.new_quest_lv52._082_say_reward = "...mit diesen Beschw\246rern und Peinigern fertig zu[ENTER]werden. Heute Nacht werdet ihr gut schlafen, das[ENTER]verspreche ich euch! "
gameforge.new_quest_lv52._083_say_reward = "Es grenzt an Selbstmord, sich mit Beschw\246rern und[ENTER]Peinigern anzulegen. Versucht den Geistern zu[ENTER]verdeutlichen, wie sehr ihr hier gebraucht[ENTER]werdet! "
gameforge.new_quest_lv52._084_say_reward = "Ihr habt recht. Dennoch hatte ich gehofft, ihr[ENTER]w\252rdet euch freiwillig melden und dem Dorf und[ENTER]mir somit einen gro\223en Dienst erweisen. "
gameforge.new_quest_lv52._090_1_select = "Nun gut... "
gameforge.new_quest_lv52._090_2_select = "Nein, das schaffe ich nicht! "
gameforge.new_quest_lv52._091_say_reward = "...wenn ich eure letzte Hoffnung bin, dann werde[ENTER]ich diese Beschw\246rer und Peiniger f\252r euch[ENTER]erledigen! "
gameforge.new_quest_lv52._092_say_reward = "Wenn ich das versuche, w\252rde euch noch ein[ENTER]weiterer Geist heimsuchen. "
gameforge.new_quest_lv52._093_say_reward = "Nun gut. Lass mich dich dennoch f\252r deine M\252he[ENTER]mit etwas Yang belohnen. "
gameforge.new_quest_lv52._093_say_reward_exp = "Du erh\228ltst 20.000 Erfahrungspunkte. "
gameforge.new_quest_lv52._093_say_reward_gold = "Du erh\228ltst 25.000 Yang. "
gameforge.new_quest_lv52._100_notice = "Das Gespr\228ch wurde beendet. "
gameforge.new_quest_lv52._110_say_reward = "Ich hatte gehofft, dass du so etwas sagst. Leider[ENTER]wei\223 ich nicht, welcher Beschw\246rer oder Peiniger[ENTER]sie get\246tet hat. Ich hoffe, dass ich es sp\252ren[ENTER]werde, wenn einer der Geister erl\246st wird. "
gameforge.new_quest_lv52._111_say_reward = "Ich werde dir einen Brief zukommen lassen.[ENTER]Die Geister teilten mir mit, dass die Rache im[ENTER]Dreieck des Drachgottes erfolgen muss. Dort[ENTER]befinden sich drei S\228ulen, die anscheinend die[ENTER]Eckpunkte des Dreiecks bilden. "
gameforge.new_quest_lv52._120_set_title = "R\228che 4 Gefallene "
gameforge.new_quest_lv52._125_say_title = "Brief vom Hauptmann "
gameforge.new_quest_lv52._130_say_reward = "Noch 3 Soldaten zu r\228chen! "
gameforge.new_quest_lv52._131_say = "Du scheinst Erfolg gehabt zu haben. Soeben habe[ENTER]ich die Stimme eines meiner gefallenen Soldaten[ENTER]vernommen. Er sagte, dass er mir verzeiht, da[ENTER]sein Tod nun ger\228cht wurde. Dies ist einzig dein[ENTER]Verdienst! "
gameforge.new_quest_lv52._132_say = "Bitte r\228che auch die anderen gefallenen Soldaten[ENTER]und t\246te Dunkle Peiniger, Dunkle Beschw\246rer, Hohe[ENTER]Peiniger und Hohe Beschw\246rer. Denke dabei stets[ENTER]daran, dass du sie nur im Dreieck der drei gro\223en[ENTER]S\228ulen des Drachengottes erl\246sen kannst. "
gameforge.new_quest_lv52._140_say_reward = "Noch 2 Soldaten zu r\228chen! "
gameforge.new_quest_lv52._141_say = "Wieder hast du einen der M\246rder meiner Soldaten[ENTER]erwischt! Mir war, als h\228tte ich im D\228mmerlicht[ENTER]einen der Gefallenen gesehen, der die Hand zum[ENTER]Abschied erhoben hatte. "
gameforge.new_quest_lv52._150_say_reward = "Noch 1 Soldat zu r\228chen! "
gameforge.new_quest_lv52._151_say = "Du bist unglaublich! Gerade eben noch stand der[ENTER]Geist eines gefallenen Soldaten neben mir und hat[ENTER]sich von mir verabschiedet. Vermutlich wird es[ENTER]nun sehr schwer sein, auch den letzten der M\246rder[ENTER]zu finden. "
gameforge.new_quest_lv52._160_say = "Die Geister, die den Hauptmann plagen, sind[ENTER]diejenigen junger Soldaten, die in seinem Auftrag[ENTER]fielen. Sie wurden von Dunklen Peinigern, Dunklen[ENTER]Beschw\246rern, Hohen Peinigern und Hohen[ENTER]Beschw\246rern get\246tet. "
gameforge.new_quest_lv52._161_say = "Du musst es schaffen, die verantwortlichen[ENTER]Peiniger und Beschw\246rer im Dreieck der drei[ENTER]S\228ulen des Drachengottes zu erledigen, um die[ENTER]Soldaten zu r\228chen. "
gameforge.new_quest_lv52._162_say = "Das Dreieck des Drachengottes befindet sich in[ENTER]der Mitte des Tals von Seungryong. "
gameforge.new_quest_lv52._170_send_letter = "Erster Soldat ger\228cht "
gameforge.new_quest_lv52._171_send_letter = "Zweiter Soldat ger\228cht "
gameforge.new_quest_lv52._172_send_letter = "Dritter Soldat ger\228cht "
gameforge.new_quest_lv52._173_send_letter = "Alle Soldaten ger\228cht "
gameforge.new_quest_lv52._180_say_reward = "Du hast alle 4 Soldaten ger\228cht! "
gameforge.new_quest_lv52._181_say = "Du hast auch den letzten der M\246rder gefunden![ENTER]Der letzte der vier gefallenen Soldaten ist mir[ENTER]soeben erschienen und bat mich, dir f\252r deinen[ENTER]Mut zu danken. Er hat auch etwas f\252r dich[ENTER]hinterlassen: %s "
gameforge.new_quest_lv52._182_say = "Komm zu mir, um deine Belohnung in Empfang zu[ENTER]nehmen. Ich warte auf dich in %s. "
gameforge.new_quest_lv52._183_say_reward = "Du hast mir und dem Dorf einen gro\223en Dienst[ENTER]erwiesen. Hier ist die Belohnung, die mir der[ENTER]Geist f\252r dich \252berreicht hat: %s "
gameforge.new_quest_lv52._184_say_reward = "Und hier ist noch etwas Yang von mir. Ich werde[ENTER]mich nun zur\252ckziehen und endlich in Ruhe[ENTER]schlafen. "
gameforge.new_quest_lv52._185_say_reward = "Ich stehe tief in deiner Schuld, mein Sohn. "
gameforge.new_quest_lv52._186_say_reward = "Ich bin dir auf ewig zu Dank verpflichtet. "
gameforge.new_quest_lv52._190_say_title = "Information: "
gameforge.new_quest_lv52._191_say_reward = "Du erh\228ltst 3.300.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 270.000 Yang.[ENTER]Du erh\228ltst ein Meisterbuch. "
gameforge.new_quest_lv52._85_say = "Dann vielleicht sp\228ter? Bitte geh zu Baek-Go,[ENTER]wenn du soweit bist! "
gameforge.new_quest_lv54 = {}
gameforge.new_quest_lv54._010_target = "Hauptmann "
gameforge.new_quest_lv54._020_say_title = "Der Nachschub "
gameforge.new_quest_lv54._030_say = "Um die Motivation unserer Truppen ist es momentan[ENTER]nicht gut bestellt - der Nachschub gestaltet sich[ENTER]schwierig. Die Gemischtwarenh\228ndlerin, eine[ENTER]wichtige Lieferantin, l\228sst uns seit Wochen nur[ENTER]eine geringe Zahl der Tr\228nke zukommen, die wir[ENTER]ben\246tigen. "
gameforge.new_quest_lv54._031_say_reward = "Bitte geh zur Gemischtwarenh\228ndlerin und bringe[ENTER]in Erfahrung, wo die Probleme liegen. "
gameforge.new_quest_lv54._032_select = "Ich besorge euch die Tr\228nke! "
gameforge.new_quest_lv54._040_say_title = "Gemischtwarenh\228ndlerin: "
gameforge.new_quest_lv54._040_set_title = "Nachschub "
gameforge.new_quest_lv54._050_target = "Gemischtwarenh\228ndlerin "
gameforge.new_quest_lv54._051_say = "Ja, in der letzten Zeit bereiten mir die[ENTER]Nachschublieferungen gro\223e Schwierigkeiten. Die[ENTER]Handelswege sind unsicher geworden, immer[ENTER]h\228ufiger tauchen Wegelagerer und wilde Bestien[ENTER]auf. Vor allem gegen die Tiger haben die[ENTER]fahrenden H\228ndler, von denen ich meine Waren[ENTER]beziehe, keine Chance. "
gameforge.new_quest_lv54._052_say = "Vielleicht kann der Hauptmann mit seinen Soldaten[ENTER]helfen. Geh bitte zu ihm und frage ihn, ob er[ENTER]Soldaten abstellen kann, um die H\228ndler zu[ENTER]sch\252tzen. "
gameforge.new_quest_lv54._054_say = "Geh zur Gemischtwarenh\228ndlerin und bringe in[ENTER]Erfahrung, warum der Nachschub an Tr\228nken ins[ENTER]Stocken geraten ist. "
gameforge.new_quest_lv54._055_say = "Die Gemischtwarenh\228ndlerin befindet sich in[ENTER]%s. "
gameforge.new_quest_lv54._056_say_title = "Hauptmann: "
gameforge.new_quest_lv54._060_say = "Die Handelswege sichern? Ja... im Grunde w\252rde[ENTER]ich das gerne tun. Nur verf\252ge ich nicht \252ber[ENTER]gen\252gend Soldaten, um auch noch die fahrenden[ENTER]H\228ndler aus anderen Reichen zu sch\252tzen. "
gameforge.new_quest_lv54._061_say = "Dar\252ber hinaus d\252rfen wir Soldaten keine Tiger[ENTER]jagen. Dies ist alleine den J\228gern der J\228gergilde[ENTER]gestattet. Es w\228re nicht f\246rderlich f\252r den[ENTER]Frieden im Dorf, gegen diese Bestimmungen zu[ENTER]versto\223en. "
gameforge.new_quest_lv54._062_say_reward = "Du m\252sstest dich daher an Yang-Shin wenden.[ENTER]Er ist Mitglied der J\228gergilde. Vielleicht kann[ENTER]er dir helfen, die Probleme mit den Tigern in den[ENTER]Griff zu bekommen. "
gameforge.new_quest_lv54._064_say = "Geh zum Hauptmann und versuche ihn zu \252berreden,[ENTER]die Handelswege gegen Tiger zu sichern. "
gameforge.new_quest_lv54._065_say = "Der Hauptmann befindet sich in %s. "
gameforge.new_quest_lv54._070_target = "Yang-Shin "
gameforge.new_quest_lv54._071_say = "Viele meiner J\228ger sind als Krieger einberufen[ENTER]worden und im Kampf gefallen. Nun ist es beinahe[ENTER]unm\246glich geworden, die Population der Wildtiere[ENTER]im Gleichgewicht zu halten. Besonders die[ENTER]Raubkatzen breiten ihre Reviere aus und gef\228hrden[ENTER]Reisende. "
gameforge.new_quest_lv54._072_say = "Wenn du uns in dieser Sache hilfst, kann ich dir[ENTER]als Belohnung diesen wertvollen Tigerschild+3[ENTER]meines gefallenen Kameraden Mi-Song anbieten.[ENTER]Daf\252r m\252sstest du die Tigerpopulation sp\252rbar[ENTER]dezimieren. "
gameforge.new_quest_lv54._073_say = "Besonders Verfluchte wei\223e Tiger haben sich[ENTER]unkontrolliert vermehrt. "
gameforge.new_quest_lv54._074_say = "Ich brauche als Beweis: "
gameforge.new_quest_lv54._075_say = "Jage daf\252r: "
gameforge.new_quest_lv54._076_say = "Suche Yang-Shin und versuche ihn zu \252berreden,[ENTER]die Handelswege gegen Tiger zu sichern. "
gameforge.new_quest_lv54._077_say_title = "Yang-Shin: "
gameforge.new_quest_lv54._078_say = "Yang-Shin befindet sich in %s. "
gameforge.new_quest_lv54._080_set_title = "Die Tigerfelle "
gameforge.new_quest_lv54._081_notice = "Ah, ein Prachtexemplar. Nur noch %s St\252ck! "
gameforge.new_quest_lv54._082_notice = "Erledigt! Schnell zur\252ck zu Yang-Shin. "
gameforge.new_quest_lv54._083_notice = "Dieses Tigerfell ist leider unbrauchbar. "
gameforge.new_quest_lv54._084_say = "Du brauchst noch %s x Schimmerndes Tigerfell. "
gameforge.new_quest_lv54._085_say = "Erbeute schimmernde Tigerfelle von Verfluchten[ENTER]wei\223en Tigern. "
gameforge.new_quest_lv54._090_npcChat = "Ich habe die Tigerfelle. "
gameforge.new_quest_lv54._091_say = "Das reicht mir noch lange nicht. Wie soll ich[ENTER]anhand dieser wenigen Felle feststellen, ob die[ENTER]Stra\223en wieder sicher sind? "
gameforge.new_quest_lv54._092_say = "Ahh endlich, diese Felle werden mir einen dicken[ENTER]Profit... \228hmm! Du bist noch hier? Dank dir sind[ENTER]die Wege endlich wieder sicher! Ich bin[ENTER]\252berzeugt, der Hauptmann wird dich daf\252r[ENTER]f\252rstlich entlohnen. "
gameforge.new_quest_lv54._093_say = "Und jetzt verzieh dich. Ich muss die Felle[ENTER]reinigen. "
gameforge.new_quest_lv54._094_say = "Ach, der Hauptmann gibt dir keine Belohnung?[ENTER]Das ist nicht mein Problem. Und falls du[ENTER]versuchst, mich anzuschw\228rzen wegen der Felle:[ENTER]Vergiss es, die gebe ich nicht mehr her! "
gameforge.new_quest_lv54._095_say_reward = "Aber ich habe dir einen Schild versprochen. Den[ENTER]sollst du nat\252rlich bekommen. F\252r dieses dreckige[ENTER]Ding habe ich sowieso keine Verwendung mehr. "
gameforge.new_quest_lv54._096_say = "Belohnung: "
gameforge.new_quest_lv54._097_say_reward = "Du erh\228ltst einen Tigerschild+3. "
gameforge.new_quest_lv54._098_say = "Du willst mich mit den paar Fellen abspeisen? So[ENTER]werde ich meine Schulden... ich meine, so werden[ENTER]die Stra\223en niemals sicher genug sein! "
gameforge.new_quest_lv54._099_say_reward = "Gehe so lang auf die Jagd, bis du %s Felle[ENTER]beisammen hast! "
gameforge.new_quest_lv54._100_say = "Das ist alles, schnell zur\252ck zu Yang-Shin. "
gameforge.new_quest_lv54._101_say_reward = "Du erh\228ltst 3.750.000 Erfahrungspunkte. "
gameforge.new_quest_lv54._102_say_reward = "Du erh\228ltst 125.000 Yang. "
gameforge.new_quest_lv7 = {}
gameforge.new_quest_lv7._010_target = "Octavio "
gameforge.new_quest_lv7._011_say_title = "Octavio: "
gameforge.new_quest_lv7._012_say_title = "Alte Frau: "
gameforge.new_quest_lv7._020_say_title = "Die Hochzeit der Tochter "
gameforge.new_quest_lv7._021_say = "Habt ihr Kinder? Dann w\252rdet ihr meine Sorge[ENTER]sicher verstehen... es geht um meine Tochter![ENTER]Sie hat diesen Mann kennengelernt, der ihr v\246llig[ENTER]den Kopf verdreht hat. Und nun ist sie mit ihrem[ENTER]Geliebten durchgebrannt. "
gameforge.new_quest_lv7._022_say = "Er stammt aus Chunjo. Nat\252rlich war ich dagegen![ENTER]Eine Dame aus Shinsoo kann doch keinen[ENTER]vergeistigten Tr\228umer aus Chunjo heiraten, dachte[ENTER]ich. Wir trennten uns im Streit, sie ist mit ihm[ENTER]geflohen. "
gameforge.new_quest_lv7._023_say = "Er stammt aus Jinno. Nat\252rlich war ich dagegen![ENTER]Eine Dame aus Chunjo kann doch keinen tumben[ENTER]Rohling aus Jinno heiraten, dachte ich. Wir[ENTER]trennten uns im Streit, sie ist mit ihm geflohen. "
gameforge.new_quest_lv7._024_say = "Er stammt aus Shinsoo. Nat\252rlich war ich dagegen![ENTER]Eine Dame aus Jinno kann doch keinen[ENTER]geldscheffelnden Weichling aus Shinsoo heiraten,[ENTER]dachte ich. Wir trennten uns im Streit, sie ist[ENTER]mit ihm geflohen. "
gameforge.new_quest_lv7._030_say = "Ich habe geh\246rt, dass sie ihn heiraten will. "
gameforge.new_quest_lv7._031_say = "Nun wartet meine Tochter auf ein Zeichen von mir.[ENTER]Was soll ich tun? Sie ist mein einziges Kind![ENTER]Nat\252rlich werde ich ihr meinen Segen geben.[ENTER]Bitte gehe f\252r mich zur Alten Frau und bitte sie,[ENTER]bei den Hochzeitsvorbereitungen zu helfen. "
gameforge.new_quest_lv7._040_target = "Alte Frau "
gameforge.new_quest_lv7._041_say = "Suche die alte Frau auf und bitte sie, die[ENTER]Hochzeitsvorbereitungen zu treffen. "
gameforge.new_quest_lv7._042_say = "Die alte Frau befindet sich in %s. "
gameforge.new_quest_lv7._051_say = "Eine Hochzeit, sagst du? Nun, das ist ein[ENTER]wichtiger Moment im Leben einer Frau. Alles muss[ENTER]stimmen, angefangen vom Brautkleid und dem[ENTER]Smoking des Br\228utigams bis zu den[ENTER]Verlobungsringen, die durch die Zeremonie zu[ENTER]Eheringen werden. Wenn der Brautvater sein[ENTER]Einverst\228ndnis erkl\228rt hat und die n\246tigen Yang[ENTER]f\252r die Zeremonie zur Verf\252gung stellt, so kann[ENTER]das Fest ausgerichtet werden. "
gameforge.new_quest_lv7._052_say = "Besonders wichtig sind Blumen - ohne einen[ENTER]Brautstrau\223, vom Br\228utigam an seine Liebste[ENTER]\252berreicht, kann keine Hochzeit stattfinden.[ENTER]Der Strau\223 sollte folgende Blumen enthalten: "
gameforge.new_quest_lv7._054_say = "Ich brauche: "
gameforge.new_quest_lv7._055_say = "Jage daf\252r: "
gameforge.new_quest_lv7._056_say = "Ich brauche auch noch: "
gameforge.new_quest_lv7._060_say = "Komm wieder zu mir, wenn du alle drei Blumen[ENTER]besorgt hast. Ich sehe nach, ob die Bl\252ten frisch[ENTER]genug sind und binde dann ein h\252bsches Bouquet[ENTER]daraus. Das kannst du anschlie\223end zu meiner[ENTER]Schwester bringen. Sie wird die Zeremonie[ENTER]durchf\252hren. "
gameforge.new_quest_lv7._081_say = "Sammle jeweils eine Blume von jeder Sorte. Du[ENTER]erh\228ltst sie, indem du Hungrige Alpha-W\246lfe,[ENTER]Hungrige Blauw\246lfe und Hungrige Alpha-Blauw\246lfe[ENTER]t\246test. "
gameforge.new_quest_lv7._082_say = "Diese verwelkte Blume ist nicht dekorativ.[ENTER]So viel Arbeit f\252r nichts! "
gameforge.new_quest_lv7._083_say = "Diese verwelkte Blume ist nicht dekorativ.[ENTER]So viel Arbeit f\252r nichts! "
gameforge.new_quest_lv7._084_say = "Diese verwelkte Blume ist nicht dekorativ.[ENTER]So viel Arbeit f\252r nichts! "
gameforge.new_quest_lv7._085_1_say_reward = "Dir fehlt noch %s Blutrote Blume. Du erh\228ltst[ENTER]sie, indem du Hungrige Alpha-W\246lfe t\246test. "
gameforge.new_quest_lv7._085_2_say_reward = "Dir fehlt noch %s Orangefarbene Blume. Du[ENTER]erh\228ltst sie, indem du Hungrige Blauw\246lfe t\246test. "
gameforge.new_quest_lv7._085_3_say_reward = "Dir fehlt noch %s Duftende gelbe Blume. Du[ENTER]erh\228ltst sie, indem du Hungrige Alpha-Blauw\246lfe[ENTER]t\246test. "
gameforge.new_quest_lv7._085_say_reward = "Dir fehlt noch %s Blutrote Blume. "
gameforge.new_quest_lv7._086_say_reward = "Dir fehlt noch %s Orangefarbene Blume. "
gameforge.new_quest_lv7._087_say_reward = "Dir fehlt noch %s Duftende gelbe Blume. "
gameforge.new_quest_lv7._088_notice = "Diese Blume ist ein Prachtexemplar. Sehr sch\246n! "
gameforge.new_quest_lv7._089_notice = "Diese Blume ist ein Prachtexemplar. Sehr sch\246n! "
gameforge.new_quest_lv7._090_notice = "Diese Blume ist ein Prachtexemplar. Sehr sch\246n! "
gameforge.new_quest_lv7._091_say = "Geschafft! Diese Blumen d\252rften f\252r einen sch\246nen[ENTER]Strau\223 ausreichen. Nun schnell zur\252ck zur Alten[ENTER]Frau, ehe sie die K\246pfe h\228ngen lassen! "
gameforge.new_quest_lv7._092_say = "Sammle Blumen f\252r das Hochzeitsbouquet. "
gameforge.new_quest_lv7._110_say = "Es sind h\252bsche Blumen, doch f\252r eine pr\228chtige[ENTER]Hochzeit gen\252gen sie nicht. "
gameforge.new_quest_lv7._111_say = "Du erh\228ltst sie, indem du Hungrige Alpha-W\246lfe,[ENTER]Hungrige Blauw\246lfe und Hungrige Alpha-Blauw\246lfe[ENTER]t\246test. "
gameforge.new_quest_lv7._112_say = "Diese Blumen sollten einen pr\228chtigen Strau\223[ENTER]ergeben. "
gameforge.new_quest_lv7._115_say = "Danke, das sieht sehr gut aus! Hier, nimm diesen[ENTER]Brautstrau\223 und begib dich damit zu meiner[ENTER]Schwester. "
gameforge.new_quest_lv7._116_say_reward = "Du findest sie in Bokjung im Reich Chunjo. "
gameforge.new_quest_lv7._117_say_reward = "Du findest sie in Bakra im Reich Jinno. "
gameforge.new_quest_lv7._118_say_reward = "Du findest sie in Yayang im Reich Shinsoo. "
gameforge.new_quest_lv7._120_set_title = "Die Schwester "
gameforge.new_quest_lv7._125_notice = "Das ist das richtige Reich, hier sollte ich die[ENTER]Schwester der Alten Frau finden. "
gameforge.new_quest_lv7._129_say = "Das ist das richtige Reich, hier sollte ich[ENTER]Octavio finden. "
gameforge.new_quest_lv7._130_say = "Das scheint das richtige Reich zu sein. Suche nun[ENTER]die Schwester der Alten Frau auf. "
gameforge.new_quest_lv7._131_say = "Das scheint nicht das richtige Reich zu sein. "
gameforge.new_quest_lv7._132_say_reward = "Du musst nach Bokjung im Reich Chunjo. "
gameforge.new_quest_lv7._133_say_reward = "Du musst nach Bakra im Reich Jinno. "
gameforge.new_quest_lv7._134_say_reward = "Du musst nach Yayang im Reich Shinsoo. "
gameforge.new_quest_lv7._135_say = "Kehre zur\252ck zu Octavio in Yongan im Reich[ENTER]Shinsoo. "
gameforge.new_quest_lv7._136_say = "Kehre zur\252ck zu Octavio in Joan im Reich Chunjo. "
gameforge.new_quest_lv7._137_say = "Kehre zur\252ck zu Octavio in Pyungmoo im Reich[ENTER]Jinno. "
gameforge.new_quest_lv7._140_say = "Hier sind Blumen f\252r die bevorstehende Hochzeit[ENTER]der Tochter Octavios. Sie sollen der Braut mit[ENTER]einem Segen \252berreicht werden. Sie wird wissen,[ENTER]von wem sie stammen. "
gameforge.new_quest_lv7._141_say = "Es sind wundersch\246ne Bl\252ten! Sie werden die Braut[ENTER]erstrahlen lassen. Damit sind die Vorbereitungen[ENTER]f\252r die Zeremonie komplett. Bitte richte doch[ENTER]Octavio aus, dass er zur Trauung eingeladen ist.[ENTER]Ich wei\223, es wird ihn freuen. "
gameforge.new_quest_lv7._142_say = "Auf zu Octavio, worauf wartest du noch? "
gameforge.new_quest_lv7._143_say = "Du bringst Blumen f\252r die Hochzeit von Octavios[ENTER]Tochter? Wie lieb von dir! Aber... wo sind sie[ENTER]denn? Hast du sie unterwegs verloren? "
gameforge.new_quest_lv7._144_say_reward = "Geh zur\252ck in dein Reich und besorge einen neuen[ENTER]Blumenstrau\223 f\252r die Hochzeit. "
gameforge.new_quest_lv7._145_say = "Schnell zur Schwester der Alten Frau, bevor die[ENTER]Blumen verwelken. "
gameforge.new_quest_lv7._150_say = "Warum riechst du nach Ochsenfroschsuppe?[ENTER]Ach egal, die Hauptsache ist, du bringst gute[ENTER]Nachrichten. "
gameforge.new_quest_lv7._151_say = "Ich danke dir vielmals. Ich bin so froh, dass ich[ENTER]am Hochzeitstag meiner Tochter dabei sein werde! "
gameforge.new_quest_lv7._152_say = "Hier, nimm deine Belohnung entgegen: "
gameforge.new_quest_lv7._153_say_reward = "Eine Waffe, geschmiedet f\252r die Hand eines[ENTER]Meisterk\228mpfers. Geh sorgf\228ltig damit um! "
gameforge.new_quest_lv7._154_say_reward = "Du erh\228ltst %s Erfahrungspunkte. "
gameforge.new_quest_lv7._155_say_reward = "Du erh\228ltst %s Yang. "
gameforge.new_quest_lv7._160_say = "Du musst mich mit einem entfernten Verwandten[ENTER]verwechseln. Ich habe keine Tochter und besitze[ENTER]auch nicht gen\252gend Yang, um eine Hochzeit[ENTER]ausrichten zu k\246nnen. "
gameforge.new_quest_lv7._165_say = "Aber m\246chtest du nicht mein Gast sein und einen[ENTER]L\246ffel Ochsenfroschsuppe probieren? Ich habe sie[ENTER]nach einem alten Rezept meiner Tante zubereitet. "
gameforge.new_quest_lv75 = {}
gameforge.new_quest_lv75._010_target = "Heuk-Young "
gameforge.new_quest_lv75._020_set_title = "Tagebuch einer Legende "
gameforge.new_quest_lv75._021_say = "Ich habe die \220berreste eines Kriegers gefunden.[ENTER]Ich wei\223 nicht, ob es sich um diesen Sura[ENTER]handelt, den Heuk-Young sucht, aber interessieren[ENTER]wird es sie bestimmt. "
gameforge.new_quest_lv75._022_say = "Hier sind mehr als nur ein Sura gestorben. Ihre[ENTER]\220berreste habe ich ja gesehen. Ob dieser[ENTER]legend\228re Krieger wohl auch unter ihnen ist?[ENTER]Ich sollte Heuk-Young davon berichten gehen. "
gameforge.new_quest_lv75._023_say = "Ich habe ein altes St\252ck Papier gefunden,[ENTER]eingefroren in einem Unterwelt-Eisgolem.[ENTER]Ich kann es kaum lesen, aber es k\246nnte sich dabei[ENTER]um einen Hinweis handeln, der Heuk-Young[ENTER]interessiert. "
gameforge.new_quest_lv75._024_say = "Inzwischen habe ich einiges gefunden, was[ENTER]Heuk-Young interessieren k\246nnte. Ich sollte zu[ENTER]ihr gehen und ihr das St\252ck Papier geben. Dabei[ENTER]kann ich ihr auch gleich von der Leiche erz\228hlen. "
gameforge.new_quest_lv75._025_say = "Heuk-Young hat mich gebeten, die Augen nach[ENTER]Hinweisen auf diesen legend\228ren Sura offen zu[ENTER]halten. Leider habe ich keine Ahnung, wonach ich[ENTER]\252berhaupt suche... "
gameforge.new_quest_lv75._030_say = "Suche nach dem legend\228ren K\228mpfer Akuma. Er war[ENTER]wom\246glich der ber\252hmteste Sura, der je gelebt hat[ENTER]- ein nahezu unbesiegbarer Krieger. Man sagt,[ENTER]dass er sogar den Kaiser herausgefordert hat. Ich[ENTER]denke, dass dieser Ort hier jener ist, an dem[ENTER]Akuma vor mehreren hundert Jahren verschwunden[ENTER]ist. Halte bitte Ausschau nach Spuren, die[ENTER]vielleicht nach all diesen Jahren noch auf seinen[ENTER]Aufenthalt hinweisen k\246nnen. "
gameforge.new_quest_lv75._040_say = "dummy "
gameforge.new_quest_lv75._050_npcChat = "Gefallenen Krieger betrachten "
gameforge.new_quest_lv75._060_say = "Es handelt sich um die \220berreste eines Kriegers.[ENTER]Der linke Arm sieht jedoch nicht menschlich[ENTER]aus... es muss ein Sura gewesen sein. Davon muss[ENTER]ich Heuk-Young erz\228hlen. "
gameforge.new_quest_lv75._070_notice = "Eine Buchseite... eingefroren in den \220berresten[ENTER]des Unterwelt-Eisgolems... "
gameforge.new_quest_lv75._090_say = "Ich kann auch nicht sagen, wonach wir genau[ENTER]suchen. Sieh dich einfach um und komm wieder zu[ENTER]mir, wenn du etwas gefunden hast. "
gameforge.new_quest_lv75._100_say = "Was hast du da? Lass mich sehen! "
gameforge.new_quest_lv75._105_say = "Eine Notiz\133 was ist das f\252r eine Schrift? Sie[ENTER]muss ziemlich alt sein. Es k\246nnte sein, dass du[ENTER]wirklich etwas Wichtiges gefunden hast. Das, was[ENTER]hier geschrieben steht, kommt mir bekannt vor. Es[ENTER]sieht so aus, als w\228re diese Seite fr\252her einmal[ENTER]Teil eines Buches gewesen. "
gameforge.new_quest_lv75._109_say = "Wenn wir mehr Seiten finden w\252rden, k\246nnte das[ENTER]alles einen Sinn ergeben. Halte Ausschau, auch[ENTER]nach weiteren Hinweisen! "
gameforge.new_quest_lv75._110_say = "Da bist du ja wieder. Du hast etwas gefunden?[ENTER]Erz\228hl! "
gameforge.new_quest_lv75._115_say = "Ein toter Sura\133 es k\246nnte sein, dass er es ist,[ENTER]oder einer aus seinem Gefolge. Aber wir brauchen[ENTER]mehr Beweise, um sicher zu sein. Suche nach[ENTER]weiteren Hinweisen, von denen man auf seine[ENTER]Identit\228t schlie\223en kann. Waffen, Schmuck...[ENTER]vielleicht Notizen oder \196hnliches. "
gameforge.new_quest_lv75._120_say = "Die Leiche eines Sura und eine Buchseite? Lass[ENTER]mich einen Blick auf das Pergament werfen...[ENTER]Hmm, es k\246nnte tats\228chlich sein, dass du Akumas[ENTER]\220berreste gefunden hast. Allerdings brauchen wir[ENTER]noch mehr Beweise. Schau bitte nach, ob du[ENTER]weitere Buchseiten finden kannst. "
gameforge.new_quest_lv75._130_say = "Ich habe bereits einen Anhaltspunkt gefunden, bin[ENTER]mir aber nicht sicher, ob dieser legend\228re Sura[ENTER]wirklich hier gewesen ist. Ich brauche mehr[ENTER]Informationen. "
gameforge.new_quest_lv75._140_1_select = "Gut. "
gameforge.new_quest_lv75._140_2_select = "Wesen aus Eis "
gameforge.new_quest_lv75._140_3_select = "Am Rande der Verzweiflung "
gameforge.new_quest_lv75._140_4_select = "Dunkle Schrecken "
gameforge.new_quest_lv75._140_5_select = "Das Angesicht des Todes "
gameforge.new_quest_lv75._140_6_select = "Das Schicksal des Kriegers "
gameforge.new_quest_lv75._140_7_select = "Nein, ich habe kein Interesse daran. "
gameforge.new_quest_lv75._150_say = "Ich kann hier nur Satzfetzen entziffern. Etwas[ENTER]von h\246fischem Leben und \252bertriebener[ENTER]Abenteuerlust... "
gameforge.new_quest_lv75._160_1_say = "Die Schrift auf dem vergilbten Pergament ist[ENTER]verblasst und zittrig, so als stamme sie von[ENTER]einem sehr alten oder sehr schwachen Menschen:[ENTER]\"...Wesen aus Eis. Selbst meine F\228higkeiten als[ENTER]Sura haben mir nicht geholfen, sie alle zu[ENTER]besiegen. Einige von ihnen streifen noch durch[ENTER]diese H\246hlen und wehe, sollten sie mich finden.[ENTER]Bisher bietet mir mein Versteck Schutz, doch[ENTER]bald...\" An dieser Stelle verblasst die Schrift. "
gameforge.new_quest_lv75._160_2_say = "Auch diese Seite ist durch ihr Alter stark in[ENTER]Mitleidenschaft gezogen. An dem Datum in der[ENTER]oberen Ecke erkennst du, dass es sich um eine Art[ENTER]Tagebuch handelt: \"Nicht zum ersten Mal w\252nsche[ENTER]ich mir, damals anders gehandelt zu haben, als[ENTER]ich die Grotte suchte. Wie stolz war ich, wie[ENTER]prahlerisch und selbstverliebt! All jene[ENTER]Eigenschaft haben mich hierher gef\252hrt, in meinen[ENTER]sicheren Tod...\" Das letzte Wort ist mehrmals[ENTER]dick unterstrichen. "
gameforge.new_quest_lv75._160_3_say = "Die Pergamentseite weist starke Besch\228digungen[ENTER]auf, teilweise sind St\252cke herausgerissen worden.[ENTER]Du kannst nur Teile der Botschaft entziffern:[ENTER]\"...Hof des Kaisers... als die Gelehrten mir[ENTER]beibrachten, was ich so innig zu wissen[ENTER]begehrte... leicht, die Portale zu \246ffnen,[ENTER]doch... Tod und Schrecken in der Dunkelh...\" Ein[ENTER]dicker, gezackter Riss verbirgt den Rest der[ENTER]Worte vor dir. "
gameforge.new_quest_lv75._160_4_say = "Auf dieser Pergamentseite findest du eine[ENTER]Zeichnung: Das l\228chelnde Gesicht einer Frau.[ENTER]Darunter stehen Worte in der Schrift geschrieben,[ENTER]die dir bereits bekannt ist. Nur scheint sie[ENTER]dieses Mal noch zittriger und unsicherer zu sein:[ENTER]\"Der Tod hat Klauen \150 ich wei\223 es seit gestern.[ENTER]Nur einen Blick habe ich auf die Kreatur[ENTER]geworfen, ehe die Angst mich hierher zur\252ck[ENTER]trieb. Oh meine geliebte Sunmi, wenn ich gewusst[ENTER]h\228tte! Wenn ich dieses uns\228gliche Grauen zuvor[ENTER]gekannt h\228tte, niemals w\228re ich hier herab[ENTER]gestiegen!\" "
gameforge.new_quest_lv75._160_5_say = "W\228hrend der Hee-Se Dynastie lebte ein legend\228rer[ENTER]Sura namens Akuma. Er war so talentiert im Kampf,[ENTER]dass sich mit der Zeit nur noch wenige Gegner[ENTER]fanden, an denen er sich messen konnte. So suchte[ENTER]er nach neuen Herausforderungen. Als ihm die[ENTER]Aufzeichnungen \252ber einen lang versiegelten Ort[ENTER]in die H\228nde fielen, setzte er alles daran, um[ENTER]diesen zu finden. Es gelang ihm, zu erlernen, wie[ENTER]er ein Portal zu jenem Platz finden und \246ffnen[ENTER]konnte. Er versprach, mit der Kunde seiner neuen[ENTER]Taten zu seiner Liebsten, Sunmi,[ENTER]zur\252ckzukehren... doch er wurde nie wieder[ENTER]gesehen. "
gameforge.new_quest_lv75._170_say = "Die Schrift wirkt altert\252mlich... zudem zittrig[ENTER]und ungleichm\228\223ig, so als habe der Schreiber[ENTER]nicht gen\252gend Kraft besessen... "
gameforge.new_quest_lv75._171_say = "Das ergibt keinen Sinn. Wir ben\246tigen mehr[ENTER]Aufzeichnungen. "
gameforge.new_quest_lv75._172_say = "So langsam glaube ich zu verstehen, was hier[ENTER]m\246glicherweise geschehen ist. Aber vieles ist[ENTER]noch unklar. "
gameforge.new_quest_lv75._173_say = "M\246chtest du die Einzelheiten wissen? "
gameforge.new_quest_lv75._174_say = "Noch eine Seite! Wer auch immer die Zeilen[ENTER]verfasst hat, er muss voller Verzweiflung gewesen[ENTER]sein. Soll ich f\252r dich zusammenfassen, was dort[ENTER]geschrieben steht? "
gameforge.new_quest_lv75._175_say = "Manche Seiten sind in einem solch schlechten[ENTER]Zustand, dass ich nur raten kann. Dennoch f\252gt[ENTER]sich so langsam die Geschichte zusammen, die sich[ENTER]vor langer Zeit in dieser H\246hle abgespielt hat. "
gameforge.new_quest_lv75._176_say = "Viel fehlt nicht mehr. M\246chtest du h\246ren, was ich[ENTER]bisher herausgefunden habe? "
gameforge.new_quest_lv75._177_say = "Es scheinen nicht mehr viele Seiten zu fehlen. "
gameforge.new_quest_lv75._178_say = "Willst du h\246ren, was ich bisher herausgefunden[ENTER]habe? "
gameforge.new_quest_lv75._180_notice = "Ich habe die letzte Buchseite bei den[ENTER]Unterwelt-Eisgolems gefunden. "
gameforge.new_quest_lv75._185_send_letter = "Das m\252ssten nun alle Seiten sein! "
gameforge.new_quest_lv75._190_notice = "Ich habe eine Buchseite bei den[ENTER]Unterwelt-Eisgolems gefunden. "
gameforge.new_quest_lv75._195_send_letter = "Eine Seite gefunden! "
gameforge.new_quest_lv75._200_npcChat = "Gefallenen Krieger durchsuchen "
gameforge.new_quest_lv75._210_say = "Bei den menschlichen \220berresten liegen 3 Seiten[ENTER]br\252chigen Pergaments. Gezackte Kanten lassen[ENTER]darauf schlie\223en, dass sie aus einem Buch[ENTER]gerissen wurden. Die Schrift darauf ist verblasst[ENTER]und schwer zu lesen. "
gameforge.new_quest_lv75._220_say = "Ich denke, das sollte reichen. Ich bringe meinen[ENTER]Fund zu Heuk-Young. "
gameforge.new_quest_lv75._230_say = "Wer hier wohl sein Leben gelassen hat? Auf jeden[ENTER]Fall hatte er nichts bei sich, was sich heute[ENTER]noch verwenden l\228sst. "
gameforge.new_quest_lv75._240_send_letter = "Ich habe die Seiten! "
gameforge.new_quest_lv75._250_say = "Ich sollte zu Heuk-Young zur\252ckkehren. Vielleicht[ENTER]kann sie das Puzzle zusammensetzen. "
gameforge.new_quest_lv75._270_say = "Ich bin erstaunt, dass du in diesen H\246hlen so[ENTER]viel gefunden hast. Diese Seiten scheinen[ENTER]urspr\252nglich Teil eines Buches gewesen zu sein.[ENTER]Was hier steht, ist sehr interessant. Mit den[ENTER]Geschichten, die ich geh\246rt habe, ergibt es einen[ENTER]Sinn... Wenn du mir die Seiten \252berl\228sst, binde[ENTER]ich dir daraus ein Buch. Vielleicht kannst du es[ENTER]nutzen, wenn du dich erneut in die Grotte der[ENTER]Verbannung begeben willst. Solltest du keine[ENTER]Verwendung mehr daf\252r haben, wird sich bestimmt[ENTER]jemand finden, der es dir f\252r eine ordentliche[ENTER]Summe abkauft. "
gameforge.new_quest_lv75._280_say = "Ich habe dir die Seiten zu einem Buch gebunden[ENTER]und noch einige meiner Aufzeichnungen[ENTER]hinzugef\252gt. Vielleicht nutzen sie dir. Wenn du[ENTER]m\246chtest, erz\228hle ich dir noch den Rest der[ENTER]Geschichte. "
gameforge.new_quest_lv75._290_1_select = "Ja, erz\228hl mir mehr! "
gameforge.new_quest_lv75._290_2_select = "Nein, das interessiert mich nicht! "
gameforge.new_quest_lv75._310_say = "Was willst du von mir? Kannst du nicht sehen,[ENTER]dass ich gerade \252ber ein Buch sinniere? "
gameforge.new_quest_lv75._320_say = "Soon: "
gameforge.new_quest_lv75._330_say = "Das ist ein sehr interessantes Buch, das du da in[ENTER]deinen H\228nden h\228ltst. Woher stammt es? Kann ich[ENTER]es mir mal ansehen? "
gameforge.new_quest_lv75._340_say = "Das sind Aufzeichnungen aus der Grotte der[ENTER]Verbannung, nicht wahr? Sie sehen sehr alt aus.[ENTER]Die Schrift ist ungew\246hnlich, die Schreibweise[ENTER]sehr alt... Es muss ein gro\223er Aufwand gewesen[ENTER]sein, an ein solches Buch zu gelangen. Du kannst[ENTER]dir sicherlich denken, dass ich solche B\252cher[ENTER]liebe. H\228ttest du Interesse daran, es zu[ENTER]verkaufen? "
gameforge.new_quest_lv75._350_1_select = "Ja. "
gameforge.new_quest_lv75._350_2_select = "Nein. "
gameforge.new_quest_lv75._360_say = "Wieviel Yang m\246chtest du f\252r das Buch haben? "
gameforge.new_quest_lv75._370_say = "Haha... du scheinst Scherze zu m\246gen. Mit dir[ENTER]kann man anscheinend keine Gesch\228fte machen. Ich[ENTER]mache dir einen Vorschlag: 500.000 Yang f\252r[ENTER]dieses legend\228re Tagebuch. Nimm es oder lass es[ENTER]bleiben! "
gameforge.new_quest_lv75._380_1_select = "Ich nehme die 500.000 Yang. "
gameforge.new_quest_lv75._380_2_select = "Dann lassen wir es bleiben! "
gameforge.new_quest_lv75._390_say = "Gut, dann nicht! "
gameforge.new_quest_lv75._400_say = "Nein, das ist mir einfach zu kostspielig. Tut mir[ENTER]leid! "
gameforge.new_quest_lv75._410_say = "Lass mich dir ein anderes Angebot machen. Du[ENTER]bekommst %s Yang f\252r dieses legend\228re Tagebuch. "
gameforge.new_quest_lv75._420_say = "Bist du einverstanden? "
gameforge.new_quest_lv75._425_say = "Das ist mein letztes Angebot! "
gameforge.new_quest_lv75._430_1_select = "Ich nehme die %s Yang. "
gameforge.new_quest_lv75._430_2_select = "Dann kommen wir nicht ins Gesch\228ft. "
gameforge.new_quest_lv75._440_say = "Wie du m\246chtest... "
gameforge.new_quest_lv75._450_say = "Das ist nicht gerade g\252nstig. Aber ich will[ENTER]gro\223z\252gig sein. "
gameforge.new_quest_lv75._460_say = "Ich lasse nur begrenzt mit mir handeln. Ich gebe[ENTER]dir 500.000 Yang f\252r das legend\228re Tagebuch. "
gameforge.new_quest_lv75._470_say = "Nimm es oder lass es bleiben! "
gameforge.new_quest_lv75._480_say = "Gut, dann nicht! "
gameforge.new_quest_lv75._490_say = "Sehr schade. Naja, vielleicht \252berlegst du es dir[ENTER]ja noch. "
gameforge.new_quest_lv80 = {}
gameforge.new_quest_lv80._010_target = "Soon "
gameforge.new_quest_lv80._020_set_title = "Die d\252stere Holzmaske "
gameforge.new_quest_lv80._030_say = "Du kommst gerade recht! Ich habe geh\246rt, dass du[ENTER]vor einiger Zeit in der Grotte der Verbannung[ENTER]gewesen bist? "
gameforge.new_quest_lv80._040_say = "Das ist das erste Mal, dass ich von jemandem[ENTER]h\246re, der von dort zur\252ckgekehrt ist. Ich muss[ENTER]zugeben, dass ich neugierig bin... "
gameforge.new_quest_lv80._050_1_say = "Ich h\228tte da eine Aufgabe, aber sie ist nicht[ENTER]ganz ungef\228hrlich. Allerdings k\246nnte ein Mann mit[ENTER]deiner Erfahrung sie bewerkstelligen. "
gameforge.new_quest_lv80._050_2_say = "Ich h\228tte da eine Aufgabe, aber sie ist nicht[ENTER]ganz ungef\228hrlich. Allerdings k\246nnte eine Frau[ENTER]mit deiner Erfahrung sie bewerkstelligen. "
gameforge.new_quest_lv80._060_say = "Nimm diese Holzmaske und begib dich in das Gebiet[ENTER]Doyyumhwan. Suche dort nach Flammengeistern.[ENTER]Du kennst sie wom\246glich - diese sph\228rischen[ENTER]Wesen, die \252ber und \252ber mit Flammen bedeckt[ENTER]sind. "
gameforge.new_quest_lv80._070_say = "Solltest du einen von ihnen t\246ten, wird die[ENTER]Holzmaske darauf reagieren und zu Asche[ENTER]verbrennen. Du solltest nur nicht den Mut[ENTER]verlieren, wenn es nicht gleich beim ersten[ENTER]Versuch funktioniert. "
gameforge.new_quest_lv80._080_say = "Die Asche bringst du dann zu mir zur\252ck. "
gameforge.new_quest_lv80._090_say = "Wenn du dich ohnehin in die Wildnis begibst,[ENTER]kannst du mir auch gleich noch %s Klumpen Eis[ENTER]mitbringen. Ich ben\246tige sie sehr dringend. "
gameforge.new_quest_lv80._100_say = "Yetis tragen sehr h\228ufig Eisklumpen bei sich![ENTER]Also, worauf wartest du noch? "
gameforge.new_quest_lv80._110_say_title = "Feuer und Eis "
gameforge.new_quest_lv80._120_say = "Soon hat mich beauftragt... "
gameforge.new_quest_lv80._130_say = "Die Eisklumpen habe ich bereits gefunden. "
gameforge.new_quest_lv80._140_say = "Ich brauche noch: "
gameforge.new_quest_lv80._150_say_reward = "Angeblich kann ich es finden, wenn ich Yetis[ENTER]jage! "
gameforge.new_quest_lv80._160_say = "Die D\252stere Holzmaske ist bereits zu[ENTER]Verzauberter Asche verbrannt. "
gameforge.new_quest_lv80._170_say = "Ich brauche: "
gameforge.new_quest_lv80._180_say_reward = "Ich muss daf\252r "
gameforge.new_quest_lv80._190_say_reward = "bei mir tragen. Soons Aussage zufolge verbrennt[ENTER]die Maske zu verzauberter Asche, wenn ich gegen[ENTER]Flammengeister k\228mpfe. "
gameforge.new_quest_lv80._200_say = "Ich brauche nun die Verzauberte Asche und die[ENTER]Eisklumpen.[ENTER]Sehr gut, warte bitte einen Augenblick... "
gameforge.new_quest_lv80._210_say = "Es hat funktioniert! Was in den alten Schriften[ENTER]steht, ist wirklich wahr! "
gameforge.new_quest_lv80._220_say = "Ich habe aus den Gegenst\228nden, die du mir[ENTER]gebracht hast, Schwarzes Eis hergestellt. "
gameforge.new_quest_lv80._230_say = "Ich habe allerdings noch eine weitere Aufgabe[ENTER]f\252r dich, die mit der ersten zusammenh\228ngt.[ENTER]Wenn du auch diese erf\252llst, \252berlasse ich dir[ENTER]all meine Ersparnisse! "
gameforge.new_quest_lv80._240_say = "Bringe das Schwarze Eis in die Grotte der[ENTER]Verbannung und opfere es dort auf einem Dunklen[ENTER]Schrein. "
gameforge.new_quest_lv80._250_say = "Es fehlen noch %s Klumpen Eis. "
gameforge.new_quest_lv80._260_notice = "Hier stimmt etwas nicht. "
gameforge.new_quest_lv80._270_say = "Sehr gut - ich sehe, du tr\228gst das Eis bei dir.[ENTER]Nun brauche ich noch die verzauberte Asche. "
gameforge.new_quest_lv80._280_say = "Worauf wartest du noch...? "
gameforge.new_quest_lv80._290_say = "Hm... es handelt sich zwar um Asche, aber sie[ENTER]scheint gew\246hnlich und nicht verzaubert zu sein.[ENTER]Es hat nicht funktioniert. "
gameforge.new_quest_lv80._300_target = "Dunkler Schrein "
gameforge.new_quest_lv80._310_set_title = "Der dunkle Schrein "
gameforge.new_quest_lv80._320_say = "Ich soll das Schwarze Eis in die Grotte der[ENTER]Verbannung bringen und dort auf einem Altar[ENTER]opfern. Diese Opferst\228tte wird nicht leicht zu[ENTER]finden sein! "
gameforge.new_quest_lv80._330_npcChat = "Schwarzes Eis opfern! "
gameforge.new_quest_lv80._340_say = "Als du dich dem Altar n\228herst, scheint sich die[ENTER]Dunkelheit um dich zu verdichten. Geisterhafte[ENTER]Stimmen fl\252stern dir von ewigen Qualen. Es ist[ENTER]ein wahrhaft gottloser Ort.[ENTER]M\246chtest du das Schwarze Eis wirklich opfern? "
gameforge.new_quest_lv80._350_1_select = "Ja! Was soll schon passieren? "
gameforge.new_quest_lv80._350_2_select = "Nein, das nimmt kein gutes Ende! "
gameforge.new_quest_lv80._360_say = "Ganz sicher bin ich mir nicht, ob ich das[ENTER]Richtige getan habe - ein Opfer in dieser Grotte[ENTER]zu bringen... das wird sicher nicht die[ENTER]Zustimmung des Drachengottes finden. Ich[ENTER]w\252nschte, ich k\246nnte es r\252ckg\228ngig machen. "
gameforge.new_quest_lv80._370_say = "Die Sache gef\228llt mir nicht. Ein Opfer in dieser[ENTER]Grotte zu bringen w\252rde sicher nicht die[ENTER]Zustimmung des Drachengottes finden.[ENTER]Ich lasse es lieber sein. "
gameforge.new_quest_lv80._380_say = "Das ist der falsche Schrein! "
gameforge.new_quest_lv80._390_send_letter = "Zur\252ck zu Soon "
gameforge.new_quest_lv80._400_set_title = "Seltsame Monster "
gameforge.new_quest_lv80._410_say = "Ich sollte zu Soon zur\252ckkehren, um mir meine[ENTER]Belohnung abzuholen. "
gameforge.new_quest_lv80._420_say = "Ich habe geh\246rt, dass in manchen Teilen des[ENTER]Landes seit einiger Zeit seltsame Monster[ENTER]gesichtet werden. "
gameforge.new_quest_lv80._430_say = "Ich hoffe es h\228ngt nicht damit zusammen, dass ich[ENTER]das Schwarze Eis in der Grotte der Verbannung[ENTER]geopfert habe. "
gameforge.new_quest_lv80._440_say = "Sehr gut gemacht! Hier ist deine Belohnung. "
gameforge.new_quest_lv80._450_npcChat = "Hast du das Monster gesehen? "
gameforge.new_quest_lv80._460_say = "Ein %s?! Meine G\252te... ich frage mich, wie so[ENTER]etwas passieren kann... Ich werde sofort meine[ENTER]B\252cher befragen! "
gameforge.new_quest_lv80._470_say = "Ich konnte das Schwarze Eis nicht opfern... es[ENTER]f\252hlte sich so falsch an! Ich werde zu Soon[ENTER]gehen und ihm sagen, dass ich diesen Auftrag[ENTER]nicht ausf\252hren werde. "
gameforge.new_quest_lv80._475_npcChat = "Das Schwarze Eis "
gameforge.new_quest_lv80._476_say = "Wie ich sehe, tr\228gst du das Schwarze Eis nicht[ENTER]mehr bei dir. Du hast es also tats\228chlich[ENTER]geopfert? Erz\228hl, was ist dann passiert?! "
gameforge.new_quest_lv80._477_say = "Verzeihung, aber das ist ein Missverst\228ndnis -[ENTER]ich habe das Schwarze Eis noch. Ich werde es[ENTER]holen und sp\228ter wiederkommen... "
gameforge.new_quest_lv80._480_say = "Ah, da bist du ja wieder! Warum tr\228gst du das[ENTER]Schwarze Eis noch bei dir? "
gameforge.new_quest_lv80._490_say = "Ich kann nicht tun, was du von mir verlangst.[ENTER]Es w\252rde gegen den Willen des Drachengottes[ENTER]gehen. Ich werde das Eis nicht opfern! "
gameforge.new_quest_lv80._495_say = "Pah, so ein Nichtsnutz! Kann nicht einmal die[ENTER]einfachsten Auftr\228ge erledigen. Dann muss ich[ENTER]eben jemanden suchen, der nicht so zimperlich[ENTER]ist. Gib mir das Eis zur\252ck! Los, her damit! "
gameforge.new_quest_lv80._500_say = "Soll ich Soon wirklich das Schwarze Eis[ENTER]\252berlassen? "
gameforge.new_quest_lv80._510_1_select = "Ja, ich will es los sein! "
gameforge.new_quest_lv80._510_2_select = "Nein, sonst stellt er etwas an! "
gameforge.new_quest_lv80._520_say = "Hier, nimm dein Schwarzes Eis und lass mich in[ENTER]Ruhe! "
gameforge.new_quest_lv80._530_say = "Erwartest du etwa meinen Dank? Geh mir aus den[ENTER]Augen! "
gameforge.new_quest_lv80._535_sayReward = "Du erh\228ltst 70.000.000 Erfahrungspunkte. "
gameforge.new_quest_lv80._540_say = "Du bekommst das Eis nicht zur\252ck. Ich werde es im[ENTER]Meer versenken - dort kann es keinen Schaden[ENTER]anrichten! "
gameforge.new_quest_lv80._550_say = "Das wagst du nicht! Gib mir mein Eigentum zur\252ck[ENTER]oder ich werde dich und deine Familie verfluchen. "
gameforge.new_quest_lv80._560_say = "Mach was du willst - ich lasse mich von dir[ENTER]nicht aufhalten. "
gameforge.new_quest_lv80._570_target_pos = "S\252dlicher Strand "
gameforge.new_quest_lv80._580_target_pos = "Westlicher Strand "
gameforge.new_quest_lv80._590_target_pos = "\214stlicher Strand "
gameforge.new_quest_lv80._599_set_title = "Ende eines Irrwegs "
gameforge.new_quest_lv80._600_say = "Ich sollte nach Yongan gehen und das Schwarze Eis[ENTER]dort ins Meer werfen. "
gameforge.new_quest_lv80._610_say = "Ich sollte nach Joan gehen und das Schwarze Eis[ENTER]dort ins Meer werfen. "
gameforge.new_quest_lv80._620_say = "Ich sollte nach Pyungmoo gehen und das Schwarze[ENTER]Eis dort ins Meer werfen. "
gameforge.new_quest_lv80._630_say_reward = "Als du das Eis den Fluten \252bergeben willst,[ENTER]schmilzt es innerhalb eines Augenblicks. Schwarze[ENTER]Fl\252ssigkeit tropft von deinen Fingern zu Boden[ENTER]- und verdampft, noch ehe sie diesen ber\252hren[ENTER]kann. "
gameforge.new_quest_lv80._640_say = "Pl\246tzlich erscheinen aus dem Nichts folgende[ENTER]Gegenst\228nde direkt vor dir: "
gameforge.new_quest_lv80._650_say = "Als du die Gegenst\228nde aufhebst, f\252hlst du eine[ENTER]innere Zufriedenheit sowie die Gewissheit,[ENTER]richtig gehandelt zu haben. Den Dank des[ENTER]Drachengottes h\228ltst du nun in deinen H\228nden. "
gameforge.new_quest_lv80._660_say = "Oh nein, ich habe vergessen das Schwarze Eis[ENTER]mitzunehmen! Mir bleibt wohl nichts \252brig, als es[ENTER]zu holen und dann wieder hierher zu kommen. "
gameforge.new_quest_lv80._670_sayReward = "Du erh\228ltst au\223erdem 120.000.000[ENTER]Erfahrungspunkte. "
gameforge.new_quest_premium_lv4 = {}
gameforge.new_quest_premium_lv4._100_npcChat = "Laden \246ffnen "
gameforge.new_quest_premium_lv4._100_say_reward = "Jage daf\252r: "
gameforge.new_quest_premium_lv4._10_targetVid = "Gemischtwarenh\228ndlerin "
gameforge.new_quest_premium_lv4._110_say = "Suche den Waffenh\228ndler und frage ihn, warum er[ENTER]nachts nicht mehr unter dem Fenster der[ENTER]Gemischtwarenh\228ndlerin singt. "
gameforge.new_quest_premium_lv4._120_qSetTitle = "Flieder sammeln "
gameforge.new_quest_premium_lv4._130_notice = "Du hast einen sch\246nen Fliederzweig erbeutet! "
gameforge.new_quest_premium_lv4._140_notice = "Fertig! Schnell zur\252ck zum Waffenh\228ndler. "
gameforge.new_quest_premium_lv4._150_notice = "Leider ist dieser Fliederzweig bereits verwelkt. "
gameforge.new_quest_premium_lv4._160_say = "Du ben\246tigst noch die folgende Menge an[ENTER]Fliederzweigen: %s. "
gameforge.new_quest_premium_lv4._170_say = "Das gen\252gt nicht. Dieser Flieder reicht gerade[ENTER]f\252r ein paar Tr\246pfchen! "
gameforge.new_quest_premium_lv4._180_say = "Ahh, der Flieder! Dazu brauche ich aber noch ein[ENTER]ungew\246hnliches Moschus\246l. Das kannst du aber nur[ENTER]in einem ganz speziellen Laden bestellen. Eine[ENTER]drehende M\252nze wird dir den Weg weisen. Dazu[ENTER]ben\246tigst du Drachenmarken - du hast doch sicher[ENTER]noch welche auf der hohen Kante? Ich w\228re dir so[ENTER]unendlich dankbar! Die Bestellung kannst du[ENTER]anschlie\223end beim Lagerverwalter abholen. Dann,[ENTER]endlich, h\228tte ich alle Zutaten beisammen! "
gameforge.new_quest_premium_lv4._190_say = "Bitte beeile dich und bringe mir schnell das[ENTER]Moschus\246l. Daf\252r sollst du auch eine Belohnung[ENTER]erhalten! "
gameforge.new_quest_premium_lv4._200_say_reward = "Gehe so lange auf die Jagd, bis du mir %s[ENTER]Fliederzweige bringen kannst! "
gameforge.new_quest_premium_lv4._20_sayTitle = "Mein Schatz "
gameforge.new_quest_premium_lv4._210_say = "T\246te Blauw\246lfe, um sie zu bekommen. "
gameforge.new_quest_premium_lv4._220_say = "Das ist alles. Schnell zur\252ck zum Waffenh\228ndler. "
gameforge.new_quest_premium_lv4._230_qSetTitle = "Das Moschus\246l "
gameforge.new_quest_premium_lv4._240_say = "Ich danke dir von Herzen. Nun kann ich endlich[ENTER]ein neues Duft\246l herstellen. "
gameforge.new_quest_premium_lv4._250_say = "Du kannst meinem Singvogel ausrichten, dass ich[ENTER]heute wieder vor ihrem Fenster singen werde. Sie[ENTER]wird sich freuen. "
gameforge.new_quest_premium_lv4._260_say = "Du hast dir eine Belohnung verdient: "
gameforge.new_quest_premium_lv4._270_say_reward = "%s Yang "
gameforge.new_quest_premium_lv4._280_say = "Ohne das Moschus\246l kann ich mein Duft\246l nicht[ENTER]herstellen. Bitte lasse dich von der drehenden[ENTER]M\252nze leiten und besorge mir ein Exemplar davon!! "
gameforge.new_quest_premium_lv4._290_say_reward = "Komme mit %s x Moschus\246l! "
gameforge.new_quest_premium_lv4._300_say = "Ich muss dem Waffenh\228ndler das Moschus\246l[ENTER]bringen. Ich soll mich von der drehenden M\252nze[ENTER]leiten lassen, ein ungew\246hnliches Duft\246l[ENTER]bestellen und dieses beim Lagerverwalter abholen. "
gameforge.new_quest_premium_lv4._30_say = "Ich vermisse meinen Schatz, den Waffenh\228ndler.[ENTER]Wochenlang hat er jeden Abend vor meinem Fenster[ENTER]gesungen und nun h\246re ich seit einigen Tagen[ENTER]nichts von ihm. Vielleicht f\252rchtet er den Zorn[ENTER]meines Vaters. Kannst du herausfinden, was mit[ENTER]ihm los ist? "
gameforge.new_quest_premium_lv4._310_say_title = "Der Waffenh\228ndler "
gameforge.new_quest_premium_lv4._320_say = "Oh, vielen Dank. Er war also nur verhindert,[ENTER]sagst du? Da bin ich aber froh. Ich werde heute[ENTER]Abend auf ihn warten. "
gameforge.new_quest_premium_lv4._330_say_reward = "F\252r deine M\252hen bekommst du: %s Erfahrungspunkte. "
gameforge.new_quest_premium_lv4._340_say = "Schnell zur\252ck zur Gemischtwarenh\228ndlerin. "
gameforge.new_quest_premium_lv4._350_npcChat = "Flieder "
gameforge.new_quest_premium_lv4._35_qSetTitle = "Sprich mit dem Waffenh\228ndler "
gameforge.new_quest_premium_lv4._360_npcChat = "Das Moschus\246l "
gameforge.new_quest_premium_lv4._40_qSetTitle = "Ein neuer Duft "
gameforge.new_quest_premium_lv4._45_qSetTitle = "Jage Blauw\246lfe "
gameforge.new_quest_premium_lv4._50_targetVid = "Waffenh\228ndler "
gameforge.new_quest_premium_lv4._55_qSetTitle = "Zur\252ck zum Waffenh\228ndler "
gameforge.new_quest_premium_lv4._60_sayTitle = "Der Schelm "
gameforge.new_quest_premium_lv4._65_qSetTitle = "Bring Moschus\246l zum Waffenh\228ndler "
gameforge.new_quest_premium_lv4._70_say = "Es stimmt, ich singe nicht mehr vor ihrem[ENTER]Fenster, weil... ach, es ist mir peinlich,[ENTER]dar\252ber zu reden! Mein K\246rpergeruch ist ziemlich[ENTER]unangenehm geworden. Ich wasche mich zwar immer,[ENTER]aber der Geruch bleibt. Daher m\246chte ich ein[ENTER]Duft\246l herstellen, das die[ENTER]Gemischtwarenh\228ndlerin, meinen kleinen Singvogel,[ENTER]durch seinen herben und faszinierenden Duft[ENTER]bet\246rt. Sie legt gro\223en Wert auf die \228u\223ere[ENTER]Erscheinung. "
gameforge.new_quest_premium_lv4._75_qSetTitle = "Zur Gemischtwarenh\228ndlerin "
gameforge.new_quest_premium_lv4._80_say = "Ich muss unbedingt Duft\246l herstellen. Nur damit[ENTER]kann ich meinen unangenehmen K\246rpergeruch[ENTER]beseitigen. "
gameforge.new_quest_premium_lv4._90_say = "Dazu muss ich verschiedene Zutaten mischen.[ENTER]Diese zuerst: "
gameforge.notify_test_server = {}
gameforge.notify_test_server._10_chat = "Testserver "
gameforge.npc_talk = {}
gameforge.npc_talk._100_say = "Ich bin ein sehr alter Mann, aber ich bin immer[ENTER]noch kr\228ftig und gesund, denn ich habe ein[ENTER]besonderes Geheimnis.[ENTER]Ich habe herausgefunden, dass ein Trank aus[ENTER]Gango-Wurzelsaft und Tue-Pilzen das Leben[ENTER]verl\228ngert. Wenn du diesen Trank auch mal[ENTER]probieren willst, solltest du mit den Zutaten zu[ENTER]Yu-Hwan gehen. Er wird dir sicher einen Trank[ENTER]brauen. "
gameforge.npc_talk._10_say = "Stillgestanden und Haltung bewahren![ENTER]Benimm dich und fange keinen Streit an. Du[ENTER]solltest Respekt gegen\252ber deinen Mitmenschen[ENTER]haben. Verstanden? "
gameforge.npc_talk._110_npcChat = "Du siehst ziemlich stark aus... "
gameforge.npc_talk._120_say = "Seit vielen Jahren wird in unserer Familie das[ENTER]Geheimnis der St\228rke weitergeben. Wenn man die[ENTER]Glockenblume auf richtige Art und Weise zu einem[ENTER]Trank verarbeitet, erz\228hlte mein Vater, kann[ENTER]dieser Trank dir f\252r kurze Zeit St\228rke verleihen.[ENTER]Soweit ich wei\223, kann Baek-Go diesen Trank[ENTER]herstellen. Du musst ihm nur eine Glockenblume[ENTER]bringen. "
gameforge.npc_talk._130_npcChat = "Im Fr\252htau zu Berge wir ziehn, fallera... "
gameforge.npc_talk._140_sayTitle = "Yu-Hwan, der Musiker: "
gameforge.npc_talk._150_say = "...es gr\252nen alle W\228lder, alle H\246hn, fallera...[ENTER]Bist du auch ein Musikfreund? Ich singe in[ENTER]aller Abgeschiedenheit, um nicht in den Krieg[ENTER]verwickelt zu werden. Aber ohne ein Land, das[ENTER]mich besch\252tzt, kann ich dieser Mu\223e nicht[ENTER]fr\246nen. "
gameforge.npc_talk._160_npcChat = "Warum liest du so viel? "
gameforge.npc_talk._170_sayTitle = "Soon, der B\252cherwurm: "
gameforge.npc_talk._180_say = "Oh, Abenteurer! Die Welt ist voller Probleme. Nur[ENTER]mit dem n\246tigen Wissen kann man \252berleben.[ENTER]Darum halte deine B\252cher immer in Ehren. In[ENTER]schlechten Zeiten \150 und die Zeiten sind[ENTER]heutzutage immer schlecht \150 werden sie dir[ENTER]weiterhelfen. Das kannst du mir ruhig glauben! "
gameforge.npc_talk._190_npcChat = "Hast du eigentlich Kinder? "
gameforge.npc_talk._200_say = "Eigentlich wollte ich keine Kinder, aber...[ENTER]Ich sammle immer mal wieder Kakibl\252ten, weil man[ENTER]mit ihnen \150 bei richtiger Zubereitung \150 die[ENTER]magische Energie st\228rken kann. Baek-Go hat das[ENTER]herausgefunden. Er braucht nur eine einzige[ENTER]Bl\252te, um daraus 100 Tr\228nke herzustellen.[ENTER]Leider hat die Kakibl\252te auch eine Nebenwirkung.[ENTER]Wenn eine Frau eine Kette aus diesen Bl\252te um[ENTER]den Hals tr\228gt, dann bekommt sie einen Sohn. Im[ENTER]Vertrauen: Meine Frau hat das schamlos[ENTER]ausgenutzt. "
gameforge.npc_talk._20_npcChat = "Hier riecht es aber gut... "
gameforge.npc_talk._210_npcChat = "Was ist mit deinem Fu\223? "
gameforge.npc_talk._220_sayTitle = "Handu-Up: "
gameforge.npc_talk._230_say = "Es geht schon wieder. Beim Spazierengehen[ENTER]stolperte ich \252ber eine Gango-Wurzel und[ENTER]verstauchte mir den Fu\223. Zum Gl\252ck kenne ich den[ENTER]Heilkundigen Baek-Go. Er hat mich behandelt und[ENTER]mir einen Tipp gegeben: Zum Heilen kleinerer[ENTER]Wunden kann man aus eben dieser Gango-Wurzel[ENTER]einen Trank brauen. Also habe ich den kleinen[ENTER]\220belt\228ter in Tee verwandelt und er hat den[ENTER]Schaden, den er angerichtet hatte, auch wieder[ENTER]beseitigt... "
gameforge.npc_talk._240_npcChat = "Wer bist du? "
gameforge.npc_talk._250_sayTitle = "Wonda-Rim: "
gameforge.npc_talk._260_say = "Ich bin Wonda-Rim, der Neffe von Chaegirab. Mein[ENTER]Onkel ist eine Ber\252hmtheit! Kennst du ihn? Er[ENTER]experimentiert viel mit Tr\228nken und Kr\228utern.[ENTER]Dabei hat er herausgefunden, dass man einen sehr[ENTER]m\228chtigen Schutz gegen magische Energie erh\228lt,[ENTER]wenn man 100 Bo-Wasser mit einer Maulbeere[ENTER]mischt. Soweit ich wei\223, kann Huahn-So solche[ENTER]Tr\228nke herstellen, wenn du ihm die Zutaten[ENTER]bringst. "
gameforge.npc_talk._270_npcChat = "Warum hast du so viele Narben? "
gameforge.npc_talk._280_sayTitle = "Verr\228ter Balso: "
gameforge.npc_talk._290_say = "Ich bin kein guter K\228mpfer und wurde im Krieg[ENTER]st\228ndig verletzt. Irgendwann fragte ich Yu-Hwan,[ENTER]ob er nicht einen Trank f\252r mich herstellen kann,[ENTER]der meinen K\246rper vor Verletzungen sch\252tzt. Er[ENTER]braute mir etwas aus Glockenblumensaft und[ENTER]Flieder, doch leider war der Schutz nicht[ENTER]ausreichend. Vielleicht lag es auch an meiner[ENTER]Unf\228higkeit. Dir wird der Trank in deinen K\228mpfen[ENTER]sicher helfen. "
gameforge.npc_talk._300_npcChat = "Warum nennt man dich Verr\228ter? "
gameforge.npc_talk._30_sayTitle = "Octavio, der Restaurantbesitzer: "
gameforge.npc_talk._310_say = "Ich bin einst vor dem Krieg geflohen und habe[ENTER]mich der Schwarzwindbande angeschlossen. Meine[ENTER]Kameraden haben mir das nie verziehen. Sp\228ter[ENTER]stellte ich fest, dass die Schwarzwindkrieger[ENTER]unschuldige Menschen t\246ten. Da habe ich mich[ENTER]sofort von ihnen getrennt. Es war furchtbar! "
gameforge.npc_talk._320_say = "Du hast unschuldige Menschen auf dem Gewissen?[ENTER]Dann f\252hrst du deinen Titel zurecht. Du hast sie[ENTER]darum gebracht, ein gutes Leben zu f\252hren. "
gameforge.npc_talk._330_say = "Es ist eine gesetzlose Welt. Aber ich habe[ENTER]beschlossen, nichts Schlechtes mehr zu tun,[ENTER]niemals. Die Leute sollten mich nicht als[ENTER]Verr\228ter bezeichnen.[ENTER]Hast du etwas Yang f\252r mich? "
gameforge.npc_talk._340_npcChat = "Man nennt dich den Gelehrten? "
gameforge.npc_talk._350_sayTitle = "Uriel, der Gelehrte: "
gameforge.npc_talk._360_say = "In dieser weiten Welt gibt es so unglaublich viel[ENTER]zu lernen. Unwissenheit verbunden mit[ENTER]milit\228rischer Macht ist besonders gef\228hrlich. Du[ENTER]willst doch nicht wie diese unwissenden Soldaten[ENTER]leben, oder? Wissen ist Macht! "
gameforge.npc_talk._370_npcChat = "Man sagte mir, du seist Heilkundiger? "
gameforge.npc_talk._380_say = "Ich tue, was ich kann. Aber in dieser[ENTER]gef\228hrlichen Welt gibt es jeden Tag mehr[ENTER]Verletzte. Wir haben viel zu wenig Arzneien und[ENTER]an Helfern mangelt es auch. Die Zeiten sind hart![ENTER]Vielleicht kannst du mir sp\228ter ein wenig zur[ENTER]Hand gehen? "
gameforge.npc_talk._390_npcChat = "Wie l\228uft das Jagdgesch\228ft? "
gameforge.npc_talk._400_sayTitle = "Yang-Shin, der J\228ger: "
gameforge.npc_talk._40_say = "Willkommen! Unser traditioneller Familienbetrieb[ENTER]ist so erfolgreich, dass wir weltweit Restaurants[ENTER]er\246ffnen konnten. Wenn dir der Sinn nach etwas[ENTER]Leckerem steht, dann komm vorbei und iss bei[ENTER]uns. "
gameforge.npc_talk._410_say = "Hmm, seit die Metinsteine fallen, sind die Tiere[ENTER]wild geworden. Heutzutage riskiert man schon beim[ENTER]H\252hnerfangen sein Leben. Es ist eine gef\228hrliche[ENTER]Zeit f\252r einen J\228ger. Zum Gl\252ck bin ich einer der[ENTER]Besten! "
gameforge.npc_talk._420_npcChat = "Woher r\252hrt deine Treffsicherheit? "
gameforge.npc_talk._430_say = "Mit dem Bogen bin ich unschlagbar, denn ich habe[ENTER]ein spezielles Rezept, hehe! Wenn du[ENTER]Pfirsichbl\252tensaft mit Flieder mischst, bekommst[ENTER]du einen Trank, der deine Treffsicherheit erh\246ht.[ENTER]Bringe Yu-Hwan die Zutaten, dann braut er dir[ENTER]bestimmt diesen Trank. "
gameforge.npc_talk._440_npcChat = "So ein sch\246ner Blumenkranz... "
gameforge.npc_talk._450_say = "Fr\252her habe ich immer mit meinem Bruder[ENTER]Pfirsichbl\252ten gesammelt. Heute muss ich das[ENTER]alleine machen. Die Bl\252ten sehen aber nicht nur[ENTER]h\252bsch aus, sie haben auch eine besondere[ENTER]Wirkung: Wenn man eine Pfirsichbl\252te zu Baek-Go[ENTER]bringt, braut er daraus einen Trank, der einen[ENTER]sehr leichtf\252\223ig macht! "
gameforge.npc_talk._460_npcChat = "Wo ist dein Bruder? "
gameforge.npc_talk._470_say = "In letzter Zeit ist mein Bruder viel unterwegs.[ENTER]Ich sehe ihn kaum noch und mache mir gro\223e Sorgen[ENTER]um ihn. "
gameforge.npc_talk._480_npcChat = "Du verkaufst Reiskuchen? "
gameforge.npc_talk._490_sayTitle = "Yu-Rang, die Reiskuchenverk\228uferin: "
gameforge.npc_talk._500_say = "In Kriegszeiten ist es schwierig, Reiskuchen[ENTER]herzustellen. Au\223erdem habe ich wegen der[ENTER]Banditen viele Kunden verloren. Ich wei\223 nicht[ENTER]mehr, wovon ich leben soll. "
gameforge.npc_talk._50_say = "Obwohl es ein gro\223es Restaurant ist, ist die[ENTER]Einrichtung \252berraschend einfach. "
gameforge.npc_talk._510_npcChat = "Wer kauft bei dir? "
gameforge.npc_talk._520_say = "Die meisten Kuchen verkaufe ich an Durchreisende.[ENTER]Einmal kam ein geheimnisvoller Reiter in Schwarz,[ENTER]der kein Yang hatte. Als Bezahlung gab er mir ein[ENTER]Rezept, mit dem man Zin-Wasser herstellen kann.[ENTER]Das ist ein Trank, der deine Angriffskraft[ENTER]verbessert. Ich habe das Rezept an Huahn-So[ENTER]verkauft. Wenn du Huahn-So ein Sim-Wasser und[ENTER]eine Alpenrose bringst, wird er dir Zin-Wasser[ENTER]herstellen. "
gameforge.npc_talk._530_npcChat = "Warum schaust du so traurig? "
gameforge.npc_talk._540_say = "Oh, wer konnte ahnen, dass unsere s\252\223en Tr\228ume[ENTER]so schnell so unbarmherzig zerst\246rt werden[ENTER]w\252rden... Mein armer Mann, er fiel im Krieg! \133[ENTER]Bitte r\228che seinen Tod. "
gameforge.npc_talk._550_npcChat = "Es fallen sehr viele im Krieg... "
gameforge.npc_talk._560_say = "Da wir immer mehr M\228nner im Krieg verlieren,[ENTER]haben wir Frauen aus dem Dorf uns zusammen getan[ENTER]und Huahn-So gebeten, einen besseren Heiltrank[ENTER]herzustellen.[ENTER]Nach langer Forschung hat er einen Trank[ENTER]entwickelt, der statt dessen die Verteidigung[ENTER]erh\246ht, so dass weniger Heiltr\228nke ben\246tigt[ENTER]werden. Geh zu ihm. Er kann dir diesen Trank, den[ENTER]er SamBo-Wasser nennt, bestimmt herstellen. Er[ENTER]ben\246tigt daf\252r ein Dok-Wasser und eine Alpenrose. "
gameforge.npc_talk._570_npcChat = "Das ist aber ein s\252\223er Fratz... "
gameforge.npc_talk._580_sayTitle = "Ah-Yu: "
gameforge.npc_talk._590_say = "Es schreit schon wieder...[ENTER]Ob es etwas Leckeres will oder ... oh nein! "
gameforge.npc_talk._600_npcChat = "Wie geht es euch beiden? "
gameforge.npc_talk._60_npcChat = "Erz\228hl mir etwas \252ber das T\246pfern. "
gameforge.npc_talk._610_say = "Da mein Mann im Krieg gefallen ist, muss ich[ENTER]sehen, wo ich bleibe. Ich versuche, mich und das[ENTER]Kind zu ern\228hren. Mit dem Bo-Wasser habe ich eine[ENTER]M\246glichkeit gefunden, meinen Lebensunterhalt[ENTER]etwas aufzubessern. Ich muss Yu-Hwan 100[ENTER]Kakibl\252tens\228fte und einen Tue-Pilz bringen.[ENTER]Daraus braut er Bo-Wasser, das ich gut verkaufen[ENTER]kann. Irgendwie muss ich ja \252ber die Runden[ENTER]kommen. "
gameforge.npc_talk._620_npcChat = "Wie geht es deinem Ehemann? "
gameforge.npc_talk._630_sayTitle = "Aranyo: "
gameforge.npc_talk._640_say = "Mein so genannter Ehemann ist mit seinen B\252chern[ENTER]verheiratet. Er schaut mich nicht mal mehr an.[ENTER]Und ich bin keine h\228ssliche Frau. "
gameforge.npc_talk._650_npcChat = "Wie l\228uft das Gesch\228ft? "
gameforge.npc_talk._660_say = "Seit der Krieg ausgebrochen ist, laufen die[ENTER]Gesch\228fte schlecht. Die Gewerkschaft der[ENTER]H\228ndler war einmal eine reiche und m\228chtige[ENTER]Vereinigung, aber diese Zeiten sind vorbei. Wir[ENTER]k\246nnen es uns nicht mehr leisten, die Wilden,[ENTER]die Wei\223er-Eid Kriegerinnen und die[ENTER]Schwarzwindbande zu ignorieren, wie wir es[ENTER]fr\252her taten. "
gameforge.npc_talk._670_npcChat = "Warum so schlecht gelaunt? "
gameforge.npc_talk._680_sayTitle = "Taurean: "
gameforge.npc_talk._690_say = "Harang ist ein b\246ses M\228dchen![ENTER]Ich hasse sie! Ich bin schwach, und sie macht mir[ENTER]zu oft das Leben schwer! "
gameforge.npc_talk._700_say = "Du bist ein Mann und hast Muskeln.[ENTER]Trainiere sie ein bisschen! "
gameforge.npc_talk._70_sayTitle = "Yonah, der T\246pfer: "
gameforge.npc_talk._710_npcChat = "Was machst du gerade? "
gameforge.npc_talk._720_sayTitle = "Harang: "
gameforge.npc_talk._730_say = "Ich warte auf Taurean. Wir spielen oft[ENTER]miteinander und h\228ufig k\228mpfen wir auch. Dieser[ENTER]Feigling! Wenn er heute nicht freiwillig kommt,[ENTER]werde ich ihn fertig machen! "
gameforge.npc_talk._740_npcChat = "Taurean hat Angst vor dir. "
gameforge.npc_talk._750_say = "Taurean ist eigentlich st\228rker als ich. Deshalb[ENTER]habe ich mir etwas einfallen lassen, wie ich[ENTER]unsere K\228mpfe trotzdem gewinnen kann. Von einem[ENTER]weisen Ninja erfuhr ich, dass man Young-Wasser[ENTER]mit einer Maulbeere mischen kann. Daraus entsteht[ENTER]ein Trank, der einen schneller zuschlagen l\228sst.[ENTER]Damit kann ich Taurean besiegen! Wenn du auch ein[ENTER]schneller Angreifer werden willst, dann geh mit[ENTER]den Zutaten zu Huahn-So. Er wird dir den Trank[ENTER]sicher herstellen. "
gameforge.npc_talk._760_npcChat = "Die neuen Erkenntnisse... "
gameforge.npc_talk._770_say_title = "Seon-Pyeong: "
gameforge.npc_talk._780_say = "Mein Freund, die Welt ist voller ungel\246ster[ENTER]Fragen. Und ich, ich bin ein Sucher der[ENTER]Antworten, ein Sucher des Wissen.[ENTER]Hast du schon einmal von epischen Waffen und[ENTER]Geiststeinen geh\246rt? "
gameforge.npc_talk._790_npcChat = "Was tust du gerade? "
gameforge.npc_talk._800_say = "Du wei\223t ja bereits, dass ich nach noch[ENTER]unbekanntem Wissen forsche. Im Moment untersuche[ENTER]ich eine Methode, Waffen \252ber das Normalm\246gliche[ENTER]hinaus zu verst\228rken und auch die Macht der[ENTER]Geiststeine zu vervollkommnen. "
gameforge.npc_talk._80_say = "Ich bin gerne T\246pfer. Es ist sehr befriedigend,[ENTER]den Ton mit den eigenen H\228nden zu formen und das[ENTER]Werk beim Entstehen zu beobachten...[ENTER]Ich stelle meist nur einfache Sachen her. Im[ENTER]Osten, au\223erhalb dieses Kontinents, sind die[ENTER]Herstellungsmethoden viel weiter entwickelt. Ich[ENTER]habe einmal T\246pferwaren von dort gesehen und war[ENTER]ganz begeistert. Manchmal, wenn ich etwas Zeit[ENTER]habe, versuche ich mich an Experimenten. Aber ich[ENTER]habe immer noch nicht herausgefunden, welchen[ENTER]Trick sie anwenden. "
gameforge.npc_talk._810_npcChat = "Die Waffenforschung... "
gameforge.npc_talk._820_say = "Interessant, nicht wahr? Willst du mehr dar\252ber[ENTER]wissen? Dann bring mir eine der folgenden[ENTER]+9-Waffen: Schlachtschwert+9,[ENTER]Gro\223gelbdrachenbogen+9, Erl\246sungsf\228cher+9,[ENTER]Drachenmesser+9, Exorzismusschwert+9,[ENTER]Himmel-&-Erde-Glocke+9 oder Geisterzahnklinge+9.[ENTER]Au\223erdem brauche ich noch ein Traktat zur[ENTER]Fechtkunst und zwei Segensschriftrollen. Ich[ENTER]werde versuchen, dir daraus eine epische Waffe[ENTER]herzustellen. "
gameforge.npc_talk._830_say = "Allerdings kann ich dir nicht versprechen, dass[ENTER]es funktioniert. "
gameforge.npc_talk._840_npcChat = "Die Geiststeine... "
gameforge.npc_talk._850_say = "Geiststeine sind weit verbreitet. Viele nutzen[ENTER]sie, aber bisher hat noch niemand ihre wahre[ENTER]Macht erkannt. Doch ich habe w\228hrend meiner[ENTER]Nachforschungen neue Erkenntnisse gewonnen.[ENTER]Wenn du mir einen Geiststein bringst, kann ich[ENTER]ihn f\252r dich verbessern. "
gameforge.npc_talk._90_npcChat = "Du bist sehr r\252stig f\252r dein Alter... "
gameforge.olympic_badge = {}
gameforge.olympic_badge._010_npcChat = "Heldenmedaille "
gameforge.olympic_badge._020_say = "Zu Hilfe! "
gameforge.olympic_badge._030_say = "Elendes Diebesgesindel ...[ENTER]Gestern Nacht wurde bei mir eingebrochen![ENTER]Sie haben die Heldenmedaille gestohlen. Mein[ENTER]Vorfahre bekam sie einst verliehen, nachdem er[ENTER]42,195 Kilometer vom Schlachtfeld zu seinem[ENTER]Kaiser gerannt war, um ihm die Kunde des Sieges[ENTER]zu \252bermitteln.[ENTER]Nun ist sie weg! "
gameforge.olympic_badge._040_say = "Oh weh ... f\252r meine Familie ist sie von[ENTER]unsch\228tzbarem Wert. Was soll ich blo\223 tun? "
gameforge.olympic_badge._050_say = "Wirst du mir helfen? "
gameforge.olympic_badge._060_npcChat = "Heldenmedaille "
gameforge.olympic_badge._070_say = "Endlich! Du bist du zur\252ck![ENTER]Hast du die Heldenmedaille gefunden? "
gameforge.olympic_badge._080_say = "Warum nur? Was wollen diese Verbrecher mit meiner[ENTER]Medaille? F\252r Fremde ist sie doch wertlos![ENTER]Kannst du mir helfen, sie wiederzufinden? "
gameforge.olympic_badge._090_npcChat = "Finde die Heldenmedaille! "
gameforge.olympic_badge._100_say = "Du kommst mit leeren H\228nden? Oh nein, ich bin[ENTER]verzweifelt. Wenn du mir nicht helfen kannst, wer[ENTER]dann? Suche weiter. Bitte! "
gameforge.olympic_badge._110_say = "Du hast meine Medaille gefunden![ENTER]Aber warte ... das ist ja blo\223 ein St\252ck. Welch[ENTER]Schande, sie haben sie in f\252nf Teile zerbrochen![ENTER]Bitte bringe mir alle Bruchst\252cke! Dann kann ich[ENTER]die Medaille vielleicht wieder zusammensetzen. "
gameforge.olympic_badge._120_say = "Diese elenden Verbrecher haben mein kostbares[ENTER]Familienerbst\252ck zerbrochen![ENTER]Ich danke dir, dass du alle Bruchst\252cke gefunden[ENTER]hast. Nun kann ich die einzelnen Teile[ENTER]zusammenf\252gen. "
gameforge.olympic_badge._130_say = "Tausend Dank! Du hast die Ehre meiner Familie[ENTER]wiederhergestellt.[ENTER]All die M\252he sollst du dir nat\252rlich nicht[ENTER]umsonst gemacht haben. Hier ist dein gerechter[ENTER]Lohn! "
gameforge.olympic_badge._140_say = "M\246chtest du diesen Auftrag wirklich ablehnen?[ENTER]Wenn du jetzt 'Ja' w\228hlst, kannst du ihn nicht[ENTER]mehr wiederaufnehmen. "
gameforge.olympic_badge._150_say = "Ich verstehe, wenn du jetzt keine Zeit daf\252r[ENTER]hast. Komm wieder, wenn es dir besser passt.[ENTER]Aber lass mich nicht zu lange warten! "
gameforge.olympic_badge._160_say = "Leider bist du zu sp\228t gekommen und kannst mir[ENTER]nun nicht mehr helfen. Ich w\252nsche dir[ENTER]alles Gute auf deinem weiteren Weg! "
gameforge.olympic_badge._170_say = "Jage die Monster, die mich bestohlen haben! Doch[ENTER]Vorsicht, sie waren sehr stark - mindestens Level[ENTER]30. Wenn du mir die Heldenmedaille wiederbringst,[ENTER]werde ich dich reichlich entlohnen! "
gameforge.olympic_badge._180_say = "Finde die Heldenmedaille und bringe sie zu[ENTER]Yu-Hwan. "
gameforge.olympic_badge._190_say = "Yu-Hwan bittet um deine Hilfe. Geh zu ihm! Du[ENTER]findest ihn im zweiten Dorf. "
