gameforge.pony_levelup._580_say = "Komm einmal zu mir geritten. "
gameforge.pony_levelup._590_say = "Dein Training ist nun fast beendet. Zieh los und[ENTER]erkunde mit deinem Pferd die Umgebung. Es wird[ENTER]diesmal vielleicht etwas schwieriger werden, aber[ENTER]du schaffst das schon. Einfach immer der Nase[ENTER]nach und die Augen offen halten. Auf Wiedersehen[ENTER]und komm bald zur\252ck! Jeder Fortschritt wird auf[ENTER]deiner Pferdemedaille notiert. Es wird nicht[ENTER]lange dauern, bis du bereit bist f\252r den Aufstieg[ENTER]zum mittleren Level. "
