gameforge.skill_reset2._10_npcChat = "Fertigkeiten zur\252cksetzen "
gameforge.skill_reset2._110_say = "Wie du willst.[ENTER]Wenn du es dir doch einmal anders \252berlegen[ENTER]solltest, komm einfach vorbei. "
gameforge.skill_reset2._120_say = "Du hast nicht gen\252gend Yang.[ENTER]Tut mir leid, aber so kann ich dir nicht helfen.[ENTER]Ich muss schlie\223lich auch von irgendetwas leben. "
gameforge.skill_reset2._130_say = "Dieser Gegenstand verschafft dir die M\246glichkeit,[ENTER]eine vollkommen neue Lehre zu beginnen und deine[ENTER]alte zu vergessen. Um ihn zu nutzen,[ENTER]musst du allerdings mindestens Level 31[ENTER]erreicht haben. Dann jedoch steht es dir frei,[ENTER]dein Schicksal neu zu bestimmen.[ENTER]M\246chtest du dich von den F\228higkeiten[ENTER]abwenden, die dich bislang auf deinem Weg[ENTER]begleitet haben? "
gameforge.skill_reset2._135_say = "Du folgst keiner Lehre und hast keine[ENTER]Fertigkeitspunkte, die zur\252ckgesetzt werden[ENTER]k\246nnten! "
gameforge.skill_reset2._140_say = "Dieses Item kann nur von Level 31 bis 98 genutzt[ENTER]werden. "
gameforge.skill_reset2._20_say = "Du hast noch keine Lehre begonnen! Solange du[ENTER]keine Fertigkeitspunkte ausgibst, kannst du sie[ENTER]auch nicht zur\252cksetzen. Komm wieder, wenn du bei[ENTER]deiner Ausbildung einen Fehler gemacht hast, dann[ENTER]helfe ich dir gern. "
gameforge.skill_reset2._30_say = "Ich kann dir leider nicht helfen, mein Kind.[ENTER]Du hast bereits Level %s erreicht, ein[ENTER]Ausbildungswechsel ist jedoch nur bis Level 30[ENTER]m\246glich. "
gameforge.skill_reset2._40_say = "Du folgst keiner Lehre und hast keine[ENTER]Fertigkeitspunkte, die zur\252ckgesetzt werden[ENTER]k\246nnten! "
gameforge.skill_reset2._50_say = "Oje, was ist los? Ich lese gro\223e Sorge in deinen[ENTER]Augen... Warte, ich kann dir helfen. Ich lasse[ENTER]dich deine bisherige Laufbahn vergessen und du[ENTER]beginnst einfach eine neue Lehre. Was h\228ltst du[ENTER]davon?[ENTER]Es kostet dich nur %s Yang. "
gameforge.skill_reset2._60_select = "Nicht zur\252cksetzen "
gameforge.skill_reset2._70_say = "Jetzt sieh sich einer dieses finstere Gesicht an![ENTER]Geht es dir nicht gut?[ENTER]Wenn du wegen deiner Lehre unzufrieden bist: Ich[ENTER]k\246nnte dir helfen, wie von Zauberhand alles zu[ENTER]vergessen, was damit zu tun hat. "
gameforge.skill_reset2._80_say = "Das bedeutet, dass all deine Fertigkeiten[ENTER]zur\252ckgesetzt werden und du die Punkte neu[ENTER]verteilen kannst. Nur die Punkte, die du durch[ENTER]das Lesen von B\252chern erworben hast, kann ich dir[ENTER]leider nicht zur\252ckgeben, sie gehen dabei[ENTER]verloren. M\246chtest du das? Alles vergessen und[ENTER]von vorne anfangen?[ENTER]Dann brauche ich %s Yang von dir. "
gameforge.skill_reset2._90_select = "Skills zur\252cksetzen "
gameforge.spider_dungeon_2floor = {}
gameforge.spider_dungeon_2floor._10_npcChat = "Zur\252ck in die 1. Ebene "
gameforge.spider_dungeon_2floor._15_sayTitle = "Pung-Ho: "
gameforge.spider_dungeon_2floor._20_say = "M\246chtest du wirklich wieder zur\252ck in die[ENTER]1. Ebene? "
gameforge.spider_dungeon_2floor._30_say = "Eine weise Entscheidung.[ENTER]Hier oben ist es viel zu gef\228hrlich, um noch[ENTER]l\228nger zu bleiben. Geh und versorge erst[ENTER]einmal deine Wunden. "
gameforge.spider_dungeon_2floor._40_say = "Ganz so wie du willst...[ENTER]Gib auf dich Acht![ENTER]Hier oben ist es sehr gef\228hrlich. "
gameforge.spider_dungeon_3floor_boss = {}
gameforge.spider_dungeon_3floor_boss._100_say = "Du willst mir doch nicht erz\228hlen, dass du dich[ENTER]nicht in den Spinnendungeon getraut hast? Du bist[ENTER]ein erfahrener K\228mpfer mit einer ausgefeilten[ENTER]Technik - so ein paar Krabbeltierchen sollten f\252r[ENTER]dich kein gro\223es Problem darstellen. Aber dir ist[ENTER]bekannt, dass du den Passierschein ben\246tigst, um[ENTER]die H\246hle zu betreten? "
gameforge.spider_dungeon_3floor_boss._10_npcChat = "Zugang zur Bruth\246hle "
gameforge.spider_dungeon_3floor_boss._110_sendLetter = "Neue Gefahr "
gameforge.spider_dungeon_3floor_boss._120_say = "Du hast eine genaue Kopie der Inschrift[ENTER]angefertigt. Zeige sie nun dem Hauptmann. "
gameforge.spider_dungeon_3floor_boss._130_say = "Sehr gut, du hast es geschafft! Zeig mal her ...[ENTER]Hm, diese Schriftzeichen sind mir fremd, ich kann[ENTER]kein Wort verstehen. Du solltest vielleicht den[ENTER]Gelehrten Uriel um Rat fragen. "
gameforge.spider_dungeon_3floor_boss._140_say = "Gehe zum Gelehrten Uriel und zeige ihm die[ENTER]Inschrift. Er wird sie sicherlich \252bersetzen[ENTER]k\246nnen. "
gameforge.spider_dungeon_3floor_boss._150_say = "Der Hauptmann bittet mich, diese geheimnisvolle[ENTER]Inschrift zu entziffern? Selbstverst\228ndlich. Ich[ENTER]liebe geistige Herausforderungen. Zeig her.[ENTER]Das ist ... Also das ist ja ungeheuerlich. Hier,[ENTER]ich schreibe dir die \220bersetzung auf dieses[ENTER]Papier. Bringe es so schnell wie m\246glich zum[ENTER]Hauptmann und kehre anschlie\223end zu mir zur\252ck.[ENTER]Wenn das stimmt, was hier steht, dann befinden[ENTER]wir alle uns in gro\223er Gefahr! Los, los! "
gameforge.spider_dungeon_3floor_boss._160_say = "Du warst noch nicht beim Hauptmann? Bitte, du[ENTER]musst dich beeilen. Wir haben keine Zeit zu[ENTER]verlieren. Er muss diesen Brief unbedingt lesen! "
gameforge.spider_dungeon_3floor_boss._170_sayTitle = "\220berbringe Uriels Brief "
gameforge.spider_dungeon_3floor_boss._180_say = "Dieser starrk\246pfige alte Mann ... W\228re ein[ENTER]kleines Dankesch\246n zu viel verlangt? Aber gut. Er[ENTER]sagte, die Informationen seien \228u\223erst wichtig,[ENTER]also werde ich sie rasch dem Hauptmann[ENTER]\252bermitteln. "
gameforge.spider_dungeon_3floor_boss._190_npcChat = "Uriels Brief "
gameforge.spider_dungeon_3floor_boss._200_say = "Oh je! In der dritten Ebene des Spinnendungeons[ENTER]hat sich ein gewaltiger Arachniden-D\228mon[ENTER]eingenistet - die Spinnenbaroness. Der Inschrift[ENTER]zufolge braucht man einen speziellen Schl\252ssel,[ENTER]um in diese verborgene H\246hle zu gelangen.[ENTER]Gehe zun\228chst zu Uriel und frage ihn nach diesem[ENTER]Schl\252ssel. Stelle dir anschlie\223end einen Trupp[ENTER]aus f\228higen K\228mpfern zusammen und st\252rmt[ENTER]gemeinsam das Versteck der Spinnenbaroness! Hier,[ENTER]ich habe einen weiteren Passierschein f\252r dich. "
gameforge.spider_dungeon_3floor_boss._20_say = "Dieses Tor l\228sst sich nur mit dem[ENTER]Arachnidenschl\252ssel \246ffnen. "
gameforge.spider_dungeon_3floor_boss._210_npcChat = "Der Arachnidenschl\252ssel "
gameforge.spider_dungeon_3floor_boss._220_say = "Ich sollte nun so schnell wie m\246glich Uriel[ENTER]aufsuchen. "
gameforge.spider_dungeon_3floor_boss._230_say = "Ah, du bist zur\252ck. Dann hat der Hauptmann dir[ENTER]also den Befehl erteilt, die Spinnenbaroness zu[ENTER]vernichten? Doch der Zugang zur Bruth\246hle der[ENTER]Baroness ist verschlossen und l\228sst sich[ENTER]nur mit dem Arachnidenschl\252ssel \246ffnen. Seine[ENTER]Herstellung ist sehr aufwendig. Aber wenn du mir[ENTER]einen Spinnen-Giftsack, einen Spinnen-Eiersack,[ENTER]ein Spinnennetz, Spinnenaugen, Spinnenbeine sowie[ENTER]das Gift der K\246niginnenspinne bringst, werde ich[ENTER]einen f\252r dich anfertigen. "
gameforge.spider_dungeon_3floor_boss._240_say = "Du m\246chtest, dass ich den Arachnidenschl\252ssel f\252r[ENTER]dich anfertige? Daf\252r ben\246tige ich einen[ENTER]Spinnen-Giftsack, einen Spinnen-Eiersack, ein[ENTER]Spinnennetz, Spinnenaugen, Spinnenbeine sowie das[ENTER]Gift der K\246niginnenspinne. Konntest du alle[ENTER]Substanzen finden? "
gameforge.spider_dungeon_3floor_boss._250_say = "Gro\223artig! Du hast alle ben\246tigten Elemente f\252r[ENTER]den Arachnidenschl\252ssel gefunden. Warte einen[ENTER]Moment. Seine Herstellung sollte nicht allzu[ENTER]lange dauern ... "
gameforge.spider_dungeon_3floor_boss._260_say = "Ha, geschafft! Hier hast du den[ENTER]Arachnidenschl\252ssel. Er \246ffnet dir den Zugang zum[ENTER]Versteck der Spinnenbaroness. Ich w\252nsche dir und[ENTER]deinen Kameraden viel Erfolg f\252r den Kampf gegen[ENTER]diese langbeinige Bestie! Doch ihr m\252sst euch[ENTER]beeilen - der Schl\252ssel ist sehr instabil. Nach[ENTER]24 Stunden zerf\228llt er in seine Bestandteile. "
gameforge.spider_dungeon_3floor_boss._270_say = "Oh oh! Ich f\252rchte, es ist noch kein Meister[ENTER]vom Himmel gefallen. Du musst wissen, das[ENTER]Verfahren zum Schmieden dieses Schl\252ssels ist[ENTER]\228u\223erst kompliziert. Schon ein winziger Fehler[ENTER]f\252hrt zum Scheitern. Leider habe ich damit auch[ENTER]alle Spinnensubstanzen, die du m\252hevoll[ENTER]gesammelt hast, vergeudet. Beim n\228chsten[ENTER]Versuch funktioniert es bestimmt! "
gameforge.spider_dungeon_3floor_boss._280_say = "Es fehlt noch etwas, so kann ich den[ENTER]Arachnidenschl\252ssel nicht herstellen. Hier[ENTER]noch einmal zur Erinnerung, was wir alles[ENTER]brauchen: einen Spinnen-Giftsack, einen[ENTER]Spinnen-Eiersack, ein Spinnennetz, Spinnenaugen,[ENTER]Spinnenbeine sowie das Gift der K\246niginnenspinne. "
gameforge.spider_dungeon_3floor_boss._300_say = "Dein Gruppenanf\252hrer hat den Dungeon betreten.[ENTER]M\246chtest du ihm folgen? "
gameforge.spider_dungeon_3floor_boss._30_npcChat = "SD3 Quest zur\252cksetzen "
gameforge.spider_dungeon_3floor_boss._310_say = "Du hast zu lange gebraucht. Der Schl\252ssel ist[ENTER]bereits zerfallen. Lass einen neuen anfertigen,[ENTER]um hier Zutritt zu erhalten. "
gameforge.spider_dungeon_3floor_boss._320_say = "In der Bruth\246hle der Baroness befindet sich[ENTER]bereits eine Gruppe und greift die[ENTER]Spinnenbaroness an. "
gameforge.spider_dungeon_3floor_boss._330_say = "Du kannst erst eintreten, wenn die vorherige[ENTER]Gruppe ihre Aufgabe beendet hat. Kehre in %s[ENTER]Minuten zur\252ck. "
gameforge.spider_dungeon_3floor_boss._340_say = "Wartezeit, bis sich das Tor zur Bruth\246hle der[ENTER]Baroness erneut \246ffnen l\228sst: "
gameforge.spider_dungeon_3floor_boss._350_say = "%s Minuten "
gameforge.spider_dungeon_3floor_boss._360_say = "Der K\228mpfer, der die H\246hle vor dir betreten hat,[ENTER]kann sich erst nach zehn Sekunden wieder bewegen.[ENTER]Bitte warte einen Moment. "
gameforge.spider_dungeon_3floor_boss._370_say = "M\246chtest du eine Eroberung starten? Du hast daf\252r[ENTER]20 Minuten. Vor Ablauf dieser Zeit kann niemand[ENTER]die Bruth\246hle der Baroness verlassen.[ENTER]Eine erneute Eroberung kann nach einer Stunde[ENTER]durchgef\252hrt werden. "
gameforge.spider_dungeon_3floor_boss._380_say = "Um den Zugang zu \246ffnen, ben\246tigst du den[ENTER]Arachnidenschl\252ssel. "
gameforge.spider_dungeon_3floor_boss._390_say = "Nur der Anf\252hrer einer Gruppe kann den[ENTER]Arachnidenschl\252ssel verwenden. "
gameforge.spider_dungeon_3floor_boss._400_say = "Die Spinnenbaroness wurde vernichtet! In drei[ENTER]Minuten werden alle K\228mpfer aus der H\246hle[ENTER]teleportiert. "
gameforge.spider_dungeon_3floor_boss._40_say = "Vor Herstellung des Schl\252ssels "
gameforge.spider_dungeon_3floor_boss._410_say = "Das hat nicht geklappt. Versuch es bitte noch[ENTER]einmal! "
gameforge.spider_dungeon_3floor_boss._420_notice = "Vorsicht: Die Spinnenbaroness wird w\252tend! Ihr[ENTER]Angriff wird st\228rker, jedoch wird ihre[ENTER]Verteidigung dadurch geschw\228cht. "
gameforge.spider_dungeon_3floor_boss._50_npcChat = "Spinnendungeon 3 "
gameforge.spider_dungeon_3floor_boss._60_say = "Ah, da bist du ja! Ein Sp\228htrupp hat im[ENTER]Spinnendungeon eine dritte Ebene entdeckt. In[ENTER]dieser bisher verborgenen H\246hle sollen sich[ENTER]einige \228u\223erst monstr\246se und heimt\252ckische[ENTER]Spinnen eingenistet haben. Au\223erdem fanden meine[ENTER]M\228nner einen alten Grabstein mit einer[ENTER]eingravierten Inschrift, doch sie konnten diese[ENTER]nicht entziffern. Begib dich auf die Suche nach[ENTER]diesem Stein und bringe mir eine Kopie der[ENTER]Inschrift. Hier, dieser Passierschein verschafft[ENTER]dir ungehinderten Zutritt zum Spinnendungeon. "
gameforge.spider_dungeon_3floor_boss._70_sendLetter = "Die Inschrift "
gameforge.spider_dungeon_3floor_boss._80_say = "Auf der dritten Ebene des Spinnendungeons findest[ENTER]du einen alten Grabstein mit einer eingravierten[ENTER]Inschrift. Fertige eine Kopie davon an und bringe[ENTER]sie dem Hauptmann. "
gameforge.spider_dungeon_3floor_boss._90_say = "Perfekt, du hast den alten Grabstein gefunden und[ENTER]eine Kopie der Inschrift angefertigt! Geh zur\252ck[ENTER]zum Hauptmann und zeige sie ihm. "
gameforge.subquest_01 = {}
gameforge.subquest_01._100_sayTitle = "Gemischtwarenh\228ndlerin: "
gameforge.subquest_01._10_targetVid = "Leere Flasche besorgen. "
gameforge.subquest_01._110_say = "Das ist gut.[ENTER]Leere Flaschen bekommst du beim T\246pfer Yonah.[ENTER]Vielen Dank. "
gameforge.subquest_01._120_targetVid = "Suche den T\246pfer Yonah "
gameforge.subquest_01._130_sayReward = "Die Gemischtwarenh\228ndlerin braucht vom T\246pfer[ENTER]Yonah eine leere Flasche f\252r ihren roten Trank. "
gameforge.subquest_01._140_sayTitle = "Yonah: "
gameforge.subquest_01._150_say = "Oh je! Verdammt! Ich kann nicht aufh\246ren zu[ENTER]husten! Wie soll ich in diesem Zustand nur[ENTER]arbeiten.[ENTER]Die Gemischtwarenh\228ndlerin schickt dich? Ich habe[ENTER]leere Flaschen, aber die gibt es nicht umsonst. "
gameforge.subquest_01._160_say = "Ich habe Asthma.[ENTER]Man hat mir erz\228hlt, Pfirsichsamen seien ein[ENTER]hervorragendes Heilmittel. Wenn du mir welche[ENTER]besorgst, werde ich dir eine leere Flasche geben.[ENTER]Du kannst Pfirsichsamen bei den Keilern au\223erhalb[ENTER]des Dorfes bekommen. Wenn die Bauern[ENTER]Pfirsichsamen pflanzen, graben die Keiler sie[ENTER]wieder aus. "
gameforge.subquest_01._170_sendLetter = "Besorge die Pfirsichsamen "
gameforge.subquest_01._180_sayReward = "Die Gemischtwarenh\228ndlerin braucht vom T\246pfer[ENTER]Yonah eine leere Flasche f\252r ihren Trank.[ENTER]Yonah, der Asthma hat, wird dir eine leere[ENTER]Flasche geben, wenn du ihm Pfirsichsamen bringst.[ENTER]Du kannst die Samen finden, indem du Keiler[ENTER]jagst. "
gameforge.subquest_01._190_npcChat = "Um Pfirsichsamen zu bekommen... "
gameforge.subquest_01._200_say = "Du kannst Pfirsichsamen bei den Keilern[ENTER]au\223erhalb des Dorfes bekommen. Wenn die[ENTER]Bauern Pfirsichsamen pflanzen, graben die[ENTER]Keiler sie wieder aus und fressen sie.[ENTER]Hust, hust.[ENTER]Vielen Dank im Voraus. "
gameforge.subquest_01._20_npcChat = "Leere Flasche besorgen "
gameforge.subquest_01._210_sendLetter = "R\252ckkehr zu Yonah "
gameforge.subquest_01._220_sayTitle = "Kehre zu Yonah zur\252ck "
gameforge.subquest_01._230_sayReward = "Du hast den Pfirsichsamen gefunden. Bringe ihn[ENTER]Yonah. "
gameforge.subquest_01._240_say = "Oh, du hast ihn bekommen! "
gameforge.subquest_01._250_say = "Danke. Jetzt kann ich mein Asthma lindern[ENTER]und kann wieder mit meiner Arbeit fortfahren. "
gameforge.subquest_01._260_say = "Hier hast du eine leere Flasche.[ENTER]Bringe sie der Gemischtwarenh\228ndlerin. "
gameforge.subquest_01._270_sendLetter = "Leere Flasche abliefern "
gameforge.subquest_01._280_sayReward = "Die Gemischtwarenh\228ndlerin braucht die[ENTER]leere Flasche vom T\246pfer. Bringe sie ihr. "
gameforge.subquest_01._290_sayTitle = "Gemischtwarenh\228ndlerin: "
gameforge.subquest_01._300_say = "Danke.[ENTER]Ich hoffe, es hat nicht zu viele Umst\228nde[ENTER]gemacht. Ich gebe dir dies als Zeichen meiner[ENTER]Wertsch\228tzung. Nochmals vielen Dank! "
gameforge.subquest_01._30_say = "Verzeihung? Wenn du gerade nicht besch\228ftigt[ENTER]bist, k\246nntest du mir einen Gefallen tun? Ich[ENTER]brauche eine leere Flasche f\252r meinen roten[ENTER]Trank. "
gameforge.subquest_01._310_sayReward = "Du erh\228ltst 1.500 Erfahrungspunkte.[ENTER]Du erh\228ltst 1.000 Yang. "
gameforge.subquest_01._320_say = "Du hast noch keine leere Flasche f\252r mich? "
gameforge.subquest_01._330_say = "Willst du wieder Keiler jagen, um eine weitere[ENTER]leere Flasche zu bekommen oder die Aufgabe[ENTER]abbrechen? "
gameforge.subquest_01._340_select = "Ja, ich werde die Keiler jagen. "
gameforge.subquest_01._350_select = "Nein, ich breche die Aufgabe ab. "
gameforge.subquest_01._360_say = "Wirklich abbrechen? "
gameforge.subquest_01._370_say = "Sch\246n, dass du mir hilfst. "
gameforge.subquest_01._380_say = "Das ist zu schwer f\252r mich.[ENTER]Es tut mir leid. "
gameforge.subquest_01._40_say = "Ich bin hier im Laden besch\228ftigt und kann sie[ENTER]mir nicht selber holen. Wenn du mir diese Flasche[ENTER]bringst, werde ich dich belohnen. "
gameforge.subquest_01._50_select = "Annehmen "
gameforge.subquest_01._60_select = "Ablehnen "
gameforge.subquest_01._70_say = "Willst du diese Aufgabe abbrechen? "
gameforge.subquest_01._80_say = "Sch\246n, dass du mir helfen willst.[ENTER]Komm wieder her, sobald du Zeit hast. "
gameforge.subquest_01._90_say = "Ich w\252nsche dir noch einen sch\246nen Tag.[ENTER]Komm mal wieder vorbei. "
gameforge.subquest_02 = {}
gameforge.subquest_02._100_sayTitle = "R\252stungsh\228ndler: "
gameforge.subquest_02._10_targetVid = "Das Abendessen "
gameforge.subquest_02._110_say = "Das ganze Gerede \252ber Essen macht mich hungrig.[ENTER]Ich habe solch einen Appetit auf Eintopf mit[ENTER]Wild, B\228r, Kohl und zwei Eiern. "
gameforge.subquest_02._120_say = "Hat mein Vater gesagt, was er heute Abend[ENTER]essen m\246chte? "
gameforge.subquest_02._121_select = "Eintopf mit Schwein, B\228r, Kohl und ein Ei "
gameforge.subquest_02._122_select = "Eintopf mit Wild, B\228r, Kohl und ein Ei "
gameforge.subquest_02._123_select = "Eintopf mit Wild, B\228r, Kohl und zwei Eiern "
gameforge.subquest_02._124_select = "Oh ... ich hab's vergessen ... "
gameforge.subquest_02._130_say = "Danke, dass du mir die Information so schnell[ENTER]gebracht hast.[ENTER]Hier ist deine Belohnung. "
gameforge.subquest_02._140_sayReward = "Du erh\228ltst 1.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 1.500 Yang. "
gameforge.subquest_02._150_say = "Gemischtwarenh\228ndlerin:[ENTER]Das wundert mich nicht, er hat immer sehr[ENTER]spezielle W\252nsche.[ENTER]K\246nntest du ihn bitte noch einmal[ENTER]fragen? "
gameforge.subquest_02._160_say = "Gemischtwarenh\228ndlerin:[ENTER]Das hat er gesagt? Bist du sicher?[ENTER]Das klingt gar nicht nach meinem Vater...[ENTER]K\246nntest du ihn bitte noch einmal fragen? Ich[ENTER]glaube nicht, dass er dieses Gericht gemeint[ENTER]hat. "
gameforge.subquest_02._20_say = "Du wei\223t doch, dass der R\252stungsh\228ndler mein[ENTER]Vater ist, oder?[ENTER]Ich will ihm das Abendessen vorbereiten, aber ich[ENTER]wei\223 nicht, was er essen will. K\246nntest du[ENTER]ihn fragen, was er essen m\246chte?[ENTER]F\252r deine M\252he werde ich dich auch belohnen. "
gameforge.subquest_02._30_sayReward = "Die Gemischtwarenh\228ndlerin m\246chte wissen, was ihr[ENTER]Vater, der R\252stungsh\228ndler, zum Abendessen haben[ENTER]m\246chte. "
gameforge.subquest_02._40_sayReward = "Gehe zum R\252stungsh\228ndler und frag ihn. "
gameforge.subquest_02._50_say = "Willkommen![ENTER]Ich habe R\252stungen, die dich gegen[ENTER]Messer- und Schwertangriffe sch\252tzen. "
gameforge.subquest_02._60_say = "Oh, meine Tochter schickt dich?[ENTER]Sie fragt sich sicher, was sie heute Abend kochen[ENTER]soll. Lass mich \252berlegen. Mmmhhh, ich h\228tte[ENTER]gerne einen scharfen Eintopf mit Wild, B\228r,[ENTER]w\252rzigem Kohl und zwei Eiern.[ENTER]Darauf habe ich richtig Appetit! "
gameforge.subquest_02._70_targetVid = "Das Abendessen "
gameforge.subquest_02._80_sayReward = "Die Gemischtwarenh\228ndlerin m\246chte wissen, was[ENTER]ihr Vater, der R\252stungsh\228ndler, zum Abendessen[ENTER]haben m\246chte. "
gameforge.subquest_02._90_sayReward = "Gehe zu ihr zur\252ck und berichte, was du in[ENTER]Erfahrung gebracht hast. "
gameforge.subquest_03 = {}
gameforge.subquest_03._100_sayTitle = "Kehre zu Baek-Go zur\252ck. "
gameforge.subquest_03._10_targetVid = "Zutat f\252r die Arznei "
gameforge.subquest_03._110_sayReward = "Du hast die Leber gefunden.[ENTER]Bringe sie Baek-Go. "
gameforge.subquest_03._120_say = "Danke. Wir stehen in deiner Schuld! "
gameforge.subquest_03._130_say = "Die Patienten werden dich loben. "
gameforge.subquest_03._140_say = "Hier, nimm dies als ein Zeichen meines Dankes. Du[ENTER]wirst es eines Tages gebrauchen k\246nnen. "
gameforge.subquest_03._150_sayReward = "Du erh\228ltst 3.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 5.000 Yang.[ENTER]Du erh\228ltst ein Wolfsfell. "
gameforge.subquest_03._20_say = "Kannst du mir helfen? Seit die Metinsteine[ENTER]fallen, ist eine unbekannte Krankheit[ENTER]ausgebrochen. Viele \196rzte suchen nach einem[ENTER]Gegenmittel, aber uns fehlt eine notwendige[ENTER]Zutat, um die Arznei herzustellen. Au\223erhalb des[ENTER]Dorfes gibt es wilde Tiere. Wir k\246nnen uns daher[ENTER]dort nicht frei bewegen. "
gameforge.subquest_03._30_say = "Kannst du mir die Zutat f\252r die Arznei bringen?[ENTER]Ich frage dich, weil du ein Soldat bist.[ENTER]Ich brauche f\252r die Arznei die Leber[ENTER]eines Blauwolfs. "
gameforge.subquest_03._40_say = "Bringe mir die Leber eines Blauwolfs. Sage mir[ENTER]Bescheid, wenn du sie hast. "
gameforge.subquest_03._50_sayReward = "Seit die Metinsteine fallen, ist eine unbekannte[ENTER]Krankheit ausgebrochen. Um die Arznei f\252r die[ENTER]Krankheit herstellen zu k\246nnen, braucht Baek-Go[ENTER]eine Blauwolfsleber. Bringe sie ihm. "
gameforge.subquest_03._60_npcChat = "Woher soll ich eine Wolfsleber nehmen? "
gameforge.subquest_03._70_say = "Es gibt nur einen Weg, eine Wolfsleber zu[ENTER]bekommen: Du musst Blauw\246lfe jagen. "
gameforge.subquest_03._80_say = "Die W\246lfe tun mir leid. Aber wir brauchen die[ENTER]Leber, um die Arznei herzustellen. Vielen Dank[ENTER]im Voraus. "
gameforge.subquest_03._90_sendLetter = "R\252ckkehr zu Baek-Go "
gameforge.subquest_04 = {}
gameforge.subquest_04._100_say = "Du hast einen weiten Weg vor dir. Pass auf dich[ENTER]auf! Und vergiss nicht: Du musst das Portal bei[ENTER]dem blauen Punkt benutzen. "
gameforge.subquest_04._10_targetVid = "Wie geht es Deokbae? "
gameforge.subquest_04._110_sayReward = "Geh und bring den Brief des Schmieds zu Deokbae,[ENTER]dem Holzf\228ller. Du findest ihn im zweiten Dorf,[ENTER]zu dem du nur mit Hilfe des Portals gelangst. "
gameforge.subquest_04._120_sendLetter = "Ein Brief vom Schmied "
gameforge.subquest_04._130_targetVid = "Finde Deokbae, den Holzf\228ller. "
gameforge.subquest_04._140_npcChat = "Ein Brief vom Schmied "
gameforge.subquest_04._150_sayTitle = "Holzf\228ller Deokbae: "
gameforge.subquest_04._160_say = "Willkommen! Ich habe gute \196xte, willst du eine[ENTER]kaufen? Du brauchst keine Axt? Warum bist du dann[ENTER]hier? Ah, ein Brief vom Schmied. Hab vielen Dank.[ENTER]Ich bin Holzf\228ller, verkaufe aber auch[ENTER]Spitzhacken und andere Werkzeuge. Manchmal[ENTER]bestelle ich verschiedene Werkzeuge bei ihm. So[ENTER]sind wir gute Freunde geworden. "
gameforge.subquest_04._170_say = "Ich sollte wirklich mal wieder mit ihm in der[ENTER]Seo-Pyung-Bar einen trinken gehen.[ENTER]Vielen Dank, dass du mir den Brief gebracht hast.[ENTER]Und viele Gr\252\223e an den Schmied! "
gameforge.subquest_04._180_say = "Ein Brief vom Schmied?[ENTER]Mann, das ist lange her. Wo ist der Brief?[ENTER]Du hast ihn doch nicht unterwegs verloren, oder? "
gameforge.subquest_04._190_select = "Hier ist er. "
gameforge.subquest_04._200_select = "Ach, doch nicht. "
gameforge.subquest_04._20_say = "Hey, du, Abenteurer! Ich m\246chte dich um[ENTER]einen Gefallen bitten.[ENTER]Kennst du einen Burschen namens Deokbae?[ENTER]Er ist Holzf\228ller und ein guter Freund von mir.[ENTER]Vielleicht ein bisschen langweilig, aber er[ENTER]ist einer der letzten hart arbeitenden[ENTER]Holzf\228ller. "
gameforge.subquest_04._210_say = "Quest beenden? "
gameforge.subquest_04._220_say = "Das freut mich sehr.[ENTER]Komm schnell wieder. "
gameforge.subquest_04._230_say = "Du hast ihn also verloren?[ENTER]Verschwinde! "
gameforge.subquest_04._240_say = "Geh zum Schmied und hol ihn.[ENTER]Verlier aber den Brief diesmal nicht.[ENTER]Mach es gut. "
gameforge.subquest_04._250_sayReward = "Geh zum Schmied zur\252ck und hole dir deine[ENTER]Belohnung ab. "
gameforge.subquest_04._260_targetVid = "Zur\252ck zum Schmied "
gameforge.subquest_04._270_npcChat = "Ich habe den Brief \252bergeben. "
gameforge.subquest_04._280_say = "Und, wie geht es Deokbae? Ha, ha! Er hat sich[ENTER]kein bisschen ver\228ndert. Danke. Nimm dies als[ENTER]Belohnung. Es ist nicht viel, aber du wirst es[ENTER]eines Tages gebrauchen k\246nnen.[ENTER]Danke.  "
gameforge.subquest_04._290_sayReward = "Du erh\228ltst 4.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 3.000 Yang. "
gameforge.subquest_04._30_say = "Ich habe ihn schon lange nicht mehr gesehen und[ENTER]ihm einen Brief geschrieben, um zu fragen,[ENTER]wie es ihm geht.[ENTER]Ich m\246chte, dass du ihm den Brief bringst.[ENTER]Im Dorf gibt es heutzutage viele Probleme.[ENTER]Also sei vorsichtig.[ENTER]Und knick den Brief nicht! "
gameforge.subquest_04._40_say = "Oh, du wei\223t nicht, wie man zum n\228chsten[ENTER]Dorf gelangt?[ENTER]Dr\252cke M, um die Minikarte anzuzeigen. Darauf ist[ENTER]ein blauer Punkt verzeichnet. Dieser Punkt[ENTER]bezeichnet ein Portal, das dich in das[ENTER]angrenzende Gebiet bringt. In diesem Gebiet[ENTER]befindet sich auch das zweite Dorf. "
gameforge.subquest_04._50_select = "Werd ich tun. "
gameforge.subquest_04._60_select = "Nein danke. "
gameforge.subquest_04._70_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_04._80_say = "Komm bald wieder zu mir zur\252ck. "
gameforge.subquest_04._90_say = "Dann eben nicht. "
gameforge.subquest_05 = {}
gameforge.subquest_05._100_say = "Das ist sch\246n zu h\246ren.[ENTER]Komm doch einfach vorbei. "
gameforge.subquest_05._10_targetVid = "Ein Gefallen f\252r Soon. "
gameforge.subquest_05._110_say = "Sehr schade.[ENTER]Lass mich nun weiterlesen. "
gameforge.subquest_05._120_say = "Wirklich? Das freut mich![ENTER]Das wird ein gutes Buch. "
gameforge.subquest_05._130_sayTitle = "Hilfe f\252r Soon "
gameforge.subquest_05._140_sayReward = "Gehe zu Uriel und frage ihn, welches die besten[ENTER]F\228cher sind. "
gameforge.subquest_05._150_npcChat = "Auflistung der F\228cher nach Angriffswert "
gameforge.subquest_05._160_say = "Was f\252hrt dich zu mir?[ENTER]Der B\252cherwurm schickt dich? Jeden Tag zieht er[ENTER]sich mit seinen B\252chern und Schriftrollen zur\252ck,[ENTER]aber dadurch gewinnt er nicht an Intelligenz.[ENTER]St\228ndig st\246rt er mich. Lass sehen, was er dieses[ENTER]Mal wissen will! "
gameforge.subquest_05._170_say = "Er m\246chte, dass ich die F\228cher ihrem[ENTER]Angriffswert entsprechend aufliste? Das ist recht[ENTER]einfach. Es ist Vogelf\228cher, Dreifachf\228cher,[ENTER]Aquatischer F\228cher und Kranichf\228cher. Kapiert? "
gameforge.subquest_05._180_sendLetter = "Zur\252ck zu Soon "
gameforge.subquest_05._190_sayTitle = "R\252ckkehr zu Soon "
gameforge.subquest_05._200_sayReward = "Geh zu Soon zur\252ck und gib[ENTER]ihm die Information. "
gameforge.subquest_05._20_npcChat = "Ein Gefallen f\252r Soon "
gameforge.subquest_05._210_say = "Und, konnte Uriel dir eine klare Antwort geben? "
gameforge.subquest_05._211_select = "Vogel, Einfach, Aquatisch, Kranich. "
gameforge.subquest_05._212_select = "Vogel, Dreifach, Aquatisch, Kranich. "
gameforge.subquest_05._213_select = "Vogel, Zweifach, Aquatisch, Kranich. "
gameforge.subquest_05._214_select = "Oh nein, ich habe es vergessen. "
gameforge.subquest_05._220_say = "Vielen herzlichen Dank![ENTER]Jetzt kann ich weiterlesen.[ENTER]Ich danke dir! "
gameforge.subquest_05._230_sayReward = "Du erh\228ltst 6.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 2.000 Yang. "
gameforge.subquest_05._240_say = "Ich bin mir nicht sicher, ob das stimmt.[ENTER]Best\228tige es bitte. "
gameforge.subquest_05._250_select = "Ja, es stimmt. "
gameforge.subquest_05._260_select = "Ich bin mir nicht sicher. "
gameforge.subquest_05._270_say = "Sch\246n zu h\246ren.[ENTER]Komm einfach vorbei. "
gameforge.subquest_05._280_say = "Dies ist nicht sch\246n zu h\246ren.[ENTER]Geh weg... "
gameforge.subquest_05._290_say = "Wunderbar, sehr gut.[ENTER]Dann komm sp\228ter wieder. "
gameforge.subquest_05._300_say = "Bist du dir ganz sicher, dass die Reihenfolge[ENTER]stimmt? "
gameforge.subquest_05._30_sayTitle = "Soon: "
gameforge.subquest_05._310_select = "Ja, bin ich. "
gameforge.subquest_05._320_select = "Nein, bin ich nicht. "
gameforge.subquest_05._330_say = "Sch\246n zu h\246ren.[ENTER]Komm sp\228ter zu mir zur\252ck. "
gameforge.subquest_05._340_say = "Es w\228re zu sch\246n gewesen.[ENTER]Geh fort... "
gameforge.subquest_05._350_say = "In meinen B\252chern steht etwas anderes[ENTER]geschrieben. Bitte geh noch einmal zu[ENTER]Uriel und frage nach, ob die Reihenfolge[ENTER]stimmt. "
gameforge.subquest_05._40_say = "Soso... Hmhm... Nein, das...[ENTER]Huch, wo kommst du denn auf einmal her? Was[ENTER]f\228llt dir ein, mich beim Lesen zu st\246ren![ENTER]Oh je! Verzeih, ich wollte dich nicht anschreien.[ENTER]Manchmal stolpere ich beim Lesen \252ber etwas, das[ENTER]ich nicht verstehe und das ist so frustrierend.[ENTER]Kannst du mir bei einer Sache behilflich sein? "
gameforge.subquest_05._50_say = "Ich untersuche die F\228cherwaffen, die die[ENTER]Schamanen benutzen. Ich habe Probleme,[ENTER]herauszufinden, welche die besten sind. Ich kann[ENTER]sie unm\246glich alle testen.[ENTER]Der Gelehrte Uriel k\246nnte sich mit diesen[ENTER]F\228chern auskennen. Kannst du ihn fragen?[ENTER]Folgende F\228cherarten interessieren mich:[ENTER]Aquatischer F\228cher, Himmelsvogelf\228cher,[ENTER]Dreifachf\228cher, Kranichfl\252gelf\228cher. "
gameforge.subquest_05._60_say = "Ich m\246chte, dass er mir die F\228cher ihrem[ENTER]Angriffswert entsprechend auflistet. "
gameforge.subquest_05._70_select = "Mach ich. "
gameforge.subquest_05._80_select = "Nein, keine Lust. "
gameforge.subquest_05._90_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_06 = {}
gameforge.subquest_06._100_say = "Fort mit dir. Verschwinde![ENTER]Nutzloser Herumtreiber... "
gameforge.subquest_06._10_targetVid = "Die R\252stungsbestellung "
gameforge.subquest_06._110_say = "Ich danke dir![ENTER]Geh zum Schmied und frage ihn, wie weit er mit[ENTER]den R\252stungen ist. "
gameforge.subquest_06._120_sayReward = "Geh zum Schmied und frage ihn, wie weit er mit[ENTER]den R\252stungen ist, die der R\252stungsh\228ndler[ENTER]bestellt hat. "
gameforge.subquest_06._130_npcChat = "R\252stungen f\252r den R\252stungsh\228ndler "
gameforge.subquest_06._140_say = "Was ist jetzt wieder los? Warum st\246rst du mich?[ENTER]Oh, der H\228ndler des R\252stungsladens schickt[ENTER]dich? Dieser alte Mann ist sehr ungeduldig.[ENTER]Es ist nicht so, dass ich es nicht tun will. Ich[ENTER]besitze nur einfach nicht die n\246tigen[ENTER]Materialien dazu. K\246nntest du mir diese[ENTER]beschaffen? Um die R\252stungen herzustellen,[ENTER]ben\246tige ich Eisenerz, Leder und Kohle. Eisenerz[ENTER]bekommst du von Uriel, Leder von Octavio und[ENTER]Kohle von Yonah. "
gameforge.subquest_06._150_select = "Ich bringe dir die Materialien. "
gameforge.subquest_06._160_select = "Nein, jetzt nicht. "
gameforge.subquest_06._170_say = "Bist du sicher, dass du die Quest abbrechen[ENTER]willst? "
gameforge.subquest_06._180_say = "Du kannst es auch sp\228ter tun. Aber warte nicht zu[ENTER]lange, der Auftrag eilt! "
gameforge.subquest_06._190_say = "Na sch\246n, dann muss ich die Sachen wohl selber[ENTER]besorgen gehen. Mach es gut. "
gameforge.subquest_06._200_say = "Dann mach dich schnell auf den Weg![ENTER]Und ich kann endlich wieder in Ruhe arbeiten... "
gameforge.subquest_06._20_npcChat = "Die R\252stungsbestellung "
gameforge.subquest_06._210_sendLetter = "Material beschaffen "
gameforge.subquest_06._220_sayReward = "Besorge die Materialien f\252r den Schmied. "
gameforge.subquest_06._221_say = "Eisenerz - das bekommst du von Uriel. "
gameforge.subquest_06._222_say = "Leder - das bekommst du von Octavio. "
gameforge.subquest_06._223_say = "Kohle - die bekommst du von Yonah. "
gameforge.subquest_06._224_sayReward = "Uriel hat dir Eisenerz gegeben. "
gameforge.subquest_06._225_sayReward = "Octavio hat dir das Leder gegeben. "
gameforge.subquest_06._226_sayReward = "Yonah hat dir die Kohle gegeben. "
gameforge.subquest_06._230_targetVid = "Geh zu Octavio. "
gameforge.subquest_06._240_targetVid = "Geh zu Uriel. "
gameforge.subquest_06._250_targetVid = "Geh zu Yonah. "
gameforge.subquest_06._260_npcChat = "Ich brauche Eisenerz. "
gameforge.subquest_06._270_say = "Vielen Dank, dass du mir mein Buch zur\252ckbringst![ENTER]Nun kann ich meine Forschungen fortf\252hren.[ENTER]Hier, nimm etwas Eisenerz. Nutze es gut. "
gameforge.subquest_06._280_say = "Du willst Eisenerz? Ich kann dir etwas geben.[ENTER]Allerdings h\228tte ich vorher noch eine Bitte:[ENTER]K\252rzlich habe ich ein Buch verloren, als ich von[ENTER]einem Rudel Wildhunde gejagt wurde. Ich glaube,[ENTER]dass die Wildhunde mein Buch noch haben. Bring es[ENTER]mir zur\252ck, dann werde ich dir etwas Eisenerz[ENTER]geben. "
gameforge.subquest_06._285_say = "Uriel wird dir Eisenerz geben, wenn du ihm sein[ENTER]Buch von den Wildhunden zur\252ckbringst. "
gameforge.subquest_06._290_npcChat = "Ich brauche Eisenerz. "
gameforge.subquest_06._300_say = "Noch mehr Eisenerz?[ENTER]Ich habe dir doch schon etwas gegeben.[ENTER]Jetzt habe ich keines mehr. "
gameforge.subquest_06._30_say = "K\246nntest du mir helfen?[ENTER]Danke, dass du meiner Tochter einen Gefallen[ENTER]getan hast. Jetzt muss ich dich um einen Gefallen[ENTER]bitten. Ich habe den Dorfschmied beauftragt,[ENTER]R\252stungen herzustellen, aber ich habe noch[ENTER]nichts von ihm geh\246rt.[ENTER]Kannst du herausfinden, wie weit er ist? "
gameforge.subquest_06._310_npcChat = "Ich brauche Leder. "
gameforge.subquest_06._320_sayTitle = "Octavio: "
gameforge.subquest_06._330_say = "Danke f\252r die Galle! Nun kann ich wieder meine[ENTER]besonders leckeren Gerichte zubereiten! Mhm...[ENTER]Hier, nimm das Leder als Belohnung. "
gameforge.subquest_06._340_say = "Ich kann dir Leder geben.[ENTER]Aber in dieser Welt gibt es nichts umsonst.[ENTER]Was h\228ltst du von einem Tausch? Ich werde dir[ENTER]Leder geben, wenn du mir eine B\228rengalle bringst.[ENTER]Ich brauche oft B\228rengalle f\252r meine Gerichte.[ENTER]Wenn du nicht interessiert bist, dann soll es mir[ENTER]auch recht sein. "
gameforge.subquest_06._345_say = "Octavio wird dir Leder geben, wenn du ihm eine[ENTER]B\228rengalle bringst. "
gameforge.subquest_06._350_npcChat = "Ich ben\246tige Leder. "
gameforge.subquest_06._360_say = "Ich hab dir schon Leder gegeben.[ENTER]Hast du es verloren?[ENTER]Ich habe keines mehr. "
gameforge.subquest_06._370_npcChat = "Ich brauche Kohle. "
gameforge.subquest_06._380_say = "Danke f\252r den Lehm.[ENTER]Eine Hand w\228scht die andere: Hier hast du deine[ENTER]Kohle. Bis bald! "
gameforge.subquest_06._390_say = "Was gibt es?[ENTER]Du bist hier, um Kohle zu holen? Ich habe eine[ENTER]Menge Kohle. Aber die gibt es nicht umsonst.[ENTER]Erst musst du etwas f\252r mich tun. "
gameforge.subquest_06._395_say = "Yonah wird dir Kohle geben, wenn du ihm Lehm[ENTER]von Roten Keilern bringst. "
gameforge.subquest_06._400_say = "Mir geht bald der Lehm aus f\252r meine Irdenware.[ENTER]Wenn du mir Lehm bringst, gebe ich dir Kohle.[ENTER]Am besten t\246test du daf\252r Rote Keiler, die[ENTER]fressen Lehm, ob du es glaubst oder nicht.[ENTER]Vielen Dank im Voraus! "
gameforge.subquest_06._40_select = "Ja, mach ich. "
gameforge.subquest_06._410_npcChat = "Ich brauche Kohle. "
gameforge.subquest_06._420_say = "Was? Ich habe dir deine Kohle schon gegeben![ENTER]Versuchst du, mich reinzulegen? "
gameforge.subquest_06._430_npcChat = "Ich habe alle Materialien beisammen. "
gameforge.subquest_06._440_say = "Anscheinend hast du kein Eisenerz.[ENTER]Geh zu Uriel. "
gameforge.subquest_06._450_say = "Du hast kein Leder.[ENTER]Geh zu Octavio. "
gameforge.subquest_06._460_say = "Du hast noch keine Kohle.[ENTER]Hol sie von Yonah. "
gameforge.subquest_06._470_makequestbutton = "Ich habe alle Materialien. "
gameforge.subquest_06._480_qSetTitle = "Materialien f\252r den Schmied "
gameforge.subquest_06._490_targetVid = "Geh zum Schmied. "
gameforge.subquest_06._500_sayTitle = "Die bestellten R\252stungen "
gameforge.subquest_06._50_select = "Nein, keine Zeit. "
gameforge.subquest_06._510_sayReward = "Ich habe alle notwendigen Materialien.[ENTER]Auf zum Schmied. "
gameforge.subquest_06._520_npcChat = "Ich habe deine Materialien. "
gameforge.subquest_06._530_say = "Hast du schon alle Materialien bekommen?[ENTER]Ich bin beeindruckt! Dank dir kann ich dem[ENTER]R\252stungsh\228ndler die bestellten Gegenst\228nde[ENTER]bald liefern.[ENTER]Geh doch bitte zu ihm und \252berbringe ihm die gute[ENTER]Nachricht! "
gameforge.subquest_06._540_sayReward = "Informiere den R\252stungsh\228ndler, dass seine[ENTER]Bestellung bald fertig ist. "
gameforge.subquest_06._550_targetVid = "Geh zur\252ck zum R\252stungsh\228ndler. "
gameforge.subquest_06._560_npcChat = "Der Schmied liefert bald! "
gameforge.subquest_06._570_say = "Er hat die R\252stungen also bald fertig?[ENTER]Vielen Dank, dass du dich darum gek\252mmert hast.[ENTER]Nimm dies als Belohnung. "
gameforge.subquest_06._580_sayReward = "Du erh\228ltst 26.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 15.000 Yang.[ENTER]Du erh\228ltst eine Schweinenase. "
gameforge.subquest_06._590_sayReward = "Du erh\228ltst einen Tiger-Plattenpanzer+3. "
gameforge.subquest_06._600_sayReward = "Du erh\228ltst einen Scharlachroten Anzug+3. "
gameforge.subquest_06._60_say = "Willst du die Quest f\252r immer abbrechen? "
gameforge.subquest_06._610_sayReward = "Du erh\228ltst einen Ungl\252cksplattenpanzer+3. "
gameforge.subquest_06._620_sayReward = "Du erh\228ltst eine Rosafarbene Kleidung+3. "
gameforge.subquest_06._70_select = "Ja, will ich. "
gameforge.subquest_06._80_select = "Nein, lieber nicht. "
gameforge.subquest_06._90_say = "Wirst du es sp\228ter tun? Komm bald wieder, der[ENTER]Auftrag eilt! "
gameforge.subquest_07 = {}
gameforge.subquest_07._100_say = "Warte einen Moment, ich m\246chte sicher gehen,[ENTER]dass es das richtige Buch ist...[ENTER]Mhm, ja, das ist wirklich gro\223artig. Diese[ENTER]Gerichte will ich auf jeden Fall kochen![ENTER]Vielen Dank! "
gameforge.subquest_07._10_targetVid = "Das beste Kochbuch "
gameforge.subquest_07._110_say = "Hmm, daf\252r br\228uchte ich aber...[ENTER]Warte, Freund! Kann ich dich um einen weiteren[ENTER]Gefallen bitten?[ENTER]Ich habe fast alle Zutaten f\252r dieses[ENTER]fantastische Gericht hier, aber es fehlt noch ein[ENTER]Grauwolfsdarm. Diese Zutat ist nicht leicht zu[ENTER]bekommen und zudem frisch am besten.[ENTER]Bitte besorge mir einen! "
gameforge.subquest_07._120_sayReward = "Besorge einen Wolfsdarm f\252r Octavio.[ENTER]Du bekommst ihn von den Grauw\246lfen. "
gameforge.subquest_07._130_npcChat = "Ich habe einen Wolfsdarm. "
gameforge.subquest_07._140_say = "Dank dir kann ich nun dieses seltene Gericht[ENTER]kochen. Das wird ein Festschmaus![ENTER]Ich sch\228tze deine Hilfe sehr. Nimm bitte diese[ENTER]bescheidene Belohnung an. "
gameforge.subquest_07._150_sayReward = "Du erh\228ltst 12.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 5.000 Yang.[ENTER]Du erh\228ltst eine Wolfskralle. "
gameforge.subquest_07._160_say = "Ich brauche immer noch diesen Grauwolfsdarm.[ENTER]Bitte bring mir einen. "
gameforge.subquest_07._20_npcChat = "Das beste Kochbuch "
gameforge.subquest_07._30_say = "Hmm, kennst du vielleicht den B\252cherwurm Soon,[ENTER]der seine Zeit nur mit Lesen verbringt? Ich habe[ENTER]geh\246rt, dass Soon ein gutes Kochbuch besitzt.[ENTER]Bitte finde heraus, ob das stimmt. Das Kochbuch[ENTER]soll voll sein mit seltenen und exotischen[ENTER]Rezepten, die ich gerne lernen m\246chte. "
gameforge.subquest_07._40_targetVid = "Frag Soon "
gameforge.subquest_07._50_sayReward = "Frag Soon, ob er ein ausl\228ndisches Kochbuch[ENTER]besitzt. "
gameforge.subquest_07._60_npcChat = "Hast du ein besonderes Kochbuch? "
gameforge.subquest_07._70_say = "Bla, bla ... Oh! Du bist es wieder! Was gibt es?[ENTER]Ja, ich besitze ein Kochbuch mit exotischen[ENTER]Gerichten. Nimm es ruhig mit, ich brauche es[ENTER]nicht. Aber st\246r mich nicht st\228ndig beim Lesen! "
gameforge.subquest_07._80_targetVid = "Soon hat dir das ausl\228ndische Kochbuch ohne[ENTER]Schwierigkeiten \252berlassen. Bringe es zu Octavio. "
gameforge.subquest_07._90_npcChat = "Hier ist das Kochbuch! "
gameforge.subquest_08 = {}
gameforge.subquest_08._100_sayReward = "Geh zum Waffenh\228ndler und frage ihn, wo man[ENTER]Reiskuchen kaufen kann. "
gameforge.subquest_08._10_targetVid = "Reiskuchen? "
gameforge.subquest_08._110_npcChat = "Was wei\223t du \252ber Reiskuchen? "
gameforge.subquest_08._120_sayTitle = "Waffenh\228ndler: "
gameforge.subquest_08._130_say = "Was? Reiskuchen? Ist das eine neue Waffe?! Ja, da[ENTER]soll mich doch...[ENTER]Achso, du meinst Reiskuchen. Essbar, verstehe.[ENTER]Warum hast du das nicht gleich gesagt?[ENTER]Geh am besten zu Octavio. Der wei\223 alles, was man[ENTER]\252ber Essen wissen kann. "
gameforge.subquest_08._140_makequestbutton = "Reiskuchen "
gameforge.subquest_08._150_sayReward = "Geh zu Octavio und frage ihn, was er \252ber[ENTER]Reiskuchen wei\223. "
gameforge.subquest_08._160_say = "Hmm, Reiskuchen... Das ist dieser weiche Kuchen[ENTER]mit roten Kirschen und Zucker oben drauf, nicht[ENTER]wahr? Ja, den habe ich schon einmal gegessen.[ENTER]Du kannst ihn bei der umherziehenden[ENTER]Reiskuchenverk\228uferin im n\228chsten Dorf bekommen.[ENTER]Sie hei\223t Yu-Rang, glaube ich. "
gameforge.subquest_08._170_select = "Nein, keine Zeit. "
gameforge.subquest_08._180_say = "Einen langen Weg hast du vor dir.[ENTER]Bis zum n\228chsten Mal. "
gameforge.subquest_08._190_say = "Ich kann dir versicher, dass du etwas verpasst...[ENTER]Schade. Bis dann! "
gameforge.subquest_08._200_say = "Du wirst sehen, es lohnt sich.[ENTER]Gute Reise! "
gameforge.subquest_08._20_say = "Entschuldige, kannst du mir bitte helfen?[ENTER]Mein Baby weint pausenlos und ich wei\223 nicht mehr[ENTER]weiter. Das Einzige, das vielleicht helfen[ENTER]k\246nnte, w\228re ein Reiskuchen; das Kindchen liebt[ENTER]diese Speise. Gehst du bitte f\252r mich zum[ENTER]Waffenh\228ndler? Ich glaube er wei\223, wo man[ENTER]Reiskuchen bekommen kann. "
gameforge.subquest_08._210_makequestbutton = "Yu-Rang suchen "
gameforge.subquest_08._220_targetVid = "Reiskuchen "
gameforge.subquest_08._230_sayReward = "Geh zur Reiskuchenverk\228uferin Yu-Rang.[ENTER]Du findest sie im n\228chsten Dorf. "
gameforge.subquest_08._240_sayTitle = "Yu-Rang: "
gameforge.subquest_08._250_say = "Kann ich dir helfen?[ENTER]Oh, Reiskuchen! Klar kann ich dir Reiskuchen[ENTER]geben! Aber... k\246nntest du vorher etwas f\252r[ENTER]mich tun? Ein Junge namens Taurean kommt oft[ENTER]hierher und \228rgert mich, obwohl ich ihm nie[ENTER]etwas getan habe. Wenn du ihn daf\252r bestrafst,[ENTER]werde ich dir Reiskuchen geben.[ENTER]Einverstanden? "
gameforge.subquest_08._260_makequestbutton = "Suche Taurean "
gameforge.subquest_08._270_sayReward = "Yu-Rang wird st\228ndig von Taurean ge\228rgert.[ENTER]Bestrafe ihn, dann gibt sie dir einen Reiskuchen. "
gameforge.subquest_08._280_npcChat = "Warum \228rgerst du Yu-Rang? "
gameforge.subquest_08._290_say = "Was, wen soll ich ge\228rgert haben? Ach, du meinst[ENTER]das M\228dchen, das die Reiskuchen verkauft?[ENTER]Nein, ich wollte sie nicht \228rgern! Mir war nur[ENTER]langweilig und sie sah nett aus und hatte nicht[ENTER]viel zu tun. Da habe ich sie ein paar Mal besucht[ENTER]und wollte mit ihr spielen, aber sie ist nur[ENTER]w\252tend geworden...[ENTER]M\228dchen sind komisch. Dann besuche ich sie eben[ENTER]nicht mehr, pah! "
gameforge.subquest_08._300_makequestbutton = "Zur\252ck zu Yu-Rang "
gameforge.subquest_08._30_select = "Akzeptieren "
gameforge.subquest_08._310_targetVid = "Reiskuchen "
gameforge.subquest_08._320_sayReward = "Taurean wird Yu-Rang nicht mehr bel\228stigen. Geh[ENTER]zu ihr und hole dir deinen Reiskuchen ab. "
gameforge.subquest_08._330_say = "Ha, ha! Du hast Taurean bestraft, danke! Jetzt[ENTER]wird er es sich zweimal \252berlegen, bevor er[ENTER]wieder her kommt.[ENTER]Hier hast du den Reiskuchen. Lass ihn dir[ENTER]schmecken! "
gameforge.subquest_08._340_makequestbutton = "Zur\252ck zu Ah-Yu "
gameforge.subquest_08._350_targetVid = "Reiskuchen f\252r Ah-Yu "
gameforge.subquest_08._360_sayReward = "Du hast von Yu-Rang einen Reiskuchen bekommen.[ENTER]Bringe ihn zu Ah-Yu.[ENTER]Du findest sie und ihr Kind im ersten Dorf. "
gameforge.subquest_08._370_npcChat = "Hier ist der Reiskuchen f\252r dein Kind. "
gameforge.subquest_08._380_say = "Du hast mir den Reiskuchen gebracht! Vielen,[ENTER]vielen Dank. Schau nur, mein Baby hat aufgeh\246rt[ENTER]zu weinen und knabbert ganz gl\252cklich daran[ENTER]herum. Du hast es geschafft. Danke f\252r deine[ENTER]Hilfe! "
gameforge.subquest_08._390_sayReward = "Du erh\228ltst 26.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 10.000 Yang. "
gameforge.subquest_08._40_say = "Aber... Ich kann hier nicht weg und das Baby[ENTER]terrorisiert die gesamte Nachbarschaft...[ENTER]Es dauert auch bestimmt nicht lang! Bist du[ENTER]sicher, dass du keine Zeit hast? "
gameforge.subquest_08._50_say = "Du bist wohl besch\228ftigt?[ENTER]Bitte komm sp\228ter noch einmal.[ENTER]Nicht weinen, mein Kind. "
gameforge.subquest_08._60_say = "Dann werde ich wohl jemand anderen fragen m\252ssen.[ENTER]Viel Gl\252ck auf deinen Reisen! "
gameforge.subquest_08._70_say = "Hab vielen Dank! Das ist f\252r mich eine gro\223e[ENTER]Erleichterung. "
gameforge.subquest_08._80_makequestbutton = "Reiskuchen "
gameforge.subquest_08._90_targetVid = "Reiskuchen "
gameforge.subquest_09 = {}
gameforge.subquest_09._100_sayReward = "Finde die Wei\223er-Eid Soldatin, die dem[ENTER]Schmied die goldene Axt gestohlen hat[ENTER]und bring diese zu ihm zur\252ck. "
gameforge.subquest_09._10_targetVid = "Finde die goldene Axt "
gameforge.subquest_09._110_sendLetter = "Goldene Axt gefunden "
gameforge.subquest_09._120_npcChat = "Hier ist die goldene Axt. "
gameforge.subquest_09._130_say = "Danke! Ich stehe in deiner Schuld. Jetzt muss ich[ENTER]mir keine Gedanken mehr machen, was ich Deokbae[ENTER]sage, wenn ich ihn sehe! "
gameforge.subquest_09._140_sayReward = "Du erh\228ltst 36.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 10.000 Yang.[ENTER]Du erh\228ltst einen Schmuckgegenstand. "
gameforge.subquest_09._20_npcChat = "Die goldene Axt "
gameforge.subquest_09._30_say = "Erinnerst du dich an meinen Freund Deokbae?[ENTER]Ich versprach ihm, eine Axt zu fertigen, aber ich[ENTER]passte einen Augenblick nicht auf und eine[ENTER]Wei\223er-Eid Soldatin stahl sie mir.[ENTER]Kannst du mir die Axt wiederholen? Eine[ENTER]Wei\223er-Eid Soldatin muss sie haben. Du solltest[ENTER]die Axt erkennen. Es gibt nicht viele davon. Ich[ENTER]werde dich f\252rstlich belohnen! "
gameforge.subquest_09._40_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_09._50_sayTitle = "Schmied: "
gameforge.subquest_09._60_say = "Ich will die Axt unbedingt![ENTER]Sehen wir uns noch einmal?[ENTER]Auf Wiedersehen. "
gameforge.subquest_09._70_say = "Danke, dass du dich darum k\252mmerst.[ENTER]Pass auf dich auf, denn der Clan macht viel[ENTER]\196rger. "
gameforge.subquest_09._80_say = "Danke, dass du dich darum k\252mmerst.[ENTER]Pass auf dich auf, denn der Clan macht richtig[ENTER]\196rger. "
gameforge.subquest_09._90_makequestbutton = "Finde die goldene Axt "
gameforge.subquest_10 = {}
gameforge.subquest_10._100_sayReward = "Frage den Schmied nach dem Verbleib der[ENTER]Haarnadel. "
gameforge.subquest_10._10_targetVid = "Finde die Haarnadel "
gameforge.subquest_10._110_npcChat = "Die gestohlene Haarnadel "
gameforge.subquest_10._120_say = "Was? Sie denkt, dass ich ihre Haarnadel gestohlen[ENTER]habe? Das ist unglaublich! F\252r wen h\228lt sie mich?[ENTER]Ich habe flei\223ig in meiner Schmiede gearbeitet![ENTER]Ah, ich sollte dir das nicht erz\228hlen, aber der[ENTER]Waffenh\228ndler war vor einer Weile im Laden der[ENTER]Gemischtwarenh\228ndlerin. "
gameforge.subquest_10._130_makequestbutton = "Die gestohlene Haarnadel "
gameforge.subquest_10._140_sayReward = "Frage den Waffenh\228ndler nach dem Verbleib der[ENTER]Haarnadel. "
gameforge.subquest_10._150_say = "Was? Du glaubst, dass ich die Haarnadel der[ENTER]Gemischtwarenh\228ndlerin gestohlen habe? Nein,[ENTER]nein, das habe ich nicht! Ehrlich! Ich war zwar[ENTER]dort, um der Gemischtwarenh\228ndlerin einen Besuch[ENTER]abzustatten! Aber sie war nicht da. An ihrer[ENTER]Stelle fand ich eine Wei\223er-Eid Bogensch\252tzin.[ENTER]Als sie mich sah, rannte sie weg. Vielleicht hat[ENTER]sie die Haarnadel gestohlen. "
gameforge.subquest_10._160_sayReward = "Hole die Haarnadel von der Wei\223er-Eid[ENTER]Bogensch\252tzin zur\252ck! "
gameforge.subquest_10._170_sendLetter = "Haarnadel gefunden "
gameforge.subquest_10._180_targetVid = "Gehe zur H\228ndlerin. "
gameforge.subquest_10._190_npcChat = "Ich habe hier deine Haarnadel. "
gameforge.subquest_10._200_say = "Oh, vielen Dank.[ENTER]Ich freue mich. Endlich habe ich meine geliebte[ENTER]Haarnadel wieder![ENTER]Du hast mir schon so oft geholfen. Wie kann ich[ENTER]das nur wieder gut machen? Ich habe eine[ENTER]Reitkarte. Es ist nur eine Kleinigkeit, aber ich[ENTER]brauche sie nicht mehr, da ich meinen Laden nicht[ENTER]mehr so einfach verlassen kann. Nimm sie, als[ENTER]Zeichen meiner Dankbarkeit! "
gameforge.subquest_10._20_say = "Bitte, h\246r mich an. Ich bin in einer misslichen[ENTER]Lage. Ich habe f\252r kurze Zeit meinen Laden[ENTER]verlassen, weil ich etwas ganz Wichtiges zu[ENTER]erledigen hatte. W\228hrend meiner Abwesenheit stahl[ENTER]jemand meine Lieblingshaarnadel. "
gameforge.subquest_10._210_sayReward = "Du erh\228ltst 60.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 10.000 Yang.[ENTER]Du erh\228ltst eine Reitkarte. "
gameforge.subquest_10._220_say = "Du hast meine Haarnadel noch nicht gefunden?[ENTER]Ich hoffe, du findest sie noch. "
gameforge.subquest_10._230_select = "Aufh\246ren "
gameforge.subquest_10._240_say = "Wirklich aufh\246ren? "
gameforge.subquest_10._250_say = "Ja, sie sind z\228he Gegner...[ENTER]Ruh dich aus und versuch es sp\228ter noch einmal. "
gameforge.subquest_10._260_say = "Wo ist meine Lieblingshaarnadel?[ENTER]Das hat wohl nicht funktioniert... Auf[ENTER]Wiedersehen. "
gameforge.subquest_10._270_say = "Vielen Dank. Sie bedeutet mir wirklich viel. "
gameforge.subquest_10._30_say = "Mein Vater schenkte mir diese schm\252ckende[ENTER]Haarnadel zum Geburtstag und ich liebe sie. Aber[ENTER]nat\252rlich kann ich meinen Laden nicht wieder[ENTER]verlassen, sonst wird mir vielleicht noch etwas[ENTER]Wichtiges gestohlen.[ENTER]K\246nntest du die Haarnadel f\252r mich suchen? Ich[ENTER]verd\228chtige den Schmied. Er erw\228hnte einmal, dass[ENTER]er nach solchem Haarschmuck sucht. "
gameforge.subquest_10._40_select = "Ich suche sie. "
gameforge.subquest_10._50_say = "Quest wirklich abbrechen? "
gameforge.subquest_10._60_say = "Bis zum n\228chsten Mal.[ENTER]Viel Spa\223 noch. "
gameforge.subquest_10._70_say = "Wo mag meine Haarnadel nur sein?[ENTER]Auf Wiedersehen... "
gameforge.subquest_10._80_say = "Du suchst sie f\252r mich?[ENTER]Oh, vielen Dank! "
gameforge.subquest_10._90_targetVid = "Geh zum Schmied "
gameforge.subquest_11 = {}
gameforge.subquest_11._100_targetVid = "Frage Yu-Hwan nach Mirines Bruder. "
gameforge.subquest_11._10_targetVid = "Finde meinen Bruder "
gameforge.subquest_11._110_npcChat = "Hast du Mirines Bruder gesehen? "
gameforge.subquest_11._120_say = "Ich habe mich verliebt, ohne zu wissen, was Liebe[ENTER]bedeutet... Lalalaa...[ENTER]Wen suchst du? Mirines Bruder? Wir haben uns kurz[ENTER]unterhalten, bevor er in die Berge ging, um[ENTER]seltene Kr\228uter zu suchen. Ich wei\223 nicht, wo er[ENTER]jetzt ist.[ENTER]Der J\228ger hier im Dorf geht h\228ufig in die Berge.[ENTER]Warum fragst du nicht ihn?[ENTER]La, la, la, Liebe ist traurig, aber sch\246n... "
gameforge.subquest_11._130_targetVid = "Frage Yang-Shin nach Mirines Bruder. "
gameforge.subquest_11._140_say = "Mirines Bruder? Ja, er hat in den Bergen nach[ENTER]Kr\228utern gesucht.[ENTER]Er hat sich so gefreut, einige wirklich seltene[ENTER]Kr\228uter gefunden zu haben. Er wollte seiner[ENTER]Schwester aus dem Erl\246s der Kr\228uter neue Kleider[ENTER]kaufen. Er ist wirklich nett.[ENTER]Ich sch\228tze, er wird in ein paar Tagen zur\252ck[ENTER]sein. Meinst du nicht auch? "
gameforge.subquest_11._150_targetVid = "Erz\228hle Mirine die Neuigkeiten. "
gameforge.subquest_11._160_npcChat = "Neuigkeiten \252ber Mirines Bruder. "
gameforge.subquest_11._170_say = "Schau, ich habe einen Brief von meinem Bruder[ENTER]bekommen! Er schreibt, dass er einen Ort mit[ENTER]vielen Kr\228utern gefunden hat und deshalb l\228nger[ENTER]fort bleiben wird.[ENTER]Verzeih. Ich h\228tte dich nicht bel\228stigen sollen.[ENTER]Hier, es ist nicht viel, aber ich hoffe du nimmst[ENTER]es an und verzeihst mir.[ENTER]Danke, dass du den weiten Weg auf dich genommen[ENTER]hast! "
gameforge.subquest_11._180_sayReward = "Du erh\228ltst 122.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 5.000 Yang. "
gameforge.subquest_11._20_npcChat = "Finde meinen Bruder. "
gameforge.subquest_11._30_say = "Kann ich dich um einen Gefallen bitten?[ENTER]Mein Bruder ist schon lange weg. Ich habe schon[ENTER]seit einiger Zeit nichts mehr von ihm geh\246rt.[ENTER]So langsam mache ich mir Sorgen.[ENTER]K\246nntest du ihn suchen? "
gameforge.subquest_11._40_say = "Mein Bruder wollte den Musiker Yu-Hwan[ENTER]im n\228chsten Dorf besuchen.[ENTER]Wenn du zu Yu-Hwan gehst, erf\228hrst du[ENTER]sicher Neues \252ber meinen Bruder.[ENTER]Vielen Dank im Voraus. "
gameforge.subquest_11._50_select = "Ja, mach ich. "
gameforge.subquest_11._60_say = "Willst du diese Quest f\252r immer aufgeben? "
gameforge.subquest_11._70_say = "Vielen Dank.[ENTER]Bitte such ihn f\252r mich.[ENTER]Ich mach mir gro\223e Sorgen.[ENTER]Bis bald. "
gameforge.subquest_11._80_say = "Schade, dass du mir nicht helfen willst.[ENTER]Bis bald. "
gameforge.subquest_11._90_say = "Du wirst ihn f\252r mich suchen?[ENTER]Vielen Dank, ich mache mir gro\223e Sorgen um ihn.[ENTER]Viel Gl\252ck. "
gameforge.subquest_12 = {}
gameforge.subquest_12._100_qSetTitle = "Mi-Jung vom Wei\223en-Eid "
gameforge.subquest_12._10_targetVid = "T\246te Mi-Jung vom Wei\223en-Eid "
gameforge.subquest_12._110_sayReward = "Gehe dann zum W\228chter des Dorfplatzes zur\252ck. "
gameforge.subquest_12._120_sayTitle = "Mi-Jung vom Wei\223en-Eid "
gameforge.subquest_12._130_sayReward = "Geh und t\246te Mi-Jung vom Wei\223en-Eid.[ENTER]Kehre dann zum W\228chter des Dorfplatzes zur\252ck. "
gameforge.subquest_12._140_targetVid = "Gehe zum W\228chter des Dorfplatzes. "
gameforge.subquest_12._150_sayTitle = "Mi-Jung vom Wei\223en-Eid get\246tet "
gameforge.subquest_12._160_sayReward = "Kehre zum W\228chter des Dorfplatzes zur\252ck,[ENTER]um deine Belohnung in Empfang zu nehmen. "
gameforge.subquest_12._170_npcChat = "Ich habe Mi-Jung get\246tet. "
gameforge.subquest_12._180_say = "Oh! Du bist wirklich so gut, wie ich geh\246rt[ENTER]habe. Ganz erstaunlich. Dank dir wird das Problem[ENTER]mit dem Wei\223en-Eid jetzt viel einfacher zu l\246sen[ENTER]sein. Gut gemacht! "
gameforge.subquest_12._190_sayReward = "Du erh\228ltst 122.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 20.000 Yang.[ENTER]Du erh\228ltst ein Silberarmband. "
gameforge.subquest_12._20_say = "Komm einen Moment her.[ENTER]Du bist ein guter K\228mpfer. Ich habe vom Hauptmann[ENTER]viel \252ber dich geh\246rt. "
gameforge.subquest_12._30_say = "Kannst du dich Mi-Jungs vom Wei\223en-Eid annehmen,[ENTER]die so viele Probleme bereitet?[ENTER]Es ist schwer, das Dorf und seine Einwohner[ENTER]vor den h\228ufigen Angriffen des Wei\223en-Eids zu[ENTER]sch\252tzen. Wenn wir Mi-Jung, eine der[ENTER]Anf\252hrerinnen, t\246ten, wird sich die Situation[ENTER]\228ndern. Die Sicherheit unseres Dorfes liegt in[ENTER]deiner Hand. Ich vertraue dir! "
gameforge.subquest_12._40_select = "Ja, werde ich. "
gameforge.subquest_12._50_select = "Jetzt nicht. "
gameforge.subquest_12._60_say = "Du willst uns wirklich nicht helfen? "
gameforge.subquest_12._70_say = "Es ist wohl nicht der richtige Zeitpunkt.[ENTER]Komm sp\228ter wieder. "
gameforge.subquest_12._80_say = "Wenn du nicht willst, kann man nichts machen.[ENTER]Dann geh... "
gameforge.subquest_12._90_say = "Willst du uns wirklich nicht helfen? "
gameforge.subquest_13 = {}
gameforge.subquest_13._100_targetVid = "Geh zu Ariyoung. "
gameforge.subquest_13._10_targetVid = "Material f\252r das Anfertigen von Waffen. "
gameforge.subquest_13._110_targetVid = "Geh zu Ah-Yu. "
gameforge.subquest_13._120_sayReward = "Der Waffenh\228ndler braucht deine Hilfe.[ENTER]Besorge ihm Eisenerz von Uriel und Leinen von[ENTER]Ariyoung. "
gameforge.subquest_13._130_npcChat = "Ich brauche Eisenerz. "
gameforge.subquest_13._140_say = "Du brauchst Eisenerz? Ich k\246nnte dir welches[ENTER]geben, wenn du mir einen Gefallen tust. "
gameforge.subquest_13._150_say = "Ich habe etwas fallen lassen, als ich vor den[ENTER]Tigern um mein Leben laufen musste: Es ist ein[ENTER]zusammengeschn\252rtes B\252ndel, in dem sich wichtige[ENTER]B\252cher befinden. Wenn ich sie nicht habe, kann[ENTER]ich die Metinsteine nicht weiter untersuchen.[ENTER]Bring mir dieses P\228ckchen und du bekommst etwas[ENTER]Erz von mir. "
gameforge.subquest_13._160_npcChat = "Ich habe dein P\228ckchen. "
gameforge.subquest_13._170_say = "Danke![ENTER]Ich bitte dich zu oft um einen Gefallen.[ENTER]Hier! Hier hast du etwas Eisenerz. Ich hoffe, es[ENTER]erf\252llt seinen Zweck. "
gameforge.subquest_13._180_say = "Was? Du brauchst noch mehr Eisenerz? Es w\228chst[ENTER]nicht auf B\228umen, wei\223t du![ENTER]Ich gebe dir etwas Eisenerz, aber du musst mir[ENTER]einen Gefallen tun.[ENTER]Tiger haben mein P\228ckchen gestohlen. Ich bin[ENTER]weggerannt, um mein Leben zu retten. In diesem[ENTER]P\228ckchen sind viele wichtige Dokumente. Ohne sie[ENTER]kann ich meine Forschung \252ber die Metinsteine[ENTER]nicht fortf\252hren. Bitte finde das P\228ckchen, das[ENTER]sie mir gestohlen haben. "
gameforge.subquest_13._190_say = "Das hab ich dir doch schon gegeben.[ENTER]Hast du das vergessen? "
gameforge.subquest_13._200_sayTitle = "P\228ckchen gefunden "
gameforge.subquest_13._20_npcChat = "Material f\252r Waffen "
gameforge.subquest_13._210_say = "Du hast das P\228ckchen von Uriel gefunden.[ENTER]Gehe zur\252ck zu ihm. "
gameforge.subquest_13._220_npcChat = "Ich brauche Leinen. "
gameforge.subquest_13._230_say = "Du brauchst Leinen? Das habe ich Ah-Yu gegeben.[ENTER]Warte![ENTER]Wenn du sowieso zu ihr gehst, dann kannst du[ENTER]diesen Brief mitnehmen. Wir sind gut befreundet,[ENTER]haben uns aber wegen ihres Kindes lange nicht[ENTER]gesehen. Ich schreibe noch dazu, dass sie dir[ENTER]etwas von dem Leinen geben soll... So, damit ist[ENTER]allen geholfen![ENTER]Und richte ihr meine Gr\252\223e aus. "
gameforge.subquest_13._240_say = "Ariyoung:[ENTER]Du hast doch bestimmt Leinen von Ah-Yu[ENTER]bekommen, oder? "
gameforge.subquest_13._250_npcChat = "Ariyoungs Brief "
gameforge.subquest_13._260_say = "Ein Brief von Ariyoung? Es ist sch\246n, nach so[ENTER]langer Zeit endlich wieder von ihr zu h\246ren.[ENTER]Fr\252her haben wir uns oft zum Reden getroffen,[ENTER]aber in letzter Zeit war es schwierig.[ENTER]Hier steht, du brauchst Leinen? Ich habe welches[ENTER]von Ariyoung bekommen, davon kann ich dir etwas[ENTER]abgeben.[ENTER]Vielen Dank, dass du mir den Brief gebracht hast.[ENTER]Ich werde ihr gleich zur\252ckschreiben... "
gameforge.subquest_13._270_qSetTitle = "Auf zum Waffenh\228ndler "
gameforge.subquest_13._280_targetVid = "Geh zum Waffenh\228ndler. "
gameforge.subquest_13._290_sayTitle = "Materialien abgeben "
gameforge.subquest_13._300_sayReward = "Ich habe das Material.[ENTER]Auf zum Waffenh\228ndler. "
gameforge.subquest_13._30_say = "Hey, du musst mir einen Gefallen tun.[ENTER]Ich versuche, neue Waffenarten zu fertigen.[ENTER]Es ist nicht leicht, das passende Material f\252r[ENTER]sie zu finden. Ich habe viele Bestellungen und[ENTER]kann nicht selbst nach den Materialien suchen.[ENTER]K\246nntest du sie f\252r mich besorgen? "
gameforge.subquest_13._310_say = "Gut gemacht. Du bist sehr f\228hig und schnell.[ENTER]Lass mich jetzt an den Waffen arbeiten![ENTER]*H\228mmer, h\228mmer.*[ENTER]Hier sind sie. Das sind die neuen Waffenarten.[ENTER]Ich habe mein Bestes gegeben. Ich hoffe, die[ENTER]Waffe gef\228llt dir. Viel Spa\223 damit! "
gameforge.subquest_13._320_sayTitle = "Belohung: "
gameforge.subquest_13._330_sayReward = "Du erh\228ltst 122.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 20.000 Yang. "
gameforge.subquest_13._340_sayReward = "Du erh\228ltst ein Breitschwert+3. "
gameforge.subquest_13._350_sayReward = "Du erh\228ltst einen Scherendolch+3. "
gameforge.subquest_13._360_sayReward = "Du erh\228ltst einen Pfauenf\228cher+3. "
gameforge.subquest_13._40_say = "Nat\252rlich werde ich dich daf\252r belohnen.[ENTER]Wenn die Waffen fertig sind, werde ich dir[ENTER]eine davon geben.[ENTER]Ich brauche folgende Materialien: Eisenerz und[ENTER]Leinen. Eisenerz erh\228ltst du bei Uriel, Leinen[ENTER]bei Ariyoung.[ENTER]Lass es mich wissen, wenn du alle Materialien[ENTER]hast. "
gameforge.subquest_13._50_say = "Willst du die Aufgabe wirklich nicht erledigen? "
gameforge.subquest_13._60_say = "Das war wohl zuviel f\252r dich.[ENTER]Komm wieder, wenn du mehr Zeit hast! "
gameforge.subquest_13._70_say = "Wenn du nicht m\246chtest, kann man wohl nichts[ENTER]machen. Bis bald. "
gameforge.subquest_13._80_say = "Sehr gut![ENTER]Wenn die Waffen fertig sind, bekommst du[ENTER]auch eine von mir. Viel Gl\252ck. "
gameforge.subquest_13._90_sendLetter = "Materialien suchen "
gameforge.subquest_15 = {}
gameforge.subquest_15._100_targetVid = "Zur\252ck zum Stadtw\228chter "
gameforge.subquest_15._10_targetVid = "Eun-Jung vom Wei\223en-Eid "
gameforge.subquest_15._110_sayReward = "Du hast Eun-Jung vom Wei\223en-Eid get\246tet.[ENTER]Geh zur\252ck zum W\228chter des Dorfplatzes und[ENTER]erstatte ihm Bericht. "
gameforge.subquest_15._120_say = "Du bist gro\223artig! Sogar noch besser, als ich[ENTER]erwartet habe. Wir konnten gegen diese beiden[ENTER]Anf\252hrer des Wei\223en-Eids nichts machen. Du aber[ENTER]bist mit beiden ganz leicht fertig geworden. "
gameforge.subquest_15._130_say = "Das ist unglaublich.[ENTER]Du solltest eine angemessene Belohnung erhalten.[ENTER]Bitte nimm dies und arbeite weiterhin f\252r den[ENTER]Frieden des Dorfes! "
gameforge.subquest_15._140_sayReward = "Du erh\228ltst 150.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 25.000 Yang.[ENTER]Du erh\228ltst eine Goldhalskette+4. "
gameforge.subquest_15._20_say = "Komm einen Moment her.[ENTER]Ich habe vom Hauptmann viel \252ber dich geh\246rt. Du[ENTER]scheinst furchtlos zu sein. Deshalb brauche ich[ENTER]noch einmal deine Hilfe: Der Wei\223e-Eid ist[ENTER]schlimmer als je zuvor. "
gameforge.subquest_15._30_say = "Du hast dich zwar um Mi-Jung, die Anf\252hrerin des[ENTER]Wei\223en-Eids, gek\252mmert, aber wir sind immer noch[ENTER]nicht sicher. Die Gefahr durch den Wei\223en-Eid ist[ENTER]nicht weniger geworden, sondern gr\246\223er als je[ENTER]zuvor! "
gameforge.subquest_15._40_say = "Um die Sache zu beenden, m\252ssen wir auch noch[ENTER]die Anf\252hrerin Eun-Jung vernichten. Der Rest[ENTER]sollte dann einfach sein.[ENTER]Geh und t\246te Eun-Jung. Unser Schicksal liegt in[ENTER]deinen H\228nden! "
gameforge.subquest_15._50_sayTitle = "W\228chter des Dorfplatzes: "
gameforge.subquest_15._60_say = "Kommst du sp\228ter wieder?[ENTER]Du bist genau richtig f\252r diesen Auftrag. "
gameforge.subquest_15._70_say = "Du kannst nicht? Na gut.[ENTER]Auf bald. "
gameforge.subquest_15._80_say = "Ich wusste, dass du uns helfen w\252rdest.[ENTER]T\246te Eun-Jung. Wir erledigen den Rest.[ENTER]Viel Gl\252ck! "
gameforge.subquest_15._90_sayReward = "T\246te die Anf\252hrerin Eun-Jung. Hoffentlich gibt[ENTER]der Wei\223e-Eid dann Ruhe. "
gameforge.subquest_16 = {}
gameforge.subquest_16._100_qSetTitle = "Frage Yu-Hwan "
gameforge.subquest_16._10_targetVid = "Suche nach der gepanzerten Kavallerie "
gameforge.subquest_16._110_targetVid = "Geh zu Yu-Hwan "
gameforge.subquest_16._120_say = "Das Leben ist so sch\246n... Oh, die Liebe,[ENTER]wundersch\246n... ![ENTER]Du schon wieder. Was willst du jetzt?[ENTER]Informationen \252ber die gepanzerte Kavallerie?[ENTER]Warum fragst du danach?[ENTER]Der Hauptmann hat wohl hochtrabende Pl\228ne? "
gameforge.subquest_16._130_sayTitle = "Yu-Hwan: "
gameforge.subquest_16._140_say = "Es sind zwar kaum Originaltexte aus dieser Zeit[ENTER]erhalten, aber ich kenne einige Lieder \252ber die[ENTER]gepanzerte Kavallerie. Moment, ich stimme kurz[ENTER]mein Instrument...[ENTER]Ach, du hast es eilig? Heutzutage nimmt sich[ENTER]niemand mehr die Zeit zum Zuh\246ren...[ENTER]Also gut. Grob zusammengefasst war Isups Reiterei[ENTER]beinahe unbesiegbar. Hervorragend ausgebildete[ENTER]Soldaten, schwere Eisenr\252stungen und dazu noch[ENTER]schnell und beweglich. "
gameforge.subquest_16._150_say = "Es war die beste Armee, die dieser Kontinent[ENTER]jemals gesehen hat. Damals gingen viele L\228nder[ENTER]unter, weil nichts die Kavallerie aufhalten[ENTER]konnte. Heute s\228he das ganz \228hnlich aus.[ENTER]Allerdings braucht man harte Trainingsmethoden[ENTER]und viel hochwertiges Eisen, um solch eine Armee[ENTER]aufzustellen.[ENTER]Du solltest den Fahrenden H\228ndler und den[ENTER]Gelehrten Uriel befragen. Sie wissen sicher mehr[ENTER]\252ber die Einzelheiten. "
gameforge.subquest_16._160_makequestbutton = "Zum Fahrenden H\228ndler "
gameforge.subquest_16._170_qSetTitle = "Die gepanzerte Kavallerie "
gameforge.subquest_16._180_targetVid = "Fahrender H\228ndler "
gameforge.subquest_16._190_sayReward = "Der Musiker Yu-Hwan sagt, dass der Fahrende[ENTER]H\228ndler und der Gelehrte Uriel Informationen[ENTER]\252ber die gepanzerte Kavallerie haben k\246nnten.[ENTER]Gehe zuerst zum Fahrenden H\228ndler. "
gameforge.subquest_16._200_sayTitle = "Fahrender H\228ndler: "
gameforge.subquest_16._20_npcChat = "Die gepanzerte Kavallerie "
gameforge.subquest_16._210_say = "Was willst du von einem einfachen fahrenden[ENTER]H\228ndler wie mir? Die Eisenr\252stungen der[ENTER]gepanzerten Kavallerie? Das sind doch alte[ENTER]Geschichten. Wen interessiert das heute noch? Ich[ENTER]muss meinen Lebensunterhalt verdienen und kann[ENTER]nicht den ganzen Tag plaudern! "
gameforge.subquest_16._220_say = "Es wird immer schwieriger, \252ber die Runden zu[ENTER]kommen. Seit diese Steine vom Himmel fallen,[ENTER]habe ich... Was sagst du?[ENTER]Achja, die Kavallerie.[ENTER]Soweit ich wei\223, trugen sie Spezialr\252stungen,[ENTER]deren Herstellung einzigartige F\228higkeiten[ENTER]erforderte. Es sind die besten R\252stungen, die je[ENTER]hergestellt wurden! Gew\246hnliche Messer oder[ENTER]sogar Pfeile prallten einfach ab! "
gameforge.subquest_16._230_say = "Dass diese R\252stungen etwas ganz Besonderes waren,[ENTER]sieht man schon an den Geldern, die n\246tig waren,[ENTER]um die Kavallerie aufzustellen. Es hei\223t,[ENTER]die Schatzkammern ganzer K\246nigreiche habe sie[ENTER]verschlungen! Wenn ich solche R\252stungen verkaufen[ENTER]w\252rde, h\228tte ich ausgesorgt! "
gameforge.subquest_16._240_say = "Heute kann man sogar aus Metinsteinen R\252stungen[ENTER]herstellen. Mit dieser neuen R\252stungsart eine[ENTER]gepanzerte Kavallerie wie die damalige[ENTER]aufzustellen, ist m\246glicherweise nicht nur ein[ENTER]Traum. Aber ich rede zu viel. Ich muss weiter.[ENTER]Bis bald! "
gameforge.subquest_16._250_sayTitle = "Die gepanzerte Kavallerie "
gameforge.subquest_16._260_say = "Der Fahrende H\228ndler wusste etwas \252ber die[ENTER]Eisenr\252stungen der gepanzerten Kavallerie.[ENTER]Gehe nun zum Gelehrten Uriel im Nachbardorf und[ENTER]frage ihn nach den Trainingsmethoden. "
gameforge.subquest_16._270_sayTitle = "Uriel: "
gameforge.subquest_16._280_say = "Was f\252hrt dich diesmal zu mir? Die gepanzerte[ENTER]Kavallerie? Nat\252rlich wei\223 ich etwas \252ber sie.[ENTER]Jeder wei\223 etwas. Man wird sie f\252r alle Zeiten[ENTER]als die beste Armee der Geschichte in Erinnerung[ENTER]behalten! Vieles, was man sich erz\228hlt, mag[ENTER]\252bertrieben sein, aber diese Reiter waren[ENTER]wirklich au\223erordentlich gef\252rchtet. Und das zu[ENTER]Recht. "
gameforge.subquest_16._290_say = "Die gepanzerte Kavallerie war allen anderen[ENTER]K\228mpfern \252berlegen. Das lag haupts\228chlich an[ENTER]ihrem unmenschlich harten Training. Nur die[ENTER]Allerbesten konnten die Ausbildung abschlie\223en,[ENTER]nicht wenige starben dabei. Ich glaube, wenn das[ENTER]gleiche Training heute durchgef\252hrt werden w\252rde,[ENTER]bliebe am Ende kein einziger Soldat \252brig. "
gameforge.subquest_16._300_say = "Einige der Trainingsmethoden sind \252berliefert.[ENTER]Ich gebe dir ein paar Notizen mit, dann kannst du[ENTER]dir selbst ein Bild davon machen.[ENTER]Ich wei\223, dass schreckliche Kriege w\252ten, aber[ENTER]ich bin nicht sicher, ob es eine gute Idee w\228re,[ENTER]noch einmal so eine furchterregende Armee[ENTER]aufzustellen. "
gameforge.subquest_16._30_say = "Ich habe einen neuen Auftrag f\252r dich.[ENTER]Du hast den Befehl, Informationen \252ber die[ENTER]gepanzerte Kavallerie zu sammeln. Sie war die[ENTER]wichtigste Einheit der Armee von Isup, dem[ENTER]Gr\252nderk\246nig und Vereiniger des Kontinents.[ENTER]Die gepanzerte Kavallerie wurde von den anderen[ENTER]L\228ndern wegen ihrer erstaunlichen Schnelligkeit[ENTER]und Angriffskraft gef\252rchtet. "
gameforge.subquest_16._310_say = "Gehe zum Hauptmann und berichte ihm alles,[ENTER]was du \252ber die gepanzerte Kavallerie erfahren[ENTER]hast. "
gameforge.subquest_16._320_makequestbutton = "Gehe zum Hauptmann "
gameforge.subquest_16._330_npcChat = "Bericht \252ber die gepanzerte Kavallerie "
gameforge.subquest_16._340_sayTitle = "Hauptmann: "
gameforge.subquest_16._350_say = "Hast du etwas herausfinden k\246nnen? Erz\228hl![ENTER]\133[ENTER]Hm, das ist sehr interessant. Es steckt also[ENTER]nicht mehr dahinter als starke R\252stungen und[ENTER]hartes Training? Dann w\228re es machbar! Mit solch[ENTER]einer Armee k\246nnten die drei Reiche wieder[ENTER]vereint werden! "
gameforge.subquest_16._360_say = "Allerdings br\228uchte ich eine ganze Menge Geld.[ENTER]Und viele gute Schmiede. Und Rekruten, die[ENTER]freiwillig durch die H\246lle gehen, um die Besten[ENTER]der Besten zu werden![ENTER]Nein, nein. Schau mich nicht so an. Keine Sorge,[ENTER]du hast vorerst genug getan. "
gameforge.subquest_16._370_say = "Hier, nimm diese Belohnung und ruh dich aus.[ENTER]Wir sehen uns sp\228ter! "
gameforge.subquest_16._380_sayReward = "Du erh\228ltst 150.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 30.000 Yang.[ENTER]Du erh\228ltst Goldohrringe. "
gameforge.subquest_16._40_say = "Mit den von dir gesammelten Informationen[ENTER]k\246nnen wir vielleicht unsere eigene milit\228rische[ENTER]Schlagkraft st\228rken. Besuch zuerst den Musiker[ENTER]Yu-Hwan. Ich bin sicher, dass er Einiges \252ber[ENTER]Isups Kavallerie wei\223. "
gameforge.subquest_16._50_say = "Hm, wie du meinst. Bis sp\228ter dann! "
gameforge.subquest_16._60_say = "Werde ich jemals so eine Kavallerie bekommen?[ENTER]Sei vorsichtig. "
gameforge.subquest_16._70_say = "Danke, pass auf dich auf. "
gameforge.subquest_16._80_sayTitle = "Die gepanzerte Kavallerie "
gameforge.subquest_16._90_sayReward = "Der Hauptmann sucht nach Informationen \252ber die[ENTER]legend\228re Reiterei des Gr\252nderk\246nigs Isup.[ENTER]Der Musiker Yu-Hwan wei\223 vermutlich etwas[ENTER]dar\252ber. Geh und frage ihn. "
gameforge.subquest_17 = {}
gameforge.subquest_17._100_targetVid = "Rede mit der Gemischtwarenh\228ndlerin "
gameforge.subquest_17._10_targetVid = "Die Geschichte von Ariyoungs Ehemann "
gameforge.subquest_17._110_say = "Geh zur Gemischtwarenh\228ndlerin und erkundige[ENTER]dich nach Ariyoungs Ehemann. "
gameforge.subquest_17._120_npcChat = "Ariyoungs Ehemann "
gameforge.subquest_17._130_say = "Das ist eine traurige Geschichte. Sie wei\223 noch[ENTER]nicht, was mit ihrem Ehemann passiert ist? Er ist[ENTER]an einem Ort, von dem niemand zur\252ckkommt...[ENTER]Er war mit seinen Waren gerade auf dem Weg[ENTER]zum Dorf zur\252ck, als er von der Schwarzwindbande[ENTER]entf\252hrt und get\246tet wurde. "
gameforge.subquest_17._140_say = "Sie wird sehr verzweifelt sein, wenn du es ihr[ENTER]mitteilst. Die beiden haben sich sehr geliebt.[ENTER]Aber erfahren muss sie es auf jeden Fall. Die[ENTER]Ungewissheit bringt sie sonst um. "
gameforge.subquest_17._150_targetVid = "Die traurige Nachricht "
gameforge.subquest_17._160_sayTitle = "Ariyoung: "
gameforge.subquest_17._170_say = "Die Gemischtwarenh\228ndlerin hatte schlechte[ENTER]Neuigkeiten. Geh zu Ariyoung und berichte ihr vom[ENTER]Tod ihres Ehemanns. "
gameforge.subquest_17._180_npcChat = "Dein Ehemann ist tot... "
gameforge.subquest_17._190_say = "Was sagst du da?! Er\133 er wurde von der[ENTER]Schwarzwindbande get\246tet?[ENTER]Oh, nein... er ist tot... Ich wei\223 nicht, was ich[ENTER]ohne ihn tun soll! "
gameforge.subquest_17._200_say = "W\252rdest du mir den Leichnam meines Mannes[ENTER]hierher bringen, bitte? Dann k\246nnte ich mich von[ENTER]ihm verabschieden. Oder wenigstens ein Andenken?[ENTER]Die Goo-Pae von der Schwarzwindbande haben[ENTER]bestimmt etwas. Bitte, bring mir alles, was du[ENTER]finden kannst, solange es nur von ihm ist! "
gameforge.subquest_17._20_say = "Es ist viel Zeit vergangen, seit ich etwas von[ENTER]meinem Mann geh\246rt habe. Ich habe Angst um ihn.[ENTER]Hoffentlich ist ihm nichts passiert.[ENTER]Ich wei\223: Es ist unn\252tz, sich Sorgen zu machen,[ENTER]wenn man doch nichts \228ndern kann. Aber mein Herz[ENTER]schl\228gt so furchtbar stark. Ich kann mich einfach[ENTER]nicht beruhigen. "
gameforge.subquest_17._210_select = "Ja, ich helfe dir. "
gameforge.subquest_17._220_say = "Komm zu mir, wenn du es dir anders \252berlegt hast.[ENTER]Bitte... "
gameforge.subquest_17._230_say = "Du hast nichts gefunden? Danke trotzdem...[ENTER]Oh, ich Arme! "
gameforge.subquest_17._240_say = "Ich kann gar nicht sagen, wie dankbar ich dir[ENTER]bin. Ich bete f\252r dich. "
gameforge.subquest_17._250_sendLetter = "T\246te Goo-Paes "
gameforge.subquest_17._260_say = "Die Schwarzwindbande hat Ariyoungs Ehemann[ENTER]ermordet und ausgeraubt. T\246te so lange Goo-Paes,[ENTER]bis du ein Andenken an Ariyoungs Ehemann findest. "
gameforge.subquest_17._270_npcChat = "Wegen deines Ehemanns... "
gameforge.subquest_17._280_say = "Wie ist es gelaufen? Konntest du ein Andenken[ENTER]von meinem Ehemann finden?[ENTER]Er war mein Ein und Alles.[ENTER]Irgendetwas? "
gameforge.subquest_17._290_select = "Noch nicht. Ich suche weiter! "
gameforge.subquest_17._300_say = "Die Goo-Pae von der Schwarzwindbande sind keine[ENTER]einfachen Gegner.[ENTER]Ruh dich ein wenig aus.[ENTER]Und hab vielen Dank f\252r deine Hilfe. "
gameforge.subquest_17._30_say = "Ich hoffe, dass die Gemischtwarenh\228ndlerin etwas[ENTER]\252ber meinen Ehemann geh\246rt hat. Sie hat viele[ENTER]Kunden. Vielleicht hat ja jemand etwas erz\228hlt. "
gameforge.subquest_17._310_say = "Dann werde ich auf einen anderen Helden warten[ENTER]m\252ssen, der mir hilft.[ENTER]Auf Wiedersehen. "
gameforge.subquest_17._320_say = "Oh, das ist sehr freundlich.[ENTER]Bitte, bring mir ein Andenken meines Ehemannes. "
gameforge.subquest_17._330_sendLetter = "Ariyoungs Ehering "
gameforge.subquest_17._340_targetVid = "Gehe zu Ariyoung "
gameforge.subquest_17._350_sayTitle = "Gehe zu Ariyoung "
gameforge.subquest_17._360_say = "Du hast bei einem der get\246teten Goo-Paes den[ENTER]Ehering von Ariyoungs Ehemann gefunden. Ein[ENTER]besseres Andenken ist kaum vorstellbar.[ENTER]Bringe den Ring zu Ariyoung. "
gameforge.subquest_17._370_npcChat = "Ich habe diesen Ring gefunden. "
gameforge.subquest_17._380_say = "Dieser Ring... ist... mein Ehering! Vielen Dank![ENTER]Jetzt kann mein Ehemann in Frieden ruhen.[ENTER]Ich werde diesen Ring zusammen mit einem Brief[ENTER]von mir vergraben![ENTER]Von jetzt an werde ich allein leben.[ENTER]Zumindest habe ich seinen Ehering wieder![ENTER]Das ist ein wunderbares Gef\252hl. Ich danke dir,[ENTER]ich danke dir so sehr. "
gameforge.subquest_17._390_sendLetter = "Quest abgeschlossen! "
gameforge.subquest_17._400_say = "Deine Taten f\252r Ariyoung sprechen sich herum.[ENTER]Viele Leute w\252rdigen deine Hilfe. "
gameforge.subquest_17._40_select = "Ich gehe zu der H\228ndlerin. "
gameforge.subquest_17._410_sayReward = "Du erh\228ltst 300.000 Erfahrungspunkte. "
gameforge.subquest_17._420_sayReward = "Du erh\228ltst 10.000 Yang. "
gameforge.subquest_17._50_select = "Nein, keine Zeit. "
gameforge.subquest_17._60_say = "Willst du diese Quest f\252r immer aufgeben? "
gameforge.subquest_17._70_say = "Komm zu mir, wenn du es dir anders \252berlegt hast.[ENTER]Bitte... "
gameforge.subquest_17._80_say = "Du hast keine Zeit?[ENTER]Keine Zeit f\252r so eine einfache Aufgabe?[ENTER]Tja, dann... "
gameforge.subquest_17._90_say = "Vielen Dank. Du bist wirklich sehr nett.[ENTER]Oh, wo ist blo\223 mein Ehemann? "
gameforge.subquest_18 = {}
gameforge.subquest_18._100_say = "Such einen Mann, der Gedichte liest und zerlumpte[ENTER]Kleider tr\228gt, und sprich ihn an. "
gameforge.subquest_18._10_targetVid = "Wo hat er sich versteckt? "
gameforge.subquest_18._110_npcChat = "Wo ist dein Ehemann? "
gameforge.subquest_18._120_say = "Ich wei\223 nicht, wo er sich versteckt.[ENTER]Er verbirgt sich inzwischen so gut, dass es[ENTER]schwer ist, ihn zu finden. Sollte ich wirklich[ENTER]ein Gl\246ckchen um seinen Hals h\228ngen, wie es der[ENTER]Ladenbesitzer vorschlug? "
gameforge.subquest_18._130_npcChat = "Finde Soon! "
gameforge.subquest_18._140_say = "Du h\246rst ein wunderbares Gedicht. Gefangen von[ENTER]den Worten folgst du dem Klang der Stimme, bis du[ENTER]vor einem Mann in zerlumpten Kleidern stehst.[ENTER]Das muss Aranyos Ehemann sein![ENTER]Du willst dich gerade abwenden, um zu Aranyo[ENTER]zur\252ckzukehren, als er dich an der Schulter packt. "
gameforge.subquest_18._150_say = "Du bist nicht von hier.[ENTER]Hat dich meine Frau geschickt?[ENTER]Oh nein! Er wei\223, wer ich bin! Was soll ich nur[ENTER]sagen? "
gameforge.subquest_18._153_select = "Ich kam nur zuf\228llig vorbei. "
gameforge.subquest_18._157_select = "Nun, eigentlich... "
gameforge.subquest_18._160_say = "Aha. Wie nett, dich kennenzulernen.[ENTER]Wunderbares Wetter, nicht wahr?[ENTER]Hast du in letzter Zeit ein gutes Buch gelesen?[ENTER]Ich lese momentan das Buch von Oja.[ENTER]Kann ich nur empfehlen. "
gameforge.subquest_18._170_say = "Ich habe Recht, nicht wahr?[ENTER]Die Sticheleien meiner Frau sind inzwischen so[ENTER]schlimm, dass ich zu Hause einfach nicht mehr in[ENTER]Ruhe lesen kann. Sie versteht mich einfach nicht.[ENTER]Und jetzt schickt sie mir auch noch Leute[ENTER]hinterher... Du hast mich zwar hier entdeckt,[ENTER]aber ich kann jederzeit woanders hin gehen. Wie[ENTER]w\228re es, wenn du ihr nichts verraten w\252rdest?[ENTER]Daf\252r werde ich dir einen guten Ratschlag geben,[ENTER]der die Jagd betrifft. "
gameforge.subquest_18._180_sendLetter = "Zur\252ck zu Aranyo "
gameforge.subquest_18._190_say = "Kehre zu Aranyo zur\252ck und erz\228hle ihr,[ENTER]dass du Soon nicht finden konntest. "
gameforge.subquest_18._200_npcChat = "Soons Geheimnis. "
gameforge.subquest_18._20_sayTitle = "Aranyo: "
gameforge.subquest_18._210_say = "Du konntest ihn nicht finden?[ENTER]Ich habe sogar Fallen aufgestellt.[ENTER]Wo zum Teufel hat er sich versteckt?[ENTER]Ich bin so besch\228ftigt...[ENTER]Was f\252r ein elendes Schicksal. "
gameforge.subquest_18._220_sendLetter = "Zur\252ck zu Soon "
gameforge.subquest_18._230_say = "Gehe zur\252ck zu Soon und teile ihm mit, dass[ENTER]du erfolgreich warst. "
gameforge.subquest_18._240_npcChat = "Hier bin ich. "
gameforge.subquest_18._250_say = "Ging alles gut? Du hast mir das Leben[ENTER]gerettet! Nimm das hier, Abenteurer. Wie[ENTER]versprochen gebe ich dir eine Belohnung. "
gameforge.subquest_18._260_sayReward = "Du erh\228ltst 7.000 Erfahrungspunkte. "
gameforge.subquest_18._270_sayReward = "Du erh\228ltst 10.000 Yang. "
gameforge.subquest_18._280_say = "Kehre zu Aranyo zur\252ck und teile ihr Soons[ENTER]Aufenthaltsort mit. "
gameforge.subquest_18._290_npcChat = "Das Versteckspiel ist schwierig. "
gameforge.subquest_18._300_say = "Vielen Dank, dass du mich nicht verraten hast![ENTER]Es ist nicht leicht, sich vor seiner Frau zu[ENTER]verstecken. Ich m\246chte doch lediglich in Ruhe[ENTER]studieren... "
gameforge.subquest_18._30_say = "Mein Ehemann ist wirklich meine gr\246\223te Plage.[ENTER]Er bezeichnet sich selbst als einen Gelehrten![ENTER]W\228hrend wir um unser t\228gliches Brot k\228mpfen,[ENTER]liest er nur B\252cher.[ENTER]Hast du ihn gesehen? Wieso habe ich blo\223[ENTER]so einen B\252cherwurm geheiratet? "
gameforge.subquest_18._310_npcChat = "Soons Aufenthalt "
gameforge.subquest_18._320_say = "Du hast ihn entdeckt?[ENTER]Vielen, vielen Dank! Wenn er bemerkt, dass du ihn[ENTER]gefunden hast, k\246nnte er fliehen. Ich mache mich[ENTER]sofort auf den Weg. Dieses Mal erwische ich ihn![ENTER]Und du bekommst das hier, als Zeichen meiner[ENTER]Anerkennung.[ENTER]Na warte, B\252rschchen...! "
gameforge.subquest_18._33_select = "Ich helfe dir. "
gameforge.subquest_18._37_select = "Daf\252r habe ich keine Zeit. "
gameforge.subquest_18._40_say = "Willst du diese Aufgabe beenden? "
gameforge.subquest_18._50_say = "Gut. Vielleicht schaust du sp\228ter nach ihm. "
gameforge.subquest_18._60_say = "Vielleicht findest du ihn doch noch... "
gameforge.subquest_18._70_say = "Daf\252r w\228re ich sehr dankbar.[ENTER]Wenn du einen armen Schreiberling entdeckst, lass[ENTER]es mich wissen. Er ist vermutlich ohnehin der[ENTER]Einzige im Dorf. Vielleicht schreibt er ja gerade[ENTER]ein Gedicht und bleibt deswegen lieber f\252r sich.[ENTER]Wenn er erf\228hrt, dass ich ihn suche, k\246nnte er[ENTER]weglaufen. Also sei vorsichtig. "
gameforge.subquest_18._80_sendLetter = "Suche Soon "
gameforge.subquest_18._90_sayTitle = "Suche den B\252cherwurm "
gameforge.subquest_19 = {}
gameforge.subquest_19._100_sendLetter = "Wolfspelz besorgen "
gameforge.subquest_19._10_npcChat = "Suche einen Staubwedel "
gameforge.subquest_19._110_sayTitle = "Wolfspelz besorgen "
gameforge.subquest_19._120_sayReward = "Besorge einen Wolfspelz, damit die Alte Frau[ENTER]ihr Haus s\228ubern kann und nicht mehr husten muss.[ENTER]Du bekommst ihn von den Grauw\246lfen. "
gameforge.subquest_19._130_targetVid = "Zur\252ck zur Alten Frau "
gameforge.subquest_19._140_npcChat = "Wolfspelz abliefern "
gameforge.subquest_19._150_say = "Ein Wolfspelz, wie liebensw\252rdig...[ENTER]Oh, nein! Dieser Wolfpelz taugt leider nichts.[ENTER]Geh noch einmal zu den W\246lfen. Vielleicht findest[ENTER]du diesmal einen besseren. "
gameforge.subquest_19._160_say = "Ich brauche einen richtigen Staubwedel.[ENTER]Entschuldige bitte, aber damit kann ich nichts[ENTER]anfangen. "
gameforge.subquest_19._170_select = "Ich versuche es nochmal. "
gameforge.subquest_19._180_select = "Ich habe keine Lust mehr. "
gameforge.subquest_19._190_say = "Willst du diese Aufgabe wirklich beenden? "
gameforge.subquest_19._200_say = "Komm einfach sp\228ter noch einmal wieder. "
gameforge.subquest_19._20_say = "Hust! Hust! Diese Husterei laugt mich aus. Ich[ENTER]habe nichts zum Abstauben. Deswegen bleibt der[ENTER]ganze Staub im Haus liegen. Oh, warum habe ich[ENTER]keinen Staubwedel? Mein Sohn nahm ihn mit, um[ENTER]irgendeine Waffe zu bearbeiten. Mein eigen[ENTER]Fleisch und Blut bringt mich um! "
gameforge.subquest_19._210_say = "Ich wei\223, dass es schwer ist. Aber versuche es[ENTER]bitte trotzdem noch einmal. "
gameforge.subquest_19._220_say = "Danke, dass du dich darum k\252mmerst. "
gameforge.subquest_19._230_say = "Du bist der Abenteurer von neulich! Wie klingt[ENTER]mein Husten? Hust, hust![ENTER]Wie du h\246ren kannst, hat sich nicht viel[ENTER]ge\228ndert. Das Haus ist immer noch voller Staub.[ENTER]Oh? Du hast mir einen Wolfspelz gebracht? Was f\252r[ENTER]ein pr\228chtiges Exemplar, der ist genau richtig![ENTER]Du bist sehr edelm\252tig. Warte einen Moment, ich[ENTER]bin gleich wieder da... "
gameforge.subquest_19._240_say = "Eins, zwei, eins, zwei. Immer einen Fu\223 vor den[ENTER]anderen...[ENTER]So, da bin ich wieder. Vielen Dank! Endlich[ENTER]konnte ich mein Haus richtig s\228ubern. Ich habe[ENTER]dabei etwas gefunden, das ich dir gerne geben[ENTER]m\246chte. Ich wei\223 nicht, ob es etwas wert ist,[ENTER]aber vielleicht kannst du es gebrauchen.[ENTER]Vielen Dank noch einmal. Lebe wohl! "
gameforge.subquest_19._250_sendLetter = "Ein verstaubtes Etwas "
gameforge.subquest_19._260_say = "Dein Lohn besteht aus einem gro\223en, unhandlichen[ENTER]Gegenstand, der unter seiner jahrzehntealten[ENTER]Staubschicht nicht zu identifizieren ist.[ENTER]Neugierig entstaubst du ihn... "
gameforge.subquest_19._270_say = "Es ist eine alte R\252stung von hoher Qualit\228t,[ENTER]das Werk eines guten Schmieds. Welch ein[ENTER]Gl\252ck! "
gameforge.subquest_19._280_say = "Es ist eine R\252stung. Alt, aber noch zu[ENTER]gebrauchen. Immerhin etwas! "
gameforge.subquest_19._290_say = "Es handelt sich um eine R\252stung. Deiner Hoffnung[ENTER]zum Trotz stellt sie sich jedoch als so gut wie[ENTER]wertlos heraus. "
gameforge.subquest_19._300_sayReward = "Du erh\228ltst 15.000 Erfahrungspunkte. "
gameforge.subquest_19._30_select = "Ich besorg dir einen. "
gameforge.subquest_19._40_say = "Ist das alles verstaubt![ENTER]Ich brauche unbedingt einen richtigen[ENTER]Staubwedel.[ENTER]Willst du mir helfen? "
gameforge.subquest_19._50_say = "Es ist schon eine ganze Weile her, aber ich[ENTER]glaube, dass mein Ehemann - m\246ge er in Frieden[ENTER]ruhen - ihn aus einem Wolfspelz fertigte.[ENTER]Hust! Hust![ENTER]K\246nntest du einer armen, alten Frau vielleicht[ENTER]einen Wolfspelz besorgen? Am besten von einem[ENTER]Grauwolf. Du w\252rdest mir damit sehr helfen. "
gameforge.subquest_19._60_say = "Willst du wirklich abbrechen? "
gameforge.subquest_19._70_say = "Schade. Ich hatte gehofft, du k\246nntest mir[ENTER]helfen. Vielleicht \252berlegst du dir es noch[ENTER]einmal. Dann komm einfach wieder. "
gameforge.subquest_19._80_say = "Was f\252r eine Belohnung kann man schon von[ENTER]so einer armen, alten Frau erwarten? "
gameforge.subquest_19._90_say = "Es ist nicht einfach, so einen Wolfspelz zu[ENTER]bekommen. Aber ich werde es versuchen. Denn ich[ENTER]will ja mal ein gro\223er Held werden! "
gameforge.subquest_20 = {}
gameforge.subquest_20._100_say = "M\246chtest du die Suche aufgeben? "
gameforge.subquest_20._10_targetVid = "Hilf Ah-Yu! "
gameforge.subquest_20._110_say = "Du kannst ruhig gehen.[ENTER]Komm aber wieder, wenn du Zeit hast. "
gameforge.subquest_20._120_say = "Du bist ein Angsthase.[ENTER]Wahrscheinlich w\252rdest du sowieso wegrennen,[ENTER]wenn du die Wilden triffst. Geh jetzt! "
gameforge.subquest_20._130_say = "Danke, dass du mir hilfst.[ENTER]Es sind 3 Speere. "
gameforge.subquest_20._140_sendLetter = "Die Speere "
gameforge.subquest_20._150_targetVid = "Ah-Yu "
gameforge.subquest_20._160_sayTitle = "Die drei Speere "
gameforge.subquest_20._170_say = "Du hast alle 3 Speere des Ehemanns von Ah-Yu[ENTER]gefunden. Du solltest zur\252ck zu Ah-Yu gehen. "
gameforge.subquest_20._180_sayTitle = "Suche nach den Speeren! "
gameforge.subquest_20._190_say = "Wilder Infanterist, Wilder Ergebener, Wilder[ENTER]Bogensch\252tze und Wilder General: Sie alle[ENTER]besitzen Speere.[ENTER]Suche bei ihnen nach den Speeren des Ehemanns. "
gameforge.subquest_20._200_sayReward = "Du musst die 3 Speere finden[ENTER]und sie Ah-Yu zur\252ckbringen.[ENTER](Anzahl der Speere: %s ) "
gameforge.subquest_20._20_npcChat = "Andenken an den Ehemann "
gameforge.subquest_20._210_npcChat = "Wo finde ich die Speere? "
gameforge.subquest_20._220_say = "Wahrscheinlich haben die Wilden die Speere meines[ENTER]Mannes.[ENTER]Wer wei\223, hoffentlich haben sie sie nicht[ENTER]verkauft. Es sind sehr gute Speere.[ENTER]Setzt du die Suche fort? "
gameforge.subquest_20._230_select = "Ja, ich suche weiter. "
gameforge.subquest_20._240_say = "Du bist ein Feigling![ENTER]Da kann man wohl nichts machen.[ENTER]Ich muss selber suchen gehen.[ENTER]M\246chtest du die Suche wirklich aufgeben? "
gameforge.subquest_20._250_select = "Ja, ich gebe auf. "
gameforge.subquest_20._260_say = "Ich w\252rde es selber tun, aber das Baby braucht[ENTER]mich. Komm wieder, wenn du alle Speere hast! "
gameforge.subquest_20._270_say = "Du hast die Suche nach den Speeren von Ah-Yus[ENTER]Ehemann aufgegeben. "
gameforge.subquest_20._280_say = "Hab vielen Dank. Du wirst sie bestimmt bald[ENTER]finden! "
gameforge.subquest_20._290_npcChat = "Die Speere des Ehemanns zur\252ckgeben "
gameforge.subquest_20._300_sayTitle = "Ah-Yu: "
gameforge.subquest_20._30_say = "Oh, bitte weine nicht mehr, mein Liebling. Mama[ENTER]hat auch Sorgen. Wenn du immer[ENTER]weiter weinst, werden wir uns beide nicht[ENTER]beruhigen k\246nnen! Bitte, h\246r auf. "
gameforge.subquest_20._310_say = "Du hast einen gefunden, das ist gut![ENTER]Aber kannst du bitte auch die \252brigen beiden[ENTER]suchen? Sie geh\246ren doch zusammen.[ENTER]Au\223erdem sieht es viel sch\246ner aus, wenn sie[ENTER]gemeinsam an der Wand h\228ngen...[ENTER]Ich danke dir. "
gameforge.subquest_20._320_select = "Ich versuche es noch einmal. "
gameforge.subquest_20._330_select = "Ich gebe auf. "
gameforge.subquest_20._340_say = "Du hast die Suche nach den Speeren von Ah-Yus[ENTER]Ehemann aufgegeben. "
gameforge.subquest_20._350_say = "Vielen Dank, dass du nicht aufgibst! "
gameforge.subquest_20._360_say = "Oh, da sind sie ja! Ich bin sehr froh, vielen[ENTER]Dank. Hier. Das ist zwar nicht viel Yang, aber[ENTER]nimm es ruhig. "
gameforge.subquest_20._370_sayReward = "Du erh\228ltst 300.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 20.000 Yang. "
gameforge.subquest_20._40_say = "So kenne ich dich gar nicht. Du bist doch sonst[ENTER]immer so fr\246hlich! Ist etwas passiert? "
gameforge.subquest_20._50_say = "Fr\252her hat mein Mann immer f\252r mich gesorgt und[ENTER]aufgepasst, dass mir nichts zust\246\223t. Dann ist er[ENTER]im Krieg gestorben.[ENTER]Das einzige, was ich jetzt noch von ihm habe,[ENTER]sind unser Baby und seine Speere. "
gameforge.subquest_20._60_say = "Aber heute hat jemand die Speere gestohlen,[ENTER]w\228hrend ich arbeiten war. Meine Nachbarin sagt,[ENTER]es seien Wilde M\228nner gewesen. Die Speere waren[ENTER]das letzte Andenken an meinen Ehemann. Und wegen[ENTER]des Babys kann ich nicht suchen gehen. "
gameforge.subquest_20._70_say = "Kannst du mir die Speere wiederbringen? Du[ENTER]findest sie bestimmt bei den Wilden. "
gameforge.subquest_20._80_select = "Ich werde sie suchen. "
gameforge.subquest_20._90_select = "Ich habe keine Zeit. "
gameforge.subquest_21 = {}
gameforge.subquest_21._100_say = "Ich danke dir, mein Freund![ENTER]Hoffentlich hast du Erfolg. "
gameforge.subquest_21._10_targetVid = "Balso? "
gameforge.subquest_21._110_sendLetter = "Heilmittel f\252r Balso "
gameforge.subquest_21._120_targetVid = "Gehe zu Balso "
gameforge.subquest_21._130_sayReward = "Du hast die Medizin f\252r Balso, der sich bei den[ENTER]Plagem\228nnern mit einer unbekannten Krankheit[ENTER]infiziert hat, gefunden. Bring sie zu Balso. "
gameforge.subquest_21._140_sayTitle = "Hol die Medizin "
gameforge.subquest_21._150_say = "Auf seiner langen Flucht hat sich Balso mit einer[ENTER]unbekannten Krankheit angesteckt.[ENTER]Hole ihm eine Medizin von den Plagenm\228nnern am[ENTER]Berg Sohan. "
gameforge.subquest_21._160_npcChat = "Ich habe deine Medizin! "
gameforge.subquest_21._170_say = "Oh, danke! Das Leben eines Fl\252chtlings[ENTER]ist hart. Besonders, wenn man dann[ENTER]auch noch krank wird. Jetzt kann ich[ENTER]mich zum Gl\252ck wieder erholen. Ich danke dir[ENTER]vielmals. "
gameforge.subquest_21._180_sayTitle = "Belohnung: "
gameforge.subquest_21._190_sayReward = "Du erh\228ltst 1.900.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 30.000 Yang. "
gameforge.subquest_21._20_npcChat = "Es juckt so sehr... "
gameforge.subquest_21._30_sayTitle = "Verr\228ter Balso: "
gameforge.subquest_21._40_say = "Darf ich dich um einen Gefallen bitten? Wie du[ENTER]wahrscheinlich schon erfahren hast, bin ich als[ENTER]ein Verr\228ter bekannt. Es ist nun sehr schwierig[ENTER]f\252r mich, mein Leben zu f\252hren. Ich hatte auch[ENTER]gute Zeiten, in denen ich gut lebte. Aber jetzt[ENTER]ist es genau das Gegenteil. Nun bin ich immer auf[ENTER]der Flucht. Dabei komme ich mit vielen[ENTER]Krankheiten in Kontakt. "
gameforge.subquest_21._50_say = "Vor ein paar Tagen war ich am Berg Sohan[ENTER]unterwegs und geriet zwischen einige[ENTER]Plagenm\228nner. Zum Gl\252ck konnte ich fliehen,[ENTER]aber ich scheine mir bei der Ber\252hrung ihrer[ENTER]fauligen Haut irgendeine Krankheit zugezogen zu[ENTER]haben. Kannst du mir helfen, Medizin zu bekommen?[ENTER]Ich vermute, dass sie welche bei sich tragen.[ENTER]Ich mache das nur ungern, aber ich bitte dich[ENTER]sehr, mir zu helfen. "
gameforge.subquest_21._60_select = "Ja, ich helfe dir. "
gameforge.subquest_21._70_say = "M\246chtest du mit der Suche aufh\246ren? "
gameforge.subquest_21._80_say = "Tja, das passiert mir immer wieder. Um mich[ENTER]herum gibt es nur Leute, die mich nicht m\246gen.[ENTER]Falls du es dir anders \252berlegst, dann komm[ENTER]sp\228ter nochmal wieder. "
gameforge.subquest_21._90_say = "Verschwinde! Und lass dich hier nie wieder[ENTER]blicken! Immer dasselbe... "
gameforge.subquest_22 = {}
gameforge.subquest_22._100_say = "Danke. Ich vertraue dir! Bring mir die Axt[ENTER]schnell zur\252ck. "
gameforge.subquest_22._10_targetVid = "Die Goldaxt von Deokbae "
gameforge.subquest_22._110_targetVid = "Besuche Deokbae "
gameforge.subquest_22._120_sayTitle = "Goldene Axt gefunden "
gameforge.subquest_22._130_say = "Du hast die Goldaxt von den Wilden zur\252ckgeholt.[ENTER]Bring sie Deokbae. "
gameforge.subquest_22._140_sayTitle = "Suche nach der goldenen Axt "
gameforge.subquest_22._150_say = "Hole Deokbaes geliebte Goldaxt von den Wilden[ENTER]Gener\228len zur\252ck. "
gameforge.subquest_22._160_npcChat = "Ich habe deine goldene Axt gefunden! "
gameforge.subquest_22._170_sayTitle = "Holzf\228ller Deokbae: "
gameforge.subquest_22._180_say = "Ohne deine Hilfe h\228tte ich die Axt[ENTER]nie zur\252ckbekommen. Danke vielmals.[ENTER]Ich werde in Zukunft besser aufpassen und sie[ENTER]immer bei mir behalten. "
gameforge.subquest_22._190_sayReward = "Du erh\228ltst 400.000 Erfahrungspunkte. "
gameforge.subquest_22._200_sayReward = "Du erh\228ltst 30.000 Yang. "
gameforge.subquest_22._20_npcChat = "Wegen deiner Goldaxt... "
gameforge.subquest_22._30_sayTitle = "Holzf\228ller Deokbae: "
gameforge.subquest_22._40_say = "Oh nein, oh nein! Ich habe die Axt verloren.[ENTER]Vielleicht wei\223t du, welche Axt ich meine?[ENTER]Es ist die goldene Axt, die ich vom Schmied[ENTER]bekommen habe. Ein Wilder hat sie mir gestohlen. "
gameforge.subquest_22._50_say = "Wenn der Schmied dies herausfindet, wird er sehr[ENTER]zornig sein und meine \196xte nicht mehr reparieren.[ENTER]Au\223erdem war es eine wirklich gute Axt. Kannst du[ENTER]sie zur\252ckbringen? "
gameforge.subquest_22._60_select = "Absagen "
gameforge.subquest_22._70_say = "M\246chtest du mit der Suche aufh\246ren? "
gameforge.subquest_22._80_say = "Oh, wenn du Zeit hast, komm einfach vorbei. "
gameforge.subquest_22._90_say = "Zu schwer? Da kann man wohl nichts machen.[ENTER]Pass auf dich auf, diese Wilden sind \252berall! "
gameforge.subquest_23 = {}
gameforge.subquest_23._100_sendLetter = "Such Yu-Hwan "
gameforge.subquest_23._10_targetVid = "Bitte suche meinen \228lteren Bruder! "
gameforge.subquest_23._110_targetVid = "Gehe zu Yu-Hwan "
gameforge.subquest_23._120_say = "Der \228ltere Bruder von Mirine ist wieder[ENTER]verschwunden. Er hat vor einiger Zeit einen Brief[ENTER]geschrieben, seitdem aber nichts mehr von sich[ENTER]h\246ren lassen. Geh zu Yu-Hwan und frage ihn, ob[ENTER]er etwas \252ber Mirines Bruder wei\223. "
gameforge.subquest_23._130_npcChat = "Hast du Mirines Bruder gesehen? "
gameforge.subquest_23._140_say = "Mirines Bruder? Nein, ich kann dir leider nicht[ENTER]weiterhelfen. Ich hatte auch schon l\228ngere Zeit[ENTER]keinen Kontakt mehr mit ihm. Ich kann mich kaum[ENTER]erinnern, wann ich ihn das letzte Mal gesehen[ENTER]habe. Ich mache mir auch Sorgen. Vielleicht ist[ENTER]etwas passiert? Frag doch mal den J\228ger[ENTER]Yang-Shin. Er kommt viel herum und ist ihm[ENTER]vielleicht begegnet. "
gameforge.subquest_23._150_sendLetter = "Suche Yang-Shin "
gameforge.subquest_23._160_targetVid = "Gehe zum J\228ger Yang-Shin "
gameforge.subquest_23._170_say = "Der J\228ger Yang-Shin kommt viel herum. Vielleicht[ENTER]hat er Mirines \228lteren Bruder gesehen. "
gameforge.subquest_23._180_npcChat = "Hast du Mirines Bruder gesehen? "
gameforge.subquest_23._190_say = "Mirines \228lterer Bruder? Als ich ihn das letzte[ENTER]Mal getroffen habe, war er unterwegs zum Tal von[ENTER]Seungryong, um dort Heilkr\228uter zu sammeln. Ich[ENTER]war etwas verwundert, weil es dort sehr[ENTER]gef\228hrlich ist, habe mir aber nichts weiter dabei[ENTER]gedacht. "
gameforge.subquest_23._200_say = "Ich h\228tte ihn aufhalten sollen. Wenn er sich[ENTER]bisher nicht gemeldet hat, dann ist ihm bestimmt[ENTER]etwas zugesto\223en.[ENTER]Am Besten gehst du gleich ins Tal von Seungryong[ENTER]und suchst nach ihm. "
gameforge.subquest_23._20_npcChat = "Warum weinst du? "
gameforge.subquest_23._210_select = "Suche beginnen "
gameforge.subquest_23._220_say = "Die Suche aufgeben? "
gameforge.subquest_23._230_say = "Mirine war wirklich sehr traurig.[ENTER]Ich werde sp\228ter wiederkommen. "
gameforge.subquest_23._240_say = "Wenn ein \228lterer Bruder sich l\228nger nicht[ENTER]meldet, dann muss das noch lange nicht bedeuten,[ENTER]dass ihm etwas zugesto\223en ist.[ENTER]Du musst nicht in dieses gef\228hrliche Tal gehen,[ENTER]blo\223 weil ein kleines M\228dchen dich darum bittet. "
gameforge.subquest_23._250_say = "Der Auftrag ist wohl doch nicht so geringf\252gig,[ENTER]wie es zun\228chst aussah. Das Tal von Seungryong[ENTER]ist ein gef\228hrlicher Ort. Aber ich habe es[ENTER]versprochen, also mache ich auch weiter. "
gameforge.subquest_23._260_sendLetter = "Der verschollene Bruder "
gameforge.subquest_23._270_targetVid = "Suche nach dem \228lteren Bruder im Tal von[ENTER]Seungryong "
gameforge.subquest_23._280_sayTitle = "Suche Mirines Bruder "
gameforge.subquest_23._290_say = "Mirines \228lterer Bruder sucht Heilkr\228uter im Tal[ENTER]von Seungryong. Geh dorthin und sieh nach, ob es[ENTER]ihm gut geht. Der Teleporter hilft dir, wenn du[ENTER]eine Abk\252rzung suchst. "
gameforge.subquest_23._300_npcChat = "Die Leiche! "
gameforge.subquest_23._30_say = "Du hast mir einmal einen Brief von meinem Bruder[ENTER]gebracht, nicht wahr? Da war ich dir sehr[ENTER]dankbar. Seitdem habe ich keinen Kontakt mehr zu[ENTER]ihm. Mein Bruder ist immer noch unterwegs. Er[ENTER]sucht nach Heilkr\228utern f\252r mich. "
gameforge.subquest_23._310_say = "Hier liegt ein toter Mann. Er war jung und d\252nn[ENTER]und hat wohl Ginseng gesammelt. Ich f\252rchte, es[ENTER]ist der gesuchte \228ltere Bruder von Mirine.[ENTER]Die Leiche tr\228gt eine Kette mit einem Anh\228nger[ENTER]bei sich. Ich nehme sie mit und bringe sie[ENTER]Mirine. "
gameforge.subquest_23._320_sendLetter = "Gehe zu Mirine "
gameforge.subquest_23._330_sayTitle = "Die traurige Nachricht "
gameforge.subquest_23._340_say = "Du hast an einer Leiche im Tal von Seungryong[ENTER]einen Anh\228nger gefunden, auf dem Mirines Name[ENTER]eingraviert ist.[ENTER]Geh zu Mirine und gib ihr Kette und Anh\228nger. "
gameforge.subquest_23._350_npcChat = "Kennst du diese Kette? "
gameforge.subquest_23._360_say = "Oh, diese Kette... die hat mein Bruder immer[ENTER]getragen. Ich habe eine \228hnliche Kette. Wir haben[ENTER]die Ketten immer getragen, damit wir uns[ENTER]aneinander erinnern und wieder zueinander finden.[ENTER]Aber... mein Bruder ist nun nicht mehr da...[ENTER]Nur seine Kette ist zur\252ckgekommen... "
gameforge.subquest_23._370_say = "Mein armer Bruder...[ENTER]Der Krieg ist schuld daran. Mein Bruder hat[ENTER]Heilkr\228uter verkauft, das war das Einzige, das[ENTER]Geld einbrachte. So konnten wir uns ern\228hren.[ENTER]Mein Bruder hat immer flei\223ig gearbeitet, damit[ENTER]ich genug zu Essen bekomme. Jetzt ist er tot.[ENTER]Wegen mir... "
gameforge.subquest_23._380_say = "Danke, dass du mir die Kette gebracht hast. Jetzt[ENTER]wei\223 ich wenigstens, was geschehen ist. H\228ttest[ENTER]du mir nicht geholfen, h\228tte ich das nie[ENTER]erfahren. "
gameforge.subquest_23._390_say = "Den Anh\228nger meines \228lteren Bruders bewahre ich[ENTER]sorgf\228ltig auf und die Kette gebe ich dir zum[ENTER]Dank. Sie wird dir sicherlich hilfreich sein.[ENTER]Danke f\252r die Hilfe.[ENTER]Bestimmt ist er jetzt im Himmel, meinst du nicht[ENTER]auch?  "
gameforge.subquest_23._400_sayReward = "Du erh\228ltst 600.000 Erfahrungspunkte.[ENTER]Du erh\228ltst 35.000 Yang. "
gameforge.subquest_23._40_say = "Aber ich sorge mich schon um ihn,[ENTER]weil ich keinen Kontakt mehr zu ihm habe.[ENTER]Entschuldige, aber k\246nntest du[ENTER]bitte noch einmal meinen Bruder suchen?[ENTER]Vielleicht wei\223 Yu-Hwan etwas. "
gameforge.subquest_23._50_select = "Absagen "
gameforge.subquest_23._60_say = "M\246chtest du die Suche aufgeben? "
gameforge.subquest_23._70_say = "Oh...[ENTER]Ich warte hier.[ENTER]Vielleicht sp\228ter? Bitte? "
gameforge.subquest_23._80_say = "Ich hab keine Zeit![ENTER]Viel Gl\252ck f\252r deinen Bruder. "
gameforge.subquest_23._90_say = "Ein weinendes M\228dchen im Stich lassen w\228re[ENTER]nicht sehr nett. Und der Auftrag wird auch nicht[ENTER]viel Zeit beanspruchen. Dann mal los! "
gameforge.subquest_24 = {}
gameforge.subquest_24._100_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_24._10_targetVid = "Yu-Rangs Reiskuchen "
gameforge.subquest_24._110_say = "Wenn du sp\228ter Zeit hast, komm bitte wieder.[ENTER]Ich wei\223 nicht, wie wir ohne den[ENTER]Reiskuchenverkauf \252berleben sollen. "
gameforge.subquest_24._120_say = "Immer dreht sich alles nur um die reichen Leute,[ENTER]die Yang verschwenden als w\228re es Wasser.[ENTER]W\228hrend wir nicht wissen, was wir morgen auf den[ENTER]Tisch bringen sollen! Geh weg! "
gameforge.subquest_24._130_say = "Danke. Du bist sehr freundlich.[ENTER]Ich warte hier, bis du wieder da bist. "
gameforge.subquest_24._140_sendLetter = "Der gestohlene Reiskuchen "
gameforge.subquest_24._150_say = "Hole Yu-Rangs verlorenen Reiskuchen von den[ENTER]Spinnen in der W\252ste. Wenn du nicht schnell genug[ENTER]bist, essen die Spinnen den Reiskuchen oder er[ENTER]vertrocknet in der Sonne. Beeile dich. "
gameforge.subquest_24._160_sayReward = "T\246te Babyspinnen in der Yongbi-W\252ste. "
gameforge.subquest_24._170_npcChat = "Wegen deines verlorenen Reiskuchens... "
gameforge.subquest_24._180_say = "Was ist? Haben die Spinnen den Reiskuchen[ENTER]aufgegessen? Oh nein! Oder ist er vertrocknet?![ENTER]Bitte sag nicht, dass alles verloren ist! "
gameforge.subquest_24._190_select = "Nein, alles ist in Ordnung. "
gameforge.subquest_24._200_select = "Ich gebe auf. "
gameforge.subquest_24._20_npcChat = "Dein gestohlener Reiskuchen... "
gameforge.subquest_24._210_say = "Kannst du es nicht vielleicht doch tun? Der[ENTER]Reiskuchen ist sehr wichtig f\252r mich. Ich bitte[ENTER]dich.[ENTER]Willst du die Quest, Yu-Rangs Reiskuchen[ENTER]in der W\252ste zu finden, aufgeben? "
gameforge.subquest_24._220_select = "Ich versuche es nochmal. "
gameforge.subquest_24._230_select = "Tut mir leid, es ist zu schwer. "
gameforge.subquest_24._240_say = "Ich kann es nicht glauben. Wer hilft uns jetzt? "
gameforge.subquest_24._250_say = "Sei doch so nett![ENTER]Bitte hilf mir! "
gameforge.subquest_24._260_say = "Du suchst also weiter? Danke![ENTER]Bitte finde den Reiskuchen so schnell wie[ENTER]m\246glich! "
gameforge.subquest_24._270_say = "Nein, es ist zu sp\228t, auch wenn du ihn bekommst.[ENTER]Er ist l\228ngst vertrocknet.[ENTER]Ich kann ihn nicht mehr[ENTER]verkaufen.  "
gameforge.subquest_24._280_say = "Du siehst auf den Boden und findest ein paar[ENTER]Kuchenst\252cke,die die Spinnen zur\252cklie\223en.[ENTER]Leider sind sie alle vertrocknet. "
gameforge.subquest_24._290_sayReward = "Du hast zuviel Zeit vergeudet bei der Suche nach[ENTER]den Reiskuchen. Sie sind vertrocknet.[ENTER]Du hast versagt. "
gameforge.subquest_24._300_sendLetter = "Zur\252ck zu Yu-Rang "
gameforge.subquest_24._30_say = "Hallo, wie geht es deiner Mutter? "
gameforge.subquest_24._310_targetVid = "Geh zu Yu-Rang zur\252ck "
gameforge.subquest_24._320_say = "Du hast Yu-Rangs Reiskuchen rechtzeitig vor den[ENTER]Spinnen gerettet. Bringe ihn zu ihr. "
gameforge.subquest_24._330_npcChat = "Du hast Gl\252ck. Hier ist dein Reiskuchen. "
gameforge.subquest_24._340_say = "Du bist wirklich gro\223artig! Ich wei\223 nicht, was[ENTER]ich sagen soll. Nun kann ich ihn morgen auf dem[ENTER]Markt verkaufen.[ENTER]Vielen Dank! "
gameforge.subquest_24._350_sayReward = "Du erh\228ltst 900.000 Erfahrungspunkte. "
gameforge.subquest_24._360_sayReward = "Du erh\228ltst 25.000 Yang. "
gameforge.subquest_24._40_say = "Oh, es geht ihr besser.[ENTER]Danke der Nachfrage. "
gameforge.subquest_24._50_say = "Du siehst aus, als h\228ttest du \196rger.[ENTER]Was ist los? "
gameforge.subquest_24._60_say = "Ich verkaufe hier t\228glich Reiskuchen, aber heute[ENTER]passierte etwas Schreckliches. Riesige Spinnen[ENTER]tauchten auf und stahlen ihn mir. Ich hatte gro\223e[ENTER]Angst und wehrte mich nicht. Jetzt habe ich[ENTER]keinen Reiskuchen mehr, den ich verkaufen kann.[ENTER]Aber wie soll ich nun \252berleben? Meine Familie[ENTER]hat keine anderen Einahmen... "
gameforge.subquest_24._70_select = "Ich finde ihn f\252r dich. "
gameforge.subquest_24._80_select = "Leider habe ich keine Zeit. "
gameforge.subquest_24._90_sayTitle = "Frage: "
gameforge.subquest_25 = {}
gameforge.subquest_25._100_npcChat = "Womit kann man dich erfreuen? "
gameforge.subquest_25._10_targetVid = "Huahn-So "
gameforge.subquest_25._110_say = "Nun, seit ich meinen Mann vor kurzem im Krieg[ENTER]verloren habe, f\252hle ich mich sehr einsam.[ENTER]Hm? Wodurch ich mich besser f\252hlen w\252rde?[ENTER]Mein Ehemann hat mir fr\252her immer kleine Blumen[ENTER]gebracht. "
gameforge.subquest_25._120_say = "Es waren Blumen, die recht weit entfernt von[ENTER]unserem Dorf wachsen. Obwohl es gef\228hrlich war,[ENTER]hat er mir diese Blumen geholt.[ENTER]Ich kann diese Blumen nun nicht mehr sehen, da[ENTER]mein Mann tot ist. Doch an Tagen wie diesen[ENTER]vermisse ich ihn sehr. Oh, was hab ich dir da[ENTER]gesagt? Das war v\246llig unpassend.[ENTER]Bitte vergiss einfach, was ich gerade gesagt[ENTER]habe. "
gameforge.subquest_25._130_qSetTitle = "Zur\252ck zu Huahn-So "
gameforge.subquest_25._140_makequestbutton = "Zur\252ck zu Huahn-So "
gameforge.subquest_25._150_targetVid = "Huahn-So  "
gameforge.subquest_25._160_say = "Ariyoung vermisst die Blumen, die ihr Mann ihr[ENTER]immer brachte. Geh zu Huahn-So und berichte ihm[ENTER]davon. "
gameforge.subquest_25._170_npcChat = "Das Geschenk f\252r Ariyoung... "
gameforge.subquest_25._180_say = "Also, was mag Ariyoung? Du hast ihr nichts \252ber[ENTER]mich verraten, oder?[ENTER]Hmm, sie mag eine Blume, die ihr Ehemann ihr[ENTER]geholt hat? Das ist ziemlich weit weg vom Dorf.[ENTER]Es wird f\252r mich sehr schwer werden, dorthin zu[ENTER]kommen. Und dort k\246nnten Monster sein, Tiger[ENTER]oder Schlimmeres! "
gameforge.subquest_25._190_say = "Genau! Warum hilfst du mir nicht aus?[ENTER]Warum holst nicht einfach die Blumen f\252r mich?[ENTER]Das w\228re f\252r uns beide von Vorteil.[ENTER]Was? Das geh\246rt nicht zur Abmachung?[ENTER]Komm schon, siehst du nicht, wie sehr ich mich[ENTER]um ihre Liebe bem\252he? Hilf mir einfach![ENTER]Ich werde dich reichlich mit Yang belohnen! "
gameforge.subquest_25._200_select = "Verweigern "
gameforge.subquest_25._20_npcChat = "Oh meine liebste Ariyoung "
gameforge.subquest_25._210_say = "M\246chtest du die Quest f\252r immer aufgeben? "
gameforge.subquest_25._220_say = "Verdammt, wie soll ich denn diese Blumen sonst[ENTER]besorgen? Bitte komm zur\252ck, wenn du deine[ENTER]Meinung ge\228ndert hast. "
gameforge.subquest_25._230_say = "Hast du niemals geliebt? Verstehst du nicht, was[ENTER]ich f\252r Ariyoung empfinde? Oh Ariyoung... "
gameforge.subquest_25._240_say = "Vielen Dank![ENTER]Bitte bring mir diese Blumen. "
gameforge.subquest_25._250_qSetTitle = "Hol die Blumen "
gameforge.subquest_25._260_targetVid = "Blumen "
gameforge.subquest_25._270_sayTitle = "Blumen f\252r Ariyoung "
gameforge.subquest_25._280_say = "Damit Huahn-So Ariyoung sagen kann, was er[ENTER]empfindet, musst du ihm besondere Blumen[ENTER]besorgen. Du findest sie in einer Ecke der Karte[ENTER]des ersten Dorfes. "
gameforge.subquest_25._290_npcChat = "Ich habe keine Blumen gefunden. "
gameforge.subquest_25._300_say = "Oh Mist...[ENTER]Ich wollte ihr meine Gef\252hle mitteilen.[ENTER]Es ist so schwer, ihre Liebe zu bekommen.[ENTER]Meine liebste Ariyoung... "
gameforge.subquest_25._30_say = "Ist dir die Dame Ariyoung bekannt? Nun, sie[ENTER]ist... nein, sie war verheiratet. Ihr Mann starb[ENTER]vor einigen Jahren, seitdem lebt sie allein. Eine[ENTER]eindrucksvolle Pers\246nlichkeit und noch immer[ENTER]eine sch\246ne Frau. Damals heiratete sie sehr[ENTER]jung, ich kam zu sp\228t... "
gameforge.subquest_25._310_select = "Ich versuche es weiter. "
gameforge.subquest_25._320_select = "Ich h\246re auf. "
gameforge.subquest_25._330_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_25._340_say = "Oh... Falls du dich anders entscheiden solltest:[ENTER]Ich werde hier warten. Bitte hilf mir! "
gameforge.subquest_25._350_say = "Wird meine Liebe so enden?[ENTER]Ariyoung.... "
gameforge.subquest_25._360_say = "Ich danke dir. Du musst auch verliebt sein, wenn[ENTER]du wei\223t, was ich f\252r Ariyoung empfinde. "
gameforge.subquest_25._370_npcChat = "Ariyoungs Lieblingsblumen "
gameforge.subquest_25._380_say = "Diese Blumen sehen aus wie die, die Ariyoung[ENTER]beschrieben hat. Ich nehme welche mit. "
gameforge.subquest_25._390_qSetTitle = "Zur\252ck zu Huahn-So "
gameforge.subquest_25._400_say = "Ich habe Ariyoungs Lieblingsblumen gefunden und[ENTER]ein paar davon gepfl\252ckt. Ich sollte sie Huahn-So[ENTER]bringen, damit er Ariyoung seine Liebe gestehen[ENTER]kann. "
gameforge.subquest_25._40_say = "Aber ihr Mann verstarb im Krieg. Deswegen wurde[ENTER]sie auch fr\252h eine junge Witwe.[ENTER]Ich m\246chte, dass sie wei\223, wie ich f\252hle![ENTER]Mir ist klar, dass das eine ma\223lose Bitte ist,[ENTER]aber... kannst du mir helfen? "
gameforge.subquest_25._410_npcChat = "Hier sind Ariyoungs Lieblingsblumen. "
gameforge.subquest_25._420_say = "Oh, das sind die Blumen? Jetzt kann ich Ariyoung[ENTER]endlich sagen, was ich f\252hle! Meinst du, es ist[ENTER]zu fr\252h daf\252r? Ach, es spielt keine Rolle, ob[ENTER]es zu fr\252h ist. Ich muss es ihr sagen, sonst[ENTER]platze ich. Hier ist deine Belohnung, und vielen[ENTER]Dank! "
gameforge.subquest_25._430_sayReward = "Du erh\228ltst 400.000 Erfahrungspunkte. "
gameforge.subquest_25._440_sayReward = "Du erh\228ltst 12.000 Yang. "
gameforge.subquest_25._50_say = "Meinst du, sie mag einen stattlichen Mann? Oder[ENTER]sch\246ne Kleidung? Zuallererst muss ich wissen,[ENTER]was sie mag. Dann kann ich vielleicht mit ihr[ENTER]reden. Kannst du das bitte f\252r mich[ENTER]herausfinden? Aber erz\228hle ihr auf keinen Fall[ENTER]etwas von mir! Ich flehe dich an. Ich werde mich[ENTER]auch erkenntlich zeigen. "
gameforge.subquest_25._60_qSetTitle = "Geh zu Ariyoung "
gameforge.subquest_25._70_makequestbutton = "Geh zu Ariyoung "
gameforge.subquest_25._80_targetVid = "Auf zu Ariyoung "
gameforge.subquest_25._90_say = "Huahn-So liebt die verwitwete Ariyoung.[ENTER]Damit Huahn-So Ariyoung sagen kann, was er f\252hlt,[ENTER]musst du herausfinden, was sie mag.[ENTER]Also frag Ariyoung, was sie mag. Aber achte[ENTER]darauf, ihr nicht zuviel zu verraten! "
gameforge.subquest_26 = {}
gameforge.subquest_26._100_say = "Dein Pech. Du verpasst die Chance deines Lebens. "
gameforge.subquest_26._10_targetVid = "Gehe zum Lagerverwalter. "
gameforge.subquest_26._110_say = "Sehr gut! Ich wusste doch, dass dich das[ENTER]interessiert. Wenn du welche kriegst, dann komm[ENTER]wieder her und teile sie mit mir! "
gameforge.subquest_26._120_sendLetter = "Gehe zu Octavio "
gameforge.subquest_26._130_targetVid = "Ok-gu "
gameforge.subquest_26._140_sayTitle = "Gehe zu Octavio "
gameforge.subquest_26._150_say = "Der Lagerverwalter hat dir einen guten Tipp[ENTER]gegeben: Froschschenkelsuppe eignet sich[ENTER]hervorragend als Mittel gegen Kraftlosigkeit und[ENTER]m\252de Knochen. Frage Octavio, ob er diese Suppe[ENTER]herstellen kann. "
gameforge.subquest_26._160_npcChat = "Froschschenkelsuppe? "
gameforge.subquest_26._170_say = "Froschschenkelsuppe... Stimmt, die habe ich mal[ENTER]gemacht. Aber das ist Vergangenheit. Damals hatte[ENTER]ich noch keine Angst vor all diesen Monstern. So[ENTER]konnte ich die Froschschenkel leicht besorgen. "
gameforge.subquest_26._180_say = "Aber jetzt... Jetzt bin ich daf\252r zu alt und zu[ENTER]m\252de. Mit der Suppe k\246nnte ich meine Energie[ENTER]zur\252ckgewinnen. Aber Fr\246sche sind nicht einfach[ENTER]zu t\246ten. Wenn du mir Froschschenkel f\252r die[ENTER]Suppe bringst, werde ich die beste[ENTER]Froschschenkelsuppe der Welt f\252r uns kochen! "
gameforge.subquest_26._190_select = "Sicher, ich mache es. "
gameforge.subquest_26._200_select = "Ich kann das nicht. "
gameforge.subquest_26._20_npcChat = "Wie geht es dir? "
gameforge.subquest_26._210_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_26._220_say = "Du bist besch\228ftigt? Wenn du deine Meinung[ENTER]\228nderst, komm wieder. "
gameforge.subquest_26._230_say = "Meine Suppe ist nicht sehr bekannt.[ENTER]W\252rdest du sie kennen, dann w\252rdest du es[ENTER]machen. Also gut, auf Wiedersehen. "
gameforge.subquest_26._240_say = "Dann beeil dich! Ich bereite schon alles f\252r die[ENTER]Suppe vor. "
gameforge.subquest_26._250_sendLetter = "Froschschenkel erhalten "
gameforge.subquest_26._260_targetVid = "Octavio "
gameforge.subquest_26._270_sendLetter = "Froschschenkel besorgen "
gameforge.subquest_26._280_say = "Du hast einen riesigen Froschschenkel besorgt.[ENTER]Gehe zur\252ck zu Octavio. "
gameforge.subquest_26._290_sayTitle = "T\246te Baumfrosch-Anf\252hrer "
gameforge.subquest_26._300_say = "Octavio ben\246tigt Froschschenkel f\252r seine[ENTER]Froschschenkelsuppe. Du erh\228ltst sie, indem du[ENTER]Baumfrosch-Anf\252hrer im Hwang-Tempel jagst. "
gameforge.subquest_26._30_sayTitle = "Lagerverwalter: "
gameforge.subquest_26._310_npcChat = "Ich kann das jetzt nicht. "
gameforge.subquest_26._320_say = "Was ist los mit dir?[ENTER]Als ich so jung war wie du, besorgte ich 10[ENTER]Froschschenkel an einem Tag! "
gameforge.subquest_26._330_select = "Nochmal versuchen "
gameforge.subquest_26._340_say = "Bist du schon m\252de? Warum machst du nicht eine[ENTER]Pause und versuchst es sp\228ter noch einmal? "
gameforge.subquest_26._350_say = "Ich h\228tte die Froschschenkelsuppe gut gebrauchen[ENTER]k\246nnen. Aber daraus wird wohl nichts. Schade. Bis[ENTER]dann! "
gameforge.subquest_26._360_say = "Dann steh hier nicht rum, sondern geh! Das Wasser[ENTER]kocht schon und alles ist bereit! "
gameforge.subquest_26._370_targetVid = "Gehe zu Octavio "
gameforge.subquest_26._380_say = "Na, das nenn ich mal einen Froschschenkel! Zu[ENTER]meiner Zeit waren die etwas kleiner. Aber der[ENTER]hier schmeckt bestimmt auch. Warte einen[ENTER]Moment... Das riecht schon ganz gut. Noch eine[ENTER]Prise Salz... So! Hier ist deine Portion. Hahaha,[ENTER]jetzt habe ich wieder genug Kraft f\252r eine ganze[ENTER]Woche Arbeit! "
gameforge.subquest_26._390_say = "Eine Bitte noch: Erz\228hl niemandem davon, dass ich[ENTER]diese Suppe gekocht habe. Vor allem nicht dem[ENTER]Lagerverwalter. Er redet gerne viel und wenn sich[ENTER]die Eigenschaften der Suppe herumsprechen, bleibt[ENTER]mir keine ruhige Minute mehr, weil jeder einen[ENTER]Schluck haben will. "
gameforge.subquest_26._400_sayReward = "Du erh\228ltst 5.000.000 Erfahrungspunkte. "
gameforge.subquest_26._40_say = "Mir geht es nicht sehr gut in letzter Zeit. Mein[ENTER]K\246rper ist nicht mehr das, was er fr\252her war. Als[ENTER]ich jung war, konnte ich bis tief in die Nacht[ENTER]arbeiten, jeden Tag in der Woche. Und noch dabei[ENTER]Alkohol trinken. Aber jetzt kostet es mich gro\223e[ENTER]M\252he, morgens aufzustehen. Ich br\228uchte eine gute[ENTER]Portion Froschschenkelsuppe, um wieder genug[ENTER]Energie zu haben. "
gameforge.subquest_26._410_sayReward = "Du erh\228ltst 50.000 Yang. "
gameforge.subquest_26._50_say = "Du wei\223t nicht, was Froschschenkelsuppe ist?[ENTER]Wenn du eine Sch\252ssel davon trinkst, bist du[ENTER]sofort hellwach und voller Energie. Dann kannst[ENTER]du eine ganze Woche durcharbeiten, ohne m\252de zu[ENTER]werden! Octavio machte diese Suppe immer. Aber[ENTER]aus irgendeinem Grund h\246rte er vor kurzem damit[ENTER]auf. "
gameforge.subquest_26._60_select = "Ich gehe zu Octavio. "
gameforge.subquest_26._70_select = "Ich bin besch\228ftigt. "
gameforge.subquest_26._80_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_26._90_say = "Gut, wenn du besch\228ftigt bist, dann komm sp\228ter[ENTER]wieder, wenn du Zeit hast. "
gameforge.subquest_27 = {}
gameforge.subquest_27._100_say = "Er sollte sich sch\228men, sich einen Vater zu[ENTER]nennen! Wenn ich ihn finde, dann gnade ihm Gott![ENTER]Denk blo\223 nicht, ich \252bertreibe. Frag ruhig die[ENTER]anderen Leute im Dorf, die sehen das ganz[ENTER]genauso. "
gameforge.subquest_27._10_targetVid = "Soon "
gameforge.subquest_27._110_targetVid = "Gemischtwarenh\228ndlerin "
gameforge.subquest_27._120_makequestbutton = "Gehe zur Gemischtwarenh\228ndlerin "
gameforge.subquest_27._130_say = "Vielleicht wei\223 die Gemischtwarenh\228ndlerin, was[ENTER]Soon gerade treibt. Gehe zu ihr und frage, ob sie[ENTER]etwas von Soon geh\246rt hat. "
gameforge.subquest_27._140_npcChat = "Was ist mit Soon? "
gameforge.subquest_27._150_say = "Gestern kam er hierher und fragte nach dem[ENTER]Geheimen Tempelbuch. Er hatte kein Yang dabei,[ENTER]deshalb schaute er es sich nur an.[ENTER]Es muss ihm schon sehr wichtig sein, wenn er[ENTER]sogar seine Familie vernachl\228ssigt. Warum[ENTER]interessiert es ihn nur so sehr? "
gameforge.subquest_27._160_sayTitle = "Gemischtwarenh\228ndlerin: "
gameforge.subquest_27._170_say = "Es tut mir leid f\252r Aranyo. Sie heiratete Soon[ENTER]nicht, um jeden Tag und jede Nacht zu arbeiten.[ENTER]Sie hat bestimmt nicht damit gerechnet, dass sie[ENTER]nun die Familie ern\228hren muss.[ENTER]Du solltest noch einmal mit ihm sprechen. Wer[ENTER]wei\223, vielleicht sieht er es ein. "
gameforge.subquest_27._180_makequestbutton = "Gehe zu Soon "
gameforge.subquest_27._190_qSetTitle = "Gehe zu Soon "
gameforge.subquest_27._200_targetVid = "Soon schon wieder "
gameforge.subquest_27._20_npcChat = "Die Freude am Lesen "
gameforge.subquest_27._210_say = "Gehe zu Soon[ENTER]Gehe zu Soon und frag ihn nach dem Tempelbuch. "
gameforge.subquest_27._220_npcChat = "Was ist das geheime Tempelbuch? "
gameforge.subquest_27._230_say = "Du wei\223t, dass ich jedes Buch der Welt gelesen[ENTER]habe. Doch vor Kurzem h\246rte ich von einem[ENTER]geheimen Buch. Die Ger\252chte besagen, dass dieses[ENTER]Buch die Geheimnisse des Dunklen Tempels enth\228lt.[ENTER]Darin wird erkl\228rt, wie man ein Heiliger wird. "
gameforge.subquest_27._240_say = "Ich muss dieses Buch unbedingt lesen. Kannst du[ENTER]es f\252r mich besorgen?[ENTER]Wenn du das tust, gebe ich dir auch etwas daf\252r.[ENTER]Selbst wenn ich mein Haus verkaufen m\252sste. "
gameforge.subquest_27._250_select = "Ich tue es! "
gameforge.subquest_27._260_select = "Ich kann leider nicht. "
gameforge.subquest_27._270_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_27._280_say = "Komm schon, willst du mir nicht helfen?[ENTER]Wenn nicht jetzt, dann komm sp\228ter wieder![ENTER]Ich warte auf dich. "
gameforge.subquest_27._290_say = "Du hilfst mir wirklich nicht? Du brauchst wohl[ENTER]Urlaub, oder? Das Dokument ist mir sehr wichtig.[ENTER]Was mach ich nur? Verdammt. "
gameforge.subquest_27._300_say = "Danke, ich warte auf dich. "
gameforge.subquest_27._30_say = "Liest du auch so gerne wie ich?[ENTER]W\246rter, die zu S\228tzen werden, um dann ein Buch zu[ENTER]bilden. Herrlich![ENTER]Und die Freude, eines zu schreiben, damit es[ENTER]wiederum andere Leute lesen k\246nnen! "
gameforge.subquest_27._310_makequestbutton = "Du hast das Tempelbuch gefunden. "
gameforge.subquest_27._320_qSetTitle = "Du hast das Tempelbuch gefunden. Gehe zur\252ck zu[ENTER]Soon. "
gameforge.subquest_27._330_targetVid = "Gehe zur\252ck zu Soon. "
gameforge.subquest_27._340_makequestbutton = "Besiege die Dunklen Fanatiker "
gameforge.subquest_27._350_sayTitle = "Du hast die Dunklen Fanatiker get\246tet. "
gameforge.subquest_27._360_say = "Bringe das Geheime Tempelbuch zu Soon. "
gameforge.subquest_27._370_say = "Soon hat gro\223es Interesse an dem Geheimen[ENTER]Tempelbuch. Wenn du die Dunklen Fanatiker t\246test,[ENTER]findest du vielleicht das geheime Buch. "
gameforge.subquest_27._380_npcChat = "Das geheime Tempelbuch "
gameforge.subquest_27._390_say = "Oh, das ist es! Vielen Dank![ENTER]Hier ist deine Belohnung.[ENTER]Und jetzt lass mich allein, ich muss lesen! "
gameforge.subquest_27._400_sayReward = "Du erh\228ltst 850.000 Erfahrungspunkte. "
gameforge.subquest_27._40_say = "Hier, zwischen diesen Buchdeckeln, pulsiert das[ENTER]Leben! Hier wohnen junges Wissen und alte[ENTER]Weisheit! Wie trostlos w\228re mein Leben ohne[ENTER]B\252cher... Nur leider... meine Frau versteht das[ENTER]nicht. Kannst du sie vielleicht \252berzeugen? "
gameforge.subquest_27._410_sayReward = "Du erh\228ltst 20.000 Yang. "
gameforge.subquest_27._420_say = "Hey...[ENTER]Hast du es noch nicht erhalten?[ENTER]Wenn du eine Aufgabe annimmst, solltest[ENTER]du sie auch zu Ende bringen.[ENTER]Jetzt beende die Aufgabe! "
gameforge.subquest_27._430_say = "Die Dunklen Fanatiker sind nicht zu[ENTER]untersch\228tzen. Versuche es doch einfach sp\228ter[ENTER]noch einmal. "
gameforge.subquest_27._440_say = "Nun, dann muss ich wohl jemand anderen um Hilfe[ENTER]bitten. Leb wohl. "
gameforge.subquest_27._450_say = "Danke, ich warte auf dich.[ENTER]Ich kann es kaum erwarten, es in[ENTER]meiner Hand zu halten und zu lesen. "
gameforge.subquest_27._50_makequestbutton = "Geh zu Aranyo "
gameforge.subquest_27._60_sayTitle = "Geh zu Aranyo "
gameforge.subquest_27._70_say = "Geh zu Aranyo und frag sie nach ihrem Mann. "
gameforge.subquest_27._80_npcChat = "Warum bist du so aufgebracht? "
gameforge.subquest_27._90_say = "Aufgebracht? Ich platze gleich vor Wut![ENTER]Geht mein Mann arbeiten? Nein. Bringt er Yang[ENTER]nach Hause? Nein. Statt dessen versteckt er sich[ENTER]irgendwo und schiebt seine Nase zwischen[ENTER]Buchdeckel! Hat man sowas schon geh\246rt?! Er[ENTER]liest! Gibt ein Buch uns vielleicht Kleidung?[ENTER]Gibt es uns Essen? "
gameforge.subquest_30 = {}
gameforge.subquest_30._100_sendLetter = "Erz f\252r den Schmied "
gameforge.subquest_30._10_npcChat = "Du brauchst Erz? "
gameforge.subquest_30._110_targetVid = "Schmied "
gameforge.subquest_30._120_sayTitle = "Zur\252ck zum Schmied "
gameforge.subquest_30._130_say = "Du hast das Erz, das der Schmied zum Fertigen[ENTER]der neuen Waffen braucht, gesammelt. Du solltest[ENTER]es zu ihm bringen. "
gameforge.subquest_30._140_sayTitle = "Besorge Erz f\252r neue Waffen "
gameforge.subquest_30._150_say = "Der Schmied ben\246tigt Erz f\252r die Herstellung[ENTER]einer neuen Waffenart. Bringe ihm jeweils 100[ENTER]Golderz, Silbererz und Ebenholzerz.[ENTER]Erzvorkommen sind \252berall auf der Karte verteilt[ENTER]und k\246nnen mit Bergbau bearbeitet werden. Du[ENTER]kannst aber auch mit anderen Spielern handeln und[ENTER]ihnen Erz abkaufen. "
gameforge.subquest_30._160_npcChat = "Ich habe Erz f\252r dich gesammelt. "
gameforge.subquest_30._170_say = "Das reicht nicht. Ich brauche die ganzen 100[ENTER]Golderz, Silbererz und Ebenholzerz! "
gameforge.subquest_30._180_select = "Weitersuchen "
gameforge.subquest_30._190_select = "Aufgeben "
gameforge.subquest_30._200_say = "Du willst wirklich f\252r immer aufgeben? "
gameforge.subquest_30._20_say = "Hey, du! Ja, genau dich meine ich! Du bist nun[ENTER]kein Anf\228nger mehr. Und warum? Weil ich dir[ENTER]komplizierte Aufgaben gestellt habe! Es war alles[ENTER]nur f\252r dein Wohl, hehehe. Aber jetzt bitte ich[ENTER]dich um einen wirklichen Gefallen. "
gameforge.subquest_30._210_say = "Es ist schwer, Erz zu bekommen, nicht wahr?[ENTER]Doch das Gl\252ck kommt erst mit der harten Arbeit.[ENTER]Wie w\228re es mit einer kurzen Pause, bevor du es[ENTER]erneut versuchst? "
gameforge.subquest_30._220_say = "Schade. Es war so eine brilliante Idee.[ENTER]Naja, was soll's. Bis bald! "
gameforge.subquest_30._230_say = "Gib dir ein wenig M\252he, dann hast du bald alles[ENTER]zusammen. Viel Gl\252ck! "
gameforge.subquest_30._240_say = "Oh, du hast tats\228chlich schon alles beisammen![ENTER]Hahaha! Ich sp\252re, dass es klappen wird! Warte[ENTER]einen Moment, es wird nicht lange dauern. Und los[ENTER]geht's! "
gameforge.subquest_30._250_say = "So, es ist fertig. Meine Begabung \252berrascht mich[ENTER]immer wieder. Hier ist deine Waffe. Sie ist neu,[ENTER]also gehe behutsam damit um! "
gameforge.subquest_30._260_sayReward = "Du erh\228ltst 200.000 Erfahrungspunkte. "
gameforge.subquest_30._270_sayReward = "Du erh\228ltst 20.000 Yang. "
gameforge.subquest_30._280_sayReward = "Du erh\228ltst ein Silberschwert+3. "
gameforge.subquest_30._290_sayReward = "Du erh\228ltst einen Aquatischen F\228cher+3. "
gameforge.subquest_30._30_say = "Ich m\246chte versuchen, eine neue Waffe zu[ENTER]schmieden, aber die Materialien sind schwer zu[ENTER]beschaffen. K\246nntest du das f\252r mich erledigen?[ENTER]Als Belohnung werde ich dir das erste fertige[ENTER]Exemplar \252berlassen. "
gameforge.subquest_30._40_say = "Ich ben\246tige je 100 St\252ck Golderz, Silbererz und[ENTER]Ebenholzerz. Das klingt nach mehr, als es ist.[ENTER]Mit Bergbau kannst du viele Rohstoffe auf einmal[ENTER]besorgen, so dass du sie mit Leichtigkeit[ENTER]zusammenbekommen solltest.[ENTER]Wenn es doch zu schwierig f\252r dich ist, dann[ENTER]kannst du sie auch von jemandem erhandeln. Ganz[ENTER]wie du willst. Ich w\252nsche dir viel Erfolg! "
gameforge.subquest_30._50_select = "Ablehnen "
gameforge.subquest_30._60_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_30._70_say = "Es eilt nicht. Also komm bitte zur\252ck,[ENTER]falls du deine Meinung \228ndern solltest. "
gameforge.subquest_30._80_say = "Schade. Es war so eine brilliante Idee.[ENTER]Naja, was soll's. Bis bald! "
gameforge.subquest_30._90_say = "Oh! Du wirst es tun?[ENTER]Du bist ein guter Freund! "
gameforge.subquest_31 = {}
gameforge.subquest_31._100_sendLetter = "Erz f\252r den Schmied "
gameforge.subquest_31._10_targetVid = "Gehe zum Schmied "
gameforge.subquest_31._110_sayTitle = "Zur\252ck zum Schmied "
gameforge.subquest_31._120_sayReward = "Du hast das Erz, das der Schmied zum Fertigen[ENTER]der neuen R\252stungen braucht, gesammelt. Du[ENTER]solltest es zu ihm bringen. "
gameforge.subquest_31._130_sayTitle = "Besorge Erz f\252r neue R\252stungen "
gameforge.subquest_31._140_sayReward = "Der Schmied ben\246tigt Erz f\252r die Herstellung[ENTER]einer neuen R\252stungsart. Bringe ihm jeweils 100[ENTER]Kupfererz, Ebenholzerz und Perlenst\252cke.[ENTER]Erzvorkommen sind \252berall auf der Karte verteilt[ENTER]und k\246nnen mit Bergbau bearbeitet werden. Du[ENTER]kannst aber auch mit anderen Spielern handeln und[ENTER]ihnen Erz abkaufen. "
gameforge.subquest_31._150_npcChat = "Ich habe Erz f\252r dich gesammelt. "
gameforge.subquest_31._160_say = "Hmm, da fehlen aber noch Materialien. Ich sagte,[ENTER]ich brauche je 100 St\252ck Kupfererz, Ebenholzerz[ENTER]und Perlen! "
gameforge.subquest_31._170_select = "Weitersuchen "
gameforge.subquest_31._180_select = "Aufgeben "
gameforge.subquest_31._190_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_31._200_say = "Ist es zu schwer? Es ist nat\252rlich nicht nur[ENTER]Gl\252ck, sondern auch harte Arbeit. Warum versuchst[ENTER]du es nicht einfach sp\228ter nochmal. "
gameforge.subquest_31._20_npcChat = "Du brauchst noch mehr Erz? "
gameforge.subquest_31._210_say = "Soviel zu meinem Plan f\252r eine neuartige[ENTER]R\252stung. Diese Idee h\228tte unser gesamtes[ENTER]Zeitalter ver\228ndern k\246nnen![ENTER]Es ist jammerschade... "
gameforge.subquest_31._220_say = "Sei stark! Ich wei\223, dass du es schaffen kannst! "
gameforge.subquest_31._230_say = "Hervorragend. Du bist wirklich gut im Beschaffen[ENTER]von Materialien. Jetzt pass auf![ENTER]Hier... und hier... und noch schnell abgek\252hlt...[ENTER]So, das ist f\252r dich, als Lohn f\252r deine M\252hen.[ENTER]Bis bald! "
gameforge.subquest_31._240_sayReward = "Du erh\228ltst 200.000 Erfahrungspunkte. "
gameforge.subquest_31._250_sayReward = "Du erh\228ltst 20.000 Yang. "
gameforge.subquest_31._260_sayReward = "Du erh\228ltst einen L\246wenplattenpanzer+3. "
gameforge.subquest_31._270_sayReward = "Du erh\228ltst einen Roten Ameisenanzug+3. "
gameforge.subquest_31._280_sayReward = "Du erh\228ltst einen Geistplattenpanzer+3. "
gameforge.subquest_31._290_sayReward = "Du erh\228ltst eine Kleidung der Liebe+3. "
gameforge.subquest_31._30_say = "Hallo, hast du eine Minute Zeit f\252r mich?[ENTER]Ich wei\223 es sehr zu sch\228tzen, dass du mir[ENTER]geholfen hast, eine neue Waffe herzustellen.[ENTER]Jetzt m\246chte ich gerne noch einmal deine Hilfe in[ENTER]Anspruch nehmen. Diesmal m\246chte ich eine neue[ENTER]R\252stung herstellen. Nachdem ich eine gute Waffe[ENTER]hergestellt habe, ist es klar, dass ich jetzt[ENTER]auch eine gute R\252stung brauche. "
gameforge.subquest_31._40_say = "Nat\252rlich brauche ich wieder Materialien f\252r die[ENTER]Herstellung. Kannst du sie mir besorgen? Du[ENTER]bekommst auch wieder die erste fertige R\252stung[ENTER]daf\252r. Diesmal brauche ich je 100 St\252ck[ENTER]Kupfererz, Ebenholzerz und Perlen. Du solltest[ENTER]das ja schon kennen. Viel Erfolg! "
gameforge.subquest_31._50_select = "Annehmen "
gameforge.subquest_31._60_say = "M\246chtest du die Quest f\252r immer aufgeben? "
gameforge.subquest_31._70_say = "Warum z\246gerst du dann? Komm wieder, wenn du[ENTER]bereit bist, dich im Bergbau zu bet\228tigen. "
gameforge.subquest_31._80_say = "Das bisschen Erz ist doch nun wirklich nicht[ENTER]zuviel verlangt. Na, wie du meinst. Verschwinde! "
gameforge.subquest_31._90_say = "Du hilfst mir wieder? Du bist ein guter Freund.[ENTER]Und keine Sorge: Die erste R\252stung geh\246rt dir! "
gameforge.subquest_32 = {}
gameforge.subquest_32._100_sendLetter = "H\228ndleranfrage "
gameforge.subquest_32._10_targetVid = "Auswahl der H\228ndler "
gameforge.subquest_32._110_targetVid = "Gehe zu Ah-Yu "
gameforge.subquest_32._120_targetVid = "Gehe zur Gemischtwarenh\228ndlerin "
gameforge.subquest_32._130_sayReward = "Materialien f\252r den H\228ndler "
gameforge.subquest_32._140_sayReward = "Der Fahrende H\228ndler braucht einige Materialen[ENTER]f\252r eine Halskette. Besorge ihm 100 Backenz\228hne[ENTER]von Stolzen Ork-Zauberern, ein Schmuckst\252ck von[ENTER]der Gemischtwarenh\228ndlerin und N\228hgarn von[ENTER]Ariyoung. "
gameforge.subquest_32._150_npcChat = "Ich brauche N\228hgarn. "
gameforge.subquest_32._160_say = "N\228hgarn herstellen ist keine gro\223e Sache.[ENTER]Allerdings kann ich dann meine andere Arbeit[ENTER]nicht machen. Ich habe heute Ah-Yus zerrissene[ENTER]Kleider gen\228ht und wollte sie ihr gerade[ENTER]bringen... "
gameforge.subquest_32._170_say = "Was h\228ltst du davon: Du bringst Ah-Yu ihre[ENTER]Kleidung zur\252ck und ich stelle inzwischen N\228hgarn[ENTER]f\252r dich her. Einverstanden? "
gameforge.subquest_32._180_say = "Willst du f\252r immer aufgeben? "
gameforge.subquest_32._190_say = "Der Weg ist wirklich nicht sehr weit. Warum[ENTER]z\246gerst du noch? Komm wieder her, wenn du[ENTER]bereit bist. "
gameforge.subquest_32._200_say = "Oh, ich hatte so gehofft, dass du Zeit hast. Dann[ENTER]muss ich wohl selber laufen. Leb wohl! "
gameforge.subquest_32._20_npcChat = "Wegen der Halsketten... "
gameforge.subquest_32._210_say = "Herrlich, ich danke dir vielmals! Gr\252\223e Ah-Yu von[ENTER]mir und pass auf, dass du ihre Kleidung unterwegs[ENTER]nicht zerdr\252ckst! Ich warte hier auf dich. "
gameforge.subquest_32._220_sayTitle = "Ariyoung: "
gameforge.subquest_32._230_say = "Ich werde dein N\228hgarn fertig haben, wenn du aus[ENTER]dem Nachbardorf zur\252ckkommst. Du hast doch nicht[ENTER]vergessen, Ah-Yu ihre Kleider zu bringen, oder?[ENTER]Das w\252rde sie mir \252belnehmen. "
gameforge.subquest_32._240_say = "Ist Ah-Yu mit der Kleidung zufrieden? Dann ist es[ENTER]ein Vergn\252gen, so hart zu arbeiten. Hier ist[ENTER]dein N\228hgarn. Es ist sehr kr\228ftig und kann f\252r[ENTER]vieles benutzt werden. Bis bald! "
gameforge.subquest_32._250_say = "Ich habe dir bereits N\228hgarn gegeben. Hast du es[ENTER]verloren? "
gameforge.subquest_32._260_npcChat = "Ariyoung schickt dir diese Kleider. "
gameforge.subquest_32._270_sayTitle = "Ah-Yu: "
gameforge.subquest_32._280_say = "Oh, wie sch\246n. Das ging wirklich schnell. Gute[ENTER]Freundschaften soll man pflegen, nicht wahr? Wir[ENTER]helfen uns oft gegenseitig...[ENTER]Danke, dass du mir die Kleidung gebracht hast.[ENTER]Bitte \252bermittle Ariyoung meine Gr\252\223e. "
gameforge.subquest_32._290_npcChat = "Ich brauche ein Schmuckst\252ck. "
gameforge.subquest_32._300_say = "Du suchst Schmuck?[ENTER]Ich kann dir ein Schmuckst\252ck geben, wenn du mir[ENTER]ein wenig hilfst. Zurzeit arbeite ich an einer[ENTER]speziellen Medizin gegen Schmerzen, aber eine[ENTER]Zutat fehlt mir: die Leber eines Tigers. Die sind[ENTER]sehr schwierig zu bekommen. Ich brauche 100[ENTER]St\252ck. "
gameforge.subquest_32._30_say = "Wir Fahrenden H\228ndler haben es im Krieg nicht[ENTER]leicht. Es fehlt zwar \252berall an Waren, aber der[ENTER]Bedarf wechselt so schnell, dass ich nie wei\223, ob[ENTER]ich gerade das Richtige im Angebot habe. Ganz zu[ENTER]schweigen von den langen Wegen durch die Wildnis,[ENTER]wo all diese Monster unachtsamen Wanderern[ENTER]auflauern. Hast du nicht Lust, dir ein paar Yang[ENTER]zu verdienen? Ich k\246nnte Hilfe gebrauchen. "
gameforge.subquest_32._310_say = "Au\223erdem brauche ich noch bestimmte Kr\228uter mit[ENTER]heilender Wirkung, aber die bekommst du auch von[ENTER]den Tigern. Sie w\228lzen sich gerne darin, weil sie[ENTER]den Geruch lieben. F\252r die Kr\228uter und die[ENTER]Tigerlebern gebe ich dir dann ein Schmuckst\252ck. "
gameforge.subquest_32._320_say = "Jage daf\252r Tiger oder Wei\223e Tiger. "
gameforge.subquest_32._330_say = "Was sagst du dazu? Kommen wir ins Gesch\228ft? "
gameforge.subquest_32._340_say = "Ist meine Aufgabe zu schwer f\252r dich? Das kann[ENTER]ich mir nicht vorstellen! Besuch mich wieder,[ENTER]wenn du es dir anders \252berlegst. "
gameforge.subquest_32._350_say = "Du l\228ufst also f\252r den H\228ndler den weiten Weg[ENTER]hierher und gibst dann auf? Wie du willst...[ENTER]Sch\246nen Tag noch. "
gameforge.subquest_32._360_say = "Sehr gut. Das wird uns beiden weiterhelfen, nicht[ENTER]wahr? Danke und viel Gl\252ck! "
gameforge.subquest_32._370_npcChat = "Bekomme ich jetzt das Schmuckst\252ck? "
gameforge.subquest_32._380_say = "Lass mich nachsehen... 100 Tigerlebern und die[ENTER]Heilkr\228uter, es ist alles da. Ich danke dir![ENTER]Bitte sehr, dieses Schmuckst\252ck hast du dir[ENTER]ehrlich verdient. Bis bald! "
gameforge.subquest_32._390_qSetTitle = "Zur\252ck zum Fahrenden H\228ndler "
gameforge.subquest_32._400_targetVid = "Zur\252ck zum Fahrenden H\228ndler "
gameforge.subquest_32._40_say = "Im Moment sind Halsketten sehr gefragt, die aus[ENTER]den Backenz\228hnen von Orks bestehen. Orkz\228hne sind[ENTER]gro\223 und hart und eignen sich gut f\252r die[ENTER]Herstellung verschiedener Schmuckst\252cke. Die[ENTER]Backenz\228hne der Ork-Zauberer gelten zudem bei den[ENTER]Soldaten als Talismane. K\246nntest du mir solche[ENTER]Z\228hne besorgen? 100 St\252ck sollten f\252rs Erste[ENTER]reichen. "
gameforge.subquest_32._410_sayReward = "Zur\252ck zum Fahrenden H\228ndler "
gameforge.subquest_32._420_sayReward = "Du hast endlich alle Materialien f\252r die[ENTER]Halskette zusammen. Bringe sie dem Fahrenden[ENTER]H\228ndler. "
gameforge.subquest_32._430_npcChat = "Ich habe alle Materialien. "
gameforge.subquest_32._440_sayTitle = "Fahrender H\228ndler: "
gameforge.subquest_32._450_say = "Hast du alle Materialien bekommen? Lass sehen...[ENTER]Tats\228chlich, es ist alles da. Dank deiner Hilfe[ENTER]kann ich mein Angebot erweitern, das ist gut.[ENTER]Hier ist dein Anteil. Viel Spa\223 damit.[ENTER]Kommt heran, Leute! Hier ist f\252r jeden etwas[ENTER]dabei! "
gameforge.subquest_32._460_sayReward = "Du erh\228ltst 1.100.000 Erfahrungspunkte. "
gameforge.subquest_32._470_sayReward = "Du erh\228ltst ein Goldarmband, eine Goldhalskette[ENTER]und Goldohrringe. "
gameforge.subquest_32._480_say = "Hmm, tut mir leid, aber da fehlt aber noch etwas.[ENTER]Unvollst\228ndige Lieferungen kann ich nicht[ENTER]gebrauchen. Versuchst du es weiter? "
gameforge.subquest_32._490_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_32._500_say = "Danke, dass du nicht so leicht aufgibst. Das[ENTER]Gl\252ck ist denen hold, die sich bem\252hen! Ich warte[ENTER]hier auf dich. "
gameforge.subquest_32._50_say = "Zus\228tzlich brauche ich noch ein Schmuckst\252ck und[ENTER]N\228hgarn. Das eine bekommst du von der[ENTER]Gemischtwarenh\228ndlerin, das andere von Ariyoung.[ENTER]So viele Sachen zu beschaffen ist nicht einfach,[ENTER]aber der Verkauf der Ketten ist ein gutes[ENTER]Gesch\228ft und du bekommst eine ordentliche[ENTER]Belohnung f\252r die Materialien. Was meinst du,[ENTER]h\246rt sich das interessant an? "
gameforge.subquest_32._510_say = "Die Aufgabe ist wohl zu schwer? Na immerhin hast[ENTER]du es versucht. Wenn ich irgendwann einmal eine[ENTER]einfachere Aufgabe f\252r dich habe, lasse ich es[ENTER]dich wissen. Leb wohl. "
gameforge.subquest_32._520_say = "Du versuchst es noch einmal? Danke.[ENTER]Ich werde hier auf dich warten. "
gameforge.subquest_32._60_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_32._70_say = "Du bist besch\228ftigt? Das kann ich gut verstehen.[ENTER]Aber komm bitte wieder, wenn du Zeit hast. "
gameforge.subquest_32._80_say = "Oh je, wie soll ich blo\223 all meine Auftr\228ge[ENTER]erledigen? Bis bald! "
gameforge.subquest_32._90_say = "Wunderbar. Ich werde hier auf dich warten. "
gameforge.subquest_33 = {}
gameforge.subquest_33._100_sayTitle = "Schatzkarte gefunden "
gameforge.subquest_33._10_targetVid = "Gehe zum B\252cherwurm. "
gameforge.subquest_33._110_say = "Du hast die Tiergottheiten vor der Stadt gejagt[ENTER]und die vier Teile der Schatzkarte gefunden.[ENTER]Bringe sie zu Soon. "
gameforge.subquest_33._120_sayTitle = "Jagd auf die Tiergottheiten "
gameforge.subquest_33._130_say = "Sammle f\252r Soon vier Teile einer Schatzkarte,[ENTER]indem du die Tiergottheiten Lykos, Scrofa, Bera[ENTER]und Tigris jagst. "
gameforge.subquest_33._140_sayReward = "(Kartenteile gefunden: %s ) "
gameforge.subquest_33._150_sendLetter = "Die Schatzkarte "
gameforge.subquest_33._160_sayTitle = "Alle Kartenteile gesammelt "
gameforge.subquest_33._170_say = "Geh zur\252ck zu Soon und berichte ihm, dass du[ENTER]die Schatzkartenteile gefunden hast. "
gameforge.subquest_33._175_npcChat = "Ich habe alle Kartenteile. "
gameforge.subquest_33._180_say = "Oh, gro\223artig! Alle vier Kartenteile beisammen...[ENTER]Ich habe kaum gewagt, davon zu tr\228umen.[ENTER]Nun noch schnell die Teile zu einer Karte[ENTER]zusammengef\252gt... so... "
gameforge.subquest_33._190_say = "Hmm, eigenartig. Die Karte sagt, der Schatz sei[ENTER]bei dem Felsen nahe des Alten Mannes versteckt.[ENTER]Ich kann mir nicht vorstellen, dass das stimmt.[ENTER]Er w\228re l\228ngst gefunden worden. Was f\252r eine[ENTER]kindische Spielerei! Willst du trotzdem nachsehen[ENTER]oder soll ich die Karte verbrennen? "
gameforge.subquest_33._200_select = "Ich werde nachsehen. "
gameforge.subquest_33._20_npcChat = "Wegen der Schatzkarte... "
gameforge.subquest_33._210_select = "Verbrenn sie ruhig. "
gameforge.subquest_33._220_say = "Bist du sicher, dass du die Karte nicht mehr[ENTER]brauchst? "
gameforge.subquest_33._230_say = "Was f\252r ein l\228cherliches M\228rchen![ENTER]Es tut mir Leid, dass ich dich auf die Suche nach[ENTER]den Kartenteilen geschickt habe. Ich verbrenne[ENTER]sie, damit nicht noch andere Leute darauf[ENTER]hereinfallen. Trotzdem vielen Dank. Leb wohl! "
gameforge.subquest_33._240_say = "Warum noch z\246gern? Die Kartenteile hast du[ENTER]bereits gesammelt, dann kannst du auch nachsehen[ENTER]gehen. Hier, nimm die Karte mit. "
gameforge.subquest_33._250_say = "Wie du meinst. Es w\252rde mich zwar sehr[ENTER]\252berraschen, wenn du wirklich etwas findest, aber[ENTER]ich w\252nsche dir viel Gl\252ck! Hier, nimm die Karte[ENTER]mit. "
gameforge.subquest_33._260_say = "Die Karte wurde in vier Teile zerlegt. Wir[ENTER]brauchen alle vier Teile, um sie wieder[ENTER]zusammensetzen zu k\246nnen! "
gameforge.subquest_33._270_select = "Erneut versuchen "
gameforge.subquest_33._280_say = "Du gibst auf? Nun denn, so sei es. Leb wohl. "
gameforge.subquest_33._290_say = "Wie erwartet bist du voller Energie. Ich vertraue[ENTER]dir!  "
gameforge.subquest_33._300_targetVid = "Fels beim Alten Mann "
gameforge.subquest_33._30_say = "Hey, ich habe in alten Texten seltsame[ENTER]Informationen entdeckt. Es hei\223t, dass es[ENTER]Schatzkarten in diesem Dorf gibt. Kennst du die[ENTER]g\246ttlichen Tierw\228chter - Hundegottheit,[ENTER]B\228rengottheit, Tigergottheit und Schweinegottheit[ENTER]- drau\223en vor der Stadt? "
gameforge.subquest_33._310_sayTitle = "Suche nach dem Schatz "
gameforge.subquest_33._320_say = "Hmm, unterhalb der Felsen bei dem Alten Mann...[ENTER]Keine Ahnung. Ich sollte zuerst den Alten Mann[ENTER]fragen. Warum ist der Weg zu ihm so weit? Mist. "
gameforge.subquest_33._330_sayTitle = "Alter Mann: "
gameforge.subquest_33._340_say = "Wonach suchst du? Nach einem Schatz? Haha, da[ENTER]kannst du lange suchen! Zeig mal die Karte...[ENTER]Hm, das m\252sste dort dr\252ben sein. Viel Gl\252ck,[ENTER]hihihi... "
gameforge.subquest_33._350_say = "Das hier muss die Stelle sein. Hau ruck! \133 und[ENTER]weiter...[ENTER]Verdammt, der Boden ist ganz sch\246n hart. Hrmpf...[ENTER]Hey, ich kann eine Kiste sehen! "
gameforge.subquest_33._360_sendLetter = "Es gibt den Schatz wirklich! "
gameforge.subquest_33._370_sayTitle = "Zur\252ck zu Soon "
gameforge.subquest_33._380_say = "Du hast an dem Ort gegraben, den die Karte der[ENTER]Tiergottheiten bezeichnete und dort tats\228chlich[ENTER]eine Schatztruhe gefunden! Gehe zu Soon und[ENTER]berichte ihm von dem unerwarteten Erfolg. "
gameforge.subquest_33._390_npcChat = "Ich habe den Schatz gefunden! "
gameforge.subquest_33._400_say = "Oh, das ist eine \220berraschung! Zeig her...[ENTER]Erstaunlich. Genau so wurde die Schatztruhe in[ENTER]den alten Texten beschrieben. Jetzt muss ich nur[ENTER]noch herausfinden, wie man sie \246ffnen kann.[ENTER]Aber das soll nicht deine Sorge sein. Ich danke[ENTER]dir! Nimm dies als Zeichen meiner Anerkennung. "
gameforge.subquest_33._40_say = "Eine uralte M\228r \252berliefert, dass diese vier[ENTER]g\246ttlichen Monster die Karte in vier Teile[ENTER]geteilt haben und diese besch\252tzen. Ich bin mir[ENTER]nicht sicher, ob es stimmt. K\246nntest du das f\252r[ENTER]mich \252berpr\252fen? Oh bitte, diese Ungewissheit[ENTER]bringt mich sonst um... Ich flehe dich an, hilf[ENTER]mir! "
gameforge.subquest_33._410_sayReward = "Du erh\228ltst 1.400.000 Erfahrungspunkte. "
gameforge.subquest_33._420_sayReward = "Du erh\228ltst 25.000 Yang. "
gameforge.subquest_33._430_sayReward = "Du erh\228ltst eine Geistermaskenschaller+1. "
gameforge.subquest_33._440_sayReward = "Du erh\228ltst einen Burghelm+1. "
gameforge.subquest_33._450_sayReward = "Du erh\228ltst eine Stahlkapuze+1. "
gameforge.subquest_33._460_sayReward = "Du erh\228ltst einen Sonnenlichthut+1. "
gameforge.subquest_33._470_say = "Ja, wo ist er denn? Willst du dich \252ber mich[ENTER]lustig machen?! Du hast ihn nicht wirklich[ENTER]gefunden, hab ich Recht? "
gameforge.subquest_33._50_say = "Interessieren alte Schatzkarten dich nicht? Du[ENTER]bist seltsam... Ich werde weiter nach Hinweisen[ENTER]in diesen Texten suchen. Komm zur\252ck, wenn du[ENTER]deine Meinung ge\228nderst hast. "
gameforge.subquest_33._60_say = "Magst du solche Abenteuer nicht? Wie soll ich nun[ENTER]an die Kartenteile kommen?[ENTER]Naja, wie auch immer. Leb wohl. "
gameforge.subquest_33._70_say = "Du bist ein wahrer Freund. Ich vertraue darauf,[ENTER]dass du sie finden wirst. "
gameforge.subquest_33._80_sendLetter = "Schatzkarte des B\252cherwurms "
gameforge.subquest_33._90_targetVid = "Geh zum B\252cherwurm "
gameforge.subquest_34 = {}
gameforge.subquest_34._100_say = "Der Hauptmann hat weiterhin Schwierigkeiten, die[ENTER]Schwarzwindkrieger in den Griff zu bekommen.[ENTER]T\246te ihre Gener\228le Jak-To, To-Su und Gu-Ryung.[ENTER]Vielleicht geben sie dann endlich Ruhe. "
gameforge.subquest_34._10_npcChat = "Was macht die Schwarzwindbande? "
gameforge.subquest_34._110_say = "Die Gener\228le sind tot! "
gameforge.subquest_34._120_select = "Weiter versuchen "
gameforge.subquest_34._130_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_34._140_say = "K\228mpfen ist eine schwierige Angelegenheit und[ENTER]Siegen erst recht. Vor allem gegen die Gener\228le.[ENTER]Versuche es noch einmal! "
gameforge.subquest_34._150_say = "Wie gesagt: Es ist eine sehr starke Bande.[ENTER]Auf Wiedersehen. "
gameforge.subquest_34._160_say = "Wie mutig du bist! Ich glaube, du kannst die[ENTER]Schwarzwindbande besiegen! "
gameforge.subquest_34._170_targetVid = "Berichte dem Hauptmann "
gameforge.subquest_34._180_say = "Geh zur\252ck zum Hauptmann und berichte, dass du[ENTER]die Gener\228le get\246tet hast. "
gameforge.subquest_34._185_npcChat = "Ich habe die Gener\228le get\246tet! "
gameforge.subquest_34._190_say = "Hmm... Du hast die Gener\228le besiegt. Gut.[ENTER]Wir hatten schon Kopfschmerzen wegen der[ENTER]Schwarzwindbande, aber dank deiner Hilfe schaffen[ENTER]wir es nun. Ohne die Gener\228le wird der Rest ein[ENTER]Kinderspiel.[ENTER]Hier ist eine Belohnung f\252r dich. Ich hoffe, wir[ENTER]sehen uns bald wieder! "
gameforge.subquest_34._200_sayReward = "Du erh\228ltst 1.000.000 Erfahrungspunkte. "
gameforge.subquest_34._20_sayTitle = "Hauptmann: "
gameforge.subquest_34._210_sayReward = "Du erh\228ltst einen Sprachenring. "
gameforge.subquest_34._30_say = "Obwohl du der Schwarzwindbande einen[ENTER]empfindlichen Schlag versetzt hast, denken sie[ENTER]nicht daran, sich ruhig zu verhalten und benehmen[ENTER]sich einfach weiter wie die Wilde Horde. Wenn wir[ENTER]sie endg\252ltig besiegen wollen, m\252ssen wir ihre[ENTER]Anf\252hrer t\246ten. "
gameforge.subquest_34._40_say = "Wenn die Anf\252hrer erst besiegt sind, wird der[ENTER]Rest der Bande auch bald untergehen. Es wird ein[ENTER]hartes St\252ck Arbeit, aber wir brauchen einen Sieg[ENTER]\252ber die Schwarzwindgener\228le Jak-To, To-Su und[ENTER]Gu-Ryung. Wenn wir sie besiegen, m\252ssen wir uns[ENTER]\252ber die Schwarzwindbande keine Sorgen mehr[ENTER]machen. Also, viel Gl\252ck, ich bete f\252r deinen[ENTER]Sieg! "
gameforge.subquest_34._50_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_34._60_say = "Hmm, na gut.[ENTER]Aber komm bitte wieder, wenn du bereit bist.[ENTER]Es gibt viel zu wenig f\228hige Leute wie dich. "
gameforge.subquest_34._70_say = "Du kannst es nicht...? Aber wie sollen wir die[ENTER]Schwarzwindbande dann besiegen? "
gameforge.subquest_34._80_say = "Ich wusste, dass ich mich auf dich verlassen[ENTER]kann! Wenn die Gener\228le tot sind, sind die[ENTER]anderen Schwarzwindkrieger kein Problem mehr.[ENTER]Viel Gl\252ck! "
gameforge.subquest_34._90_sendLetter = "T\246te die Schwarzwindgener\228le "
gameforge.subquest_36 = {}
gameforge.subquest_36._100_sayTitle = "Auf zum Stallburschen "
gameforge.subquest_36._10_targetVid = "Yonah "
gameforge.subquest_36._110_say = "Du hast 10 Ballen Heu zusammengetragen.[ENTER]Bringe sie zum Stallburschen, damit er die Pferde[ENTER]f\252ttern kann. "
gameforge.subquest_36._120_sayTitle = "Heu f\252r die St\228lle "
gameforge.subquest_36._130_say = "Es herrscht Futtermangel bei den St\228llen.[ENTER]Besorge 10 Ballen Heu und bringe sie dem[ENTER]Stallburschen, bevor die Pferde verhungern![ENTER]Heu erh\228ltst du bei der Jagd. "
gameforge.subquest_36._140_npcChat = "Du brauchst Heu? "
gameforge.subquest_36._150_say = "Du bist wohl hier, weil Yonah dich geschickt hat?[ENTER]Ich habe bereits viel von dir geh\246rt.[ENTER]Ach, unsere Pferde leiden an Unterern\228hrung. Wir[ENTER]m\252ssen daf\252r sorgen, dass sie \252berleben. Hilf mir[ENTER]und besorge Heu f\252r die Pferde! "
gameforge.subquest_36._160_say = "Was man verspricht, das soll man halten.[ENTER]Au\223erdem will ich sp\228ter vielleicht auch einmal[ENTER]ein Pferd reiten. Ich muss unbedingt Heu finden! "
gameforge.subquest_36._170_say = "Es tut mir leid. Ich suche ja auch, aber es ist[ENTER]einfach kein Heu zu finden. "
gameforge.subquest_36._180_say = "Ich wei\223, es ist nicht sehr nett von mir, dir[ENTER]meine Arbeit aufzudr\252cken. Trotzdem hatte ich[ENTER]gehofft, du k\246nntest es schaffen.[ENTER]Versuchst du es bitte noch einmal? Ich kenne[ENTER]jemanden in einem anderen Reich, eine sehr[ENTER]wichtige Pers\246nlichkeit. Wenn du mir hilfst,[ENTER]frage ich ihn, ob er etwas f\252r dich tun kann. "
gameforge.subquest_36._190_select = "Weitersuchen "
gameforge.subquest_36._200_say = "Nat\252rlich helfe ich dir. Mal sehen, was ich tun[ENTER]kann. "
gameforge.subquest_36._20_npcChat = "Die St\228lle haben \196rger "
gameforge.subquest_36._210_say = "Ich kann nicht die Energie daf\252r aufbringen.[ENTER]Ich will dir wirklich helfen, aber ich kann[ENTER]nicht. Ich bin nicht stark genug. "
gameforge.subquest_36._220_npcChat = "Ich habe Heu f\252r die Pferde. "
gameforge.subquest_36._230_say = "Du hast Heu besorgt? Oh, danke.[ENTER]Das Pferdefutter wurde knapp und ich erz\228hlte[ENTER]Yonah davon. Er ist ein guter Freund von mir. Ich[ENTER]dachte mir schon, dass er sich umh\246rt, ob jemand[ENTER]helfen kann. Aber dass es so schnell geht, das[ENTER]h\228tte ich nicht gedacht. Schau nur, wie[ENTER]begeistert die Pferde fressen! "
gameforge.subquest_36._240_sayReward = "Du erh\228ltst 1.800.000 Erfahrungspunkte. "
gameforge.subquest_36._250_sendLetter = "Zur\252ck zu Yonah "
gameforge.subquest_36._260_sayTitle = "Zur\252ck zu Yonah "
gameforge.subquest_36._270_say = "Du hast dem Stallburschen 10 Ballen Heu f\252r die[ENTER]hungernden Pferde gebracht. Geh und berichte[ENTER]Yonah von deinem Erfolg. "
gameforge.subquest_36._280_npcChat = "Die Pferde sind versorgt! "
gameforge.subquest_36._290_say = "Hallo, du bist zur\252ck![ENTER]Es war bestimmt nicht leicht, so viel Heu zu[ENTER]sammeln. Danke, dass du nicht aufgegeben hast![ENTER]Hier ist ein kleines Geschenk f\252r dich. "
gameforge.subquest_36._300_sayReward = "Du erh\228ltst ein Missionsbuch. "
gameforge.subquest_36._30_say = "Hallo, ich habe eine Frage an dich![ENTER]Ich wei\223, dass du nicht f\252r die St\228lle[ENTER]verantwortlich bist, aber in letzter Zeit haben[ENTER]wir viel \196rger und k\246nnten deine Hilfe[ENTER]gebrauchen. Die Pferde haben w\228hrend des Krieges[ENTER]viel zu tun, aber selbst ein ausgewachsenes,[ENTER]starkes Pferd hat seine Grenzen. "
gameforge.subquest_36._40_say = "Zum Gl\252ck haben wir noch gen\252gend Pferde, aber es[ENTER]gibt zu wenig Futter. So sterben viele.[ENTER]Kannst du bitte Futter besorgen, damit die[ENTER]ersch\246pften Pferde wieder zu Kr\228ften kommen?[ENTER]Ich habe niemand anderen, den ich fragen[ENTER]k\246nnte... Sammel 10 Ballen Heu und bring sie dem[ENTER]Stallburschen. Er wei\223 schon Bescheid. Sag[ENTER]einfach, dass du von mir kommst. "
gameforge.subquest_36._50_select = "Ich gehe sofort los! "
gameforge.subquest_36._60_select = "Nein, das ist niedere Arbeit. "
gameforge.subquest_36._70_say = "Heutzutage m\246chten immer mehr Leute Pferde[ENTER]haben. Aber keiner denkt daran, dass das Futter[ENTER]f\252r die Pferde knapp wird. Und jetzt verhungern[ENTER]sie im Stall. Wenn du deine Meinung \228nderst, komm[ENTER]zur\252ck. "
gameforge.subquest_36._80_say = "Oh, die armen Pferde! Sie hungern und ich kann[ENTER]nichts dagegen tun. Was soll ich nur machen... "
gameforge.subquest_36._90_say = "Mir ist klar, dass du sehr besch\228ftigt bist. Um[ENTER]so mehr wei\223 ich deine Hilfsbereitschaft zu[ENTER]sch\228tzen. Heutzutage sind Pferde sehr wichtig.[ENTER]Wir brauchen das Heu wirklich dringend. "
gameforge.subquest_37 = {}
gameforge.subquest_37._100_say = "Yonah gibt sein Bestes, um neues Porzellan[ENTER]herzustellen, kommt aber mit seinen Experimenten[ENTER]nicht weiter. Geh zum Gelehrten Uriel und frage[ENTER]ihn, ob er etwas \252ber Seladon-Porzellan wei\223. "
gameforge.subquest_37._10_targetVid = "Das Geheimnis des Seladon-Porzellans "
gameforge.subquest_37._110_npcChat = "Kennst du Seladon-Porzellan? "
gameforge.subquest_37._120_sayTitle = "Uriel: "
gameforge.subquest_37._130_say = "Seladon-Porzellan?[ENTER]Nun, ich habe gute Kenntnisse in Geschichte und[ENTER]Wissenschaft. Kunst aber interessiert mich nicht.[ENTER]Deshalb kann ich dir \252ber das Seladon-Porzellan[ENTER]leider nichts sagen.[ENTER]Aber k\246nnte Soon das nicht wissen? Er ist zwar[ENTER]nicht sehr beliebt, aber er liest viele B\252cher.[ENTER]Vielleicht wei\223 er etwas dar\252ber. "
gameforge.subquest_37._140_makequestbutton = "Geh zu Soon "
gameforge.subquest_37._150_targetVid = "Weiter zu Soon "
gameforge.subquest_37._160_say = "Uriel wei\223 leider nichts \252ber Seladon-Porzellan.[ENTER]Aber der B\252cherwurm Soon liest viele Sachen in[ENTER]seinen B\252chern. Geh zu ihm und frage ihn, ob er[ENTER]etwas \252ber die Herstellungsmethode wei\223. "
gameforge.subquest_37._170_sayTitle = "Soon: "
gameforge.subquest_37._180_say = "Was willst du? St\246r mich nicht beim Lesen![ENTER]H\228h? Seladon-Porzellan? Nat\252rlich kenne ich das.[ENTER]Immerhin habe ich ann\228hernd ein Dutzend B\252cher[ENTER]gelesen, die sich nur damit befassen. Warum? Ich[ENTER]werde nicht umsonst 'B\252cherwurm' genannt! Ich[ENTER]kann alles verstehen, was in jedem Buch[ENTER]geschrieben steht! "
gameforge.subquest_37._190_say = "Ich k\246nnte dir die Herstellungsmethode f\252r das[ENTER]Seladon-Porzellan aus dem Kopf aufschreiben,[ENTER]aber warum sollte ich das tun?[ENTER]Hmm, warte, ich habe eine Idee: Ich habe beim[ENTER]Fahrenden H\228ndler im Nachbardorf ein Buch[ENTER]angefordert, das mir noch fehlt, aber ich habe[ENTER]keine Zeit f\252r den langen Weg. Hole es f\252r mich[ENTER]ab, dann helfe ich dir mit dem Porzellan. Los,[ENTER]los! "
gameforge.subquest_37._200_makequestbutton = "Auf zum Fahrenden H\228ndler "
gameforge.subquest_37._20_sayTitle = "Yonah: "
gameforge.subquest_37._210_targetVid = "Geh zum Fahrenden H\228ndler "
gameforge.subquest_37._220_say = "Soon, der B\252cherwurm, kennt sich mit[ENTER]Seladon-Porzellan aus. Er will sein Wissen aber[ENTER]nicht ohne Gegenleistung teilen.[ENTER]Geh f\252r Soon zum Fahrenden H\228ndler im Nachbardorf[ENTER]und hole das Buch ab, das er bei ihm bestellt[ENTER]hat. "
gameforge.subquest_37._230_npcChat = "Soon schickt mich... "
gameforge.subquest_37._240_say = "Hallo! Kommst du, um mir nochmal zu helfen?[ENTER]Ah, du m\246chtest das Buch f\252r Soon. Ich w\228re[ENTER]sowieso bald in die Stadt gekommen, aber er ist[ENTER]zu ungeduldig. Bittet andere darum, es f\252r ihn[ENTER]zu holen. Hmm.[ENTER]Hier ist es. Ich verstehe nicht, was Soon immer[ENTER]an diesen Papierstapeln findet. Es ist doch viel[ENTER]wichtiger, schnell Yang zu verdienen! "
gameforge.subquest_37._250_qSetTitle = "R\252ckkehr zu Soon. "
gameforge.subquest_37._260_targetVid = "R\252ckkehr zu Soon "
gameforge.subquest_37._270_say = "Du hast Soons Buch beim Fahrenden H\228ndler[ENTER]abgeholt. Geh zur\252ck zu Soon und gib es ihm,[ENTER]damit er dir die Herstellungsmethode des[ENTER]Seladon-Porzellans verr\228t. "
gameforge.subquest_37._280_npcChat = "Ich habe das Buch. "
gameforge.subquest_37._290_say = "Juhu! Endlich neuer Lesestoff! Ich danke dir.[ENTER]Es gibt nicht viele B\252cher, die ich noch nicht[ENTER]kenne...[ENTER]Hier, ich habe dir aufgeschrieben, worauf es beim[ENTER]Herstellen von Seladon-Porzellan ankommt. Halte[ENTER]dich an die Anweisungen, dann wirst du[ENTER]fantastisches Porzellan herstellen.[ENTER]Und nun wird es Zeit, das neue Buch zu lesen.[ENTER]Leb wohl. "
gameforge.subquest_37._300_makequestbutton = "Zur\252ck zu Yonah "
gameforge.subquest_37._30_say = "Hmm... Das hier taugt nichts. Und dieses[ENTER]auch nicht...[ENTER]Oh, hallo! Schaut einmal her: Ich stelle[ENTER]ununterbrochen Porzellan her, aber die meisten[ENTER]Sachen zerbrechen sofort. Ich denke, ich brauche[ENTER]ein neues, wegweisendes Porzellan... "
gameforge.subquest_37._310_targetVid = "Bring die Notizen zu Yonah "
gameforge.subquest_37._320_say = "Soon hat sein Versprechen gehalten und dir eine[ENTER]Anleitung zum Brennen von Seladon-Porzellan[ENTER]geschrieben. Bringe sie zu Yonah. "
gameforge.subquest_37._330_say = "Ooh!!! Hier steht alles \252ber die Herstellung von[ENTER]Seladon-Porzellan. Mit Hilfe dieser[ENTER]Aufzeichnungen werde ich als Meister in die[ENTER]Geschichte eingehen. Danke f\252r deine[ENTER]Hilfsbereitschaft. Schon bald werde ich dir die[ENTER]allerbeste Keramik zeigen k\246nnen! Verlass dich[ENTER]auf mich. Mein Porzellan wird die Jahrhunderte[ENTER]\252berdauern. "
gameforge.subquest_37._340_sayReward = "Du erh\228ltst 2.500.000 Erfahrungspunkte. "
gameforge.subquest_37._350_sayReward = "Du erh\228ltst 35.000 Yang. "
gameforge.subquest_37._360_sayReward = "Du erh\228ltst Jadeschuhe+3. "
gameforge.subquest_37._40_say = "Ich werde eine neue Methode ausprobieren.[ENTER]Seladon-Porzellan ist sehr schwer herzustellen,[ENTER]daher k\246nnen es nur sehr wenige. Aber ich werde[ENTER]es f\252r meine Kunstwerke brauchen! Daher...[ENTER]Hmm, der weise Uriel k\246nnte es wissen![ENTER]Geh doch bitte zu Uriel und frag ihn nach der[ENTER]Herstellung von Seladon-Porzellan! "
gameforge.subquest_37._50_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_37._60_say = "Hm, du bist wohl zu besch\228ftigt?[ENTER]Denk daran, mich nochmal zu besuchen, wenn[ENTER]du mehr Zeit hast. "
gameforge.subquest_37._70_say = "Verstehe. Leb wohl... "
gameforge.subquest_37._80_say = "Vielen Dank. Uriel wei\223 bestimmt weiter. Bis[ENTER]gleich! "
gameforge.subquest_37._90_targetVid = "Auf zu Uriel "
gameforge.subquest_38 = {}
gameforge.subquest_38._100_say = "Dem J\228ger Yang-Shin wurde sein Verzierter Bogen,[ENTER]ein Erbst\252ck der Familie, gestohlen.[ENTER]Geh zum Sangsun Dong und hole den Bogen von den[ENTER]diebischen Affen zur\252ck. "
gameforge.subquest_38._10_targetVid = "Schatz des J\228gers "
gameforge.subquest_38._110_sendLetter = "Verzierten Bogen gefunden "
gameforge.subquest_38._120_targetVid = "Geh zum J\228ger Yang-Shin "
gameforge.subquest_38._125_say = "Du hast den Verzierten Bogen des J\228gers gefunden.[ENTER]Bringe ihn zur\252ck zu Yang-Shin. "
gameforge.subquest_38._130_npcChat = "Hier ist der Bogen! "
gameforge.subquest_38._140_say = "Tats\228chlich, das ist er! Mein Bogen! Meine Ehre[ENTER]vor den Ahnen ist gerettet. Puuuh. Wie lange habe[ENTER]ich darunter gelitten, ihn verloren zu haben...[ENTER]Ich bin \228u\223erst dankbar f\252r deine Hilfe. Es ist[ENTER]mir wahrhaft eine Ehre, dir dies hier zu geben.[ENTER]Es mag nach wenig aussehen, aber es kommt von[ENTER]Herzen. Bitte nimm es. Dank dir kann ich nun in[ENTER]Frieden weiterleben! "
gameforge.subquest_38._150_sayReward = "Du erh\228ltst 1.500.000 Erfahrungspunkte. "
gameforge.subquest_38._160_sayReward = "Du erh\228ltst 35.000 Yang. "
gameforge.subquest_38._170_sayReward = "Du erh\228ltst einen Tapferkeitsumhang. "
gameforge.subquest_38._180_say = "Du hast meinen Bogen gefunden? Aber wo ist er[ENTER]denn? Hast du ihn schon wieder verloren? "
gameforge.subquest_38._190_select = "Ich suche weiter. "
gameforge.subquest_38._200_say = "So sei es.[ENTER]Pass auf dich auf. "
gameforge.subquest_38._20_say = "Hey. H\246rst du mir kurz zu?[ENTER]Wie du sehen kannst, bin ich ein J\228ger. Meine[ENTER]Familie jagt seit vielen Generationen. Wir sind[ENTER]alle J\228ger, eine Familie mit gro\223er Ehre.[ENTER]Aber ich habe einen Fehler begangen, der mich vor[ENTER]meiner Familie entehrt... "
gameforge.subquest_38._210_say = "Du versuchst du es noch einmal? Ich danke dir.[ENTER]Ich bin sicher, mit deinen F\228higkeiten kannst du[ENTER]es schaffen. "
gameforge.subquest_38._30_say = "Es geht um einen Verzierten Bogen, der vor[ENTER]einiger Zeit von Affen gestohlen wurde.[ENTER]Ich habe damals im Affendungeon gejagt und war[ENTER]f\252r einen Moment unaufmerksam. Sie nutzten die[ENTER]Gelegenheit und stahlen ihn mir. "
gameforge.subquest_38._40_say = "Ich war niemals tief im Sangsun Dong, daher kenne[ENTER]ich mich dort nicht aus und ben\246tige deine[ENTER]Hilfe. Ich habe von einigen Einwohnern geh\246rt,[ENTER]du h\228ttest gro\223es Talent. Deswegen bitte ich[ENTER]dich um diesen Gefallen.[ENTER]Ich kann meinen Ahnen nicht ohne meinen[ENTER]Verzierten Bogen entgegentreten. "
gameforge.subquest_38._50_sayTitle = "Yang-Shin: "
gameforge.subquest_38._60_say = "Oh, ich muss ihn schnell zur\252ckhaben...[ENTER]Bitte, komm wieder, wenn du Zeit hast.[ENTER]Leb wohl. "
gameforge.subquest_38._70_say = "Nun denn...[ENTER]Sei wachsam auf deinen Reisen. "
gameforge.subquest_38._80_say = "Er kann leicht gefunden werden, denn er ist ein[ENTER]sehr aufwendig verzierter Bogen. Ich werde dich[ENTER]daf\252r gut belohnen! "
gameforge.subquest_38._90_sayTitle = "Suche den verzierten Bogen "
gameforge.subquest_39 = {}
gameforge.subquest_39._100_sayTitle = "Verr\228ter Balsos Zustand "
gameforge.subquest_39._10_targetVid = "Lieferung f\252r Verr\228ter Balso "
gameforge.subquest_39._110_say = "Der Gesundheitszustand von Verr\228ter Balso hat[ENTER]sich verschlechtert. Geh zu Baek-Go und frage[ENTER]ihn, wie man Balso helfen kann. "
gameforge.subquest_39._120_makequestbutton = "Geh zu Baek-Go "
gameforge.subquest_39._130_qSetTitle = "Geh zu Baek-Go "
gameforge.subquest_39._140_targetVid = "Auf zu Baek-Go "
gameforge.subquest_39._150_npcChat = "Ich habe einen Patienten... "
gameforge.subquest_39._160_sayTitle = "Baek-Go: "
gameforge.subquest_39._170_say = "Oh, du bist es, wie geht es dir?[ENTER]Du behandelst einen Kranken? Erz\228hl mal, was[ENTER]hat er denn... Hmm...[ENTER]Und welche Medizin hat er bisher bekommen?[ENTER]Wie bitte?! Kein Wunder, dass es ihm schlechter[ENTER]geht! Diese Medizin ist v\246llig ungeeignet! "
gameforge.subquest_39._180_say = "Er kann froh sein, dass er noch lebt! Es ist sehr[ENTER]gef\228hrlich, einen Kranken falsch zu behandeln![ENTER]Aber ich wei\223 etwas, das ihm helfen wird. Es gibt[ENTER]ein bestimmtes Kraut, das den K\246rper von Giften[ENTER]befreit und ihn bei der Heilung unterst\252tzt.[ENTER]Allerdings ist die Suche danach sehr riskant. "
gameforge.subquest_39._190_say = "Soweit ich wei\223, w\228chst das Kraut nur im Sangsun[ENTER]Dong. Es wird aber immer f\252r den Affen-Lord[ENTER]abgeerntet, der es gerne isst. Du wirst ihn t\246ten[ENTER]m\252ssen, um es zu bekommen.[ENTER]Wenn du mir das Kraut bringst, stelle ich dir[ENTER]daraus die richtige Medizin her. "
gameforge.subquest_39._200_select = "Gut, ich hole es. "
gameforge.subquest_39._20_npcChat = "Wegen deiner Medizin... "
gameforge.subquest_39._210_select = "Das kann ich nicht. "
gameforge.subquest_39._220_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_39._230_select = "Ja "
gameforge.subquest_39._240_say = "Naja, dann eben sp\228ter, wenn du Zeit hast.[ENTER]Viele Menschen sind krank, aber nur wenige suchen[ENTER]nach der Medizin. "
gameforge.subquest_39._250_say = "Hmm, so ist das leider. Schade, dass keiner den[ENTER]Mut dazu hat. Wie soll das nur weitergehen... "
gameforge.subquest_39._260_say = "Oh, danke. Es ist eine schwierige Aufgabe, aber[ENTER]du wirst damit vielen Menschen helfen! "
gameforge.subquest_39._270_makequestbutton = "Kraut des Affen-Lords "
gameforge.subquest_39._280_targetVid = "Zur\252ck zu Baek-Go "
gameforge.subquest_39._290_sayTitle = "Kraut des schweren Affen gefunden "
gameforge.subquest_39._300_say = "Du hast dem Affen-Lord das Kraut des schweren[ENTER]Affen abgenommen. Bringe es zu Baek-Go, damit er[ENTER]dir die Medizin f\252r Balso herstellen kann. "
gameforge.subquest_39._30_say = "Danke, dass du mir letztens die Medizin gebracht[ENTER]hast. Aber es gibt da ein Problem... Die Wirkung[ENTER]der Medizin hat in letzter Zeit stark[ENTER]nachgelassen. Ich glaube, dass sie schlecht[ENTER]geworden ist.[ENTER]*Hust* - Ich brauche dringend eine Behandlung. "
gameforge.subquest_39._310_sayTitle = "Hole das Kraut aus dem Sangsun Dong "
gameforge.subquest_39._320_say = "Baek-Go kann eine Medizin f\252r Verr\228ter Balsos[ENTER]Krankheit herstellen. Er ben\246tigt daf\252r das Kraut[ENTER]des schweren Affen. Du erh\228ltst es vom Affen-Lord[ENTER]im schweren Affendungeon. "
gameforge.subquest_39._330_npcChat = "Das Kraut des schweren Affen... "
gameforge.subquest_39._340_say = "Wir scheinen kurz vor einer Epidemie zu stehen,[ENTER]aber wir wissen nicht, woran es liegt. Zum Gl\252ck[ENTER]hat uns die akademische Gesellschaft \252ber eine[ENTER]Heilungsm\246glichkeit durch Affenkraut berichtet.[ENTER]Was ist? Hast du das Kraut schon gefunden? "
gameforge.subquest_39._350_select = "Noch nicht. Aber bald! "
gameforge.subquest_39._360_select = "Ich kann das Kraut nicht besorgen. "
gameforge.subquest_39._370_say = "Du willst wirklich aufgeben? Hmm, mehr kannst du[ENTER]wohl nicht tun.[ENTER]Was soll ich nur machen? Dieses Kraut k\246nnte ein[ENTER]wahrer Segen sein... "
gameforge.subquest_39._380_select = "Ich schaffe es nicht. "
gameforge.subquest_39._390_select = "Ich will helfen! "
gameforge.subquest_39._400_say = "Die Affen sind zu stark f\252r mich. Ich habe keine[ENTER]M\246glichkeit, an das Kraut heranzukommen. Es tut[ENTER]mir leid. "
gameforge.subquest_39._40_say = "Ich wei\223, dass in der n\228chsten Stadt ein Arzt[ENTER]lebt. Kannst du zu ihm gehen und ihm meinen[ENTER]Zustand erkl\228ren, damit er dir sagt, wie man mir[ENTER]helfen kann? Wie du sehen kannst, schaffe ich es[ENTER]in meinem Zustand nicht, die Stadt zu verlassen.[ENTER]Ich bin dir sehr dankbar, dass du mir bereits[ENTER]letztes Mal geholfen hast. Ich werde dich auch[ENTER]dieses Mal belohnen. "
gameforge.subquest_39._410_say = "Du verwehrst Menschen, die an einer furchtbaren[ENTER]und mysteri\246sen Krankheit leiden, deine Hilfe.[ENTER]Geh mir aus den Augen! "
gameforge.subquest_39._420_say = "Du hast Recht. Jemand muss dieses Kraut besorgen,[ENTER]sonst werden all diese Kranken furchtbar leiden.[ENTER]Ich werde mich darum k\252mmern. "
gameforge.subquest_39._430_say = "Nun denn. Beeil dich. "
gameforge.subquest_39._440_say = "Oh, du hast das Kraut des Affen besorgt. Sehr[ENTER]gut! Ich hoffe, es kann tats\228chliche diese[ENTER]mysteri\246se Krankheit besiegen! Warte kurz, ich[ENTER]werde dir die Medizin herstellen... "
gameforge.subquest_39._450_sayTitle = "Baek-Go: "
gameforge.subquest_39._460_say = "So, hier hast du die Medizin. Nun mach dich[ENTER]schnell auf den Weg zu deinem Patienten und gib[ENTER]sie ihm. Dann sollte es ihm bald besser gehen.[ENTER]Und erinnere ihn daran, dass man lieber einen[ENTER]Arzt fragen sollte, welche Medizin die richtige[ENTER]ist! "
gameforge.subquest_39._470_makequestbutton = "Bring Balso die Medizin "
gameforge.subquest_39._480_targetVid = "Du gibst dem Verr\228ter Balso die Medizin. "
gameforge.subquest_39._490_sayTitle = "Verr\228ter Balsos Medizin "
gameforge.subquest_39._500_say = "Baek-Go hat dir aus dem Kraut des schweren Affen[ENTER]eine Medizin hergestellt, die viele seltene[ENTER]Krankheiten zu heilen vermag. Bringe sie zum[ENTER]Verr\228ter Balso im Nachbardorf. "
gameforge.subquest_39._50_say = "M\246chtest du die Quest f\252r immer aufgeben? "
gameforge.subquest_39._510_npcChat = "Hier ist die Medizin. "
gameforge.subquest_39._520_say = "Bringst du mir neue Medizin? Es gibt also[ENTER]Fortschritte in der Medizinforschung?[ENTER]Entschuldige, dass ich dir solchen \196rger bereitet[ENTER]habe. Ich h\228tte von Anfang an einen Arzt um Rat[ENTER]fragen sollen. Wie dem auch sei, ich werde mich[ENTER]damit abfinden m\252ssen, diese Medizin zu nehmen. "
gameforge.subquest_39._530_say = "Vielen Dank, dass du mir in meinem Elend geholfen[ENTER]hast. Ich habe nicht viele Freunde.[ENTER]Hier, es ist keine gro\223e Summe, aber es kommt von[ENTER]Herzen. Nimm es bitte. Und wenn ich einmal den[ENTER]gro\223en Durchbruch schaffen sollte, werde ich[ENTER]dich nicht vergessen! "
gameforge.subquest_39._540_sayReward = "Du erh\228ltst 4.000.000 Erfahrungspunkte. "
gameforge.subquest_39._550_sayReward = "Du erh\228ltst 65.000 Yang. "
gameforge.subquest_39._60_say = "Wenn du wei\223t, wie man mir helfen kann,[ENTER]treffen wir uns wieder hier. "
gameforge.subquest_39._70_sayTitle = "Verr\228ter Balso: "
gameforge.subquest_39._80_say = "Ob ich wohl so weiter leben muss?[ENTER]Bis zum n\228chsten Mal. "
gameforge.subquest_39._90_say = "Danke. Sei vorsichtig. "
gameforge.subquest_40 = {}
gameforge.subquest_40._100_say = "Ich wusste, dass ich auf dich z\228hlen kann! Es[ENTER]ist ein schwieriger Auftrag, aber du schaffst das[ENTER]schon. Viel Erfolg! "
gameforge.subquest_40._10_targetVid = "Unterst\252tzendes Kriegs-Hilfsmittel "
gameforge.subquest_40._110_targetVid = "Zur\252ck zum Hauptmann "
gameforge.subquest_40._120_say = "Du hast alle 5000 Pfeilspitzen gesammelt. Bringe[ENTER]sie dem Hauptmann. "
gameforge.subquest_40._130_say = "Die Armee hat Probleme mit dem Nachschub von[ENTER]Pfeilen. T\246te Plagenbogensch\252tzen auf dem Berg[ENTER]Sohan und sammle ihre Pfeilspitzen f\252r den[ENTER]Hauptmann. 5000 St\252ck gen\252gen. "
gameforge.subquest_40._140_npcChat = "Wegen den Pfeilspitzen... "
gameforge.subquest_40._150_say = "Diese Plagenbogensch\252tzen haben irgendeine[ENTER]Krankheit, die sich auf dem Kontinent verbreitet[ENTER]hat. Nicht einmal unsere \196rzte k\246nnen sich das[ENTER]erkl\228ren. Noch sind die meisten ihrer[ENTER]Pfeilspitzen unverseucht, aber sie sind immer[ENTER]\246fter giftig. "
gameforge.subquest_40._160_select = "Ich mache dann mal weiter. "
gameforge.subquest_40._170_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_40._180_say = "Du hast Angst vor der Krankheit. Beruhige dich[ENTER]und komm sp\228ter wieder. "
gameforge.subquest_40._190_say = "Bist du sicher, dass du aufgeben willst?[ENTER]Hmm, vielleicht ist der Auftrag wirklich zu[ENTER]schwer f\252r dich. Ich frag jemand anderen.[ENTER]Bis dann! "
gameforge.subquest_40._200_say = "Ich verstehe.[ENTER]Du gibst niemals auf, nicht wahr?[ENTER]Dann los. "
gameforge.subquest_40._20_say = "Achtung, Krieger! Wie du sicher schon bemerkt[ENTER]hast, h\228ufen sich die Angriffe unserer Feinde.[ENTER]Au\223erdem haben wir von Yu-Hwan Informationen[ENTER]erhalten, die sehr alarmierend sind. Kurz gesagt:[ENTER]Wir haben zu wenig Pfeile! "
gameforge.subquest_40._210_npcChat = "Hier sind 5000 Pfeilspitzen! "
gameforge.subquest_40._220_say = "Sehr gute Arbeit! Dank deiner Hilfe k\246nnen wir[ENTER]uns jetzt auf den Angriff vorbereiten. Ich werde[ENTER]sofort den Befehl geben, die Pfeile herzustellen.[ENTER]Das war eine wirklich gute Zusammenarbeit. Ich[ENTER]hoffe, dass wir sp\228ter wieder auf dich z\228hlen[ENTER]k\246nnen. "
gameforge.subquest_40._230_say = "Hier ist deine Belohnung. Wenn ich das n\228chste[ENTER]Mal einen wichtigen Auftrag habe, wirst du der[ENTER]erste sein, der davon erf\228hrt. Viel Gl\252ck und bis[ENTER]bald! "
gameforge.subquest_40._240_sayReward = "Du erh\228ltst 4.500.000 Erfahrungspunkte. "
gameforge.subquest_40._250_sayReward = "Du erh\228ltst 50.000 Yang. "
gameforge.subquest_40._260_sayReward = "Du erh\228ltst 3x Kritischer Kampf.[ENTER]Du erh\228ltst 3x Durchbohrender Kampf. "
gameforge.subquest_40._30_say = "Bogensch\252tzen sind ein wichtiger strategischer[ENTER]Faktor bei der Kriegsf\252hrung. Sobald die Feinde[ENTER]in Reichweite sind, sollten unsere Bogensch\252tzen[ENTER]sie beschie\223en. So k\246nnen wir sie entweder gleich[ENTER]in die Flucht schlagen oder zumindest ihre Zahl[ENTER]verringern. Wenn aber viele Angriffe in kurzer[ENTER]Zeit stattfinden, gehen uns schnell die Pfeile[ENTER]aus. "
gameforge.subquest_40._40_say = "Deswegen brauchen wir dich! Reise zum Berg Sohan.[ENTER]Dort sollst du Plagenbogensch\252tzen t\246ten und ihre[ENTER]Pfeilspitzen einsammeln. Diese Pfeilspitzen sind[ENTER]vergiftet. Das kommt uns sehr gelegen, um unsere[ENTER]Feinde zu besiegen.[ENTER]5000 St\252ck ben\246tigen wir. Was sagst du? "
gameforge.subquest_40._50_select = "Ich nehme an. "
gameforge.subquest_40._60_select = "Das ist zu hart f\252r mich. "
gameforge.subquest_40._70_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_40._80_say = "Ist es dir etwa zu weit zum Berg Sohah?[ENTER]Denk noch einmal dar\252ber nach. Dieser Auftrag ist[ENTER]von h\246chster Wichtigkeit. "
gameforge.subquest_40._90_say = "Hm, du hast Angst vor den Plagenbogensch\252tzen?[ENTER]Dann habe ich dich wohl falsch eingesch\228tzt.[ENTER]Ich sehe keine Hoffnung mehr f\252r uns. "
gameforge.subquest_41 = {}
gameforge.subquest_41._015_npcChat = "Was liest du da? "
gameforge.subquest_41._100_say = "Du hast die 100 Spinnenaugen f\252r Octavios neues[ENTER]Spezialrezept gesammelt. Bringe sie schnell zu[ENTER]ihm. "
gameforge.subquest_41._10_targetVid = "Spinnenaugen spezial "
gameforge.subquest_41._110_sayTitle = "Spinnenaugen besorgen "
gameforge.subquest_41._120_say = "Octavio will ein neues Rezept ausprobieren:[ENTER]'Spinnenaugen spezial'. Dazu braucht er[ENTER]einhundert Spinnenaugen von den Spinnen in der[ENTER]Yongbi-W\252ste. "
gameforge.subquest_41._130_targetVid = "Zur\252ck zu Octavio "
gameforge.subquest_41._140_npcChat = "Ich habe die Spinnenaugen. "
gameforge.subquest_41._150_sayTitle = "Octavio: "
gameforge.subquest_41._160_say = "Zeig her. Genau einhundert Augen, sehr gut.[ENTER]Dann wollen wir mal...[ENTER]Mmh, fertig! Willst du auch probieren? Schau[ENTER]nicht so entsetzt. Es wird dich schon nicht[ENTER]umbringen. "
gameforge.subquest_41._170_say = "Hm, hmm... Was f\252r ein Erlebnis! Sehr gehaltvoll,[ENTER]nicht zu s\252\223... atemberaubender Geschmack![ENTER]Ich wusste, der Aufwand lohnt sich. Ohne dich[ENTER]h\228tte ich das niemals geschafft. Vielen Dank f\252r[ENTER]die Hilfe! "
gameforge.subquest_41._180_sayReward = "Du erh\228ltst 2.100.000 Erfahrungspunkte. "
gameforge.subquest_41._190_say = "Was redest du da? Das sind keine hundert Augen,[ENTER]das seh ich doch ohne nachzuz\228hlen! Besorge bitte[ENTER]noch weitere. "
gameforge.subquest_41._200_say = "Ich will das unbedingt kochen.[ENTER]Egal, danke. Mach es gut und pass auf dich auf. "
gameforge.subquest_41._20_say = "Hey, wie geht es dir? Ich lese gerade ein[ENTER]Kochbuch, das Soon mir freundlicherweise[ENTER]\252berlassen hat. Darin habe ich ein Rezept f\252r[ENTER]'Spinnenaugen spezial' gefunden. So etwas habe[ENTER]ich noch nie zuvor gesehen! Hast du? Es scheint[ENTER]sich um eine Spezialit\228t aus fernen L\228ndern zu[ENTER]handeln. "
gameforge.subquest_41._210_say = "Danke, dass du mich nicht h\228ngen l\228sst. Du bist[ENTER]sehr freundlich! "
gameforge.subquest_41._30_say = "Ich w\252rde dieses Gericht gerne ausprobieren, aber[ENTER]wie soll ich an Spinnenaugen kommen? Deswegen[ENTER]ben\246tige ich deine Hilfe! Bitte hol mir[ENTER]Spinnenaugen von den Spinnen in der Yongbi-W\252ste. "
gameforge.subquest_41._40_say = "K\246nntest du das tun? Ich w\228re dir sehr dankbar.[ENTER]F\252r den ersten Versuch brauche ich einhundert[ENTER]Augen, damit es auch eine ordentliche Portion[ENTER]ergibt. Ich bin schon ganz aufgeregt... "
gameforge.subquest_41._50_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_41._60_say = "Ich will dieses Rezept unbedingt kochen. Falls du[ENTER]mir einen Gefallen tun m\246chtest, besuch mich[ENTER]bitte. "
gameforge.subquest_41._70_say = "Hm, woher bekomme ich diese Augen?[ENTER]Ok, bis bald. "
gameforge.subquest_41._80_say = "Danke. Ich wusste, du w\252rdest mir diesen Gefallen[ENTER]tun. Im Gegenzug werde ich dir ein ganz[ENTER]vorz\252gliches Gericht servieren. "
gameforge.subquest_41._90_sayTitle = "Zur\252ck zu Octavio "
gameforge.subquest_42 = {}
gameforge.subquest_42._100_say = "Das ist sehr bedauerlich. Ich h\246re so[ENTER]viele Stimmen von Toten, die nicht in Frieden[ENTER]ruhen k\246nnen. Wir m\252ssen ihnen unbedingt[ENTER]helfen. Ich frage jemand anderen. Leb wohl. "
gameforge.subquest_42._10_targetVid = "F\252r den Rest des Todes "
gameforge.subquest_42._110_say = "Du bist sehr mutig. Ich bin mir sicher, dass dank[ENTER]deiner Hilfe die jungen toten Krieger bald ins[ENTER]Nirwana gehen k\246nnen. "
gameforge.subquest_42._120_say = "Schlimme Kriege t\246ten immer h\228ufiger junge[ENTER]M\228nner. Es sind K\228mpfer, die an der Frontlinie[ENTER]f\252r sich selbst, ihre Familie und ihr Land[ENTER]k\228mpfen. Aber nach dem Tod kamen einige nicht in[ENTER]das Nirwana. Sie blieben in dieser Welt. "
gameforge.subquest_42._130_say = "Ich h\246rte, dass der Stolze dunkle Oberst im[ENTER]Hwang-Tempel einen Tempelschal und eine[ENTER]Tempellehre besitzen soll.[ENTER]Bitte hilf mir und meinen Kameraden, diejenigen[ENTER]zu beruhigen, die f\252r ihr Land gestorben sind. "
gameforge.subquest_42._140_sayTitle = "Zur\252ck zum Lehrer der Drachenmacht "
gameforge.subquest_42._150_say = "Du hast einen Tempelschal und eine Tempellehre[ENTER]gefunden. Bringe sie dem Lehrer der Drachenmacht,[ENTER]damit die Schamanen ihr Ritual zur Bes\228nftigung[ENTER]der Toten beginnen k\246nnen. "
gameforge.subquest_42._160_sayTitle = "Hol den Tempelschal und die Tempellehre "
gameforge.subquest_42._170_say = "Die Schamanen brauchen einen Tempelschal und eine[ENTER]Tempellehre f\252r eine Zeremonie, die die Geister[ENTER]gefallener Soldaten beruhigen soll.[ENTER]T\246te den Stolzen dunklen Oberst im Hwang-Tempel,[ENTER]um diese rituellen Gegenst\228nde zu erhalten. "
gameforge.subquest_42._180_npcChat = "Ich habe den Schal und die Lehre. "
gameforge.subquest_42._190_say = "Sehr gut. Nun k\246nnen wir die toten Soldaten[ENTER]beruhigen. Sie haben ihr Bestes gegeben, also[ENTER]sollen sie jetzt auch in Frieden ruhen.[ENTER]Lass mich dir eine Belohnung geben f\252r diese[ENTER]noble Tat. "
gameforge.subquest_42._200_sayReward = "Du erh\228ltst 1.700.000 Erfahrungspunkte. "
gameforge.subquest_42._20_sayTitle = "Lehrer der Drachenmacht: "
gameforge.subquest_42._210_sayReward = "Du erh\228ltst 30.000 Yang. "
gameforge.subquest_42._220_sayReward = "Du erh\228ltst 3 Diamanten. "
gameforge.subquest_42._230_say = "Sehr gut. Nun k\246nnen wir die toten Soldaten[ENTER]beruhigen. Sie haben ihr Bestes gegeben, also[ENTER]sollen sie jetzt auch in Frieden ruhen.[ENTER]Lass mich dir eine Belohnung geben f\252r diese[ENTER]noble Tat. "
gameforge.subquest_42._30_say = "Schlimme Kriege t\246ten immer h\228ufiger junge[ENTER]M\228nner. Es sind K\228mpfer, die an der Frontlinie[ENTER]f\252r sich selbst, ihre Familie und ihr Land[ENTER]k\228mpfen. Aber nach dem Tod kamen einige nicht in[ENTER]das Nirwana. Sie blieben in dieser Welt. "
gameforge.subquest_42._40_say = "Man sagt, sie seien w\228hrend des Krieges resistent[ENTER]gegen den Tod geworden. Sie glauben, dass sie ihr[ENTER]Land immer noch verteidigen m\252ssen.[ENTER]Unsere Schamanen wollen nun eine Zeremonie[ENTER]abhalten, um diese Geister zu beruhigen. Daf\252r[ENTER]brauchen wir einen speziellen Tempelschal und[ENTER]eine Tempellehre, aber heutzutage ist es schwer,[ENTER]so etwas zu finden. K\246nntest du diese beiden[ENTER]Sachen f\252r uns holen? "
gameforge.subquest_42._50_say = "Ich h\246rte, dass der Stolze dunkle Oberst im[ENTER]Hwang-Tempel einen Tempelschal und eine[ENTER]Tempellehre besitzen soll.[ENTER]Bitte hilf mir und meinen Kameraden, diejenigen[ENTER]zu beruhigen, die f\252r ihr Land gestorben sind. "
gameforge.subquest_42._60_select = "Ich helfe dir. "
gameforge.subquest_42._70_select = "Tut mir leid, ich habe zu viel Angst. "
gameforge.subquest_42._80_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_42._90_say = "Bitte hilf uns, ihre Seelen zu beruhigen, damit[ENTER]sie in Frieden ruhen k\246nnen. Ich warte hier auf[ENTER]dich. "
gameforge.subquest_44 = {}
gameforge.subquest_44._100_sendLetter = "Die Spinne mit der Glocke "
gameforge.subquest_44._10_targetVid = "Die Spinne "
gameforge.subquest_44._110_say = "Taurean sagt, er habe einer Spinne ein Gl\246ckchen[ENTER]umgeh\228ngt. Nun m\246chte Yu-Rang wissen, ob ihr[ENTER]Freund wirklich so mutig gewesen ist, wie er[ENTER]behauptet.[ENTER]Suche nach dieser Spinne in der W\252ste. "
gameforge.subquest_44._120_say = "Hast du die Spinne mit dem Gl\246ckchen schon[ENTER]gefunden? Nein? Wahrscheinlich wirst du sie auch[ENTER]nie finden. Taurean ist ein Angsthase und wollte[ENTER]nur angeben! "
gameforge.subquest_44._130_sendLetter = "Kein Gl\246ckchen zu finden "
gameforge.subquest_44._140_sayTitle = "Viele Spinnen, kein Gl\246ckchen "
gameforge.subquest_44._150_say = "Du hast einige Spinnen get\246tet, aber kein[ENTER]Gl\246ckchen bei ihnen gefunden. Du kannst nicht[ENTER]ewig suchen. Wahrscheinlich ist es einfacher,[ENTER]Taurean zu suchen und ihn nach der Wahrheit zu[ENTER]fragen. "
gameforge.subquest_44._160_sendLetter = "Geh zu Taurean "
gameforge.subquest_44._170_targetVid = "Frage Taurean nach dem Gl\246ckchen "
gameforge.subquest_44._180_say = "Es ist kaum anzunehmen, dass Taurean wirklich so[ENTER]mutig ist, einer Spinne ein Gl\246ckchen umzuh\228ngen.[ENTER]Frage ihn am besten direkt nach der[ENTER]Wahrheit. "
gameforge.subquest_44._190_npcChat = "Sag mal, deine Wette mit Yu-Rang... "
gameforge.subquest_44._200_say = "Du wei\223t von der Wette mit Yu-Rang? Sie traut mir[ENTER]nicht und denkt, ich h\228tte es nicht geschafft.[ENTER]Sie denkt, ich w\252rde schon tot umfallen, wenn ich[ENTER]eine Riesenspinne nur ansehe. "
gameforge.subquest_44._20_npcChat = "Eine Spinne mit Gl\246ckchen...? "
gameforge.subquest_44._210_say = "Ehrlich gesagt... Also, eigentlich hat sie ja[ENTER]Recht. Ich habe mich nicht getraut, es ihr zu[ENTER]beichten, weil ich zu stolz bin. "
gameforge.subquest_44._220_say = "Aber du siehst sehr stark aus! Kannst du nicht[ENTER]f\252r mich das Gl\246ckchen an eine Babyspinne[ENTER]h\228ngen und dann sagen, dass ich es war? Bitte,[ENTER]bitte! Sonst wird sie sich f\252r den Rest meines[ENTER]Lebens \252ber mich lustig machen. "
gameforge.subquest_44._230_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_44._240_say = "Du willst es nicht machen? Aber du wirst doch[ENTER]hoffentlich nicht alles Yu-Rang erz\228hlen?![ENTER]Bitte, hilf mir. Komm wieder her, wenn du Zeit[ENTER]f\252r mich hast! "
gameforge.subquest_44._250_say = "Jetzt wird Yu-Rang nie mehr mit mir reden.[ENTER]Oder mich nur auslachen... "
gameforge.subquest_44._260_say = "Ah, ich hatte Recht: du bist tats\228chlich so[ENTER]freundlich, wie du aussiehst! Danke f\252r deine[ENTER]Hilfe. Viel Erfolg! "
gameforge.subquest_44._270_sendLetter = "Zur\252ck zu Yu-Rang "
gameforge.subquest_44._280_say = "Geh zur\252ck zu Yu-Rang und berichte ihr von[ENTER]Taureans L\252ge. "
gameforge.subquest_44._290_npcChat = "Yu-Rang ist sehr entt\228uscht von dir. "
gameforge.subquest_44._300_say = "Du hast es ihr gesagt?![ENTER]Ich kann verstehen, dass sie nicht mehr meine[ENTER]Freundin sein will. Aber es macht mich sehr[ENTER]traurig. Ich hoffe ich kann sie irgendwann[ENTER]umstimmen. Vielleicht f\228llt mir etwas Sch\246nes f\252r[ENTER]sie ein... "
gameforge.subquest_44._30_say = "Hey, kannst du mir einen Gefallen tun? Mein[ENTER]Freund Taurean war sehr ver\228rgert, weil ich ihn[ENTER]einen Feigling nannte. Er sagte, dass er[ENTER]eigentlich recht tapfer sei. Er hat mit mir eine[ENTER]Wette abgeschlossen, dass er es schaffen w\252rde,[ENTER]ein Gl\246ckchen an eine Babyspinne zu h\228ngen. Er[ENTER]erz\228hlte mir auch, dass er es schon getan h\228tte,[ENTER]aber ich kann ihm das einfach nicht glauben. "
gameforge.subquest_44._310_npcChat = "Taurean hat gelogen. "
gameforge.subquest_44._320_say = "Seine Geschichte stimmt also nicht?[ENTER]Hmm, die L\252ge an sich finde ich nicht so schlimm.[ENTER]Jeder hat seinen Stolz. Aber dann h\228tte er[ENTER]wenigstens versuchen m\252ssen, sie wahr zu machen![ENTER]Mit so einem Angsthasen will ich nicht l\228nger[ENTER]befreundet sein. "
gameforge.subquest_44._330_sayReward = "Yu-Rang gibt dir eine Belohnung f\252r deine[ENTER]Ehrlichkeit. "
gameforge.subquest_44._340_sayReward = "Du erh\228ltst 30.000 Yang. "
gameforge.subquest_44._350_sayReward = "Du erh\228ltst 350.000 Erfahrungspunkte. "
gameforge.subquest_44._360_sendLetter = "Gl\246ckchen f\252r die Spinne "
gameforge.subquest_44._370_say = "Geh in die W\252ste zu den Babyspinnen und versuche,[ENTER]einer von ihnen Taureans Gl\246ckchen umzuh\228ngen. "
gameforge.subquest_44._380_npcChat = "Wegen des Gl\246ckchens... "
gameforge.subquest_44._390_say = "Du hast das Gl\246ckchen noch nicht angeh\228ngt?[ENTER]Dann mach es bitte bald. Und pass auf, dass[ENTER]Yu-Rang dich nicht erwischt! "
gameforge.subquest_44._400_sendLetter = "Geschafft! "
gameforge.subquest_44._40_say = "Ich wei\223, dass ich meinem Freund vertrauen[ENTER]sollte. Ich m\246chte aber dennoch wissen, ob er es[ENTER]wirklich getan hat. F\252r mich ist es zu gef\228hrlich[ENTER]in der W\252ste. Du siehst sehr stark aus. Es wird[ENTER]sicher leicht f\252r dich. W\252rdest du gehen und f\252r[ENTER]mich nachsehen? "
gameforge.subquest_44._410_say = "Es war sehr schwierig, aber du hast es endlich[ENTER]geschafft, das Gl\246ckchen einer Babyspinne[ENTER]umzuh\228ngen. Gehe nun zu Yu-Rang und erz\228hle ihr,[ENTER]dass das Taureans Werk sei. "
gameforge.subquest_44._420_npcChat = "Das Gl\246ckchen ist angebracht. "
gameforge.subquest_44._430_say = "Du hast es geschafft? Das ist toll![ENTER]Dann erz\228hle schnell Yu-Rang davon, damit sie mir[ENTER]endlich glaubt! "
gameforge.subquest_44._440_npcChat = "Taurean hat die Wahrheit gesagt. "
gameforge.subquest_44._450_say = "Wie bitte? Du hast eine Spinne mit Gl\246ckchen[ENTER]gefunden? Dann hat Taurean es tats\228chlich getan.[ENTER]Das h\228tte ich niemals f\252r m\246glich gehalten.[ENTER]Vielleicht wird doch noch einmal ein richtiger[ENTER]Mann aus ihm. Danke, dass du das f\252r mich[ENTER]\252berpr\252ft hast. Hier ist eine Belohnung f\252r deine[ENTER]Hilfe. "
gameforge.subquest_44._460_sendLetter = "Zur\252ck zu Taurean "
gameforge.subquest_44._470_targetVid = "Zur\252ck zu Taurean "
gameforge.subquest_44._480_say = "Du hast Yu-Rang erz\228hlt, dass ihr Freund[ENTER]tats\228chlich einer Babyspinne eine Glocke[ENTER]umgeh\228ngt habe.[ENTER]Gehe nun zur\252ck zu Taurean und berichte ihm von[ENTER]der erfolgreichen T\228uschung. "
gameforge.subquest_44._490_npcChat = "Yu-Rang glaubt dir. "
gameforge.subquest_44._500_say = "Danke vielmals. Nun verachtet Yu-Rang mich nicht.[ENTER]Wir m\252ssen das f\252r immer geheimhalten![ENTER]Versprochen? Bis bald! "
gameforge.subquest_44._50_select = "Annehmen "
gameforge.subquest_44._510_sayReward = "Taurean gibt dir eine Belohnung f\252r die[ENTER]Unterst\252tzung bei seiner L\252ge:[ENTER]Du erh\228ltst 30.000 Yang. "
gameforge.subquest_44._520_sayReward = "Du erh\228ltst 700.000 Erfahrungspunkte. "
gameforge.subquest_44._60_say = "M\246chtest du die Quest f\252r immer aufgeben? "
gameforge.subquest_44._70_say = "Warum nicht? Hast du etwa auch Angst?[ENTER]Besuche mich, wenn du deine Meinung ge\228ndert[ENTER]hast. "
gameforge.subquest_44._80_say = "Oh, hast du etwa auch Angst? Aber du bist doch[ENTER]viel gr\246\223er und st\228rker als ich! Haha, du bist[ENTER]feige! Dann muss ich wohl jemand anders fragen. "
gameforge.subquest_44._90_say = "Die Spinnen leben in der W\252ste.[ENTER]Du bist stark. Ich bin sicher, du wirst es[ENTER]schaffen. Viel Gl\252ck! "
gameforge.subquest_45 = {}
gameforge.subquest_45._100_sayTitle = "Hole die geheimen Informationen "
gameforge.subquest_45._10_npcChat = "Die Sache mit dem Dunklen Tempel "
gameforge.subquest_45._110_say = "Du hast nun die Tempelehre, den Tempelschal und[ENTER]die \220bersetzung der Fluchsammlung in deinem[ENTER]Besitz. Bringe die Gegenst\228nde zu Soon. "
gameforge.subquest_45._120_say = "Wenn du Soon, dem B\252cherwurm, hilfst, kann er[ENTER]seine Studien \252ber den Dunklen Tempel fortf\252hren.[ENTER]Dies ist nur m\246glich, wenn er in den Besitz von[ENTER]folgenden Sachen kommt: Die Tempellehre, den[ENTER]Tempelschal und die \220bersetzung der[ENTER]Fluchsammlung. Besorge diese Sachen und bringe[ENTER]sie dann zu Soon. Du findest sie im Hwang-Tempel[ENTER]im Tal von Seungryong. "
gameforge.subquest_45._130_npcChat = "Die Sachen aus dem Dunklen Tempel "
gameforge.subquest_45._140_say = "Ah, du hast sie! Vielen Dank.[ENTER]Was die Wesen im Tempel betrifft, nun, das ist[ENTER]einfach: sie sind gef\228hrlich. Aber das hast du ja[ENTER]am eigenen Leib erfahren.[ENTER]Au\223erdem scheinen sie b\246sen G\246ttern zu dienen.[ENTER]Ich kenne keine Details, aber ich vermute, sie[ENTER]planen Schlimmes. "
gameforge.subquest_45._150_say = "Jetzt, wo ich einige ihrer heiligen[ENTER]Gegenst\228nde besitze, werde ich hoffentlich mehr[ENTER]herausfinden k\246nnen. Am besten ich beginne mit[ENTER]der Tempellehre.[ENTER]Mal sehen... Hmmhm... Aha...[ENTER]Warum stehst du noch hier rum? Hast du nichts zu[ENTER]tun? "
gameforge.subquest_45._160_sayReward = "Du erh\228ltst 7.000.000 Erfahrungspunkte. "
gameforge.subquest_45._170_sayReward = "Du erh\228ltst 70.000 Yang. "
gameforge.subquest_45._180_sayReward = "Du erh\228ltst ein Buch des Anf\252hrers. "
gameforge.subquest_45._190_say = "Was? Du hast sie nicht?[ENTER]Beeil dich, wenn du einen Auftrag annimmst.[ENTER]Schnell, geh los! "
gameforge.subquest_45._200_select = "Noch einmal versuchen "
gameforge.subquest_45._20_say = "Irgendetwas ist im Dunklen Tempel im Gange. Ich[ENTER]denke, es sind gef\228hrliche Wesen, die dort die[ENTER]alten Zauber studieren.[ENTER]Die Geheimnisse des Dunklen Tempels sind schwer[ENTER]zu durchdringen, auch f\252r mich. Aber ich bin[ENTER]sicher, dass die Motive dieser Wesen mehr als[ENTER]zweifelhaft sind. Ich muss mehr dar\252ber[ENTER]herausfinden! "
gameforge.subquest_45._210_say = "Dann werde ich wohl einen st\228rkeren Helden fragen[ENTER]m\252ssen. Leb wohl. "
gameforge.subquest_45._220_say = "Danke.[ENTER]Ich hoffe du hast diesmal mehr Erfolg! "
gameforge.subquest_45._30_say = "Ich ben\246tige Fakten f\252r meine Studien.[ENTER]Ich denke, die Tempellehre, der Tempelschal und[ENTER]die \220bersetzung der Fluchsammlung k\246nnten mehr[ENTER]als hilfreich sein.[ENTER]Kannst du mir diese Dinge bringen? Ich w\228re dir[ENTER]sehr dankbar. Und tr\246dle nicht zu lange, ich[ENTER]brauche sie bald! "
gameforge.subquest_45._40_select = "Ich werde sofort gehen. "
gameforge.subquest_45._50_say = "Willst du die Aufgabe annehmen? "
gameforge.subquest_45._60_say = "Ich bitte dich um deine Hilfe![ENTER]Wenn du besch\228ftigt bist, dann komm sp\228ter[ENTER]wieder. Vielleicht hast du dann mehr Zeit.[ENTER]Ich warte auf dich. "
gameforge.subquest_45._70_say = "Ich bitte um deine Hilfe und du drehst dich[ENTER]einfach um?[ENTER]Ach, wer braucht dich schon... Los, verschwinde! "
gameforge.subquest_45._80_say = "Danke! "
gameforge.subquest_45._90_makequestbutton = "Dunkler Tempel "
gameforge.subquest_46 = {}
gameforge.subquest_46._100_say = "Viel Erfolg bei deiner Suche.[ENTER]Nur wenn ich die richtigen Materialien habe, kann[ENTER]ich auch das richtige Porzellan produzieren.[ENTER]Meine K\228ufer warten schon ungeduldig! "
gameforge.subquest_46._10_targetVid = "Das Geheimnis des blassgr\252nen Porzellans "
gameforge.subquest_46._110_makequestbutton = "Blassgr\252nes Porzellan "
gameforge.subquest_46._120_qSetTitle = "Blassgr\252nes Porzellan "
gameforge.subquest_46._130_say = "Du hast nun alle Materialien, die Yonah f\252r die[ENTER]Herstellung des Seladon-Porzellans ben\246tigt.[ENTER]Bringe sie zu ihm. "
gameforge.subquest_46._140_say = "Damit Yonah das blassgr\252ne Porzellan perfekt[ENTER]herstellen kann, braucht er diese Materialien:[ENTER]W\252stensand von den W\252stenbanditen in der W\252ste[ENTER]Yongbi, Kristallerz aus einer entsprechenden[ENTER]Erzader und Affenblut von den Starken Steinaffen[ENTER]oder Starken Goldaffen im Sangsun Dong.[ENTER]Finde alle drei Materialien und bringe sie Yonah! "
gameforge.subquest_46._150_targetVid = "Das Geheimnis des blassgr\252nen Porzellans "
gameforge.subquest_46._160_npcChat = "Ich habe die Materialien besorgt. "
gameforge.subquest_46._170_say = "Du hast es geschafft! Ich danke dir![ENTER]Mit der richtigen Technik und den passenden[ENTER]Materialien kann ich nun wundersch\246nes,[ENTER]blassgr\252nes Porzellan herstellen. Der Verkauf[ENTER]wird ein Segen f\252r meinen Geldbeutel sein. Hier,[ENTER]nimm diese Belohnung. Du hast sie dir verdient.[ENTER]Ich werde sofort mit der Produktion beginnen! "
gameforge.subquest_46._180_sayReward = "Du erh\228ltst 3.000.000 Erfahrungspunkte. "
gameforge.subquest_46._190_sayReward = "Du erh\228ltst 30.000 Yang. "
gameforge.subquest_46._20_say = "Hallo Abenteurer! Hast du mir nicht letztens[ENTER]Soons Rezept f\252r Seladon-Porzellan gebracht? Ich[ENTER]habe ein Problem damit... Obwohl ich die Technik[ENTER]nun kenne, gelingt es mir einfach nicht,[ENTER]richtiges Seladon-Porzellan herzustellen.[ENTER]Wahrscheinlich liegt es daran, dass ich es mit[ENTER]meinen \252blichen Zutaten versucht habe, statt den[ENTER]schwer zu beschaffenden Materialien, die auf dem[ENTER]Rezept stehen. "
gameforge.subquest_46._30_say = "Ich brauche feink\246rnigen W\252stensand, Kristallerz[ENTER]und Affenblut. Wenn man diese mischt und dem Lehm[ENTER]hinzuf\252gt, wird er beim Brennen enorm fest. Zudem[ENTER]erh\228lt die Glasur dadurch die typische blassgr\252ne[ENTER]Farbe, die an Jade erinnert. Diese Farbe ist sehr[ENTER]beliebt bei den Kunden und ich muss dringend mehr[ENTER]verkaufen! "
gameforge.subquest_46._40_say = "Den W\252stensand erh\228ltst du bei den[ENTER]W\252stenbanditen, Kristallerz kannst du aus einer[ENTER]Erzader gewinnen und f\252r das Affenblut musst du[ENTER]Affen im Sangsun Dong t\246ten. Kannst du mir diese[ENTER]Materialien besorgen? Ich wei\223, es wird nicht[ENTER]einfach, aber ich werde dich reich entlohnen. "
gameforge.subquest_46._50_select = "Annehmen "
gameforge.subquest_46._60_select = "Ablehnen "
gameforge.subquest_46._70_say = "M\246chtest du die Quest f\252r immer aufgeben? "
gameforge.subquest_46._80_say = "Wenn du gerade zu besch\228ftigt bist, komm doch[ENTER]sp\228ter nochmal vorbei. "
gameforge.subquest_46._90_say = "Du gibst auf? Wirklich?[ENTER]Dann muss ich mich selber auf die Suche begeben.[ENTER]Ich brauche dieses Porzellan wirklich dringend.[ENTER]Auf Wiedersehen und alles Gute. "
