gameforge.subquest_48._100_sayTitle = "Suche nach dem Spion "
gameforge.subquest_48._10_npcChat = "Finde den Spion "
gameforge.subquest_48._110_say = "Einer der Spione des Hauptmanns lebt als Fischer[ENTER]im Dorf Pyungmoo im Jinno-Reich. Nimm unauff\228llig[ENTER]Kontakt zu ihm auf und \252berbringe seinen Bericht[ENTER]dem Hauptmann. "
gameforge.subquest_48._120_say = "Einer der Spione des Hauptmanns lebt als Fischer[ENTER]im Dorf Yongan im Shinsoo-Reich. Nimm[ENTER]unauff\228llig Kontakt zu ihm auf und \252berbringe[ENTER]seinen Bericht dem Hauptmann. "
gameforge.subquest_48._130_say = "Einer der Spione des Hauptmanns lebt als Fischer[ENTER]im Dorf Joan im Chunjo-Reich. Nimm[ENTER]unauff\228llig Kontakt zu ihm auf und \252berbringe[ENTER]seinen Bericht dem Hauptmann. "
gameforge.subquest_48._140_npcChat = "Was machst du gerade? "
gameforge.subquest_48._150_say = "Psst, sei leise! Du verscheuchst alle Fische.[ENTER]Was willst du eigentlich hier? Du bist so laut[ENTER]und ungeschickt. Du kannst kaum zum Angeln[ENTER]gekommen sein. "
gameforge.subquest_48._160_say = "Ah, ich verstehe. Ich habe dich schon l\228ngst[ENTER]erwartet. Du kommst sp\228t. Es war nicht leicht, an[ENTER]die Informationen zu kommen, ohne entdeckt zu[ENTER]werden. \220berall lauern Feinde und warten nur[ENTER]darauf, dass man sich verr\228t. "
gameforge.subquest_48._170_say = "Halten wir uns hier nicht zu lange auf! Nicht,[ENTER]dass uns noch jemand entdeckt. Hier hast du die[ENTER]Dokumente. Mache dich geschwind auf den Weg und[ENTER]\252berbringe sie direkt dem Hauptmann! "
gameforge.subquest_48._180_say = "Einen kleinen Moment noch! Ich habe hier etwas[ENTER]f\252r dich. Ein kleines Geschenk. So, nun mach dich[ENTER]auf den Weg. "
gameforge.subquest_48._190_sayReward = "Neugierig \246ffnest du das P\228ckchen, um[ENTER]nachzusehen, was der Spion dir geschenkt hat. "
gameforge.subquest_48._200_say = "Toll! Gegrillte Rotfeder! Offensichtlich versteht[ENTER]der Spion tats\228chlich etwas vom Fischen. "
gameforge.subquest_48._20_say = "Steh bequem, Soldat![ENTER]Da wir mit den Nachbarl\228ndern in feindlicher[ENTER]Beziehung leben, ist es sehr wichtig, Freunde zu[ENTER]haben, die dort verdeckt kundschaften. So kommen[ENTER]wir an Informationen und k\246nnen uns auf[ENTER]m\246gliche Angriffe vorbereiten. Es ist von[ENTER]gr\246\223ter Wichtigkeit, dass diese Spione nicht[ENTER]enttarnt werden. "
gameforge.subquest_48._210_sayReward = "Du hast 3 gegrillte Rotfedern bekommen. "
gameforge.subquest_48._220_sendLetter = "Zur\252ck zum Hauptmann "
gameforge.subquest_48._230_targetVid = "Der Hauptmann "
gameforge.subquest_48._240_say = "Die gef\228hrliche Reise nach Pyungmoo im Reich[ENTER]Jinno war erfolgreich: Du hast den Bericht des[ENTER]als Fischer getarnten Spions erhalten.[ENTER]Kehre nun schnell in dein Reich zur\252ck und bring[ENTER]dem Hauptmann die Informationen. "
gameforge.subquest_48._250_say = "Die gef\228hrliche Reise nach Yongan im Reich[ENTER]Shinsoo war erfolgreich: Du hast den Bericht des[ENTER]als Fischer getarnten Spions erhalten.[ENTER]Kehre nun schnell in dein Reich zur\252ck und bring[ENTER]dem Hauptmann die Informationen. "
gameforge.subquest_48._260_say = "Die gef\228hrliche Reise nach Joan im Reich Chunjo[ENTER]war erfolgreich: Du hast den Bericht des als[ENTER]Fischer getarnten Spions erhalten.[ENTER]Kehre nun schnell in dein Reich zur\252ck und bring[ENTER]dem Hauptmann die Informationen. "
gameforge.subquest_48._270_npcChat = "Die Mission war erfolgreich! "
gameforge.subquest_48._280_say = "Sind das die Dokumente? Fantastisch! Ich danke[ENTER]dir. Nun kennen wir die Pl\228ne unserer Feinde und[ENTER]k\246nnen die richtigen Ma\223nahmen treffen, um uns zu[ENTER]sch\252tzen. Du hast deinem Reich einen gro\223en[ENTER]Dienst erwiesen! "
gameforge.subquest_48._290_sayReward = "Du erh\228ltst 5.500.000 Erfahrungspunkte. "
gameforge.subquest_48._300_sayReward = "Du erh\228ltst 50.000 Yang. "
gameforge.subquest_48._30_say = "Du kennst doch sicherlich Yu-Hwan, den Musiker?[ENTER]Auch er ist ein Spion und arbeitet f\252r unser[ENTER]Land. Aber ein einzelner Spion reicht nicht aus.[ENTER]So haben wir mehrere \252ber die ganze Welt[ENTER]verteilt. Einer von ihnen h\228lt sich als Fischer[ENTER]im ersten Dorf auf. "
gameforge.subquest_48._40_say = "Da ich nicht in direkten Kontakt zu ihm treten[ENTER]kann, ohne seine Tarnung zu gef\228hrden, bin ich[ENTER]auf die Mithilfe von furchtlosen Soldaten[ENTER]angewiesen. Ja, ich meine dich! Geh f\252r mich zu[ENTER]diesem Fischer und bring mir seinen neuesten[ENTER]Bericht. Es ist von h\246chster Wichtigkeit f\252r[ENTER]die Sicherheit des Reiches! "
gameforge.subquest_48._50_say = "Willst du die Quest f\252r immer aufgeben? "
gameforge.subquest_48._60_say = "Du willst dich erst noch vorbereiten? Dann komm[ENTER]sp\228ter wieder vorbei. Ich erwarte dich. Aber[ENTER]z\246gere nicht zu lange, ich brauche diesen[ENTER]Bericht! "
gameforge.subquest_48._70_say = "Was ist denn los mit dir? Du hast doch letztes[ENTER]Mal so gro\223artige Arbeit f\252r uns geleistet! Und[ENTER]jetzt l\228sst du dein Reich im Stich? Aber da kann[ENTER]ich wohl nichts machen. Leb wohl. "
gameforge.subquest_48._80_say = "Ich wusste, dass auf dich Verlass ist.[ENTER]Viel Erfolg! Und pass auf dich auf! "
gameforge.subquest_48._90_makequestbutton = "Den Spion treffen "
gameforge.subquest_49 = {}
gameforge.subquest_49._100_sayTitle = "Was ist Bingsu "
gameforge.subquest_49._10_targetVid = "Bingsu? "
gameforge.subquest_49._110_say = "Taurean hat sich mit Harang gestritten, weil er[ENTER]ihr nicht glaubt, dass man im Sommer Eis[ENTER]herstellen kann. Geh zu Harang und frage sie, was[ENTER]sie \252ber Bingsu wei\223. "
gameforge.subquest_49._120_qSetTitle = "Harang fragen "
gameforge.subquest_49._130_targetVid = "Frage Harang "
gameforge.subquest_49._140_npcChat = "Was ist Bingsu? "
gameforge.subquest_49._150_say = "Dieser Taurean tut immer so, als w\252sste er alles.[ENTER]Dabei kennt er nicht einmal Bingsu! Wie kann man[ENTER]so etwas Leckeres nicht kennen?[ENTER]Du wei\223t es auch nicht?? Dann geh am besten[ENTER]gleich zu Octavio ins Nachbardorf. Er ist ein[ENTER]ber\252hmter Koch und kennt alle guten Rezepte.[ENTER]Einmal hat er mir Bingsu gemacht, mmmmh... Er[ENTER]wird dir beweisen, dass ich Recht habe! "
gameforge.subquest_49._160_makequestbutton = "Auf zu Octavio "
gameforge.subquest_49._170_say = "Taurean m\246chte unbedingt wissen, was Bingsu ist.[ENTER]Geh f\252r ihn zum Restaurantbesitzer Octavio. Er[ENTER]kann dir sicherlich weiterhelfen. "
gameforge.subquest_49._180_npcChat = "Wei\223t du, was Bingsu ist? "
gameforge.subquest_49._190_say = "Bingsu? Nat\252rlich kenne ich das. Jeder gute Koch[ENTER]wei\223, wie man Bingsu herstellt! Zun\228chst ben\246tigt[ENTER]man fein gemahlenes Eis. Darauf kommt dann[ENTER]Zucker, klein geschnittene Reiskuchen und[ENTER]frisches Obst zum Dekorieren. "
gameforge.subquest_49._200_say = "Warum fragst du? Weil Taurean und Harang sich[ENTER]streiten? Das ist ja nichts Neues. Aber Harang[ENTER]hat Recht. Besonders in hei\223en Sommern ist[ENTER]Bingsu eine beliebte Speise.[ENTER]Taurean ist ein guter Junge, auch wenn er[ENTER]manchmal etwas engherzig ist. Wenn du mir die[ENTER]Zutaten besorgst, k\246nnte ich Bingsu f\252r ihn[ENTER]herstellen. "
gameforge.subquest_49._20_npcChat = "Bingsu? "
gameforge.subquest_49._210_say = "Ich w\252rde Taurean gerne eine Freude machen und[ENTER]ihm Bingsu servieren. Was meinst du? Kannst du[ENTER]mir Eis vom Berg Sohan holen? "
gameforge.subquest_49._220_say = "M\246chtest du die Quest f\252r immer aufgeben? "
gameforge.subquest_49._230_say = "Magst du kein Eis? Oder hast du schon zu viel[ENTER]gegessen? Es ist f\252r Taurean, also \252berleg es dir[ENTER]bitte nochmal. "
gameforge.subquest_49._240_say = "Schade. Taurean wird sehr entt\228uscht sein.[ENTER]Bis dann. "
gameforge.subquest_49._250_say = "Sehr gut. Ich ben\246tige Eisklumpen von dem[ENTER]Verzauberten Eis auf dem Berg Sohan. Bring mir 50[ENTER]St\252ck, dann kann ich leckeres Bingsu machen. "
gameforge.subquest_49._260_targetVid = "Geh zu Octavio "
gameforge.subquest_49._270_say = "%s[ENTER]Du hast die Eisklumpen f\252r Taureans Bingsu.[ENTER]Bringe sie zu Octavio. "
gameforge.subquest_49._275_say = "Eisklumpen besorgt "
gameforge.subquest_49._280_say = "%s[ENTER]Octavio hat sich bereit erkl\228rt, f\252r Taurean[ENTER]Bingsu herzustellen, braucht aber Eis daf\252r. T\246te[ENTER]Verzaubertes Eis auf dem Berg Sohan und sammle 50[ENTER]Klumpen Eis. Bringe diese dann zu Octavio. "
gameforge.subquest_49._285_say = "Suche nach dem Eis "
gameforge.subquest_49._290_npcChat = "Hier, ich habe Eisklumpen mitgebracht. "
gameforge.subquest_49._300_say = "Ah, sehr gut! Damit ist der schwierigste Teil der[ENTER]Bingsuherstellung erledigt. Jetzt muss ich nur[ENTER]noch ein bisschen Zucker... und etwas Obst...[ENTER]Bitte sehr! Ein Eis f\252r Taurean. Nimm es gleich[ENTER]mit, dann vergisst er bald seinen \196rger. "
gameforge.subquest_49._30_sayTitle = "Taurean: "
gameforge.subquest_49._310_say = "Es tut mir leid, aber das reicht nicht. Du musst[ENTER]noch mehr besorgen, sonst wird es nur eine winzig[ENTER]kleine Portion! "
gameforge.subquest_49._320_select = "Weiter versuchen "
gameforge.subquest_49._330_say = "Ich wei\223, der Weg ist weit und die Monster stark.[ENTER]Wenn es dir zu schwierig ist, kann man nichts[ENTER]machen. Bis dann. "
gameforge.subquest_49._340_say = "Versuche es ruhig noch einmal. Mit deinem Mut und[ENTER]deiner Ausdauer kannst du es schaffen! "
gameforge.subquest_49._350_targetVid = "Bingsu! "
gameforge.subquest_49._360_say = "Es ist vollbracht: Octavio hat aus dem Eis vom[ENTER]Berg Sohan Bingsu hergestellt. Jetzt schnell[ENTER]zur\252ck zu Taurean, bevor es schmilzt. "
gameforge.subquest_49._370_npcChat = "Hier ist das Bingsu! "
gameforge.subquest_49._380_say = "Das ist Bingsu? Das schmeckt wirklich gut. S\252\223[ENTER]und k\252hl. Sowas habe ich noch nie gegessen,[ENTER]danke! Harang hatte also recht. Jetzt werde ich[ENTER]mich wohl bei ihr entschuldigen m\252ssen... "
gameforge.subquest_49._390_sayReward = "Du erh\228ltst 6.000.000 Erfahrungspunkte. "
gameforge.subquest_49._400_sayReward = "Du erh\228ltst 70.000 Yang. "
gameforge.subquest_49._40_say = "Heut habe ich mich mit Harang gestritten.[ENTER]Ich k\246nnte sie...[ENTER]Sie behauptet, dass es etwas sehr Leckeres gibt,[ENTER]das aus fein zerkleinertem Eis besteht.[ENTER]Bingsu hei\223t es. "
gameforge.subquest_49._410_sayReward = "Du erh\228ltst eine Schriftrolle des Krieges. "
gameforge.subquest_49._420_say = "Hast daran gedacht, mir Bingsu mitzubringen? "
gameforge.subquest_49._430_say = "Oje, das habe ich ganz vergessen! Hmm, ob ich es[ENTER]noch weiter versuche? Oder soll ich es lieber[ENTER]lassen? "
gameforge.subquest_49._440_select = "Ich mache weiter. "
gameforge.subquest_49._450_select = "Ich gebe auf. "
gameforge.subquest_49._460_say = "Ich schaffe es nicht.[ENTER]Es tut mir leid.  "
gameforge.subquest_49._50_say = "So etwas ist eigentlich nur im Winter machbar,[ENTER]wenn es richtig kalt ist. Trotzdem behauptet sie[ENTER]st\228ndig, dass es geht. Kannst du herausfinden, ob[ENTER]man dieses Bingsu auch im Sommer herstellen kann?[ENTER]Wenn es so etwas \252berhaupt gibt... "
gameforge.subquest_49._60_say = "Dieses Bingsu ist bestimmt lecker! Bist du[ENTER]sicher, dass du mir niemals helfen willst,[ENTER]welches herzustellen? "
gameforge.subquest_49._70_say = "Wenn du es sp\228ter erledigen[ENTER]m\246chtest, sage es mir bitte. "
gameforge.subquest_49._80_say = "Ich w\252rde ja so gerne mal Bingsu probieren...[ENTER]Aber du hast recht. Harang wollte bestimmt blo\223[ENTER]angeben und es gibt \252berhaupt kein Bingsu![ENTER]Mach's gut. "
gameforge.subquest_49._90_say = "Danke, dass du mir hilfst. Lass es mich wissen,[ENTER]wenn du etwas herausfindest. Dann kann ich dieser[ENTER]Harang die Meinung sagen! "
gameforge.training_grandmaster_skill = {}
gameforge.training_grandmaster_skill._100_sayReward = "Es stehen nicht gen\252gend Rangpunkte f\252r[ENTER]das Training zur Verf\252gung. "
gameforge.training_grandmaster_skill._10_answer = "trainieren "
gameforge.training_grandmaster_skill._10_sayTitle = "Fertigkeitstraining der Gro\223meister "
gameforge.training_grandmaster_skill._110_sayReward = "Erforderliche Rangpunkte: %s -> %s "
gameforge.training_grandmaster_skill._120_sayReward = "Deine Rangpunkte sind im negativen Bereich.[ENTER]Das bedeutet, dass du zum Steigern einer[ENTER]Gro\223meister-Fertigkeit doppelt so viele[ENTER]Rangpunkte ausgeben musst, wie jemand,[ENTER]dessen Punkte sich im positiven Bereich befinden. "
gameforge.training_grandmaster_skill._130_sayReward = "Erforderliche Rangpunkte: %s "
gameforge.training_grandmaster_skill._140_sayReward = "Wenn du jetzt trainierst, werden deine[ENTER]Rangpunkte in den negativen Bereich fallen. "
gameforge.training_grandmaster_skill._150_sayReward = "Best\228tigen! "
gameforge.training_grandmaster_skill._160_say = "Wenn du jetzt eine Gro\223meisterfertigkeit[ENTER]steigerst, k\246nnten deine Rangpunkte in den[ENTER]negativen Bereich fallen, da du im Moment nur[ENTER]wenige besitzt. Wenn du wirklich trainieren[ENTER]willst, gib das Wort 'trainieren' in die[ENTER]Befehlszeile ein. "
gameforge.training_grandmaster_skill._170_sayReward = "trainieren "
gameforge.training_grandmaster_skill._180_say = "Willst du nicht trainieren, dr\252cke einfach[ENTER]'ENTER'. "
gameforge.training_grandmaster_skill._190_sayReward = "Erfolgreich! "
gameforge.training_grandmaster_skill._200_say = "Herzlichen Gl\252ckwunsch! Du hast es geschafft. "
gameforge.training_grandmaster_skill._20_say = "Du bist bis jetzt noch keiner Lehre beigetreten. "
gameforge.training_grandmaster_skill._210_say = "%s ist nun eine Gro\223meister-Fertigkeit. "
gameforge.training_grandmaster_skill._220_say = "Dies bedeutet, dass du diese Fertigkeit nun[ENTER]perfekt beherrschst und nicht mehr weiter[ENTER]verbessern kannst. "
gameforge.training_grandmaster_skill._230_say = "Herzlichen Gl\252ckwunsch! Du hast es geschafft.[ENTER]Durch das Fertigkeitstraining der Gro\223meister[ENTER]stieg "
gameforge.training_grandmaster_skill._240_say = "%s auf Level %s. "
gameforge.training_grandmaster_skill._250_sayReward = "Du hast dein Level erfolgreich gesteigert! "
gameforge.training_grandmaster_skill._260_sayReward = "Du hast %s Rangpunkte verbraucht. "
gameforge.training_grandmaster_skill._270_sayReward = "Fehlgeschlagen! "
gameforge.training_grandmaster_skill._280_say = "Du hast deine Fertigkeiten nicht verbessern[ENTER]k\246nnen. "
gameforge.training_grandmaster_skill._290_sayReward = "Du hast einige Rangpunkte verloren[ENTER]und den Seelenstein verbraucht. "
gameforge.training_grandmaster_skill._30_say = "Da du die Exorzismus-Schriftrolle gelesen hast,[ENTER]kannst du weiter trainieren, ohne eine Pause[ENTER]einlegen zu m\252ssen. "
gameforge.training_grandmaster_skill._40_say = "Wenn du dein Training absolviert hast, musst du[ENTER]einen halben Tag Pause machen. Versuche es sp\228ter[ENTER]noch einmal oder benutze eine[ENTER]Exorzismus-Schriftrolle. "
gameforge.training_grandmaster_skill._50_say = "Du hast noch keine Fertigkeit so weit erlernt,[ENTER]dass du den Status des Gro\223meisters erlangen[ENTER]kannst. "
gameforge.training_grandmaster_skill._60_say = "Bitte w\228hle eine Fertigkeit aus, in der du den[ENTER]Status des Gro\223meisters erlangen m\246chtest. "
gameforge.training_grandmaster_skill._70_chat = "Aktuelle Rangpunkte: %s "
gameforge.training_grandmaster_skill._75_chat = " Erforderliche Rangpunkte:  "
gameforge.training_grandmaster_skill._80_stringFormat = "%s Gro\223meister Fertigkeitstraining "
gameforge.training_grandmaster_skill._90_say = "Das Gro\223meistertraining verbraucht Rangpunkte.[ENTER]Es kann also sein, dass du in den negativen[ENTER]Punktebereich f\228llst. "
gameforge.training_mount = {}
gameforge.training_mount._01_say = "Tut mir leid, aber du hast noch nicht die n\246tige[ENTER]Reiterfahrung, um dein Mount zu verbessern. Daf\252r[ENTER]solltest du mindestens die Kampfpferd-Lizenz[ENTER]haben. "
gameforge.training_mount._02_say = "Tut mir leid, ohne die richtigen Dokumente kann[ENTER]ich nichts f\252r dich tun. Versuche nicht noch mal,[ENTER]mich \252bers Ohr zu hauen, sonst lasse ich dich[ENTER]daf\252r bezahlen. "
gameforge.training_mount._03_say = "Wo ist dein Reittier-Siegel? Ohne dieses Siegel[ENTER]kann ich auch kein Mount verbessern. Schau mal[ENTER]hinter der drehenden M\252nze. Dort findest du[ENTER]Urkunden, die du bei mir gegen ein[ENTER]Reittier-Siegel eintauschen kannst. "
gameforge.training_mount._04_say = "Ich m\246chte ein neues Mount reiten! "
gameforge.training_mount._05_say = "Hey! Du reitest noch immer auf einem Pferd?[ENTER]Ist das zu fassen? Heutzutage k\246nnen wir doch[ENTER]Wildtiere z\228hmen. "
gameforge.training_mount._06_say = "Um gez\228hmte Wildtiere f\252r den Kampf zu[ENTER]trainieren, solltest du allerdings gute[ENTER]Reitkenntnisse besitzen. Au\223erdem ben\246tigst du[ENTER]folgende Gegenst\228nde: die Rolle der Evolution, um[ENTER]dein Mount zu einem Wilden Reittier zu[ENTER]verbessern, und die Rolle der Mutation, um es zu[ENTER]einem Tapferen Reittier zu machen. "
gameforge.training_mount._07_say = "Wenn du Fragen hast, suche mich jederzeit wieder[ENTER]auf. Ich werde dir helfen, so gut ich kann. "
gameforge.training_mount._08_say = "Ich will mein Mount verbessern! "
gameforge.training_mount._09_say = "Du willst also dein Mount verbessern? Wei\223t du[ENTER]denn, wie das geht? Also gut, ich werde es dir[ENTER]erkl\228ren. "
gameforge.training_mount._10_say = "Um dein Mount zu einem Wilden Reittier zu[ENTER]verwandeln, musst du dich auf die Suche nach der[ENTER]Rolle der Evolution begeben. Finde die Rolle der[ENTER]Mutation, damit du das Wilde zu einem Tapferen[ENTER]Reittier ausbilden kannst. Es hei\223t, sie seien in[ENTER]einem fernen Land, bewohnt von gef\228hrlichen[ENTER]Giganten, versteckt! "
gameforge.training_mount._11_say = "Bringe mir eine dieser Rollen und ich werde dein[ENTER]Mount verbessern. Du hast sie nicht zuf\228llig[ENTER]schon bei dir? "
gameforge.training_mount._12_say = "Ja, ich m\246chte mein Mount verbessern! "
gameforge.training_mount._13_say = "Nein, jetzt nicht. "
gameforge.training_mount._14_say = "Ah, du hast eine der Rollen dabei. Welche ist[ENTER]es denn? Mit der Rolle der Evolution bildest du[ENTER]dein unerfahrenes Jungtier f\252r den Kampf aus. Mit[ENTER]der Rolle der Mutation kannst du es dann zum[ENTER]Tapferen Reittier verbessern. "
gameforge.training_mount._15_2_say = "Ich habe die Rolle der Mutation. "
gameforge.training_mount._15_say = "Ich habe die Rolle der Evolution. "
gameforge.training_mount._16_say = "Ich habe keine der Rollen dabei. "
gameforge.training_mount._17_say = "Ah, schau an - die Rolle der Evolution! Dann lass[ENTER]mich mal einen Blick auf dein Reittier-Siegel[ENTER]werfen. So mancher hat schon versucht, mich mit[ENTER]einer F\228lschung reinzulegen! Ich werde[ENTER]zuerst seine Echtheit pr\252fen. Gib es mir mal her.[ENTER](Ziehe das Siegel auf den Stallburschen.) "
gameforge.training_mount._18_say = "Die Rolle der Mutation! Bisher kannte ich sie[ENTER]nur aus Erz\228hlungen. Ich habe sie noch nie in den[ENTER]H\228nden gehalten. Zeige mir nun dein[ENTER]Reittier-Siegel. Ich werde es gegen ein[ENTER]m\228chtigeres austauschen, sobald ich seine[ENTER]Echtheit best\228tigt habe. (Ziehe das Siegel auf[ENTER]den Stallburschen.) "
gameforge.training_mount._19_say = "Sobald du eine der Rollen gefunden hast, kehre[ENTER]zu mir zur\252ck. Dann kann ich dein altes[ENTER]Reittier-Siegel in ein m\228chtigeres tauschen. "
gameforge.training_mount._20_say = "Dein Reittier-Siegel hat wahrhaftig schon bessere[ENTER]Tage gesehen. Warte, ich werde es[ENTER]gegen ein neues eintauschen.[ENTER]Bitte, hier hast du es. Nun kannst du dein Wildes[ENTER]Reittier herbeirufen. Kehre zu mir zur\252ck, sobald[ENTER]du die Rolle der Mutation entdeckt hast. Dann[ENTER]werde ich dir ein noch machtvolleres[ENTER]Reittier-Siegel erschaffen. "
gameforge.training_mount._21_say = "Das ist das Reittier-Siegel, dass du vor einer[ENTER]Weile von mir erhalten hast. Es ist aber schon[ENTER]ziemlich abgenutzt. Gib es mir zur\252ck und ich[ENTER]werde dir ein noch machtvolleres Reittier-Siegel[ENTER]erschaffen! "
gameforge.training_mount._22_say = "Die Macht dieses Siegels ruft dein verwandeltes[ENTER]Mount herbei. Achte gut darauf, denn es ist von[ENTER]unsch\228tzbarem Wert! "
gameforge.training_mount._23_say = "Kann ich Pferdefertigkeiten nutzen? "
gameforge.training_mount._24_say = "Du m\246chtest Pferdefertigkeiten einsetzen? Du bist[ENTER]ganz sch\246n anspruchsvoll! Aber auch ich tr\228ume[ENTER]davon ... Nun gut, um das zu erlernen, musst du[ENTER]ein paar Regeln befolgen. "
gameforge.training_mount._25_say = "Als Erstes solltest du das Reiten beherrschen,[ENTER]andernfalls bringst du dich ernsthaft in Gefahr.[ENTER]Au\223erdem muss dein Mount kampftauglich sein, denn[ENTER]nur dann ist es in der Lage, Pferdefertigkeiten[ENTER]einzusetzen. "
gameforge.training_mount._26_say = "Ist dein Mount in der Lage, Pferdefertigkeiten zu[ENTER]erlernen? Andernfalls kann ich das[ENTER]Training nicht erlauben. Was m\246chtest du tun? "
gameforge.training_mount._27_say = "Ich verstehe. Ich werde nun deine St\228rke und[ENTER]deine Reitkenntnisse einsch\228tzen. Warte einen[ENTER]Moment. "
gameforge.training_mount._28_say = "Hm ... ein starkes R\252ckgrat, fundierte[ENTER]Reitkenntnisse und dein Mount ist \228u\223erst[ENTER]kampflustig. Du kannst Pferdefertigkeiten nutzen. "
gameforge.training_mount._29_say = "Nun kann dein Mount Pferdefertigkeiten einsetzen.[ENTER]Holst du dir allerdings ein neues Reittier, muss[ENTER]es auch die Fertigkeiten erst wieder erlernen.[ENTER]Kehre in diesem Fall zu mir zur\252ck. "
gameforge.training_mount._30_say = "Komm schon, ich habe dir doch gesagt, dass es[ENTER]zu gef\228hrlich ist, wenn du nicht reiten kannst.[ENTER]Kehre zu mir zur\252ck, wenn du es erlernt hast. "
gameforge.training_mount._31_say = "Ich f\252rchte, dein Mount ist noch nicht bereit.[ENTER]Komm wieder, wenn es mehr Kampflust zeigt. "
gameforge.training_mount._32_say = "K\246nntest du bitte von deinem Mount absteigen,[ENTER]solange wir miteinander reden? Ich habe einen[ENTER]steifen Nacken und es ist ziemlich anstrengend,[ENTER]die ganze Zeit zu dir aufschauen zu m\252ssen. "
gameforge.training_mount._33_say = "Du hast nicht die geeignete Reitlizenz, um dein[ENTER]Mount zu verbessern. Du ben\246tigst mindestens die[ENTER]Kampfpferd-Lizenz, damit du ein Wildes Reittier[ENTER]trainieren kannst. Um ein Tapferes Reittier[ENTER]b\228ndigen zu k\246nnen, musst du die[ENTER]Milit\228rpferd-Lizenz haben. "
gameforge.training_mount._34_say = "Ich sehe, du besitzt einen Powersnack. Diese[ENTER]wertvolle Heilpflanze versorgt dein Power Mount[ENTER]mit reiner Energie - das verl\228ngert seine[ENTER]Lebenszeit um einige Tage. Was soll ich f\252r dich[ENTER]tun? M\246chtest du, dass ich das Leben deines[ENTER]Mounts verl\228ngere oder m\246chtest du es verbessern[ENTER]lassen? "
gameforge.training_mount._35_select_1 = "Verl\228ngern "
gameforge.training_mount._35_select_2 = "Verbessern "
gameforge.training_mount._36_select_1 = "7 Tage "
gameforge.training_mount._36_select_2 = "15 Tage "
gameforge.training_mount._36_select_3 = "30 Tage "
gameforge.training_mount._36_select_4 = "Rolle der Mutation + 200k Yang "
gameforge.training_mount._37_say = "Leider hast du nicht den passenden Powersnack f\252r[ENTER]die ausgew\228hlte Dauer. Aber du findest ihn hinter[ENTER]der drehenden M\252nze! "
gameforge.training_mount._38_say = "Die Rolle der Mutation besitzt gro\223e Macht! Sie[ENTER]kann das Leben deines Tapferen Mounts bis zu[ENTER]vier Tage verl\228ngern. Ein Versuch kostet dich[ENTER]200.000 Yang. Dein Mount muss daf\252r jedoch sehr[ENTER]ersch\246pft sein und weniger als einen Tag zu leben[ENTER]haben. Nat\252rlich geh\246rt auch etwas Gl\252ck dazu![ENTER]Sollte die Verl\228ngerung fehlschlagen, f\252ttere ihm[ENTER]doch einen Powersnack. Du findest diesen hinter[ENTER]der drehenden M\252nze. "
gameforge.training_mount._39_say = "Dein Power Mount ist noch zu stark. Hier kann die[ENTER]Rolle der Mutation nichts bewirken. Komme wieder,[ENTER]wenn es weniger als einen Tag zu leben hat. "
gameforge.training_mount._40_say = "Leider kann ich dir nicht helfen. Entweder tr\228gst[ENTER]du die Rolle der Mutation nicht bei dir oder du[ENTER]besitzt weniger als 200.000 Yang. "
gameforge.upgrade_refine_scroll = {}
