gameforge.upgrade_refine_scroll._120_say = "Die Schriftrolle des Drachen steigert die[ENTER]Wahrscheinlichkeit einer erfolgreichen[ENTER]Verbesserung. Sogar bei Fehlschl\228gen nimmt nur[ENTER]das Level ab, der Gegenstand wird nicht zerst\246rt.[ENTER]Die Schriftrolle ist ein r\228tselhafter Gegenstand,[ENTER]den man als eine verbesserte Segensschriftrolle[ENTER]betrachten kann. "
gameforge.upgrade_refine_scroll._130_say = "Um sie herzustellen, ben\246tigt man Magisches[ENTER]Eisenerz. "
gameforge.upgrade_refine_scroll._140_sayItem = "Magisches Eisenerz "
gameforge.upgrade_refine_scroll._150_say = "Um sie herzustellen, ben\246tigt man eine[ENTER]Segensschriftrolle. "
gameforge.upgrade_refine_scroll._160_say = "Hast du alle ben\246tigten Gegenst\228nde? Willst du[ENTER]eine Schriftrolle des Drachen herstellen? Daf\252r[ENTER]brauchst du eine Segensschriftrolle und Magisches[ENTER]Eisenerz. "
gameforge.upgrade_refine_scroll._170_say = "Du hast eine Schriftrolle des Drachen[ENTER]hergestellt! Es ist in der Tat einfacher, eine[ENTER]Schriftrolle des Drachen herzustellen, wenn man[ENTER]Magisches Eisenerz verwendet. Das gef\228llt mir! "
gameforge.upgrade_refine_scroll._180_say = "Dein Versuch, die Schriftrolle herzustellen, ist[ENTER]fehlgeschlagen, weil du nicht alle notwendigen[ENTER]Materialien bei dir tr\228gst. "
gameforge.upgrade_refine_scroll._190_npcChat = "Schmiede-Handbuch herstellen "
gameforge.upgrade_refine_scroll._200_say = "Hast du von einem Stein geh\246rt, den man den Stein[ENTER]des Schmieds nennt? Solche Steine entstehen in[ENTER]jahrelanger Arbeit am Amboss und kosten viel[ENTER]Schwei\223 und Blut. Wenn du mir einen solchen Stein[ENTER]und eine Segensschriftrolle bringst, werde ich[ENTER]dir ein Handbuch herstellen, mit Informationen[ENTER]zum Schmiedehandwerk, die in meiner Familie seit[ENTER]Generationen weitergegeben wurden.[ENTER]Dieses Schmiede-Handbuch funktioniert wie eine[ENTER]Schriftrolle des Drachen, aber die Erfolgsrate[ENTER]ist h\246her.  "
gameforge.upgrade_refine_scroll._20_say = "Die Schriftrollen des Krieges sind geheimnisvolle[ENTER]Gegenst\228nde, die +0 bis +3 Gegenst\228nde[ENTER]verbessern, und das mit 100-prozentiger[ENTER]Erfolgsrate. Sie wirken jedoch nicht bei[ENTER]Gegenst\228nden +4 und h\246her. "
gameforge.upgrade_refine_scroll._210_say = "Um es herzustellen, ben\246tigt man einen Stein des[ENTER]Schmieds. "
gameforge.upgrade_refine_scroll._220_sayItem = "Stein des Schmieds "
gameforge.upgrade_refine_scroll._230_say = "Um es herzustellen, ben\246tigt man eine[ENTER]Segensschriftrolle. "
gameforge.upgrade_refine_scroll._240_say = "Hast du alle ben\246tigten Gegenst\228nde?[ENTER]Soll ich dir jetzt ein Handbuch herstellen, das[ENTER]mein generationenlang getestetes Wissen[ENTER]enth\228lt? "
gameforge.upgrade_refine_scroll._250_say = "Ich habe ein Schmiede-Handbuch f\252r dich[ENTER]hergestellt! Du verf\252gst jetzt \252ber das uralte[ENTER]Wissen einer gesamten Schmiededynastie. Nutze es[ENTER]weise! Ha, ha, ha! "
gameforge.upgrade_refine_scroll._260_sayItem = "Schmiede-Handbuch "
gameforge.upgrade_refine_scroll._270_say = "Ich kann dir das Schmiede-Handbuch nicht[ENTER]herstellen, weil du nicht alle notwendigen[ENTER]Materialien bei dir tr\228gst. "
gameforge.upgrade_refine_scroll._30_say = "Um sie herzustellen, ben\246tigt man Magisches[ENTER]Kupfererz. "
gameforge.upgrade_refine_scroll._40_sayItem = "Magisches Kupfererz "
gameforge.upgrade_refine_scroll._50_say = "Zus\228tzlich ben\246tigt man eine Segensschriftrolle. "
gameforge.upgrade_refine_scroll._60_sayItem = "Segensschriftrolle "
gameforge.upgrade_refine_scroll._70_say = "Hast du alle ben\246tigten Gegenst\228nde?[ENTER]Dann brauchst du noch 200.000 Yang.[ENTER]Wenn du eine Segensschriftrolle, Magisches[ENTER]Kupfererz und 200.000 Yang hast, kannst du eine[ENTER]Schriftrolle des Krieges herstellen.[ENTER]Willst du die Schriftrolle herstellen? "
gameforge.upgrade_refine_scroll._80_say = "Die Schriftrolle wurde erfolgreich hergestellt![ENTER]Es ist in der Tat einfacher, eine Schriftrolle[ENTER]des Krieges herzustellen, wenn man Magisches[ENTER]Kupfererz hat! Das gef\228llt mir! Ha, ha, ha! "
gameforge.upgrade_refine_scroll._90_sayItem = "Schriftrolle des Krieges "
