gameforge.warehouse._100_say = "Willkommen! Wei\223t du, wozu ein Goldbarren dient?[ENTER]Wenn du Yang mit dir herumtr\228gst, ist das so, als[ENTER]w\252rdest du sagen: Bitte! T\246tet mich![ENTER]Darum tausche ich das Yang der Leute gegen[ENTER]Goldbarren und lagere diese Barren f\252r sie. "
gameforge.warehouse._10_npcChat = "Ich m\246chte das Lager benutzen. "
gameforge.warehouse._110_say = "Gut, ich verlange etwas mehr, als der Goldbarren[ENTER]wert ist. Aber f\252r solch eine Dienstleistung ist[ENTER]das trotzdem fair, oder? Es gibt keinen Grund,[ENTER]sich betrogen zu f\252hlen. Wie du wei\223t, ist es da[ENTER]drau\223en sehr gef\228hrlich. "
gameforge.warehouse._120_npcChat = "Itemshop-Lager \246ffnen "
gameforge.warehouse._130_say = "Die Minen sind inzwischen alle ersch\246pft.[ENTER]Es ist sehr schwer, Gold oder Silber zu finden.[ENTER]Solange keine neue Erzader entdeckt wird,[ENTER]gibt es kein Gold oder Silber. "
gameforge.warehouse._140_say = "Willkommen! Du willst dein Itemshop-Lager[ENTER]einsehen? Warum kommst du dann zu mir?[ENTER]Sieh einfach in dein Inventar, dort gibt es[ENTER]inzwischen einen direkten Zugang. "
gameforge.warehouse._150_say = "Klicke einfach dieses Symbol an, damit kommst du[ENTER]\252berall und jederzeit in dein Itemshop-Lager.[ENTER]Das Passwort lautet \252brigens 000000, sofern du es[ENTER]noch nicht ge\228ndert hast. "
gameforge.warehouse._20_sayTitle = "Lagerverwalter: "
gameforge.warehouse._30_say = "F\252r die Benutzung des Lagers musst du etwas[ENTER]zahlen. Ich bin heute allerdings in so guter[ENTER]Stimmung, dass ich es dir f\252r l\228cherliche 500[ENTER]Yang anbiete. Wie w\228re es? Das ist ein guter[ENTER]Preis! "
