gameforge.warehouse._60_sayReward = "000000 "
gameforge.warehouse._70_say = "Aus Sicherheitsgr\252nden solltest du das aber[ENTER]\228ndern.[ENTER]Vielleicht meinst du, dass 45 F\228cher zu wenig[ENTER]sind. Aber wer wei\223, vielleicht gebe ich dir mehr[ENTER]Platz, wenn wir uns gut verstehen. "
gameforge.warehouse._80_say = "Na, ich zwinge niemanden. Wenn dir jetzt nicht[ENTER]danach ist, dann komm eben sp\228ter wieder. "
gameforge.warehouse._90_npcChat = "Lager \246ffnen "
